INSERT INTO `kerdesek` (`id`, `temakor_id`, `kerdes_tipus_id`, `kronologia_esemeny_id`, `kerdes_szoveg`, `instrukcio`, `magyarazat`, `nehezseg`, `aktiv`, `created_at`, `updated_at`) VALUES
(2001, 1001, 4, 1103, 'Írd be Drakón törvényeinek évszámát!', 'Csak az évszám számjegyeit írd be, az app külön kezeli a Kr. e./Kr. u. jelölést.', 'Drakón törvényeit a hagyomány szerint Kr. e. 621-ben foglalták írásba.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2002, 1001, 1, 1104, 'Melyik évben hajtotta végre Szolón a reformjait Athénban?', '', 'Szolón reformjait Kr. e. 594-hez kötjük.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2003, 1001, 3, 1105, 'Igaz vagy hamis? Kleiszthenész reformjai Kr. e. 508-ban történtek.', '', 'Kleiszthenész reformjai Kr. e. 508/507-re tehetők; az iskolai kronológiában általában 508 szerepel.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2004, 1001, 1, 1107, 'Melyik évszám kapcsolódik a marathóni csatához?', '', 'A marathóni csata Kr. e. 490-ben volt.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2005, 1001, 1, 1108, 'Mikor zajlott a szalamiszi csata?', '', 'A szalamiszi csata Kr. e. 480-ban zajlott.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2006, 1001, 2, NULL, 'Mely események tartoznak a Kr. e. V. század elejéhez?', '', 'A marathóni (490) és a szalamiszi (480) csata a Kr. e. V. század elejéhez tartozik.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2007, 1001, 5, NULL, 'Tedd időrendbe az alábbi athéni eseményeket a legrégebbitől a legkésőbbiig!', '', 'Helyes sorrend: Drakón, Szolón, Kleiszthenész, Marathón.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2008, 1001, 6, NULL, 'Párosítsd az eseményeket a megfelelő évszámokkal!', '', 'Az alap athéni reformok és csaták biztos évszámai: 621, 594, 508, 490.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2009, 1001, 1, 1101, 'Melyik évben rendezték a hagyomány szerint az első olümpiát?', '', 'Az első olümpia hagyományos dátuma Kr. e. 776.', 1, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2010, 1001, 1, 1110, 'Mikor indította meg Nagy Sándor az ázsiai hadjáratát?', '', 'Nagy Sándor ázsiai hadjáratának kezdete Kr. e. 334.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2011, 1001, 1, 1102, 'Melyik évszám Róma hagyományos alapításának dátuma?', '', 'Róma hagyományos alapítási éve Kr. e. 753.', 1, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2012, 1001, 1, 1106, 'Mikor kezdődött a római köztársaság?', '', 'A római köztársaság hagyományos kezdete Kr. e. 509.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2013, 1001, 4, 1112, 'Írd be annak az évnek a számát, amikor Caesar átlépte a Rubicont!', 'Csak az évszám számjegyeit írd be.', 'Caesar Kr. e. 49-ben lépte át a Rubicont.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2014, 1001, 1, 1113, 'Melyik évben gyilkolták meg Julius Caesart?', '', 'Caesart Kr. e. 44-ben gyilkolták meg.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2015, 1001, 1, 1114, 'Mikor volt az actiumi csata?', '', 'Az actiumi csata Kr. e. 31-ben zajlott.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2016, 1001, 1, 1115, 'Melyik évben kezdődött Augustus principátusa?', '', 'Augustus principátusa Kr. e. 27-ben kezdődött.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2017, 1001, 2, NULL, 'Mely évszámok kapcsolódnak közvetlenül Augustus felemelkedéséhez?', '', 'Augustus felemelkedésének fő állomásai: Caesar halála (44), Actium (31), principátus (27).', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2018, 1001, 3, NULL, 'Igaz vagy hamis? Caesart az actiumi csata után gyilkolták meg.', '', 'Hamis: Caesart Kr. e. 44-ben gyilkolták meg, az actiumi csata csak Kr. e. 31-ben volt.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2019, 1001, 5, NULL, 'Tedd időrendbe az alábbi római eseményeket!', '', 'Helyes sorrend: Rubicon, Caesar halála, Actium, principátus.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2020, 1001, 6, NULL, 'Párosítsd a római eseményeket a megfelelő évszámokkal!', '', 'A római államfejlődés és Caesar–Augustus kora alap kronológiájának ismerete kötelező.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2021, 1001, 1, 1111, 'Mikor pusztult el Karthágó?', '', 'Karthágó Kr. e. 146-ban pusztult el.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2022, 1001, 4, 1109, 'Írd be a XII táblás törvények első évszámát!', 'Csak az első évszámot írd be.', 'A XII táblás törvényeket Kr. e. 451–450-hez kötjük; első évként 451 szokott szerepelni.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2023, 1001, 3, NULL, 'Igaz vagy hamis? Az actiumi csata Caesar halála után történt.', '', 'Igaz: Caesar Kr. e. 44-ben halt meg, Actium pedig Kr. e. 31-ben volt.', 1, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2024, 1001, 4, 1115, 'Írd be Augustus principátusának kezdetét!', 'Csak az évszám számjegyeit írd be.', 'Augustus principátusának kezdete Kr. e. 27.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2025, 1001, 1, 1116, 'Melyik évben adták ki a milánói ediktumot?', '', 'A milánói ediktumot 313-ban adták ki.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2026, 1001, 1, 1117, 'Mikor ült össze a niceai zsinat?', '', 'A niceai zsinat 325-ben ült össze.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2027, 1001, 1, 1118, 'A feltöltött tétel szerint melyik évben vált államvallássá a kereszténység?', '', 'A feltöltött tételben Theodosiushoz kapcsolva 391 szerepel.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2028, 1001, 3, 1119, 'Igaz vagy hamis? Theodosius 395-ben kettéosztotta a Római Birodalmat.', '', 'Igaz: a birodalom 395-ben vált ketté.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2029, 1001, 1, 1119, 'Mikor vált ketté a Római Birodalom?', '', 'A Római Birodalom kettéválása 395-höz kötődik.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2030, 1001, 1, 1120, 'Melyik évszám jelzi a Nyugatrómai Birodalom bukását?', '', 'A Nyugatrómai Birodalom bukása 476.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2031, 1001, 2, NULL, 'Mely évszámok kapcsolódnak a késő antik kereszténységhez?', '', 'A milánói ediktum 313, a niceai zsinat 325, az államvallássá válás 391.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2032, 1001, 5, NULL, 'Rendezd időrendbe a késő antik eseményeket!', '', 'Helyes sorrend: 313, 325, 391, 395, 476.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2033, 1001, 6, NULL, 'Párosítsd az eseményeket és az évszámokat!', '', 'A késő antik kereszténység kronológiája: 313, 325, 391, 395, 476.', 3, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2034, 1001, 4, 1119, 'Írd be a Római Birodalom kettéválásának évét!', 'Csak az évszám számjegyeit írd be.', 'A Római Birodalom kettéválása 395.', 1, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2035, 1001, 4, 1120, 'Írd be a Nyugatrómai Birodalom bukásának évét!', 'Csak az évszám számjegyeit írd be.', 'A Nyugatrómai Birodalom bukása 476.', 1, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2036, 1001, 3, NULL, 'Igaz vagy hamis? A milánói ediktumot 325-ben adták ki.', '', 'Hamis: a milánói ediktum 313-as.', 1, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2037, 1001, 2, NULL, 'Melyek Kr. e. évszámok az alábbiak közül?', '', 'A Kr. e. események: 776, 31; a 313 és 476 már Kr. u. dátum.', 1, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2038, 1001, 5, NULL, 'Rendezd időrendbe a következő vegyes eseményeket!', '', 'Helyes sorrend: első olümpia, Róma alapítása, köztársaság kezdete, marathóni csata.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2039, 1001, 6, NULL, 'Párosítsd az általános ókori eseményeket a megfelelő évszámokkal!', '', 'Fontos kiegészítő évszámok: 776, 753, 334, 146.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2040, 1001, 3, NULL, 'Igaz vagy hamis? A római köztársaság hagyományos kezdete korábbi, mint Kleiszthenész reformjai.', '', 'Igaz: 509 korábbi, mint 508.', 2, 1, '2026-04-17 18:08:20', '2026-04-17 18:08:20'),
(2101, 1002, 1, 1124, 'Melyik évben koronázták császárrá Nagy Károlyt?', 'Egy helyes válasz van.', 'Nagy Károlyt 800 karácsonyán koronázták császárrá Rómában.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2102, 1002, 1, NULL, 'Mi volt a feudum a hűbéri rendszerben?', 'Egy helyes válasz van.', 'A feudum feltételes birtokadomány volt, amelyért a hűbéres szolgálattal tartozott.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2103, 1002, 2, NULL, 'Mely elemek tartoztak a középkori uradalomhoz?', 'Több helyes válasz is van.', 'Az uradalom része volt a majorság, a jobbágytelkek és a közösen használt területek is.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2104, 1002, 3, NULL, 'Igaz vagy hamis? A háromnyomásos gazdálkodás csökkentette az ugar arányát és növelte a termésbiztonságot.', '', 'A háromnyomásos rendszer egyik lényege éppen az volt, hogy kevesebb föld maradt ugaron, és biztonságosabb lett a termelés.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2105, 1002, 1, NULL, 'Melyik technikai újítás segítette leginkább a nehézeke hatékony használatát?', '', 'A szügyhám és a patkó révén hatékonyabban lehetett igavonó állatokat használni.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2106, 1002, 1, 1127, 'Melyik évhez kötjük az egyházszakadást?', '', 'A keleti és a nyugati kereszténység közötti végleges szakítást 1054-hez kötjük.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2107, 1002, 2, NULL, 'Mely szerzetesrendek tartoznak a középkori kolduló rendek közé?', 'Több helyes válasz is van.', 'A ferencesek és a domonkosok kolduló rendek, a bencések nem.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2108, 1002, 3, NULL, 'Igaz vagy hamis? Az ortodox egyház elfogadta a pápa egyetemes főhatalmát.', '', 'Ez hamis: éppen a pápa elsőbbségének kérdése is a kelet–nyugati szakítás egyik oka volt.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2109, 1002, 1, NULL, 'Melyik kiváltság volt tipikusan a középkori városok egyik fontos joga?', '', 'A városok fontos kiváltsága volt a vásártartási jog.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2110, 1002, 2, NULL, 'Mely állítások igazak a céhekre?', 'Több helyes válasz is van.', 'A céhek szabályozták a termelést, a minőséget és a képzést is.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2111, 1002, 1, 1129, 'Melyik évszám kapcsolódik az angol rendi fejlődés egyik alapdokumentumához, a Magna Cartához?', '', 'A Magna Cartát 1215-ben adták ki.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2112, 1002, 1, 1130, 'Melyik évben hívták össze először a francia rendi gyűlést?', '', 'A francia rendi gyűlést először 1302-ben hívták össze.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2113, 1002, 3, NULL, 'Igaz vagy hamis? A francia rendi gyűlés első összehívása megelőzte a Magna Carta kiadását.', '', 'Hamis: a Magna Carta 1215-ös, míg a francia rendi gyűlés első összehívása 1302-es.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2114, 1002, 1, 1122, 'Melyik évben történt a hidzsra, vagyis Mohamed kivonulása Mekkából Medinába?', '', 'A hidzsrát 622-höz kötjük; ez az iszlám időszámítás kezdete.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2115, 1002, 2, NULL, 'Melyek az iszlám vallás fő tanításai, kötelességei közé tartozó elemek?', 'Több helyes válasz is van.', 'Az iszlám öt pilléréhez tartozik többek között a hitvallás, az ima, a böjt és az alamizsna.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2116, 1002, 1, 1131, 'Melyik esemény jelzi az Oszmán Birodalom egyik nagy áttörését Európában?', '', 'Konstantinápoly 1453-as elfoglalása az oszmán terjeszkedés kulcseseménye.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2117, 1002, 1, NULL, 'Melyik építészeti stílusra jellemző inkább a félkörív és a vastag fal?', '', 'A román stílusra jellemző a félkörív, a vastag fal és a kisebb ablak.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2118, 1002, 2, NULL, 'Mely elemek jellemzőek a gótikus építészetre?', 'Több helyes válasz is van.', 'A gótikára csúcsív, támpillér, rózsaablak és nagy üvegfelületek jellemzők.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2119, 1002, 3, NULL, 'Igaz vagy hamis? A reneszánsz Itáliából indult, és az antik kultúra újjászületését hirdette.', '', 'A reneszánsz Itáliából indult, és tudatosan fordult az antikvitás felé.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2120, 1002, 4, 1125, 'Írd be a verduni szerződés évét!', 'Csak az évszám számjegyeit írd be.', 'A Frank Birodalom felosztását rögzítő verduni szerződés 843-ban született.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2121, 1002, 5, NULL, 'Tedd időrendbe az alábbi egyetemes középkori eseményeket a legrégebbitől a legkésőbbiig!', '', 'Helyes sorrend: Nyugatrómai bukás, Nagy Károly koronázása, egyházszakadás, Konstantinápoly eleste.', 3, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2122, 1002, 6, NULL, 'Párosítsd az eseményeket a megfelelő évszámokkal!', '', 'Az iszlám, a Frank Birodalom, az angol rendiség és az oszmán terjeszkedés alapévszámai szerepelnek itt.', 3, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2123, 1003, 1, 1133, 'Melyik évhez kötjük a honfoglalás kezdetét?', '', 'A honfoglalás hagyományos dátuma 895.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2124, 1003, 2, NULL, 'Mely állítások jellemzőek a honfoglaló magyarság életmódjára?', 'Több helyes válasz is van.', 'A honfoglaló magyarságra a lovas harcmodor és az állattartás meghatározó volt.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2125, 1003, 1, 1135, 'Melyik évszám jelzi a kalandozások végét jelentő augsburgi vereséget?', '', 'Az augsburgi (Lech-mezei) vereség 955-ben volt.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2126, 1003, 3, NULL, 'Igaz vagy hamis? A pozsonyi csata a honfoglalás után zajlott le.', '', 'Igaz: a honfoglalást 895-re, a pozsonyi csatát 907-re tesszük.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2127, 1003, 4, 1136, 'Írd be Géza fejedelemségének kezdetét!', 'Csak az évszám számjegyeit írd be.', 'Géza 972-ben került hatalomra.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2128, 1003, 1, 1137, 'Melyik évben koronázták meg I. (Szent) Istvánt?', '', 'A hagyományos iskolai évszám 1000, bár a koronázás 1000 karácsonya és 1001 újéve között történt.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2129, 1003, 2, NULL, 'Mely intézkedések kapcsolódnak I. (Szent) István államszervező tevékenységéhez?', 'Több helyes válasz is van.', 'István vármegyéket és püspökségeket szervezett, és a keresztény államot építette ki.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2130, 1003, 1, 1138, 'Melyik évben lépett trónra Könyves Kálmán?', '', 'Könyves Kálmán 1095-ben lett király.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2131, 1003, 3, NULL, 'Igaz vagy hamis? Szent László és Könyves Kálmán uralkodása az új keresztény rend megszilárdulásának időszaka volt.', '', 'Igaz: a két uralkodó alatt stabilizálódott a keresztény királyság.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2132, 1003, 1, 1139, 'Melyik évben adták ki az Aranybullát?', '', 'Az Aranybullát II. András 1222-ben adta ki.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2133, 1003, 2, NULL, 'Mely pontok kapcsolódnak az Aranybullához?', 'Több helyes válasz is van.', 'Az Aranybulla a nemesi jogok védelméről és az ellenállási záradékról is ismert.', 3, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2134, 1003, 1, 1140, 'Melyik évben kezdődött a tatárjárás Magyarországon?', '', 'A tatárjárás kezdete 1241.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2135, 1003, 2, NULL, 'Mely intézkedések jellemzőek IV. Béla országújjáépítő politikájára?', 'Több helyes válasz is van.', 'IV. Béla a várépítést és a betelepítést ösztönözte, erősítette a városokat.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2136, 1003, 3, NULL, 'Igaz vagy hamis? Az Árpád-ház kihalása 1241-ben következett be.', '', 'Hamis: az Árpád-ház 1301-ben halt ki.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2137, 1003, 4, 1141, 'Írd be az Árpád-ház kihalásának évét!', 'Csak az évszám számjegyeit írd be.', 'Az Árpád-ház férfiága 1301-ben halt ki.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2138, 1003, 1, 1143, 'Melyik évben tartották a visegrádi királytalálkozót?', '', 'A visegrádi királytalálkozó 1335-ben volt.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2139, 1003, 1, 1144, 'Melyik évben hozta I. (Nagy) Lajos a nevezetes törvényeit?', '', 'I. (Nagy) Lajos törvényei 1351-hez kötődnek.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2140, 1003, 3, NULL, 'Igaz vagy hamis? Az 1351-es törvényekhez kapcsoljuk az ősiség és a kilenced rögzítését.', '', 'Igaz: az 1351-es törvényekhez kötjük az ősiség és a kilenced megerősítését.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2141, 1003, 1, 1145, 'Melyik évben lépett trónra Luxemburgi Zsigmond?', '', 'Zsigmond 1387-ben lett magyar király.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2142, 1003, 2, NULL, 'Mely területekhez kapcsolódott leginkább Zsigmond külpolitikája?', 'Több helyes válasz is van.', 'Zsigmond külpolitikájában a német-római birodalmi, a cseh és a törökellenes irány is jelentős volt.', 3, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2143, 1003, 1, 1146, 'Melyik évben szenvedett vereséget Hunyadi János Várnánál?', '', 'A várnai csata 1444-ben volt.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2144, 1003, 1, 1147, 'Melyik évben aratott győzelmet Hunyadi János Nándorfehérvárnál?', '', 'A nándorfehérvári diadal 1456-ban volt.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2145, 1003, 3, NULL, 'Igaz vagy hamis? Hunyadi János megnyerte a várnai csatát.', '', 'Hamis: Várnánál vereséget szenvedtek, Nándorfehérvárnál viszont győztek.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2146, 1003, 1, 1148, 'Melyik évben választották királlyá Hunyadi Mátyást?', '', 'Mátyást 1458-ban választották királlyá.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2147, 1003, 2, NULL, 'Mely intézkedések kapcsolódnak Hunyadi Mátyás reformjaihoz?', 'Több helyes válasz is van.', 'Mátyás hadsereget, adórendszert és kormányzást is megerősítő reformokat vezetett be.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2148, 1003, 1, 1149, 'Melyik évben hajtotta végre Mátyás nevezetes adóreformját?', '', 'Mátyás adóreformját 1467-hez kötjük.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2149, 1003, 2, NULL, 'Mely célok jellemezték Mátyás külpolitikáját?', 'Több helyes válasz is van.', 'Mátyás egyszerre törekedett a nyugati expanzióra és a török elleni védelemre.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2150, 1003, 5, NULL, 'Tedd időrendbe az alábbi magyar középkori eseményeket!', '', 'Helyes sorrend: honfoglalás, István koronázása, Aranybulla, tatárjárás.', 3, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2151, 1003, 6, NULL, 'Párosítsd az eseményeket és az évszámokat!', '', 'A késő Árpád-kor, az Anjouk és a Hunyadiak korának alapévszámai.', 3, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2152, 1003, 1, 1151, 'Melyik évben foglalta el Mátyás Bécset?', '', 'Mátyás 1485-ben foglalta el Bécset.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2153, 1003, 4, 1152, 'Írd be Mátyás halálának évét!', 'Csak az évszám számjegyeit írd be.', 'Mátyás 1490-ben halt meg.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2154, 1003, 3, NULL, 'Igaz vagy hamis? A kenyérmezei csata később volt, mint a nándorfehérvári diadal.', '', 'Igaz: Nándorfehérvár 1456, Kenyérmező 1479.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2155, 1003, 1, 1150, 'Melyik évhez kötjük a kenyérmezei csatát?', '', 'A kenyérmezei csata 1479-ben zajlott.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2156, 1003, 2, NULL, 'Mely uralkodók tartoznak az Anjou-korhoz Magyarországon?', 'Több helyes válasz is van.', 'Az Anjou-kor meghatározó uralkodói I. Károly és I. (Nagy) Lajos voltak.', 2, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2157, 1003, 3, NULL, 'Igaz vagy hamis? A „boszorkányok pedig nincsenek” elv Könyves Kálmán törvénykezéséhez kapcsolódik.', '', 'Igaz: a híres megfogalmazás Könyves Kálmánhoz kötődik.', 1, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00'),
(2158, 1003, 2, NULL, 'Mely intézkedések erősítették I. Károly uralkodását?', 'Több helyes válasz is van.', 'I. Károly a tartományurak leverésével és a regálébevételek megerősítésével stabilizálta a királyi hatalmat.', 3, 1, '2026-04-18 14:30:00', '2026-04-18 14:30:00');
