INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(1, 1, 'Mezőgazdasági és ipari termelés, kereskedelem a középkorban és a kora újkori Európában', '1.docx', 'tétel: Mezőgazdasági és ipari termelés, kereskedelem a középkorban és a kora újkori Európában\n\nKÖZÉPKOR: 476-1492. Nyugat-Európából. FEUDALIZMUS\n\nA termelési viszonyok háttere\n\nA középkorban a népesség 80-90%-a mezőgazdasági termeléssel foglalkozott, elsősorban néhány gabonafajtára építve. A terméshozamok kezdetben rendkívül alacsonyak, maximum két-háromszorosak voltak, így egy-egy rosszabb év negatívan érintette a népesség élelmezési viszonyait. Északon gyengébb tápértékű gabonákat, árpát és rozst termeltek, az időjárási változásokra érzékenyebb búza csak a délebbi területeken termett. Súlyos probléma volt a nagy tételben zajló élelmiszerkereskedelem hiánya, ami tovább nehezítette az ellátást. Az ipar a középkorban a falusi háziipar és a céhes ipar kettősségére épült.\n\nA mezőgazdaság fejlődése\n\nA X. századtól jelentős fejlődés figyelhető meg a középkori mezőgazdaságban. A mezőgazdaság fejlődését eredményező technikai (a termelés eszközeit érintő) és technológiai (a termelés módját érintő) fejlődés leginkább a kolostorokból terjedt el az egyes vidékeken. Ilyen alapvető technikai eszköz volt a mélyebb földréteget megforgató és így magasabb terméshozamot eredményező vaspapucsos, kerekes nehézeke, valamint az állati erő jobb kihasználását lehetővé tévő újfajta fogatolási mód, a lovaknál alkalmazott szügyhám, illetve az ökröknél a homlokra illesztett hám. A korábbi nyakhámmal ellentétben ezek az eszközök kevésbé terhelték az állatokat.\n\nA földművelés új eszközei:\n\n• A korábban használt hagyományos könnyű, szimmetrikus eke (kemény, kötött talajok művelésére alkalmatlan, mert nem szánt mélyen) mellett megjelent a germánok által kifejlesztett csoroszlyás, kormánylemezes nehéz fordítóeke. Ez a felszíni gyeptakaró felhasítása után mélyen megforgatta a talajt, és az ekevas által lenyesett földdarabot az egyik oldalra vetette ki. Mozgatása már 6-8 ökröt igényelt, ugyanakkor időt takarított meg, mert nem kellett keresztirányban még egyszer felszántani a földet.\n\n• Az igaerő szükséglet jelentős nagyállattartást igényelt.\n\n• Az új nehézekét csak új fogatolási módszerrel lehetett vontatni. Az ökör (és a ló is) a nyakhám helyett már szügyhámot kapott, amely munka közben nem „fojtogatta”. Patkó.\n\n• A gabonatermelő és nagyállattenyésztő gazdálkodás kialakulása jobb táplálkozást tett lehetővé, és egy idő után a terményfelesleg is megjelent, amit piacra lehetett vinni.\n\n• A mezőgazdasági termelés növekedésében az új módszerek és eszközök elterjedése mellett a művelésbe vont területek megsokszorozódása is komoly szerepet játszott:\n\n• erdőket, bozótosokat irtottak ki; füves területeket törtek fel; mocsarakat csapoltak le.\n\nA földművelés új módszerei:\n\nAz ókorban az uralkodó művelési mód az ún. vadtalajváltó vagy legelőváltó rendszer volt, amelyben az erdőirtással nyert földet 10-30 évig művelték, majd kimerülésük után elhagyták, és új területet vontak művelés alá.\n\nSzintén a kolostoroktól indult el a két-, majd háromnyomásos gazdálkodás módszere, amellyel - a föld pihentetésével, illetve különböző időszakokban történő használatával - megőrizték a föld termőképességét. Az új művelési eljárás, a háromnyomásos gazdálkodás, egyharmaddal csökkentette az ugar területét, a megnövelt szántón pedig őszi és tavaszi vetésű gabonát termesztettek. Mindez megnövelte a termés mennyiségét, ráadásul a tavaszi és őszi vetés biztonságosabbá tette a gazdálkodást.\n\n• A VIII. századtól a kolostorok tehát áttértek a nyomásos földművelésre, a talajpihentetési rendszerre:\n\nelőbb a kétnyomásosra (szántó+ugar évente cserélve);\n\nkésőbb a háromnyomásosra (őszi+tavaszi+ugar évente forgatva).\n\nEzeknél a rendszereknél már megszűnt a vándorlási kényszer, és az adott földterületet egyre jobban kihasználva, a szükséges talajerő utánpótlást biztosítva (trágyázás) lehetett termelni. Nyugat-Európában a X-XI. századra lett általános a háromnyomásos gazdálkodás, míg Dél-Európában megmaradt a kétnyomásos földművelés. A nyomásos műveléssel egyre többet és egyre biztonságosabban lehetett termelni - ez megalapozta a népesség folyamatos gyarapodásának lehetőségét. A háromnyomásos rendszerben (a szántó két részre bontásával) vált lehetővé a zab termelése, amely megteremtette az alapját a ló szélesebb körű elterjedésének és használatának. A tápanyag pótlását a trágyázás segítette elő. Mindez a termelés intenzív fejlődését jelentette, vagyis adott termőterületen nagyobb terménymennyiséget lehetett termeszteni. A termelékenység növelését és a többszörös gabonahozamok elérését segítette a XI. század melegebb, csapadékosabb éghajlata is. A stabil ellátás kialakulása és a jelentősebb fölösleg felhalmozása cserére ösztönzött, ami végül is a pénzgazdálkodás előretörését eredményezte. A korai és az érett középkor határán lejátszódó népességrobbanás alapja az élelmiszer-termelés szintjének növekedése volt. A faluközösség határozza meg, hogy melyik területet fogják bevetni és pihentetni: ez a nyomáskényszer.\n\nJobbágy – földesúri viszony:\n\nA IX-X. századra végbement feudalizáció eredményeként a falusi népesség a földesúr alávetettségébe került, röghöz kötött jobbággyá vált. A jobbágyok nem rendelkeztek a föld fölött tulajdonjoggal, azt csak használatra kapták. A birtokosok a tulajdonukban lévő uradalom egy részét szétosztották a parasztok között (jobbágytelek, házhely), amiért azok szolgáltatásokkal tartoztak nekik (terményjáradék /kilenced/, ajándékok). A földesúr saját kezelésű földjén (majorság) a jobbágyok ingyenmunkára (robot) voltak kötelezhetők. A közföldeket (legelők, erdők, halászhelyek) viszont a falvak lakói is használhatták. A jobbágyok személyes függését jelzi, hogy a földesúr joghatósága alá tartoztak (úriszék).\n\nA jobbágyság jogai és kötelességei:\n\nKialakulása a kora középkorban, jellemző az érett középkorban, de fennmarad a kora újkorig, egyes térségekben a 19. századig. A középkor hagyományos időhatárai 476–1492. Elsősorban Nyugat-Európára jellemző, de a középkorban Közép-Európában is megjelenik.\n\nA jobbágy használatra kapta földjét a birtokostól, azaz földesúrtól. A használatért cserében tartozott szolgáltatásokkal, földjéről – kötelességszegés esetén – akár el is űzhették, el is költözhetett. A földesúr ezen felül védelmet is ígért neki.\n\nAz uradalom alkotórészei: telkek, majorság, közös használatú területek. A jobbágytelek a belső kertből, házhelyből és a szántókból állt, a szántók a dűlőkben helyezkedtek el, ahol 2 vagy 3 nyomásos gazdálkodás folyt. A szántóföldi parcellákat sorsolták. A jobbágyok a saját szántón kívül a majorságot is megművelték - robotmunkával.\n\nA jobbágy földesurának termény- és munkajáradékkal, azaz robottal tartozott. A terményjáradékot a saját telken termett termény arányában fizette. Magyarországon ez volt a kilenced. A terményjáradékot később felváltotta a pénzadó, a robotot a telekméret arányában teljesítette, a robotot saját eszközökkel, állatokkal teljesítette. A robotban a majorságot művelték meg, azaz a földesúr saját kezelésében maradt földjét.\n\nA jobbágy jogállása: a jobbágyság személyi függést is jelentett, a földesúr bíráskodhatott is jobbágya felett. A jobbágy örökíthette földhasználati jogát. A jobbágyok további szolgáltatásokkal – pl. fuvarozás, ajándék – is tartozhattak. A jobbágyság eltérő helyzetű társadalmi csoportokból alakult ki. A földesúr engedélye szükséges volt bizonyos gazdasági tevékenységekhez, magánéleti eseményekhez. A jobbágyi állapot, kötelességek is öröklődtek. A jobbágyok szabadon költözködhetnek, ennek ellentéte a röghöz kötés. A földesúr bíráskodhat is felettük, ezt Magyarországon úriszéknek és pallosjognak nevezik. 1351-től Magyarországon kilencedet fizetnek a földesúrnak, az egyháznak tizedet, és emellett állami adót pl. kapuadót.\n\nA technika forradalma\n\nA középkorban használtak először nagyobb méretekben nem emberi vagy állati erővel hajtott gépeket a termelésben, részben a rabszolgatartó termelési mód hiánya miatt. Míg az ókori szerkezetek csak az élőerő energiájának hatékonyabb hasznosítását segítették elő, addig a középkori gépek már annak kiváltását is lehetővé tették.\n\nNagyon fontos eredmény a vízi vagy szélenergiával hajtott kerekek megjelenése, amelyeket elsődlegesen a malmokban alkalmaztak. De a kerekeket bütykös forgótengellyel összekötve át tudták alakítani a körmozgást szakaszos mozgássá is, ami lehetővé tette például a vasolvasztó kemencék fújtatóinak, az érctörő malmok zúzógépeinek vagy a favágó fűrészmalmok gépeinek működtetését.\n\nA kőszén- és ércbányászat területén úgyszintén jelentős bővülés mutatkozott. Ezeknek a megoldásoknak volt köszönhető, hogy a középkor vasművességének színvonala messze túlszárnyalta a korábbi korszakokét.\n\nAz északi országokban alkalmazott szélkerekeknek a szél irányába történő forgatását is megoldották, és már olyan hajók építésére is képesek voltak, amelyek ún. latin vitorláikkal a széllel szemben tudtak haladni.\n\nEkkor épültek az első, teljes mértékben evezők nélkül haladó vízi járművek, és kialakultak azok a navigációs módszerek, amelyek később kivitelezhetővé tették az Újvilág felfedezését.\n\nAz emberi erő hatékonyabb kihasználását tette lehetővé a láb szakaszos mozgását körmozgássá alakító, a régi varrógépekhez hasonlatos lábító, amelyet a szövőszékeken alkalmaztak, és a textilipar ugrásszerű fejlődését eredményezte. Ekkor jelent meg a különböző áttételeket kezelő és így a mozgás sebességét változtatni képes, a mai kerékpárokról ismert zsinórhajtás.\n\nAz építészet, a mérnöki tudományok, valamint az építési technika és technológia fejlődése lehetővé tette a korábbiaknál magasabb, karcsúbb és merészebb épületek kivitelezését, például a gótikus katedrálisokét.\n\nA céhes ipar bemutatása\n\nNyugat-Európában a XI-XIII. században kezdett kialakulni az árutermelés és pénzgazdálkodás. A jobbágy termékfölöslegét eladja, s pénzzel fizetnek az áruért. Különválik a kézművesség, a földművelés és a kereskedelem. A kereskedelmi szempontból előnyös helyeken létrejönnek a városok: 1. a síkság és hegyvidék találkozásánál, 2. fontos utak kereszteződésénél, 3. folyók torkolatvidékén, 4. átkelőhelyeken, 5. kikötőknél, 6. nyersanyagforrások mellett /pl. bányák/, 7. püspöki székhelyek, kolostorok mellett, 8. királyi és földesúri várak környékén. A városok lakói a polgárok. Céljuk, hogy a földesúri fennhatóságuk megszűnjön. A mezővárosok kiváltságokat szereznek meg: városi önkormányzattal rendelkeznek, egy összegben adóznak évente, saját bíráik ítélkeznek felettük. A szabad királyi városok egyedül a királynak adóznak, vásártartással, vámmentességgel és árumegállító joggal rendelkeznek. A városok önálló szervezetet, kommunát hoznak létre. Észak-Itáliában városköztársaságok alakulnak ki, saját államot alkotnak, pl. Velence.\n\nA városi polgárság társadalma: 1. A város vezetője a patríciusokból, azaz gazdag polgárokból álló szenátus. 2. A kézművesek, iparosok képviselői a városi nagytanácsban foglalnak helyet. 3. A plebejusok a polgárság szegényebb rétege, akik iparos legények, napszámosok. Polgárjoggal ugyan nem rendelkeznek, de már nem jobbágyi szinten élnek. Ezért mondják azt, hogy a városi levegő szabaddá tesz. Polgárjoga: ingatlantulajdonosnak.\n\nA VÁROSOKBAN működtek a céhek\n\nA céhek az azonos szakmát űzők érdekvédelmi szervezetei voltak. A céh szakmai szervezet volt. Szabályozták a piacot, korlátozták a versenyt:\n\n- minőségi és mennyiségi rendelkezésekkel (pl. munkaidő, munkaeszközök száma);\n\n- az inasok és legények számának szabályozásával, és a nekik fizetett bér maximalizálásában;\n\n- az éjszakai munka és a reklám tiltásával; az árak maximalizálásával;\n\n- a város körüli falvakban az iparűzés tiltásával.\n\nMeghatározták a mesterek számát és a mesterré válás feltételeit. Csak annyi mester működhetett a céhben, amennyi meg is tudott élni. A mesterré válás stádiumai:\n\n2-10 év inaskodás egy mester mellett, felszabadulás, majd vándorút, más városban egy-egy mester mellett kellett legénykedni, végül egy mesterremeket kellett készíteni: ha ezt elfogadták, és elegendő pénze volt a műhely nyitásához, a mesterek megvendégeléséhez, akkor mesterré válhatott. Ha nem, akkor legényként, segédként kellett tovább dolgoznia egy mester mellett. Ha valaki céhen kívül kezdett iparűzésbe, kontárnak hívták - őket a céhek üldözték, megpróbálták kiszorítani a városból.\n\nA céh védelmet, segítséget biztosított tagjainak: pl. közös kasszát tartottak fenn, amelyből a mester halála, vagy betegsége esetén támogatni tudták a családot.\n\nA céh fontos szerepet játszott a város életében: a XIII. századtól kezdve kiharcolták, hogy tisztségviselőiket maguk választhassák, és hogy részt vehessenek a város irányításában. Mindegyik céhre ráosztották a városfal egy-egy szakaszának védelmét. Szerepet kapott a tisztségek betöltésénél, az adók kivetésénél, a céhmester bíráskodhatott a céhtagok felett.\n\nA munkaidő hajnaltól napnyugtáig tartott, de az ünnepnapokon (az év kb. egyharmada) és éjszaka nem dolgoztak. A mester műhelyében dolgoztak a családtagjai, az inasok (csak szállást és ellátást kaptak) és a legények (ők bért kaptak).\n\nEgyetlen ember végezte el egy adott munkadarabon az összes munkafolyamatot, nem volt munkamegosztás.\n\nKereskedelem:\n\nA helyi kereskedelem kiszélesedik, leghíresebb vásárváros: Champagne.\n\nA távolsági kereskedelmet hivatásos kereskedők végzik, s elsősorban luxuscikkeket szállítanak. Kereskedelmi útvonalak: a levantei kereskedelem, mely Ázsiát kötötte össze Európával. Legfőbb haszonélvezői: Velence, Genova, Pisa. Keletről: fűszer, festék, illatszer, déligyümölcs, finom textiláru, nyersselyem, papír érkezik, a karavánutak végén hajók várják a keletről jövő árut. Európából: posztó, fa, vas, rabszolga, fegyver kerül keletre.\n\nA Hanza-szövetség (1161) az észak-német városok szövetsége. Az északi- és balti-tengeri kereskedelmet bonyolította le Novgorodtól Londonig. Legfőbb élvezői: Hamburg, Lübeck, Bréma. Északkeletről: gabona, hal, fa, prém, borostyán, méz, északnyugatról pedig: só, posztó, keleti áru, fémáru, bor. A két kereskedelmi útvonal összeköttetésben állt az Alpok hágóin keresztül az Észak-Itáliai városok és Flandria között. A kereskedők szakmai egyesülete a guilde. Itáliában már pénzügyekkel foglalkozó bankok jönnek létre, pl. Firenzében.\n\nVáltozások a kora újkorban, a földrajzi felfedezések következményei\n\nA kora újkorban a termelés keretei is jelentősen módosultak. A nagy földrajzi felfedezéseket követő nemesfémáradat jelentősen növelte a pénzgazdálkodás szerepét, erőre kapott a pénzgazdálkodás és a bankrendszer.\n\nA XV. századi Európában meginduló gazdasági fellendülés, és a népesség gyarapodása a XVI. századra már újra az egyensúlytalanság állapotába jutott a mezőgazdaság fejlődése nem tudott lépést tartani a lakosság növekedésével, emiatt elkezdődött, főként a mezőgazdasági termékeknél egy lassú áremelkedés.\n\n• Ezt a már megkezdődött lassú áremelkedést fokozta a gyarmatokról dömpingszerűen beáramló nemesfémtömeg. Emiatt csökkent a nemesfémek többi áruhoz viszonyított (vásárló) értéke, azaz ugyanannyi áruért egyre több pénzt kellett fizetni.\n\n• Az árforradalomként emlegetett lassú inflációs folyamat során a mezőgazdasági termékek ára emelkedett a leginkább.\n\nAz 1492 utáni felfedezések gazdasági és társadalmi hatása: az árforradalom, illetve a manufaktúrák kialakulásához vezető folyamatot. A XVI. század folyamán a gabona és a kézműipari termékek ára a többszörösére emelkedett, ezt a jelenséget nevezzük árforradalomnak. A kézműipari termékek árai sokkal kisebb mértékben emelkedtek, mint a gabonáé: az agrártermékeknek az ipari termékekhez mért relatív ára is nőtt, és ez ösztönzőleg hatott a mezőgazdasági termelésre. Spanyolországból és Portugáliából kiáramlott az ezüst és az arany a Kelet-Közép-Európából megvásárolt gabonáért és a Nyugat-Európából megvásárolt iparcikkekért cserében. Ez nem hatott ösztönzően az ibériai gazdaságok fejlődésére. Az ipari termelés új üzemformája alakult ki, a manufaktúra, itt munkamegosztás érvényesült, a munkafolyamatot részfeladatokra bontották, ezek elvégzését egy-egy alacsony bérű társadalmi rétegre bízták, s minden munkás csak egy műveletet végzett.\n\nKialakult a kontinentális munkamegosztás: Nyugat-Európa mezőgazdasági felvevőpiacként ipari termékekkel látta el Kelet-Közép-Európát. Kelet-(Közép)- Európa pedig a mezőgazdasági termékek exportőreként a nyugati ipari termékek felvevőpiaca lett. Az árforradalom hatására korlátlanul lehetett értékesíteni Nyugat-Európa számára a kelet-közép-európai gabonát. Az Elbától keletre a földesurak növelték a majorsági területet és a jobbágyi szolgáltatásokat. Az európai kereskedelem súlypontja az Atlanti-óceánra helyeződött. Az atlanti térség országai Európa gazdasági centrumává váltak. Az olcsó ipari termékek iránt is fokozódott az igény, ez a folyamat először Angliában, Németalföldön és Franciaországban vezetett el a manufaktúrák kialakulásához. A mezőgazdaságban felszabadult munkaerő bérmunkásként áramlott az új típusú üzemekbe.\n\nMezőgazdaság:\n\n• Nyugat-Európában továbbra is ez volt a legfontosabb, legtöbb embert foglalkoztató gazdasági ág.\n\n• Általánossá vált azonban a jobbágyi kötelékek lazulása: a parasztok szabad bérlőkké, kistulajdonosokká váltak, a földeket szabadon lehetett adni-venni. A BEKERÍTÉSEK során a földesurak kiterjesztik földbirtokaikat, elveszik a közös földeket, hogy juhokat tenyésszenek, és a gyapjút a manufaktúrák számára eladják. A földekről a parasztság egy része a városokba áramlik, ahol a manufaktúrák bérmunkásai lesznek, amely nem igényelt szaktudást, csak betanított munkát.\n\n• A földbirtokosokból Németalföldön és Angliában vállalkozók lettek, akik piacra termeltek, és érdekeltségeket szereztek a kereskedelemben és az iparban is.\n\nA spanyolok afrikai rabszolgákat hurcoltak Amerikába, és ültetvényeken, bányákban dolgoztatták őket, pótolták az indián munkaerőt.\n\n• Később, a XVII. századra, a legfejlettebb területen, Németalföldön megjelent a mezőgazdasági specializálódás (tej és tejtermék, ipari növények és virágtermesztés). Mindezt a gabona lehetséges megvásárlása a piacokon tette lehetővé, mert így már nem kellett feltétlenül a földek nagy részén gabonát termeszteni.\n\nA városi ipar munkaerő igényének bővülése, valamint például Angliában a mezőgazdaságból jelentős munkaerőtömeget felszabadító bekerítéses rendszer folytán elindult a széles körű urbanizáció, a városiasodás folyamata. Emellett hosszú távon végleg sikerült biztosítani a stabil élelmiszer-ellátást, aminek köszönhetően visszaszorultak a ciklikusan ismétlődő éhínségek és járványok.\n\nIpar:\n\nNyugat-Európában előrehaladt a céhes keretű kézművesipar felbomlása, átalakulása. Ennek oka az volt, hogy a belső és a külső piacok megnövekedett igénye, illetve az árforradalom során bekövetkezett romló cserearányok (ugyanannyi élelmiszer megvásárlásához több iparcikket kellett eladni: „ipari-olló kinyílása”) miatt többet kellett termelni. A városi céhrendszer kikerülésére már régóta létezett a kisebb vidéki műhelyekben alkalmazott kiadatási-felvásárlási rendszer (verlag system).\n\nAz igazi áttörést azonban a városi manufaktúrák megjelenése jelentette. Megkezdődött az eredeti tőkefelhalmozás folyamata, kialakult a tőkés termelési mód. A korábbi háziipar helyét átvette a felvásárlási és kiadási rendszer, a céhes ipart pedig a manufaktúrák váltották fel. Ezek már sokkal nagyobb tételben voltak képesek az egyes termékek előállítására, hiszen a céhekhez képest több gépet alkalmaztak, és a munkaszervezésük is fejlettebb volt, mivel itt egy munkás csak egyetlen munkafázist hajtott végre. A manufakturális ipar termékeinek felvevőpiaca megnőtt az ismét rohamosan növekvő népességnek köszönhetően, valamint a kontinentális munkamegosztás és a világkereskedelem kialakulása következtében bővülő exportlehetőségek folytán. A technikai és technológiai fejlődés a manufaktúrákban végül a gőzgépek alkalmazásához és a gyárak megjelenéséhez vezetett.\n\nManufaktúraipar lényege:\n\nA textiliparban jelennek meg először manufaktúrák. A gyapjú feldolgozása munkamegosztással történik, a manufaktúrák tömegtermékeket állítottak elő, olcsóbbá vált a termelés, elvált egymástól a tulajdonos és a bérmunkás. A manufaktúrákat általában kereskedők, vállalkozók alapították, akik bérmunkásokat alkalmaztak. A műhelyekben még kézműves technikákkal (manus=kéz; facere=csinálni), de már munkamegosztásban dolgoztak. A munkafolyamatot fázisokra osztották, egy-egy munkás már csak egy-egy fázist csinált. A manufaktúrákban így nagyobb tömegben, olcsóbb (persze sokszor rosszabb minőségű) árut lehetett előállítani.\n\nA XVI. században kialakuló új világgazdasági rendszer\n\nCentruma: Németalföld, Anglia, Észak-Franciaország, Észak-Itália.\n\nEzek voltak a kiemelkedően iparosodott térségek. A nemzetközi kereskedelemben iparcikk-exportőrök és mezőgazdasági termék, illetve nyersanyagimportőrök voltak.\n\nPeriféria: Kelet-Közép-Európa és Latin-Amerika. A centrum régióiba mezőgazdasági termékeket exportáltak és késztermékeket, iparcikkeket importáltak.\n\nA nagy földrajzi felfedezések, és az azt követő gyarmatosítás nyomán a középkori távolsági kereskedelemhez képest 4 fontos változás következett be:\n\n• Kereskedelmi utak átrendeződése (a Levante és a Hanza lassabban fejlődött, mint az Atlanti-óceán kereskedelme). A Hanza-városok a kontinentális munkamegosztásban közvetítők lettek, de a levantei kereskedelem leépül.\n\n• Kereskedelmi cikkek körében bekövetkezett változás: a luxuscikkek mellett fellendült a kisebb értéket képviselő tömegáru (gabona, fa, só, szövet, fémek) szállítása.\n\n• Új kereskedő nemzetek (portugálok és spanyolok, majd hollandok és angolok) és központok (Brugge, Antwerpen és Amszterdam, majd London) emelkedtek fel.\n\n• A kereskedelem új formái jelentkeztek:\n\nMonopoljoggal rendelkező társaságok szerveződtek a tengerentúli területekkel folytatandó kereskedelemre (1600: Brit Kelet-indiai Társaság; 1602: Holland Kelet-indiai Társaság; 1664: Francia Kelet-indiai Társaság).\n\nKialakult a részvénytársasági forma (a vállalkozások nagy tőkeigénye és a kockázat megosztása miatt).\n\nA középkori időszakos vásárok mellett megjelent az egész évben működő árubörze (tőzsde), ahol már csak az üzletet kötötték meg, az árucikkek ott nem cseréltek ténylegesen gazdát.\n\nÚj kereskedő dinasztiák alakultak ki (pl. augsburgi Fuggerek), amelyek azután más területeken (pénzügyek, bányászat stb.) is meghatározóvá válta\n\nA nemesfém beáramlásának gazdasági hatásai és az európai munkamegosztás alakulását a XVI. században (összefoglalás)\n\nA nemesfém beáramlása Európába Amerika felfedezése (1492) után kezdődött,\n\na nyugat-, illetve a kelet-közép-európai gazdaság fejlődése eltért egymástól.\n\nnőttek az árak, a mezőgazdasági árak növekedése meghaladta az iparcikkekét\n\naz árnövekedés fő oka a beáramló nemesfém, ugyanis árforradalom alakult ki\n\nA nemesfém spanyol amerikai gyarmatokról származott.\n\nAz élelmiszerhiány a század során nem enyhült,\n\naz élelmiszerhiányt majd csak a vetésforgó és az új növények meghonosítása, illetve az európai munkamegosztás oldotta meg.\n\nA magas mezőgazdasági árak ösztönözték a mezőgazdasági termelést Közép - Kelet - Európában\n\nLengyelországnak, a lengyel földesuraknak jelentős bevételük volt a gabonaexportból.\n\nHolland kereskedők végezték a lengyel gabonaexportot. Ez a Hanza kereskedelem bővülését eredményezte.\n\nNyugat-Európában a növekvő városi lakosság élelmiszerigénye megnőtt, ezzel összefüggésben Közép – Kelet – Európában a jobbágyokat röghöz kötötték és nőttek a jobbágyi terhek, Kelet-Közép-Európában a feudális jelleg megmaradt.\n\nNyugat-Európában létrejöttek a manufaktúrák, kibontakozott a tőkés gazdaság, bevezették a munkamegosztást, a mezőgazdaságban felszabadult munkaerő bérmunkásként áramlott az új típusú üzemekbe, olcsó tömegtermékek gyártását tették lehetővé, az olcsó ipari termékek iránt is fokozódott az igény.\n\nNyugat - Európa szerepe a világkereskedelemben: a gyarmatosítás innen indult ki, a világkereskedelmet Európa uralta, a nemesfém elosztása, felhasználása itt történt.\n\nA Távol-Kelet elsősorban luxuscikket exportált Európába, leginkább iparcikkeket exportáltak, nyersanyagokat importáltak, kialakult a kontinentális munkamegosztás, a luxuscikkekért továbbra is nemesfémmel kellett fizetni, a nemesfém révén minden kontinens között gazdasági kapcsolat alakult ki.\n\nNyugat-Európából elsősorban iparcikkeket exportáltak, és cserébe nyersanyagokat hoztak be.\n\nA gyarmatok felvevőpiacot jelentettek, a manufaktúrák tették lehetővé a tömegtermelést, kialakult az európai munkamegosztás.\n\nAmerikából nemesfémet és nyersanyagokat szállítottak Európába, és ez Európában árforradalmat, inflációt okozott. Néhány jellemző termék: cukor, dohány, indigó.\n\nAz atlanti kereskedelmet kezdetben Spanyolország és Portugália uralta. Később Anglia, Hollandia és Franciaország is bekapcsolódott.\n\nMindez elősegítette a kapitalista gazdaság kialakulását, ösztönzőleg hatott a nyugat-európai városiasodásra, a hajózási technika fejlődésére. Gyarmati, tengeri vetélkedés alakult ki. A kereskedelem hasznát befektették, kialakult a bankrendszer.\n\nÚj hajótípus volt a karavella. A hajózás a kikötővárosokban sok munkaalkalmat teremtett, megkönnyítette a városi lakosság ellátását.', 108, 1, '2026-04-17 09:40:02', '2026-04-17 09:40:02');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(2, 2, 'Magyarország gazdasága a 14-15. században', '2.docx', 'Magyarország gazdasága a 14-15. században\n\nKároly Róbert gazdasági reformjai\n\n• A XIV. század elején, Károly Róbert uralkodása idején (1308—1342) már megértek a feltételek arra, hogy a király domaniális jövedelmek helyett a regálé jövedelmekre támaszkodjon. Az Árpád-korban az állami, királyi jövedelmek fő forrása a királyi magánföldbirtok, az ún. domaniális (uradalmi) jövedelem. Kisebb részét azok a pénzjövedelmek alkották, amelyeket a király uralkodói jogán (regálé) szerzett. I. Károly gazdasági reformjának lényege, hogy az Árpádokkal ellentétben uralkodói jövedelmét a regálékra alapozta. Oka: 1301-ben kihalt az Árpád-ház, a királyi birtokállomány lecsökkent a birtokadományozások, majd pedig a kiskirályok (oligarchák vagy tartományurak) terjeszkedése miatt. A kiskirályok legyőzése után (pl. 1312-ben az Abák legyőzése a rozgonyi csatában) a megszerzett birtokokat inkább az őt támogató földesuraknak adta.\n\nA királyi jogon szerzett jövedelmek, azaz regálék: a vámok, adók, monopóliumok. A regálékra való áttérésre késztette a fejlődő árutermelés és a vele együtt terjedő pénzgazdálkodás, valamint a királyi uradalmak korábbi súlyos veszteségei. Nem mondott le a jogtalanul elidegenített királyi birtokokról sem, a levert tartományurak földjének jelentékeny részével is a királyi birtokállományt gyarapította, s ezek egy részét honorként (honorálta a hűségét), de csak használatra adta legfőbb tisztségviselőinek. Ez nem volt örökölhető, a tisztséghez kapcsolódott.\n\nGazdasági reformjai uralkodása második felében történtek. A reformok bevezetésének feltétele a királyi hatalom megszilárdítása volt. Az intézkedések célja a királyi jövedelmek növelése volt.\n\n• Reformja alapját az jelentette, hogy Magyarország gazdag volt nemesfémekben. Magyarország adta 1330-80 között Európa aranytermelésének 75%-át (2500 kg/év) és jelentős volt az ezüsttermelése is (kb. 10000 kg/év). Magyarország tehát az egyik legjelentősebb nemesfém lelőhelynek számított.\n\n• A reformfolyamatot Nekcsei Demeter tárnokmester irányította.\n\n• Bányaregálé (urbura) reformja\n\n• Az Árpád-korban a király kiváltságos bányászai a kitermelt arany l/10-ét, az ezüst 1/8-át átadták a királynak, ez volt a bányaregálé. A nemesfémbányák térbeli elhelyezkedése: Felvidék, Erdély. Károly Róbert csehországi pénzverőket telepített be az országba, ezzel a szakképzett munkaerő biztosítása volt a célja.\n\nA bányaregálét érintő változások: urbura megosztása, kötelező birtokcsere megszüntetése. Ez fellendítette a nemesfémbányászatot, a földesúrnak is érdeke lett a bányafeltárás.\n\n• Károly Róbert tehát érdekeltté akarta tenni a földesurakat a bányák nyitásában.\n\nAz addigi gyakorlattól eltérően megtarthatták azt a földterületet, ahol a bánya működött, ők maguk is nyithattak bányát, és a király lemondott a földesúr javára az urbura l/3-áról is. Elvileg így csökkent volna az urburából származó jövedelem, de a fellendülő bányászkodás, és az ebből származó többletbevételek mindezt ellensúlyozták. Károly Róbert tehát a bányabér (urbura) egyharmadát a földesuraknak adta, hogy érdekeltté tegye őket a birtokukon található bányák feltárásában, ennek köszönhetően fellendült a nemesfémbányászat.\n\n• Nemesfém és pénzverés monopóliuma\n\n• Az 1320-as évektől tilos volt a kitermelt nyersfémet adni-venni és kivinni az országból (ugyanis az addigi gyakorlat szerint a kereskedők megvették, és kivitték az országból a nemesfémet - ebből a királynak nem sok haszna származott).\n\n• A kitermelt fémet a királyi kamarák vásárolták fel, az általuk meghatározott beváltási árfolyamon, amely az ezüstnél 35%-os, az aranynál 40%-os hasznot biztosított.\n\n• A felhalmozott nemesfémből Károly Róbert új, értékálló pénzt veretett firenzei mintára (Firenzéből hozatott mestereket): az első aranyforint 1325-ben készült; váltópénzei az ezüstgaras és az ezüstdénár volt (l aranyforint = 16 ezüst garas = 96 ezüstdénár).\n\nKároly Róbert tehát aranyforintot veretett, és ez hozzájárult a kereskedelmi forgalom növekedéséhez. Az értékálló pénz a Magyar Királyság gazdasági presztízsét is javította, ennek egyik feltétele a fellendülő aranybányászat volt. A gazdasági reformokat az árutermelés és pénzgazdálkodás fejlődése tette lehetővé. Fellendült a pénzgazdálkodás és a kereskedelem. Az értékálló aranypénz miatt azonban az uralkodó elesett a pénzrontásból származó jövedelemtől.\n\n• Kapuadó bevezetése (1336)\n\n• Az új értékálló (tehát évenként már nem beváltott) aranyforint és ezüst váltópénz miatt a király elesett a kamara hasznától. Ezt pótolva vezették be a kapuadót (portális adó): minden olyan kapu után 18 ezüstdénár adót kellett fizetni jobbágyportánként évente, amelyen egy szénásszekér átfért; ahol nem volt ekkora kapu, ott csak a felét kellett fizetni. Károly Róbert tehát a bevezetett kapuadóval a pénzváltásból származó kieső jövedelmet (kamara hasznát) pótolta. A jobbágyok ezt telkenként, kapunként fizették.\n\n• Rendkívüli adó\n\n• A korábbi századokban az utazó királyi udvar vendéglátása volt szokásban. Ez megszűnt, ezt helyettesítette a rendkívüli adót.\n\n• Harmincadvám (nyugati kereskedelemből) és a huszadvám (déli kereskedelemből). A megnövekedett külkereskedelmi forgalomra kivetett határvámok voltak. Károly Róbert oklevélben biztosította a kereskedelem szabadságát. A kereskedőknek vámot kellett fizetni, melynek hatására a kereskedelem fejlődött, királyi jövedelmek növekedtek.\n\n• Esetenként lefoglalta a pápaságnak juttatott tizedrészt (általában a tized l/3-a, amire a pápaság rendkívüli események idején igényt tartott).\n\nA szászok, jászok, hunok és egyéb kiváltságolt elemek és a városok adói.\n\nKiváltságosok és a városok adói:\n\nA legnagyobb városok (Buda, Pest) együttes lakossága 15-25 ezer lehetett.\n\nA határszéli városok zöme német anyanyelvű volt, a középkor végén Budán már a magyarok voltak többségben (Szeged, Székesfehérvár, Esztergom, Pest magyar város volt).\n\nA lakosság zöme mezőgazdaságból élt, különösen fontos szerepe volt a szőlőművelésnek, amely lehetőséget nyújtott a borkereskedelem kialakítására.\n\n• Céhes ipar\n\n• A XIV. században, Nagy Lajos korában megjelentek a céhek is, de számuk és politikai súlyuk elmaradt a nyugat-európai céhekétől.\n\n• A városok éltető eleme a távolsági kereskedelem volt, a kézműiparnak kisebb volt a szerepe.\n\n• A mezőváros, vagy agrárváros (oppidum) földesúri hatalom alatt álló, nagyra nőtt falu volt, amely rendelkezett a piactartás és általában az egyösszegű adófizetés jogával. Később bírót és tisztviselőket is szabadon választhattak, és így korlátozott önkormányzati jogokhoz jutottak.\n\n• A mezővárosok XIV. századi nagy számú megjelenése a távolsági kereskedelem fellendülésének volt köszönhető.\n\n• A piacokat tartó mezővárosokban idővel megjelent a szolgáltató ipar (kádár, kovács, szabó, kötélverő stb.) is. A mezővárosok általában nem voltak fallal körülvéve (a mezőváros elnevezés is erre utal - a település a nyílt mezőn, nem falak között terül el).\n\n• Szabad királyi városok\n\n• Legelőkelőbb csoportja a tárnokmester bírósága alá tartozó nyolc, fallal körülvett város: Buda, Pozsony, Nagyszombat, Sopron, Kassa, Bártfa, Eperjes és Mátyás király korától Pest.\n\n• Ugyancsak jelentős város volt az erdélyi szászok 3 nagy városa: Nagyszeben, Brassó és Beszterce.\n\n• Másodrangú királyi városnak számítottak az un. személynöki városok: Zágráb, Székesfehérvár, Esztergom, Lőcse, Visegrád, Kolozsvár, illetve néhány mezővárosi jellegű város (Szeged).\n\nA nemesfémbányászat fellendülésével a Felvidéken és Erdélyben bányavárosok jöttek létre nagy számban. „Szabad” bányavárosok:\n\n• keleten: Nagybánya és Felsőbánya;\n\n• alsó-magyarországi bányavárosok: Körmöc-, Selmec-, Beszterce-, Baka-, Libet-, Új- és Bélabánya.\n\nÉrtékelése:\n\nGazdasági reformjai serkentették az árutermelést és pénzgazdálkodást. Nagyszabású reformokat vezetett be. Az ország vezetésében minden jelentős tisztség új kezekbe került, visszaállt a királyi birtokok 50 százalékos aránya. A várak birtoklása a hivatalhoz kapcsolódott, ami a királyi akarat érvényesítését könnyítette meg.\n\nAz elnéptelenedett területeket elsősorban német telepesekkel telepítette be, akik gyakran tíz évig adómentességet élveztek. A Felvidékre a németeken kívül sok morva és lengyel telepes érkezett.\n\nAz udvari bevételek fokozása céljából az Anjouk számos várost és falut vontak ki a földesurak fennhatósága alól. A szabad királyi városok csoportja a fallal is körülvett településekből alakult ki. A városfejlődést azonban nem lehetett pusztán adminisztratív intézkedésekkel gyorsítani. Somogy és Zala térségében egyáltalán nem voltak városok, de a másutt meglévőkben élő polgárság súlya sem vetekedhetett a nyugat-európai polgárságéval.\n\nA világviszonylatban kiemelkedő magyar aranytermelés pénzügyi reformot tett lehetővé. Az új magyar aranyforint Európa megbecsült pénzévé vált. A nemesfém-kitermelés fokozására alapította Károly Róbert a Felvidéken Körmöcbányát, mely évszázadokra a bányavárosok központja maradt.\n\nAz uralkodói jövedelmek növelése érdekében eltörölte a bányamonopóliumot, a korábbi teljes elkobzás helyett bevezette az urburát, amely legfeljebb egynyolcada volt a kitermelt ércnek, így a földbirtokos érdekeltté vált a bányafeltárásban. A kincstár helyzete jelentősen javult a sóregálék bevezetése révén, az újjászervezett harmincadvám a kereskedelem hasznát fölözte le, a kapuadó a pénzbeváltás jövedelmét pótolta. A pápa jóváhagyásával a király az egyházi jövedelmek egy részéhez is hozzájutott.\n\nAz Anjouk gyakori háborúskodása vélhetően nem ingatta meg a kincstár anyagi helyzetét, hiszen Károly Róbert és utóda, I. (Nagy) Lajos a nemesi felkelést vette igénybe, ami ellenkezett ugyan az Aranybullában leírt jogokkal, viszont megfelelt a tényleges hatalmi helyzetnek. Fontos volt az udvari lovagság szerepe is.\n\nA pezsgő gazdasági élet föllendítette a külkereskedelmet is. Magyarország hátrányos helyzetben volt Bécs árumegállító joga miatt. Előnyösebb helyzetet sikerült teremteni az 1335-ös visegrádi királytalálkozón, ahol Károly Róbert Luxemburgi János cseh és III. Kázmér lengyel királlyal kötött kereskedelmi egyezményt. Károly Róbert így halálakor nemzetközileg elismert, belpolitikailag szilárd államot hagyott fiára, I. Lajosra.\n\nI. Lajos (1342-1382) az ország erejét hódító háborúkra használta fel. A nápolyi trónért folytatott két hadjárata inkább izgalmakban bővelkedett, mintsem eredményekben; a távoli országot nem sikerült megszerezni. Meghódította viszont Bulgária északi részét, Szerbiát és Boszniát. Ahogy a betelepített területeken is egyre sűrűbb lett a lakosság, a földesurak már kevésbé voltak „kiszolgáltatva\" jobbágyaiknak, fokozták a terheket. A szolgáltatások növelése főleg a kevésbé tehetős, tehát kevesebb jobbággyal rendelkező földesuraknak állt érdekében, az ő birtokaikról volt a leggyakoribb a jobbágyok elvándorlása. Nagy Lajos 1351-ben vitathatatlanul a kevésbé módos földesurak védelmében intézkedett, amikor elrendelte a kilenced egységes beszedését, így jogilag is egységes jobbágyság jött létre. Az 1351. évi törvények az Aranybullát újították fel, s az azonos jogú nemesség elvének megfogalmazásán kívül kimondták a nemesi birtok elidegeníthetetlenségét, az ősiség törvényét. A nemzetség kihalása után a birtok a királyra szállt vissza (háramlási jog). A Nagy Lajos halála utáni évtizedekből arra következtethetünk, hogy a köznemességet védő törvényeket, a kilencedet és az ősiséget a király a hatalomból ismét nagyobb részt kérő bárók ellensúlyozására hozta; velük szemben kereste a köznemesek szövetségét.\n\nFelértékelődön a kézművesség, terjedőben volt a céhes termelés és a felvásárlási rendszer. A király támaszát képező szabad királyi városok száma is emelkedett.\n\nLuxemburgi Zsigmond (1387-1437)\n\nA bárói függés megszüntetése és a központi hatalom megszilárdítása új szövetségeseket igényelt: Zsigmond kiemelkedően pártolta a városok fejlődéséi, kiváltságokat adott nekik (pl. a vámmentes kereskedelem jogát) és meghívta képviselőiket az 1435-ös országgyűlésre, segítve ezzel renddé szerveződésüket. A kereskedelem ösztönzésére támogatta a súly- és mértékrendszer egységesítését.\n\nA folyamatos pénzhiány miatt azonban gyakran folyamodott a városok elzálogosításához és a pénzrontás eszközéhez. Utóbbi a pénzgazdálkodás elterjedése miatt a birtokok szétaprózódásához (zselléresedés) vezetett, ami tovább mélyítette a társadalmi ellentéteket. Az 1437-es Budai Nagy Antal-féle parasztfelkelés Erdélyben azért tört ki, mert Lépes György erdélyi püspök 3 évre visszamenőleg pénzben kérte a tized fizetését a parasztságtól.\n\nI. (Hunyadi) Mátyás (1458-1490)\n\nMátyás király uralkodásának kezdetén még kb. 250 000 aranyforint jövedelemmel rendelkezett. A centralizált, kora abszolutisztikus kormányzás során a hatalmas állami bevétel (500-750 ezer arany) a jobbágyi terhek növelésének volt köszönhető. Nőtt a népesség (3,5-4 millió főre), egyre többen laktak mezővárosokban. Elterjedt a háromnyomásos gazdálkodás, jelentős volt az állattartás (szarvasmarha, sertés, ló, baromfi). Élénkültek a gazdasági kapcsolatok, a kézművesipar azonban nem tudta kielégíteni az igényeket, így folyamatos behozatalra szorult.\n\nMátyás célja az adóreformok terén az volt, hogy kivonja a rendek ellenőrzése alól a jövedelmeket. Ambiciózus külpolitikai vállalkozásaihoz több bevételt kellett a kincstár számára biztosítani, így Mátyás megszüntette több társadalmi csoport adómentességét. Az adóalap növelésére szolgált az 1467-ben bevezetett füstpénz, amit már jobbágyháztartásonként (tehát a korábbinál kisebb egységekben) szedtek, mely évi 20 dénár volt. Megadóztatta az egytelkes nemességet és a városokat is. A harmincadvámot koronavámra keresztelték át. A legfontosabb bevételt a rendkívüli hadiadó jelentette, amit szükség esetén évente kétszer is beszedethetett.\n\nMátyás király gazdasági intézkedéseinek céljai tehát:\n\n• kivonni a jövedelmek nagy részét a rendek és a bárók ellenőrzése alól. Ezért felállította a kincstartóságot, amelynek élére köznemesi és polgári származású szakemberek kerültek (pl. Ernuszt János);\n\n• növelni a királyi kincstár bevételeit:\n\n— az 1467-es országgyűlésen megszűntették a kamara hasznát;\n\n— új néven és új módon vetették ki a kapuadót: királyi kincstár adója, amelyet már nem portánként, hanem családonként szedtek be (füstpénz = l család: l kémény, évi 20 dénár);\n\n— a harmincadvámot is új néven — koronavám — szedték be: így az addig a fizetése alól mentességet szerzetteknek is újra fizetniük kellett.\n\n• Jövedelmei: évi 500—750 ezer aranyforint (kb. kétszerese a Zsigmond kori királyi bevételeknek), de: rendszertelenül folyt be, nagy részét a hadsereg fenntartása emésztette fel.\n\n• Államszervezeti reformok\n\nItt is a báróktól való függetlenedésre törekedett:\n\n— összevonta a nagykancelláriát és a titkos kancelláriát, létrehozta az új, királyi kancelláriát élére Vitéz Jánost nevezte ki;\n\n— átszervezte a bíróságokat is: megalakult a királyi személyes jelenlét bírósága, amelynek az élére a személynök került.\n\n• Katonai reformok\n\n• Zsoldossereg (fekete sereg) felállítása:\n\n— háború esetén 15—20 ezer fős volt; magját Giskra huszita harcosai jelentették, de lengyel, német zsoldosok is voltak; 4 fegyvernem: nehézlovasság, könnyűlovasság, gyalogság, tüzérség. Hadvezérei: Magyar Balázs, Kinizsi Pál, Hág Ferenc, Haugwitz János. A katonaság finanszírozásához stabil jövedelemre volt szüksége. Ennek köszönhetően folytatta a déli végvárrendszer kiépítését:\n\n— külső vonal: az Al-Dunától az Adriáig (Nándorfehérvár, Szabács, Jajca, Knin, Kiissza);\n\n— belső vonal (Karánsebes, Lúgos, Temesvár, Pétervárad, Bihács).\n\nKözpontosító belpolitikája, a korban kötelező fejedelmi pompa (építkezések, művészetpártolás stb.), a török felé védekező, nyugat felé támadó hadjáratok ennél lényegesen nagyobb összegeket követeltek meg.\n\nAz egyház egész Európában adómentességet élvezett. A magyar nemességnek az Aranybullában rögzített adómentessége is megtámadhatatlan volt, így az adóterhek a jobbágyságra, valamint a városi iparosokra és kereskedőkre nehezedtek. A jobbágy adóalapja a telek, amely után 20 dénár (0,2 aranyforint) pénzadót fizetett a királyi adószedőknek. A városok egy összegben adóztak. (Buda évi 4000, Szeged 2000, Pozsony 400, Kolozsvár csak 200 arannyal tartozott.)\n\nAz adóbevételekhez társultak a kizárólag a királyt illető regálejövedelmek (vám, só, nemesfémek, pénzverés). Mátyás számíthatott a királyi birtokok hozamára is. A rendkívüli jövedelmek kiegészítették a királyi költségvetést. Az adók emelése elvileg az országgyűlés hozzájárulásához volt kötve. Mátyás ennek birtokában vetette ki az évi l forintos hadiadót. (Igaz, csak egyszeri alkalomra, utána azonban ünnepélyes ígérete ellenére többször is behajtotta.) Jövedelemnövelő hatású volt az 1467-és kincstári reform. Ennek keretében az adók és vámok összege ugyan nem változott, de a jövedelmek nevének megváltoztatásával (pl. „kamaranyereség\" helyett „királyi kincstár adója\") minden korábbi mentességet eltöröltek, és az adókat szigorúan behajtották.\n\nÍgy a király évi rendszeres jövedelme kb. 600.000 aranyra, a rendkívüli jövedelmekkel tetézett összjövedelme kb. 700.000 aranyra emelkedett az 1470-1480-as években. Európai összehasonlításban az összeg nem csekély: a kortárs francia király l millió, a spanyol 800.000, az angol 700.000 arannyal rendelkezett évente.\n\nA királyi bevételek arányai tükrözik az ország gazdasági szerkezetét. A jövedelmek 60%-a a mezőgazdaságból származik; nemcsak a jobbágyi adók, hanem a városok és a szászok adójának egy része is agrárjellegű. Az adóemelések is elsősorban a jobbágyságot terhelték, amelynek adózó képességét nagymértékben, de még elviselhetően tették próbára. (Viszonyításul: l aranyforint volt pl. egy vágómarha ára. A becslések szerint a királyi, egyházi és földesúri terhek a jobbágygazdaságban megtermelt érték kb. 42%-át vitték el évente.)\n\nA városi ipartól - fejletlensége miatt - nem lehetett nagyobb jövedelmeket várni. A külkereskedelmi vám összege nem változott Mátyás uralkodása alatt. A nálunk iparilag fejlettebb országok piacán a szarvasmarhán, boron és néhány ipari félkész terméken kívül mással nem tudtunk megjelenni. Innen a negatív külkereskedelmi mérleg, a nemesfém állandó kiáramlása. (Becslések szerint a behozatal értéke kétszeresen múlta felül a kivitelét.) Mivel a nagy kereskedelmi útvonalak elkerülték hazánkat, az átmenő forgalmat sem lehetett megvámolni.\n\nMátyás gazdaságpolitikájának összefoglalása\n\nElhelyezés időben: Hunyadi Mátyás 1458–90 között uralkodott Magyarországon.\n\nTérbeli jellemzők: uralkodói székhelyek Visegrádon és Budán, jelentős végvárak pl. Nándorfehérvár, bányavidékek a Felvidéken, sókitermelés Erdélyben, elsősorban nyugat-északnyugat irányú kereskedelem.\n\nBEVÉTELEI:\n\nBevételeinek egy része királyi regálékból, más része birtokaiból származó jövedelem.\n\nA füstpénz fizetésének módja: telek és családszám alapján fizették. Egyben növelte a füstpénz összegét. A változtatással növelte a bevételeit, egyben megszüntette a korábbi mentességeket. A korábbi kapuadót még a pénzverés fedezetére szedték, I. Károly vezette be. A harmincadvámból koronavám lesz: elsősorban nyugat-északnyugat irányú kereskedelem.\n\nA Hunyadi-család jelentős birtokokkal rendelkezett az ország délkeleti részén. Hunyadi János a legjelentősebb báró, nagybirtokos volt. Ehhez járultak még – a már csekélyebb méretű – királyi birtokok; az ebből származó jövedelem mégsem volt jelentős; főleg terményjövedelem származott belőle.\n\nJövedelmeinek felét jelentős részét a rendkívüli hadiadó adta, évente beszedte; a legjelentősebb jobbágyi adó volt; a török fenyegetéssel indokolta a beszedését. A nyugati hadjáratai is kiadással jártak.\n\nEgyéb jövedelmei: bányamonopólium - bányavidékek a Felvidéken, sómonopólium - sókitermelés Erdélyben.\n\nLétrejött a kincstartóság; állandó bírói fórumok létesültek; polgárok, jobbágyok is hivatalt szerezhettek. Mátyás fizetett hivatalnokokat alkalmazott; központosított hatalmának támaszai voltak ezek az intézmények.\n\nKIADÁSAI:\n\nÁllandó zsoldoshadsereget tartott fenn (fekete sereg), ezzel is erősítette központosított hatalmát; nyugati hódításokra használta; modern szerkezetű, fegyverzetű hadsereg volt.\n\nMagyarország déli határán végvárak épültek, a török veszély miatt volt rá szükség; kettős végvárvonal alakult ki; ez váltotta fel, egészítette ki az ütközőállamok rendszerét; Mátyás a végvárrendszer kiegészítésére törekedett. Jelentős végvár Nándorfehérvár.\n\nReneszánsz udvart tartott fenn pl. palota építése Visegrádon, Budán; humanista tudósok foglalkoztatása; feleségének, Beatrixnek a hatása; Corvina könyvtár létesítése; a királyi udvar reprezentációs célokat is szolgált.\n\nSZENT ISTVÁN, KÁROLY RÓBERT ÉS MÁTYÁS KIRÁLY GAZDASÁG-POLITIKÁJÁNAK ÖSSZEHASONLÍTÁSA\n\nIstván jövedelmeinek legnagyobb része a királyi birtokokról származott. A birtokok gondoskodtak a vándorló udvar ellátásáról. A jövedelmek jelentős része terményben folyt be. A jövedelmeket a várnépek termelték, az ispánok a beszedett jövedelem kétharmadát szolgáltatták be. István a királyi javak közé sorolta a várbirtokon élőket is. Büntette a sikkasztó ispánokat, és törvényekkel védte az uralkodói vagyont, igyekezett biztosítani, hogy az uralkodói jövedelmek befolyjanak.\n\nKároly Róbert idején, a királyi felségjogon szedett regálé jövedelmek kerülnek előtérbe. Ez a királyi birtokok csökkenésével magyarázható. A városok fejlődése, a kereskedelem fellendülése, a harmincad bevezetése növelte a regálé jövedelmeket. Fontos regálé jövedelem származott a sóbányászatból. A regálé jövedelmek többsége vámokból és monopóliumokból származott, és a jövedelmek legnagyobb része pénzben folyt be. Károly Róbert idején a bányászok bányabért, azaz urburát fizettek a királynak, a földbirtokosok pedig megkapták a bányabér egyharmadát. Fellendült a nemesfém-bányászat. A bányászat egyébként királyi monopólium volt. A kapuadót portánként, azaz jobbágytelkenként szedték. A kamaraispánok szedték be és a jobbágyok fizették. Ez volt a jobbágyok első állami adója. Károly Róbert a kamara haszna, a pénzváltási illeték pótlására vezette be.\n\nMátyás növelte az uralkodói jövedelmeket. A jövedelmek növekedéséhez hozzájárult a népesség növekedése. A jövedelmek növekedése azonban nagyobb arányú volt a népesség növekedésénél. Mátyás jövedelmeinek legnagyobb részét a rendkívüli hadiadó tette ki. Ezt hivatalosan a hadjáratok költségeinek fedezésére szedte, gyakran évente többször is beszedte. Ezzel a jobbágyok adóztatására helyeződött a hangsúly. Bevezette a harmincadvám helyett a koronavámot, a kapuadó helyett pedig a füstpénz beszedését. A füstpénzt házanként szedték be a jobbágyoktól, azaz jobbágyháztartásonként. Az árutermelés fellendülése növelte a jövedelmeket. Mátyás megszüntette a korábbi mentességeket, és szakértő kincstartókat alkalmazott.\n\nTehát István korában a királyi birtokból, Károly Róbert idején a regálékból, míg Mátyás alatt a pénzadókból folyt be a legtöbb királyi jövedelem. A királyi jövedelmek az idők során növekedtek, de a királyi birtokállomány folyamatosan csökkent. A pénzbeli jövedelmek aránya folyamatosan nőtt. A jövedelmi szerkezet változásának oka a gazdasági fejlődés. István törvénye védte a királyi birtokot, az Árpád-korban a megművelhető földek zöme a királyi birtok volt, így a királyi jövedelmek zömét a birtokok terményszolgáltatása jelentette. Az Árpád-kori királyi jövedelmek sajátossága a birtokok terményszolgáltatása. Ennek oka a fejletlen árutermelés és a csekély pénzforgalom. Károly Róbert megszüntette a kötelező birtokcserét és megosztotta az urburát, ezzel érdekeltté tette a birtokosokat a bányanyitásban. Az Anjou uralkodók legfontosabb bevételi forrásai a regálék voltak (ásványkincsek, kereskedelmi haszon, pénzverés). Ennek okai: a pénzgazdálkodás fejlődése, a városi fejlődés megindulása és a királyi birtokállomány csökkenése. A királyi birtokállomány csökkenésével párhuzamosan nő a többi jövedelemforrás jelentősége. Mátyás a füstpénz fizetését telekmérethez és családszámhoz, azaz a háztartások számához kötötte. A királyi jövedelmek zömét a jobbágyok pénzadói tették ki, mint pl. a jobbágyság által fizetett rendkívüli hadiadó. Ennek okai: a hódítások és az egyre bővülő árutermelés. Ez a jövedelem európai összehasonlításban is magasnak tekinthető. Mátyás bizonyos jövedelmeket átnevezett: a kapuadóból füstpénz, harmincadvámból koronavám lett, és megszüntette a korábbi mentességeket\n\nGazdasági helyzet a Jagellók idején a XV. század végén\n\nII. Ulászlónak (1490-1516) a rendek a következő feltételeket szabták:\n\nsaját költségére megvédi az országot,\n\nnem szedi be a Mátyás alatt megszokottá vált rendkívüli hadiadót,\n\nminden fontos kérdésben előzetesen kikéri a rendek véleményét.\n\nA királyi hatalom szétesett. Belső bázissal nem rendelkezett, így nem volt ereje ahhoz, hogy ígérete ellenére beszedesse a rendkívüli hadiadót, nem tarthatott zsoldossereget. A királyi jövedelmek negyedükre csökkentek, s alig haladták meg a 200 000 aranyforintot. Éppen csak arra voltak elegendőek - a Csehországból származó pénzekkel együtt. A fekete sereget szétoszlatták, hiszen zsoldot nem tudtak nekik fizetni, a maradékot a Délvidékre a török ellen küldték. A fizetetlen zsoldosok a Száva menti lakosságon élősködtek, így a térség népének megváltás volt, amikor az egykori vezér, Kinizsi Pál csapatai 1492-ben a Valkó vármegyei Halászfalu mellett szétverték a hajdan dicső sereg maradékait. A csatának nézői is akadtak: a törökök a folyó túlsó partján.\n\nRENDI KÜZDELMEK\n\nA tényleges hatalom a királyi tanács, a bárók kezében volt. Velük szemben az egyetlen szervezett erő a nemesség volt. A mohácsi csatáig tartó Jagelló-kor a nemesség két pártjának folyamatos küzdelmét eredményezte. A mátyási reformokat fölszámolták, a királyi jövedelmek a negyedükre csökkentek.\n\nA JOBBÁGYSÁG HELYZETE\n\nA XVI. század elején a népesség növekedésével együtt a parasztság tovább differenciálódott: vékony gazdagparaszti réteg alakult ki, amely már béresekkel is dolgoztatott, ugyanakkor tömegek váltak zsellérré, vagyis 1/8 teleknél kisebb birtokú jobbággyá.\n\nA túladóztatás miatt a Mátyás korában megkezdődött folyamat, a pusztásodás, a jobbágyföldek elhagyása tovább folytatódott. A telkek száma a XV. század eleji 400 000-ről 300 000 alá csökkent. Ez a visszaesés részben valóságos termeléskiesést mutat, részben a nemesek és a jobbágyok közös adócsalását. A termőföldeket kivették a teleknyilvántartásból.\n\nA parasztság legmódosabb elemeit zárta el a további felemelkedéstől a mezővárosok adózására vonatkozó törvény. A mezővárosi lakosságot is fejenkénti adózásra kötelezte, vagyis a nagyobb egyéni jövedelmeket elvonta. A parasztság eltiltása a vadászattól és a halászattól a jobbágyság legszegényebb rétegeit sújtotta. Az egész parasztság helyzetét nehezítette meg a szabad költözés korlátozása.\n\nKERESZTES HADJÁRATBÓL PARASZTFELKELÉS\n\nMátyás halála után a jobbágyság terhei nem változtak, de megszűnt a biztonság. A nemesek akadályozták a jobbágyok szabad költözését, elvették a piacra vihető cikkeket, belső vámhelyeket hoztak létre, megnyirbálták a mezővárosok kiváltságait, tovább folytatódott a zselléresedés. A fokozódó társadalmi feszültségek a Dózsa-féle parasztfelkeléshez vezettek, amelynek leverése (1514) után a jobbágyság „büntetésből” röghöz kötötté vált, és a robotot is növelték.\n\nEnnek előzménye: Bakócz Tamás esztergomi érsek keresztes hadjárat szervezését kapta feladatul a török ellen. A jobbágyság nagy számban állt a zászlók alá. Bakócz nem talált megfelelő, tekintélyes főnemesi vezetőt a had élére, s egy végvári katonát, Dózsa Györgyöt bízta meg a vezetéssel. Dózsa feltehetően székely családból származó végvári harcos volt, akit vitézsége emelt ki az egyszerű katonák közül. A Pest környékén összegyűlt keresztesek egy részével Dózsa megindult dél felé a török ellen, ám menet közben a parasztok uraik ellen fordultak. Temesvárnál a török földről visszatérő Szapolyai János erdélyi vajda hadai a felkelőket leverték. Dózsát és alvezéreit halálra ítélték. A fizikai megtorlás mellett a nemesek a törvény erejével is büntetni akartak. A rendelkezések elsősorban a nemesség gazdasági érdekeit fejezik ki a terhek emelésével, a költözés tilalmával és a robot emelésével.\n\n1514-es paraszttörvények végrehajtása azonban a török háborúk során hosszú ideig nem volt időszerű. Werbőczy István Tripartitumában (Hármaskönyvében) is megjelentek a parasztságra vonatkozó törvények. A Tripartitum egyben összefoglalta a korabeli szokásjogot is. Ezzel Magyarországon megmerevedtek a feudális viszonyok. Míg Nyugat-Európában a parasztság nagy része bérlővé válik a század végére, és felszámolják a feudális viszonyokat, addig Kelet-Közép-Európában második jobbágyságról beszélhetünk, ahol a jobbágyi terhek megerősödnek, a robotmunka kiterjesztése és a szabad költözködés megvonása a földesúri hatalom megerősödését eredményezi.', 114, 1, '2026-04-17 09:40:02', '2026-04-17 09:40:02');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(3, 3, 'A világgazdaság a 20-21. században', '3.docx', '3. tétel: A világgazdaság a 20-21. században\n\n(világgazdasági válság, európai integráció, a világgazdaság átalakulása az ezredfordulón: hagyományos és új centrumok, a globális gazdaság)\n\nAz első világháború utáni helyzet: az 1920-as évek (mindegyik elé jó)\n\n1. Európai országok a háború alatt áruhiánnyal küzdöttek, és ez a béke után sem változott, infláció, fedezetlen pénzkibocsátás (aranytartalékok kimerültek, egyszerűen csak nyomtatták a pénzt, letértek az aranyalapról az USA kivételével). Legjelentősebb inflációs térség Közép-Kelet-Európa volt (németországi helyzet), sok országban valutát kellett cserélni, hogy stabilizálják a pénzügyet. Anglia 1925-ben, Franciaország 1928-ban tudott visszatérni az aranyalaphoz (a Dawes-terv segítségével).\n\n2. Hadigazdálkodásról vissza kellett térni polgári gazdaságba, ami munkanélküliséget okozott, az infláció miatt beszűkült a piac (a felvásárló-réteg szűkült).\n\n3. A győztesek a Németországra és csatlósaira kirótt jóvátételi összegektől várta a helyzet javulását, azonban a vesztesek is ugyanazokkal a gondokkal küzdöttek. (franciák a Ruhr-vidéket megszállják, hogy ezzel Németországot fizetésre kényszerítsék 1923-ban, azonban a németek nem tettek semmit, a megszállás túl sok pénzbe került, nem lett eredménye, a franciák visszavonultak.)\n\n4. Háború alatt csökkent az élelmiszertermelés, a gyarmatokkal rendelkező országok a megszállt területekről hozatták az ételt, a kereslet nőtt, de a fizetőképesség - az infláció és a munkanélküliség miatt - alacsony volt, ezért a gazdasági áruk ára is csökkent. Az európai termelés csak az 1920-as évek közepére állt helyre, azonban túltermelésbe kezdtek, ami tovább csökkentette az árakat. A mezőgazdasági exportőrök komoly gondokkal küszködtek a felesleg miatt, kialakult a tömegtermelés, a monopolizáció erőteljes volt, de a kisipar sem tűnt el (helyi szinten maradt meg).\n\n5. Dawes-terv:\n\nAz első világháborúba való belépésével (1917) az USA kilépett izolációs politikájából, s hozzájárul az antant hatalmak győzelméhez. A versailles-i béketárgyalások résztvevője, Wilson elnök 14 pontja a háború békés megoldását kínálja, mint pl. a nemzetek önrendelkezési joga. A háború után támogatja az európai államokat. Az európai gazdaság nehéz helyzetbe kerülése az USA számára is kedvezőtlen volt, nem érkeztek vissza a kölcsönösszegek. 1923-ban jóvátételi konferenciát rendeztek, ahol egy Dawes nevű közgazdász javaslatára kidolgozták a Dawes-tervet, ami annyit jelentett, hogy Amerika befektetőként lép fel a válságos időben, újabb kölcsönnel és tőkével segíti Európát, innentől kezdve az európai gazdaság amerikai tőkén nyugodott. Tehát lényege: a szilárd valuta és a normalizált gazdaság megteremtése jelentős összegű kölcsönök segítségével. A terv alapján 1924-25-ben Németország milliárdos nagyságrendű hitelt kapott az USA-tól. Következménye: megszilárdult a márka, stabilizálódott a gazdaság, politikai konszolidáció. A jóvátételt így fizetni tudta Németország Angliának és Franciaországnak, ezek az államok pedig így vissza tudták fizetni az USA háborús hiteleit.\n\n6. Ipar: hanyatlott a vas-acélipar, bányászat, ugyanakkor a modernebb ágazatok, autógyártás, villamosgép-gyártás, alumíniumkohászat, vegyipar gyorsan fejlődött.\n\n7. Az államok feladata: visszaállítani a hadigazdaságot békebeli termelésre, irányítsa az újjáépítést, a kölcsönök és befektetések révén újra lendületbe hozni a gazdaságot, ezt legtöbbször állami megrendelésekkel érték el. Európában megnövekedtek a vámhatárok, a békeszerződések után létrehozott országok, új gazdasági egységek miatt nem 26, hanem most már 38 új gazdasági egység lépett be a rendszerbe, s ezért az új kisállamok protekcionista politikát folytattak, bezárkóztak és megválogatták kereskedőpartnereiket.\n\n8. Politikai irányzatok változása: Az első világháború után kialakult válságos helyzetben előtérbe kerültek a szélsőjobb-baloldali pártok, és a nemzetek különleges mivoltát hirdették. Ezek a pártok a fennálló politikai rendeket (alkotmányos alapokat) akarták eltörölni, és diktatúra bevezetését tűzték ki célul. A szélsőséges pártok a politika eszközeivel (nemzeti-szociális demagógia, népvezér-kultusz) tömegpártokká nőttek, esetenként párthadsereggel rendelkeztek (Hitler: SA, SS). A háború után Oroszországban bolsevik diktatúra létesült, Olaszországban a fasiszta Mussolini került hatalomra. Térnyerésüket azonban csak a gazdasági nehézségeknek, a nép, a tömegek életkörülményeinek, biztonságának romlásának köszönhették (békés körülmények között az ember nem gyűlölködik ennyire). A húszas években a stabilizálódó gazdaság azonban javította az életkörülményeket, emellett a nők választójoghoz jutása is segítette a szélsőséges pártok visszaszorítását (pl. Nagy Britanniában).\n\nA világgazdasági válság\n\nUSA:\n\n1929-ben az USA-ban robban ki a világgazdasági válság, mely az egész világ gazdaságának működését meghatározza. A New York-i tőzsdekrach oka a túltermelési válság volt, ennek következtében leállt a termelés, bezártak az üzemek, gyárak, sok ember lett munkanélküli, amely még inkább mélyítette a válságot, mely 1933-ig tartott. Mindez továbbgyűrűződött egész Európára.\n\nAlapfogalmai: világgazdaság: egyes nemzetgazdaságok közti kapcsolatok összessége. A válság: a gazdaság és társadalom valamely területén fellépő egyensúly hiány (a válság általános szakaszai: válság, pangás, felélénkülés, fellendülés.\n\nOkai: a kapitalizmus alapvető ellentmondásai, a termelés – fogyasztás közti aránytalanság és a pénzügyi spekulációk. Az 1920-as évek második felében a gazdasági konjunktúrának köszönhetően az USA sokmilliárdos kölcsönöket folyósított, gazdasági befolyást gyakorolt Európára, melyet fogyasztópiacának tekintett. A termelés üteme az európai gazdaságok beindulása után nem csökkent az USA-ban, így az meghaladta a fogyasztás ütemét, s így túltermelés alakult ki. Eladhatatlan árukészletek halmozódtak fel. Az USA gazdasági változásai világméretű következményekkel jártak.\n\nA tőzsdekrach: a New York-i tőzsdén 1929. október 24-én (fekete csütörtök) a részvények 40-60%-os árzuhanása következett be.\n\nA válság kibontakozása:\n\nFizetésképtelenné váltak a bankok. A tőkét pedig kivonták a beruházásokból.\n\nA részvények árfolyama megingott, majd áruk zuhanni kezdett, mindenki el akarta adni értékpapírjait. A kínálat rohamosan felülmúlta a keresletet\n\nLeállt a fogyasztási cikkeket gyártó ipar és a nyersanyag-kitermelés egy része.\n\nCsökkent az USA-ban az építkezések száma és a tartós fogyasztási cikkek eladása\n\nAz ipari válság összekapcsolódott a mezőgazdasággal, amely szintén értékesítési gondokkal küzdött: az árukészletek felhalmozódtak, eladhatatlanná váltak, áraik zuhanni kezdtek, összeomlott a pénzügyi és a kereskedelmi világ\n\nMindenki ki akarta venni a pénzét, a hitelrendszer összeomlott.\n\nA bel- és külkereskedelem működésképtelenné vált\n\nA vállalatok leálltak, a felesleges munkaerőt elküldték, a munkanélküliség nőtt, vásárlóképesség csökkent (pl.: USA 1929-33 között 1,5 millió -12,8 millió)\n\nA válság az USA-ból átterjedt Európára\n\nMegszűnt a tőkeexport az USA-ból, az amerikai bankok felmondták, az európai hiteleket. Különösen súlyossá vált az osztrák és német pénzügyi helyzet. A világon mintegy 30 millióan maradtak munka nélkül, 1929-35 között a világkereskedelem 65%-kal esett vissza.\n\n- Társadalmi következmények: a kis- és középüzemek tönkrementek, további tőkekoncentráció történt. Munkanélküliség, létbizonytalanság tovább súlyosbította a válságot általános elégedetlenség alakult ki.\n\nPolitikai hatások: szélsőséges politikai irányzatok felerősödése pl. szélsőjobb: fasizmus; szélsőbal: kommunizmus. Megváltozott az állam gazdasági szerepe. Európában munkanélküliség, infláció, hitelekkel, megrendelésekkel stabilizálják a gazdaságokat egyenként, levezetődik a felesleg, de nemzetgazdaságok alakulnak ki a fasiszta eszmék miatt.\n\nA kibontakozás útja az USA-ban – A New Deal, 1933\n\n1929-től 1932-re 73%-kal esett vissza fogyasztási cikkek termelése. A válság mélypontján, 1932 végén Franklin Delano Roosevelt lett az USA elnöke, aki demokrata párti politikus volt. A kongresszus elfogadta a New Dealt (Új irányvonal), melyet egy agytröszt dolgozott ki (egy gazdasági szakemberekből álló csapat) Lényege: az állam közvetlen beavatkozása a gazdaságba. Keynes angol közgazdász elméletét alkalmazták.\n\nKeynes (angol közgazdász) növekedés elmélete szerint:\n\nAz állam gazdaságirányító és koordináló szerepét növelnie kell. Az államnak meg kell teremtenie a konjunktúrához szükséges keresletet. Olyan munkaalkalmakat kell teremteni, ami 1. megélhetést nyújt a dolgozóknak, 2. bővíti a keresletet, 3. de nem növeli túlzottan az árukínálatot. Infrastrukturális beruházásokra van szükség, szociális intézményekre. Az állam közvetlenül részt vesz a termelésben részvények felvásárlásával. Egyes vállalatok, illetve iparágak támogatásával közvetlenül is részt vesz a termelésben és a forgalomban. Az állam befolyásolja a pénz- és hitelforgalmat, a külkereskedelmet, ellenőrzi az árak és bérek alakulását, állami tervek kidolgozásába kezd, beleszól a gazdasági folyamatokba.\n\nA New Deal lényege ez alapján a következő:\n\núj banktörvények: az elnök közvetlenül beavatkozik a pénzügyi- és a bankpolitikába,\n\nértékpapír kibocsátás, a dollár leértékelése\n\nipari vállalkozások szabályozása: iparügyi kormánybizottság, fejlesztési törvény\n\nközmunkák szervezése a munkanélküliség felszámolására, a Közmunkaügyi Hivatal irányításával: utak, lakótelepek, iskolák, kórházak építése\n\nszociális intézkedések: társadalombiztosítás rendszere; bérek alsó határának megszabása; gyerekmunka betiltása; a munkahelyi egészségvédelem állami feladat lett; kollektív szerződések\n\nmezőgazdasági termelés és fogyasztás egyensúlyának megteremtése; farmerek támogatása; állami felvásárlás; rögzített árak\n\nkülpolitikában nyitás a szovjetek felé: 1933: diplomáciai kapcsolat a Szovjetunióval\n\nellenzői: konzervatívok, nagyvállalkozók => a New Deal lelassul\n\ntámogatói: a munkásság, fekete bőrűek, etnikai csoportok, liberális értelmiség.\n\nÖsszefoglalása: a válságból Roosevelt elnök idején sikerült kilábalni. A New Deal lényege tehát, hogy állami beavatkozás révén oldották meg a válságot: pl. ipartörvényt hoztak, bezárták a bankokat, s csak az életképesek maradtak fenn, a gazdáknak kárpótlást fizettek azért, ha nem vetették be gabonával a földjeiket, vagy levágták az állatállományt. Közmunkaprogramokat indítottak el, melyek során az infrastruktúra fejlődése érdekében dolgoztak, pl. utak, hidak építése. A New Deal bevált, s kilendítette az USA-t a válságból.\n\nAz európai integráció\n\nAz Európai Unió létrejötte és intézményrendszere\n\nFranciaország és Németország történelmi megbékélésével Nyugat-Európából indult a második világháború után. Az európai országokat sok évszázados kulturális és történelmi hagyományok fűzik egymáshoz. 1946-ban Churchill zürichi beszédében Európai Egyesült Államokról beszélt. Az 1949 óta Strasbourgban működő intézmény, az Európa Tanács viszonylag laza együttműködést valósít meg a demokratikus európai államok között. (Magyarország 1990-ben lépett be az Európa Tanácsba).\n\nAz európai integrációs folyamat okai: a béke és a jólét iránti vágy, a hidegháború, illetve a szovjet fenyegetettség segítette az egységfolyamatot. Európa egységesülése a politikain túl gazdasági érdek is, hiszen versenyben áll az USA-val és az ázsiai térséggel. A globális versenyben az integráció versenyelőnyt jelenthet a nemzetgazdasági léttel szemben.\n\nAz európai integráció rövid története: az európai integráció elindítói: Adenauer, Monnet, Schumann\n\nAz európai integráció az 1950-es Schumann-tervvel indult. A 6 országot összefogó együttműködés legfontosabb elemét a német-francia kapcsolat jelentette, hiszen 1945-ig még háborús ellenfelek voltak. 1950. május 9-én Robert Schumann francia külügyminiszter előterjesztette a megbékélésről és az európai együttműködésről szóló tervét, felvázolta a „konkrét lépések politikáját”. (azóta ez a nap az Európa-nap).\n\n1951. április 18-án hat ország (Franciaország, Német Szövetségi Köztársaság, Olaszország, Belgium, Hollandia és Luxemburg) aláírta az ún. kölcsönös függőség megteremtését célzó Európai Szén- és Acélközösség (ESZAK vagy Montánunió) létrehozásáról szóló szerződést. Cél: közösen ellenőrizzék a tagállamok szén- és acéltermelését.\n\n1957. március 25-én ugyanezek az államok aláírták a római szerződést is, amely megteremti az Euroatomot és az Európai Gazdasági Közösséget (EGK, közkeletű nevén: „Közös Piac”), melynek célja a tagországok közötti vámunió létrehozása volt, a belső piac, közös agrárpolitika, strukturális politika. A tőke, az áruk, a munkaerő és a szolgáltatások szabadsága érvényesül.\n\nAz integrációt az 1962-ben bevezetett közös agrárpolitika és az 1968-ban elfogadott vámunió mélyítette tovább.\n\n1968-ban a Közös Piac Európai Közösséggé (EK) alakult.\n\nBővülés:\n\nNagy-Britannia is kifejezte csatlakozási szándékát, először 1963-ban, majd 1967-ben. Amikor azonban benyújtotta felvételi kérelmét, De Gaulle francia köztársasági elnök vétót emelt, mert versenytársnak érezte az angolokat. 1973-ban végül mégis csatlakozott az Egyesült Királyság, illetve Írország és Dánia. Ekkor vált szokássá, hogy a csatlakozó országok türelmi időt kapnak.\n\nEzt követően az ún. déli bővítés került napirendre: 1981-ben Görögország, 1986-ban pedig Spanyolország és Portugália csatlakozott. Így az EK a világ legnagyobb gazdasági egységévé vált, s népessége meghaladta mind a Szovjetunióét, mind az Egyesült Államokét.\n\nA hidegháború befejeződése (1990) felvetette az európai integráció jövőjének kérdését. A közösség az integráció elmélyítése és kibővítése mellett döntött: 1991-ben a hollandiai Maastrichtban elfogadták az integráció továbbfejlesztésének programját, majd 1993-ban lép érvénybe:\n\n- az európai valuta; a közös kül- és biztonságpolitika;\n\n- az egységes vízumpolitika;\n\n- a közös intézmények – Európa Parlament, Európai Bizottság - szerepének kiszélesítése;\n\n- az EK elnevezése 1992-től Európai Unióvá (EU) változott.\n\n1995-ben Ausztria, Finnország és Svédország csatlakozott.\n\n1995-ben életbe lépett a luxemburgi Schengenben aláírt egyezmény, amely az unió tagállamai között „lebontotta a határokat”, viszont a külső határokon szigorúbb ellenőrzést írt elő.\n\nA 2000. decemberi nizzai csúcsértekezleten megállapodás született az Európai Unió új működési szabályairól, lehetővé teszik az új csatlakozók beillesztését. A 2002. decemberi koppenhágai csúcsértekezleten döntés született az időpontról is.\n\n2002-ben 12 tagállam megszüntette saját valutáját, bevezette helyette az eurót. Nagy-Britannia, Dánia és Svédország nem vezette be.\n\nA nagy bővítést 2004. május l-je jelentette, amikor 10 új tagállam, vagyis Észtország, Lettország, Litvánia, Lengyelország, Csehország, Szlovákia, Szlovénia, Ciprus és Málta mellett Magyarország is csatlakozott az EU-hoz. A tagállamok jelenlegi száma (28) a 2007-ben csatlakozott Romániával és Bulgáriával alakult ki. 2013-ben Horvátországgal bővült.\n\nAz európai integráció a nemzetek feletti egység (szupranacionális) megteremtésének irányába tett lépés. Az integráció a nacionalizmusok korának meghaladását ígérte, a kilencvenes évekre ez a folyamat azonban megtorpanni látszik.\n\nAz uniós együttműködésben rejlő nehézségek:\n\na nemzeti érdekek és nemzetek feletti érdekek, nettó befizetők és nettó részesedők konfliktusa, nagy és kis országok eltérő érdeke.\n\nA különböző érdekek és értékek egyeztetése konfliktusok forrása is lehet.\n\nProblémás: a bonyolult döntéshozatali rendszer, a demokratikus deficit, és a túlbürokratizáltság. A nemzetállamok feletti békés és erős Európa eszméje a gyakorlatban nehezen működik.\n\nGazdasági és politikai félelmek: a piacvesztés és a nemzeti hagyományok háttérbe szorulása akadályozhatják az egység megvalósulását.\n\nA közös biztonságpolitikához a tagállamok biztosítják a katonai eszközöket, ez az érdekellentétek miatt gyakran megbénul; a tagállamok nem feltétlenül érdekeltek a katonai képességek növelésében; az EU-nak nincs saját katonai ereje.\n\nVita van a közös intézményeknek átadandó jogkörökről, pl. ezt a szuverenitás, függetlenség feladásaként, veszélyeztetéseként is értelmezik. Nem alakult ki közös európai nemzeti identitás. A közös intézmények demokratikus kontrollja nem teljesen megoldott.\n\nAz intézményrendszer átalakulásának lépcsőfokait a Brüsszeli Szerződés (1967), az Egységes Európai Okmány (1986), a Maastrichti Szerződés (1993), az Amszterdami Szerződés (1999) és a Nizzai Szerződés (2000) jelentette, az integráció pedig tovább szélesedett például a Schengeni Szerződés hatálybalépésével (1995) vagy az euró (€) bevezetésével (2002). 2009. december l-jén hatályba lépett a Lisszaboni Szerződés.\n\nAz EU jogi rendszere\n\nAz Európai Unió sajátos jogi struktúra, erősebb az országok konföderációjánál, de nem szövetségi állam, ugyanakkor nemzetközi közjogi értelemben jogi személy. Alapját az ún. elsődleges jog képezi, ami az Európai Uniót megalapító szerződések összessége. Ezeket módosítja és foglalja egységes keretbe a 2009-es Lisszaboni Szerződés, vagy más néven Reformszerződés. A legfontosabb szerződések közé tartozik az Európai Unióról szóló (Maastrichti) szerződés és az Európai Unió működéséről szóló (Római) szerződés is; a Lisszaboni Szerződéssel megszűnt a korábbi hármas pillérrendszer (Európai Közösségek, közös kül- és biztonságpolitika, rendőri és bírói együttműködés).\n\nErre épül az ún. másodlagos jog; ez olyan területekre terjedhet ki, amelyekre az elsődleges jog is kiterjed, és az EU intézményei által elfogadott minden tagállamra kötelező érvényű, közvetlen hatályú rendeletekből, kötelező célokat megfogalmazó, de a megvalósítás módját nem részletező irányelvekből, konkrét ügyre és csak a címzettre vonatkozó határozatokból áll. Ez kiegészül a nem kötelező érvényű ajánlásokkal és véleményekkel.\n\nEzeket a döntéseket az egyes tagállamok kormányait képviselő Tanácsból, az európai állampolgárokat képviselő Parlamentből, és az EU egységes érdekeit képviselő Bizottságból álló intézményi háromszög hozza meg (döntéshozatali háromszög).\n\nAZ EURÓPAI UNIÓ FELÉPÍTÉSE főbb intézményei, döntési mechanizmusai\n\nAz Európai Bizottság tekinthető az EU kormányának, az Európai Parlament pedig az EU parlamentjének, egyik sem rendelkezik kiterjedt jogkörrel. Az Unió legfontosabb döntéseit az egyes tagállamok kormányai által alkotott testületek, a tagállamok állam- és kormányfőiből álló Európai Unió Tanácsa határozza meg (ez nem azonos az 1949-ben létrehozott Európa Tanáccsal!). Jelenleg 27 tagállama van az EU-nak. A britek kilépésével a többi nettó befizetőre jelentősen nagyobb teher járul.\n\nBrexit: Nagy-Britannia kilépésére az Európai Unióból 2020. január 31-én.\n\nA 2016. júniusi népszavazáson a kilépést támogató szavazatok voltak többségben, az Egyesült Királyság parlamentjének jóváhagyásával Theresa May miniszterelnök 2017. március 29-én jelentette be az Egyesült Királyságnak az Európai Unióból való kilépési szándékát a lisszaboni szerződés 50. cikke alapján.\n\n1. Az Európai Unió Tanácsa (Miniszterek Tanácsa) - Brüsszel\n\nSzerep: az EU-tagállamok kormányainak képviseletét ellátó intézmény, mely uniós jogszabályokat fogad el és összehangolja az uniós szakpolitikákat\n\nTagok: az uniós országoknak a megvitatandó szakpolitikai területért felelős miniszterei\n\nElnök: rotációs alapon mindegyik uniós ország 6 hónapig tölti be az elnöki tisztet\n\nSzékhely: Brüsszel (Belgium)\n\nEz az EU fő döntéshozó szerve. Elsősorban politikai testület, a politikai kompromisszumok színtere, amely évente négyszer ülésezik, a jelenlegi gazdasági válság idején gyakrabban. Elnökét a Tanács választotta meg két és fél évre, a Lisszaboni Szerződés szerint azonban 2009-től félévente rotációs rendszerben végzik. Az elnöki tisztet betöltő tagállamok hármas csoportokban, az úgynevezett elnökségi triókban szorosan együttműködnek egymással.\n\nA Tanács elnökségét félévente más-más uniós tagállam tölti be. E féléves időszak során minden szinten a soros elnökség vezeti a tanácsi üléseket, így biztosítva a Tanácsban az Unió munkájának folytonosságát.\n\nElnökét (a Lisszaboni Szerződés szerint már 2009-től) a Tanács választja két és fél évre.\n\nA jelenlegi triót a francia, a cseh és a svéd elnökség alkotja. Az EU Tanácsának francia elnöksége: 2022. január 1 – június 30. (Emmanuel Macron, a Francia Köztársaság elnöke)\n\nA 2009. december 1-jén életbe lépett Lisszaboni szerződés létrehozta az Európai Tanács állandó elnöki posztját, így annak már nincs köze az elnökséget aktuálisan ellátó országhoz. Donald Tusk, az állandó elnök kinevezése 2019 novemberében járt le, jelenleg Charles Michel, belga politikus az állandó elnök.\n\nMinden államot annak államfője vagy miniszterelnöke, illetve egy-egy minisztere képvisel, attól függően, hogy milyen ügy szerepel a napirenden (pl. külügyek, mezőgazdaság, környezetvédelem stb.), és a testületben helyet foglal az Európai Bizottság elnöke is. Ezt a két szintet (Európai Tanács, Miniszterek Tanácsa) egészíti ki a tagállami szakminisztériumok tisztségviselőinek szintje (COREPER 1. és COREPER 2.), illetve az előkészítő szakértői munkacsoportok szintje.\n\nA Tanács a Parlamenttel közösen felelős az EU költségvetéséért, valamint jogalkotói hatáskörrel rendelkezik. Döntéseit konszenzussal vagy szavazással (egyszerű többséggel, egyhangú döntéssel vagy minősített többséggel) hozza. 2014-től a minősített többség tekintetében az eddigi hármas többség (tagállamok száma, lélekszáma és szavazati súlya) megváltozik. 2014-től a minősített többség tekintetében a kettős többség elvét vezetik be a Tanácsban a döntéshozatal terén: a tagállamok 55%-ának kell támogatnia egy javaslatot, és az igennel szavazó országok lélekszámának el kell érnie az Unió teljes lakosságának 65%-át. A másik oldalról az ún. blokkoló kisebbséget legalább négy tagállamnak kell alkotnia, ha ez nem valósul meg, akkor el kell tekinteni a lélekszámbeli kritériumtól. Pl. Visegrádi 4-ek (V4-ek).\n\n2. Az Európai Parlament – Strasbourg, Brüsszel, Luxemburg\n\nA Parlament 1979 óta a tagállamok polgárai által közvetlenül, ötévente választott testület. A Parlament képviselői politikai alapon frakciókra tagolódnak. A Parlament plenáris üléseit Strasbourgban, a bizottsági üléseket és a frakciók üléseit Brüsszelben tartják. A hivatali apparátus Luxemburgban van.\n\nFelügyeli az EU intézményeit, és jogalkotói hatáskörrel is rendelkezik. 751 tagja van, ebből 21-t választhatnak a magyar állampolgárok. A Parlament az ún. együttdöntési eljárásban egyes jogalkotási területeken a Tanáccsal egyenrangú döntéshozónak minősül. A Lisszaboni Szerződés az együttdöntést kiterjesztette a jogalkotási területek többségére; ilyen terület az Unió költségvetésének egésze is.\n\nA Parlament választja - a Tanács javaslatára - a Bizottság elnökét, és hozzá kell járulnia a külügyi és biztonságpolitikai főképviselő személyéhez is. Nagyon erős jogköre, hogy kétharmados többségű bizalmatlansági indítvánnyal feloszlathatja a Bizottságot. A képviselők emellett kérdéseket intézhetnek a Bizottsághoz és a Tanácshoz. Elnöke 2017-ig Martin Schulz volt, majd Antonio TAJANI, 2019 júliusától pedig az olasz David Maria Sassoli. A parlament elnökét, a 14 alelnököt a képviselők választják maguk közül 2,5 évre. Az Európai Parlament jelenlegi elnöke – Roberta Metsola 2022. január – 2024. június között.\n\n3. Az Európai Bizottság – Brüsszel\n\nVolt elnöke (2014-2019) a luxemburgi Jean-Claude Juncker, a 2004-től elnöklő Manuel Barroso után. Biztosok: 27 fős. Junker mandátuma 2019 október végéig tartott. Jelenlegi elnöke: Ursula von der Leyen, belga születésű német kereszténydemokrata politikus 2019. december – 2024. október között. A Bizottság irányítja az EU napi működését, feladata az EU, mint közösség egységes érdekeinek támogatása és képviselete, vagyis teljesen független az egyes országok nemzeti kormányaitól, illetve parlamentjeitől. A Bizottság végzi az egyes javaslatok hatásvizsgálatát és folytatja le a konzultációt a döntésekben érintett felekkel, amelyeket végül a Tanács és a Parlament több olvasatban vitat meg és fogad el.\n\n2009-től a Lisszaboni Szerződéssel létrejött az Unió külügyi és biztonságpolitikai főképviselői tisztsége, aki egyben alelnöki tisztséget tölt be az Európai Bizottságban. 2014-től kezdve a tagországok kétharmada jelölhet biztost (a Parlament hozzájárulásával öt évre), mégpedig rotációs elven (addig minden tagállamból l fő tagja a Bizottságnak).\n\nA Lisszaboni Szerződéssel lehetőség nyílt a petícióra is, hogy több tagország állampolgárai egymillió aláírással kezdeményezzék a Bizottságnál egy adott javaslat beterjesztését.\n\nAz Európai Unió további intézményei:\n\nAz Európai Bíróság – tagállamonként 1 fő, feladata a közösségi jog érvényesítésének, valamint a szerződések alkalmazásának és helyes értelmezésének biztosítása. Székhelye Luxembourg, a testületbe minden tagállam egy-egy bírót delegál hat évre. Ítélkezik az európai jog értelmezésének ügyeiben, főként alábbi esetekben: pl. az Európai Bizottság követelése, amikor egy tagállam nem hajt végre egy uniós irányelvet vagy más jogi követelményt.\n\nA Számvevőszék tagjait szintén a tagállamok és szintén hat évre delegálják, a Parlamenttel való konzultációt követően. A testület feladata az unió költségvetésének ellenőrzése, mind a szabályszerűség, mind a hatékonyság szempontjai szerint, ellenőrizni az Európai Unió intézményeinek pénzügyeit, valamint az európai forrásokból részesedő, illetve azokat kezelő szervezetek pénzügyeit és gazdálkodását. Székhelye Luxembourg. Tagállamonként 1 tag.\n\nAz Európai Gazdasági és Szociális Bizottság és a Régiók Bizottsága a Tanács és a Bizottság munkáját segítő, azoktól független szerv; az egyik az egyes civil gazdasági és társadalmi érdekcsoportokat, a másik a tagállamok helyi és regionális választott testületeit képviseli. Tagjait a Tanács nevezi ki négy évre.\n\nAz Európai Beruházási Bank kölcsönökkel segíti az EU egyes elmaradottabb területeinek fejlesztését és versenyképességét, míg a frankfurti központú Európai Központi Bank az euró stabilitásáért és az Európai Unió monetáris (pénzügyi) politikájáért felelős. Korábbi elnöke Mario Draghi, akinek a mandátuma 2019 október végén járt le, jelenleg Christine Lagarde a vezetője.\n\nAz Európai Unió gazdasága\n\nA 27 országot tömörítő, egységes piacot működtető Európai Unió kereskedelmi nagyhatalom.\n\nAz uniós gazdaságpolitika célja, hogy a pénzügyi erőforrások célravezetőbb felhasználása, a beruházások előtt álló akadályok felszámolása, valamint a beruházási projektek láthatóságának és technikai támogatásának biztosítása révén fellendítse a munkahelyteremtést és a növekedést.\n\nAz előállított áruk és szolgáltatások összértékét tekintve az EU bruttó hazai terméke (GDP-je) 2019-ben – amikor az Egyesült Királyság még az EU-hoz tartozott – 16,4 billió (ezermilliárd) EUR volt.\n\nKereskedelem\n\nAz uniós tagországok az összkereskedelmük kb. 64%-át egymással bonyolítják le.\n\nBár a világ népességének mindössze 6,9%-a él az Európai Unióban, a más országokba irányuló uniós export és az EU-ba érkező import a világkereskedelem mintegy 15,6%-át teszi ki.\n\nAz EU az Egyesült Államok és Kína mellett egyike a nemzetközi kereskedelem három legjelentősebb szereplőjének.\n\n2016-ban az Európai Unió országainak volt együttesen a második legnagyobb részesedésük a globális áruexportból és -importból.\n\nAz uniós tagországok együttes áruexportja a világ teljes áruexportjának 15,6%-át tette ki, amit 2014-ben – az EU fennállása óta először – túlszárnyalt Kína (amelynek részesedése a 2014. évi 16,1%-ról 2016-ra 17%-ra nőtt), miközben az Egyesült Államok részesedése (11,8%) elmaradt az EU-országokétól.\n\nAz importrészesedés terén az Egyesült Államok 17,6%-kal mind az uniós országok (14,8%), mind Kína (12,4%) előtt állt.\n\nAz EU a világ bruttó hazai termékének (GDP) több mint 20%-át termeli meg, és ezáltal a világ legnagyobb gazdasága.\n\nEgységes piac\n\nA munkaerő, a tőke szabad áramlása, az áruk és szolgáltatások szabad kereskedelme a tagállamok között.\n\nKözös EU-versenytörvény, amely a cégek és a tagállamok versenyellenes tevékenységét szabályozza (előbbit a trösztellenes törvény és a vállalkozások összeolvadását szabályozó törvény révén, utóbbit az államoknak nyújtott segélyek rendszere révén)\n\nA schengeni egyezmény lehetővé tette a tagállamai közötti belső határellenőrzések eltörlését és a külső határok ellenőrzésének összehangolását. Ez nem vonatkozik Írországra és nem vonatkozott az Egyesült Királyságra, viszont a nem EU-tagállam Izland és Norvégia szintén részt vesz az együttműködésben.\n\nA tagállamok polgárai szabadon megválaszthatják, hol éljenek és dolgozzanak az Európai Unión belül, feltéve, hogy gondoskodni tudnak magukról.\n\nA tőke szabad áramlása a tagállamok között.\n\nEgységes pénznem, az euró (Dániát, korábban még Nagy-Britanniát is kivéve). Svédország, bár nincs saját kimaradási klauzulája, nem csatlakozott a II-es árfolyamrendszerhez (ERM II), s ezzel önként kizárta magát a monetáris unióból.\n\nA környezetvédelmi irányelvek nagyarányú egyeztetése az Unió országaiban. Közös agrár- és halászati politika.\n\nA közvetett adózás, az áfa (hozzáadottérték-adó) egységes rendszere, valamint egységes vám különféle termékeken.\n\nElmaradott területek fejlesztésének támogatása (strukturális és kohéziós alapok).\n\nEgységes külső vámtarifa, egységes álláspont a nemzetközi kereskedelmi tárgyalásokon.\n\nA tagjelölt országok és más kelet-európai országok programjainak támogatása, segély számos fejlődő országnak.\n\nBREXIT: az Európai Unióból való brit kilépés, azaz a Brexit 2020. január 31-én megtörtént, ami érinti az Egyesült Királyságban élő európai uniós polgárok helyzetét is.\n\n2021. január 1-től megszűnt az uniós polgárok szabad mozgása.\n\nA Brexit (vagy brexit) nemzetközileg elterjedt elnevezés az Egyesült Királyság kilépésére az Európai Unióból. Két angol szó összevonása: British (magyarul \'brit\') + exit (\'távozás\', \'kijárat\').\n\nA globális világ ellentmondásai\n\nA GLOBÁLIS VILÁGELLENTMONDÁSAI\n\nA fejlődő országok népesedési jellemzői a XXI. században:\n\nA Föld népességének zöme a fejlődő országokban él. A fejlődő országok elsősorban Afrikában, Ázsiában és Latin-Amerikában találhatók. A fejlődő országokból a fejlett országokba migráció folyik, mely kulturális konfliktusokat eredményez. A bevándorlók gazdasági menekültek, és jórészt muzulmánok. Problémák: bevándorlás kulturális konfliktushoz vezethet, ugyanakkor a bevándorlók versenytársak a munkaerőpiacon, és szociális ellátásokat igényelhetnek. Az előrejelzések szerint Afrika népessége fog valószínűleg a legdinamikusabban növekedni. Eddig Ázsia népessége növekedett a legdinamikusabban a XX. században. Jelenleg is Ázsia népessége a legnagyobb: Kína és India.\n\nIndia és Kína demográfiai kilátásai: Kína és India a világ két legnépesebb országa, mindkét ország lakossága egymilliárd feletti, tehát a világ lakosságának bő harmadát teszik ki, így demográfiai folyamataik az egész világra kihatnak. A különbségek politikai oka: Kínában kommunista diktatúra van, ahol bevezették az egykepolitikát. Indiában demokrácia van. India népessége várhatóan nagyobb lesz, mint Kínáé, ugyanis a kínai társadalom elkezd elöregedni. Indiában még tart, Kínában már lelassult a népességnövekedés. Indiában még magas, Kínában már alacsonyabb a születési arány. Indiában az állam kevésbé avatkozik bele családtervezésbe, nagy a vallások szerepe. Kína jóval fejlettebb, gazdagabb Indiánál. Összefügg a családméret és a gazdasági fejlődés: a gazdasági fejlődés, a modernizálódó társadalom a kisebb családméretet részesíti előnyben.\n\nA népességrobbanás a fejlődő világban, így Indiában is a XX. század második felében kezdődött, ez globális következményekkel jár. India népessége a második világháború befejezése és a függetlenség kikiáltása óta gyors ütemben nő (1947 és 2010 között nagyjából 3–4-szeresére), ezt nevezzük népességrobbanásnak. Indiában a születések aránya a csökkenés ellenére még mindig jelentősen meghaladja a halálozások szintén csökkenő arányát, és ezért magas a természetes szaporulat. A halálozások aránya 2010-ben kevéssel alacsonyabb, a születések aránya viszont lényegesen magasabb Indiában, mint az Európai Unióban. India társadalma fiatalodó társadalom. A fejlődő országokban a közlekedési eszközök gyakran túlzsúfoltak, az infrastruktúra fejlődése nem tud lépést tartani a gyors népességnövekedéssel, ez hozzájárul a gyakori tömegbalesetekkel. A fejlődő világban jellemzően lényegesen kevesebb az ezer főre jutó kórházi ágy, mint az Európai Unióban. Az egészségügyi ellátás színvonala alacsonyabb, mint a fejlett világban. A gyors népességnövekedés sokmilliós nagyvárosok kialakulásához vezetett, és ezeknek a városoknak a peremén jellemzően nyomornegyedek találhatóak. A fejlődő világ országainak jelentős része nem tudja megfelelő mennyiségű élelmiszerrel vagy ivóvízzel ellátni a növekvő népességét. Az éhezés vagy alultápláltság, ivóvízhiány további problémák kialakulásához járulhat hozzá pl. járványok, éhínség. A fejlődő országokban jellemző túlnépesedés további problémákat idéz elő pl. az analfabéták vagy a szakképzetlen, alacsonyan megfizetett munkaerő magas arányát. A fejlődő országok problémái globális jelentőségűek pl. a migráció vagy a világméretű járványok miatt. A fejlett országok a nemzetközi szervezeteken keresztül igyekeznek segítséget nyújtani a fejlődő országoknak.\n\nEurópában, a fejlett világban az elöregedés folyamata zajlik, ez gazdasági nehézségeket okozhat, ennek oka az alacsony születésszám és gyakoribb az egyke család.\n\nA népességrobbanás a XXI. században várhatóan megáll vagy lassul, ez átrendezheti a gazdasági és politikai erőviszonyokat. A probléma az, hogy éppen a legszegényebb országok népessége növekszik leginkább. A népességrobbanás leállása összefügg a gazdasági fejlődéssel.\n\nA fejlődő országokban zajló népességrobbanás oka a halálozások számának csökkenése. Magas a születésszám, a fiatalodó társadalom, magas, és csökken a csecsemőhalandóság. A jelenség oka: a hagyományos családmodell, a női emancipáció elmaradása, a rossz vagy javuló egészségügyi viszonyok. A népességrobbanás lényegi következménye: a munkanélküliség, az oktatási és az egészségügyi rendszer túlterhelése, a járványok újbóli megjelenése és az élelmezési válság. Mindez összefügg az instabil politikai viszonyokkal, helyi háborúkkal, amely menekülthullámot indít el, így nemzetközi segélyezésre szorulnak a menekültek.\n\nA hidegháború időszakában a két, ellentétes társadalmi-gazdasági berendezkedésű országcsoport egymás közötti vetélkedése évtizedeken keresztül alapvető befolyást gyakorolt a világgazdaság térszerkezetének alakulására. Észak-Amerika országai, az integráció útjára lépett nyugat-európai államok, illetve Japán és a köré csoportosuló délkelet-ázsiai országok („kis tigrisek”) együttesen alkották a fejlett piacgazdasággal rendelkező úgynevezett első világot.\n\nA Szovjetunió által vezetett keleti blokk, a második világ gazdasági rendszere a tervutasításos gazdaság elképzelésén alapult.\n\nAzokra a gazdaságilag többnyire elmaradott államokra, amelyek egyik politikai-gazdasági tömörüléshez sem tartoztak, a harmadik világ megnevezést használták.\n\nA világgazdaság rendszerére egészen a hidegháborús időszak végéig, az 1990-es évekig ez a hármas felosztás volt jellemző, a szocialista tömb szétesése azonban ezen a területen is nagy változásokkal járt együtt. A 20. század végén végbement politikai változások, a 21. század elején kibontakozó társadalmi-gazdasági folyamatok napjainkra többpólusú világgazdasági rendszer kialakulásához vezettek.\n\nA világgazdaság központját (centrumát) az észak-amerikai, az európai és a csendes-óceáni gazdasági térség által formált Triád alkotja, amelyek országai ezer szállal kötődnek egymáshoz.\n\nA 2000-es évek elején egyes közgazdászok és politikai döntéshozók azt jósolták, hogy a világgazdaság új motorjai az úgynevezett BRICS-országok (Brazília, Oroszország, India, Kína, Dél-Afrikai-Köztársaság) lesznek. Növekedési ütemüknek köszönhetően pedig felzárkóznak a Triád államaihoz. Mára ezen országok gazdasági növekedése lelassult, Brazília és Oroszország gazdasága pedig recesszióba esett. Mindannyian komoly gazdaságszerkezeti és társadalmi problémákkal küzdenek. Ezt megnehezíti napjaink háborúja is, az orosz-ukrán háború, melyben a világ több gazdasági hatalma is érdekeltté vált, pl. az USA, az EU országai.\n\nA világgazdaság peremterületeihez (perifériájához) a legkevésbé fejlett országok tartoznak. Ezek az országok túlnyomórészt a Föld déli féltekén helyezkednek el, míg a legfejlettebbek az északi féltekén. A társadalmi-gazdasági különbségek a két régió között gyorsan növekedtek az utóbbi évtizedekben.\n\nA 2008-ban kirobbant pénzügyi válság a nagy gazdasági világválság óta a legnagyobb világméretű gazdasági visszaesést indította el. Az egész folyamat kiindulópontja az USA ingatlanpiacán fejfújódó buborék volt. Egyre több lakást értékesítettek egyre magasabb árakon úgy, hogy a vevők hitelből vásároltak. Az ingatlanok maguk voltak a hitelek fedezete. Mikor kiderült, hogy a piac túlárazott és az árak zuhanni kezdtek, a hitelintézők elveszítették hiteleik fedezetét. Ennek következtében több nagy jelzálogbank csődbe ment. Az emberek elvesztették a lakásaikat, házaikat, mert nem tudták fizetni a hitelt. Gazdasági visszaesés következett be, ami az egész világra kihatott.\n\nAz ipari társadalmaktól az információs társadalmakig\n\nNapjaink globális világgazdasági rendszerének létrejötte az 1970-es évek elején kibontakozó és jelenleg is tartó világgazdasági korszakváltás következményeinek tudható be. Ennek során az addig túlsúlyban lévő, nyersanyag- és energiaigényes gazdasági ágazatokon (pl. vas- és acélkohászat, gépipar, textilipar) alapuló ipari (indusztriális) társadalmak helyébe az ipar utáni, posztindusztriális társadalmak léptek, amelyek gazdaságára már a szolgáltatások dominanciája jellemző. A folyamat két legfontosabb hajtóereje a tömegáru-termelés hanyatlása, illetve a kőolaj árának többszöri, ugrásszerű emelkedése (kőolajár-robbanások) volt. A 20. század második felében végbement tudományos-technikai forradalom az informatika, a kommunikáció és a közlekedés robbanásszerű fejlődését idézte elő. Az új vívmányok széles körű elterjedésének köszönhetően az 1990-es évek posztindusztriális társadalmaiból létrejöttek az első információs társadalmak. Ezekben a magasan képzett munkaerőt igénylő gazdasági ágazatok (például biotechnológia, média, számítástechnika – „tudásipar”) dominálnak.\n\nA világgazdasági korszakváltásban élen járó, a bekövetkező változásokra „érzékeny” országok gazdasága gyors fejlődésnek indult. A kevésbé jó adottságokkal rendelkező, a világgazdasági folyamatokra nehezebben reagáló államok többsége azonban csak kölcsönök felvételével volt képes fenntartani a gazdaság működését. Az 1973-as és az 1979-es kőolajár-robbanás által kiváltott nagymértékű infláció, a hitelek után fizetendő kamatok emelkedése és a nyersanyagok iránti kereslet csökkenése rendkívül nehéz helyzetbe hozta a fejletlen gazdaságú országokat. A sok esetben elmaradt szerkezeti átalakítások nem segítették elő a gazdasági növekedést, ezért az eladósodott államok csak újabb hitelek felvételével tudták törleszteni a korábbi kölcsönöket, vagyis adósságspirálba kerültek.\n\nGLOBALIZÁCIÓ a XXI. században\n\nA globalizáció kifejezés a globus (jelentése: ’földgömb’) latin szóból ered, és szó szerint világméretűvé válást jelent. Azokat a 20. század második felére, a 21. század elejére jellemző politikai, társadalmi, gazdasági, kulturális és környezeti jelenségeket, folyamatokat foglalja magában, amelyek az egész Földre kiterjednek, és bolygónk valamennyi területére hatást gyakorolnak. Mindehhez fejlett informatikai, kommunikációs és közlekedési rendszerekre van szükség, ezért a globalizáció legfontosabb hajtóereje a tudományos-technikai forradalom kibontakozása, az információs társadalmak létrejötte volt. A globalizáció során az államok között fennálló addigi gazdasági kapcsolatok gyökeresen átalakultak, és új gazdasági szereplők pl. a transznacionális vállalatok, integrációk jöttek létre. Ezek a változások jelentős mértékben hozzájárultak ahhoz, hogy a világgazdaságban zajló különböző folyamatok napjainkban már világméretekben, globális szinten szerveződnek.\n\nA globális világgazdaság működésére az államokon kívül a transznacionális vállalatok és az integrációk fejtik ki a legnagyobb hatást. A transznacionális vállalatok (röviden TNC-k) olyan cégek, amelyeknek számos országban működnek gazdasági tevékenységet végző egységei. Legelső képviselőik már az 1900-as évek elején megjelentek. Számuk és ezzel együtt jelentőségük a globalizációnak köszönhetően a 20. század második felében ugrásszerűen megnőtt. Jelenleg a világ gazdasági termelésének kb. egynegyedét, a nemzetközi kereskedelemnek pedig a kétharmadát a TNC-k bonyolítják le.\n\nAz egymásrautaltság és a kölcsönös függés csökkentése, illetve az erősebb gazdasági pozíciók megszerzése érdekében a 20. század végén számos ország összehangolta működését. Így több államot is magában foglaló, nemzetek felett álló szervezetek, integrációk alakultak ki. Ezek többsége csak kereskedelmi együttműködésen alapul, de van közöttük az egyes nemzetgazdaságok szoros összefonódására épülő gazdasági unió (Európai Unió) is.\n\nA GYARMATI VILÁG FELBOMLÁSA\n\nDEKOLONIZÁCIÓ ÉS HIDEGHÁBORÚ\n\nA hidegháború időszakában, a nyugati „első világ” és a kommunista „második világ” mintájára született meg a „harmadik világ” kifejezés a két tömbhöz nem tartozó latin-amerikai, afrikai és ázsiai országok együttes elnevezéseként. Ezen országok többsége csak a második világháború után vált függetlenné. Az elnevezés túlélte a bipoláris világ korszakát.\n\nA dekolonizáció, azaz a gyarmatok függetlenné válása a Közel-Keleten, valamint Kelet- és Dél-Ázsiában kezdődött: 1946 és 1948 között függetlenné vált a Fülöp-szigetek, Holland-India (Indonézia) és az indiai szubkontinens államai. Egyes országok hosszas gyarmati háborúkba bonyolódtak, mint pl. a franciák Indokínában (1946-1954) és Algériában (1954-1962). A portugálok csak az 1970-es évek második felében adták fel gyarmataikat.\n\n1955-ben az indonéziai Bandungban találkoztak a függetlenné vált, többségében afrikai és ázsiai államok vezetői, akik megalapították az ún. el nem kötelezettek mozgalmát. Szándékaik szerint a felszabadult és felszabadításra váró harmadik világbeli államoknak egyenlő távolságot kell tartaniuk mind a Nyugattól, mind a Szovjetuniótól. Együttműködésüket azonban társadalmi – politikai - kulturális különbségek, köztük támadt konfliktusok is akadályozták, és szinte sohasem tudtak függetlenedni a hidegháborús viszonyoktól. Bármilyen összecsapás tört ki a harmadik világban - akár egy országon belül, akár országok között -, ha az egyik fél megszerezte valamelyik tömb támogatását, ellenfele számíthatott a másik szuperhatalom segítségére.\n\nHelyi és hidegháborús konfliktus kapcsolatára jó példa Angola. A portugál gyarmaton 1961-ben függetlenségi háború kezdődött, amelyben több, etnikai alapon szerveződött gerillaszervezet is harcolt. A portugálok 1975-ös kivonulása utáni káoszban végül az MPLA nevű szervezet szerezte meg a hatalmat, kikiáltotta a népköztársaságot, s így szovjet anyagi és kubai katonai segítséghez jutott.\n\nA legjelentősebb ellenzéki gerillaszervezet, az UNITA erre a demokratikus piacgazdaság programját hirdette meg, s amerikai és dél-afrikai támogatást kapott. Az ország déli területeire dél-afrikai csapatok hatoltak be, s harcba szálltak a kubaiakkal. A szovjet tömb összeomlása után a kubai és dél-afrikai csapatokat kivonták, a hatalmon lévő párt bejelentette, hogy szakít a marxizmus-leninizmussal, s az UNITA amerikai támogatása is megszűnt. Ennek ellenére a gerillaharc - egészen az UNITA karizmatikus vezetője, Jóm Sawimbi 2002-es haláláig - tovább folytatódott, ezúttal már világnézeti különbségek nélkül.\n\nINDIA ÉS PAKISZTÁN\n\nIndia függetlenedésében jelentős szerepet töltött be Mohandász Karamcsand Gandhi (1869–1948)\nIndiában a brit gyarmati uralom már a két világháború között meggyengült. Gandhi, a hindu Nemzeti Kongresszus egyik vezetője már az 1920-as évek elejétől erőszakmentes polgári ellenállást hirdetett. Gandhi a követőitől a Mahatma melléknevet kapta, ami azt jelenti, hogy nagy lélek. A látványos tömegmozgalmakat szervező és a britek által többször bebörtönzött Gandhi egy független, egységes India megteremtését tűzte ki célul. Az egység megőrzésére azonban egyre kevesebb esély volt, mivel Indiában kiújultak a hindu-muzulmán ellentétek. A lakosság mintegy egynegyedét kitevő muszlim népesség nevében fellépő Muzulmán Liga már egy iszlám többségű önálló ország, Pakisztán létrehozása mellett állt ki. Az ellentétek csak látszólag csökkentek a világháború alatt. Nagy-Britannia közel 2,5 millió indiai katonát mozgósított, miközben London számára is nyilvánvaló volt, hogy az indiaiak háborús erőfeszítése még inkább erősíti a függetlenségpárti erők öntudatát.\n\nA háború után néhány hónappal a 400 milliós országban kaotikus állapot alakult ki. 1946 elején tömegtüntetések, sztrájkok kezdődtek, és a flotta egyes erői megtagadták a parancsot, majd a vallási ellentétek erőszakba torkolltak. A brit kormány a helyzetet az ország függetlenségének megadásával, illetve a hindu és muzulmán területek szétválasztásával kívánta orvosolni.\n\n1947 augusztusában véget ért a brit gyarmati uralom, Delhiben kikiáltották India függetlenségét, az ország első miniszterelnöke Dzsaváharlál Nehru lett.\n\nAz új államok megszületését véres vallási konfliktusok, etnikai tisztogatások kísérték. Mintegy 12 millió ember kényszerült lakóhelye elhagyására, a modern kori népvándorlás során kölcsönös tömegmészárlások zajlottak. Az elszabadult indulatokat Gandhi sem tudta megfékezni, és a nagy tekintélyű politikust egy hindu fanatikus 1948-ban meggyilkolta. Rövidesen háború tört ki India és Pakisztán között a két ország határán fekvő Kasmír tartományért. Az első indiai–pakisztáni háború a tartomány átmeneti felosztásával zárult, de a két ország a következő évtizedekben még kétszer vívott nyílt háborút. (1971-ben az indiai hadsereg segítségével Kelet-Pakisztán Banglades néven önállósult Karachitól.) A kasmíri határok kérdése napjainkban is állandó feszültségforrás a két ország között, a szembenállás súlyát pedig növeli, hogy 1998 óta mind India, mind Pakisztán atomfegyverrel rendelkezik.\n\nNehru 1947-től 1964-ig volt India miniszterelnöke; 1966 és 1977, majd 1980 és 1984 között lánya, Indira Gandhi volt a kormányfő, akit fia, Radzsiv Gandhi követett 1984 és 1989 között\n\nIndia történetének összegzése:\n\nA második világháborút követően Nagy-Britannia feladta gyarmati pozícióit. Brit-India helyén 1947. augusztus 15-én egyszerre kiáltották ki a hindu India és a muzulmán Pakisztán függetlenségét. A szétválasztás azonban megoldhatatlan problémákat okozott: a muszlim többségű területek India északkeleti és északnyugati „sarkában\", egymástól mintegy ezer kilométerre terültek el; ráadásul szét kellett választani két vegyes lakosságú tartományt, nyugaton Pandzsábot, keleten Bengáliát. Ezeken a területeken lehetetlen volt igazságos határokat húzni, aminek drámai következményei lettek: 12-14 millió ember menekült a „saját” országába, becslések szerint fél és kétmillió között volt a kölcsönös mészárlások áldozatainak a száma. Kasmír hovatartozása miatt Pakisztán és India között háború tört ki, amelyet 1949-ben fegyverszünet zárt le. A tartományt kettévágó demarkációs vonal mentén évtizedek óta tartó összecsapások zajlanak. A felosztást követően India lakosságának több mint tizede - ami az ezredfordulón mintegy százmillió embert jelentett - muzulmán maradt.\n\n1970-ben Kelet-Pakisztánban felkelés robbant ki a nyugat-pakisztáni uralom ellen, s India, ahová milliószám érkeztek menekültek, beavatkozott a harcokba. A kelet-pakisztáni felkelők indiai segítséggel győzni tudtak, elszakadtak Pakisztántól, és Banglades néven létrehozták saját független muszlim államukat. Pakisztán és India konfliktusainak veszedelme, hogy 1998 óta mindkét állam rendelkezik atomfegyverrel.\n\nPakisztánban nem tudott meggyökeresedni a demokrácia, történelmének fél évszázada alatt többnyire katonai diktátorok irányították. India a vallási és etnikai sokszínűség ellenére megteremtette a parlamentáris demokrácia intézményi kereteit, és fenn tudja tartani azokat. Különösen fontos szerepet játszott ebben az Indiai Kongresszus Párt és a Nehru-család: Dzsavarharlal Nehru 1947-től 1964-ig volt India miniszterelnöke; 1966 és 1977, majd 1980 és 1984 között lánya, Indira Gandhi volt a kormányfő, akit fia, Radzsiv Gandhi követett 1984 és 1989 között. Mindkettőt merénylők ölték meg.\n\nA Kínai Népköztársaság létrejötte\n\nA kínai polgárháború következményei\n\nKínában már a két világháború között polgárháború dúlt a nacionalista jellegű Kuomintang (Nemzeti Párt) hadserege és a kommunista erők között. A fegyveres harcokat a japán támadás kezdetén (1937) átmenetileg felfüggesztették. Az Amerikai Egyesült Államok fontos szerepet szánt a háború utáni Kínának, így vált az ország az ENSZ Biztonsági Tanácsának vétójoggal is rendelkező állandó tagjává.\n\nA Csang Kaj-sek vezette Kuomintang jelentős anyagi és fegyveres támogatást kapott a japánok elleni harchoz Washingtontól. 1945-ben azonban Északkelet-Kínában a szovjet csapatok is megjelentek, amikor Mandzsúriából kiszorították a japánokat. Sztálin nyíltan a Mao Ce-tung vezette Kínai Kommunista Pártot támogatta, és a Vörös Hadsereg felfegyverezte az ottani kommunista partizánokat.\n\n1946-ban a Kuomintang újrakezdte a polgárháborút. Csang Kaj-sek azonban rosszul mérte fel az erőviszonyokat. Bár kezdetben a hadsereg túlerőben volt, de a kommunisták a parasztság soraiból toborozva megnövelték haderejüket, és ellentámadásba lendültek.\n\n1949 őszén a Kuomintang vereséget szenvedett, majd a Csang Kaj-sekhez hű erők Tajvan szigetére menekültek. Mao Ce-tung Pekingben kikiáltotta a Kínai Népköztársaságot, és rövid idő alatt sztálinista jellegű diktatúrát vezetett be. A kibontakozó hidegháborúban a Truman-doktrína kihirdetését követően az Amerikai Egyesült Államok már csak azt tudta megakadályozni, hogy ne induljon fegyveres invázió Tajvan ellen. Washington 1971-ig a szigeten kiépülő Kuomintang-rezsimet tekintette a hivatalos Kína jogi örökösének, ezért például az ENSZ Biztonsági Tanácsában Kína tagságát Tajvan képviselői látták el. A kelet-ázsiai geostratégiai erőviszonyok Mao Ce-tung győzelmével jelentősen átrendeződtek, a kínai pártfőtitkár rövidesen Moszkvában egyeztetett Sztálinnal, majd a két ország barátsági szerződést kötött. Kommunista diktatúrát vezettek be.\n\nKínában az ötvenes években a szovjet gazdaságpolitikai elveket vették át, bevezették a tervutasításos gazdálkodást, és a nehézipar fejlesztését erőltették, illetve kollektivizáltak a mezőgazdaságban. Az elhibázott gazdaságpolitikai döntések idézték elő a „nagy ugrás” időszakának (1958–1961) tragikus következményeit. A mezőgazdasági termelés szétzilálása országszerte óriási éhínséghez vezetett, amelynek több millió ember esett áldozatul.\n\nLATIN-AMERIKA - DEMOKRÁCIA ÉS DIKTATÚRA KÖZÖTT\n\nA latin-amerikai országokat a XIX. század óta fontos, sokáig egyenlőtlen viszony fűzte az Egyesült Államokhoz: az USA gazdasági és katonai fölényét kihasználva többször is beavatkozott a régió államainak politikájába. Ezért is érezte sok latin-amerikai, hogy helyzetük sokban rokon a volt gyarmati népekével. 1954-ben az USA által támogatott emigránsok fegyverrel döntötték meg a guatemalai rendszert; ezzel próbálkoztak 1961-ben Kubában is, de sikertelenül. Haitiben 1965-ben avatkoztak be amerikai tengerészgyalogosok a polgárháborúba, majd az 1990-es években ismét. Az USA titkosszolgálata, a CIA támogatta a Pinochet-puccsot Chilében, s Nicaraguában a baloldali kormány ellen harcoló gerillákat. Panamában 1989-ben szálltak partra amerikai csapatok, hogy eltávolítsák a hadsereg főparancsnokát, a kábítószer-csempészettel vádolt Noriega tábornokot.\n\nA XX. század második felében Latin-Amerika országainak politikai viszonyait a demokrácia és a diktatúra sajátos „váltógazdasága” jellemezte: alig volt olyan állam, amely ne élte volna meg hosszabb-rövidebb ideig mindkét rendszert.\n\nA kivételek közé tartozott Mexikó: itt az 1928-baa hatalomra jutott Intézményes Forradalmi Párt sajátos, korlátozott parlamentarizmust épített ki, amelyben a párt jelöltje mindig meg tudta nyerni az elnökválasztást. 1989-ig ez a párt adta valamennyi szövetségi állam kormányzóját és az összes polgármestert is. A kilencvenes években inogni kezdett az egypárti rendszer, s az ellenzék mind nagyobb szerephez jutott.\n\nA demokráciát Latin-Amerikában két oldalról fenyegeti veszély: egyrészt a régióban aktív politikai szerepet játszó hadseregek részéről, amelyek gyakran ragadták magukhoz államcsínnyel a hatalmat (az ilyen katonai kormányzatot juntának is nevezik); másrészt a forradalmi, általában marxista ideológiája mozgalmak részéről. Kolumbiában például már évtizedek óta tart a gerillaháború: egész országrészeket tartanak ellenőrzésük alatt magukat marxistának valló, de a kokain termesztésében és árusításában is részt vállaló felkelők. „Valódi”, egypártrendszerű kommunista diktatúra azonban egyedül Kubában épült ki a kontinensen.\n\nFEKETE-AFRIKA\n\nAfrikának a többségében fekete bőrű őslakosság által lakott, a Szaharától délre eső részét - megkülönböztetve a többségében arabok lakta Észak-Afrikától - Fekete-Afrikának is nevezik. Ezen a területen a felszabadulást követően a helyi többség vette át a hatalmat. A kivételek közé tartozott Dél-Afrika, ahol többmilliós - bár így is kisebbségben lévő - fehér népesség szerezte meg a hatalmat. A fehér kisebbség politikáját a rasszista elkülönítés, az apartheid jellemezte egészen 1990-ig, amikor a fekete többség békés átmenettel vette át a hatalmat.\n\nA dél-afrikai fekete népesség képzettebb, és jobban elszakadt a törzsi hagyományoktól, mint a kontinens többi részén élők. Legfontosabb szervezetük, az Afrikai Nemzeti Kongresszus (ANC) a két világháború között kezdte meg működését A kezdetben gandhista elveket követő ANC 1960-as betiltását követően kezdett fegyveres harcot A dél-afrikai rezsim végül 1990-ben tárgyalásokat kezdett az ANC-vel.\n\nA függetlenség elnyerése óta Afrika népei súlyos, reménytelen helyzetbe kerültek. A gazdaságot nem sikerült modernizálni, s lemaradásuk a világ többi részétől növekedett a XX. század második felében. Fekete-Afrika északi részét ökológiai katasztrófa is sújtja: a kiszáradás következtében évről évre terjeszkedik a Szahara, tovább csökkentve az amúgy is csekély termőföld területét.\n\nFekete-Afrika egyik legnagyobb problémája a népességrobbanás: a kontinensen a népesség gyorsabban növekszik, mint a termelés. Kenya lakossága például függetlensége első három évtizedében megnégyszereződött. Az ötvenes-hatvanas években elterjedő modern gyógyászati eljárások - mindenekelőtt a védőoltások - nagymértékben csökkentették a korábban igen magas csecsemőhalandóságot, miközben a születések száma alig változott. Míg például Kínában vagy Indiában a kormányzat kampányokat indított a születésszám csökkentése érdekében, a fekete-afrikai kormányoknak nincsenek eszközeik e cél megvalósítására. Afrikában még mindig a sokgyerekes családot tartják eszménynek, s mivel az állami intézmények alig működnek, az afrikaiak szinte kizárólag rokonaikra támaszkodhatnak.\n\nAz afrikai államok gondjait növeli az etnikai és törzsi sokszínűség. Az országok vezetésében általában egy-egy etnikum vagy törzs tagjai játszanak szerepet, a többiek kiszorulnak a hatalomból, ezért gyakoriak az etnikai jellegű konfliktusok, melyek olykor polgárháborúba torkollnak.\n\nA nyelvi, etnikai határok gyakran Afrikában sem esnek egybe az államhatárokkal, amiért a gyarmatosítókat hibáztatják. De például Etiópiában - amely sok évszázados államisággal rendelkezik, s néhány éves olasz uralmat leszámítva nem volt gyarmat - 76 etnikai csoport és 286 beszélt nyelv található. A kormányok a felmerülő problémákat nem képesek kezelni, sőt, gyakran inkább fokozzák azokat. A legtöbb fekete-afrikai országban egypártrendszer vagy katonai diktatúra alakult ki, a vezetőt övező személyi kultusszal. A választások csak nagyon ritkán szabadok valóban.\n\nAZ ARAB VILÁG\n\nÉszak-Afrikától a Közel-Keleten át a Perzsa-öbölig húzódó arab világba 21 állam tartozik. Egy részük - Marokkó, Jordánia és az Arab-félsziget legtöbb országa - konzervatív monarchia maradt, amelyekben vagy egyáltalán nincsenek választott képviseleti szervek, vagy csak nagyon szűk hatáskörrel rendelkeznek. De az arab köztársaságokban is rendszerint csak színjáték a választás, az államfők kezében diktatórikus hatalom összpontosul.\n\nTársadalmi, gazdasági és politikai különbségeik ellenére az arab államoknak közös problémáik is vannak: ilyen mindenekelőtt az arab-izraeli konfliktus, valamint az iszlám fundamentalizmus veszélye, amely a konzervatív monarchiákat és az „arab szocialista\" köztársaságokat egyaránt fenyegeti. Az országok közös gondja a túlnépesedés és a lassú gazdasági növekedés, valamint az erőszak alkalmasa a politikai életben. Az arab országok lakossága az 1950-es évekre elérte a 100 milliót, az ezredfordulóra a 280 milliót; a világon ebben a régióban a legmagasabb a fiatalok aránya. Ugyanakkor ezen országok együttes nemzeti jövedelme kevesebb, mint a 40 milliós Spanyolországé. Ötödannyi külföldi könyvet fordítanak le évente arabra, mint ahányat Görögország a maga nyelvére, s átlagosan a GDP 0,5%-át költik oktatásra és kutatásra (a világátlag 3,5%).\n\nBár világszerte legendásnak számít az arab olajmonarchiák gazdagsága, az olajvagyon jellegzetesen zsákutcás fejlődést alakított ki ezekben az országokban. Jó példa erre Szaúd-Arábia: itt található a világ olajkészletének negyede, az ország a világ legnagyobb kitermelője, s ez óriási bevételekhez juttatja. A népesség száma azonban gyorsan növekszik, az ezredfordulón már 18 millió körül járt; egyharmaduk munkanélküli, miközben 6 millió külföldi vendégmunkás dolgozik olyan szakmákban, amelyeket a helyiek alantasnak tartanak, vagy amelyek magas képzettséget igényelnek. Az egy főre jutó nemzeti jövedelem 1980-ban még 28 600 dollár volt, az ezredfordulón már csak 6800 dollár. Szaúd-Arábiában nő az iszlám fundamentalizmus ereje, s a nemzetközi terroristák között is mind több a szaúdi. Jelenleg a szíriai háború miatt rengeteg menekült érkezik Európába, amelynek megoldásában az Európai Unió vezetőinek álláspontja eltérő. Egyre fenyegetőbb a menekülthullám és a terrorveszély.\n\nBár sok európai használja szinonimaként az „arab” és a „muzulmán” kifejezéseket, a világ muszlimjainak többsége nem arab, hanem török, perzsa, indonéz. Egyedül az indiai szubkontinensen több muzulmán él, mint az arab országokban összesen, összekeveredve a még nagyobb lélekszámú hindu népességgel.\n\nA közel-keleti helyzet összetevői, az izraeli állam\n\nA brit mandátum sorsa Palesztinában\n\nPalesztina a két világháború között népszövetségi mandátumterületnek számított, ahol Nagy-Britannia gyakorolta a felügyeletet. A mandátum a Népszövetségtől az első világháborúban győztes hatalmaknak adott megbízás a volt német gyarmatok és török területek igazgatására.\n\nNagy-Britannia még az első világháború előtt ígéretet tett egy „zsidó nemzeti otthon” megteremtésére. Ezt követően egyre több zsidó család telepedett le Palesztinában, ami hamar komoly vallási és etnikai feszültséghez vezetett a helyi arab lakossággal. A zsidóság érdekképviseletét a britek által elismert Zsidó Ügynökség és annak vezetője, Dávid Ben Gurion látta el. Az arab lakosság és a környező arab államok ellenkezésére a brit hatóságok 1939-ben korlátozták a betelepülő zsidók számát. A világháború után az amerikai kormány nyomására mégis engedélyezték a holokauszt-túlélők letelepedését, ami még tovább fokozta a feszültséget a térségben. Ezzel egy időben cionista fegyveres csoportok a britek kiűzését tűzték ki céljukul, és számos merényletet követtek el ellenük. A londoni kormányzat számára világossá vált, hogy a mandátumterület fenntarthatatlanná vált. London a palesztin kérdést az ENSZ elé utalta.\n\n1947 őszén az ENSZ egy önálló zsidó, illetve egy önálló arab állam megteremtése mellett állt ki, továbbá nemzetközi fennhatóság alá rendelte a három világvallás szent városának tekintett Jeruzsálemet. Az ENSZ-határozat végrehajtása azonban nem valósult meg. A zsidó szervezetek elfogadták ugyan a határozatot, de hangsúlyozták, hogy a számukra kijelölt terület stratégiailag védhetetlen. Az arab országok képviselői teljesen elutasították Palesztina felosztását. A térségben elszabadult az erőszak, a kölcsönös merényleteket gyakran etnikai tisztogatások kísérték. A zsidó szervezetek rövidesen meghozták a döntést, és 1948 májusában bejelentették Izrael Állam létrejöttét. Az ország első miniszterelnöke Ben Gurion lett.\n\nA konfliktus most már nyílt háborúvá változott, a környező arab országok hadereje (Egyiptom, Jordánia, Szíria, Libanon és Irak) rátámadt Izraelre. Az első arab–izraeli háborúban (1948–1949) Izrael Állam győzelmet aratott, miközben elfoglalta az ENSZ-határozatban arab területnek kijelölt térségek jelentős részét is. A háború végén több százezer palesztin menekült el a környező arab országokba, ahonnan szintén sok zsidót űztek el. A hidegháborús „logika” a közel-keleti konfliktusban is érvényesült. Az 1950-es években az Amerikai Egyesült Államok haditechnikai eszközökkel és pénzügyi támogatással Izrael Állam mögé állt, míg a Szovjetunió az arab országok felé nyitott.\n\nA fejlődő országok demográfiai helyzete\n\nA XX. század második felétől un. demográfiai robbanásnak lehetünk tanúi. A technológiai vívmányoknak köszönhetően folyamatosan csökken a halálozási ráta, tehát a népesség túlélési esélyei egyre javulnak. A születésszám emelkedése elsősorban az afrikai, dél-amerikai és ázsiai kontinensre jellemző, ahol az 1950-60-as évektől indult meg a növekedés. Az un. harmadik világ országai felszabadultak a gyarmati sorból és átvették a fejlett világ technikai-egészségügyi vívmányait (pl. gyógyszerek, termelési technikák).\n\nA népesedési centrumok fokozatosan a fejlődő országok irányába tolódtak el, ahol ezzel együtt sok, egymással szorosan összefüggő társadalmi probléma merült fel. A gazdasági elmaradottság és az elégtelen oktatási színvonal miatt alacsonyak voltak a munkabérek, ami általános nyomorhoz vezetett, ez pedig fokozta a kiszolgáltatottságot. Az éhezés mindennapos probléma és csak kisebb részben vezethető vissza természeti katasztrófákra: egyrészt nem terem elegendő élelem, másrészt a megtermelt élelmiszer elosztása sem egyenletes.\n\nBár Európában több járványt sikerült megfékezni a század folyamán, a fejlődő országoknak folyamatosan szembe kell nézniük a tbc, a tífusz, az AIDS, az Ebola stb. veszélyeivel. A segélyezés rendszere több akadályba ütközik: sok esetben nem az arra szánt helyre és célra jutnak el a szállítmányok, valamint a nyugati országok általában követelményekhez kötik a segélyek felhasználását (pl. a politikai rendszerek demokratizálásához), ami a gyarmati sorból felszabadult országokban ellenérzéseket szülhet, ezért a segélyezés a humanitárius katasztrófáknak csak megelőzésére, enyhítésére alkalmas.\n\nA világ demográfiai helyzete aránytalan: míg a fejlődő országok magas születési aránnyal (túlnépesedéssel), rossz életszínvonallal és alacsony várható élettartammal, addig a nyugati államok a népességcsökkenéssel és a hosszú várható élettartam miatti elöregedéssel küzdenek. A fogamzásgátló módszerek használata és a tudatos családtervezés nyomán a nők egyre idősebb korban vállalnak gyermeket. Ezzel azonban csökken a jövőbeni munkaerő száma, miközben az élettartam folyamatosan nő. így a következő generációk szociális ellátása veszélybe kerül. Európa stagnáló, illetve csökkenő népességszámát a fejlődő világból bevándorlók kompenzálják ugyan, de ez még a toleráns országokban is társadalmi, vallási és kulturális feszültségekhez, illetve a szociális ellátórendszerek válságához vezethet.\n\nMegoldási lehetőségek\n\nA népesedés jelenlegi üteme mellett 2050-re kb. tízmilliárd ember élhet a Földön, a bolygó természeti adottságai viszont nem teszik lehetővé a jelenleginél sokkal nagyobb népesség eltartását. A világ nemzetközi szervezetei számos utat kipróbáltak a népesedési problémák enyhítésére. Az elmaradott országok élelmezésének javítására az ENSZ 1945-ben létrehozta a Mezőgazdasági és Élelmezési Szervezetet (FAO - Food and Agriculture Organization, székhelye Róma), amelynek célja a jobb táplálkozás, az élelmiszerbiztonság és a mezőgazdasági fejlesztések elősegítése. Emellett a túlnépesedés környezeti hatásaival, az élelmiszer-elosztás javításával és nagyobb hozamú, egy évben többször begyűjthető növényfajták elterjesztésével foglalkozik. Az ENSZ másik szakosított intézménye az Egészségügyi Világszervezet (WHO - World Health Organization, székhelye Genf), amely együttműködik a nemzetállamok kormányaival az egészségügyi programok, technológiák és szabványok tervezésében és irányításában. Ezen kívül az egyes országok kormányai is igyekeznek saját érdekeiknek megfelelően szabályozni a lakosságszámot. Kínában például a túlnépesedés elleni politika a születésszabályozásban (egy családban egy gyermek) öltött testet, míg egyes európai államokban gyermekvállalást ösztönző családtámogatási programokat indítanak.\n\nKiugrási pont lehet az oktatás fejlesztése, a kis energiaigényű technológiai újítások (lásd a délkelet-ázsiai „kistigrisek” gazdaságait), a széles körű egészségügyi felvilágosító kampányok bevezetése és a fejletlen országok gazdaságai számára a megfelelő termelési keretek kialakítása (pl. fair-trade), illetve területeik fokozatos fejlesztése (a városiasodással ugyanis csökken a népszaporulat), valamint a nők a munkavállalás területén tapasztalható hátrányos helyzetének megszüntetése. Mindehhez azonban a nemzetközi (pl. Vöröskereszt, Világkereskedelmi Szervezet) és regionális szervezetek (pl. Afrikai Unió, Arab Liga, Európai Unió, Délkelet-ázsiai Nemzetek Szövetsége) hatékonyabb együttműködése szükséges, ennek keretén belül pedig a gazdag országok (a G-20-ak) elkötelezett fellépése.', 216, 1, '2026-04-17 09:40:02', '2026-04-17 09:40:02');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(4, 4, 'Magyarország gazdasága 1867-től napjainkig', '4.docx', '4. tétel: Magyarország gazdasága 1867-től napjainkig\n\n(gazdasági változások a dualizmus korában, a trianoni béke gazdasági hatásai, gazdasági konszolidáció az 1920-as években és a gazdasági válság, Rákosi- és Kádár-korszak gazdasága, gazdasági rendszerváltoztatás)\n\nA dualizmus gazdasága\n\nAz 1867-es kiegyezés során kétközpontú, azaz dualista állam jött létre, neve Osztrák - Magyar Monarchia. Az alkotmányos monarchia uralkodója: Habsburg Ferenc József (1848/67-1916). A politikai kiegyezést gazdasági kiegyezés is követte. A két ország egymástól független, azonban az uralkodó személye és a közös ügyek kötik össze őket: a külügy, a hadügy és a pénzügy. A közös ügyeket a birodalmi gyűlésből és a magyar parlamentből választott 60-60 tagú „delegátus” intézi. A magyar országgyűlés kétkamarás. A parlamentnek felelős a kormány. Az első gróf Andrássy Gyula kormánya volt 1867-től.\n\nA kiegyezés gazdasági hatása:\n\nGazdasági kiegyezés 10 évre szóló (majd meghosszabbítandó) vámunió.\n\nKözös maradt a pénzrendszer (korona), a mértékrendszer;\n\nA közös költségekre kvótát állapítottak meg 70:30 arányban viselte a közös terheket Ausztria és Magyarország.\n\nA kiegyezés meggyorsította a magyar gazdaság fejlődését, és a tőkebeáramlás elősegítette a tőkés árutermelés előfeltételeinek megteremtését. A tőkés szabad versenyt a dualizmus rendszere hozta meg. Fejlődött a hitelszervezet, a bankalapítás.\n\nAz 1880-as évek közepétől a 2. ipari forradalom hatására a magyar ipar is fejlődött.\n\nA magyar kormányok adókedvezményekkel is segítették az ipar fejlődését.\n\nA fejlődés első jelei a közlekedésben, a hírközlésben, az oktatásban és hitelrendszerben jelentkeztek. Fejlődött az infrastruktúra. Jelentős volt a folyószabályozás, Európa leghosszabb gátrendszerének kiépítése, és a dunai gőzhajózás. A vasútépítés gyors ütemét a külföldi tőke részvétele is elősegítette 1882-ben létrejött a Magyar Állami Vasút (MÁV). Baross Gábor közlekedési minisztersége (vasminiszter) idején kiépült a vasúthálózat, az egységes tarifarendszer.\n\nA vas- és acéltermelésnek köszönhetően világszínvonalú gépgyártás alakult ki (Ganz)\n\nA mezőgazdaságban megjelent a vetésforgó, a műtrágya és a cséplőgép.\n\nA korszakban agrár-ipari jellegű országgá alakultunk át. A cukor-, a szesz- és a malomipar terén fejlődtünk a legjobban. Budapest a malomipar központja lett.\n\n1873-ban egyesült Pest, Óbuda és Buda: Budapest lett a neve (korábban Széchenyi István nevezte így először) kb. 700 ezer lakossal rendelkezett a század végére. Felgyorsult az urbanizáció (városiasodás), az építkezések pl. Parlament, Operaház.\n\nNevezetesek az 1896-os millenniumi ünnepségek, melyeken Magyarország 1000 éves múltját ünnepelték. Pl. Hősök tere, földalatti, Vajdahunyad vára.\n\nWekerle Sándor miniszterelnöksége idején (1892-95) a koronát (a Monarchia pénzét) arany alapra helyezték.\n\nKifejtés:\n\nA magyar gazdaságot a kiegyezés előtt a birodalmi alárendeltség, a kitörés képtelensége jellemezte. A korábban eltörölt vámhatár miatt már az európai vérkeringésbe való bekapcsolódás lehetősége is adott volt, az elszigetelt és erőtlen magyar gazdaság erre azonban még képtelen volt. A kiegyezés törvényének gazdasági pontjai a magyar és az osztrák fél pénzügyi érdekeit egyaránt szolgálták. Magyarország számára viszont új időszámítást jelentett a kiegyezés: hatalmas, meglepetésszerű fellendülést indukált. A virágzást természetesen nemcsak a dualizmus új jogi rendszere, hanem például az is előmozdította, hogy Magyarországon a két ipari forradalom – az első elmaradása/késése miatt – összeért.\n\nA legjelentősebb változtatások értelmében az állami költségvetés közös fedezésére 70-30% arányban osztott kvótát hoztak létre, a birodalmat egyetlen egységes piaccá formálták, megújították a vámszövetséget, megerősítették a közös valutát, egységesített adó- és mértékrendszert vezettek be. A hírközlési és a közlekedési rendszert összehangolása elkezdődött. A belső, közös piac védelmére koncentrálva a külső importot korlátozó külső vámrendszert dolgoztak ki, mely a kezdetben tőkehiányos, csak drága előállításra képes, induló magyar vállalkozásokat is hatékonyan védte. Az egyre szélesedő és egységesedő piacok az egyébként is rohamosan növekvő polgárosodó tömegek keresletét tovább gerjesztették, ami piaci versenyt idézett elő, beindítva a rég várt befektetéseket. A szabad tőke- és munkaerő-áramlás lehetővé vált, ami megteremtette a nyugat-európai tőke gyorsabb beáramlásának és a magyar áruk Lajtán túli értékesítésének lehetőségét. Az osztrák fél számára a magyarok versenytárssá válása nehézséget jelentett, a törvényeket saját érdeküket érvényesítve kívánták keresztülvinni, de felismerték, hogy mindez csak kompromisszumokkal lehetséges. A két fél megegyezett, hogy a gazdasági megállapodásokat 10 évenként újra tárgyalják. Ennek megfelelően - a magyar gazdaság megizmosodásával - a költségvetési kvótát is módosították az arány növelésével.\n\nAz 1867 utáni ugrásszerű gazdasági fejlődés alappillére a modern szabad verseny aktivizálódása volt. Elviekben már a szabadságharc utat nyitott a tőkés szabad versenynek, ám csak a dualizmus rendszere hozta meg a megfelelő politikai, társadalmi biztonságot. Ennek következtében sokat nőtt a hitelbiztonság, a kamatok elérhetőbbek lettek, a hitel felvétele egyszerűbbé vált, így a befektetések számára nélkülözhetetlen hitelélet felvirágozhatott. Az állam szakítva a régi hagyományokkal egyre tudatosabb politikát folytatott a magyar gazdaság, a hazai vállalkozások, az ipar támogatása terén. Az állami szubvenció egyben jelentett pénzügyi kedvezményeket/engedményeket (pl.: adómentesség, kamatgarancia-kedvezmény) és aktív vállalkozásösztönző hitelek nyújtását, iparfejlesztő programok kidolgozását, melyek az állam befolyását fokozták. A költekező jellegű állam lassan maga is befektetővé vált, mi több - a vállalatokkal szorosabban összefonódva - az országos folyamatok fő alakítójává. Megalakultak az országos, regionális kereskedelmi és iparszervezetek, kamarák. Wekerle valutareformjával modernizálta a monarchia pénzrendszerét; a forint helyett bevezette a stabil koronát, és áttért az aranyalapú monetáris rendszerre.\n\nA tőkeigényes infrastrukturális fejlesztések a befektetések beindulásának legnagyobb mozgatóerejévé váltak. Az olcsó munkaerőt igénylő közlekedési, tereprendezési, városképi/építőipari beruházások mágnesként vonzották az újabb befektetéseket, az ipart és a kereskedelmet. A nyugat-európai infrastrukturális szinthez való igazodás rendkívül rövid idő alatt a legfejlettebb körülményeket teremtette meg az országban, az átlagos színvonal azonban főleg a peremterületek elmaradottsága miatt soha nem közelíthette meg a nyugatit.\n\nFelgyorsultak az ország térképét is átalakító, hatalmas földmunkákat igénylő gátépítések, folyórendezések. Több ezer kilométer hosszú gátrendszert építettek meg az állami és regionális társulások erőfeszítésével. Az eddig kihasználhatatlan folyók közül számos hajózhatóvá vált, és a vízi szállítás nagy szerepet kapott a korszakban. A folyami és állóvízi személyszállítás és a kompközlekedés rugalmasabb és komfortosabb lett. A mocsarak lecsapolásával, a tározó- és gátrendszerrel a nagy árhullámok kezelhetőbbé váltak, az árvízveszély folyamatosan eltűnt, de előtérbe került a belvíz problémája. Hatalmas, korábban időszakosan víz által borított területek és árterek szabadultak fel, melyeket mezőgazdasági művelésbe lehetett vonni. A földmunkákat a nagyszámú, jó munkabíró képességű kubikos tömegek végezték, akik jó fizetésükért szorgalmasan dolgoztak.\n\nA másik nagy húzóerőt a vasúthálózat kiépítése jelentette, amelynek jelentőségét Magyarország nagyon hamar felismerte, és erős tőkekoncentrációval, kivételesen nagy tempóban, európai szintű hálózatot épített ki. A reformkori építkezések a 67-es fordulat után felgyorsultak, a kormányok felismerték a vasút felzárkóztató és vállalkozásvonzó hatását, és a befektetőket hitelkedvezményekkel támogatták. A kezdetben magántőkéből épült vasútpályák tervezésekor a gabonatermékek kiemelt központjait, hadászati szempontokat és a nyersanyaglelőhelyeket vették figyelembe. Budapest-centrikus rendszer alakult ki, melynek sűrűsége a perifériák felé centrikusan ritkult. A legtöbb jó földrajzi helyzetű várost elérték a vasútépítők, ezzel gazdaságukat, áruforgalmukat fellendítve, azok a városok azonban, amelyek nem részesülhettek az új közlekedési forma áldásaiban, többnyire elveszítették jelentőségüket. A bányák, gyárak építésével összhangban épültek a vasúti mellékvonalak, sokszor az iparos és a vasúti társaság együttműködésével. Évek után létrehozták az állami tulajdonú MÁV-ot, amely a kisebb-nagyobb magántársaságok és pályaszakaszok felvásárlásával óriásvállalattá nőtte ki magát. Egységes, olcsóbb és színvonalasabb közlekedés vált így lehetővé. Sokak számára a vasút a hagyományos életforma megszűnését is jelentette, hiszen pl. városiasodott az addig poros, izolált falucska, családok szakadtak ketté az utazás gyorsasága, egyszerűsége (munkahelyi ingázás, felköltözés) miatt. A vasút mellett javult a közúthálózat, tökéletesedett a távközlés, a postai szolgáltatások új generációba léptek (pl. távírórendszer). A viharos gyorsaságú városfejlődést jelzi, hogy az 1873-ban egyesült Pest és Buda és Óbuda, az 1896-os millenniumi ünnepségek városnegyedeket teremtő építkezései után már 700 ezer lakossal rendelkezett. A liberális vezetőréteg fontosnak tartotta, hogy Budapest utolérje, sőt megelőzze a császárváros fejlettségét. A központi fekvés, a közlekedési központ jelleg (Duna, hidak, vasút, utak), a szakképzett munkaerő, az iparhoz szükséges infrastruktúra, a nagy piac mind adott volt ahhoz, hogy a főváros 1914-re Európa 10 legjelentősebb városa közé kerüljön.\n\nMialatt Európa mezőgazdasága piaci gondokkal küszködött, a magyar mezőgazdaság a monarchia védett piaca miatt folytatta konjunktúráját. A hetvenes évek világválságáig, az amerikai exportbúza megjelenéséig évről évre akadálytalanul bővült a gabona Lajtán túli értékesítése (a monarchia éléskamrája), de ezután részben a belterjes kultúrák felé (gyümölcs, szőlő, állattenyésztés) kellett fordulnia a gazdálkodóknak. A század végén a termelékenység javítása nyomán a termelés mennyisége folyamatosan bővült, ekkor már nem a termőterület, hanem a termésátlagok bővítésével. Mindeközben az agrárnépesség 60-62%-ra csökkent. A korábban kifejlesztett eljárások (alagcsövezés, műtrágya) és termelőeszközök (cséplőgépek, vasekék, vasboronák) először a tőkeerősebb nagybirtokokon jelentek meg. Az új technológiák bevezetésében nagy szerepet játszott, hogy elterjedt a bérleti rendszer, amelynek keretein belül tőkét hozó vállalkozók bérelhettek földet használatra. Mindemellett a nyugat-európaihoz hasonló birtokszerkezet-váltás nem történt meg, ami a polgárosodás folyamatát lelassította. A hegyvidéki és kisparcellás paraszti földeken minden maradt a régi a gazdálkodás terén. A korszakban a mezőgazdaságot és kereskedelmet támogató erők között kiéleződött az agrárius-merkantil ellentét.\n\nTerjedt a kapásnövények (burgonya, kukorica) és a cukorrépa főleg paraszti termesztése, melyek többnyire a szesz és- cukoriparra épültek rá. A városok környékén előretört a zöldség/gyümölcstermesztés és a tejgazdálkodás. A nyomásos rendszert végleg felváltotta a vetésforgó, az ugar megszűnt. A mezőgazdasági ágazatokra ráépültek a különféle élelmiszeripari ágazatok, a konzervipar a tömegek ellátását szolgálta. A kezdetben osztrák tőkéjű szesz- és konzervipar magyarrá vált. Budapesten kiépült a világ élvonalába kerülő malomipar, mely modern technológiával (Mechwart-henger) őrölt és sok ezer munkásnak adott kenyeret. A bortermesztőknek nagy érvágást jelentett a filoxériajárvány, és a parlagfű is ekkor került be az ország területére.\n\nAz agrárjellegű ország a korszakban agrár-ipari jellegű országgá alakult át. A fejlődés mindenre kiterjedt, de míg a mezőgazdasági termelés a század végén megkétszereződött, az ipari termelés mintegy nyolcszoros növekedésen ment át. A legtöbb későbbi ipari központ a nulláról indult, a városok kialakulása ettől fogva egyértelműen az ipari centrumok kiépülésének függvényévé vált. A központi régiók az országosnál jóval nagyobb mértékben iparosodtak, infrastruktúrájuk magasabb szintre jutott, mialatt a peremvidékeken elmaradoztak, lelassultak a befektetések (részben az elérhetőségi nehézségek, elzártság, a szakképzetlen munkaerő miatt). Az így kialakuló központ-periféria ellentét számos problémahalmaz (társadalmi, nemzetiségi ellentétek) okozójává vált, és jelentősen hozzájárult a dualizmus válságához.\n\nA 67-tól 73-ig tartó időszakban többek között az állam iparbarát politikájának és a kedvező hitelfeltételeknek köszönhetően az évi cégalapítások száma rekordokat döntött (gründolási láz), hatalmas mennyiségű külföldi tőkét fektettek be. A külföldi vállalkozások (főleg osztrák ill. francia/német) a behozott tőkével pozitív hatást fejtettek ki: a korszak végére már a magyar tőke vált maghatározóvá, a magyar gazdaság újabb befektetésekbe forgatta vissza a profitot. A külföldi hitelekből bányák, gyárak épülését finanszírozták. A hitelintézetek 73-ig gombamód szaporodtak. Ugyan a 1873-as, Európán végig söprő válság megritkította soraikat, de a megmaradó bankok megerősödtek és országos piaci erőt szereztek (Pesti Magyar Kereskedelmi Bank, Pesti Hazai Első Takarékpénztár). 1914-ben 5 ezer bank volt bejegyeztetve, ami jelzi, hogy ez az ágazat végig húzóerőt jelentett a dualizmus gazdasági konjunktúrájában. A pezsgő gazdasági élet központjaként a századfordulón megépült a budapesti árutőzsde impozáns épülete.\n\nA gőzgép térhódításával sorra nyíltak a szénbányák és a peremvidékeken a nemesércbányák. Ahol nagy bányaközpontok nőttek ki a földből, hamar rájuk épült a nyersanyagot feldolgozó nehézipar (vaskohászat, acéltermelés Borsodban, Szörény-vidéken, Hunyadban). A termelékenységet magas szintre tudták emelni, hiszen Európából készen vették át a legújabb ipari technológiákat, továbbá az olcsó munkaerő is könnyebbséget jelentett. A magyar ipar hamar az osztrákokat megelőzve a német gazdaság fejlődési sebességét produkálta és egyre nagyobb versenyt jelentett a monarchia többi ipari központjának (pl. Szilézia, Csehország). A verseny egyébként mindkét fél fejlődésére kedvező hatást gyakorolt. A nehézipari hagyományos iparágak mellett a 80-as, 90-es években sorra épültek a gépgyártás és a feldolgozóipar egységei. A gépgyártásban világszínvonalú termékeket dobtak piacra, sokszor magyar innovatív fejlesztés eredményeként és a sikeres megrendeléseket kapó, az európai piacra termelő cégek világcégekké nőtték magukat. A Ganz gyáróriás számos magyar találmány kovácsműhelyévé vált (elektromos turbina, transzformátor, háromfázisú elektromotor, porlasztó, karburátor, vízturbina, Bláthy, Déry, Zipernovszky, Kandó, Bánki, Csonka J.). A legmodernebb iparágak hamar tért nyertek, mint a vegyipar, az elektromos ipar, az autó/repülőgyártás és ezen ágazatok súlya a monarchiában lassan Magyarországra tevődött át. Az izzólámpagyártás világméretűvé nőtte ki magát, Puskás Tivadar révén elterjedt a korszakalkotó telefonhírmondó. A könnyűipar is mozgásba lendült, az eddig kizárólag Ausztria és Csehország központú textilgyáraknak magyar versenytársakkal kellett szembenézniük. A közepes méretű üzemek száma kisebb volt az átlagosnál, de sokan keresték betevőjüket kézműves műhelyekben.\n\nA 90-es évekre – a piacgazdaság következő lépéseként – megjelentek a monopóliumok, kartellek, trösztök. A piac megszerzéséért küzdő harcban egyre érzékelhetőbbé váltak a szabadversenyes kapitalizmus negatív tünetei, mint a túltermelés és a lehető legalacsonyabban tartott ipari bérek. A szegény munkásság helyzete romlott, a szociális háló (pl. betegsegélyezés, rokkant pénztár, munkásjogok, jobb munkafeltételek) kiépítéséért hamar szervezkedések, szakszervezetek, pártok alapultak. A korábban ismeretlen munkanélküliség leginkább a peremvidékeken ütötte fel a fejét. A demográfiai robbanás és a nagybirtokrendszer felbomlása, illetve a nehézipar kis munkaerőigénye következményeként a megélhetés egyes vidékeken nehezebbé vált. A gyorsan növekvő lakossággal és rossz mezőgazdasági adottságokkal rendelkező Felvidéken és Kárpátalján az átlagosnál nagyobb mértékben indult meg a kivándorlás vagy a migráció. Az elköltözők nagy része Budapestet vagy USA-t vette célba. A dualizmus alatt mintegy másfél millióan hagyták el Magyarországot. Számarányukhoz képest a legnagyobb arányban a szlovák és a ruszin nemzetiségűek vándoroltak ki.\n\nA föld nélküli parasztok még a 90-es években is aratósztrájkkal és zendüléssel akartak eredményeket elérni. A Viharsarokban kitörő lázadásokat keményen leverte a kormányzat. A korábbi középbirtokos rétegek jelentős része is vesztesnek érezhette magát a dualizmus átalakuló gazdaságában. A jobbágyfelszabadítás során nem kaptak akkora kártalanítást, hogy modernizálni tudják birtokaikat. A lepusztuló majorságokból származó állandó bevételük megszűnt, így csak a tőkével rendelkező vagy vállalkozásra képes családok tudták megtartani anyagi stabilitásukat és társadalmi rangjukat. Az elszegényedő közép- és kisnemesek (dzsentrik) ragaszkodtak a régi külsőségekhez, a látszat fenntartásával próbálták megtartani politikai befolyásukat és presztízsüket.\n\nMagyarország gazdasági súlya a monarchiában a századfordulóra akkorára növekedett - az osztrák befolyás csökkenése mellett -, hogy a politikai vezetésben is egyre inkább a magyar dominancia vált szükségszerűvé. A feudalizmus keretei azonban valamelyest megmaradtak, és a kapitalizmusra való áttérés nehézségeihez hozzáadódtak a feudalizmus maradványainak társadalmi problémái: torlódott társadalom.\n\nA trianoni békeszerződés és gazdasági hatásai\n\nAz első világháborút (1914-1918) követő békék:\n\n1918-ban véget ért az első világháború. Magyarország az Osztrák- Magyar Monarchia tagjaként vett részt az első világháborúban a központi hatalmak oldalán, így a vesztes országok közé tartozott. A háború végén, 1918-ban felbomlott a Monarchia.\n\nA győztes antant hatalmak: Nagy-Britannia, USA, Franciaország, Olaszország, Japán. 1919. január 18-án ült össze a versailles-i kastély tükörtermében a békekonferencia. A legfontosabb döntésekben 4 nagyhatalomnak volt döntő szava: Clemanceau francia, Lloyd George brit, Orlando olasz és Wilson amerikai elnök vezetésével. A konferencián elhatározták, hogy a veszteseknek a területi veszteségeken túl háborús jóvátételt kell majd fizetniük, flottájukat és légi erejüket leszerelték, csak korlátozott létszámú hadsereget tarthattak fenn, és el kellett törülniük az általános hadkötelezettséget. Vesztes országok: Németország, Ausztria, Bulgária, Magyarország és Törökország.\n\nA kisantant országok francia támogatásra területeket kaptak a történelmi Magyarországból, így jött létre: Csehszlovákia, Románia, Szerb – Horvát - Szlovén királyság (1929-től Jugoszlávia).\n\nMagyarországon 1918-ban az őszirózsás forradalom, 1919-ben a tanácsköztársaság kikiáltása, majd a fehérterror időszaka alatt nem volt olyan kormány, amelyet a győztes antant hatalmak elfogadtak volna, hogy békét kössenek velünk. Csak 1920-ban jött létre az antant által is elfogadható törvényes kormány, s ezt követően kötöttek Magyarországgal békét 1920. június 4-én a Párizs melletti Trianoni kastélyban. A magyar békedelegáció gróf Apponyi Albert vezetésével érkezett Párizsba 1920 januárjában. A küldöttség kifejthette álláspontját a békekonferencia előtt, de ez nem befolyásolta a győztesek döntését. A magyar küldöttség visszautasította a béketervezetet. Magyarország területi integritásának szükségességét hangsúlyozták, azt, hogy nem lehet egy ország történelmi, földrajzi, gazdasági és kulturális egységét megbontani. Apponyi az elcsatolandó területeken népszavazásra tett javaslatot. Wilson USA elnök önrendelkezési elvére hivatkozott a békeküldöttség: azaz minden nép maga döntse el, hogy melyik országhoz akar tartozni. Gróf Teleki Pál elkészítette Magyarország „vörös térképét”, amely jelöli, hogy mely területeken laknak többségében magyarok (vörös színnel). Az antant vezetői azonban elsősorban a csehszlovák, román, és jugoszláv követeléseket fogadták el, és a Millerand-levélben elutasították a magyarok kéréseit és tiltakozását: mivel Magyarország vesztes ország, nincs abban a helyzetben, hogy feltételeket diktáljon.\n\nA trianoni béke következményei:\n\nMagyarország területe 283.000 km²-ről 93.000-re csökkent, lakossága 18,2 millióról 7,6-re. A magyarság kb. 1/3-a 3,3 millió fő idegen fennhatóság alá került. Magyarország elvesztette a Felvidéket, Kárpátalját, Erdélyt, a Partiumot (Részeket), Bánátot, Bácskát, Burgenlandot (Őrvidéket). Romániához kb. 104.000 km² (Erdély és a Részek) és 1,6 millió magyar, Csehszlovákiához 61.000 km² (Felvidék, Kárpátalja) és 1 millió magyar, Jugoszláviához (Bácska, Bánát, Újvidék) 21.000 km² és 0,5 millió magyar, Ausztriához 4.000 km² (Burgenland) és 25.000 magyar.\n\nA békeszerződés gazdasági következményei:\n\nA területi veszteségeknél is súlyosabb következményekkel járt a béke a gazdasági struktúra számára. A magyar ipar a dualizmus korában kezdett fejlődni, a századfordulóra már jelentős tényezővé vált. Az ipari körzetek elcsatolásával azonban a magyar gazdaságban újra a mezőgazdasági jelleg dominált. A bányák, vízierőművek, az erdők nagy részét elveszítettük, az adriai kereskedelemhez való hozzájutásunk megszűnt. A közlekedés, áruszállítás is nagymértékben akadályoztatva volt: a közutak, a hajóutak döntő része a határon kívülre került.\n\nA jóvátétel fizetésén kívül (a 20-as évek végéig Magyarország 30 millió aranykorona jóvátételt fizetett) a különböző katonai (max. 35.000 fő katonát tarthatunk csak fenn) és kereskedelmi korlátozások voltak. Az etnikai elvet csak a környező népek esetében vették figyelembe, s azzal nem törődtek, hogy több millió magyar került idegen uralom alá. Súlyos gazdasági válságot okozott Magyarországon, hogy a nyersanyagforrások, bányák, vasúthálózat nagy része az országhatáron kívül maradt.\n\nJelentős nyersanyagkészlet-csökkenés (vasérc: Felvidék, Dél-Erdély / só: Kelet- Erdély / fa: Felvidék) Az Osztrák-Magyar Monarchiához méretezett ipari kapacitás nyersanyag nélkül maradt.\n\nipari hanyatlás: faipar, gyáripar, nehézipar, bányászat nagy része → elcsatolt területeken. Szénbányák: csak barnaszén (Salgótarján, Tata, Pécs környéke) marad meg.\n\nAlföld értékes részeinek elvesztése (Bácska, Bánát), búzaterületek elvesztése (Szerbia, Erdély) → malomipar, élelmiszeripar összeomlása. Külföldön a magyar gabona nem tudott versenyre kelni az olcsóbb amerikai gabonával.\n\nKözigazgatási központok elvesztése (Kassa, Pozsony, Kolozsvár, Arad, Temesvár)\n\nMegmaradt városok peremre szorulnak, elvágták őket gazdasági hátterüktől (Miskolc, Kaposvár, Szeged, Pécs, Debrecen)\n\nSzomszéd államok: önellátó gazdálkodása miatt az OMM árukereskedelme megszűnik\n\na szomszédos országok protekcionista gazdaságpolitikát folytatnak, de Magyarországgal szemben (a hazai gazdaságot védő, másokat kiszorító).\n\nközlekedés: centrális hálózat (Budapest) → végpontokhoz közeli szakaszok leválnak A vasúti hálózat több mint felét elcsatolták, azonban ez a vasútvonal pókhálószerű felépítése miatt még súlyosabb következményekkel járt, hiszen a második kör fő csomópontjai már más ország területén helyezkedtek el. (Kassa, Pozsony, Losonc, Arad. Fülek, Szatmárnémeti)\n\nA vasúthálózat fele az országhatáron kívülre került; a mozdonyok, vagonok száma csökkenést (a román megszállás során elviszik)\n\nA kialakuló gazdasági-társadalmi válság során tehát Magyarország a nyersanyag-bázisa jó részét elvesztette, az állatállomány, az erdők, bányák, termőföldek, kőolaj és az infrastruktúra (vasút, közutak) nagy része a szomszédos országokhoz került. Hazánk külkereskedelemre utalt országgá vált.\n\nFoglalkoztatási gondok keletkeztek: a gazdaság már nem volt képes felszívni a falusi munkaerőt, ráadásul a kivándorlási láz is alábbhagyott (az USA évi 473 főben határozta meg a magyar bevándorlási kvótát). Az áttelepülők (főleg értelmiségiek, tisztviselők, Amerikából hazatelepülők) lakás és állás nélkül maradtak, növelve a hajléktalanok számát. Vagonokban laktak a szomszédos országokból átmenekülő magyarok.\n\nIpartelepek- 48%-a maradt az új országban\n\nGyáripari termelés 55%\n\nVasérctermelés 11%\n\nTextilipar 42%\n\nVasúthálózat 38% (fontos csomópontok határon kívül kerültek)\n\nSzántóföldek 42%, ennek ¾-e csak 1-5 hold nagyságú\n\nÉlelmiszeripar 57% (túl sok, le kell építeni)\n\nLakosság 89% magyar lesz\n\nVároslakók aránya 30%-ra nő (1910: 20%!)\n\nA trianoni békeszerződés példátlan mértékű területvesztés volt, ezt a magyarság nem tudta elfogadni és tragédiának fogta fel. A kormányok célja ezután a revízió, azaz a béke felülvizsgálata, a határok visszaállítása volt.\n\nBethlen István gazdaságpolitikája\n\n1921-31: 10 éven keresztül miniszterelnök: 1921.ápr.14 - 1931.aug.24.\n\nA Bethlen-féle konszolidáció és Trianon hatásai\n\nAz 1920. június 4-én aláírt trianoni béke után Magyarország elvesztette területének több, mint kétharmadát és lakosságának több mint 65 %-át. A béke felborította az ország gazdasági életét, hiszen az új határokon kívül maradt a nehézipar működtetéséhez szükséges összes nyersanyagforrás. A nemzeti vagyon jelentős részét pedig a háború elvesztése miatt az antanthatalmaknak fizetett jóvátételre kellett fordítani.\n\nStabilizációs lépések:\n\n• Rendezték a nyitott határkérdéseket (pl. 1921-ben soproni népszavazás).\n\n• A sikertelen második „királypuccs” (1920. okt. 20-23.) után a nemzetgyűlés 1921. nov. 06-án detronizálta a Habsburgokat.\n\n• A gazdasági élet stabilizálásához a politikai élet konszolidációjára volt szükség: Bethlen a belpolitikában uralkodó szerephez akarta juttatni a konzervatív politikai tábort, amely a háború előtti korlátozott parlamentarizmus újbóli megvalósítását tűzte ki célul.\n\n• Bethlen ezért megkezdte kettős küzdelmét:\n\na paraszti (Kisgazda), polgári, munkás (MSZDP) demokrata politikai tábor ellen, amelynek elképzelése: a háború előtti politikai rendszer nagyfokú demokratizálása;\n\na jobboldali radikális csoportosulások ellen, amelyek a parlamentarizmus korlátozását vagy felszámolását hirdették.\n\n• A két politikai táborral szembeni fellépés, egyben a konzervatív politikai rendszer konszolidációját is jelentette:\n\n- 1921: Bethlen-Peyer paktum megkötése (Megegyezés az MSZDP-vel, hogy ha korlátozza a kormánnyal szembeni fellépését, akkor visszatérhet a politikai életbe.)\n\n- 1922: Egységes Párt létrehozása (A legitimista KNEP helyett a Kisgazdapártra alapozódó új, erős kormánypárt.)\n\n- 1922: a választójog módosítása (Szűkítették a választásra jogosultak körét úgy, hogy a feltehetően legitimista, illetve kisgazda szavazóbázist kizárták a választásokból, továbbá visszaállították a nyílt szavazást.)\n\n- 1923: a szélsőjobb kiszorítása a kormánypártból (Gömbös és csoportja kilépett az Egységes Pártból és megalakították a Fajvédő Pártot.)\n\n- 1926: új felsőházi törvény (Konzervatív többségű felsőház létrehozása.)\n\nGazdasági stabilizáció és konszolidáció\n\nFolytatta a Teleki-kormány idején, 1920-ban elkezdett földreformot. Nagyatádi Szabó István miniszter vezetésével kezdték el a földreformot hajtottak végre (1920 végén) Családtagokkal együtt kb. 2 millió embert érintett, de a nagybirtokokhoz nem nyúltak.\n\nA Nagyatádi-féle földreform és a mezőgazdaság a húszas években (1920-22)\n\nA kormányzat az alsóbb néprétegek körében csak földreform útján tehetett szert valamiféle legitimációra, legfontosabb támogatóinak, a nagybirtokosoknak az érdekeit viszont nem hagyhatta figyelmen kívül. A földeknek csupán egytizedét osztották fel, de ezeknek is egy részét közcélra vették igénybe, így nem alakultak ki életképes paraszti birtokok, és nem enyhült a munkanélküliség sem: kb. 300.000-en kaptak 1-2 hold birtokot a szegényparasztok, de kb. 100.000 25-50 holdas „vitézi telket” osztottak ki a Horthy-rendszer egykori katonáinak. Az 1920-as évek mezőgazdaságában főleg a gabonatermesztés és a hagyományos módszerek domináltak, exportra kevés lehetőség nyílt. Modernizációra legfeljebb a nagybirtokosok költhettek. Az ágazat a nemzeti jövedelem kb. 40%-át adta, a lakosság felének nyújtva megélhetést.\n\nAz 1920-as évek elejére hiperinfláció bontakozott ki. Bethlen először egy önerőre támaszkodó, szigorú költségvetési politikával, majd annak kudarca után, 1921 végétől egy tudatosan irányított inflációs konjunktúra gerjesztésével kívánta a gazdaságot lendületbe hozni, ami végül sikerült is.\n\n• A hosszútávon is stabil gazdasági fejlődéshez azonban egy nagyobb összegű külföldi kölcsönre volt szükség. 1922. Magyarországot felvették a Népszövetségbe, majd benyújtotta kérvényét egy népszövetségi kölcsönre: 250 millió aranykorona.\n\nA Bethlen-kormány 1924-ben kedvező kölcsönt kapott a Népszövetségtől. Az ekkor felállított Magyar Nemzeti Bank feladata az államadósság kezelése és a pénzkibocsátási fedezet biztosítása volt. 1927-ben stabil pénzt vezettek be, a pengőt.\n\nA javuló gazdasági eredmények szociális reformokat tettek lehetővé:\n\n• 1927-ben kiszélesítették a kötelező betegbiztosítást, 1928-ban létrehozták az Országos Társadalombiztosító Intézetet.\n\n• kötelező öregségi, rokkantsági, özvegységi és árvasági biztosítás bevezetése (1928)\n\n• új lakóházak, kórházak, iskolák építése.\n\nIpar és növekedés a húszas években\n\nA tőke- és energiaigényes nehézipar helyett az élelmiszer- és textiliparra tevődött át a hangsúly: elsősorban lakossági fogyasztásra, később exportra is termeltek. Jelentőssé vált a bauxitbányászat és a timföldgyártás. A villamosenergia-ipar jelentőségét szaporodó távvezetékek és erőművek mutatták, az Egyesült Izzó pedig rádiógyártásba kezdett. A gépipar a traktorgyártásban, az autók, motorok gyártásában könyvelhetett el sikereket, világhírűvé vált a mozdonygyártás. Orion rádió, automata telefonközpont, Kandó-féle villamosmozdony.\n\nHatása a mezőgazdaságra: konzervipar fejlődése, gyümölcstermesztés, gépesítés.\n\nNehézségek: az értékesítés terén; elavultak a termelés keretei; alacsony technikai színvonal.\n\nTurizmus fejlődése pl. építkezés Lillafüreden (Palotaszálló).\n\nKülpolitikai konszolidáció\n\n• Bethlen két alapvető célkitűzése: a revízió és a dunai országok gazdasági és defenzív jellegű együttműködésének megteremtése (lengyel-magyar-román blokk, francia támogatással).\n\n• A kisantant kialakulásával azonban a két cél összeegyeztethetetlen volt, Bethlen a revíziót „választotta”. A kisantant országok protekcionista gazdaságpolitikája miatt nem jutunk hozzá a nyersanyagokhoz, amelyek az országhatáron kívülre kerültek.\n\nBalsikerű akciók: szövetségkötés terve a Szovjetunióval, frankhamisítási botrány.\n\nKitörés az elszigeteltségből: 1927. olasz-magyar szerződés.\n\nGazdasági válság Magyarországon: 1929-ben az USA-ból indul ki.\n\n• A gazdasági válság félbeszakította a gazdasági rekonstrukció folyamatát.\n\n• Elhúzódó agrár, ipari és hitelválság:\n\n• mezőgazdaság: túltermelés, csökkenő világpiaci árak, beszűkülő exportlehetőségek;\n\n• ipar: beszűkült a belső piac;\n\n• pénzügyi és hitelválság 1931 nyarától: leállt a tőkeimport, befagytak a hitellehetőségek, az ország katasztrofális módon eladósodott.\n\n• Állami beavatkozás:\n\n• 1930-tól a mezőgazdaságban a boletta-rendszer (gabonajegy) bevezetése - az állam a termelőnek gabonajegyet adott, amin vásárolni lehetett.\n\n•A kormány komoly exportpiac-kutatásba kezdett: 1931-ben megállapodás Németországgal.\n\n1931. júl. 13-tól 3 napos bankzárlat, megkezdődött a bankszektor rendbetétele. Bevezették a kötött deviza-gazdálkodást, azaz külkereskedelmi ügyleteket csak a Nemzeti Bankon keresztül lehetett bonyolítani. Bethlen nem tud úrrá lenni a válságon, ezért 1931-ben lemond.\n\n• 1931 decemberétől Magyarország felfüggesztette külföldi hiteleinek törlesztését.\n\n• A jómódúak kevésbé érezték meg a válságot, a szegényebb rétegeknek viszont drámaian romlott az életszínvonaluk:\n\n• parasztság: csökkenő napszámbér, eladósodottság;\n\n• munkásság: csökkenő bérek, munkanélküliség;\n\n• kispolgárság: kereskedők, iparosok tönkrementek. • 1930. szept. 1. a két világháború közötti időszak legnagyobb munkástüntetése Budapesten.\n\n• Megélénkültek, újjászerveződtek a demokratikus politikai pártok:\n\n• MSZDP: nyitott a parasztság irányába; tüntetéseket, sztrájkokat szerveztek;\n\n• 1930-ban megalakult a Független Kisgazdapárt;\n\nVILÁGGAZDASÁG az első világháború után, az 1920-as évek\n\n1. Az európai országok a háború alatt áruhiánnyal küzdöttek, és ez a béke után sem változott, infláció, fedezetlen pénzkibocsátás (aranytartalékok kimerültek, egyszerűen csak nyomtatták a pénzt, letértek az aranyalapról az USA kivételével). Legjelentősebb inflációs térség Közép-Kelet-Európa volt (németországi helyzet), sok országban valutát kellett cserélni, hogy stabilizálják a pénzügyet. Anglia 1925-ben, Franciaország 1928-ban tudott visszatérni az aranyalaphoz (a Dawes-terv segítségével).\n\n2. Hadigazdálkodásról vissza kellett térni polgári gazdaságba, ami munkanélküliséget okozott, az infláció miatt beszűkült a piac (a felvásárló-réteg szűkült).\n\n3. A győztesek a Németországra és csatlósaira kirótt jóvátételi összegektől várta a helyzet javulását, azonban a vesztesek is ugyanazokkal a gondokkal küzdöttek. (franciák a Ruhr-vidéket megszállják, hogy ezzel Németországot fizetésre kényszerítsék 1923-ban, azonban a németek nem tettek semmit, a megszállás túl sok pénzbe került, nem lett eredménye, a franciák visszavonultak.)\n\n4. Háború alatt csökkent az élelmiszertermelés, a gyarmatokkal rendelkező országok a megszállt területekről hozatták az ételt, a kereslet nőtt, de a fizetőképesség - az infláció és a munkanélküliség miatt - alacsony volt, ezért a gazdasági áruk ára is csökkent. Az európai termelés csak az 1920-as évek közepére állt helyre, azonban túltermelésbe kezdtek, ami tovább csökkentette az árakat. A mezőgazdasági exportőrök komoly gondokkal küszködtek a felesleg miatt, kialakult a tömegtermelés, a monopolizáció erőteljes volt, de a kisipar sem tűnt el (helyi szinten maradt meg).\n\n5. Dawes-terv:\n\nAz első világháborúba való belépésével (1917) az USA kilépett izolációs politikájából, s hozzájárul az antant hatalmak győzelméhez. A versailles-i béketárgyalások résztvevője, Wilson elnök 14 pontja a háború békés megoldását kínálja, mint pl. a nemzetek önrendelkezési joga. A háború után támogatja az európai államokat. Az európai gazdaság nehéz helyzetbe kerülése az USA számára is kedvezőtlen volt, nem érkeztek vissza a kölcsönösszegek. 1923-ban jóvátételi konferenciát rendeztek, ahol egy Dawes nevű közgazdász javaslatára kidolgozták a Dawes-tervet, ami annyit jelentett, hogy Amerika befektetőként lép fel a válságos időben, újabb kölcsönnel és tőkével segíti Európát, innentől kezdve az európai gazdaság amerikai tőkén nyugodott. Tehát lényege: a szilárd valuta és a normalizált gazdaság megteremtése jelentős összegű kölcsönök segítségével. A terv alapján 1924-25-ben Németország milliárdos nagyságrendű hitelt kapott az USA-tól. Következménye: megszilárdult a márka, stabilizálódott a gazdaság, politikai konszolidáció. A jóvátételt így fizetni tudta Németország Angliának és Franciaországnak, ezek az államok pedig így vissza tudták fizetni az USA háborús hiteleit.\n\n6. Ipar: hanyatlott a vas-acélipar, bányászat, ugyanakkor a modernebb ágazatok, autógyártás, villamosgép-gyártás, alumíniumkohászat, vegyipar gyorsan fejlődött.\n\n7. Az államok feladata: visszaállítani a hadigazdaságot békebeli termelésre, irányítsa az újjáépítést, a kölcsönök és befektetések révén újra lendületbe hozni a gazdaságot, ezt legtöbbször állami megrendelésekkel érték el. Európában megnövekedtek a vámhatárok, a békeszerződések után létrehozott országok, új gazdasági egységek miatt nem 26, hanem most már 38 új gazdasági egység lépett be a rendszerbe, s ezért az új kisállamok protekcionista politikát folytattak, bezárkóztak és megválogatták kereskedőpartnereiket.\n\n8. Politikai irányzatok változása: Az első világháború után kialakult válságos helyzetben előtérbe kerültek a szélsőjobb-baloldali pártok, és a nemzetek különleges mivoltát hirdették. Ezek a pártok a fennálló politikai rendeket (alkotmányos alapokat) akarták eltörölni, és diktatúra bevezetését tűzték ki célul. A szélsőséges pártok a politika eszközeivel (nemzeti-szociális demagógia, népvezér-kultusz) tömegpártokká nőttek, esetenként párthadsereggel rendelkeztek (Hitler: SA, SS). A háború után Oroszországban bolsevik diktatúra létesült, Olaszországban a fasiszta Mussolini került hatalomra. Térnyerésüket azonban csak a gazdasági nehézségeknek, a nép, a tömegek életkörülményeinek, biztonságának romlásának köszönhették (békés körülmények között az ember nem gyűlölködik ennyire). A húszas években a stabilizálódó gazdaság azonban javította az életkörülményeket, emellett a nők választójoghoz jutása is segítette a szélsőséges pártok visszaszorítását (pl. Nagy Britanniában).\n\nA világgazdasági válság\n\nUSA:\n\n1929-ben az USA-ban robban ki a világgazdasági válság, mely az egész világ gazdaságának működését meghatározza. A New York-i tőzsdekrach oka a túltermelési válság volt, ennek következtében leállt a termelés, bezártak az üzemek, gyárak, sok ember lett munkanélküli, amely még inkább mélyítette a válságot, mely 1933-ig tartott. Mindez tovább gyűrűződött egész Európára.\n\nAlapfogalmai: világgazdaság: egyes nemzetgazdaságok közti kapcsolatok összessége. A válság: a gazdaság és társadalom valamely területén fellépő egyensúly hiány (a válság általános szakaszai: válság, pangás, felélénkülés, fellendülés.\n\nOkai: a kapitalizmus alapvető ellentmondásai, a termelés – fogyasztás közti aránytalanság és a pénzügyi spekulációk. Az 1920-as évek második felében a gazdasági konjunktúrának köszönhetően az USA sokmilliárdos kölcsönöket folyósított, gazdasági befolyást gyakorolt Európára, melyet fogyasztópiacának tekintett. A termelés üteme az európai gazdaságok beindulása után nem csökkent az USA-ban, így az meghaladta a fogyasztás ütemét, s így túltermelés alakult ki. Eladhatatlan árukészletek halmozódtak fel. Az USA gazdasági változásai világméretű következményekkel jártak.\n\nA tőzsdekrach: a New York-i tőzsdén 1929. október 24-én (fekete csütörtök) a részvények 40-60%-os árzuhanása következett be.\n\nA válság kibontakozása:\n\nFizetésképtelenné váltak a bankok. A tőkét pedig kivonták a beruházásokból. Mindenki ki akarta venni a pénzét, a hitelrendszer összeomlott. A részvények árfolyama megingott, majd áruk zuhanni kezdett, mindenki el akarta adni értékpapírjait. A kínálat rohamosan felülmúlta a keresletet\n\nLeállt a fogyasztási cikkeket gyártó ipar és a nyersanyag-kitermelés egy része.\n\nCsökkent az USA-ban az építkezések száma és a tartós fogyasztási cikkek eladása\n\nAz ipari válság összekapcsolódott a mezőgazdasággal, amely szintén értékesítési gondokkal küzdött: az árukészletek felhalmozódtak, eladhatatlanná váltak, áraik zuhanni kezdtek, összeomlott a pénzügyi és a kereskedelmi világ\n\nA bel- és külkereskedelem működésképtelenné vált\n\nA vállalatok leálltak, a felesleges munkaerőt elküldték, a munkanélküliség nőtt, vásárlóképesség csökkent (pl.: USA 1929-33 között 1,5 millió -12,8 millió)\n\nA válság az USA-ból átterjedt Európára\n\nMegszűnt a tőkeexport az USA-ból, az amerikai bankok felmondták, az európai hiteleket. Különösen súlyossá vált az osztrák és német pénzügyi helyzet. A világon mintegy 30 millióan maradtak munka nélkül, 1929-35 között a világkereskedelem 65%-kal esett vissza.\n\n- Társadalmi következmények: a kis- és középüzemek tönkrementek, további tőkekoncentráció történt. Munkanélküliség, létbizonytalanság tovább súlyosbította a válságot általános elégedetlenség alakult ki.\n\nPolitikai hatások: szélsőséges politikai irányzatok felerősödése pl. szélsőjobb: fasizmus; szélsőbal: kommunizmus. Megváltozott az állam gazdasági szerepe. Európában munkanélküliség, infláció, hitelekkel, megrendelésekkel stabilizálják a gazdaságokat egyenként, levezetődik a felesleg, de nemzetgazdaságok alakulnak ki a fasiszta eszmék miatt.\n\nA kibontakozás útja az USA-ban – A New Deal, 1933\n\n1929-től 1932-re 73%-kal esett vissza fogyasztási cikkek termelése. A válság mélypontján, 1932 végén Franklin Delano Roosevelt lett az USA elnöke, aki demokrata párti politikus volt. A kongresszus elfogadta a New Dealt (Új irányvonal), melyet egy agytröszt dolgozott ki (egy gazdasági szakemberekből álló csapat) Lényege: az állam közvetlen beavatkozása a gazdaságba. Keynes angol közgazdász elméletét alkalmazták.\n\nKeynes (angol közgazdász) növekedés elmélete szerint:\n\nAz állam gazdaságirányító és koordináló szerepét növelnie kell. Az államnak meg kell teremtenie a konjunktúrához szükséges keresletet. Olyan munkaalkalmakat kell teremteni, ami 1. megélhetést nyújt a dolgozóknak, 2. bővíti a keresletet, 3. de nem növeli túlzottan az árukínálatot. Infrastrukturális beruházásokra van szükség, szociális intézményekre. Az állam közvetlenül részt vesz a termelésben részvények felvásárlásával. Egyes vállalatok, illetve iparágak támogatásával közvetlenül is részt vesz a termelésben és a forgalomban. Az állam befolyásolja a pénz- és hitelforgalmat, a külkereskedelmet, ellenőrzi az árak és bérek alakulását, állami tervek kidolgozásába kezd, beleszól a gazdasági folyamatokba.\n\nA New Deal lényege ez alapján a következő:\n\núj banktörvények: az elnök közvetlenül beavatkozik a pénzügyi- és a bankpolitikába,\n\nértékpapír kibocsátás, a dollár leértékelése\n\nipari vállalkozások szabályozása: iparügyi kormánybizottság, fejlesztési törvény\n\nközmunkák szervezése a munkanélküliség felszámolására, a Közmunkaügyi Hivatal irányításával: utak, lakótelepek, iskolák, kórházak építése\n\nszociális intézkedések: társadalombiztosítás rendszere; bérek alsó határának megszabása; gyerekmunka betiltása; a munkahelyi egészségvédelem állami feladat lett; kollektív szerződések\n\nmezőgazdasági termelés és fogyasztás egyensúlyának megteremtése; farmerek támogatása; állami felvásárlás; rögzített árak\n\nkülpolitikában nyitás a szovjetek felé: 1933: diplomáciai kapcsolat a Szovjetunióval\n\nellenzői: konzervatívok, nagyvállalkozók => a New Deal lelassul\n\ntámogatói: a munkásság, fekete bőrűek, etnikai csoportok, liberális értelmiség.\n\nÖsszefoglalása: a válságból Roosevelt elnök idején sikerült kilábalni. A New Deal lényege tehát, hogy állami beavatkozás révén oldották meg a válságot: pl. ipartörvényt hoztak, bezárták a bankokat, s csak az életképesek maradtak fenn, a gazdáknak kárpótlást fizettek azért, ha nem vetették be gabonával a földjeiket, vagy levágták az állatállományt. Közmunkaprogramokat indítottak el, melyek során az infrastruktúra fejlődése érdekében dolgoztak, pl. utak, hidak építése. A New Deal bevált, s kilendítette az USA-t a válságból.\n\nMagyarország helyzete az 1930-as évek elején a világválság hatására\n\nA gazdasági válság világméretű, Magyarországot 1929/30-ban érte el, és abból 1933 után kezdett az ország kilábalni.\n\nAz élelmiszeripar, valamint a fémfeldolgozás és gépgyártás termelése zuhant, kivételt a 20-as években megjelent új ágazatok, a textilipar, vegyipar, villamosenergia-termelés jelentenek. A mezőgazdaság válságát az agrárolló kinyílása jelzi, ez az export kiesésének következménye. Magyarország Trianon után exportra utalt országgá vált, főleg agrárpiacokat igényelt. A főbb partnerek Ausztria, Csehország, Németország, majd 1927-től Olaszország voltak. Magyarország a trianoni békekötés következtében tehát erősen a külkereskedelemre volt utalva, és komoly adósságokkal rendelkezett. Ezek a tényezők könnyítették meg a válság hazai kitörését. Magyarországon is hitel-, ipari és mezőgazdasági válság volt egyszerre, melyek egymást erősítették. 1931 nyarán Magyarországot is elérte a nemzetközi hitelrendszer összeomlása, 1931. július 13-án a kormány háromnapos bankzárlatot hirdetett. A válság megnövelte a munkanélküliséget, eladósodást, és a vagyonvesztést okozott, és ez jelentős szociális és politikai feszültségekhez vezetett.\n\nA mezőgazdaság helyzete\n\nA világpiaci folyamatok hatására lecsökkent a mezőgazdasági termékek ára. Eközben a mezőgazdasági gépek ára megnőtt: szélesre nyílt az agrárolló. Az exportlehetőségek beszűkültek, a hazai értékesítést korlátok közé szorította a piac alacsony befogadóképessége. A kisbirtokos parasztságból egyre kevesebben tudtak napszámosként elhelyezkedni. A középrétegek körében is tömeges elbocsátásokra került sor. Az eladósodás miatt sokan elvesztették földjüket, ezért a kormány birtokvédelmi intézkedéseket hozott.\n\nAz ipar válsága\n\nA válság legjobban a termelőeszközöket előállító gépipart sújtotta. Az élelmiszeripar is megsínylette a csökkenő fogyasztást, a könnyűipar viszont a jelentős állami beavatkozásnak (a vámvédelemnek) köszönhetően még csekély növekedést is elért. Az ipari szektorban nagyjából 250 ezren maradtak munka nélkül, a munkanélküli-segély azonban kevés volt, ezért elkeseredett megmozdulásokra került sor.\n\nGazdasági válság Magyarországon:\n\n• A gazdasági válság félbeszakította a gazdasági rekonstrukció folyamatát.\n\n• Elhúzódó agrár, ipari és hitelválság:\n\n• mezőgazdaság: túltermelés, csökkenő világpiaci árak, beszűkülő exportlehetőségek;\n\n• ipar: beszűkült a belső piac;\n\n• pénzügyi és hitelválság 1931 nyarától: leállt a tőkeimport, befagytak a hitellehetőségek, az ország katasztrofális módon eladósodott.\n\n• Állami beavatkozás:\n\n• 1930-tól a mezőgazdaságban a boletta-rendszer (gabonajegy) bevezetése - az állam a termelőnek gabonajegyet adott, amin vásárolni lehetett.\n\n•A kormány komoly exportpiac-kutatásba kezdett: 1931-ben megállapodás Németországgal.\n\n1931. júl. 13-tól 3 napos bankzárlat, megkezdődött a bankszektor rendbetétele. Bevezették a kötött devizagazdálkodást, azaz külkereskedelmi ügyleteket csak a Nemzeti Bankon keresztül lehetett bonyolítani.\n\n• 1931 decemberétől Magyarország felfüggesztette külföldi hiteleinek törlesztését.\n\n• A jómódúak kevésbé érezték meg a válságot, a szegényebb rétegeknek viszont drámaian romlott az életszínvonaluk:\n\n• parasztság: csökkenő napszámbér, eladósodottság;\n\n• munkásság: csökkenő bérek, munkanélküliség;\n\n• kispolgárság: kereskedők, iparosok tönkrementek. • 1930. szept. 1. a két világháború közötti időszak legnagyobb munkástüntetése Budapesten.\n\n• Megélénkültek, újjászerveződtek a demokratikus politikai pártok:\n\n• MSZDP: nyitott a parasztság irányába; tüntetéseket, sztrájkokat szerveztek;\n\n• 1930-ban megalakult a Független Kisgazdapárt;\n\n• 1930-ban megalakult a Nemzeti Radikális Párt (Bajcsy-Zsilinszky Endre).\n\n• Megerősödtek a szélsőséges mozgalmak: a KMP aktivizálódott;\n\n• 1931-től több kisebb fasiszta párt alakult.\n\n• A Bethlen-kormány az 1931. júniusi választások megnyerése után egyfajta gazdasági kényszerdiktatúrával próbálkozott, de belebukott - Bethlen lemondott 1931-ben.\n\nKárolyi Gyula alakított kormányt (1931. aug. 24 - 1932. szept. 21.):\n\n• Sikereket csak a kommunisták elleni fellépésben tudott elérni.\n\nBethlen miniszterelnök utóda, Károlyi Gyula (1931-1932) intézkedései (közalkalmazotti fizetések csökkentése, adóemelés, a szervezett munkásságnak munkanélküli-segély folyósítása) azonban hatástalanok maradtak.\n\nA válság megoldását végül 3 tényező segítette elő:\n\n- állami beavatkozás olyan ágazatok védelmében, ahol dinamikus növekedés volt várható (villamosenergia-termelés, szénhidrogénipar);\n\n- a világpiaci árak lassú emelkedése;\n\n- a németországi változások extenzív hatásai: a német gazdaság nemzetiszocialista fejlesztése rengeteg nyersanyagot és agrárterméket igényelt. A gazdaság állapota nem sokat javult, ezért lemondott.\n\nGömbös Gyula és a gazdasági válság megoldása\n\nHorthy Gömbös Gyulát bízta meg a kormányalakítással: a Gömbös-kormány (1932-1936)\n\n• Újdonságként hatott az addigi miniszterelnökök sorában:\n\n- katona volt, és nem arisztokrata;\n\n- nézetei szerint nem sorolható a konzervatív táborba;\n\n- példaképe: Mussolini (ezért csúfolták „signor Gömbölini”-nek);\n\n- konkrét kormányprogrammal állt elő - 95 pontos Nemzeti Munkaterv, ebben mindenkinek ígért valamit („Gömbös álmoskönyve”).\n\nA program alapján Gömbös társadalmi célja: a szociális bajok megszüntetése, ezek a problémák összefüggtek a gazdasági válsággal, és a Trianon utáni társadalmi problémákkal pl. nemzeti felemelkedés és revízió ígérete. Gömbös a gazdaság fellendítését és a szociális biztonság megteremtését ígérte, és ezért növekedett meg társadalmi népszerűsége az 1930-as évek elején. Gömbös hosszabb távon egy olasz mintájú (korporatív) államot akart kiépíteni, ehhez azonban nem voltak meg a megfelelő politikai és társadalmi feltételek.\n\nA gazdasági válság felszámolása:\n\n• egyes iparágak támogatást kaptak, csökkentették a mezőgazdasági termények szállítási díját, fenntartották a kötött devizagazdálkodást;\n\n• 1933-ban, majd 1934-ben magyar-német kereskedelmi pótegyezményeket kötöttek, illetve az 1934-ben aláírt római jegyzőkönyvek is újabb exportpiaci lehetőséghez juttatták a magyar agráriumot.\n\n• Szociális reformok:\n\n• 48 órás munkahét, rögzített minimálbér, parasztság terheinek csökkentése.\n\n• Politikai reformtervek:\n\n• A kormánypárt nevét Nemzeti Egység Pártjára (NEP) változtatta, és megpróbálta egy modern tömegpárttá szervezni.\n\n• Választójogi reformot, a parlamentarizmus korlátozását és a munka világának korporációs átalakítását tervezte.\n\n• Gömbös nagyszabású tervei nem valósultak meg, mert: széleskörű politikai összefogás született ellene („alkotmányvédők”);\n\nnem tudta kialakítani a tömegpártot;\n\nnem tudta megnyerni a szellemi elit támogatását;\n\nnem szakított a politikai tradíciókkal, nem vált igazi néptribunná (mint Mussolini vagy Hitler). Gömbös elveszítette Horthy bizalmát is, de nem mondatták le, mert beteg volt, majd 1936-ban meg is halt.\n\nA Gömbös-korszak következménye: a válság megoldása: a gazdaság újjászervezése.\n\nGömbös kereskedelmi szerződéseket kötött Ausztriával, Olaszországgal, Németországgal. Magyarország első számú gazdasági, majd később politikai partnere Németország lett; továbbá a közigazgatásban és a hadseregben sok, a németekkel rokonszenvező ember került pozícióba. A belgazdaság szintjén támogatta a parasztságot adósságainak visszafizetésében, a korporációs rendszer bevezetése azonban a munkásság és a gyárosok ellenállásán elbukott.\n\nA Rákosi-korszak gazdaságpolitikája\n\n1949-1953, 1955-1956\n\n1. A kommunista diktatúra kiépülése Magyarországon\n\n1945-ben Magyarország vesztes országként került ki a második világháborúból is. A Szovjetunió érdekszférájába került Magyarország, így a keleti tömb része lett Csehszlovákiával, Lengyelországgal, Németország keleti részével (NDK), Jugoszláviával, Romániával, Bulgáriával és Albániával együtt. A német megszállás alól a szovjetek szabadították fel az országot, de egyben katonailag meg is szállták. Szovjetunió és Sztálin tudatosan kommunista gazdasági rendszer létrehozására törekedett, a keleti tömbben a szovjet gazdasági és politikai mintát kellett követni. Magyarország szovjet befolyás alatt állt. A vezetők a szocializmus építését tűzték ki célul. A Rákosi-korszakban (1949-1956) egypárti kommunista diktatúra, azaz pártállami rendszer épült ki. A Magyar Dolgozók Pártjának vezetői irányították az országot.\n\n2. A Rákosi-korszak gazdaságpolitikája\n\nA Rákosi-korszak gazdasága\n\nA kékcédulás választások (1947) a kommunisták győzelmét hozták, ezzel elkezdődött a gazdaság szovjet mintájú átalakítása. 1947 és 1949 között államosították a bankokat, ipari, kereskedelmi vállalkozásokat, gyárakat, üzemeket. 1948-ban megindult a parasztság szövetkezetekbe kényszerítése, kuláküldözések zajlottak. Az első ötéves terv (1950-1954) tervszámai irreálisak voltak, túlnyomóan a nehézipart fejlesztették elavult szovjet technológiával. A beruházásokat nem volt miből fedezni, a Marshall-segély a keleti blokkban nem volt igénybe vehető). Csak a mezőgazdaság kárára (beszolgáltatási kényszerrel, padlássöprésekkel), a bérek alacsonyan tartásával és kötelező békekölcsön-jegyzésből tudták finanszírozni őket. A túlzott (közel 100 %-os növekedést produkáló) iparosítás és az ésszerűtlen mezőgazdasági kezdeményezések (pl. gumipitypang- és gyapottermesztés) miatt - miközben új városok nőttek ki a földből (pl. Sztálinváros) - ellátási problémák jelentkeztek. Újra bevezették a jegyrendszert, az életszínvonal 20%-kal csökkent.\n\nIPAR: ÁLLAMOSÍTÁSOK, TERVGAZDÁLKODÁS, A NEHÉZIPAR FEJLESZTÉSE\n\nAz első 3 éves tervet 2,5 év alatt sikerült teljesíteni: ez a 2. világháború utáni újjáépítési program volt. 1950-ben indult az ötéves terv, mely az erőltetett iparosítás meghirdetését jelentette. Felsőbb rendelkezésre tervutasításos rendszer jön létre. Cél: Magyarország a vas és acél országa legyen, ezért nagy ipari beruházások kezdődnek. A nehézipart 100%-osan államosítják. Az államosítás menete: 1946-ban a szénbányákat, a legnagyobb nehézipari üzemeket, 1947-ben a nagybankokat, nagyvállalatokat, 1948-ban a középüzemeket, 1949-ben a kisüzemeket államosítják. Megszűnik a tőzsde, a magántulajdon. Az ipar tehát szocialista jellegű átalakításon megy végbe. Létrejön az állami tulajdon túlsúlya. Az üzemek élére nem szakmailag, hanem politikailag megbízható embereket állítottak. Nem a minőségre, hanem a mennyiségre törekedtek a termelés során. Az ország gazdasági sajátosságait nem veszik figyelembe, a nehézipart egyoldalúan fejlesztik szovjet mintára, katonai célokból.\n\nA hidegháború légkörében a hadsereg megerősítésére volt szükség, ezért kellett a nehézipart fejleszteni.\n\nA néphadsereg, a BM és az ÁVH ellátására 21 hadiüzem épült. 1953-ban a néphadsereg többet költött fizetésre, mint az állam 5 év alatt az oktatás fejlesztésére. A túlzott iparosítás következtében csökkent az életszínvonal, s a szolgáltatások színvonala. A fogyasztási cikkek, a könnyűipari termékek mennyisége, minősége elmaradt a lakossági igényektől. Munkaversenyeket hirdettek meg, hogy túlteljesítsék a tervet („a határ a csillagos ég”), a béreket azonban visszafogták. Folyamatosan növekedett a munkáslétszám. A nők tömeges munkába állása felgyorsult. Tőkét vontak el a mezőgazdaságból is a szélesre nyitott agrárolló segítségével, valamint a támogatás csökkentésével.\n\nA keleti tömb országaiban, 1949-ben megalakult KGST, a Kölcsönös Gazdasági Segítség Tanácsa. Ez a szocialista országok kereskedelmét hangolta össze, de főleg a Szovjetunió kiszolgálói lettek. 1947-ben szovjet nyomásra elutasították a nyugati tömbből érkező amerikai segélyt, a Marshall-segélyt, ez gazdasági téren is integrálódást jelentett Magyarország számára.\n\nMEZŐGAZDASÁG: KOLLEKTIVIZÁLÁS, KULÁKÜLDÖZÉS, VISSZAFEJLŐDÉS\n\nSzovjet mintára megindul a kollektivizálás, azaz a földek közös tulajdonba kerülnek. Erőszakos szövetkezetesítési program indul, a földek állami tulajdonba kerülnek. Kötelező beszolgáltatási rendszert vezetnek be, s aki nem teljesíti, azt szabotálónak tartják, s börtönbe, munkatáborba kerülhet. A gazdag parasztokat, azaz a kulákokat üldözik, megbélyegzik, arra kényszerítik őket, hogy földjeiket állami tulajdonba adják. Adózással, zaklatással, perekkel felszámolták az árutermelő középparasztságot. Az ÁVH a falvakban is éreztette mindenhatóságát. A bíróság szigorú, gyakran halálbüntetést hozott a „kulákbűncselekmények” megtorlására. Az évszázados paraszti életforma szétverése eredménnyel járt. Falusi tömegek menekültek az iparba. A szövetkezetekben a termelés jóval elmaradt a korábbi szinttől. 195l-ben ezért be kellett vezetni a jegyrendszert. Nem a magyar adottságokhoz igazították a gazdaságot.\n\n3. A Rákosi-rendszer belpolitikája\n\nA Szövetséges Ellenőrző Bizottság és a szovjet katonaság jelenléte (1991-ig) biztosította a kommunista párt hatalomra kerülését, és a sztálini rendszer kiépítését. 1945-47 között még működtek a demokrácia intézményei, koalíciós kormányzás jöhetett létre a Független Kisgazdapárt vezetésével, de a kommunista párt fokozatosan kiszorította a pártokat (szalámi taktika). A kommunisták a Baloldali Blokk megszervezésével (1946) elhatárolódtak a kisgazdáktól, majd 1947-ben sorozatos támadásaikkal elérték a párt lassú felbomlását.\n\n1947 a fordulat éve, egyre inkább érezhető a hidegháború hatása, a Szovjetunió vezetésével keleti és az USA vezetésével nyugati tömbre szakad a világ: ez az integrálódás.\n\nA magyar kommunisták számára kedvező lett a nemzetközi helyzet arra, hogy kíméletlenül, ügyes taktikával építsék ki a párt- és rendőrállamot. Először a „háborús bűnösök” ellen, majd a koalíción kívüli „reakció\" ellen, majd a koalíciós partnereik ellen fordultak. A Szövetséges Ellenőrző Bizottság (SZEB), majd az ÁVH támogatása célhoz segítette őket. Az osztályharc éleződésének elméletével, ellenfeleik megsemmisítése után a saját pártjuk soraiban keresték az „ellenséget\". Az éberség lett a legfőbb kommunista erény. Az 1947-es kékcédulás választásokat ugyan megnyerték a kommunisták, de csak 22%-ot szereztek, a koalíciós pártokkal együtt azonban 60 %-os többséget szereztek. A választások során visszaélések is történtek, ugyanis nem állandó lakhelyen is lehetett szavazni, kék cédulával. A kommunisták teherautóval járták a településeket, hogy kék cédulával szavazzanak. Az ellenzéki mandátumok egy részét pedig érvénytelenítették. Ezzel világossá vált, hogy a kommunisták a továbbiakban már nem kívánják betartani a törvényességi formákat. A támadások miatt az ellenzéki pártok többsége 1948-ra ellehetetlenült, s feloszlatta önmagát. Rákosi Mátyás a fordulatot a két baloldali párt (a kommunista és a szociáldemokrata párt) egyesülésével, a Magyar Dolgozók Pártjának létrejöttével (1948. június 12.), és a megmaradt szervezetek Népfrontba tömörítésével fejezte be (1949). Ezzel gyakorlatilag kialakult az egypártrendszer. Ilyen előzmények után az 1949-es választás már pusztán formalitássá vált, s szerepe pusztán a kommunista diktatúra legalizálása volt az 1949-es alkotmánnyal együtt, mely a szovjet alkotmány másolata. Az alkotmány szerint a munkásosztály vezette az államot. Az államforma Népköztársaság lett.\n\nA Rákosi-rendszer lényege:\n\nA Rákosi-féle Magyarország a szovjet csatlós országok egyike volt. Szovjetunió és Sztálin tudatosan támogatta a kommunista hatalmi elitet. Elzárták a nyugati kapcsolatok lehetőségét. Magyarország politikai, katonai megszállás, azaz szovjet befolyás alatt állt.\n\nA vezetők hatalmukat a dolgozó néptől eredeztették, fő célul a szocializmus építését tűzték ki.\n\nA Rákosi-korszakban egypárti diktatúra, azaz pártállami rendszer épült ki. A Magyar Dolgozók Pártjának vezetői irányították az országot. Ténylegesen a pártfőtitkár kezében volt a hatalom. Az állampárton kívül más párt nem működött, és nem működhettek a párttól független társadalmi szervezetek sem.\n\nAz államfői hatalmat az Elnöki Tanács gyakorolta, a kormányt minisztertanácsnak nevezték. Az Elnöki Tanács tagjait az országgyűlés választotta, a minisztertanács és tagjai rendeleteket adhattak ki, megszűnt a köztársasági elnöki tisztség. Az Elnöki Tanács átvette az országgyűlés jogkörét, és törvényerejű rendeleteket alkotott. A törvényhozó hatalom szerepe így formálissá vált. A rendeleti kormányzás a diktatúra jellemzője.\n\nNövelték az államigazgatásban és a gazdasági irányításban a párthoz hű alkalmazottak létszámát, a pártapparátus irányította a közigazgatást.\n\nLétrejött a tanácsrendszer: a tanácsok a településeket és a megyéket irányították. A tanácsok a helyi érdekek érvényesítése helyett pártutasításokat hajtottak végre.\n\nLétrejött a Legfelsőbb Bíróság, de nem érvényesült a bírói függetlenség elv.\n\nLétrejött a személyi kultusz: szobrok készültek Rákosiról, akinek 60. születésnapját országszerte ünneplés kísérte.\n\nA megfélemlítés fő végrehajtó szerve az ÁVH volt. Törvényes eljárás nélkül elvittek vagy eltávolítottak tisztségükből embereket, az áldozatokat megkínozták. A megfélemlítést a párt funkcionáriusaival szemben is alkalmazták. Az egyes emberek teljesen kiszolgáltatottak voltak a hatalommal szemben.\n\nA rendszerre jellemző volt a terror. Nem érvényesültek az alapvető emberi jogok.\n\nA megfélemlítés eszközei pl. internálások; kényszermunka; koncepciós perek, mint pl. Rajk-per; recski munkatábor. Koholt vádak, hamis bizonyítékok alapján politikai okokból ítéltek el embereket. Sokak számára kényszerlakhelyet jelöltek ki, sokakat a Horthy-rendszerben betöltött tisztségük miatt telepítettek ki, mert le akartak számolni az „osztályellenségekkel”.\n\nA koncepciós perekben iktatták ki a politikai ellenfeleket.\n\nSztálin (december 18.), majd Rákosi (március 9.) születésnapjának ünneplését országossá alakították: személyi kultusz.\n\nA hamis sajtó, rádió csak részben tudta elhitetni a lakossággal a hatalmas fejlődést, miközben az életszínvonal folyamatosan esett. . A vezetés az MDP, a Párt kezében volt.\n\nA vezetés a 4-es fogat kezében van: Rákosi Mátyás, Gerő Ernő, Révai József, Farkas Mihály.\n\n1949-ben megalakult a Népfront, melynek pártjai közös listán indultak a választásokon: „egyindulós lóverseny”. Ellenzéki pártja nem volt. Elkezdődött a szocializmus építésének programja. 1949. augusztus 20-án az államforma a népköztársaság lett. Szovjet típusú alkotmányt és címert vezettek be. Az állam élén az Elnöki Tanács állott, és annak elnöke törvényerejű rendeleteivel még a látszatparlamentet is kiiktatta. 1950-ben összevonással 19 megyét szerveztek. Kiépült a tanácsrendszer, hihetetlenül felduzzadt a hivatalnoki és alkalmazotti létszám. A tanácsok nem önkormányzati, hanem a központi akaratot végrehajtó szervek voltak. 1952-ben Rákosi magához ragadta a párt és az állam tényleges vezetését, kormányfő lett. Hatvanadik születésnapjának megünneplése a személyi kultuszról tanúskodik.\n\nLeszámoltak az egyházakkal, mint ideológiai ellenséggel, letartóztatták Mindszenthy József bíborost, aki tiltakozott az iskolák 1948-as államosítása ellen.\n\nA párt módszere az erőszak, a megfélemlítés. Eszköze: 1946-tól az ÁVO (Államvédelmi Osztály), 1950-től az ÁVH (Államvédelmi Hatóság, vezetője Péter Gábor) A megfélemlítést a koncepciós perek sora biztosította, melynek során koholt vádak alapján állítanak bíróság elé embereket. Az első áldozatok között volt a párt népszerű vezetői közé tartozó Rajk László korábbi belügyminiszter. Rákosi a szovjet-jugoszláv viszony megromlását használta fel ürügyként. A kitelepítés, az internálás a rendszer lényegéhez tartozott, pl. Recsk, Hortobágy. Munkatáborokat hoztak létre, ahol „malenkij robot”-ot kellett végezni, többen a szovjet munkatáborokba is kerültek. A megfélemlítés eszköze volt a börtön, a kínzás, a halálbüntetés. A Rákosi-kormányzat a sztálini modell másolásával, a terrorral ellenállást váltott ki, ami 1956-hoz vezetett.\n\nA Kádár-korszak gazdasága\n\nKádár-korszakon a Magyarországnak az 1956-os forradalom és a rendszerváltás közötti történelmét meghatározó időszakot értjük: 1956-1988. Magyarország ekkor a Szovjetunó érdekszférájába tartozott.\n\nA korszak különböző időszakai meglehetősen különbözőek. A forradalom megtorlását (1956-1963) követően a rendszer konszolidációjára került sor (1963-1968). Az 1968. január l-jén beinduló új gazdasági mechanizmus a szintén 1968-as prágai tavasz következményeként az 1970-es évek közepére kudarcba fulladt, 1978-tól a gazdaságpolitika célja már csak a fizetőképesség és a pénzügyi egyensúly fenntartása volt. A 1980-as években a rendszert mélyülő konfliktusok, gyorsuló reformok jellemezte.\n\nKádár csak két rövid időszakra állt a kormány élére, az Elnöki Tanácsnak pedig csak „egyszerű tagja” volt. Ennek ellenére 1956 vége és 1988 között az MSZMP első titkáraként egyértelműen ő volt az ország vezetője. Ezért nevezzük ezt az időszakot Kádár-korszaknak.\n\nA Kádár-korszakban a politikai rendszer és az uralkodó ideológia a Rákosi-rendszerhez képest abban nem változott, hogy megkérdőjelezhetetlennek számított az egypártrendszer, a parlament szerepe jelentéktelen maradt, cenzúra működött, a külpolitikában pedig meghatározó volt a Szovjetunióhoz fűződő „barátság”.\n\nUgyanakkor sokat változott a hatalmon lévők stílusa, a hatalom gyakorlásának módszere: Kádár ügyelt arra, hogy ne épüljön ki körülötte olyan személyi kultusz, mint Rákosi körül; a párt- és állami vezetők kirívó kiváltságai mérséklődtek; a terror „csak” a hatvanas évek elejéig volt tömeges, a politikai üldöztetés többnyire a rendszer ellenfeleit sújtotta, az alkalmazkodó állampolgárokat azonban nem. A hivatalos kommunista rendszer a munkásosztály hatalmát testesítette meg.\n\nA hétköznapok átpolitizáltsága is csökkent. Az emberektől csupán azt várták el, hogy ne legyenek ellenségesek a rendszerrel szemben. Míg a rákosista korszak politikája az „aki nincs velünk, az ellenünk van” szlogennel fejezhető ki, addig a híressé vált kádári szólam szerint: „aki nincs ellenünk, az velünk van”.\n\nA viszonylag bőséges és folyamatos áruellátás és a viszonylagos szabadság a Kádár-kori Magyarország védjegyévé vált. Magyarország lett „a legvidámabb barakk” a szocialista tömbön belül, ezért is emlegették az itteni rendszert „gulyáskommunizmus”-nak, illetve „fridzsiderszocializmus”-nak.\n\nKádárnak, aki 1956 végén az ország egyik leggyűlöltebb alakja volt, a hatvanas-hetvenes években nőtt a népszerűsége. Az emberek vele azonosították a lassú gyarapodást és a hétköznapi élet viszonylagos nyugalmát. A hatvanas évek során kialakult egyfajta hallgatólagos közmegegyezés: a rendszer eltűri, hogy az emberek saját jólétükkel foglalkozzanak, cserébe elfogadják a fennálló hatalmat, s „elfelejtik” annak eredetét.\n\nSokan állítják, hogy a rendszer a legjobb lehetőségnek számított a fennálló keretek között, s a lehető legtöbbet nyújtotta az embereknek – a szovjet megszállás körülményei között.\n\nAz MSZMP, bár a korszakban pártnak nevezték, valójában nem csupán politikai párt volt, hanem a legfontosabb államhatalmi szerv is. Szervezetei minden szinten összefonódtak az állami szervekkel, ezért is beszélnek a rendszeri kapcsán pártállamról.\n\nMezőgazdaság:\n\nA Rákosi-korszakot időszakonként jellemző élelemhiányt Kádár a hatvanas évekre kiküszöbölte, az élelemellátás stabillá, kiszámíthatóvá vált. A parasztságot - épp az élelemtermelés folytonosságának biztosítása érdekében - csak 1958-tól kényszerítették újra termelőszövetkezetekbe, 1961-re befejeződött a paraszti magángazdaságok felszámolása. 1961 márciusára a parasztság termelőszövetekbe kényszerítése lezárult. Ezzel a parasztság önállósága megszűnt, az utolsó társadalmi csoportot is betagozták a pártállam intézményrendszerébe. A háztáji gazdálkodás engedélyezése azonban nagyban hozzájárult az ellátás zavartalanságához. Az életkörülmények fokozatos javulásával módosultak a táplálkozási szokások is: arányeltolódás figyelhető meg a burgonya és tésztafélék felől a húsfélék, zöldségek és tejtermékek javára. Mindezek hatására beépült a köztudatba a Magyarországra, mint a „legvidámabb barakkra” jellemző gulyáskommunizmus elnevezés.\n\nMunkakörülmények\n\nA szocialista iparosító törekvéseknek köszönhetően a mezőgazdasági szektorban dolgozók átáramlása révén a munkások száma nagymértékben növekedett. A szellemi foglalkozásúak száma is megnőtt, ám a vállalati adminisztrációban dolgozók közel harmada érettségivel sem rendelkezett. A foglalkoztatási politikának köszönhetően mindenkinek volt ugyan állása, de kialakult a „gyárkapukon belüli munkanélküliség”.\n\nA mezőgazdaságra is jellemzővé vált a nagyüzemi termelés, aminek következtében szakosodás indult meg. A tervutasításos rendszer következtében - leginkább az acél-, a vas- és a vegyiparban - erőszakos fejlesztések voltak megfigyelhetők. Az állami szférán túl az 1960-as évek végétől a magánszektor is mind nagyobb jelentőségre tett szert: a maszek, azaz magánszektorbeli dolgozók körében a vendéglátóipari egységek üzemeltetésének bérbevétele, az ún. gebin volt a jellemző vállalkozási forma volt. A fusizás mellett az 1980-as évektől megjelent a gyári túlmunka hivatalos formája, a gazdasági munkaközösség (GMK) is, ami tovább növelte a második gazdaság szerepét. Az 1980-as évektől kezdve a munkásság terhei fokozatosan enyhültek: bevezették a szabad szombatot, majd a 40 órás munkahetet.\n\n„FRIZSIDERSZOCIALIZMUS”\n\nA XX. század utolsó harmadában a mezőgazdasággal foglalkozók aránya jelentősen csökkent. Az ipari munkások aránya 1970-ben volt a legmagasabb. Ezzel szemben a harmadik szektorban (szolgáltatás, kereskedelem, egészségügy, kultúra, oktatás, közig gátas) folyamatosan nőtt a foglalkoztatottak száma.\n\nA korszakban jelentősen csökkent a szegénység. A Kádár-rendszerben emelkedett szinte valamennyi civilizációs mutató: javultak a lakásviszonyok, a tartós fogyasztási cikkekkel való ellátottság; 100%-os lett a társadalombiztosításban részesülők aránya; javult az iskolázottsági szint; általánosan elterjedt a nyaralás szokása, és bővült a külföldi utazások lehetősége.\n\nA hatvanas években általánossá tették a nyugdíjrendszert. De nem számoltak a lakosság elöregedésével - 1952-ben a nyugdíjasok a lakosság 5,8%-át tették ki, 1990-ben 24,3%-át, 1999-ben pedig már 31%-át. Azzal, hogy az első nyugdíjak egy jelentős részét a korábbi, alacsony bérek alapján számították ki, idővel azonban emelkedtek a bérek, és a nyugdíjakat ez alapján kellett kiszámítani. Míg 1952-ben az átlagnyugdíj az átlagbér 23%-át tette ki, addig 1983-ban már 58,6%-át Míg 1960-ban a nemzeti jövedelem, tehát a GDP 2,5%-a ment nyugdíjakra, 1990-ben már 9,7%-a.\n\nAz életszínvonal emelkedésének árát azonban nemcsak az állam fizette meg, hanem az emberek is, akiknél jelentős része önkizsákmányoló munkát végzett az ún. „második gazdaságban”. „Második gazdaság” alatt a háztájiban, a kisiparban és kiskereskedelemben - legtöbbször nem fő-, hanem mellékállásban - végzett munkát értették, de ide számították a csempészetet és a fusizást is, vagyis a magáncélú termelést az állami tulajdonban lévő eszközökön, munkaidőben. A második gazdaság meghatározó jelentőségű volt például a lakásépítések terén. A hetvenes években a magyar családok mintegy háromnegyede szerzett jövedelmei a második gazdaságból.\n\nA növekvő életszínvonal, a javuló társadalmi közérzet egyelőre elfedte, hogy az elvileg mindenkinek járó társadalmi szoláltatásokhoz mégsem egyenlő mértékben lehet hozzájutni: a keményebb érdekérvényesítésre képes pártelit előnyökhöz jutott.\n\nA hiánygazdaság miatt még a javuló ellátás mellett is gyakran csak hosszas várakozás után lehetett hozzájutni a keresett áruféleségekhez, szolgáltatásokhoz, pl. autóhoz.\n\nEgy átlagos magyar család a szocializmus éveiben többéves várakozás, többéves gyűjtögetés után juthatott autóhoz. Sokaknak csak a keletnémet gyártmányú Trabantra tellett. A kommunista korszak végén a magyar utakon futó kb. kétmillió személygépkocsi csaknem ötöde Trabant volt.\n\nIngázók jártak a városokba dolgozni. A városi lakásépítések ugyanis nem tartottak lépést a városi munkahelyek számának gyarapodásával és a falusi munkahelyek számának csökkenésével. Tömegek kényszerültek arra - a hetvenes évek elején közel egymillió dolgozó, hogy lakóhelyük és munkahelyük között naponta „ingázzanak”.\n\nGazdaságpolitikája:\n\nKádár tanult a forradalom előtti hibás gazdaságpolitikából, a szövetkezetek létrehozásában enyhébb módszereket alkalmazott. Bár a tervgazdálkodás 1956 után is fennmaradt. A gazdasági növekedésnek a tervgazdálkodás nem jelenthette szilárd alapját. A mezőgazdaság átszervezésekor például határozottan végrehajtották a téeszesítést, de magántulajdonban hagyták a háztáji földeket, ahol a parasztság önmaga számára és piacra is tudott termelni. Ez a politika annyira sikeresnek bizonyult, hogy a háztájinak hamarosan kulcsszerepe lett az élelmiszerellátásban. Az 1950-es évek végén és az 1960-as évek elején a magyar gazdaságpolitika lényegében még mindig az extenzív iparosítás útját járta, azaz a termelés mennyiségi növelését elsősorban új munkaerő bevonásával oldották meg.\n\nA mezőgazdaság kollektivizálásának következtében továbbra is tömegével áramlott a munkaerő a városokba, illetve az iparba. A gazdaságpolitika irányítói azonban tisztában voltak vele, hogy ez hosszú távon már nem fenntartható. Az ötvenes évek első felére jellemző iparosítási politikához képest annyi változott, hogy a mezőgazdaságban felszabaduló munkaerőre számítva tudatosan, addig iparral nem rendelkező vidékekre telepítették az új üzemeket. A gazdaság mennyiségi növekedése mellett azonban minden igyekezet ellenére sem sikerült leküzdeni az egyes áruféleségből fellépő hiány jelenségét, javítani a termelékenységen, vagy hazai műszaki fejlesztések révén emelni a technológiai színvonalat. Az ipar a modern, külföldön is versenyképes termékek előállításához továbbra is rászorult a Nyugatról vásárolt használati jogokra, technológiai licencekre, alkatrészekre. Mindez a külkereskedelmi mérleg időről időre jelentkező hiányához, illetve hullámzó növekedéshez vezetett.\n\nAz 1960-as évek közepén a nyilvánvaló egyensúlytalanságok arra késztették a vezetést, hogy felülvizsgálják a gazdaság egész működésmódját.\n\nAz új gazdasági mechanizmus: 1968-1973.\n\nAz életszínvonal emelését és szinten tartását mindennél fontosabbnak tartó politikai szándéknak köszönhető az 1968-ban elindított gazdasági reform is, az új gazdasági mechanizmus. Nagyobb önállóságot kaptak az üzemek, piaci viszonyok is érvényesültek. A reformok elindításában szerepet játszott a nagyhatalmi enyhülés időszaka. A gazdasági reform a hatvanas évek közepére szükségessé vált, de a reform kibontakozásának politikai akadályai voltak. A gazdaság problémáinak megoldására Nyers Rezső vezetésével dolgoztak ki reformprogramot, amit hivatalosan 1968. január 1-jén vezettek be.\n\nAz új gazdasági mechanizmus keretében az állami vállalatok nagyobb gazdasági önállóságot kaptak, elvileg nyereségre kellett törekedniük és az üzletvitelüket bevételeiknek megfelelően irányítaniuk. Nem írták elő, mint korábban, hogy mit és mennyit termeljenek. A vállalatok vezetőit és dolgozóit érdekeltté tették a cégek gazdasági sikerében. A vállalatok, kínálhattak magasabb bért a jobb munkaerőnek, ezért felgyorsult a munkaerő-áramlás a vállalatok között. A reform előzményei megtalálhatóak voltak a mezőgazdaságban, mert a termelőszövetkezetek megszervezésekor nagyobb szerepet hagytak a háztáji gazdaságoknak és a téeszen belüli egyéni kezdeményezéseknek. A magyar gazdaság a központi tervezés és a piaci viszonyok ötvözeteként a szomszédos szocialista országoknál hatékonyabban tudott működni.\n\nA téeszek sora indított melléküzemágat olyan termékek előállítására, melyekre a hiánygazdaságban piaci igény volt, ami által nőtt az árukínálat. A mezőgazdasági művelés iparszerűvé válása, valamint az intenzív termelést végző háztáji gazdálkodás következtében a mezőgazdaság látványos fejlődésnek indult. Az új gazdasági mechanizmusnak köszönhetően folytatódni tudott a gazdaság korábbi növekedési üteme. 1968 augusztusában a prágai tavasz eltiprása megmutatta, hogy a reformfolyamatok nem mehetnek olyan messzire, hogy veszélyeztessék az állampárt gazdaság és politika feletti uralmát.\n\nA hazai, magyarországi reformoknak sok ellenzője volt az MSZMP-n belül és a keleti blokk más országaiban, mindenekelőtt a Szovjetunióban. A hazai „munkásellenzék” szerint az ország letért a szocialista fejlődés útjáról. Kádár János ezért pozícióját féltve visszavett a reformokból, majd eltávolította a vezetésből a reform kidolgozóit és irányítóit, aminek következtében termelési nehézségek jelentkeztek.\n\nAz életszínvonal emelkedésében, a politikai stabilitás megteremtésében nagy szerepet játszott a „második gazdaság”, a háztáji, a melléküzemágak és a gmk rendszere. Ez ugyanakkor a lakosság túlhajszoltságához vezetett. Magyarország eladósodásában jelentős szerepet játszott a hibás és pazarló gazdaságpolitika, a tervgazdálkodási rendszer anomáliái, a reformok leállítása. A világgazdasági folyamatok, mint pl. az 1973-as kőolaj-árrobbanás is hozzájárultak a Kádár-rendszer gazdasági-politikai válságához.\n\nA hetvenes évek végétől újra nagyobb teret engedtek a magánkezdeményezéseknek. A magyar gazdaság a reformok ellenére sem volt képes a szabadpiaci gazdaságokkal lépést tartani. Az életszínvonal-alku fenntartása csak külföldi hitelfelvétel révén volt lehetséges. A hatvanas évek végétől gyorsuló ütemben adósságspirálba került az ország.\n\nA rendszer értékelése:\n\nA Kádár-korszakban engedélyezték az önálló kisiparosok, kiskereskedők tevékenységét. Kádár a kispolgársággal szemben a korábbinál engedékenyebb politikát akart folytatni, felismerte a kispolgárság közvélemény-formáló szerepét. Ez a magánszektor korlátozott engedélyezését jelentette, a „kádári alku” egyik eleme volt. Kádár az engedékenység fejében a kommunista rendszer tudomásul vételét várta a kispolgároktól, ezzel a Rákosi-korszak gyakorlatán változtatott.\n\nA reálbérek az 1970-es évek második feléig nőttek, a Kádár-korszak utolsó évtizedében már csökkentek. A reálbérek növekedése az életszínvonal emelkedését jelzi, a fogyasztás bővülését vonta maga után. A reálbérek csökkenése az életszínvonal esésével járt együtt, hátterében az egyre növekvő infláció állt. Ennek következménye volt a „második gazdaság” kialakulása.\n\nA bányászok és a gyári munkások kerestek a legjobban. A legmagasabb és legalacsonyabb átlagkereset között másfélszeres különbség volt. A rendszer ugyanis a munkásosztályt tekintette fő társadalmi bázisának. A munkások viszonylag magas fizetésének ideológiai okai voltak. Ezen túl nem voltak jelentős különbségek ágazatonként az átlagkeresetek között. A rendszer nem tette lehetővé jelentős vagyoni különbségek kialakulását.\n\nAz állam támogatta a művelődési házak építését. A művelődési házak a kulturális élet és a társas élet központjai voltak. A kulturális élet szervezeti kereteit gyakran a párt ifjúsági szervezetei biztosították. Az állam igyekezett mindenki számára biztosítania művelődés lehetőségét, a kultúra az ideológia terjesztésének eszköze volt.\n\nA Rákosi-korszakhoz képest javultak az életkörülmények, a többi szocialista országhoz képest magas volt az átlagos életszínvonal. Az életkörülmények javítása politikai cél volt, ezért szokás „gulyáskommunizmusról” vagy „fridzsiderszocializmusról” beszélni. Igyekeztek megelőzni egy újabb forradalom kirobbanását.\n\nSzociálpolitikai intézkedések pl. GYES, családi pótlék, családtámogatás bevezetése, bölcsődék, óvodák építése, a társadalombiztosítás kiterjesztése. Ezzel a születések számának csökkenését próbálták megállítani, és a nők munkavállalása tette szükségessé. Ez jelentősen növelte az államadósságot.\n\nAz életkörülmények javítását szolgáló további intézkedések: az iskolahálózat bővítése, állami lakásépítések, az élelmiszerárak alacsonyan tartása, a sport támogatása. A sporteredményeket a politikai propaganda is kihasználta. Nőtt az iskolázottság, csökkent a lakáshiány. A lakáshoz jutás ennek ellenére nehézkes volt. A korszakban már nem volt jellemző az éhezés.\n\nA kultúrpolitika fő jellemzője a 3T elvének érvényesülése: tűrni, tiltani, támogatni. A politikai szempontból semleges művek közlését engedélyezték. Nagyobb művészi, tudományos szabadságot biztosítottak a korábbiakhoz képest, de a rendszerrel szembeni nyílt kritika megjelenítését továbbra is tiltották. Aczél György.\n\nA rendszer csúcsán a káderek és a nómenklatúra felett állt a pártvezetők, a hatalmi elit köre. Őket a köznyelv a 4K révén különítette el. K-vonalú telefonnal rendelkeztek – ami az államigazgatás külön hálózata volt –, korlátlanul utazhattak külföldre, a Kútvölgyi Kórházban kezelték őket, életük végén pedig a Kerepesi úti temető úgynevezett munkásmozgalmi panteonjába temették el őket. Aki egyszer bekerült a káderek sorába, rendszerint nem is hullott már ki onnan a nyugdíjazása előtt (a „kádermegmaradás törvénye”). Szemben az 1950-es évekkel, a káderré válásnak már nemcsak a politikai megbízhatóság volt az egyedüli feltétele, hanem az adott területnek megfelelő szakértelem is. A káderek köre fokozatosan mind professzionálisabbá vált, nőtt közöttük a diplomások aránya. A kádereknél szűkebb kör volt a nómenklatúra, melynek tagjai olyan pozíciókat töltöttek be, amelyekhez a megfelelő pártszerv jóváhagyása kellett. Létszámuk országosan háromezer körül volt a hetvenes években.\n\nA ’70-as, ’80-es években nőtt a lakosság életszínvonala, de Magyarország a ’80-as évekre jelentős hitelek felvételére kényszerült és eladósodott. Adósságspirál. A viszonylagos jólétnek ára volt. Mivel a politikai vezetők a rendszer stabilitása miatt növelték az életszínvonalat. A szociális intézkedések bevezetésekor nem számoltak a hosszú távú következményekkel. A költségek növekedése folytatódott a nyolcvanas években is, amikor a gazdaság növekedése már megtorpant, ez vezetett el az 1980-as évek végén a rendszerváltáshoz, a Kádár-rendszer végéhez.\n\nGazdasági rendszerváltás 1989 után\n\nA gazdasági rendszerváltás legfontosabb jellemzői:\n\nA rendszerváltás előtt Magyarország a Szovjetunió érdekszférájába tartozott, a rendszerváltás 1989–1990-ben történt. A kommunista diktatúrát felváltotta a demokrácia.\n\nA politikai változásokat a gazdasági élet gyökeres átalakulása követte.\n\nA kétpólusú világ megszűnése, és egyben a szovjet befolyás megszűnése, a Kádár-rendszer bukása, jelentősen hatottak a gazdasági viszonyok átalakulására. Magyarországon a rendszerváltással megteremtődtek a piacgazdaság feltételei. A tulajdonviszonyok átalakulásában a privatizáció (magánosítás) folyamata meghatározó volt, és ez jelentős társadalmi hatásokkal járt: munkahelyek elvesztése, vagyoni különbségek növekedése. A külkereskedelem súlypontjainak áthelyeződése összefüggött Magyarország nyugati orientációjával. A rendszerváltással bekövetkező átalakulás jelentős gazdasági visszaesést eredményezett. A gazdasági nehézségek egyaránt hatottak a magyar társadalom életkörülményeire és a rendszerváltás utáni kormányok politikai döntéseire is.\n\nA Kádár-rendszer során felvett hitelek miatt az adósságspirál egyre nőtt. Az államadósság felhalmozódása a Kádár-korszakban kezdődött. Az adósságok növekedése ösztönzője volt a rendszerváltásnak. (Adósságspirál.)\n\nAz állami tulajdonú cégeket fokozatosan magánkézbe adták, ez a privatizáció. A korábban veszteséges üzemeket, termelőszövetkezeteket bezhzárták.\n\nEmiatt viszont sok ember vált munkanélkülivé.\n\nA magántulajdon szerepe előtérbe került, a köztulajdon háttérbe szorult. A rendszerváltás alapvető változásokat hozott a tulajdon szerkezetében. A rendszerváltás után a fogyasztói árak jelentősen növekedtek, az árnövekedés leginkább az energia-szektort és a szolgáltatásokat érintette.\n\nFokozatosan kiépül a szociális piacgazdaság a tervutasításos rendszer helyett. Ennek ellentmondásai:\n\nA korábbi gazdasági partnerek (Szovjetunió, KGST) helyét új piacok foglalták el (Németország, Nyugat-Európa). A külkereskedelem irányai jelentősen átalakultak. A külkereskedelem új irányainak kialakítására hatott a régi kereskedelmi intézmények megszűnése is (KGST). Az 1989-es rendszerváltást közvetlenül követő időszakban nyitás történt a nyugati világ felé. A volt szocialista országokkal való kereskedelmi kapcsolatok visszaestek. A külkereskedelmi forgalom növekedett: ez a nyugat felé való nyitás következménye volt, ezzel párhuzamosan a külkereskedelmi mérleg passzívvá vált.\n\nA szociális piacgazdaság nem a rendszerváltás utáni Magyarországon épült ki először, hanem a második világháború utáni Német Szövetségi Köztársaságban (NSZK). (Konrad Adenauer kancellár, Ludwig Erhard miniszter idején). A német kereszténydemokrata programot átvették később a szociáldemokraták is, és ennek kiteljesedéséhez köthető a háború utáni német gazdasági fellendülése. A rendszerváltozás után Magyarország is ezt a modellt követte, a modell megvalósítása Antall József miniszterelnök kormányprogramjában is szerepelt\n\nA mezőgazdasági és ipari termelés aránya visszaesett, de a szolgáltatások aránya növekedett. A hagyományos ágazatok tehát visszaszorultak, így a harmadik szektor lett a legjelentősebb. A változások iránya összhangban áll a világgazdasági folyamatokkal.\n\nAz ipari termelés visszaesése a gyárak és bányák bezárását vonta maga után.\n\nA termelőszövetkezetek visszaszorultak, az egyéni gazdálkodás vált a legjelentősebbé. A változás a privatizáció és a kárpótlás következménye, melynek során az 1945-ös földosztás utáni állapotokat állították részben vissza.\n\nA jövedelmek reálértéke nagymértékben csökkent. A rendszerváltás az ország gazdasági teljesítményének jelentős visszaesésével járt.\n\nA korszak nagyobb részében csökkent a keresetek és a nyugdíjak reálértéke, csak az évtized végén indult növekedésnek a keresetek és nyugdíjak reálértéke. A nyugdíjak azonban többet veszítettek értékükből, mint a keresetek. A változások az inflációval és az életszínvonallal függnek össze.\n\nA rendszerváltás következtében szociális piacgazdaság jött létre, ez a tervgazdálkodást, a szocialista gazdaságot váltotta fel.\n\nBiztosították a vállalkozás szabadságát, a magántulajdon védelmét, teret nyert a piaci verseny, bár az állam korlátozza a versenyt.\n\nA vállalatok jelentős része magántulajdonba került, tehát privatizáció történt. Az állam ugyanis eladta a vállalatok jelentős részét, a vállalatok egy része külföldi tulajdonba került, vagy tönkrement, a privatizációt ugyanis visszaélések kísérték.\n\nGazdasági nehézségek: a magas államadósság és a kiterjedt feketegazdaság. A feketegazdaság miatt az állam adóbevételektől esik el.\n\nJelentősek a regionális különbségek. A legfejlettebb régió Budapest és környéke, a leginkább elmaradott régió az északkeleti országrész volt. A fejletlen régiókban magas a munkanélküliség és alacsony szintű a fogyasztás.\n\nAz 1990-es évek második felében sikerült csak csökkenteni az államadósságot.\n\nA szociális piacgazdaság jellemzése:\n\nkiterjedt szociális ellátások, relatíve magas adóelvonási szint\n\na magyar szociális piacgazdasági modell az angolszász modellhez viszonyítva nagyobb állami szerepvállalást és kiterjedtebb társadalmi szolidaritást jelent\n\nA szociális piacgazdaság fogalma: az állam a gazdaság irányítását a piacnak engedi át, de törekszik az igazságosabb jövedelem- és vagyonelosztásra.\n\nAz állam beavatkozik a piaci folyamatokba\n\nA szociális piacgazdaságban az állam jelentős újraelosztó szerepet tölt be.\n\nA politika valamely lényegi jellemzői: a nyugdíj-rendszer, egészségügyi rendszer, oktatási rendszer, szociális segélyek, családtámogatás, progresszív adóztatás, társadalmi szolidaritás\n\nMagyarország versenyképessége emiatt azonban megkérdőjelezhető, ezért marad el az angol vagy amerikai gazdasághoz képest.\n\nBekapcsolódás a világgazdaságba:\n\n1989/1990-et tekintjük a rendszerváltás évének. A rendszerváltást gazdasági szerkezetváltás is kísérte. A külkereskedelmi forgalom növekedéséből arra lehet következtetni, hogy a piacgazdaságra való átállás alapvetően sikeres volt Magyarországon, bár erős piaci versenyben kellett helytállni. Hazánk külgazdasági kapcsolatrendszerében változások történtek: a KGST országok elsődlegességének megváltozása után új kereskedelmi partnereket kellett keresni, s a 90-es évekre ez a partner az Európai Közösség, illetve az Európai Unió lett.\n\nA kereskedelmi volumen tekintetében a 90-es években növekedés következett be. Mindez a gazdasági kapcsolatok élénkülését jelzi. A gazdasági növekedést a külföldi tőkebehozatal is elősegítette. A külkereskedelem áruszerkezetében változások történtek. Visszaesett az élelmiszeripari termékek jelentősége, meghatározóak maradtak a feldolgozott termékek, és túlsúlyba került a gépek és szállítóeszközök kereskedelme.\n\nA magyar gazdaság export-lehetőségeit érintő körülmény: az európai agrárprotekcionizmus, illetve a magyar termékek jelentős része nem versenyképes. Magyarországnak rendkívül nehéz körülmények közt kellett helytállnia a külgazdasági versenyben.\n\nAz 1989-es rendszerváltás során tehát a magyar piacgazdaság kialakítása volt az egyik legkiemelkedőbb feladat, ennek a magánosítás, vagyis a privatizáció volt az egyik lépcsője.\n\nAz állami ipari üzemek megszűnésével elsősorban külföldi tőkéből valósultak meg az ipari beruházások, a már meglévő iparterületek átalakításával (barnamezős beruházás), új ipari parkok létrehozásával (zöldmezős beruházás). Az ipar területén elsősorban az autóipar és az elektrotechnika vált kimagaslóvá a kilencvenes évek végére. A mezőgazdaságban a TSZ-ek bezárásával nem történt strukturális átalakítás. Az újonnan kialakult magángazdaságok nem voltak elég korszerűek a versenyképesség fenntartásához.\n\nA piacgazdaságba való átmenet azonban nehézségeket okozott, mivel felszínre kerültek olyan problémák, amelyek a rendszerváltásig rejtve maradtak (pl. a rejtett munkanélküliség kérdése, ami az ipari létesítmények bezárásával tömeges munkanélküliséggé alakult. A gazdaság a kilencvenes évek második felére stabilizálódott, de kiszolgáltatott maradt a nemzetközi viszonyoknak). A rendszerváltással párhuzamosan megkezdődött egy új hazai gazdasági elit kialakulása is. A zárt tervgazdálkodásról áttérés a nyitott piacgazdaságra:\n\n• privatizáció: az állami tulajdon magánkézbe adása;\n\n• új, magántulajdonban lévő cégek alapítása;\n\n•a mezőgazdaságban a magángazdaságok újbóli kialakítása.\n\nA szolgáltatási szféra fejlesztése:\n\n• kétszintű bankrendszer kialakítása (MNB és a kereskedelmi bankok); biztosítók; tőzsde.\n\nAz átalakulás nyertesei: új vállalkozói réteg, hatalmi elit.\n\nAz átalakulás vesztesei: munkanélküliek, nagycsaládosok, nyugdíjasok.\n\nAz új, szabad és független köztársaság legfontosabb célkitűzése az euroatlanti integráció: 1999: NATO tagság; 2004: EU tagság.\n\nSzociális piacgazdaság:\n\nA piac olyan kapcsolatrendszer, amelynek révén az eladók és a vevők kapcsolatba lépnek egymással. A piacgazdaság alapja a magántulajdon, hajtóereje az egyének nyereségre való törekvése. A liberális piacgazdaság klasszikus felfogásában az állam szerepe minimális.\n\nA liberális piacgazdaság működése során nagy társadalmi különbségek, egyenlőtlenségek alakulnak ki, ezért az államnak bizonyos mértékű újraelosztó szerepre kell vállalkoznia:\n\n• célja a szegényebb és/vagy hátrányos helyzetű rétegek segítése;\n\n• eszköze a szociálpolitika: progresszív adóztatás (a gazdagok jövedelmének nagyobb hányadát vonják el); szociális kiadások: nyugdíjrendszer; egészségügyi ellátás (és ezen belül a gyógyszerár-támogatás); táppénz; munkanélküli segély; szociális segély; oktatás; lakás (építés és lakhatási támogatás); fogyasztói ártámogatások;\n\n• elve: alanyi jog, illetve a rászorultság elve. Az állam mellett fontos a társadalmi szolidaritás: karitatív szervezetek; jótékonysági rendezvények; adakozás.\n\nGazdasági- társadalmi változások a rendszerváltozás után:\n\nGyors gazdagodás (vadkapitalizmus): a kommunista pártelit átalakult gazdasági elitté; kialakult egy új vállalkozói réteg. A középosztály megerősödött, társadalmi szerepe megnövekedett. Nagyok lettek a társadalmi különbségek, nagymérvű lett a szegénység, okai: szakképzettség hiánya, kedvezőtlen adottságú lakóhely; alacsony nyugdíj, demográfiai szegénység (nagycsaládosok vagy egyedül élők). Az átlagos életszínvonal a rendszerváltozás éveiben csökkent, majd 1997-től lassan ismét emelkedni kezdett. Nincs esélyegyenlőség, jelentős az egyes rétegek lemaradása (pl. cigányság).\n\nMagyarország beilleszkedése az európai és a világgazdaságba a rendszerváltás után:\n\n• A tulajdonviszonyokban a privatizációval uralkodó lett a magántulajdon.\n\n• Kelet-Közép-Európában 1995-ig Magyarországba érkezett a legtöbb külföldi tőke:\n\n• a GDP 55%-át multinacionális cégek állítják elő, és az export jelentős része is tőlük származik. A legnagyobb befektető Németország, utána az Amerikai Egyesült Államok, Franciaország és Ausztria következik.\n\n• Kialakultak a pénz- és tőkepiac intézményei:\n\n• kétszintű bankrendszer (Magyar Nemzeti Bank és a kereskedelmi bankok);\n\n• biztosítási piac (a korábbi két állami tulajdonú biztosító helyett piaci verseny);\n\n• 1990-ben megnyitotta kapuit a Budapesti Értéktőzsde (BÉT), majd a Budapesti Árutőzsde (BÁT). Az Értéktőzsde 1991-ben alakította ki saját részvényindexét, a BUX-ot.\n\n• Vállalati struktúra:\n\n• a szocialista gazdaságra jellemző nagyvállalatok többnyire megszűntek, helyükbe a piaci viszonyokhoz alkalmazkodni jobban tudó közepes és kisvállalatok léptek.\n\n• A GDP ágazati struktúrája (2002): a mezőgazdaság erőteljesen visszaszorult (5%);\n\n• az ipar is csökkenő részesedéssel bír (28%);\n\n• a szolgáltatások már 67%-át adják a GDP-nek.\n\n• Foglalkoztatási szerkezet:\n\n• csökkent az ipari és a mezőgazdasági alkalmazottak aránya, növekedett viszont a szolgáltatásokban foglalkoztatottak aránya;\n\n• a mezőgazdaságban a keresők 6%-a, az iparban 34%-a, míg a szolgáltatásokban (kereskedelem, szociális intézmények, pénzügy, közlekedés stb.) 60%-a dolgozott 2002-ben.\n\n• A külkereskedelem földrajzi iránya:\n\nA szocializmusban a legjelentősebb külkereskedelmi partnerek a KGST-országok, és a Szovjetunió volt. Jelenleg már az Európai Unió és azon belül is Németország a legfontosabb külkereskedelmi partner. Magyarország tagja lett a legjelentősebb nemzetközi gazdasági szervezeteknek (WTO, OECD stb.)\n\n• A külkereskedelem szerkezete:\n\n• az exportban igen jelentős szerepre tett szert a külföldi (multinacionális) cégek uralta gépipar; az importban megnövekedett a fogyasztási cikkek aránya.\n\n• A legnagyobb magyarországi cégek listáján megtalálható az 1990-es években:\n\n• az állami kézben maradt közlekedési vállalatok: pl. MÁV, BKV;\n\n• a tőzsdére bevezetett magyar cégek: pl. MOL, T-Com (MATÁV), OTP Bank;\n\n• a nagy multinacionális cégek leányvállalatai: pl. Suzuki, IBM, Audi, Philips.\n\nA szociális ellátórendszer:\n\nA foglalkoztatást segítő intézkedések, a családtámogatások, a rászorulóknak juttatott szociális segélyek, valamint a társadalombiztosítás, melynek része az egészségbiztosítás és a nyugdíjrendszer.\n\n• A munkájukat elvesztők álláskeresési járadékot kapnak 90 napig. (A korlátozás oka elvileg az, hogy ösztönözze a munkanélküliek álláskeresését.).\n\nA tartósan munkanélküliek részt vehetnek a közfoglalkoztatásban, melynek célja a visszavezetésük a munkaerőpiacra. (A rendszer kritikusai szerint azonban így az érintetteknek kevesebb ideje van álláskeresésre és a továbbképzésre, miközben a közmunka csak ideiglenes megoldás.)\n\n• A családtámogatások elvi alapja az, hogy a gyereknevelés magas egyéni költségeit az állam részben megtéríti, ezzel is elismerve a gyereknevelés társadalmi hasznát (és lassítva a társadalom elöregedését). A gyerek születése után három évig vehető igénybe a fix és alacsony összegű gyes (gyermekgondozási segély), illetve helyette az első két évben a korábbi fizetés arányában megállapított gyed (gyermekgondozási díj). A gyerekek nagykorúságáig jár a családi pótlék. A gyereket nevelő családok adókedvezményben is részesülnek. Kifejezetten a szegények számára nyújt segítséget a foglalkoztatást helyettesítő segély, az egészségkárosodási és a gyermekfelügyeleti támogatás. Az idős korról való gondoskodás elterjedt formája a nyugdíjbiztosítás. Mivel az egyéni élettartam nem tudható előre, az állampolgárok kockázatközösséget alkotnak. Amíg dolgoznak, addig jövedelmük arányában fizetnek be a rendszerbe, majd idős korukban életük végéig járó nyugdíjat, életjáradékot kapnak. Eredetileg Magyarországon is tőkefedezeti rendszer működött: a befizetéseket egyéni számlákon nyilvántartva befektették, és az így gyarapodó vagyonból fizették a nyugdíjba vonuló járadékát. A második világháború pusztításai után a nyugdíjakat az adott évben befizetett járulékokból kezdték el fedezni: ez a felosztó-kirovó rendszer. Jelenleg a Nyugdíjbiztosítási Alap működteti a rendszert. A nyugdíj fedezete a munkavállaló által fizetett nyugdíjjárulék és a munkaadó által fizetett szociális hozzájárulási adó. Probléma: a társadalom elöregedése következtében csökken a járulékfizetők, és növekszik a nyugdíjasok létszáma. Ezért lehetőség van önkéntes nyugdíjpénztári megtakarításra, ami tőkefedezeti alapon működik. A társadalombiztosítás másik nagy alrendszere az egészségbiztosítás. Az állampolgárok itt is kockázatközösséget alkotnak. Jövedelmük arányában egészségügyi járulékot fizetnek (a gyerekek, nyugdíjasok, munkanélküliek helyett az állam fizet), és szükség esetén egészségügyi ellátásban részesülnek. A járulékok jelenleg az Egészségbiztosítási Alaphoz kerülnek, és innen fedezik az egészségügyi ellátórendszer (háziorvosok, rendelőintézetek, kórházak) kiadásait és a gyógyszerek ártámogatását, illetve a munkaképtelenség ideje alatt a beteg részére folyósított táppénzt.', 388, 1, '2026-04-17 09:40:02', '2026-04-17 09:40:02');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(5, 5, 'Az Erdélyi Fejedelemség a 16-17. században (etnikai és vallási helyzet, államszervezet)', '5.docx', '5. tétel: Az Erdélyi Fejedelemség a 16-17. században (etnikai és vallási helyzet, államszervezet)\n\nA XVI. századi Erdély két szempontból is sajátos államalakulat volt Európában. Egyrészt egyedül itt szerveződött meg a politikai élet etnikai alapon (szász és székely székek, országgyűlésen a három nemzet), másrészt sehol sem alakult ki olyan vallási sokszínűség, mint éppen itt, éppen akkor, amikor Európában sok helyen véres vallásháborúk és üldözések folytak.\n\nAz 1437-es Budai Nagy Antal-féle parasztfelkelés egységbe kovácsolta az országrész előkelőit. A szorongatott helyzetű nemesek 1437-ben a kolozsmonostori egyezményben biztosítottak jelentős kiváltságokat lázadó jobbágyaiknak, ám mindez a nemesség, azaz a három erdélyi nemzet összefogását is előidézte: a szintén 1437-ben megkötött kápolnai unió a három rendi nemzet (magyar, székely, szász) előkelőinek összetartását deklarálta mind a külső, mind pedig a belső ellenséggel szemben. A kápolnai uniótól a Dózsa György vezette parasztfelkelésen át jutunk el 1526-ig, majd a Mohács utáni, Erdély különállását eredményező kettős királyválasztásig, amelynek következményeit az 1570-es speyeri egyezmény rendezte.\n\nErdély, mint önálló állam 1541-et követően alakult ki, bár államjogi státusa csak a speyeri szerződésben lett tisztázva (1570): Habsburg I. Miksa és Szapolyai János Zsigmond kötött jött létre.\n\nSzapolyai János halála és Buda török elfoglalása (1541) után II. Szulejmán szultán a Tiszától keletre lévő országrészt adta vazallusának, János Zsigmond királynak. Miután a gyermekkirály nevében kormányzó Fráter György számára világossá vált, hogy a kialakult helyzet tartós lesz, megkezdte az új királyság igazgatásának megszervezését. Még 1541 decemberében közös országgyűlést tartott a keleti országrész rendjeinek (ekkor jött létre az erdélyi három nemzet). A kiszélesített erdélyi gyűlés azonban csak 1544-től vált gyakorlattá, bár a szászok elérték, hogy az adót saját gyűlésükön szavazzák meg, és a tiszántúli megyék is tartottak részgyűléseket. A töröktől függ Erdély, egy összegben fizet adót, külpolitikájában a török hagyja jóvá a háború indítását.\n\n- János Zsigmond apja jogán királynak címezte magát, amit a szultáni athname (hitlevél) is megerősített 1566-ban. Az 1570-es speyeri szerződésben azonban lemondott a királyi cím használatáról, s elismerte, hogy Erdély Magyarország politikai része. Habsburg Miksa ugyanakkor elfogadta őt Erdély szuverén uralkodójának, s a két ország pontos határát is megállapították. A fejedelmi címet elsőként Báthory István használta. Báthory Zsigmond pedig az 1594-es szövetségi szerződésben elérte, hogy II. Rudolf Erdélyt önálló államnak ismerje el (két ország elve).\n\nETNIKAI HELYZET:\n\nSzékelyek\n\n- Erdély sajátos helyzete abból adódott, hogy az Árpád-kortól kezdve fontos határvidék volt, s ennek megfelelően különböző etnikumokat telepítettek ide, autonómiát biztosítva számukra saját ügyeikben, így a honfoglalástól kezdve határvédő székelyek megőrizték személyes szabadságukat és személyes hadkötelezettségüket, ami adómentességgel párosult. Rájuk nem terjedt ki a vajda közigazgatása, saját székekre tagolódtak választott vezetőkkel, és saját igazságszolgáltatási fórumuk is volt. KATOLIKUS vallásúak.\n\n• Középkori, nemzetiségi alapon nyugvó társadalmuk (3 rend: főemberek, lovon szolgáló „lófők”, gyalogos „község”) a XVI. század közepére fölbomlott.\n\nA székelyek társadalma még mindig ősi, jellegű volt, s csak a XVI. század végére vált (részben erőszak hatására) valódi feudális létformává. A primorok, lófők és gyalogok hármasára tagolódott társadalom faluközösségekben élt, s adózás helyett általános hadra kötelezhetőségével szolgálta a közösséget. A Szapolyai-adminisztráció az adózó jobbágyok sorába kényszerítette a gyalogokat, míg a primoroknak és lófőknek „feudális típusú” kiváltságként biztosította az adómentességet. A korábbi státus visszaállításáért a székelyek több ízben is fellázadtak.\n\nA székelyek lesüllyesztése éppen a török korban indult meg. A fejedelmeknek szükségük volt az adók növelésére, ezért a székely szabadokat is adóztatni kezdték. Az 1562-es lázadás után pedig további jogfosztó intézkedéseket is hoztak.\n\nAz elszegényedett, katonáskodni már nem akaró/tudó, előkelők szolgálatába álló székelyek jobbágyi sorba kerültek, de régi szabadságjogaikra hivatkozva igyekeztek kibújni az adófizetés alól is (Báthory Zsigmond 1601-ben megerősítette régi szabadságjogaikat).\n\n• Csakhogy így a székely katonaság száma nagyon lecsökkent, ezért Bethlen Gábor 1622-ben elrendelte, hogy az a székely, aki a jobbágyi státuszt választja, köteles adót fizetni - sokan újra katonáskodni kezdtek, vagy elvándoroltak Székelyföldről (így a székelyek kb. 15.000 fős sereget tudtak kiállítani).\n\n• Békeidőben a székelyek közül kerültek ki a fejedelmi testőrség tagjai.\n\nA XVII. századra a korábban szabadságot jelentő katonai kötelezettség inkább teherré vált a számukra, s az adómentesség megtartásával önként lettek jobbággyá. A fejedelmi hatalom számára ez - és nem az adómentesség - jelentette az igazi érvágást, tekintve, hogy a székelyek adták az állandó haderőnek legalább a felét. A katonák lemorzsolódásának folyamatát Bethlen Gábornak sem sikerült megállítania, így rendszeres állami adót vetett ki a székelyekre. Ez azonban nagyarányú elvándorlásukat idézte elő, s a bekövetkezett népességcsökkenést II. Rákóczi György 1658-as balsikerű hadjárata csak tovább fokozta.\n\nSzászok:\n\n- A szászok betelepítése a XIII. század elejétől tudatos királyi politika volt. A szászok II. Andrástól kaptak kiváltságlevelet, mely önkormányzatot adott nekik. Az egységes tömbben letelepedő szászok székei saját gyűléseket tarthattak, saját törvényeket hozhattak. A szász terület irányításában a legnagyobb szász városok (Brassó, Szeben, Beszterce) patrícius családjainak volt döntő szerepe. A szászok külön adóztak, és katonát kellett adniuk az ország védelmére.\n\n• A XVI-XVII. században is megőrizték középkori eredetű kiváltságaikat:\n\n- közösen, egy összegben adóztak;\n\n- maguk választhatták meg elöljáróikat, tisztségviselőiket.\n\nA XVII. században azonban kiterjesztették rájuk is a fejedelmi bíráskodást, városaikban idegenek is vehettek házat.\n\n• Közösségük élén Nagyszeben állt, amelynek polgármestere (szász gróf) irányította a „szász nemzetet”. A szász városok (Brassó, Beszterce, Segesvár) az ország leggazdagabb városai voltak. A városok vezetését gazdag kereskedők, iparosok alkották.\n\n• A szász földművesek nem jobbágyként éltek.\n\nTehát a szászok zárt közösségei leginkább a polgárosodó városok lakosságát jelentették, akik zömmel céhekbe tömörülve végeztek kézműves tevékenységet. Ennek jövedelmezőségét a városfejlődés eredményei (pl. impozáns kőépületek) ma is jól mutatják. Két nagyobb városuk Brassó és Szeben volt (kb. 10 000 lakossal).\n\nTársadalmuk a XVII. században differenciálódott: egyre látványosabban tagolódott kereskedő patríciusokra és a céhek védelme alatt álló iparosok rétegére, akik évente egyszer, egy összegben fizettek adót. Helyzetük csak a század második felére romlott meg, mert csökkent a román vajdaságok felvevő piacának igénye ipari termékeik iránt, másfelől pedig II. Rákóczi György a szuverenitásukat korlátozó intézkedésekkel sújtotta őket. Az 1658-as összeomlás eltörölte ezeket az intézkedéseket. A reformáció után evangélikus vallásúak lettek.\n\nRománok:\n\n- A románok betelepülése több hullámban történt az Árpád-kortól kezdve. A román betelepülők saját vajdáik vezetése alatt érkeztek, és csoportosan telepedtek meg a Kárpátok hegyvidékein. Jórészt állattartó pásztorok voltak. Számuk növekedésével az alacsonyabb területekre is lehúzódtak, s többen tértek át a földművelésre. Ez felgyorsította az etnikai keveredést. A folyamatot a nemesek is támogatták, mivel szükségük volt a munkaerőre. A XVI. században a havasalföldi és moldvai helyzet romlása a románok újabb tömeges betelepülését vonta maga után. A románok nem kaptak politikai státust, s így országgyűlési képviselettel sem bírtak. A felemelkedő román családok a magyar nemesség soraiba igyekeztek bejutni, s így etnikai gyökerüktől elszakadtak. Csonka társadalom jellemzi őket, inkább pásztorkodással, földműveléssel foglalkoztak, nemesi és polgári rétegük nem alakul ki jelentős mértékben.\n\n• A XVI. század végétől tehát jelentős betelepülési hullám figyelhető meg.\n\n• Túlnyomórészt hegyvidékeken telepedtek le, vándorló pásztorkodást folytattak, csak egy részük élt letelepülve, jobbágytelken gazdálkodva (juh, szarvasmarha; és termékeik után adóztak). Egy szűk csoportjuk felemelkedett és integrálódott a magyar nemességbe (Kendeffyek, Macskássiak).\n\nA román fejedelemségekben (Havasalföldön, Moldvában) azok a vajdák kerültek pozícióba, akik a legtöbb adót ígérték a szultánnak. A kiszámíthatatlan helyzet elől sok román telepedett Erdély peremhegyein belülre, ahol pásztorkodással, kisebb részt földműveléssel tartották el magukat. A román falvak ellensúlyozták a lassú asszimilációt, gyarapítva ezáltal a román jobbágyok számát. A XVII. században a románság jobbágyai a székely jobbágyokhoz, előkelői pedig a magyar nemesekhez válnak mindinkább hasonlóvá. A feudalizmus rendszerén kívül élő pásztor nomád románság viszont őrizte különállását. Orthodox vallásúak.\n\nA XVIII. században következett el Erdély életében a Pax Habsburgica, azaz a Habsburg birodalomba való betagolódást követő békeévek időszaka, ami a század végére Erdély népességének megduplázódását eredményezte. A statisztikát a török alól felszabadult területek néptelen részeire történő elvándorlás, és az 1717-1720-as pestisjárvány rontotta. A románok számaránya a XVIII. században meghaladja az erdélyi lakosság egyharmadát. A Habsburgok nem egyesítették Erdélyt Magyarországgal, hanem külön kormányozták, ez a Gubernium.\n\nErdély társadalma:\n\nMagyarok - teljes társadalom: nemesség, polgárság, jobbágyság.\n\n• 1600 körül kb. 800 ezer (magyar és román 550 ezer, székely 180 ezer, szász 100 ezer) lakosa volt Erdélynek.\n\n• A fejedelem:\n\n• gazdagságát a családi és a kincstári birtokok együttes jövedelme határozta meg, a fejedelem volt az egyetlen igazi nagybirtokos.\n\n• A nemesség:\n\n• 300-400 birtokos család volt, szétaprózott birtokokkal. A leggazdagabbak: Kendiek, Apafiak, Csákyak, Bánffyak, somlyai Báthoryak, iktai Bethlenek, Wesselényiek.\n\n• A nemesség nemcsak gazdaságilag, hanem politikailag is gyenge volt, az erdélyi országgyűlésen csak akkor vehettek részt, ha személyre szóló meghívót kaptak.\n\nPolgárság: mezővárosi elsősorban.\n\nJobbágyság:\n\n• A síkvidéken magyarok - háborúkban nagy veszteségeket szenvedtek;\n\n• a hegyvidékeken románok - a háborúk kevésbé sújtották őket, havasalföldi bevándorlókkal még gyarapodtak is.\n\nErdély vallási sokszínűsége a XVI. század közepére alakult ki a reformáció eredményeként. Legtovább a székelyek ragaszkodtak a katolicizmushoz, míg a szászok körében a németországi kapcsolatok miatt igen korán teret nyertek a lutheri tanok (ők szervezték meg az első protestáns egyházszervezetet is). A reformáció és a vallási sokszínűség tehát részben Erdély sajátos etnikai és politikai sokszínűségéből következett (a románok többsége megőrizte görögkeleti hitét).\n\nA reformáció lutheri irányzata már Mohács előtt megjelent Magyarországon, míg a kálvini tanok a szakadást követően kezdtek terjedni. Erdélyben a brassói Honterus indította meg a térítőmunkát, aminek eredményeként az 1550-es évekre készen állt a szászok lutheri egyházszervezete, s már saját püspököt is választottak. Kolozsvárott Heltai Gáspár vált a vallás ismert lelkészévé, aki többek között majdnem a teljes Bibliát lefordította és kiadta. 1556 után (ekkor álltak Erdély urai János Zsigmond pártjára, s hívták őt haza országába) a kálvini tanok terjedése is felgyorsult, s a Partium jelentős részén (Debrecennel az élen) az új vallás hívei kerültek többségbe. Közben a Szervét Mihály-féle antitrinitárius (Erdélyben unitárius), azaz Szentháromság-tagadó tanok is elterjedtek. A Heltait váltó kolozsvári lelkész, Dávid Ferenc hatására a város előbb a kálvini hitre tért át, később az unitárius tanok szolgálójává lett. A lelkész hatására János Zsigmond is a Szentháromság-tagadó irányzat felé fordult. Maga János Zsigmond (1541-1571) tehát nyitott volt az új tanok iránt. A katolicizmust már csak azért sem pártfogolhatta, mivel a katolikus Habsburgok ellenfelei voltak (a katolikusok vallásszabadságát csak 1581-ben ismerték el). Az erdélyi egyház pedig még akkor meggyengült, amikor Fráter György üresen hagyta a gyulafehérvári püspöki széket, és lefoglalta a püspöki birtokokat az állam részére. Ezt követte a szerzetesrendek kiutasítása, majd az összes katolikus egyházi vagyon elkobzása (1556).\n\n- János Zsigmond fejedelmi védelem és irányítás alá vonta a protestáns felekezeteket (1557). Ő maga hívta össze a zsinatokat, és állást foglalt a hitvitákban, megerősítette a választott papokat. 1564 után sorra szervezte meg a lutheránus püspökségeket (külön püspököt kaptak a magyarok és a románok). A király hitbéli nyitottsága megerősítette Erdély vallási toleranciáját. Udvarában különféle vallási irányzatok képviselői kaptak helyet, akik hatást is gyakoroltak rá. Így Dávid Ferenc püspök hatására a kálvini tanok felé fordult, majd Blandrata György Erdélybe érkezése után az antitrinitárius felekezet híve lett, amit az 1569-es országgyűlésen jelentett be. E vallási nyitottságot tükrözi az országgyűlés határozata a gyülekezetek szabad vallásválasztásáról (1568), ami megvonta a birtokosok beleszólását a kérdésbe.\n\nAz 1560-as években tehát Erdélyben három protestáns felekezet is létezett, s a katolicizmus sem tűnt el teljesen, hiszen a csíki és a háromszéki székelyek nemessége mindvégig megmaradt őseik hitén. Mindemellett pedig a mind nagyobb létszámban jelen lévő románok hite, az ortodox kereszténység is külön színfolt volt Erdély vallási térképén.\n\nE sokszínűség elismerését az 1568-as tordai országgyűlés hozta meg, ahol törvényt alkottak az evangélium hirdetésének és magyarázatának teljes szabadságáról. A „négy bevett vallás” (katolikus, református, evangélikus és unitárius) iránti türelemről azonban csak Báthory István fejedelemségétől beszélhetünk (visszaadta az 1556-ban elüldözött katolikusok szabadságát, de toleráns maradt a protestánsokkal szemben is). Bár sem az ortodox, sem a zsidó hit, sem pedig a reformáció Erdélyben szintén népszerű más (anabaptista, szombatos) irányzatai nem tartoztak a bevett irányzatok közé, a Tordán megvalósult tolerancia még így is páratlan volt a maga korában. Ez a vallási sokszínűség egészen a Habsburg uralom visszaállításáig töretlen maradt, s csak a III. Károly által szorgalmazott ellenreformáció változtatta meg a XVIII. században.\n\nErdély sajátos sokszínűsége egy hosszú történelmi fejlődés eredménye, és összefügg periférikus, határvédő fekvésével. Az Árpád-korban kialakult struktúrák 1541 után egy önálló állam keretei között teljesedtek ki (három nemzet). A vallási sokszínűség részben az etnikai kevertség következménye, részben a fejedelmi politika eredményeképpen alakulhatott ki. E vallási sokszínűséget Dávid Ferenc esete példázza, aki lutheránus püspök lett, majd a református tételektől az antitrinitárius irányzaton át a szombatosokig jutott el az igaz hit keresése közben.\n\nÖsszegzés: a reformáció megjelenése és irányzatai:\n\n• A reformáció először a szász városi polgárság körében terjedt (evangélikusok);\n\n• a magyarok körében a kálvinizmus terjedt el; a székelyek nagy része katolikus maradt;\n\n• a románság megmaradt ortodox hitűnek.\n\nMíg más országokban vallásháborúk dúltak, Erdélyt a vallási türelem jellemezte:\n\n- 1557-ben az erdélyi országgyűlés kimondta a katolikusok és evangélikusok;\n\n- 1564-ben az evangélikusok és a reformátusok szabad vallásgyakorlását;\n\n- 1568-ban, a tordai országgyűlésen pedig a János Zsigmond által is támogatott unitáriusok szabad vallásgyakorlását (a 4 bevett vallás: katolikus, református, evangélikus, unitárius).', 58, 1, '2026-04-17 09:40:02', '2026-04-17 09:40:02');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(6, 6, 'Demográfiai és etnikai változások Magyarországon a 18-20. században', '6.docx', '6. tétel: Demográfiai és etnikai változások Magyarországon a 18-20. században\n\nMagyarország demográfiai viszonyai a török kiűzése után: VÁZLAT\n\nA folyamat a török kiűzése után, a XVIII. században ment végbe, és a néptelenebb hódoltsági területeket érinti.\n\nMagyarországnak csak Habsburg segítséggel sikerül kiűzni a törököt az országból, így a Habsburg uralkodók az ország területét meghódított területnek tekintették.1686-ban sikerült kiűzni a törököt Budáról, a felszabadító háborúk az 1699-es karlócai békével értek véget, ezzel Magyarország a Temesköz kivételével felszabadult a kb. 150 éves török uralom alól. A török kiűzéséért vívott háború jelentős népességvesztéssel járt. A török által eddig megszállt területek elnéptelenedtek, melyeket a Habsburgok segítségével benépesítenek. Míg Európa népessége dinamikusan növekedett, addig Magyarország népessége a török korszakban nem nőtt.\n\nHabsburg III. Károly (1711-1740) a Rákóczi-szabadságharcot lezáró szatmári béke (1711) után Magyarország újjáépítésére törekedett. A népesség növekedésének módjai: telepítés, belső vándorlás, bevándorlás.\n\nDemográfiai változások a török hódoltság után: az ország népessége 1720 körül alig érte el a Mátyás korabelit: kb. 3,5 millió lehetett. Akkor a magyarok a lakosság 80 %-át tették ki, 1720-ban számuk 2 millióra csökkent. A XVIII. századi népmozgások során a magyarság kisebbségbe szorult, számaránya alig közelíti meg az 50%-ot. A lakatlan tájak benépesítése a török kiűzésével megindult, és elsősorban a nem magyarok telepedtek ide. A betelepítéseket a korábbi háborúk által okozott, illetve a török hódítás időszakában bekövetkezett népességpusztulás indokolta\n\nTelepítések: a bécsi kormány és a nagybirtokosok szervezett telepítéseiről van szó. 1720-tól főként a német birodalom déli részéről települtek hazánkba. Kedvezményeket kaptak az idejövők: 6 évig adómentesség, házak, mezőgazdasági felszerelések. A főleg katolikus németek előre megépített, szabályos alaprajzú falvakba költöztek. A XVIII. század végén már egymillió német élt hazánkban. A német telepeseket a köznyelv sváboknak nevezte. Főként Buda környéki falvakba, a Bakonyba, Veszprémbe, Tolnába és Baranyába, a Dél-Dunántúlra és a Temesközbe költöztek.\n\nA betelepítettek kedvezményeket kaptak: meghatározott ideig mentesség az adók, beszállásolás és forspont alól. Ez ösztönözte őket a betelepülésre. A betelepítettek számára építőanyagot vagy előre épített házakat és telkeket biztosítottak, tehát a betelepítés szervezett volt. A betelepülő németek katolikusok voltak, betelepítésük részben az udvar céljait szolgálta: az udvarhű réteg erősítése, protestantizmus visszaszorítása. A betelepítés a földesuraknak és az udvarnak egyaránt érdekében állt, és ezzel nőtt az adóalap is. A betelepítések hozzájárultak a XVIII. századi népességnövekedéshez, ugyanakkor csökkentették a magyarok arányát a teljes népességen belül.\n\nSzervezett telepítéssel érkeztek még hazánkba még: itáliaiak, spanyolok, franciák, csehek, bolgárok. A szerbeket fegyveres határőrökként telepítette be.\n\nKárolyi Sándor a svábok betelepítését kérvényezi, a cél az adózók számának növelése, a katolikus vallás erősítése is. Az adózás és katonáskodás alóli mentességet kéri. A földbirtokosoknak is érdeke a betelepítés, hogy legyen, aki megműveli a földjeiket. A délnémet és rajnai tartományokból származnak a bevándorlók.\n\nTessedik Sámuel német, szláv és román bevándorlókról ír, illetve a Magyarországon belüli vándorlásról, a vallási türelemről, az óriási népességnövekedésről, és arról, hogy a hódoltság idején a középső területek elnéptelenedtek.\n\nBelső vándorlás: ebben magyar és szlovák jobbágyok, románok és horvátok vettek részt. A sűrűn lakott megyékből érkeztek az elnéptelenedett vidékekre, azaz a Felvidék egyes megyéinek falvaiba, az Alföldre és a Temesközbe. A belső vándorlásban elsősorban magyarok, szlovákok, Bevándorlás: a Magyarország környékén élő népek beköltözéséről van szó. Legnagyobb tömegben románok jöttek be Erdélybe, az Alföld keleti részébe és a Temesközbe. A szerbek a török fenyegetés elől menekültek Magyarországra. A szerbek a Délvidéken Bácskába települtek be és a Határőrvidéken helyezkedtek el . Bevándoroltak még a ruszinok, morvák, lengyelek, örmények, görögök is.\n\nII. Etnikai arányok a XVIII. század végén: II. József (1780-1790) népszámlálást rendelt el a XVIII. század végén, 1790-ben. Az ország lakossága ekkor már 9,3 millió a telepítéseknek és a vándorlásoknak köszönhetően, illetve annak, hogy az országot ekkor már nem sújtották háborúk, mint a török korban. Mária Terézia (1740-1780) és II. József politikájának következtében az ország népessége növekedett.\n\nA lakosságból 3,5 millió magyar, 1,5 millió román, 1,25 millió szlovák, 1,1 millió német, 0,8 millió horvát, 0,6 millió szerb, 0,3 millió ruszin, 0,3 millió zsidó, örmény, görög. Tehát 5,8 millió lakos idegen ajkú Magyarországon, így a magyarok számaránya nem éri el az 50 %-ot sem. Soknemzetiségű országgá váltunk, ahol a lakosság 39 %-át teszi ki a magyarság.\n\nA XVIII. század végére Magyarország népessége robbanásszerűen növekedett. Az országon belül a népsűrűség egyenlőtlensége csökkent, a népességnövekedés gazdasági növekedést is eredményezett. Magyarország többnyelvű, soknemzetiségű országgá vált. A magyarság csak relatív többségben volt. A korszakban az önmeghatározás alapja még a kiváltság és a vallás volt, nemzeti konfliktusokra csak a XIX. században került sor.\n\nIII. Gazdaság: A különböző területeken eltérő volt a fejlődés. Míg nyugaton árutermelés és 3 nyomásos gazdálkodás volt, addig az ország középső és déli részén önellátó szinten éltek és elmaradottság volt. A Habsburg Birodalmon belül munkamegosztás jött létre Magyarország és az örökös tartományok között: Magyarország elsősorban élelem- és nyersanyagtermelő ország volt, míg az osztrák és a cseh tartományok ipari termékekkel látták el országunkat. Így eredményes magyar ipar nem volt.\n\nKIFEJTÉS\n\nNépességpusztulás\n\nDemográfia: Az emberi népességek, összetételük, területi elhelyezkedésük és változásaik számszerű elemzésével foglalkozó tudomány.\n\nA XVII-XVIII. század háborús évtizedeiben a Magyarországot ért csapások közül a legsúlyosabb következményekkel járó és hosszútávon a legnagyobb kihatású az emberveszteség, a népességpusztulás volt. A háborúk okozta szenvedések és károk – falvak kiirtása, emberek legyilkolása vagy rabságba hurcolása, éhínségek, járványok – jelentősen megváltoztatták Magyarország demográfiai arculatát; hatásai legerősebben a Hódoltságban és Erdélyben jelentkeztek, de érezhetőek voltak a Királyi Magyarország területén is.\n\n• területi vonatkozások\n\nEgész területek váltak lakatlanná a seregek nyomán, a Délvidéken a Maros vonalától délre, a Dél-Dunántúlon és a Duna mentén egészen Pest térségéig teljes volt a népességvesztés; a mai Magyarország területén, a Felvidék déli részein és az Erdélyi-medencében is jelentős népességvesztés történt. (Az Alföldön 1 fő/km² átlagos népsűrűség volt jellemző, Erdélyben ugyanez a mutató 25-30 fő/km² volt.) Ezek a területek többnyire alacsony domborzattal, viszonylag jó megközelíthetőséggel rendelkeztek, vagy – mint például a Duna mente – hadi utak mentén helyezkedtek el. A jelentős pusztulástól csak a magasabban fekvő, nehezen megközelíthető vidékek (mocsarak, lápok, sűrűségek) menekültek meg, melyek kiestek a hadak vonulási útjából: a Felvidék északi részei, az Erdélyi-szigethegység, Kárpátalja, illetve a belső területnek számító Székelyföld és Szászföld.\n\n• időbeli vonatkozások\n\nA 150 éves török uralom során a legnagyobb népességpusztulással leginkább az elhúzódó harcok jártak: visszafordíthatatlan folyamatokat okozott az 1593-1606 között zajló tizenöt éves háború, majd a török kiűzésének jó másfél évtizedes időszaka (1683-99). A Rákóczi-szabadságharc (1703-11) tanulságainak levonását követően a Habsburg uralkodók igyekeztek helyreállítani a megbomlott egyensúlyt, az ország újbóli betelepítésén fáradoztak, s mindenirányú fejlődését segítették elő. Az új rend (felvilágosult abszolutizmus) gyors bevezetése miatt kialakuló elégedetlenséget elfojtották, az országon belüli parasztfelkeléseket időben leverték (Maros-Körös köze 1735, Nyugat-Dunántúl 1765-66, Erdély 1784).\n\n• a veszteségek nagysága\n\nA veszteségek nagyságáról nincsenek pontos adataink. A pusztulás mértéke máig vitatott, hiszen népszámlálást először a XVIII. század végén tartottak Magyarországon, s így főként a török adóösszeírások, a defterek adataira támaszkodva a történeti demográfia kutatói inkább csak becslésekkel dolgozhatnak. Míg korábban a XVI. század eleji népességet 3,5-4 millióra, esetenként 4,5 millióra becsülték, addig az újabb elemzések csak 3,3-3,5 millió fővel számolnak. Így az 1711-es népesedési mélyponton meghatározott 4 millió főhöz képest beszélhetünk enyhe csökkenésről, stagnálásról, illetve az újabb kutatásoknak megfelelően lassú növekedésről.\n\nMindazonáltal nem vitatott, hogy a két évszázad alatt Magyarország vérvesztesége rendkívül jelentős volt. Ezt jól mutatja az a tény is, hogy Európa népessége a korszakban átlagosan közel 60%-kal növekedett, azaz Magyarország népessége kedvezőbb körülmények között hozzávetőleg másfélszeresére nőhetett volna, ahelyett, hogy stagnált vagy enyhén csökkent, illetve enyhén nőtt. A nagyarányú magyar népességvesztéssel és az ezzel párhuzamos jelentős európai népességnövekedéssel a magyarok számaránya is csökkent Európában: az ország népességének aránya a kontinens lakosságában 6%-ról 4%-ra csökkent. Tovább árnyalja a képet az a tény, hogy a stagnáló népességszám magában foglalja a két évszázad jelentős mennyiségű román és szláv bevándorlóit is.\n\nNépességmozgás\n\nA nagyarányú népességpusztulás hatására komoly változások, mozgások indultak el Magyarország demográfiájában, melyeknek három formája alakult ki: a népesség belső mozgása, a népesség kintről történő bevándorlása (öntevékeny betelepülés) és a tudatos, szervezett betelepítés.\n\n• a népesség belső mozgása (migráció)\n\nMég a török kiűzése előtt, a harcokkal egy időben kialakult a népesség egyfajta mozgása Magyarország határain belül, melynek köszönhetően alapvetően megváltozott a háborús pusztítások által leginkább érintett térségek településszerkezete. A tizenöt éves háború visszavonhatatlan változásokat hozott e téren is: az Alföld egykori aprófalvainak népe, a Temesközben és a hadi utak mentén fekvő falvak lakossága a nagyobb biztonságot nyújtó településekre menekült, melyek így idővel óriásfalvakká, később mezővárosokká nőtték ki magukat. Az aprófalvak, a jobban veszélyeztetett kisebb települések így teljesen elpusztultak, miközben lassan kialakult egy új társadalmi réteg, a mezővárosok polgársága.\n\nAz aprófalvak pusztulásánál azonban jelentősebb volt a belső népességmozgás (migráció) azon fajtája, mely a háborúk elmúltával komoly szerepet játszott a ritkán lakott területek benépesítésében. Mivel a pusztítások nem egyenletesen érintették az ország területét, a jórészt sértetlenül maradt hegyvidékek népsűrűsége magasabb volt, s így ezen országrészek lakossága a völgyek, dombságok és sík földterületek felé indult meg. Ezt a hatalmas népességmozgást a hegyvidékek kevés és rossz minőségű termőföldjének korlátozott eltartó képessége indokolta, s a gyéren lakott területeken fellépő munkaerőhiány, s az ott biztosított kedvezmények (pl. átmeneti adómentesség) ösztönözték.\n\nAz ország ritkán lakott belső vidékeit elsősorban az Észak-Dunántúlról és az Alföld peremvidékeiről érkező magyar jobbágyok népesítették be. A szlovák jobbágyok egyrészt az elvándorló magyarok helyére költöztek, másrészt – a magyar jobbágyokhoz hasonlóan – az Alföld szabad földterületein települtek le. Kisebb mértékű volt a szlovákhoz hasonló ruszin (rutén) népmozgás. Hosszabb távon súlyos következményekkel járt a védett hegyvidékek románságának belső vándorlása is, akik a völgyek és az Alföld irányában mozogva a XVIII. század végére túlsúlyba kerületek Dél-Erdélyben, az Erdélyi-szigethegységben és a Temesköz vidékén. A belső mozgások következtében a Kárpát-medence belseje felé húzódott vissza a magyar etnikai határ, ugyanakkor megmaradt az ország középső részének magyar jellege.\n\n• bevándorlás\n\nA bevándorlás öntevékeny betelepülés volt, azaz az ország határai mentén élő idegen ajkú népcsoportok a szabad földterületeket, a munkaerőhiánnyal küzdő magyar nemesek átmeneti engedményeit szem előtt tartva önként települtek be Magyarországra, ahol – a továbbra is török hódoltságban lévő Balkán országaival ellentétben – a békés munka, a nyugodt, rendezett élet lehetősége volt biztosítva.\n\nKezdetben csupán délről indult meg a bevándorlás szerbek, bosnyákok, szlavónok, horvátok és vlachok (románok) részéről, majd északról csehek, lengyelek és ruszinok érkeztek. A szerbek (korabeli nevükön rácok) a Bácskában telepedtek le. A románok (korabeli nevükön oláhok) a török vazallus dunai fejedelemségekből, Havasalföldből és Moldvából nagyszámban vándoroltak be erdélyi területekre, s ennek is köszönhető, hogy az 1700-as évek végére több helyen többségbe kerültek. A csehek, lengyelek és ruszinok a Felvidék északi részein telepedtek le, s később beolvadtak a szlovák nyelvű népességbe.\n\n• betelepítés\n\nA tudatos, szervezett betelepítés kisebb részben a magyar földbirtokosok, nagyobb részben a bécsi udvar irányításával folyt. Míg a birtokosoknak a munkaerő pótlására volt szükségük ahhoz, hogy a termelés szintje elérje a békés évtizedek szintjét, addig az államot az adóalap növelése, a gazdaság talpra állítása vezette. Ennek értelmében a magyar földesurak – a korszak szellemének megfelelően – etnikai szempontok figyelembe vétele nélkül telepítettek le és láttak el munkával szláv és román jobbágyokat.\n\nI. Lipót a török kiűzése után mintegy 100 000 menedéket kérő szerbet telepített le a későbbi Határőrvidék területén, s egyházi autonómiájukért cserébe a török határ védelmét bízta rájuk.\n\nAz udvar elsősorban azonban katolikus németeket költözetett Magyarországra, ami a korszakban nem elhanyagolható felekezeti szempontokat is figyelembe véve a saját hatalmának erősítését, bázisának növelését jelentette. A betelepülő katolikus németséget már a XVIII. században sváboknak nevezték el, „Sváb Törökország” volt a neve a Tolna és Baranya vidékén létre jövő összefüggő német tömbnek, sváb települések keletkeztek Buda környékén, a Bakony, a Vértes és a Pilis hegyeken, sváb szigetek alakultak ki Bácskában és Bánátban is. A német telepeseket az udvar komoly engedményekkel ösztönözte (pl. adómentesség hat évre), sőt, egyes helyeken (pl. Bánát) előre felépített és berendezett falvak várták az idegeneket.\n\nAz egyes nemzetiségek a XVIII-XIX. században Magyarországon\n\n• románok (oláh)\n\nA XVIII. század folyamán a románság nagy számban vándorolt be Havasalföldből és Moldvából Erdélybe, s Székelyföld kivételével Erdélyben többnyire túlsúlyba is kerültek. Így a század végére a román lett a legnagyobb nemzetiség Magyarországon: az ország lakosságának 13,7%-át tette ki. Román etnikai tömbök Erdélyben, a Partiumban és a Temesközben alakultak ki, de még a leginkább román többségű területeken is keverten helyezkedett el a magyar, a német és a román nemzetiség.\n\nA románok csonka társadalmat alkottak: a túlnyomórészt parasztságból álló etnikumban csak igen vékony vezető réteg jelent meg, kis számú egyházi, nemes és polgár. (Csonka társadalom: olyan társadalmi szerkezet, amelyből hiányzik valamelyik társadalmi réteg. A horvátokat kivéve az összes magyarországi nemzetiségre ez volt jellemző.)\n\nA görög katolikus püspökség székhelye Balázsfalva, míg a görögkeleti (ortodox) püspökség székhelye Szeben lett, s mivel a románság vezetésében első számú hely jutott a papságnak, mindkét város fontos központja lett a későbbi román nemzeti mozgalmaknak.\n\n• németek (svábok)\n\nA németség volt Magyarországon a második legnagyobb nemzetiség (11,6%), azonban nem beszélhetünk róluk mint egységes etnikumról: a magyarországi németség a XVIII. századtól három viszonylag jól elkülöníthető csoportra oszlott.\n\nA szabad királyi városok német polgárai és az erdélyi szász polgárok (Szepesség, Szászföld) döntő többsége egyaránt evangélikus volt, és városi polgári életmódot éltek, jellemzően iparos, kereskedő vagy valamilyen értelmiségi mesterséget űztek.\n\nA bécsi udvar által nagy számban betelepített svábok nagyobb tömbökben, etnikai szigetekben helyezkedtek el Magyarországon (Tolna és Baranya megye, Buda környéke, Bakony, Vértes, Pilis tája, Bácska, Bánát). Zömében egynemű paraszti társadalmat alkottak, és a katolikus vallást gyakorolták, mint a Habsburgok.\n\n• szlovákok (tótok)\n\nA harmadik legnagyobb nemzetiség (10,2% a XVIII. század végén) Észak-Magyarországon, a Felvidéken került túlsúlyba, de jelentős etnikai szigetek jöttek létre a migráció következtében az ország belsőbb területein is (pl. Buda és Pest környéke, Békés).\n\nA szlovákok is csonka társadalmat alkottak, hiszen túlnyomórészt jobbágyi sorban éltek, csak vékony polgári réteggel rendelkeztek (polgárság, kispolgárság a városokban), a szlovák származású kis- és középnemesek jobbára a magyar nemesség részének tekintették magukat. A kedvezőtlen adottságú terület (magas hegyek, hűvös völgyek, rossz termőföld) nem tudta eltartani a növekvő népességet, így a férfiak gyakran idénymunkák elvállalására kényszerültek, vagy mesteremberként járták a birodalmat (drótostótok, üvegestótok). A későbbiekben kibontakozó nemzeti mozgalmukat nem segítette saját, különálló egyház: az egyes tájak vallási viszonyainak megfelelően a magyarokkal keveredve katolikusok vagy evangélikusok voltak.\n\n• horvátok\n\nAnnak ellenére, hogy a horvát csak a negyedik legnagyobb nemzetiség volt Magyarországon (9,1%), a magyar közjog egyedül Horvátországot ismerte el különálló országnak Magyarországon belül, s egyedül a horvát nemesség számított valódi nemesi nemzetnek a magyar nemességen kívül. Kiemelt helyzetük történeti okokkal magyarázható.\n\nTerületi autonómiájuknak is köszönhetően egyedül a horvátok alkottak teljes társadalmat a magyarországi nemzetiségek között, hiszen a népes parasztság mellett kis számú polgárság és értelmiség, valamint rendi öntudattal bíró nemesség képezte társadalmukat. A horvátok katolikusok voltak, s a zágrábi püspökség kapcsolta egyházukat Rómához.\n\n• szerbek (rácok)\n\nA szerbek 6,5%-kal részesedtek Magyarország lakosságából a XVIII. század végén, amihez jócskán hozzájárult, hogy a század folyamán a szabad földterületek, a nyugodt munka és a rendezett élet csábítására jelentős számban vándoroltak be a török hódoltságban maradt Szerbiából. Az ország déli részén, a Határőrvidéken éltek Bácska, Bánság és Szerémség területén egy nagyobb tömbben magyarokkal és németekkel keveredve, illetve jelentős szerb etnikai szigetek jöttek létre Szlavónia és Horvátország déli részein is a horvát többségi lakosság közé ékelve.\n\nA szerbeké is csonka társadalom volt: hiányzott a nemesi réteg, csoportjaik irányítása így elsősorban görögkeleti papságukhoz és – a Határőrvidék következtében – a szerb katonai vezetőkhöz köthető. A Határőrvidék közvetlenül a bécsi Haditanács igazgatása alá tartozott, így Magyarországtól független volt, s lakói nem kerültek földesúri függésbe.\n\nLipóttól kapott egyházi autonómiájuk is megerősítette különállásukat, így a karlócai érsekség nemzeti fejlődésük központját képezte a későbbiekben.\n\n• ruszinok (ruténok)\n\nA ruszin (rutén, kárpátukrán) nemzetiség Északkelet-Magyarország hegyvidékén élt, s az ország lakosságának 3,4%-t tette ki. A jobbágyi tömegek mellől a nemesség és a polgárság rétege teljesen hiányzott, vezetőik a görög katolikus papság soraiból kerültek ki.\n\n• zsidók\n\nA XVIII. század második felében Galíciából sok szegény, míg a Lajtántúlról (Morvaországból) kevés gazdag zsidócsalád vándorolt be Magyarországra. Mivel földtulajdonnal nem rendelkezhettek, s számos foglakozást nem gyakorolhattak, a magyar társadalomban hiányzó pozíciókat töltötték be, elsősorban a kereskedelemben.\n\n• cigányok\n\nA cigányság a XV-XVI. századtól települt be kelet felől, számaránya azonban még a XVIII. században is csekély volt Magyarországon. A vándorló életmódot folytató etnikumot drasztikus módszerekkel próbálták asszimilálni (nyelv betiltása, gyermekek elvétele szüleiktől); a század első felében a vármegyék időszakonként elüldözték őket területükről, a század második felében kísérletet tettek letelepítésükre.\n\nA népességmozgások következményei\n\nA szervezett és az öntevékeny betelepülésekkel a magyarság számaránya a XVIII. században Magyarországon jelentősen csökkent. Ehhez még a betelepülések előtt hozzájárult, hogy a népességvesztés legnagyobb mértékben eleve a többnyire síkvidéken, dombságokon vagy völgyekben élő magyarságot érte, míg az idegen ajkúak többsége a jórészt érintetlen hegyvidékeken lakott. Így a két tényező hatására a XV. századi 80%-ról 40-42%-ra esett vissza a magyarság számaránya az országban a történeti demográfia becslései szerint.\n\nAz etnikai összetétel és arány megváltozásával Magyarország soknemzetiségű állammá vált, ami egyben multikulturalitást is jelentett. A nemzetállamok létrehozásában később a XIX-XX. században komoly gondot okozott, hogy Magyarország a XVIII. századra nemcsak soknemzetiségű, de kevert nemzetiségű lett, azaz az egyes nemzetiségek keverten helyezkedtek el. Az etnikai tömbök határai egymásba fonódtak, etnikai szigetek jöttek létre, nem lehetett egyetlen vonallal szétválasztani a különböző nemzetiségeket. (Gyakran egy falun belül is egymás mellett éltek több nemzet tagjai.)\n\nUgyanakkor a XVIII. század végéig a nemzetiségek egymás mellett élése nem vezetett komolyabb ellentétekhez. A nacionalizmus még nem terjedt el Magyarországon, a fő azonosulási pont továbbra is a társadalmi helyzet és a felekezeti hovatartozás volt; a nemzettel való azonosulás helyett még az országgal való azonosulás („hungarus”-tudat) volt jellemző. (A Horea és Closca-féle 1784-es román parasztfelkelés volt a Kárpát-medencében az első, ahol nemzeti szempontok is fölmerültek.)\n\nA népességmozgások legfőbb kedvező hatása – és egyben szükségessége – az volt, hogy az ország újra benépesült, az ország népessége „regenerálódott”, a munkaerőhiány megszűnt, így biztosítva volt a gazdasági fejlődés alapja.\n\nAz első magyarországi népszámlálás II. József uralkodása alatt, 1787-ben zárult le, s eredménye azt mutatja, hogy az ország népessége kevesebb, mint egy évszázad folyamán megkétszereződött. Az 1711-es 4 millió körüli népességhez képest 1787-ben a lakosság száma megközelítette a 10 millió főt. A békés évtizedek, a gazdaság helyreállása, az éhínségek megszűnése, a nélkülözések és járványok csökkenése jól látható módon meghozta gyümölcsét. A nagyarányú népességnövekedés egyszerre volt köszönhető a betelepüléseknek és kisebb részben a jelentős népszaporulatnak.\n\nÖsszegzés\n\nA XVI-XVII. század török- és Habsburg-ellenes harcai, valamint a Rákóczi-szabadságharc rendkívül tekintélyes népességvesztéssel járt Magyarországon. A XVII. században meginduló migráció, a belső népességmozgás, a külső öntevékeny bevándorlás és a szervezett betelepítés újra benépesítette Magyarországot és megteremtette a gazdasági fejlődés alapját; majd a XVIII. századi népszaporulattal megkétszerezte az ország népességét az 1711-es demográfiai mélyponthoz képest. Az idegen ajkúak bevándorlásával azonban a magyarság számaránya a Kárpát-medencében 50% alá csökkent, ami Magyarország későbbi története folyamán a legsúlyosabb gondok egyikévé vált. Ezért állíthatjuk, hogy a korszak háborúskodásaiban a Magyarországot ért csapások közül a legsúlyosabb következményekkel járó és hosszútávon a legnagyobb kihatású az emberveszteség, a népességpusztulás.\n\nNemzeti eszme és nemzetiségek a reformkorban\n\nNacionalizmus (natio, azaz nemzet)\n\nA XIX. századra Európában a feudális rendszer egyre tarthatatlanabbá vált. Az 1830-as éveknek a Szent Szövetség konzervatív rendszere ellen irányuló forradalmi mozgalmak olyan nemzetközi válságot eredményeztek, amely megnyitotta a polgári átalakulást elősegítő liberalizmus előretörésének időszakát. Nyugaton a polgári nemzeti átalakulás a gazdasági életben együtt járt a polgárság felemelkedésével. Itt a liberális eszméket is a polgárság képviselte, először politikai hatalmának kivívása, majd megtartása érdekében. Kelet-Közép-Európában ez a liberalizmus erősen nemzeti jellegű volt. Ebben a régióban hiányzott a politikai függetlenség vagy a területi egység.\n\nAz egyes országok más-más szintjét érték el annak a fejlődésnek, amely a feudális rendszertől a tőkés gazdaság, a polgári nemzetállam felé tartott. A felvilágosodás és a francia forradalom hatására született meg a modern polgári nemzet fogalma: egy terület lakosságának a nyelv, a kultúra és a történelmi tradíciók által kibontakozó közössége.\n\nA modern nemzetek kialakulásának verziói:\n\nállamnemzeti fejlődés pl. Franciaország, Anglia – a nemzetté válás egy önálló állam keretei között ment végbe. Kialakulhatott a nemzetállam.\n\nkultúrnemzeti fejlődés\n\negységesülési törekvések pl. német, olasz (1848 forradalmi út, majd az 1860-as években dinasztikus út) Cél: az önálló nemzetállam kialakítása.\n\negy nagy birodalom fennhatósága alatt élő népek önállósodási törekvései pl. horvát, magyar. Önálló államiság hiányában a nemzeti fejlődés a kultúra világában kezdődik el.\n\nMagyarországon a XVIII. században a II. Józseffel (1780-90) való szembeszegülés és a felvilágosodás következtében nyelvi, etnikai tartalmat kapott a nemzeti eszme. II. József nyelvrendelete, a német nyelv kötelezővé tétele ellenállást váltott ki Magyarországon, a magyar hagyományok előtérbe kerültek a tiltakozás során. A felvilágosodás képviselői a magyar nyelv ügyét helyezték előtérbe: „Minden nemzet a maga nyelvén lett tudós, de idegenen sohasem” – írja Bessenyei György. Kazinczy nyelvújítási mozgalomba kezd a század elején, és 10.000 új szót hoznak létre. A romantika jellegzetessége a nemzeti múlt felé fordulás. Vörösmarty: Zalán futása, Kölcsey: Himnusza, Vörösmarty: Szózata, Erkel Ferenc nemzeti operái, Katona József Bánk bánja is erről tanúskodik.\n\nA XIX. századra a liberalizmus és a nacionalizmus eszméinek jegyében reformmozgalom bontakozik ki, melynek célja: Magyarország polgári átalakulása és nemzeti függetlensége a Habsburg-birodalmon belül. Kölcsey szavaival élve: „Jelszavaink valának: haza és haladás.” A XIX. századra kialakult polgári nemzeteszme nyelvi, etnikai alapú volt, de a nemesi nemzetfelfogás számos elemével (történelmi múlt, nemzeti erények, nemzeti viselet és szokások) kibővült. A reformok jegyében a nemesség fog síkra szállni, mert gyenge a polgárság. A reformok fórumai a reformországgyűlések: 1825-27, 1830, 1832-36., 1839-40, 1844, 1848.\n\nA magyar nyelv ügye: a latin helyett a magyar legyen a hivatalos nyelv. A reformkorban a reformtábor követelései közül egyedül a magyar nyelv ügye oldódott meg teljes mértékben. Ez alapvetően annak köszönhető, hogy a nyelvkérdésben a magyar politikai élet minden irányzata egységes állásponton volt.\n\n• a hivatalos nyelv a latin volt évszázadok óta;\n\n• a nyelvújítás mozgalma „modernizálni” kezdte a magyar nyelvet;\n\n• a liberális reformmozgalom sikeresen küzdött a magyar államnyelvvé tételéért:\n\n1792: a magyarországi iskolákban tantárgy lett a magyar nyelv.\n\n1805: a feliratok magyar nyelvűek is.\n\n1825: MTA megalapítása.\n\n1830: a Helytartótanács és a bíróságok nyelve a magyar.\n\n1836: törvények nyelve magyar,\n\n1840: a feliratok nyelve és a megyékben,\n\n1844: a magyar lett az államnyelv. A sok részeredmény után Magyarországon a magyar nyelv államnyelvvé vált (1844. évi. II. tc.). A korszakban a hivatalos közélet (országgyűlés, törvények, megyei ügyintézés, bíróságok), valamint a közép- és felsőoktatás nyelvét értették államnyelven.\n\nA politikai nemzet kialakítása:\n\n• Nem etnikai, nyelvi, hanem politikai és jogi alapon szerveződik, az állami léthez kötődik.\n\n• A Magyar Királyságban így csak a magyar és a horvát politikai nemzet létezhet, és ezek keretei között élnek a nemzetiségek.\n\n• Cél: a magyar politikai nemzetbe integrálni a különböző magyarországi nemzetiségeket. A nemzetiségek részesülhetnek az egyéni gazdasági, társadalmi és politikai jogegyenlőségből, de nem kaphatnak közösségi jogokat (autonómia), de hosszútávon a nemzetiségek elmagyarosítása volt a cél, de ez csak a nemzetiségek nemességénél, illetve a zsidóságnál vált nagymértékűvé.\n\nA nemzetiségeknél is jelentkezett a nemzetté válás folyamata:\n\n• megteremtették irodalmi nyelvüket, sajtójukat, kulturális intézményeiket;\n\n• fejlődésük lassúságának okai (kivéve horvátok): magyarokétól rosszabb gazdasági helyzet; hiányos, csonka társadalom; szétszórt területi elhelyezkedés.\n\n• A nemzetiségek a reformkorban kidolgozták politikai programjukat (ruszinokat kivéve): egyenjogúsítás; esetleg független, önálló állam létrehozása.\n\n• A magyarokkal való konfliktus oka a magyar államnyelvvé tétele és az erőszakos magyarosítás (egy politikai nemzet koncepciója).\n\nKossuth és a liberális középnemesség nemzetiségpolitikája:\n\nEgy politikai nemzetben gondolkodott kortársaihoz hasonlóan, s ez a magyar politikai nemzet. Célja: Magyarország függetlensége, nemzetté válása, egyelőre még a Habsburg-birodalom határain belül.\n\nAz 1844-es országgyűlés a magyart tette államnyelvvé a latin helyett. Ezt a nemzetiségek negatívan fogadták. A reformerek a jogkiterjesztést, az érdekegyeztetést faji, nemzetiségi és vallási megkülönböztetés nélkül kívánták megvalósítani, s úgy vélték, ezek megadásával a nemzetiségek is csatlakozni fognak a magyarokhoz.\n\nA nemzetiségeknek azonban ez kevés volt, fenyegetve látták saját nyelvüket, kultúrájukat, ők is önállóak akartak lenni, ez pedig nemzeti ellentétekhez vezetett.\n\nKossuth álláspontja: a magánéletben mindenki használhatja saját nyelvét, de „a közigazgatásnak minden ága, valamint a hivatalos közlekedési nyelv a magyar kormánnyal és a törvényhatóságokkal a magyar korona birtokainak bármely részéből magyar legyen. Ennél kevesebbet tenni gyávaság, többet parancsolni zsarnokság, mi reánk nézve mondhatni öngyilkolás volna”.\n\nKossuth és hívei nem tagadták, hogy a békés rábeszélő eszközökkel folytatott magyarosítást lehetségesnek ítélik, csak azt a vádat utasították vissza, mintha erőszakos eszközökkel akarnának fellépni a más nyelvűekkel szemben.\n\nNemzetiségek a reformkorban és 1848-ban\n\nElőzmény: a török kiűzése után a XVIII. században Magyarországon a bevándorlás és szervezett telepítés útján megindult az ország benépesítése, így a magyarság elvesztette számbeli fölényét. A reformkorban a magyar etnikum az összlakosság 40 százaléka volt. A legnagyobb lélekszámú nemzetiség a román volt, amely Erdélyben és a Magyar Királyság keleti részén helyezkedett el. A horvátok a Dráván túli területen, a szerbek Dél-Magyarországon, a szlovákok északon és elszórtan az Alföldön éltek. A betelepített németek (svábok) és a már régebb óta itt lakó szászok kisebb tömböket alkottak a Szepességben és Erdélyben, valamint Dél-Magyarország falvaiban, illetve számos városban már a középkor óta laktak (szászok).\n\nA társadalmi szerkezetükre jellemző volt, hogy a horvátok kivételével hiányzott a nemzetiségi uralkodó osztály, a földesurak általában magyarok voltak. A jobbágy-földesúr szembenállás ezért nemzetiségi ellentét formáját is öltötte.\n\nA nemzetiségi kérdés különös élességgel akkor jelentkezett, amikor megkezdődött a magyar nyelv hivatalos használatáért folytatott harc. A nemzetiségek a maguk társadalmi és politikai fejlődése során éppúgy eljutottak a nacionalizmushoz, mint a magyarok. A nemzeti fejlődés a nemzetiségeknél is nyelvi, irodalmi síkon jelentkezett. A kibontakozó mozgalmak vezetői papok, kereskedő polgárok, népi és polgári származású értelmiségiek voltak.\n\nA nemzetiségek közül csak a horvátoknak voltak jogaik. Tartományi önállósággal rendelkeztek, s államnyelvük továbbra is a latin maradt. A horvát nagybirtokosok Ljudevit Gaj köré tömörülve egy horvát vezetéssel megvalósítandó délszláv egység gondolatát vetették fel.\n\nTemes megyében a szerbek Habsburg-orientációja megerősödött.\n\nA szlovák mozgalmak központjai a felvidéki evangélikus líceumok nyelvművelő és irodalmi körei voltak.\n\nA román nemzeti törekvések már a XVIII. században megfogalmazódtak. Egyházi és világi értelmiségiek álltak e mozgalom élére, támaszkodva az ortodox egyházi szervezetekre. Sajtójuk kapcsolatot keresett a horvát és szlovák mozgalmakkal.\n\nA magyar nemesség az országot - történeti egységét megtartva - saját vezetése alatt szerette volna átalakítani. A magyar reformmozgalom a nemzeti nyelvért küzdve a magyarosítást is célul tűzte ki. Ez a törekvés tovább élezte az ellentéteket. A nemzetiségi vezetők hamar felfedezték szövetségesként a bécsi kormányzatot. Kossuth és az ellenzék tartott attól, hogy a magyarországi nemzetiségi mozgalmak nemcsak Ausztria, hanem még inkább Oroszország eszközévé válhatnak.\n\n1848-ban a nemzetiségi mozgalmak mindinkább politikai síkra terelődtek. Az 1848-as márciusi forradalom eleinte kedvező visszhangot keltett a nemzetiségek körében, főleg a jobbágyfelszabadítást illetően. A forradalom nemzetiségi különbség nélkül mindenkinek egyénileg megadta az új polgári jogokat. Rövidesen fölmerült a kollektív elismertetés és a nemzetségi politikai jogok igénye.\n\nA konfliktus először Horvátországgal éleződött ki. Márciusban a bécsi és pesti forradalom hatására nemzeti bizottság alakult Zágrábban. Jelacic (magyaros helyesírással: Jellasics) bán a horvát nacionalizmus szeparatista (elszakadni kívánó) törekvéseit pártolta. A bécsi ellenforradalom igyekezett saját érdekeinek szolgálatába állítani. Jelacic már az év tavaszán megkezdte a fegyverkezést Latour osztrák hadügyminiszter segítségével. V. Ferdinánd törvénytelennek bélyegezte az eljárást, de később megváltoztatta véleményét.\n\nA szerbek - hivatkozva I. Lipóttól kapott kiváltságaikra - külön szerb vajdaság területi leválasztását követelték. A szerb mozgalom Bécsből és Belgrádból kapott támogatást. A karlócai gyűlés kimondta a magyarországi szerbek teljes politikai önállóságát. Felkelést szerveztek, amely 1848 nyarán ki is tört.\n\nA szlovák nemzeti mozgalmat is értelmiségi réteg képviselte. A liptószentmiklósi gyűlésen területi önkormányzatot követeltek. Az értelmiség vezetői a cseh mozgalomra támaszkodtak. (Palacky cseh történész a Felvidéket Csehországhoz kívánta csatolni.)\n\nA német etnikum nem lépett fel külön nemzeti követelésekkel. Egyedül az erdélyi szászok sérelmezték, hogy régi előjogaik a polgári államban nem érvényesülnek.\n\nAz erdélyi románok a balázsfalvi gyűlésen nem ismerték el Magyarország és Erdély unióját. A románok is fegyvert fogtak, és Erdély véres harcok színtere lett. A havasalföldi román liberálisok közül Bálcescu a magyarokhoz kívánt közeledni.\n\n1849. márciusában az olmützi alkotmány elvben nemzeti egyenjogúságot ígért a Habsburg Birodalmon belül, Debrecenben az ifjú radikálisok is felvetették, hogy Magyarországon a föderatív államszerkezet bevezetésére lenne szükség. Teleki László - felismerve a hasonlóságot Ausztriával és Lengyelországgal: a soknemzetiségű jelleget - szintén javasolta a föderatív államberendezkedést. A kormány a maga eszközeivel igyekezett a nemzetiségi konfliktusokból a tanulságokat levonni és a tárgyalásokat elősegíteni. 1849. július 14-én írta alá Kossuth és Bálcescu a magyar-román megbékélési tervezetet. Július 16-án egyezség jött létre a szerb felkelőkkel, majd július 28-án a Szegedre átköltözött országgyűlésen elfogadták a régóta esedékes nemzetiségi törvényt. Ez a törvény mindenkinek megadta a jogot arra, hogy a hatóságok előtt saját nyelvét használja. A helyi közigazgatás nyelvét a többség választhatta meg. Biztosította a nemzetiségi nyelvek használatát az iskolákban is. A törvény önmagában is jelentős, jóllehet alkalmazására már nem kerülhetett sor. 1848-ban Bécs szövetkezett a nemzetiségi mozgalmakkal a legerősebb nemzet, a magyar ellen. 1849-et követően a nemzetiségek azt kapták jutalmul, amit a magyarok büntetésül. 1867-ben Bécs kiegyezett a legerősebb nemzettel, a magyarral. A magyar parlament 1868-ban újabb nemzetiségi törvényt alkotott, amely bár liberális jellegű volt, de a nemzetiségieket már nem elégítette ki. Ezt felismerve ezért is ellenezte Kossuth a kiegyezést. A kütahyai alkotmánytervében és a Dunai konföderációs tervében a nemzetiségekkel való együttműködés tervét dolgozza ki egy föderációs államban.\n\nNemzetiségek és etnikumok a dualizmus korában\n\nMagyarország az Osztrák–Magyar Monarchia része, a dualizmus időszaka 1867 és 1918 közötti időszakot jelenti.\n\nA kiegyezés előzményei a nemzetiségi kérdés szempontjából:\n\n- Az 1848-49-es szabadságharc idején a nemzetiségek vezető rétege szinte mindenütt szembefordult a magyar kormánnyal. Az udvar ígéretei alapján nemzeti céljaikat a dinasztia oldalán látták biztosítottnak. A császári kormányzat azonban - miután a hatalmát visszanyerte - az ígéretei jelentős részét nem tartotta be. Az 1849-es olmützi alkotmány értelmében nem alakíthattak önálló tartományokat, de még autonómiát sem kaptak. S ahol ez mégis létrejött, mint a szerbeknél (Szerb Vajdaság és Temesi Bánság), ott is a bécsi kormányzat tartotta kézben a hatalmat.\n\n- 1849 után, az újabszolutizmus idején magyarokat és a nemzetiségieket egyaránt elnyomták. Az ismert értékelés, miszerint „a nemzetiségek azt kapták jutalmul, amit a magyarok büntetésül\", azonban félrevezető. A magyarországi nemzetiségek helyzete saját nemzeti szempontjukból 1849 után kedvezőbbé vált. Egyrészt megszabadultak a számukra veszélyes magyar nemzetállami törekvésektől. Másrészt az újabszolutizmus jelentős pozíciókat juttatott nekik a korábban a magyar nemesség által kézben tartott közigazgatásban. Ezáltal felgyorsult a szabadságharc során megindult folyamat, a nemzeti öntudat kiteljesedése a nemzetiségi tömegek körében is, ami tovább növelte a nemzetiségi vezetők befolyását és erejét. Az önkényuralom alatti közös elnyomás, az udvar be nem váltott ígéretei mindkét félben a közeledési szándékot erősítették meg. A közeledési kísérletek azonban kimerültek baráti hangú újságcikkekben, összejövetelekben. Hiányoztak a tényleges és kölcsönös engedmények. A magyar fél továbbra is az egységes nemzetállam alapján állt, de a megerősödő nemzetiségi vezetők sem mérsékelték önállósági igényeiket.\n\n- Hogy mennyire bizonyult komolynak a két fél közeledése, az az 1861-és országgyűlésen derült ki, amikor lehetőség volt az álláspontok kifejtésére. Az országgyűlési választásokat megelőzően a nemzetiségek gyűléseket tarthattak, ahol a szlovákok és a szerbek területi autonómiát követeltek, míg a románok elutasították Erdély és Magyarország unióját. Az országgyűlés a kérdés rendezésére Eötvös József vezetésével bizottságot állított fel, mely széles nyelvhasználati joggal kívánta orvosolni a problémát. A vita során nyilvánvalóvá vált, hogy az álláspontok lényegesen nem közeledtek. A nemzetiségek nem mondtak le a területi autonómiáról, a magyarok pedig az egységes nemzetállam koncepciójáról.\n\n- Kossuth Lajos Duna-konföderációs terve: a szabadságharc bukásának okait és az újrakezdés lehetőségeit keresve tervezetet készített a nemzetiségi kérdés megoldására. Elgondolása az egész térséget érintette, hiszen a Duna menti népek államszövetségét akarta létrehozni (Dunai konföderáció), de rendezni kívánta a magyarországi nemzetiségek helyzetét is. Kossuth az uralkodó magyar állásponthoz képest jelentős engedményeket tett. Elismerte Horvátország önállóságát, Erdély önállóságának eldöntésére pedig népszavazást javasolt. A szélesebb területi autonómia helyett a nemzetiségek számára lehetővé kívánta tenni a területtől független politikai és kulturális önkormányzati testületek megalakítását.\n\nKossuth Lajos dunai konföderációs tervében összefogásra hívta fel Közép-Európa kis nemzeteit (a horvátot, a románt, a szerbet és a magyart) a német és orosz hatalommal szemben. A terv szerint a konföderáció államai szuverének és önállóak lettek volna, de közös hadüggyel, külüggyel, kereskedelemmel és közös gazdasággal\n\nA nemzetiségek azonban a szövetség létrehozásában is a magyar fölény fenntartásának szándékát látták, így ez az elképzelés nem valósulhatott meg. Ha önállóságukat feladták volna, akkor azt inkább a Habsburgok javára tették volna meg.\n\n- A magyar vezető réteg nagy többsége elutasította a tervezetet, mivel az gátolta volna a magyar nemzetállam kialakítását, illetve a magyar és a nemzetiségi vezetők hatalomban való megosztozását eredményezte volna. A nemzetiségek vezetői is kevesellték engedményeket.\n\nKossuth elgondolásának ennek ellenére jelentős politikai hatása volt. Szándékaival ellentétesen a tervezet tudatosította a magyar vezető rétegben, hogy a független magyar nemzetállam vagy a dinasztiával és Ausztriával való kiegyezés a valós alternatíva. A szomszéd népekkel és államokkal vagy az Ausztriával való szövetkezés között kell választani.\n\n- A nemzetiségekkel vagy a birodalommal való kiegyezés alternatívája az erdélyi országgyűlés összehívásakor vált egyértelművé 1863-ban. Schmerling, hogy a magyarokat megszorítsa, megváltoztatta az 1848-as választási törvényeket. Leszállította a cenzust, hogy a románság érvényesíthesse számbeli fölényét. A magyar képviselők törvénytelennek nyilvánították és bojkottálták az erdélyi országgyűlést, azonban a szászok és a románok részvételével az erdélyi törvényhozás elküldte képviselőit a birodalmi gyűlésbe, s törvénybe iktatta a románok politikai és vallási egyenjogúságát.\n\nAZ 1868-AS NEMZETISÉGI TÖRVÉNY\n\nAz 1867-as kiegyezést több szempontból reális kompromisszumként lehet értékelni; tény azonban, hogy azt a birodalom két legerősebb, de szám szerint kisebbségben lévő nemzeteként az osztrák-német és a magyar kötötte meg kizárva a megegyezésből a többi nemzetiséget.\n\nA kiegyezés 1867-es megkötésével a magyar vezető réteg folytathatta nemzetállam kiépítését. A nemzetiségek helyzetét külön törvényben szabályozták: nemzetiségi törvény (1868:XLIV. tc.). A törvényt előkészítő országgyűlési bizottság az egy politikai nemzet koncepcióján állva elutasította a területi autonómiát és a nemzetiségek kollektív jogait. A törvényt előterjesztő Eötvös József vallás- és közoktatásügyi miniszter azonban - Deák támogatásával meg tudta védeni az országgyűlés növekvő ellenállásával szemben az egyéni szabadságok alapján álló nemzetiségi jogokat. Mindenekelőtt a széles körű anyanyelvhasználatot. A vegyes lakosságú vidékeken a 20%-ot elérő kisebbségek számára a törvényóságokban biztosították az anyanyelv használatát. Az alsó- és középfokú bíróságokon anyanyelvükön képviselhették ügyüket a nemzetiségi állampolgárok. Alsó- és középfokon engedélyezték a nemzetiségi iskolahálózatot, sőt annak fenntartását az állam kötelességévé tették. A polgári egyesülési jog alapján lehetőség nyílt nemzetiségi egyesületek és pénzalapok létrehozására, amennyiben azok nem a magyar államegység megbontásán munkálkodtak. A nemzetiségi törvény lehetővé tette az anyanyelv széleskörű használatát, és az iskolatörvény is csupán a magyar mint tantárgy oktatását írta elő. A nemzetiségi iskolák száma csökkent, ill. a magyarok aránya országosan nőtt, és dualizmus időszaka alatt a hatalom az oktatáson keresztül igyekezett az asszimilációt biztosítani. Magyarország soknemzetiségű állam volt, a politikai elit ennek ellenére ragaszkodott az egy politikai nemzet fikciójához. A nemzetiségi törvény kortárs európai mércével nézve liberális volt, de a nemzetiségiek tiltakozását a törvény be nem tartása váltotta ki. A törvény oktatásra vonatkozó előírásai kevéssé érvényesültek. Az állam az asszimiláció során ért el ugyan sikereket, ugyanakkor a nemzetiségieket maga ellen fordította.\n\nAz 1868 után az iskolaköteles korosztályokban (6-12 év) lényegében megvalósult az oktatás reformja, de a nemzetiségi törvény szerinti anyanyelvi oktatás elve nem érvényesül maradéktalanul. Az anyanyelven folyó oktatáshoz való jogot a nemzetiségi törvény tartalmazta a nemzeti kisebbségek számára. A dualizmus kori asszimilációs törekvések a magyar nyelvűség oktatásban való kiterjesztésével próbálkoztak.\n\nAz 1868-as törvény tehát nem elégítette ki a nemzetiségeket, ugyanakkor nemzetközi összehasonlításban megállja a helyét: a nemzetállamok korában szabadelvűsége egyértelmű a nyugat-európai, és még inkább a kelet-európai megoldásokhoz képest.\n\nÉrtékelése: az Eötvös József nevéhez fűződő 1868-as Nemzetiségi törvény a kor követelményeihez képest is egyedülállóan liberális módon szabályozta a nemzetiségi jogokat. Az államnyelv a magyar volt, de a nemzetiségek az alsó fokú oktatásban, a közigazgatásban és az igazságszolgáltatásban anyanyelvüket használhatták. Mindezek a községi, városi és megyei életben valósultak meg, de nemzetiségi nyelven lehetett beadvánnyal fordulni a törvénykezés szerveihez és a minisztériumokhoz is. A kollektív jogokat azonban, amelyek lényegében autonóm területek szervezését jelentették volna, nem biztosította.\n\nA HORVÁT-MAGYAR KIEGYEZÉS (1868)\n\nA magyar közjog az ország nemzetiségei közül egyedül a horvátot ismerte el politikai nemzetnek. A polgári állam keretei között is meghagyták a tartomány területi autonómiáját (1868:XLII. tc.). A horvát autonómia széles körűnek mondható. Horvátországot egyesítették Szlavóniával és a Határőrvidékkel. Az így létrejött Horvátország saját országgyűléssel rendelkezett, mely képviselőket küldött a magyar országgyűlésbe. A horvát országgyűlés és kormány nyelve a horvát lett.\n\nA horvát-magyar kiegyezésről szóló 1868. évi XXX. törvény szerint a két ország „egy és ugyanazon állami közösséget képez\", továbbá Horvátország „külön területtel bíró nemzet, amely belügyeire nézve saját törvényhozással és kormányzással bír\" (emellett pl. külön oktatásüggyel is). A Monarchia csehekkel való kiegyezése viszont elmaradt, ami az I. világháború során súlyos következményekkel járt.\n\nA végrehajtó hatalom élén a magyar miniszterelnök javaslatára az uralkodó által kinevezett bán állt. A horvát kormány hatáskörébe tartozott a teljes közigazgatás, az igazságügy és az oktatásügy. Bár a horvát-magyar kiegyezést számos nép (pl. írek) példának tekintették, a horvát vezető réteg a Habsburg Birodalmon belüli teljes különállásra törekedett. A kiegyezési törvényt a horvát országgyűléssel csak többszöri próbálkozás után, jelentős magyar gazdasági és pénzügyi támogatások fejében sikerült elfogadtatni.\n\nAz ellentéteket Fiume kérdése is kiélezte. Az olasz kikötőváros Mária Terézia óta Magyarországhoz tartozott, de a horvátok is igényt tartottak rá. Miután a magyar kormány fontosnak tartotta a tengeri kikötő biztosítását, a kérdésben nem tudtak megegyezni. A város magyar igazgatás alá került, hivatalos nyelve pedig az olasz lett.\n\nNépek a dualizmus korában\n\nA németség kivételével a nemzetiségek főleg az agráriumból élő parasztsághoz tartoztak. Ez főleg történeti okokra vezethető vissza (csonka társadalmak). A németség kivételével a városlakó nemzetiségiek aránya jóval kisebb az össznépességben elfoglalt számarányuknál. Az urbanizáció a nemzetiségi beköltözők nagyarányú asszimilációjával járt. A németek kivételével jelentős a nemzetiségek alfabetizációs lemaradása, ebben a történetileg kialakult öröklöttség mellett szerepe van a hazai oktatáspolitikának is. A román, szerb és szlovák nemzetiségi mozgalmak elutasították a dualizmus kialakult rendszerét és a nemzetiségi törvényt. Nyelvi, önkormányzati, iskoláztatási törekvéseikkel szembekerültek a magyar kormánypolitikával, de nagyobb önállóságuk keretéül az első világháborúig elfogadták a Monarchiát.\n\nA magyar politikai elit az „egy politikai nemzet” elvét vallotta. A nemzetiségi kérdés 1868-as rendezése kizárta a belső autonómia lehetőségét (kivétel: horvát kiegyezés). A dualizmus kori ország alapjában a polgári nemzetállamok elvén (a liberalizmus elvei szerint) működött. A nemzetiségek az 1868-as nemzetiségi törvény alapján széles körű nyelvhasználattal élhettek, politikai pártokat, egyleteket szabadon alapíthattak. Negatívumok: az asszimiláció és a nemzetiségi kivándorlás. A nemzetiségek politikai törekvéseiben a nacionalizmus jelentős szerepet játszott. A századfordulón gazdaságilag is megerősödő nemzetiségek politikai törekvései a külföld rokonszenvétől kísérve az önkormányzatiság elérésére irányultak, de a magyar politika nem talált erre megfelelő választ.\n\nAz Osztrák-Magyar Monarchiában mind az osztrák-németek, mind a magyarok csupán relatív többséget alkottak, tehát a birodalom összlakosságán belül kisebbségben maradtak; így a nemzetiségi kérdés továbbra is megoldásra várt. Az osztrák törvényhozás az egyenjogúság elvéből kiindulva deklarálta, hogy az állam minden népének egyenlő és elidegeníthetetlen joga az egyes népcsoportok nemzetiségének és nyelvének ápolása és megtartása. Az államnemzet felfogásával szemben e nemzetek így un. kultúrnemzetet alkothattak. Ezek szerint, ha vannak kulturális intézményeik, de nincs autonóm területük önálló adminisztratív intézményekkel, akkor saját kultúrájában élő nemzetként, a közös nyelv, az összetartozás tudatával alkothatták a birodalom részét. Tartományi szinten így törhették át a szabad nyelvhasználat korlátait.\n\nA magyar országgyűlés az állam egységét tartotta legfontosabbnak, az 1868-as nemzetiségi törvény pedig ki is mondta az „egy politikai nemzet\" létrehozásának szándékát, ennek alapján nem férhetett bele a törvénybe a nemzetiségi nyelvű felsőoktatás. Amíg Magyarországon a horvátok önállósága okozott problémákat, addig a Lajtán túl az osztrák-cseh konfliktus eredményezett küzdelmeket. Bécs támogatta a csehek kulturális és nyelvi törekvéseit - kárpótlásul, hiszen a cseheket nem ismerték el harmadik nemzetként. Az osztrák kormányzat azonban a csehországi németek ellenállásába ütközött, akik az anyanyelvű oktatásért folytattak harcot (hiszen a korban a cseh városok nagy része német többségű volt).\n\nAz I. világháborúig a monarchia nemzetiségei közül egyedül az olaszok kívántak elszakadni és hazájukhoz csatlakozni. Ezzel szemben a többi nemzetiség a birodalmon belüli autonómia elérésére törekedett (pl. a galíciai lengyelek, akik önkormányzatot is kaptak).\n\nNemzetiségi kérdés a XX. század elején\n\nA magyarok többsége érzelmileg mindig is szemben állt a kiegyezéssel, ezért a politika és az értelmiség választás elé került. Az ellenzék a függetlenség célzatával a kiegyezés módosítását kívánta, így a magyar kormányzat a nemzetiségellenes nacionalizmus politikájával igyekezett leszerelni az ellenzéket. Ez azt is jelentette, hogy egyre többen kívánták a birodalmon belüli magyar hegemónia megvalósítását; ez az igény azonban hasonló bomlasztó tényezővé vált a Monarchia létét illetően, mint az ellenzék tevékenysége.\n\nA nemzetiségi kérdés ugyanakkor szorosan összekapcsolódott a demokratikus jogok kiterjesztésével. Ausztriában 1907-ben általános választójogot vezettek be - a magyar politikusok ettől elzárkóztak. A nemzetiségi ellentétek egyik oldalon sem enyhültek, köszönhetően annak, hogy Magyarország eltávolodott az 1868-as nemzetiségi törvény liberalizálásától.\n\nA XIX. és a XX. század fordulójára erőteljessé vált a nemzetiségi származásúak önkéntes magyarrá válása - ehhez hozzájárult a magyarosítási politika is. Ennek ellenére az 1900-as népszámláláskor az ország összlakosságának csak 60%-a tudott magyarul. Az 1907-es Lex Apponyi bevezetésével az alsó fokú oktatásban magyart tanítottak és magyar tanárok igyekeztek kinevelni a gyerekekből a nemzetiségi tudatot - sikertelenül.\n\nA dualista rendszerrel nem csak országunkban, hanem a Lajtán túl élők is elégedetlenek voltak. A nemzetiségi kérdés tisztázatlansága csak tovább fokozta a századelőn már kibontakozott feszültséget, amely végül a Monarchián belüli politikai válsághoz vezetett. E tényező szintén kiemelt szerephez jutott akkor, amikor az I. világháborút követően felbomlott az Osztrák-Magyar Monarchia, és Magyarország területének kétharmadát azok a nemzetiségek kapták a trianoni békeszerződés folyományaként, amelyek már a dualizmus idején elég erősek voltak ahhoz, hogy ellen tudjanak állni a magyar politika erőszakos asszimilációs törekvéseinek.\n\nDEMOGRÁFIAI ROBBANÁS ÉS KIVÁNDORLÁS\n\nA demográfiai robbanás az 1880-as években bontakozott ki Magyarországon. Eredményeként az első világháborúig (1914) az ország népessége néhány évtized alatt a harmadával emelkedett (Horvátország nélkül - a nagymértékű kivándorlás ellenére - meghaladta a 18 millió főt). A folyamat hazánkban is a jobb életkörülményeknek, a higiéniai és az egészségügyi viszonyok javulásának volt köszönhető.\n\nMiután a fejlődés eltérő mértékű volt az ország egyes területein, a népességnövekedés is jórészt a fejlettebb vidékeken jelentkezett, és később érte el az elmaradott régiókat. A korszak demográfiai változásairól már pontos statisztikai adatokkal rendelkezünk, mivel a kiépülő polgári állam a kiegyezést követően rendszeresen átfogó népszámlálásokat tartott (1880-tól tízévente).\n\nA falvak nem tudták eltartani növekvő lakosságukat, ezért innét egyre többen költöztek el. A belső vándorlás (belső migráció) a városok, s különösen Budapest felé irányult. Azonban a városok - Nyugat-Európához hasonlóan - nem tudták befogadni a hirtelen megnövekvő népességet. Emiatt az 1890-es évektől Magyarország is bekapcsolódott a nagy európai kivándorlási hullámba (közel másfél millió ember hagyta el az országot). A fő célpontot az Amerikai Egyesült Államok jelentette. A legtöbben a növekvő népességű, de kedvezőtlen mezőgazdasági adottságokkal rendelkező területekről vándoroltak ki (Felvidék, Kárpátalja).\n\nA kivándorlási veszteséget részben enyhítette a bevándorlás. A birodalom nyugati tartományaiból közel százezer német és cseh szakmunkás érkezett, akiket a fejlődő ipar munkaerő-szükséglete vonzott az országba. A korszak folyamán keletről, Galíciából több százezer zsidó vándorolt be az üldöztetések elől a befogadó és megfelelő életlehetőséget biztosító Magyarországra.\n\nA MAGYARSÁG ARÁNYÁNAK NÖVEKEDÉSE\n\nA XIX. század második felében megállt a magyarság számarányának csökkenése, s ezután a magyarok aránya a népességen belül fokozatosan gyorsuló ütemben emelkedett (Horvátország nélkül 41%-ról 54,5%-ra). A folyamatnak három forrása volt: a népszaporulat, a ki- és bevándorlás és az asszimiláció. A demográfiai robbanás a fejlettebb területeket érintette, ahol a magyarság zöme is lakott. így a magyar népesség nagyobb arányban részesedett a növekedésből. A kivándorlásban pedig a magyarság kisebb mértékben vett részt, mint az ország nemzetiségei. Minden száz kivándorlóból csak kb. 33 volt magyar. Ennek hátterében az áll, hogy főként a hegyvidéki lakosság (pl. a szlovákok és a ruszinok) megélhetését nem biztosították földjeik.\n\nA XIX. századi bevándorlás résztvevői - a XVIII. századival ellentétben - nem egy tömbben telepedtek le, s jórészt városlakók voltak. A szülőhelyüket (nemzeti, egyházi és családi közegüket) elhagyó emberek az idegen környezetben egy-két nemzedék alatt természetes módon beolvadtak (asszimilálódtak) a többségi (magyar) környezetbe. A asszimiláció fő színtere a főváros volt. Az ide érkezők a világvárosban magyarrá váltak, ugyanakkor értékeik átmentésével gazdagították a város kultúráját, így olvadtak be a hegyekből a fővárosba érkező szlovákok és ruszinok. Városaink német lakossága a korszakban szintén asszimilálódott. Az asszimiláció azonban főként a vegyes népességű vidékeket és a városokat érintette, a nagy nemzetiségi tömbök jórészt érintetlenek maradtak, így a korszak etnikai változásai döntően a számarányokban és nem az ország népeinek területi elhelyezkedésében mutatkoztak meg.\n\nA MAGYAROK ÉS A NEMZETISÉGEK\n\nA magyar vezető réteg a nemzetállam kiépítését tűzte ki célul, s ennek érdekében szorgalmazta a nemzetiségek asszimilációját. Ugyanakkor a korszakban még csak kiépülőben volt az erős állam, emiatt lehetőségeik korlátozottak voltak. A társadalom alsóbb rétegei - az emberek többsége - alig került kapcsolatba az államszervezettel, így az erőszakos asszimiláció csak az értelmiséget érintette, amennyiben állami hivatalokat kívánt megszerezni. Az asszimiláció gyorsítására leginkább az oktatás terén nyílt mód. Elemi szinten itt sem lehetett sokat elérni, mert a javarészt egyházi fenntartású iskolákban a diákok alig találkoztak a magyar nyelvvel és kultúrával. A dualista kormányok nem hajtották végre az 1868-as nemzetiségi törvény számos rendelkezését. Fokozatosan bevezették a magyar nyelv tanítását a nemzetiségi iskolákban (1879, 1907), visszaszorították a nemzetiségi középiskolákat és megakadályozták a nemzetiségek világi felsőoktatási intézményrendszerének a kialakulását. A nemzetiségek azonban az oktatás és a kultúra területén is szembefordultak az állami törekvésekkel.\n\nA magyar politika a nemzetiségi kérdés megoldódását a felgyorsuló asszimilációtól várta. Csak néhányan - és jelentősebb hatás nélkül - emeltek szót az 1868-as törvények védelmében (pl. Mocsáry Lajos országgyűlési képviselő). Más politikusaink erőteljesebb fellépést sürgettek a nemzetiségekkel szemben.\n\nA nemzetiségek vezető rétegei a kiegyezéssel és a nemzetiségi törvénnyel szemben passzív ellenállást tanúsítottak, majd folyamatosan tiltakoztak a törvény megsértései ellen. Közvetlen célként a megyei szintű területi autonómia kiépítését tűzték ki. A XX. század elején azonban már a Monarchia föderatív (szövetségi) átalakításáért szálltak síkra. Egyes magyarországi nemzetiségek politikáját befolyásolta, hogy nekik is voltak - Magyarországgal határos - nemzetállamaik (Szerbia, Románia). Ezek hatására megjelentek az elszakadási törekvések is. A magyar és a nemzetiségi vezető réteg így a korszak bán nem talált közös nevezőt, a nemzetiségi kérdés egyre inkább elmérgesedett.\n\nAz 1890-es évektől az ellentétek kiéleződtek. Hangosabbá vált a határos nemzetállamok propagandája (irredentizmus). A gazdasági fejlődés miatt megerősödött a nemzetiségi polgárság és az értelmiség, másrészt a még mindig jórészt paraszti társadalmakat mozgósította az agrárkérdés (a kisbirtokosok és földnélküliek nagy aránya, munkalehetőségek hiánya stb.).\n\nA ZSIDÓ EMANCIPÁCIÓ\n\nA zsidó (izraelita vallású) magyar állampolgárokat a kiegyezés idején a törvények egyenjogúsították. A magyar társadalom továbbra is nyitott és befogadó maradt a zsidóság iránt, így a század végén (1895) sor került az izraelita vallás egyenjogúsítására is. A korszakban a népszaporulat és a nagyarányú bevándorlás révén a zsidóság lélekszáma rohamosan növekedett. Zömük asszimilálódott, és azonosult a magyar nemzeteszmével és kultúrával. A zsidóság tömegei a kiskereskedelemből és a kisiparból éltek, de közülük került ki a magyar nagypolgárok döntő többsége is. Mivel olyan foglalkozásokban találtak megélhetést, melyek felé a magyar társadalom kevésbé törekedett, nem jelentkezett komolyabb konkurenciaharc. A bevándorló és gyorsan polgárosodó zsidó családok gyermekei a dualizmus időszakában nagy számban jelentek meg bizonyos értelmiségi pályákon (újságíró, színész, orvos, ügyvéd). Az egyetemeken a zsidó hallgatók aránya ötszöröse volt országos számarányuknak.\n\nA zsidóság azonosult a magyar nemzeteszmével, így kiegyensúlyozott viszony jött létre a zsidóság és a társadalom többi csoportja között. A nagyvárosokban - sokszor a városok főterein - sorra épültek az impozáns zsinagógák. Az antiszemitizmus (zsidógyűlölet) a korszak Európájához képest kisebb mértékben, de jelen volt a magyarországi társadalomban is. Elsősorban a városi kispolgári rétegeket jellemezte, akik számára a zsidó bevándorlók versenytársat jelentettek. A kormányzat azonban visszaszorította az antiszemita megnyilvánulásokat, mint a tiszaeszlári per során is történt (1882). Tiszaeszláron egy cselédlány eltűnése okán - néhány antiszemita izgatására - a helyi zsidó közösség ellen fordult a község. Az elszabaduló indulatokat a kormány, személyesen Tisza Kálmán fellépése csillapította le. A lefolytatott per nem igazolta a vádat (hogy a zsidók vallási okokból ölték meg a lányt), s a politikai életből rövidesen mind a kormánypárt, mind az ellenzék kiszorította az antiszemita politikusokat. A magyar szabadelvű politika antiszemitizmussal kapcsolatos álláspontjának az ad jelentőséget, hogy Franciaországban például a Dreyfus-perre a tiszaeszlári per után egy évtizeddel kerül sor.\n\nA CIGÁNYSÁG HELYZETE A DUALIZMUS KORÁBAN\n\nA dualizmus korában a népszámlálások ellenére nehéz meghatározni a cigányság számát, mivel a kérdőívek inkább az anyanyelvre kérdeztek rá. Becsült lélekszámuk háromszázezer körül lehetett. Miután körükben a demográfiai robbanás még nem bontakozott ki, a cigány népesség a Románia felől történő bevándorlás révén növekedett. Fejlődést jelentett, hogy a korszakban a vándorló közösségek száma csökkent, s terjedt a letelepedett életvitel. A foglalkozással bírók közül a legtöbben (60%) iparosok voltak (pl. kovács), de sokan éltek alkalmi munkákból, lókereskedelemből is. A kormányzat próbálta segíteni felzárkózásukat.\n\nETNIKAI VÁLTOZÁSOK TRIANON UTÁN\n\nTRIANON!!!!!\n\nAz 1914-1918 között zajló 1. világháborúban az Osztrák – Magyar Monarchia Németország oldalán harcolt, mint központi hatalom. Az 1916-ban hatalomra lépő IV. Károly reformkísérletei nem találtak széles táborra a Monarchia, illetve Magyarország nemzetiségei körében. A csehek, szerbek, románok ekkor (1917-18) már az önálló nemzetállam megteremtésén dolgoztak. Diplomáciai és katonai céljuk az volt, hogy minél nagyobb területet szerezzenek meg a széteső Monarchiából.\n\n1918. április: a római kongresszuson az antant elismerte a csehek és a románok területi igényeit. Az antanthatalmak hadviselő félnek ismerték el Csehszlovákia Nemzeti Tanácsát (vezetője Tomas Masaryk) és a Román Egység Nemzeti Tanácsát (vezetője Octavian Goga).\n\nA Monarchián belül - főleg Magyarországon - a nemzetiségi határok igen nehezen vagy egyáltalán nem húzhatók meg. Már 1918 elején nyilvánvalóvá vált, hogy a Monarchia széthullása esetén az országhatárokat nem a történelmi, kulturális múlt és a reális etnikai viszonyok, hanem az antant pillanatnyi politikai érdeke fogja meghatározni.\n\nA háború végén, 1918-ban felbomlott a Monarchia. Magyarország a vesztes országok közé tartozott. 1918-ban az őszirózsás forradalom, 1919-ben a tanácsköztársaság kikiáltása, majd a fehérterror időszaka alatt nem volt olyan kormány, amelyet a győztes antant hatalmak elfogadtak volna, hogy békét kössenek velünk. Csak 1920-ban jött létre az antant által is elfogadható törvényes kormány, s ezt követően kötöttek Magyarországgal békét 1920. június 4-én a Párizs melletti Trianoni kastélyban. A magyar békedelegáció gróf Apponyi Albert vezetésével érkezett Párizsba 1920 januárjában. A küldöttség kifejthette álláspontját a békekonferencia előtt, de ez nem befolyásolta a győztesek döntését. A magyar küldöttség visszautasította a béketervezetet. Magyarország területi integritásának szükségességét hangsúlyozták, azt, hogy nem lehet egy ország történelmi, földrajzi, gazdasági és kulturális egységét megbontani. Apponyi az elcsatolandó területeken népszavazásra tett javaslatot. Wilson USA elnök önrendelkezési elvére hivatkozott a békeküldöttség: azaz minden nép maga döntse el, hogy melyik országhoz akar tartozni. Gróf Teleki Pál elkészítette Magyarország „vörös térképét”, amely jelöli, hogy mely területeken laknak többségében magyarok (vörös színnel). Az antant vezetői azonban elsősorban a csehszlovák, román, és jugoszláv követeléseket fogadták el, és a Millerand-levélben elutasították a magyarok kéréseit és tiltakozását: mivel Magyarország vesztes ország, nincs abban a helyzetben, hogy feltételeket diktáljon.\n\nA trianoni béke következményei:\n\nMagyarország területe 283.000 km²-ről 93.000-re csökkent, lakossága 18,2 millióról 7,6-re. A magyarság kb. 1/3-a 3,3 millió fő idegen fennhatóság alá került.\n\nMagyarország elvesztette a Felvidéket, Kárpátalját, Erdélyt, a Partiumot (Részek), Bánátot, Bácskát, Burgenlandot (Őrvidéket).\n\nRomániához kb. 102.000 km² (Erdély és a Részek) és 1,6 millió magyar,\n\nCsehszlovákiához 61.000 km² (Felvidék, Kárpátalja) és 1 millió magyar,\n\nA Szerb-Horvát-Szlovén Királysághoz, a későbbi Jugoszláviához (Bácska, Bánát, Újvidék) 21.000 km² és 0,5 millió magyar,\n\nAusztriához 4.000 km² (Burgenland) és 25.000 magyar. Eredetileg Sopron Ausztriához kerül volna, de a magyar kormánynak sikerült népszavazást elérnie. A lakosság a Magyarországhoz való csatlakozás mellett voksolt, ezért Sopront a „leghűségesebb város” címmel tüntették ki.\n\nA békeszerződést a Simonyi - Semadam Sándor kormány idején írták alá, ezt követően a kormány lemondott. Az aláíró: Drache – Lázár Alfréd és Benárd Ágoston volt.\n\nA békeszerződés következményei a jóvátétel fizetésén kívül a különböző katonai (max. 35.000 fő katona) és kereskedelmi korlátozások voltak. Az etnikai elvet csak a környező népek esetében vették figyelembe, s azzal nem törődtek, hogy több millió magyar került idegen uralom alá. Súlyos gazdasági válságot okozott Magyarországon, hogy a nyersanyagforrások, bányák, vasúthálózat nagy része az országhatáron kívül maradt.\n\nA trianoni békeszerződés példátlan mértékű terület, és népességvesztés volt, ezt a magyarság nem tudta elfogadni és tragédiának fogta fel (Trianon-sokk). A kormányok célja ezután a revízió, azaz a béke felülvizsgálata, a határok visszaállítása volt. A békeszerződés újabb háborúba sodorta emiatt Magyarországot, és ez máig is súlyos nemzetiségi problémák forrása.\n\nEtnikai változások:\n\nMagyarország homogénebb összetételű ország lett, nemzetállammá lett, a nemzetiségek aránya lecsökkent. A magyarok aránya kb. 88%-os.\n\nKb. 400.000 magyar hagyta ott a volt anyaország területét, és költözött a szűkebb Magyarországra: ők a repatriáltak. Megélhetésük azonban bizonytalan volt, vasúti vagonokban laktak. A magyar értelmiségiek foglalkoztatása nehézségekbe ütközött.\n\nAz 1920-as numerus clausus (zárt szám) törvény Teleki Pál miniszterelnöksége idején ezért szabályozza az egyetemekre való bejutást a népfajok és nemzetiségek arányában, mely származási és politikai megkülönböztetést tartalmazott. Ez elsősorban a zsidóságot érintette, de a nemzetiségekre is vonatkozott.\n\nA kb. 10 milliós magyarság 1/3-a az országhatáron kívülre került.\n\nMagyarország abban a sajátos helyzetben található, hogy majdnem az összes szomszéd országban több magyar él, mint ahány más nemzetiségű Magyarországon.\n\nÍgy sokkal több lett a szlovákiai magyar, mint a magyarországi szlovák, és mialatt az erdélyi magyar kisebbség talán az egyik legnagyobb nemzetiség Európában, addig a magyarországi románok viszonylag kis létszámú népességet alkotnak hozzájuk képest.\n\nMAGYARORSZÁGI NÉPMOZGÁSOK 1945 UTÁN\n\nA népmozgások a második világháború végén (1944–45) és az azt követő években zajlottak, a népmozgások egész Közép-Európát érintik. A népmozgás összeurópai jelenség. A népmozgásokra a győztes hatalmak által kinyilvánított kollektív felelősség elvének alkalmazása miatt a háborús vereség következtében került sor. Magyarországon kívül számos országban ment végbe hasonló kitelepítés (pl. Lengyelország, Szovjetunió, Jugoszlávia, Románia. Háborús veszteségek, a zsidóság halála (0,6 millió)\n\nA népmozgások a SZEB (Szövetséges Ellenőrző Bizottság) utasítására történt, és a szomszédos országok magyarellenes nemzetiségi politikája kényszeríttette ki. A magyar politika nem tudott ellene tenni semmit.\n\nA kitelepítések célja a nemzetállamok további etnikai homogenizálása, a nemzeti kisebbségek felszámolása volt.\n\nA magyarországi népmozgások jellemzői:\n\nA kitelepítést a békeszerződések engedélyezték. Európa több más országából is kitelepítettek németeket. A magyarországi németek többségét a nyugati, amerikai megszállási övezetben telepítették le. Magyarországról is kitelepítették a német nemzetiségűeket, velük szemben a kollektív bűnösség elvét alkalmazták, a háborús bűnösséget rájuk hárították. A kitelepített németektől jelentős értékeket koboztak el: a kitelepítetteknek „egy batyuval”, max. 50 kg ingósággal kellett távozniuk. A kitelepített németeknek le kellett mondaniuk ingó és ingatlan vagyonuk jelentős részéről, megfosztották állampolgárságuktól. A kitelepítés így alapvető emberi jogot sértett. A kitelepítés ellenére a második legnagyobb kisebbség maradt a német. A magyarországi népmozgások mértéke: közel félmillió magyar és kétszázezer német. A propaganda szembe állította a svábokat és a magyarokat, uszított a svábok ellen.\n\nMagyarországról a szlovák, míg Csehszlovákiából a magyar nemzetiségűek egy részét a lakosságcsere-egyezmény keretében áttelepítették. Az egyezmény csehszlovák nyomásra született. A Benes-dekrétumok megfosztották a felvidéki magyarságot állampolgárságától. Az áttelepített magyarok száma jóval meghaladta az áttelepített szlovákokét, a felvidéki magyarok nem önként jelentkezhettek, hanem kijelölték őket. A Csehszlovákiából kitelepített magyarok hozhatták ingóságaikat, de a menekültek mindenüket elvesztették.\n\nAz át-, illetve kitelepítések egyéni és családi tragédiákat, illetve jelentős társadalmi problémákat is okoztak. A kitelepítések egyik célja, illetve következménye a javak átcsoportosítása volt. A tulajdonosváltás és szakértelem hiánya miatt gazdasági nehézségek, jogbiztonság hiánya.\n\nMagyarország a kitelepítések következtében tovább homogenizálódott. A szomszéd államokban a kitelepítések ellenére is nagy létszámú magyar kisebbségek maradtak, bár Romániából és Jugoszláviából sok magyar menekült Magyarországra.\n\nA második világháborút lezáró békeszerződések nem biztosították a kisebbségek védelmét, a pártállami rendszerben a kisebbségi kérdés tabunak számított.\n\nA rendszerváltás előtt a magyarországi németek nem rendelkeztek kisebbségi jogokkal, a második világháborút lezáró békeszerződések nem biztosították a kisebbségek védelmét.\n\n1980-ban a népszámláláson a becsült adatokhoz képest feleannyian vallották magukat németnek a népszámláláson, de 1990 és 2000 között megkétszereződött a magukat németnek vallók száma. Az egypárti diktatúra időszakában ugyanis sokan nem vállalták, hogy a német kisebbséghez tartoznak. Az 1990-es években fogadtak el törvényt a kisebbségek védelméről, így a közélet demokratizálódásának köszönhetően vallották többen németnek magukat. A törvény kollektív és egyéni jogokat is biztosított, lehetővé tette kisebbségi önkormányzat létrehozását, óvodák, iskolák, kulturális intézmények fenntartását.\n\nA zsidóság száma a holocaust miatt csökkent – kb. 0,5 millióan haltak meg.\n\n1945 utáni népesedési-demográfiai folyamatok\n\naz élve születések száma az 1950-es és az 1970-es évek közepén emelkedett,\n\nbár a születések száma más időszakokban csökkent, a népesség száma 1980-ig nőtt.\n\na születéskor várható élettartam 1941 és 1970 között jelentősen nőtt, és ez a folyamat késleltette a csökkenő születésszám miatt bekövetkező lakosságszám csökkenést.\n\nA terhesség-megszakítás lehetőségét szűkítő 1952-es rendeletet a Rákosi-korszak egészségügyi kormányzata hozta. Célja volt a nők védelmén túl a születések számának növelése. Ratkó Anna népegészségügyi miniszter alatt születtek az ún. Ratkó-gyerekek.\n\nA Kádár- korszakban bevezetett gyermekgondozási segély bevezetésével próbálta a kormányzat növelni a gyermekvállalási kedvet.\n\na születések számának alakulására átmenetileg ugyan hatást gyakoroltak a politikai intézkedések, de a 80-as évekig a népesség gyarapodását inkább az átlagéletkor növekedése okozta.\n\na születések számának csökkenése összefügg a női szerepek átalakulásával, a nők munkába állásával\n\na 80-as évektől tapasztalható népességfogyás okaiként említhető a magas halálozási arány, az egészségtelen életmód következtében fellépő betegségek, a házasságok háttérbe szorultak, a válások magas száma pedig hozzájárul a társadalom egyik alapegységének, a családnak a széteséséhez, és ez kedvezőtlenül befolyásolja a társadalom reprodukciós folyamatát.\n\nA társadalom elöregedése és a csökkenő gyereklétszám az ellátórendszerek problémái is okozták, és ez a XX. század végi magyar társadalom egyik legnagyobb problémája.\n\nEtnikumok és nemzetiségek a magyar társadalomban\n\nNemzeti és etnikai kisebbség a Magyarország területén legalább egy évszázada honos minden olyan népcsoport, amely az állam lakossága körében számszerű kisebbségben van, tagjai magyar állampolgárok, a lakosság többi részétől saját nyelve és kultúrája, valamint hagyományai megkülönböztetik. Olyan összetartozás-tudatról tesz bizonyságot, amely önazonosságának megőrzésére, közösségi érdekeinek kifejezésére és védelmére irányul. Ezer, magát valamely kisebbséghez tartozónak valló választópolgár népi kezdeményezéssel kérheti kisebbségként való elismerését. Számos településen működnek nemzetiségi iskolák (Budapest, Baja, Pécs) ahol biztosított az anyanyelvű oktatás, de a legtöbb esetben kétnyelvű az iskola (Gara, Komlóska, Piliscsév), vagy az anyanyelvi oktatásnak egy gyengébb formája valósul meg, amikor a nemzetiségi nyelvet idegen nyelvként oktatják.\n\nNemzetiségek Magyarországon\n\nA ma Magyarországon élő legnagyobb nemzetiségi csoport a német (szászok, svábok). Jelenlegi számuk kb. 170 ezer, jellegzetes településeik Baranyában és a Dunántúli-középhegység területén vannak. A németek, mint magyarországi nemzetiségek több évszázada együtt élnek a magyarsággal. Az első német betelepülők iparosok, bányászok voltak, akik külön jogokat kaptak: az erdélyi szászok és a felvidéki (szepességi) cipszerek például. A 18. században, a török hódoltság után a kipusztult területekre (Dunántúl, Tolna, Baranya) szintén sok német telepes (sváb) érkezett, akik ipari és kereskedelmi ismeretekkel gazdagították a magyar kultúrát és nyelvet.\n\nA szlovákok a török pusztítás után, a 18. században telepedtek le nagyobb számban, elsősorban Komárom, Veszprém, Nógrád, Pest és Békés megyében. A szlovákok napjainkban mindössze kb. 80-100 ezren maradtak a gyors elmagyarosodás és az 1946-48-ban lezajlott magyar-szlovák lakosságcsere eredményeként (73 ezer szlovák települt át Csehszlovákiába). Főleg Pest környékén, az Északi-középhegységben és Békés megyében élnek.\n\nA románok a 12. században jelentek meg Erdélyben. A mai Magyarországon, Gyula környékén élnek (pl. Kétegyházán, Méhkeréken). A mai ország területen kis létszámú nemzetiség a román. Jelenleg a román-magyar határ mentén, valamint a fővárosban élnek nagyobb számban, összesen kb. 15-20 ezren.\n\nA horvát-magyar határ mentén (Mohács, Baja) élnek magyarországi horvátok (kb. 35 ezer). A magyarok a horvátokkal évszázadokig szövetségben éltek. A mai Magyarországon a Dráva mellett, Szombathely környékén élnek kisebb számban horvátok.\n\nA lengyelek a II. világháború kirobbanását követően menekültként, majd később vendégmunkásként érkeztek Magyarországra. Napjainkban kb. 8.000-10.000 lengyel nemzetiségű lakos él az országban. A legnagyobb közösség Budapesten található.\n\nAz ortodox vallású szerbek a török kiűzését követően, mint kereskedők jöttek az ország belsejébe. Egykori településeiket a Duna mentén találjuk (Szentendre, Komárom, Dunakeszi, Ráckeve, Mohács). Lélekszámuk ma kb. 5.000 fő. A délszláv háború következtében szerb családok százai telepedtek le a szerb-magyar határ melletti településeken (Szeged, Pécs).\n\nA XVIII. századtól kezdve települtek be az országba a kertészkedéssel foglalkozó bolgárok. A bolgár kertészek utódai - kb. 3.000 fő - ma Budapesten, Pécsen, Miskolcon élnek.\n\nA XVIII. századtól érkeztek az országba a kereskedő görögök. 1948-1950 között, a görög polgárháború következtében mintegy 13 ezer menekült érkezett Magyarországra, akiknek Fejér megyében külön falut is alapítottak (Beloiannisz). Miskolcon a Tátra utcába költöztek. Az 1970-es évektől sokan hazaköltöztek közülük, ezért létszámuk napjainkra 3.000 körüli.\n\nAz Őrség (Vendvidék) Szlovéniával határos falvaiban élő kisebbség a szlovénoké (vendek) kb. kétezren vannak. Magyarországon, Szentgotthárd környékén hét településen élnek.\n\nA rutének (ruszinok) a 18. században vándoroltak be főleg a Hegyalja környéki településekre (Szerencs, Tokaj, Sátoraljaújhely környékére).\n\nA Magyarországon élő nemzetiségek többsége évszázadokkal ezelőtt telepedett le hazánk területén. Legtöbbször ide menekültek, vagy betelepítették őket a török és egyéb háborúk miatt elnéptelenedett területekre. Magyarország a 20. század elejéig soknemzetiségű ország volt.\n\nNemzetiségek Magyarországon\n\nMi a nemzetiség? A nemzetiség valamely állam területén kisebbségben lévő emberek csoportja, akiket elsősorban a nyelv és a kultúra, a közös történelmi múlt, illetve az ezekből fakadó magatartásbeli sajátságok és pszichológiai jellegzetességek, valamint az összetartozás tudata köt össze és választ el más nemzetiségektől és nemzetektől.\n\nA magyar korona országaiban 1910-ben összesen 20 744 744 lakos élt, ebből 9 978 318 fő volt a magyarok száma az anyanyelvi megoszlás viszonylatában. A lakosság több mint fele egy-egy nemzetiségi nyelvet beszélt: ebből a román és német ajkú lakosság közel 2-2 millió volt. Az l. világháborút lezáró 1920-as trianoni békekötést követően a nemzetiségek java része és akkor még mintegy 3 millió magyar is Magyarország határain kívül kezdett új életet.\n\nA magyar törvények a legalább száz éve nálunk élő népcsoportokat ismerik el nemzetiségként. Ezek a nemzetiségi csoportok nyelvükben, kultúrájukban és vallásukban is különbözhetnek a többségi nemzet lakosaitól. Magyarország alaptörvénye és a nemzetiségek jogairól szóló 2011. évi CLXXIX. törvény értelmében 13 nemzetiség él Magyarországon, amelyek lélekszámukat tekintve csökkenő sorrendben a következők: cigány, német, román, szlovák, horvát, szerb, ukrán, lengyel, bolgár, görög, ruszin, örmény, szlovén. Népszámláláskor rákérdeznek az adott személy nemzetiségére és anyanyelvére is.\n\nA mai Magyarországon élő nemzetiségek lélekszáma az össznépesség 10%-a.\n\nNemzetiségek száma Magyarországon 2011-ben\n\nANYANYELV NEMZETISÉG\n\nNEMZETISÉG\n\nmagyarok\n\n8 409 049\n\n8 314 029\n\ncigányok\n\n54339\n\n315 583\n\nnémetek\n\n38248\n\n185 696\n\nrománok\n\n13886\n\n35641\n\nszlovákok\n\n9888\n\n35208\n\nhorvátok\n\n13716\n\n26774\n\nszerbek\n\n3708\n\n10038\n\nukránok\n\n3384\n\n7396\n\nlengyelek\n\n3049\n\n7001\n\nbolgárok\n\n2899\n\n6272\n\ngörögök\n\n1872\n\n4642\n\nruszinok\n\n999\n\n3882\n\nörmények\n\n444\n\n3571\n\nszlovének\n\n1723\n\n2820\n\nNépesség összesen:\n\n9 937 628\n\n9 937 628\n\n(Forrás: ksh.hu)\n\nNemzetiségi politika:\n\nHazánkban 1995 óta december 18-án ünnepeljük a nemzetiségek napját. Az ENSZ ezen a napon fogadta el a nemzeti vagy etnikai, vallási és nyelvi kisebbségek jogairól szóló nyilatkozatát. Ezen a napon adják át a Nemzetiségekért-díjat, amelyet a nemzetiségek érdekében a közéletben, az oktatásban, a kultúrában, az egyházi életben, a tudományban, a tömegtájékoztatásban, a gazdasági önszerveződésben kiemelkedő tevékenységet végző magyarországi és határon túli személyek és szervezetek kaphatnak meg.\n\nKisebbségi törvény (1993. évi 77. tv.): „A nemzeti és etnikai kisebbségek jogairól”\n\nJelentősége az 1868-as nemzetiségi törvényhez hasonló. Meghatározza a kisebbségek egyéni és közösségi jogait: helyi és országos kisebbségi önkormányzatok; kisebbségek művelődési és oktatási önigazgatása; kisebbségek nyelvhasználata (mindenkor és mindenhol szabad használat); támogatások és jogvédelem (Nemzeti és Etnikai Jogvédő Iroda, kisebbségi ombudsman). A kisebbségi önkormányzatok: „Az általános önkormányzati választásokon, ha a megválasztott önkormányzati képviselő-testület több mint fele egy kisebbségből kerül ki, akkor a testület kisebbségi települési önkormányzattá nyilváníthatja magát.\n\nHa a helyi önkormányzat képviselőinek legalább 30%-át ugyanabból a kisebbségből választották, e képviselők önálló (legalább 3 tagú) kisebbségi önkormányzatot hozhatnak létre. Közvetlen képviselőválasztás: az általános önkormányzati választásokkal egy időben, valamennyi választópolgár részvételével kisebbségi önkormányzati választásokat is tarthatnak. Ha egy kisebbségnek nincs kisebbségi önkormányzata, akkor a kisebbség képviseletét szószóló (a legtöbb szavazatot elért kisebbségi jelölt) is elláthatja.\n\nAz országos kisebbségi önkormányzatot a kisebbségi elektorok választják. Elektornak számít a kisebbségi önkormányzatok valamennyi képviselője és valamennyi szószóló, illetve ezek hiányában a településeken kisebbségenként választói gyűléseken megválasztott delegátus.\n\nVÁLTOZÁS: a 2011. évi CLXXIX. törvény a nemzetiségek jogairól:\n\nA nemzetiségi törvény a nemzetiségek egyenjogúságát szabályozza. A törvény szerint tizenhárom nemzetiségnek van joga kisebbségi önkormányzatokat alakítani: a szlovén, a horvát, a szerb, a román, a ruszin, az ukrán, a szlovák, a német, a bolgár, a görög, a lengyel, az örmény és a roma (cigány) kisebbségnek. A kisebbségi önkormányzatok képviselik a kisebbségek érdekeit és segítik a kulturális örökség ápolását. Külön regisztrálni kell a kisebbségi önkormányzati választásokon való részvételre.\n\nA nemzetiségi iskolákat nem a kisebbségi önkormányzatok tartják fenn, hanem az állam.\n\nAz Alaptörvény szerint (2012. január 1.)\n\nA Magyarországon élő nemzetiségek államalkotó tényezők. Minden, valamely nemzetiséghez tartozó magyar állampolgárnak joga van önazonossága szabad vállalásához és megőrzéséhez.\n\nA Magyarországon élő nemzetiségeknek joguk van az anyanyelvhasználathoz, a saját nyelven való egyéni és közösségi névhasználathoz, saját kultúrájuk ápolásához és az anyanyelvű oktatáshoz.\n\nA Magyarországon élő nemzetiségek helyi és országos önkormányzatokat hozhatnak létre.\n\nNemzetiségi listát állíthatnak az országos nemzetiségi önkormányzatok. A nemzetiségek államalkotó tényezők, ezért az Országgyűlésben képviselőjük vagy szószólójuk van. Nemzetiségi listára a pártlisták helyett szavazhatnak a magukat regisztrált választópolgárok, ha azonban nincs elég szavazat, akkor képviselő helyett szavazati joggal nem rendelkező szószólót küldhetnek az Országgyűlésbe.\n\nA kisebbségeket ért jogsérelmek kivizsgálásával a kisebbségi jogok országgyűlési biztosa (ombudsman) foglalkozott.\n\nNemzetiségi szószóló: lehetőség van nemzetiségi szószólót küldeni az Országgyűlésbe azoknak a nemzetiségi listát állító nemzetiségeknek, melyek nem érték el a kedvezményes mandátumhoz szükséges szavazatszámot. A szószóló a listájukon 1. helyen szereplő személy lesz.\n\nA magyarországi romák\n\n• A cigányság több, különböző hagyományú és eredetű csoport gyűjtőneve, akiket a többségi társadalom magától szokásaikban és megjelenésükben különbözőnek vél. Újabban elterjedt a roma megnevezés is, ami eredetileg a cigányok többségének önelnevezése.\n\n• Mivel a cigányság nem egységes csoport, kultúrája, hagyományai is sokszínűek. A korai feljegyzések vándorló csoportként írták le őket, akik különböző iparosmesterségekkel (pl. kovács), valamint kereskedelemmel foglalkoztak (lókupec).\n\nA 19. századra többségük letelepedett, továbbra is főleg iparosként, illetve napszámosként dolgozott. A kevés szakértelmet igénylő javító tevékenységek, illetve a nagyon olcsó nyersanyagból készíthető használati cikkek előállítása jellemző rájuk (pl. üstfoltozó, kosárfonó, teknővájó, vályogvető stb.) A társadalom perifériáján éltek, vándorló életmódot folytattak. Kevés írásos emlék tesz róluk említést.\n\nA II. világháborút követően, a szocializmus idején a cigányság tömegesen állt munkába, főként a szaktudást nem igénylő építőiparban, textiliparban és bányászatban. Többségük az északkeleti megyékben, aprófalvakban élt. Jellemző volt az alacsony iskolázottság, a szakképzettség hiánya, ezért általában alacsony presztízsű, rosszul fizetett nehéz fizikai munkát végeztek. Lakásukból gyakran mindenféle komfort hiányzott. Az 1961-es MSZMP-határozat a cigányság integrálását tűzte ki célul az egészségtelen lakóhelyek felszámolásával és átfogó lakásépítési programmal. Társadalmi integrációjuk érdekében megkezdődött a cigánytelepek felszámolása, de sokukat csak csökkentett komfortfokozatú (ún. ,,Cs”-lakásokba) költöztették. A hetvenes években a modernizáció tovább folytatódott, de életszínvonaluk továbbra is elmaradt a többségi társadalométól. A szocializmus időszakában végképp megszűnt az igény a hagyományos mesterségeikre, de a kiépülő nagyipar képzetlen munkaerőként alkalmazta őket. A kialakult társadalmi előítéletek az 1989/90-es rendszerváltáskor csak átmenetileg enyhültek. A cigányság körében a rendszerváltás után (1989) drasztikusan nőtt a munkanélküliség, a hagyományos cigány mesterségek (pl. kovácsolás, teknőégetés) eltűntek. A rendszerváltással ezek az üzemek jórészt megszűntek, a cigányok között tömegessé vált a munkanélküliség. A rendszerváltás után a gazdaságtalanul működő ipari vállalatokat bezárták, vagy eladták, és így az alacsony képzettségű romák közül sokan munkanélküliek lettek.\n\nElhelyezkedésük: a cigányság zöme hagyományosan az ország észak-keleti (és dél-nyugati) részén él, amely eleve szegényebb, és ahol eleve nagyobb a munkanélküliség. Nagyobb népességtömörülés alakult ki Budapesten. Napjainkban a társadalom legszegényebb rétegeihez tartoznak. A cigányság 40%-a városlakó, elsősorban tehát Budapesten és a régi iparvidékek nagyobb városaiban (pl. Ózd) találhatóak nagy számban. A többiek leszakadó, fejletlen térségekben élnek az ország keleti felében, illetve a Dunántúlon, Baranya megyében.\n\nA cigányság a legnagyobb Magyarországon élő etnikai kisebbség. A romák létszámát a becslések általában 400 ezer és 600 ezer közé teszik.\n\nŐket 2011-ig etnikai kisebbségként jelölték, ugyanis a többségük anyanyelve magyar, de hagyományaik, életmódjuk megkülönbözteti őket a többségi magyar társadalom egészétől. Sajátos, vándorló életmódjuk miatt több száz éven keresztül a társadalom peremén éltek. Az állam sokszor próbálta őket letelepíteni, és asszimilációra kényszeríteni - sikertelenül.\n\nMi a nemzetiség? A valamely állam területén kisebbségben levő emberek csoportját értjük alatta, akiket elsősorban a nyelv és a kultúra, a közös történelmi múlt, illetve az ezekből fakadó magatartásbeli sajátságok és pszichológiai jellegzetességek, valamint az összetartozás tudata köt össze és választ el más nemzetiségektől és nemzetektől. Hazánkban 13 nemzetiségi csoport él, ezek közé tartozik a cigányság is.\n\nA leghátrányosabb helyzetben a legnagyobb nemzetiség, a cigányság van, amelynek nincs anyaországa, és a csoport nagy része mélyszegénységben, hátrányos helyzetben él. A cigányság számát Magyarországon 600 ezerre becsülik. A hazánkban élő cigányoknak nyelvileg három nagy csoportját különböztetjük meg: a magyarul beszélő romungrókat, a romani nyelven beszélő oláhcigányokat, és a román nyelv egy archaikus nyelvjárását beszélő beásokat. Legnagyobb csoportjuk a magyar nyelvű romungrók (magyar cigányok, muzsikus cigányok). Az oláhcigányok az indiai eredetű romani nyelv különböző változatait beszélték eredetileg (egyik törzsük a lovári).\n\nTársadalmi problémák:\n\nElőítéletes gondolkodás: egy személlyel vagy csoporttal kapcsolatos előzetesen kialakult elképzelések, amelyek új információk hatására sem változnak meg. A romákkal kapcsolatos sztereotípiák: buta, koszos, lop, nem szeret dolgozni stb. Ilyen a túlzott szaporaság mítosza: a valóságban a cigány családok gyerekszáma átlagosan megegyezik a hasonló anyagi körülmények között élő nem cigány családok gyerekszámával (a szegény családokban átlagosan több gyerek él). Ilyen a túlsegélyezettség mítosza: a valóságban a segélyek nem nyújtanak méltó megélhetést, összegük pedig a magyar jóléti kiadások töredékét teszi csak ki. Ilyen a „cigánybűnözés” mítosza: a valóságban a cigányság bűnözési statisztikái megegyeznek a hasonlóan szegény nem cigány lakosság statisztikáival. A sztereotípiák azonban előítéletekhez, az pedig diszkriminációhoz (megkülönböztetés) és szegregációhoz (elkülönítés) vezetnek: A szabad iskolaválasztás eredményeképpen kialakultak a középosztályt, illetve a szegényeket (köztük a cigányokat) kiszolgáló iskolák. Sok munkahely nem vesz fel cigány alkalmazottat. Azokról a településekről vagy településrészekről, ahova sok cigány költözik, elköltöznek a nem cigányok, és kialakulnak a cigány gettók. Itt az ingatlanárak csökkennek, ami végleg ideköti a szegényeket (és idevonz újabbakat).\n\nDiszkrimináció, hátrányos megkülönböztetés: a romák hátrányban vannak a munkaerőpiacon, a szórakozóhelyekre nem engedik be őket stb.\n\nA diszkrimináció eredménye: a rossz környéken lakó, rossz iskolába járó, az álláskeresés során kudarcokat megélő cigányok számára nincs követendő pozitív minta.\n\nMásrészt a rossz környéken lakó, szegényesen öltözött, iskolázatlanul beszélő (és sötétebb bőrű) ember valószínűleg rosszabb tanuló vagy munkavállaló lesz, így diszkriminálása az iskola vagy a vállalat szempontjából „érthető”.\n\nAz emiatt a csoport egészét érő kudarcok azonban nem csak dühöt eredményeznek, de csökkentik is a cigányok motivációját, hiszen eredményeik nem az erőfeszítéseiken, hanem a külső megítélésen múlnak.\n\nA cigányság össztársadalmi gondjai:\n\nA cigányság össztársadalmi gondjai: iskolázatlanság, munkanélküliség, szegénység, rossz életkörülmények, vékony az értelmiségi rétegük, megosztottság: egységes politikai fellépés hiánya.\n\n• iskolázatlanság: a szakképzetlen munkaerő elhelyezkedése nehéz. A hagyományos szakmákban szerzett tudásra nem tart igényt a piac.\n\n• munkanélküliség: gyakran már a második, harmadik generációban, így nagyon alacsony a családok jövedelme. A magas gyerekszám, ami a szegénységnek és iskolázatlanságnak oka és következménye is egyben. (A korai családalapítás és a munkanélküliség hajlamosít a gyerekvállalásra.\n\n• rossz életkörülmények, szegénység\n\nA szegénység és iskolázatlanság eredménye a rossz egészségügyi állapot, a többségi társadalomhoz képest korai halálozás. Ez természetesen visszahat a jövedelemszerző képességre, azaz a szegénység oka is egyben.\n\n• vékony az értelmiségi rétegük, illetve megosztottak: hiányzik az egységes politikai fellépés.', 331, 1, '2026-04-17 09:40:12', '2026-04-17 09:40:12');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(7, 7, 'Az ipari forradalmak társadalmi háttere és hatásai', '7.docx', '7. tétel: Az ipari forradalmak társadalmi háttere és hatásai\n\nAz 1. ipari forradalom és a forradalmat kiváltó tényezők:\n\nAz 1. ipari forradalom 1750/80 körül jött létre Angliában és kb. 1850-ig tartott. Az ipari forradalom olyan komplex nemzetgazdasági és társadalmi jelenség, amely az iparban végbemenő minőségi változás. A kézműipart (manufaktúrát) felváltja a gyáripar, a gépek, s tömegtermelésre és munkamegosztásra törekednek. Új energiaforrás a gőz lesz. Az ipari forradalom húzóágazata a textilipar.\n\nFeltételei:\n\n1. a mezőgazdaság kapitalizálása, azaz a piacorientált termelés, a tőkés-bérlő viszony létrejötte 2. a gyáripar, a gépek elterjedése,\n\n3. a pénztőke felhalmozódása, a hitelszervezet létrejötte,\n\n4. a gyarmatok kifosztása,\n\n5. a polgári forradalmak, melyek elhárítják a feudális akadályokat (Angliában 1640-ben).\n\nAz ipari forradalom kibontakozása:\n\n1. A könnyűiparban, ezen belül a textiliparban kerül sor először gépesítésre, tömegfogyasztási cikkek előállítására. A gyarmatokról származó olcsó gyapot, a kiterjedt piac, az óriási profit, az olcsó munkaerő, a tőke és a találmányok lehetővé tették kibontakozását. Ezért lett húzóágazat a textilipar.\n\nA fonás gépesítése: 1733. John Kay repülő vetélője, 1764. Hargreaves fonó Jennyje, 1767. Arkwright vízikerék meghajtású fonógépe, 1779. Crompton gőzhajtású fonógépe, Roberts önműködő fonógépe. A szövés gépesítése: 1785. Cartwright mechanikus szövőgépe; Jacquart feltalálta a pepita mintás szövést.\n\n2. A gőz forradalma: a gőz használatának elterjedésével a termelés nőtt, s elősegítette a közlekedés forradalmát. 1698-ban Newcomey alkalmazott először gőzhajtású gépet, mégpedig bányaszivattyút. Magyarországon 1723-tól működik ilyen gép. 1769-ben James Watt gőzgépe tökéletesebbnek bizonyult, mely kettős üzemeltetésű és nem áll le.\n\n3. A közlekedés forradalma: a gőz erejének felhasználásával fellendült a közlekedés, a szállítás felgyorsult. Találmányok: 1807. Fulton gőzhajója, melyet az USA-ban, a Mississippi folyón próbáltak ki. 1817. Stephenson gőzmozdonya Angliában, melyet 1825-ben próbáltak ki először a Stockton – Darlington között felépített vasútvonalon. A Rocket nevű gőzmozdony 32 mérföld/óra sebességgel haladt. A találmányok közé tartozik a McAdam által tervezett műút (makadám út), a csatornaépítés, s a hídépítés is. Az első vashidat 1819-ben az angliai Tweed folyón hozták létre. 1837. a hírközlés forradalma: Morse szikratávírójával.\n\n4. A nehézipar forradalma: a gépgyártó gépek létrehozása. Lehetővé vált a sorozatgyártás, a szabványosítás. Hatalmas tőkéket fektettek a nehéziparba. Találmányok:\n\nMaudsley vas esztergapadja, 1760. Hulot tengelyvágó gépe, a különböző fúrógépek, marógépek, köszörűk, gyalugépek a nehézipar fejlődését jelzik.\n\nAz ipari forradalom következményei:\n\n1. Agrárforradalom: tőkés bérleti rendszer létrejötte, a mezőgazdasági technika korszerűsítése, pl. vetőgép, gőzeke. Technológiai változás: a vetésforgó (évente más-más növény ültetnek ugyanabba a földbe). A terméshozam növekedését elősegíti a trágyázás, a műtrágyák elterjedése, a fajtanemesítés. Elsősorban ipari és takarmánynövények termesztése. A korábbi évszázadok gazdasági eredményeit (tőkés vállalkozások, manufaktúrák) felhasználó országban mezőgazdasági fejlesztések indultak a 18. század elejétől. A bekerítések során a föld polgári tulajdonba került, és a földterületek többségén a birtokosok korszerű termelési módszereket alkalmaztak. A vetésforgó a nyomásos gazdálkodás meghaladását jelentette, az ugar területére takarmánynövényeket (zabot, lucernát) ültettek, így az állatoknak télre is tudtak élelmet biztosítani. Az istállózó állattartás a családokat egész évben ellátta hús- és tejtermékkel, az új kapásnövények (burgonya, kukorica) további élelemforrást nyújtottak. A birtokosok talajjavító módszerekkel (vetésforgó, trágyázás) bővítették a gabonatermelést, és a szigetországban az éhínség megszűnt. A 18. századi mezőgazdasági forradalom biztosította a folyamatosan növekvő népesség és az iparosodó városok ellátását, így fenntartotta a gazdasági növekedést.\n\n2. Az infrastruktúra forradalma: javul az egészségügyi ellátás, fejlődik a közlekedés, az út- és csatornaépítéssel nő a közművesítés, modern bankrendszer épül ki, jelentős a szakképzés.\n\n3. Demográfiai forradalom,: a lakosság növekedésnek indul, pl. Angliában megháromszorozódik. Így olcsó lesz a munkaerő. Sőt a gépesítés miatt csökkentik a munkások számát: géprombolás.\n\n4. Urbanizáció (városiasodás) A városi lakosság 50%-kal nő a falusihoz képest.\n\n5. Társadalmi – strukturális forradalom: tőkés – bérmunkás viszony jön létre.\n\nNagy-Britanniát számos kedvező feltétel is segítette: az ország jelentős szén- és vasérckészlettel rendelkezett. A folyók szabályozása, illetve a csatornahálózat kiépítése a belső szállítás költségeit csökkentette, míg az egyre terebélyesedő gyarmatbirodalom a kivitelt lendítette fel.\n\nA 18. századtól kezdve sorra születtek a tudományos-technikai találmányok, a feltalálók a szabadalmi törvény értelmében védettséget élveztek, és 14 évig kizárólagos jogon értékesíthették találmányukat. A beruházásokhoz szükséges tőkét jól működő hitelszervezet biztosította, az Angol Bank (1694) fiókszervezetei az egész országot behálózták.\n\nAz időszakot jellemző szabad versenyes kapitalizmus elvetette az állami beavatkozást a gazdasági folyamatokba. A modern közgazdaságtan alapítója, Adam Smith a szabad kereskedelem híveként a „láthatatlan kéz” szerepét hirdette a gazdaságban. Eszerint a keresletre és a kínálatra ható erők mintegy elrendezik a piacot, bármilyen külső beavatkozás megakasztja a fejlődést (önszabályozó piac).\n\nA népesség számának gyarapodásával a növekvő belső fogyasztás először a textilipart állította kihívás elé. A két alapművelet, a fonás-szövés gépesítése több feltaláló találmánya során, lépésről lépésre valósult meg pl. Hargreaves fonógépe 1769-ben és Cartwright szövőszéke 1785-ben.\n\nA gazdasági növekedést felgyorsította az emberi munkavégzést megkönnyítő külső energiaforrás, a gőzenergia szolgálatba állítása. A természeti energiák hasznosítása után James Watt gőzgépe (1769) korszakváltást jelentett. A gőzenergiát kezdetben a bányászatnál alkalmazták a bányavíz kiszivattyúzására (a Thomas Savery és Thomas Newcoman által kifejlesztett gőzszivattyú segítségével). Watt tökéletesítette a gőzgépet: a munkagép sokkal kevesebb tüzelőanyagot igényelt, és műhelyi szerszámgépek hajtására is alkalmazták. Az addigi dugattyúk egyenes vonalú, váltakozó (fel-le) irányú mozgását Watt áttételek segítségével egyenletes körmozgássá alakította át. A forgómozgás folyamatos biztosítása számos új találmány megszületéséhez vezetett. A gőzenergia hasznosítása gyorsan terjedt a textiliparban, rövidesen létrejött az első gőzgéppel működő fonoda (1785).\n\nA hagyományos posztógyártás mellett a 19. század első felében a pamutipar is fellendült, a „nyersanyagéhséget” kezdetben az Indiából behozott gyapot elégítette ki.\n\nA tömegtermelés a belső szállítás felgyorsítását igényelte, és a 19. század elején megindult a közlekedés forradalma.\n\nA Robert Fulton által megépített lapátkerekes gőzhajó először az Egyesült Államokban mutatkozott be (1807), de rövidesen az európai országok is megvették a találmányt.\n\nNéhány évvel később az Atlanti-óceánt először átszelő gőzhajó (1819) nemcsak a világkereskedelemnek, hanem a flottafejlesztésnek is irányt szabott. Először a lapátkerekek sérülékenységét kellett kiküszöbölni, majd a hajócsavar feltalálásával az egyre erősebb gőzgépekkel hajtott hajók háttérbe szorították a vitorlásokat. A szárazföldi áruszállítás a szilárd burkolatú úthálózat kiépítésével és a vasút megjelenésével gyorsult fel.\n\nBár a gőzmozdony megépítésével többen is kísérleteztek, George Stephenson lokomotívjai megőrizték technikai fölényüket. Stephenson első mozdonyának megépítését követően (1814) még tucatnyi modellt készített; a kétkedőket az első vasútvonal átadásánál tartott bemutatója győzte meg (1825).\n\nA találmányok, a technikai változások óriási mennyiségű nyers- és kovácsolt vasat igényeltek. Az ipari forradalom kibontakozását a kohászat műszaki fejlődése is segítette. A vaskohászat technikája a kora újkorban sokat javult, az olvasztókohókban az előállított nyersvas mennyisége folyamatosan növekedett. A vastermeléshez azonban rengeteg faszén (a vasérc megolvasztásához szükséges tüzelőanyag) kellett, és az erdőirtás riasztó méreteket öltött. A 18. század elején a vashiánnyal küszködő Anglia oroszországi nyersvas behozatalára szorult. A problémát a kokszosítás technikájának kidolgozása és a koksz kohászati felhasználása oldotta meg (Darby, 1735). A további műszaki fejlesztések nyomán Nagy-Britannia néhány évtized alatt a nyersvastermelésben az élre került. A vasfeldolgozás és a hengerelési technika fejlődése pedig jó minőségű szerkezeti anyagot biztosított a gőzgépek gyártásának, a közlekedés forradalmának (gőzhajók, gőzmozdonyok, vasúti sínhálózat).\n\nAz első ipari forradalom legmeghatározóbb vívmánya tehát a gépesített, tömegtermelésre képes gyári nagyipar létrejötte volt. Ez környezeti hatása szempontjából máig meghatározó: óriási mértékben növelte meg a termékek mennyiségét (amelyek szükségesek a növekvő népesség ellátásához), s ehhez egyre nagyobb mennyiségű nyersanyagot és energiahordozót használ fel, s ezáltal közvetlenül és közvetve egyre nagyobb mértékben pusztítja a természetes élővilágot, s változtatja meg a szárazföldek arculatát.\n\nForradalmi változást hozott a közlekedésben is: a gőzgép által termelt mozgási energiát hasznosították a gőzhajó és a gőzmozdony működéséhez, s bár eleinte fával fűtötték őket, a kőszén fokozatosan kiszorította a fát, mint energiahordozót, s fokozta a környezetszennyezést. Az erdőket ennek ellenére nem „mentette meg” a kőszén, mert a fára szükség volt a mélyművelésű kőszénbányászathoz, a vasútépítéshez (talpfa, jelzőpóznák, sorompók stb.), sőt a gyáriparban is (pl. textilipar).\n\nAz ipari forradalom következményei:\n\nA javuló életkörülmények miatt rohamosan megnövekedett a fejlett világ lakossága. (Anglia háromszorosára; USA, Kanada tizenkétszeresére; Franciaország másfélszeresére; Európa többi részén másfél-kétszeresére) Nőtt az átlagéletkor (25-ről 46-47 évre) az agrárforradalom és a jobb orvosi ellátás, a védőoltások bevezetése miatt.\n\nJelentős méreteket öltött az urbanizáció is. Párizs, Lyon, Antwerpen, Rotterdam Európa, míg Boston, New York, Chicago Amerika vezető városaivá váltak. A városiasodás hatására megnőtt az elszegényedés mértéke. Nagy volt a lakáshiány is. Gyakran 10-12 ember élt egyetlen lakásban. A munkásokat embertelen körülmények között dolgoztatták. 10-12 órás munkaidő volt, nem adtak hétvégét és betegszabadságot. Terjedt a deviáns viselkedés (bűnözés, alkoholizmus, prostitúció)\n\nAz első ipari forradalom átalakította a társadalom hagyományos kereteit, a mezőgazdasági termelők aránya folyamatosan csökkent. (Angliában a korszak elején a lakosság 60 százaléka élt mezőgazdaságból, a 19. század közepére már csak 22 százalékuk.) Az életkörülmények megváltozásával az átlagéletkor nőtt (27 évről 42 évre), és csökkent a gyermekhalandóság. Mindezek hátterében az egészségesebb táplálkozás, illetve a fertőző betegségek elleni sikeres küzdelem állt. A himlő elleni védőoltás felfedezése (1798) a század egyik legsúlyosabb járványától szabadította meg az emberiséget. Sokat javultak a tisztálkodási szokások, a mindennapos mosakodás és szappanhasználat az egyéni higiénia megjelenését jelezte.\nA tömegtermelés lehetővé tette az olcsó pamutruhák megvásárlását és a kialakuló polgári viselet széles körű elterjedését. A nagyvárosokban a polgári középosztály új életmódot alakított ki, öltözködésével és viselkedési szabályaival elkülönült az alsóbb társadalmi rétegektől.\n\nA városiasodás, az urbanizáció folyamata ütemesen gyorsult, a belső migráció (országon belüli elvándorlás, átköltözés) a létrejövő ipari nagyvárosokba irányult (például Manchester, Liverpool, Birmingham).\n\nA munkalehetőséget a gyáripar kibontakozása és a nagyüzemek létrejötte biztosította. A nagyipari üzemszervezés méltatlan körülményeket teremtett a munkásoknak, akik napi 14-16 órás munkaidőre, alacsony fizetésre és szigorú büntetésekre számíthattak. A kiszolgáltatottság érzését növelte, hogy baleset- és betegbiztosítás, illetve munkanélküli segély nem létezett.\n\nA női munka és a gyermekmunka rendszeressé vált a korszakban, a bányászatban alacsonyabb fizetésért sokszor 13 év alatti gyerekeket is foglalkoztattak. Az előkelők negyedeiben megkezdődött a csatornahálózat kiépítése, az utcák kikövezése és a szemétszállítás megoldása, de a városi munkásság életkörülményeinek javítását még elhanyagolták. A megoldatlan munkáskérdés, a zsúfolt külvárosi bérkaszárnyák és a közeli gyártelepek egészségkárosító füstkibocsátása az ipari forradalom árnyoldalának tekinthető.\n\nGyökeresen átalakult a társadalom:\n\nA XIX. századtól kezdték el használni az osztály fogalmát. Egy osztályba az azonos társadalmi helyzetű emberek tartoznak, akiket közös érdek mozgat és közös kulturális vonások jellemeznek.\n\nA társadalmat két osztályra tagolták:\n\n1. akik a termelőeszközöket birtokolják (gyárosok, banktulajdonosok, bányatulajdonosok, nagybirtokosok) Őket összefoglaló néven burzsoáziának nevezzük.\n\n2. Akik a termelőeszközöket működtetik (munkások, parasztok, napszámosok). Összefoglaló nevük a proletariátus.\n\nMindkét osztály differenciálódott, megjelent a középosztály (közép- és kisvállalkozók, önállóan gazdálkodó parasztok, hivatalnokok, értelmiség) Ez a réteg nem rendelkezett nagy vagyonnal, de biztonságos megélhetése volt. Ők voltak a polgári demokrácia fő támogatói.\n\nA munkásság is két rétegre tagozódott:\n\nA fehérgallérosok adták a munkáselitet. Ők nagyon jólképzett, szinte nélkülözhetetlen munkások voltak. Jó fizetésük volt és biztosan meg tudtak élni.\n\nA másik csoportba a kékgalléros munkások tartoztak. Ezek segédmunkások voltak, akik képzetlenségük miatt állandó létbizonytalanságban éltek, bármikor elbocsáthatták őket.\n\nMunkásmozgalom:\n\nNagy-Britanniában a változó gazdasági körülmények felgyorsították az alsóbb társadalmi rétegek elszegényedését. A városokban élő nagyüzemi munkásság egy-két évtized alatt elszakadt a hagyományos gyökereitől, és bizonytalanságérzetét a kiszolgáltatottság is fokozta. A gyakori elbocsátások miatti felháborodások először spontán mozgalmakhoz vezettek, a munkások összetörték a gépeket, felgyújtották a gyárakat (1810-es évek). A gépromboló mozgalmat a kormányzat gyorsan felszámolta, és számos vezetőjét Ausztráliába deportálták.\n\nA munkásoknak nem voltak politikai jogaik, de a szervezkedések miatt az államhatalom kénytelen volt engedni követeléseiknek. Kezdetben ösztönös megmozdulások voltak (géprombolás pl. luddizmus), de sor került fegyveres felkelésre is. (1831 és 34-Lyon; 1844-Szilézia) Az 1820-as években megjelentek az első szakszervezetek (trade unionok). Az egységes fellépés, a szakszervezeti mozgalom kibontakozása sokkal eredményesebbnek bizonyult. A szakszervezetek a munkások önsegélyező egyesületeiből (például baleset-biztosítás) szerveződtek, hatékonyságukat a közös munkabeszüntetés, és a sztrájk megszervezése biztosította. A sztrájk olyan megmozdulás lett, amely a munkaadót engedményekre késztette (béremelés, munkakörülmények javítása). A brit törvények engedélyezték a szakszervezetek működését (1824), habár a sztrájk ellen még sokáig erőszakosan léptek fel.\n\nAz 1830-as években bontakozott ki a chartizmus. Ez volt az angol munkások első önálló mozgalma. Céljaik közé tartozott az általános titkos választójog megszerzése, egyenlő lélekszámú választókerületeket akartak létrehozni, különböző jóléti intézkedéseket követeltek. Újságot alapítottak: az Észak Csillagát. Követeléseiket összegyűjtött aláírásokkal együtt tárták a parlament elé. Az 1830-as években már a politikai törekvések is megfogalmazódtak a munkásságon belül. A chartista mozgalom (charta: alkotmányjavaslat) kérvényekkel akarta elérni az általános választójog bevezetését. A londoni parlament, annak ellenére, hogy több millió aláírást is csatoltak a kérvények (petíciók) mellé, elutasította a kérelmüket. A kiélezett helyzetben a brit törvényhozás munkásvédő törvényekkel próbálta leszerelni a mozgalmat.\n\nA chartisták hat pontja\n\náltalános választójogot minden férfinak;\n\nválasszák évenként újra a parlamentet;\n\nadjanak fizetést a parlament tagjainak, hogy vagyontalanok is elfogadhassák a képviselői megbízatást;\n\nvezessék be a titkos szavazást;\n\nalakítsanak egyenlő választókerületeket, hogy így biztosíthassák az egyenlő képviseletet;\n\nlegyen mindenki választható.\n\nEredmények:\n\n1833 A gyermekmunka korlátozása (9 év alatt tilos, 13 év alattiaknál napi 9 óra a maximum)\n\n1842 Tilos a nők és a gyermekek foglalkoztatása a bányákban\n\n1844 Kötelező a gyárakban a munkafeltételek javítása\n\n1847 A munkaidőt tíz órában korlátozzák\n\nAz első ipari forradalomhoz kapcsolódott az utópista szocialisták megjelenése is. Ide tartozott Sant-Simon, Charles Fourier (falanszter-elmélet) és Robert Owen. Olyan elképzelésekkel léptek fel, melyek abszolút megvalósíthatatlanok voltak, ezért hatásuk nem jelentős.\n\nA 2. IPARI FORRADALOM\n\nAz 1850-60-as években a világgazdaság rohamos fejlődésnek indult újra. Általános modernizációra került sor több vezető szektorban. Anglia előnye megszűnt, mert az USA és Németország a későn indulók előnyével fejlődött gazdaságilag. Míg Anglia hosszú évek alatt tökéletesítette a találmányokat, addig az USA és Németország csak adaptálta a legfejlettebb technikát, így előnyre tett szert. Fejlődött Skandinávia, Közép- és Kelet- Európa, de ezek e térségek periférián maradtak. Fejlődésük komplementer volt (követte a centrumot lemaradva) és derivált (kielégítette a Ny igényeit). Az itteni fejlődést a centrum tőkéje és igényei határozták meg.\n\nHárom lényeges változás történt.\n\n1. Új anyagok (műanyag, acél) jelentek meg.\n\n2. Új energiaforrásokat használtak (kőolaj, elektromosság).\n\n3. Gépesítés és munkamegosztás térnyerése (pl.: Ford T-modell- gyártósoron készült) Fejlődött az acélgyártás is. Lecsökkentették a vas széntartalmát, így a keletkezett anyag, az acél, sokkal ellenállóbb lett. Nagy fejlődés ment végbe a vegyiparban is. Beindult az alumínium, üveg, papír, gumi, cement és kerámia tömeggyártása. Kialakult a petrolkémia, a kőolajvegyészet.\n\n1876-ban Nicolaus Otto feltalálta a négyütemű motort, mely jóval csendesebb, takarékosabb és könnyebben indítható volt elődeinél. 1898-tól Henry Ford futószalagon gyártotta az autókat, melynek karburátorát Csonka János fejlesztette ki, a T-modell főkonstruktőre Galamb József volt. Az autó fejlesztésében szintén Németország és az USA jártak az élen. Az utóbbiban 20 év alatt 15 millió kocsit adtak el. Az első autógyárak között volt a Ford, az Opel, a Mercedes és a Bugatti. Benz a benzines autót, Diesel a nyersolajjal hajtott motort találta fel. A porlasztó Bánki Donát és Csonka János találmánya.\n\nFejlődött a repülés is. 1900-ban Zeppelin feltalálta a kormányozható léghajót,1903-ban a Wright testvérek pedig a motoros repülőt. Ezután nagy verseny indult a két repülőeszköz között, amiből a gyorsabb és erősebb repülők kerültek ki győztesen.\n\nRendkívüli gyorsasággal terjedt az elektromosság világszerte. Faraday felismerte az elektromágneses indukciót, Jedlik Ányos feltalálta a dinamót, elterjedtek a villamos motorok. A legnagyobb feltaláló Edison volt, aki több, mint 1000 találmányával forradalmasította az elektromosságot. Ő alkotta meg a szénszálas izzót, a fonográfot. Daguerre a fényképet, Remington az írógépet, Singer a varrógépet hozta létre. A filmezés, a mozi a Lumiére testvérek érdeme, a röntgensugár Röntgen, a védőoltás Pasteur találmánya.\n\n1881-ben üzembe helyezték az első közszolgálati villamos erőművet a Siemens cégnél. A Monarchia elektromos ipara is jelentős volt (Ganz gyár, Lang gépgyár), de nem vehette fel a versenyt a németekkel és Amerikával.\n\nA kommunikáció is tökéletesedett. 1840-ben Morse feltalálta a távírót, 1876-ban Belle a telefont. Puskás Tivadar építette az első telefonközpontot.\n\nHertz felfedezte az elektromágneses hullámokat, amivel megteremtette a rádiózás alapját.\n\nA mezőgazdaság is gyökeresen átalakult. Megjelentek a műtrágyák. Elkezdték használni a cséplőgépet és a traktort.\n\nTalán a hadiipar fejlődött leggyorsabban. Minden ország elkezdett fegyverkezni, ugyanis meghirdették a világ felosztását. Feltalálták a gépfegyvert. Nobel svéd kémikus a dinamitot. Növelték az ágyúk hatótávolságát. Tankokat és vadászgépeket kezdtek gyártani. Alkalmazták a vegyipar találmányait is (pl.: harci gáz).\n\nA második ipari forradalom alapvetően átalakította a társadalmat Európában. Élesen elkülönült egymástól centrum és periféria, melynek lemaradása behozhatatlanná vált. Míg nyugaton a középréteg irányította az államot, keleten torlódott társadalom alakult ki (Magyarország), ugyanis jelen voltak a feudális maradványok (jobbágyság, nemesség) és a tőkés elemek is (burzsoázia és munkásság). Kialakultak világszerte a monopóliumok.\n\nEgyes vélemények szerint a második ipari forradalom napjainkban is zajlik, ugyanis az élet minden terén a tökéletesítésre törekednek. Fő cél lett a magas hatásfok, a tömegtermelés és olcsó ár, hogy a termékeket mindenki megvásárolhassa. Rohamosan fejlődik a közlekedés és a távközlés.\n\nMonopólium: A tőkekoncentráció eredményeként kialakult olyan tőkés nagyvállalat vagy vállalatok közti szervezet, amely uralkodó pozícióra tesz szert a termelésben és az értékesítésben. Megállapodásokkal korlátozza a szabad versenyt és monopolista extraprofitra törekszik. Az olyan nagyvállalatokat, amelyek egy-egy iparágon vagy piacon belül uralkodó pozícióra tesznek szert, monopóliumnak nevezzük. A monopóliumok gazdasági erejüknél fogva képesek arra, hogy korlátozzák a szabadpiaci versenyt, és diktálják az árakat.\n\nKartell: olyan vállalati szövetség, amelyben a résztvevő felek megegyeznek a verseny korlátozásában és a piac, esetenként az árak és a bérek szabályozásában. Laza kapcsolatot jelent. (Németország)\n\nSzindikátus: olyan vállalati szövetség, amelyben a résztvevő cégek közös felvásárlási és értékesítési rendszert hoznak létre, de megőrizték termelői önállóságukat. (Németország, Japán)\n\nKonszern: bankok irányítása alatt különböző iparágakból létrejött nagyvállalat. A századforduló után újonnan iparosodott országokra jellemző.\n\nTröszt: egy-egy iparág vezető vállalatainak teljes összeolvadása. Az USA-ra jellemző. Az USA-ban trösztellenes törvényeket hoztak 1887, 1890, 1914-ben. A tröszt létrejötte egy szűk elit érdeke, a középrétegeknek nem kedvez.\n\nKorporáció: sok kisebb vállalat termelési láncát, integrációját jelenti. Az USA-ban jellemző. (Később Olaszországban állami ellenőrzést jelent a vállalatok és munkavállalók tekintetében a fasizmus idején.)\n\nHolding: a nyereséges részvények felvásárlására és nagyvállalatok ellenőrzésére alakult egyesülés. Jellemző a részvénytársaságok megjelenése.\n\nA 2. ipari forradalom következményei\n\nA villamosság elterjedése, a gépgyártás, az autógyártás és a vegyipar megteremtése jellemző. A 19. század közepére a fémolvasztás tökéletesítésével a vasnál tartósabb és rugalmasabb acél válhatott a gépgyártás legfontosabb alapanyagává.\n\nEzzel a korszakban meghatározóvá vált az acélgyártás, és a nehézipar eredményei már a nagyhatalmak erőviszonyait is meghatározták. A megfelelő nyersanyagokkal (feketekőszén, vasérc) rendelkező országok közül az Amerikai Egyesült Államok és Németország az élre tört. Ugyanakkor a vasbeton szerkezet megalkotása pedig az építőipart forradalmasította, mert teherbírása és nagyobb hajlékonysága miatt lehetővé vált magas házak és betonhidak építése viszonylag olcsón.\n\nAz ipari forradalom hatása a mindennapokra is kiterjedt, és gyökeresen átalakította az emberek életét. Edison találmánya, a szénszálas izzólámpa elterjedt. Az olcsó tömeggyártásra alkalmas villanykörték kifejlesztése fokozatosan átalakította a nagyvárosok közvilágítását, és javította a közbiztonságot. Ugyanakkor a villanyvilágítás lehetővé tette a gyárakban a fárasztó éjszakai műszak bevezetését is.\n\nAz elektromos ipar látványos térnyerése megváltoztatta a gyáripart is. A gőzenergiával hajtott gépek mellett az elektromos árammal működtetett villanymotorok szerepe is egyre jelentősebb lett. Az elektromosság elterjedésének és a technikai újításoknak köszönhetően megjelentek a lakásokban a különféle háztartási kisgépek, az árammal működő vasaló vagy a villanyporszívó, amelyek könnyebbé tették az emberek életét. A villanymotorral hajtott felvonók kifejlesztése pedig a modern felhőkarcolók építése előtt nyitotta meg a lehetőséget az egyre zsúfoltabb világvárosokban.\n\nA század végén több országban megkezdődött a kőolaj kitermelése, ami a belső égésű motoros járművek széles körű elterjedését tette lehetővé. Ennek köszönhetően forradalmi változások történtek a közlekedésben is. Az utakon megjelentek a legelső gépkocsik, és a 20. század elején megkezdődött a légtér meghódítása is. A korszakban új iparágak is születtek. Ilyen volt a gyorsan fejlődő vegyipar, amely az üzemanyaggyártáson túl megkezdte a műtrágyák és növényvédő szerek előállítását is, amivel a mezőgazdaság termelését segítette. Az ipari forradalom következtében szinte robbanásszerűen megnövekedett a népesség. Az emberek életkörülményein sokat javított a nagyvárosok átépítése, az ivóvíz- és szennyvízhálózat fokozatos kiépítése is. A biológia és az orvoslás fejlődése következtében sikerült azonosítani sok tömegjárvány kórokozóját, és kidolgozni az ellenük való védekezési módokat. Több súlyos fertőző betegségnek pedig az ellenszerét is megtalálták. Kifejlesztették a diftéria és a veszettség elleni oltásokat.\n\nKörnyezeti szempontból a következmények:\n\nElektromos áramot előállító hő- és vízerőművek építése. pl. Franciaországban 1897-ben árapályerőművet is építettek. A hőerőművek meghatározónak bizonyultak a 20. század légköri szennyeződéseiben.\n\nA robbanómotor (Otto-motor, 1876) majd a dízelmotor (Diesel, 1897) az új energiahordozó: a kőolaj származékainak világméretű jelentőségét alapozta meg. 1877-től szigetelt tartályhajókkal szállították a kőolajat. Az olaj és származékainak környezetszennyezése végigkíséri a 20. századot is.\n\nAz elektromágneses hullámok (Hertz, 1887), a röntgensugár (Röntgen, 1895), majd a radioaktivitás felfedezése (Bequerel, 1896; Marie Curie, 1898) mindezek 20. századi sokoldalú alkalmazását alapozták meg.\n\nA német Otto Walkhoff 1900-ban megállapította, hogy a rádium sugárzása biológiai szöveteket roncsol. Fel kell hívni a figyelmet a radioaktív sugárzás és az elektromágneses hullámok egészségügyi hatásaira.\n\nA kémia tudományának fejlődése pl. Mengyelejev orosz és Meyer német kémikus egymástól függetlenül felfedezték az elemek periódusos rendszerét /1869/, s ezt további számos kémiai felfedezés követte.\n\nA kémiai felfedezések megalapozták a 20. századi vegyipar fejlődését, s ennek számos áttételes hatása is lett mind a társadalmi fejlődésre, mind a környezetre ez utóbbi erős elszennyezését okozva.\n\nA vízzáró beton (1892) és a vasbeton (1899) felfedezése. A 20. század meghatározó építőanyagai lettek, meghatározó szerepük lett az épített környezet gyors ütemű, s nem éppen környezetbarát terjeszkedésében.\n\nAz ebben az időben feltalált dinamitot (Nobel) először a bányászatban hasznosították, és a kőzetek könnyebb kitermelésére alkalmazták, de a robbanóanyagot a vasútépítés és a hadiipar is hamar „felfedezte”.\n\nTársadalmi problémák és megoldási javaslatok\n\nA modern gyáripar kialakulásával és a tömegtermelés megindulásával a városi munkásság létszáma a 19. század folyamán rohamosan emelkedett. A tömegesen rendelkezésre álló munkaerő következtében azonban a munkabérek alacsonyak maradtak, a munkakörülmények pedig alig javultak. Az ipari munkásság helyzetének a megoldására és a társadalmi igazságtalanságok felszámolására több politikai mozgalom is kínált megoldást.\n\nA Karl Marx és Friedrich Engels tanításait követő kommunisták azt hirdették, hogy a munkásosztálynak forradalom útján kell megszereznie a hatalmat a kizsákmányolónak tartott tőkés polgári rétegtől. A diktatórikus eszközöket is nyíltan hirdető mozgalom végső célként a teljes egyenlőségen alapuló kommunizmust akarta megvalósítani, ahol a magántulajdon helyett a közösség egésze fog rendelkezni megtermelt javak felett.\n\nA szociáldemokraták nagyrészt elfogadták Marx nézeteit, de úgy gondolták, hogy a munkásság hatalomra jutása békés eszközökkel is elérhető a demokrácia keretei között. Azaz elutasították a kommunisták forradalmi és diktatórikus törekvéseit. Éppen ezért a munkások érdekeinek a képviseletére szakszervezeteket és szociáldemokrata pártokat kell alakítani. Legfőbb követeléseik közé tartozott a választójog megadása a munkásság részére, valamint a munkakörülmények javítása, a munkaidő csökkentése és a bérek emelése.\n\nA keresztény egyházak is érzékelték az ipari munkásság problémáit, nehéz életkörülményeit, az ipari társadalomban megjelenő nyomort.\n\nAZ IDEOLÓGIÁK KIFEJTÉSE\n\nSZOCIALIZMUS\n\nA szocializmus (latin socius = társ) olyan eszmei áramlatok, politikai ideológiák összessége, melyek először a 19. század folyamán jelentek meg, közös elemük az individualizmusnak, a magánérdek elsődlegességének elvetése, a kollektivizmus, a társadalmi egyenlőség, a szolidaritás előtérbe helyezése. A szocializmus magában foglal egy gazdasági programot – a termelési eszközök fölötti társadalmi ellenőrzés valamilyen formáját –, szociális követeléseket – társadalmi egyenlőséget, az anyagi javak igazságos elosztását – és politikai célokat – a demokrácia megvalósítását, kiszélesítését akár hagyományos parlamenti, vagy közvetlen formájában.\n\nA legáltalánosabb értelemben szocialistának nevezhetünk minden olyan törekvést, amely a társadalmi berendezkedést a szociális igazságosság szemszögéből kísérli meg átalakítani, függetlenül attól, hogy eszmeileg a marxizmus, az anarchizmus, a szociáldemokrácia vagy a keresztényszocializmus áramlatát követi. A szocializmus, mint politikai ideológia megnevezése az 1830-as években alakult ki. Először Robert Owen követőit nevezték szocialistának (1827), majd Saint-Simon követőit is ehhez az irányzathoz sorolták. Kezdettől fogva több meggyőződést foglalt magában, mint szellemi áramlat, politikai ideológia és mozgalom rendkívül változatos formákat hozott létre.\n\nKözös elemek:\n\nBírálták a kapitalizmust.\n\nAz egyenlőséget és az igazságosságot hirdették.\n\nUTÓPISTA SZOCIALISTÁK:\n\nA szocialista tanokkal először az utópista szocialisták, főként Saint-Simon (1760-1825), Charles Fourier (1772-1837) és Robert Owen (1771-1858) foglalkoztak, akik a termelés közösségi szintre történő emelését tartották a legjobb megoldásnak.\n\nSzolidárist vállalnak a munkásokkal, a munkások helyzetén szeretnének javítani egy ideális társadalom létrehozásával, aminek megvalósulása valójában utópia.\n\nVagyoni egyenlőségre és a verseny kiiktatására törekedtek zárt közösségek létrehozásával. Pl. Owen New Lanark-i gyára, Fourier falansztere – de ezek az elméletek életképtelenek voltak a gyakorlatban, ezért nevezzük őket utópistáknak. A gazdaság fejlődése a versenyen alapult, tehát nem lehet kiiktatni.\n\nA társadalmi problémákat a magántulajdon korlátozásával és a közösség, az állam szerepének növelésével akarták megoldani.\n\nFourier a falansztere kiküszöbölhetné az elidegenedést, melyben a termelékenység és az elosztás is egy humánus társadalmat eredményezhetne, a nők egyenjogúsítását is alapvető feladatnak tekintette.\n\nOwen gyakorlati megoldásokkal kísérletezett, üzemeiben szociálpolitikai reformokat, emberhez méltó körülményeket vezetett be például munkavédelem, oktatás, nevelés, magasabb bérek, mérsékelt árú termékek forgalmazása a dolgozóinak.\n\nSaint-Simon a tudósokra (szellemi vezetőkre) és az iparosokra (anyagi erőkre) bízná a társadalom vezetését.\n\nMARXIZMUS\n\nA társadalmi igazságtalanságok fokozódása életre keltette azokat az eszméket, amelyek egy harmonikusan működő, egyenlőségen alapuló társadalmat képzeltek el. A szocialista eszmék a közösségi szemléletmód kialakításában, az önző egyéni törekvések háttérbe szorításában látták a megoldást. Az elképzelések szerint igazságos társadalmat csak a magántulajdon felszámolásával, a piac és pénzforgalom megszüntetésével, valamint a javak közös elosztásával lehet teremteni. A legátfogóbb elméleti rendszert Karl Marx és Friedrich Engels dolgozta ki a 19. század közepén. A kialakítandó kommunizmust egy olyan ideális társadalmi rendszernek írták le, ahol már nem létezik államhatalom Ebben a rendszerben „mindenki képességei szerint” dolgozik, továbbá „mindenki szükségletei szerint” részesül a közös tulajdonból. Az ideológia hadat üzent a fennálló politikai rendszereknek, és radikális társadalmi forradalmat hirdetett. A Kommunista kiáltvány (1848) szerint a történelmet állandó osztályharcok jellemzik, mindig voltak elnyomók és elnyomottak; és az újkorban a proletariátus és a burzsoázia (polgárság) közötti ellentét a legélesebb.\n\n„Kísértet járja be Európát – a kommunizmus kísértete. […] Minden eddigi társadalom története osztályharcok története. Szabad és rabszolga, patrícius és plebejus, báró és jobbágy, céhmester és mesterlegény, egyszóval: elnyomó és elnyomott folytonos ellentétben álltak egymással, szakadatlan… harcot vívtak, olyan harcot, amely mindenkor az egész társadalom forradalmi átalakulásával vagy a harcban álló osztályok közös pusztulásával végződött […]. A mi korszakunkat, a burzsoázia korszakát azonban az jellemzi, hogy egyszerűsítette az osztályellentéteket. Az egész társadalom mindinkább két nagy ellenséges táborrá szakad, két nagy, egymással homlokegyenest szembenálló osztályra: burzsoáziára és proletariátusra. […] Amilyen mértékben a burzsoázia, azaz a tőke fejlődik, ugyanolyan mértékben fejlődik a proletariátus, a modern munkások osztálya, akik kénytelenek eladni magukat, éppen olyan áruk, mint minden egyéb kereskedelmi cikk. A burzsoázia pusztulása és a proletariátus győzelme egyaránt elkerülhetetlen.” (Marx Kommunista kiáltványa, 1848)\n\nA kommunista eszme radikális volt, mert kíméletlen harcot hirdetett a burzsoázia, mint elnyomó társadalmi osztály ellen. A munkásosztály (proletariátus) egy szocialista forradalommal proletárdiktatúrát vezetne be, ennek során megszüntetné a tőkés magántulajdont, és felszámolná a burzsoázia hatalmát. Marx elvetette a hagyományos zsidó-keresztény világképet, és materialista (azaz csak az anyagi világ létezését elfogadó) elveket vallott. A létező kapitalizmusban szerintük az ember „elidegenedik” az alkotómunkától. Az elidegenedés mellett a másik ember általi kizsákmányolás lépett a közösségi kapcsolatok helyére. Marx és Engels szerint a kapitalizmus tönkretette az emberi természetet, ami az általuk elképzelt kommunista társadalomban az elidegenedés és a kizsákmányolás megszüntetésével magára találna.\n\nMarx és Engels a kommunizmus ideológiáját komoly filozófiai, történelmi és közgazdasági érvekkel próbálta alátámasztani. A marxizmus 3 forrása:\n\nA klasszikus német filozófiát, Hegel dialektikáját is beépítették: tézis-antitézis-szintézis, a világ az ellentétek harca. Marx úgy fejlesztette ezt tovább és fordította meg, hogy „a lét határozza meg a tudatot”. A történelmet osztályharcok történelmének tartotta. Magasabb rendű osztálytársadalmak jönnek létre a régi társadalmak romjain. Szerinte a kapitalizmus pusztulása után megvalósul az osztály nélküli társadalom. Cél: az államhatalom megszerzése, amely a proletariátus kezébe kerül majd forradalom útján. Ő a legfejlettebb kapitalista államban, Angliában képzelte ezt el, ahol a legnagyobb számú munkásréteg élt.\n\nAz angol Smith és Ricardo közgazdasági tanai is hatottak a marxizmusra. A politikai gazdaságtan képviselői a burzsoázia szemszögéből igazolták a tőkés termelési módot, de kritizálták is annak ellentmondásait.\n\nHarmadik forrása az utópista szocializmus, melynek gondolkodói látták a munkásosztály nyomorát és a burzsoázia egyre növekvő gazdagságát, s megkísérelték megtalálni a kivezető utat a kapitalizmus ellentmondásaiból.\n\nMarx fő műve, A tőke (Das Kapital), melynek első kötete 1867-ben jelent meg. Marx abból indult ki, hogy a kapitalizmusban a tőkés a bérmunkás erejét piaci értéken vásárolja meg, majd a bérmunkást arra készteti, hogy értékének többszörösét állítsa elő pl. munkaideje meghosszabbításával, munkatempója növelésével. A munkások kizsákmányolását Marx közgazdasági alapokon vizsgálta a problémát, és azt igyekezett bizonyítani, hogy a kizsákmányolás és a tőkés rend bukása fog elkövetkezni. Az ideális társadalom megteremtéséhez szükség van egy átmeneti, politikai korszakra, ezért a szocializmust két szakaszra bontotta. Az első szakaszban, a szocializmusban még jelen van az állam és a jog, az elosztás a végzett munkateljesítmény alapján történik, még nem szűntek meg a társadalmon belüli egyenlőtlenségek. A következő szint kommunizmus, ahol már a szükségletek szerinti elosztás rendszere dominál. Egyúttal megszűnik az állam, a pénz, a piac.\n\nA második ipari forradalom során a gazdasági és társadalmi átalakulás több problémát is a felszínre hozott, amelyek kezelésére mind radikálisabb megoldási javaslatok születtek. A meglévő társadalmi egyenlőtlenségek, a kapitalista gazdálkodás árnyoldalai megerősítették a szocialista eszmék továbbélését. Európa-szerte számos baloldali szervezet jött létre, miközben a Marx és Engels által kidolgozott kommunista ideológia a 19. század második felében politikai erővé vált. Az általuk alapított nemzetközi munkásmozgalom (első Internacionálé, 1864) megpróbálta összefogni a baloldali munkáspártokat. Az egységes fellépést azonban megakadályozták a belső politikai ellentétek, a különböző frakcióharcok.\n\nAz 1917-es októberi orosz forradalom nyomán Oroszországban, a Szovjetunióban, majd a II. világháború végén, 1945 után a keleti blokk országaiban és másutt kiépült marxista –leninista autoriter politikai rendszerek hivatalosan szintén szocialistának tekintették magukat. A marxizmus harcos ateizmusa a 20. században egyház- és vallásüldözésbe fordult, és a kommunista ideológia gyakorlati megvalósítása véres diktatúrák kialakulásához vezetett. A hatalomra kerülő kommunista pártok mindenhol erőszakos eszközökkel törekedtek céljaik megvalósítására. A proletárdiktatúrák felszámolták az alapvető szabadságjogokat, és terrorisztikus uralmat építettek ki. A kommunista diktátorok a marxi utópisztikus társadalomkép nevében több tízmillió ember halálát okozták a 20. században.\n\nANARCHIZMUS\n\nA XIX. század 2. felében kialakuló anarchista mozgalom a kommunisták befolyását veszélyeztette. Az anarchizmus (hatalomnélküliség) szintén a társadalmi igazságtalanság ellen hirdetett harcot. A mozgalom forradalommal akarta eltörölni a fennálló rendszert. Ideológusai elvetették a proletárdiktatúrát, mivel úgy vélték, a kommunista párt kisajátítja majd a hatalmat. Az anarchisták egy önszerveződő, nemzetek feletti, állam nélküli társadalmi modellben gondolkodtak. Bár az anarchizmus főbb ideológusai elvetették az egyéni terrort, a 19. században az anarchisták a politikai gyilkosságokkal váltak ismertté. Az általuk elkövetett merényletek célpontjai a hatalomhoz köthető személyek voltak (például Erzsébet osztrák császárné és magyar királyné meggyilkolása Genfben). Az ideológiai viták miatt Marx elérte az anarchista mozgalom kizárását a munkásmozgalomból.\n\nSZOCIÁLDEMOKRÁCIA\n\nA nyugat-európai országokban a munkáspártok mérsékelt irányba fordultak, elvetették a hatalom erőszakos megragadását, és túlzottnak vélték az osztályharc erőltetését. A kialakuló szociáldemokrácia továbbra is a marxi elképzeléseken alapuló társadalmi igazságosság mellett állt ki, de annak megteremtését demokratikus úton képzelte el. Elutasította az osztályharcot, és legfőbb követelései az általános választójog bevezetésére, a parlamenti többség kialakítására, és a szociális intézkedések meghozatalára irányultak. A baloldali mozgalmon belül hamarosan újabb szakadás következett be, a kommunista ideológusok megalkuvónak tartották a szociáldemokratákat. A közösen megfogalmazott alapcélok (például a nyolcórás munkaidő követelése; május 1-jét a munka nemzetközi napjává nyilvánították) ellenére sem tudta a második Internacionálé a mozgalom egységét visszaállítani (1889).\n\nA KERESZTÉNYSZOCIALIZMUS\n\nAz egyház is reagált a változásokra. A 19. század utolsó harmadában gyökeresen átalakult a nyugati kultúrkör értékrendszere, a világról alkotott elképzelése. A tudományos ismeretek bővültek. Pl. Charles Darwin evolúciós elmélete (A fajok eredete, 1859) és az ember származásáról szóló műve (1871), majd az ősrégészet eredményei új megvilágításba helyezték a bibliai teremtéstörténetet.\n\nA világias nézetek terjedése minden egyházat érintett. A kiépülő polgári államok több feladatot átvettek az egyházaktól például oktatás, kötelező polgári házasság.\n\nA katolikus egyház vezetője, IX. Pius pápa hiába foglalta jegyzékbe a hívők számára az általa tévedésnek tartott eszméket (például ateizmus, szocializmus, kommunizmus, liberalizmus stb.), a folyamatot ez csupán lassította.\n\nA munkáskérdés megoldását sürgető „szociális katolicizmus” német területen bontakozott ki az 1860-as években. Az iparosodás társadalmi-szociális problémáira XIII. Leó (1878–1903) reagált az egyik nagy hatású körlevelében, a Rerum Novarumban, 1891-ben.\n\nA XIII. Leó pápa védelmébe vette a munkásságot, jogosnak ismerte el törekvéseiket, és méltányos bérezést sürgetett. A kibontakozó keresztényszocialista mozgalom az egyház szociális tanításának megvalósítását, az iparosodás során leszakadó társadalmi rétegek emberséges megsegítését tűzte ki célul. A keresztény alapokon álló mozgalom elutasította a liberalizmust, és felemelte szavát az ateizmust hirdető marxizmussal szemben: „Ha a társadalmi törvényeket a hit szilárd alapjára építjük, akkor nyitva áll az út a társadalmon belüli viszonyok helyes elrendezése, a békés együttélés és a virágzó jólét biztosítása felé.”', 146, 1, '2026-04-17 09:40:12', '2026-04-17 09:40:12');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(8, 8, 'Életmód és mindennapok Magyarországon a 20. században', '8.docx', '8. Életmód és mindennapok Magyarországon a 20. században\n\n(Horthy-korszak, 2. világháború, Rákosi- és a Kádár-korszak)\n\nA Horthy-korszak (1920-1944) életmódja rendkívül differenciált volt, a dualizmuskori „torlódó társadalom” megmaradt: az arisztokrácia, a nagypolgárság, a dzsentri, a közép- és kispolgárság, a munkásság, és a nagyszámú, szegény parasztság között óriási különbségek voltak. A legszegényebbek (tanyasi lakosság, nincstelen parasztok) sanyarú körülmények között éltek, míg az elit tagjai (arisztokraták, nagypolgárok, gazdasági vezetők) luxusban, a városok polgári élete (bálok, színház, mozi) és a vidéki élet (kocsma, lakodalmak) keveredett, a modernizáció (rádió, autó) lassan szűrődött be, de a társadalmi mobilitás korlátozott volt. Társadalmi rétegek és életmód:\n\nArisztokrácia és nagypolgárság (elit): Politikailag még befolyásosak, a dualizmusban alapozott vagyonukból éltek, elzárkóztak, magas életszínvonalon. A nagypolgárság (zsidó és német családok, pl. Weiss, Dreher) erősen jelen volt a gazdasági életben.\n\nKözéposztály (polgárság): A városokban élők száma nőtt. Havi 200 pengő fix fizetés már tisztességes polgári életet biztosított, de kevesen kerestek ennyit. A vágy a feljebb jutásra, a modernizációra (városba költözés) jellemezte őket.\n\nMunkásság: A városokba vándorlók jelentős része ide tartozott.\n\nParasztság: A népesség több mint fele, de többségük (72%) kevés, 5 holdnál kevesebb földdel rendelkezett, nehezen élt meg. A földkérdés megoldatlan maradt, óriási különbségek voltak a birtokosok és a nincstelenek között.\n\nTanyavilág lakossága: A legnehezebb körülmények; szegényes, zsúfolt, fűtetlen házak, a természettel és az évszakokkal való szoros összefüggés jellemezte őket.\n\nÉletmód a második világháború idején Magyarországon\n\nA Rákosi-korszak: 1949-1953, 1955-1956\n\nA kommunista diktatúra kiépülése Magyarországon\n\n1945-ben Magyarország vesztes országként került ki a második világháborúból is. A jaltai egyezmény (1945) értelmében a győztes nagyhatalmak közül a szovjet érdekszférába került Magyarország, így a keleti tömb része lett Csehszlovákiával, Lengyelországgal, Németország keleti részével (NDK), Jugoszláviával, Romániával, Bulgáriával és Albániával együtt. A német megszállás alól a szovjetek szabadították fel az országot, de egyben meg is szállták. A Szövetséges Ellenőrző Bizottság és a szovjet katonaság jelenléte (1991-ig) biztosította a kommunista párt hatalomra kerülését, és a sztálini rendszer kiépítését. 1945-47 között még működtek a demokrácia intézményei, koalíciós kormányzás jöhetett létre a Független Kisgazdapárt vezetésével, de a kommunista párt fokozatosan kiszorította a pártokat (szalámi taktika). A kommunisták a Baloldali Blokk megszervezésével (1946) elhatárolódtak a kisgazdáktól, majd 1947-ben sorozatos támadásaikkal elérték a párt lassú felbomlását.\n\nA koalíciós időszakban az MKP célja az FKgP meggyengítése, a kisgazda parlamenti többség megszüntetése volt. Ehhez felhasználták a fegyveres testületeket (megfélemlítés) és a többi pártba beépített ügynökeiket (bomlasztás). Egy-egy politikus vagy kisebb csoport leválasztását a Kisgazdapártról szalámitaktikának nevezte Rákosi. A kormányon belül létrehozták a Baloldali Blokkot (MKP, MSZDP, NPP). A földosztás szabálytalanságait kivizsgálni akaró kisgazda minisztert, Kovács Bélát azzal a váddal mondatták le, hogy vissza akarja állítani a nagybirtokrendszert. („Földet vissza nem adunk!”) A megbízhatatlan hivatalnokokat eltávolították az államigazgatásból (B-listázás), ennek ürügyén a kisgazda szimpatizánsokat is. Rajk László belügyminiszter egy szovjet katona meggyilkolásának ürügyén betiltotta az összes civil szervezetet. A SZEB megtiltotta a parasztság érdekvédelmi szervezetének megalakítását. Elfogadták a „demokratikus államrend védelméről” szóló törvényt, ami később lehetővé tette a politikai ellenfelek elítélését.\n\nKözben 1947. február 10-én aláírták a világháborút lezáró párizsi békét. Helyreállították a trianoni határokat (sőt a pozsonyi hídfőt is Csehszlovákiához csatolták). A békeszerződések nem tartalmaztak kisebbségvédelmi kikötéseket, mivel a szövetségesek attól tartottak, hogy ezek újabb viszályok ürügyeivé válhatnak. A békekötés után fordulat következett be.\n\n1947 - a fordulat éve, egyre inkább érezhető a hidegháború hatása, a Szovjetunió vezetésével keleti és az USA vezetésével nyugati tömbre szakad a világ: ez az integrálódás.\n\nA magyar kommunisták számára kedvező lett a nemzetközi helyzet arra, hogy kíméletlenül, ügyes taktikával építsék ki a párt- és rendőrállamot. Először a „háborús bűnösök” ellen, majd a koalíción kívüli „reakció” ellen, majd a koalíciós partnereik ellen fordultak. A Szövetséges Ellenőrző Bizottság (SZEB), majd az ÁVH támogatása célhoz segítette őket. Az osztályharc éleződésének elméletével, ellenfeleik megsemmisítése után a saját pártjuk soraiban keresték az „ellenséget\". Az éberség lett a legfőbb kommunista erény. Az 1947-es kékcédulás választásokat ugyan megnyerték a kommunisták, de csak 22%-ot szereztek, a koalíciós pártokkal együtt azonban 60 %-os többséget szereztek. A választások során visszaélések is történtek, ugyanis nem állandó lakhelyen is lehetett szavazni, kék cédulával. A kommunisták teherautóval járták a településeket, hogy kék cédulával szavazzanak. Az ellenzéki mandátumok egy részét pedig érvénytelenítették. Ezzel világossá vált, hogy a kommunisták a továbbiakban már nem kívánják betartani a törvényességi formákat. A támadások miatt az ellenzéki pártok többsége 1948-ra ellehetetlenült, s feloszlatta önmagát. Rákosi Mátyás a fordulatot a két baloldali párt (a kommunista és a szociáldemokrata párt) egyesülésével, a Magyar Dolgozók Pártjának létrejöttével (1948. június 12.), és a megmaradt szervezetek Népfrontba tömörítésével fejezte be (1949). Ezzel gyakorlatilag kialakult az egypártrendszer. Ilyen előzmények után az 1949-es választás már pusztán formalitássá vált, s szerepe pusztán a kommunista diktatúra legalizálása volt az 1949-es alkotmánnyal együtt, mely a szovjet alkotmány másolata. Az alkotmány szerint a munkásosztály vezette az államot. Az államforma Népköztársaság lett.\n\nA Rákosi-rendszer lényege:\n\nA Rákosi-féle Magyarország a szovjet csatlós országok egyike volt. Szovjetunió és Sztálin tudatosan támogatta a kommunista hatalmi elitet. Elzárták a nyugati kapcsolatok lehetőségét. Magyarország politikai, katonai megszállás, azaz szovjet befolyás alatt állt.\n\nA vezetők hatalmukat a dolgozó néptől eredeztették, fő célul a szocializmus építését tűzték ki.\n\nA Rákosi-korszakban egypárti diktatúra, azaz pártállami rendszer épült ki. A Magyar Dolgozók Pártjának vezetői irányították az országot. Ténylegesen a pártfőtitkár kezében volt a hatalom. Az állampárton kívül más párt nem működött, és nem működhettek a párttól független társadalmi szervezetek sem.\n\nAz államfői hatalmat az Elnöki Tanács gyakorolta, a kormányt minisztertanácsnak nevezték. Az Elnöki Tanács tagjait az országgyűlés választotta, a minisztertanács és tagjai rendeleteket adhattak ki, megszűnt a köztársasági elnöki tisztség. Az Elnöki Tanács átvette az országgyűlés jogkörét, és törvényerejű rendeleteket alkotott. A törvényhozó hatalom szerepe így formálissá vált. A rendeleti kormányzás a diktatúra jellemzője.\n\nNövelték az államigazgatásban és a gazdasági irányításban a párthoz hű alkalmazottak létszámát, a pártapparátus irányította a közigazgatást.\n\nLétrejött a tanácsrendszer: a tanácsok a településeket és a megyéket irányították. A tanácsok a helyi érdekek érvényesítése helyett pártutasításokat hajtottak végre.\n\nLétrejött a Legfelsőbb Bíróság, de nem érvényesült a bírói függetlenség elv.\n\nLétrejött a személyi kultusz: szobrok készültek Rákosiról, akinek 60. születésnapját országszerte ünneplés kísérte.\n\nA megfélemlítés fő végrehajtó szerve az ÁVH volt. Törvényes eljárás nélkül elvittek vagy eltávolítottak tisztségükből embereket, az áldozatokat megkínozták. A megfélemlítést a párt funkcionáriusaival szemben is alkalmazták. Az egyes emberek teljesen kiszolgáltatottak voltak a hatalommal szemben.\n\nA rendszerre jellemző volt a terror. Nem érvényesültek az alapvető emberi jogok.\n\nA megfélemlítés eszközei pl. internálások; kényszermunka; koncepciós perek, mint pl. Rajk-per; recski munkatábor. Koholt vádak, hamis bizonyítékok alapján politikai okokból ítéltek el embereket. Sokak számára kényszerlakhelyet jelöltek ki, sokakat a Horthy-rendszerben betöltött tisztségük miatt telepítettek ki, mert le akartak számolni az „osztályellenségekkel”.\n\nA koncepciós perekben iktatták ki a politikai ellenfeleket.\n\nSztálin (december 18.), majd Rákosi (március 9.) születésnapjának ünneplését országossá alakították: személyi kultusz.\n\nA Rákosi-rendszer belpolitikája\n\nA hamis sajtó, rádió csak részben tudta elhitetni a lakossággal a hatalmas fejlődést, miközben az életszínvonal folyamatosan esett. . A vezetés az MDP, a Párt kezében volt.\n\nA vezetés a 4-es fogat kezében van: Rákosi Mátyás, Gerő Ernő, Révai József, Farkas Mihály.\n\n1949-ben megalakult a Népfront, melynek pártjai közös listán indultak a választásokon: „egyindulós lóverseny”. Ellenzéki pártja nem volt. Elkezdődött a szocializmus építésének programja. 1949. augusztus 20-án az államforma a népköztársaság lett. Szovjet típusú alkotmányt és címert vezettek be. Az állam élén az Elnöki Tanács állott, és annak elnöke törvényerejű rendeleteivel még a látszatparlamentet is kiiktatta. 1950-ben összevonással 19 megyét szerveztek. Kiépült a tanácsrendszer, hihetetlenül felduzzadt a hivatalnoki és alkalmazotti létszám. A tanácsok nem önkormányzati, hanem a központi akaratot végrehajtó szervek voltak. 1952-ben Rákosi magához ragadta a párt és az állam tényleges vezetését, kormányfő lett. Hatvanadik születésnapjának megünneplése a személyi kultuszról tanúskodik.\n\nLeszámoltak az egyházakkal, mint ideológiai ellenséggel, letartóztatták Mindszenthy József bíborost, aki tiltakozott az iskolák 1948-as államosítása ellen.\n\nA párt módszere az erőszak, a megfélemlítés. Eszköze: 1946-tól az ÁVO (Államvédelmi Osztály), 1950-től az ÁVH (Államvédelmi Hatóság, vezetője Péter Gábor) A megfélemlítést a koncepciós perek sora biztosította, melynek során koholt vádak alapján állítanak bíróság elé embereket. Az első áldozatok között volt a párt népszerű vezetői közé tartozó Rajk László korábbi belügyminiszter. Rákosi a szovjet-jugoszláv viszony megromlását használta fel ürügyként. A kitelepítés, az internálás a rendszer lényegéhez tartozott, pl. Recsk, Hortobágy. Munkatáborokat hoztak létre, ahol „malenkij robot”-ot kellett végezni, többen a szovjet munkatáborokba is kerültek. A megfélemlítés eszköze volt a börtön, a kínzás, a halálbüntetés.\n\nA mindennapi élet a szovjet mintájú átalakítást jelentette. 1947 és 1949 között államosították a bankokat, ipari, kereskedelmi vállalkozásokat, gyárakat, üzemeket. 1948-ban megindult a parasztság szövetkezetekbe kényszerítése, kuláküldözések zajlottak. Az első ötéves terv (1950-1954) tervszámai irreálisak voltak, túlnyomóan a nehézipart fejlesztették elavult szovjet technológiával. A beruházásokat nem volt miből fedezni (a Marshall-segély a keleti blokkban nem volt igénybe vehető); csak a mezőgazdaság kárára (beszolgáltatási kényszerrel, padlássöprésekkel), a bérek alacsonyan tartásával és kötelező békekölcsön-jegyzésből tudták finanszírozni őket. A túlhajszolt (közel 100 %-os növekedést produkáló) iparosítás és az ésszerűtlen mezőgazdasági kezdeményezések (pl. gumipitypang- és gyapottermesztés) miatt - miközben új városok nőttek ki a földből (pl. Sztálinváros) - ellátási problémák jelentkeztek. Újra bevezették a jegyrendszert, az életszínvonal 20%-kal csökkent.\n\nA Rákosi-korszakban az abortusztilalom miatt rendkívül megnőtt a háború utáni időszakban amúgy is magas születésszám (Ratkó-korszak), a második világháború miatt ugyanis alacsony volt a szülőképes korosztályok létszáma.\n\nIPAR: ÁLLAMOSÍTÁSOK, TERVGAZDÁLKODÁS, A NEHÉZIPAR FEJLESZTÉSE\n\nAz első 3 éves tervet 2,5 év alatt sikerült teljesíteni: ez a 2. világháború utáni újjáépítési program volt. 1950-ben indult az ötéves terv, mely az erőltetett iparosítás meghirdetését jelentette. Felsőbb rendelkezésre tervutasításos rendszer jön létre. Cél: Magyarország a vas és acél országa legyen, ezért nagy ipari beruházások kezdődnek. A nehézipart 100%-osan államosítják. Az államosítás menete: 1946-ban a szénbányákat, a legnagyobb nehézipari üzemeket, 1947-ben a nagybankokat, nagyvállalatokat, 1948-ban a középüzemeket, 1949-ben a kisüzemeket államosítják. Megszűnik a tőzsde, a magántulajdon. Az ipar tehát szocialista jellegű átalakításon megy végbe. Létrejön az állami tulajdon túlsúlya. Az üzemek élére nem szakmailag, hanem politikailag megbízható embereket állítottak. Nem a minőségre, hanem a mennyiségre törekedtek a termelés során. Az ország gazdasági sajátosságait nem veszik figyelembe, a nehézipart egyoldalúan fejlesztik szovjet mintára, katonai célokból.\n\nA hidegháború légkörében a hadsereg megerősítésére volt szükség, ezért kellett a nehézipart fejleszteni.\n\nA néphadsereg, a BM és az ÁVH ellátására 21 hadiüzem épült. 1953-ban a néphadsereg többet költött fizetésre, mint az állam 5 év alatt az oktatás fejlesztésére. A túlzott iparosítás következtében csökkent az életszínvonal, s a szolgáltatások színvonala. A fogyasztási cikkek, a könnyűipari termékek mennyisége, minősége elmaradt a lakossági igényektől. Munkaversenyeket hirdettek meg, hogy túlteljesítsék a tervet („a határ a csillagos ég”), a béreket azonban visszafogták. Folyamatosan növekedett a munkáslétszám. A nők tömeges munkába állása felgyorsult. Tőkét vontak el a mezőgazdaságból is a szélesre nyitott agrárolló segítségével, valamint a támogatás csökkentésével.\n\nA keleti tömb országaiban, 1949-ben megalakult KGST, a Kölcsönös Gazdasági Segítség Tanácsa. Ez a szocialista országok kereskedelmét hangolta össze, de főleg a Szovjetunió kiszolgálói lettek. 1947-ben szovjet nyomásra elutasították a nyugati tömbből érkező amerikai segélyt, a Marshall-segélyt, ez gazdasági téren is integrálódást jelentett Magyarország számára.\n\nMEZŐGAZDASÁG: KOLLEKTIVIZÁLÁS, KULÁKÜLDÖZÉS, VISSZAFEJLŐDÉS\n\nSzovjet mintára megindul a kollektivizálás, azaz a földek közös tulajdonba kerülnek. Erőszakos szövetkezetesítési program indul, a földek állami tulajdonba kerülnek. Kötelező beszolgáltatási rendszert vezetnek be, s aki nem teljesíti, azt szabotálónak tartják, s börtönbe, munkatáborba kerülhet. A gazdag parasztokat, azaz a kulákokat üldözik, megbélyegzik, arra kényszerítik őket, hogy földjeiket állami tulajdonba adják. Adózással, zaklatással, perekkel felszámolták az árutermelő középparasztságot. Az ÁVH a falvakban is éreztette mindenhatóságát. A bíróság szigorú, gyakran halálbüntetést hozott a „kulákbűncselekmények” megtorlására. Az évszázados paraszti életforma szétverése eredménnyel járt. Falusi tömegek menekültek az iparba. A szövetkezetekben a termelés jóval elmaradt a korábbi szinttől. 195l-ben ezért be kellett vezetni a jegyrendszert.\n\nA Rákosi-kormányzat a sztálini modell másolásával, a terrorral ellenállást váltott ki, ami 1956-hoz vezetett.\n\nA Kádár-korszak: 1956-1988.\n\nKádár-korszakon a Magyarországnak az 1956-os forradalom és a rendszerváltás közötti történelmét meghatározó időszakot értjük: 1956-1988. Magyarország ekkor a Szovjetunó érdekszférájába tartozott\n\nA korszak különböző időszakai meglehetősen különbözőek. A forradalom megtorlását (1956-1963) követően a rendszer konszolidációjára került sor (1963-1968). Az 1968. január l-jén beinduló új gazdasági mechanizmus a szintén 1968-as prágai tavasz következményeként az 1970-es évek közepére kudarcba fulladt, 1978-tól a gazdaságpolitika célja már csak a fizetőképesség és a pénzügyi egyensúly fenntartása volt. A 1980-as években a rendszert mélyülő konfliktusok, gyorsuló reformok jellemezte.\n\nKádár csak két rövid időszakra állt a kormány élére, az Elnöki Tanácsnak pedig csak „egyszerű tagja” volt. Ennek ellenére 1956 vége és 1988 között az MSZMP első titkáraként egyértelműen ő volt az ország vezetője. Ezért nevezzük ezt az időszakot Kádár-korszaknak.\n\nA Kádár-korszakban a politikai rendszer és az uralkodó ideológia a Rákosi-rendszerhez képest abban nem változott, hogy megkérdőjelezhetetlennek számított az egypártrendszer, a parlament szerepe jelentéktelen maradt, cenzúra működött, a külpolitikában pedig meghatározó volt a Szovjetunióhoz fűződő „barátság”.\n\nUgyanakkor sokat változott a hatalmon lévők stílusa, a hatalom gyakorlásának módszere: Kádár ügyelt arra, hogy ne épüljön ki körülötte olyan személyi kultusz, mint Rákosi körül; a párt- és állami vezetők kirívó kiváltságai mérséklődtek; a terror „csak” a hatvanas évek elejéig volt tömeges, a politikai üldöztetés többnyire a rendszer ellenfeleit sújtotta, az alkalmazkodó állampolgárokat azonban nem. A hivatalos kommunista rendszer a munkásosztály hatalmát testesítette meg.\n\nA hétköznapok átpolitizáltsága is csökkent. Az emberektől csupán azt várták el, hogy ne legyenek ellenségesek a rendszerrel szemben. Míg a rákosista korszak politikája az „aki nincs velünk, az ellenünk van” szlogennel fejezhető ki, addig a híressé vált kádári szólam szerint: „aki nincs ellenünk, az velünk van”. A szocialista országokba könnyebb volt eljutni, ehhez az ún. piros útlevelet kellett kiváltani. Ha viszont valaki „nyugati” országba akart utazni, akkor ezt az ún. kék útlevéllel tehette meg. Erre azonban csak a hetvenes évektől, és csak háromévente kerülhetett sor, szűkös valutakerettel. A politikailag megbízhatatlanoktól - akik közé sokszor olyanokat is beleértettek, akiknek pl. „disszidált” valamelyik rokona - a rendőrség bírósági döntés nélkül megtagadhatta az útlevél kiadását.\n\nA viszonylag bőséges és folyamatos áruellátás és a viszonylagos szabadság a Kádár-kori Magyarország védjegyévé vált. Magyarország lett „a legvidámabb barakk” a szocialista tömbön belül, ezért is emlegették az itteni rendszert „gulyáskommunizmus”-nak, illetve „fridzsiderszocializmus”-nak.\n\nKádárnak, aki 1956 végén az ország egyik leggyűlöltebb alakja volt, a hatvanas-hetvenes években nőtt a népszerűsége. Az emberek vele azonosították a lassú gyarapodást és a hétköznapi élet viszonylagos nyugalmát. A hatvanas évek során kialakult egyfajta hallgatólagos közmegegyezés: a rendszer eltűri, hogy az emberek saját jólétükkel foglalkozzanak, cserébe elfogadják a fennálló hatalmat, s „elfelejtik” annak eredetét.\n\nSokan állítják, hogy a rendszer a legjobb lehetőségnek számított a fennálló keretek között, s a lehető legtöbbet nyújtotta az embereknek – a szovjet megszállás körülményei között.\n\nAz MSZMP, bár a korszakban pártnak nevezték, valójában nem csupán politikai párt volt, hanem a legfontosabb államhatalmi szerv is. Szervezetei minden szinten összefonódtak az állami szervekkel, ezért is beszélnek a rendszeri kapcsán pártállamról.\n\nA párt taglétszáma 1957-ben 350 ezer fő volt, 1985-ben 871 ezer.\n\nA párt ifjúsági szervezete 1957-ben Kommunista Ifjúsági Szövetség (KISZ) néven jött létre. A tagság együtt járt bizonyos előnyökkel, az egyetemi felvételhez „ajánlott” volt. A 10-14 éves korosztályt az úttörő, a 6-10 éveseket a kisdobos mozgalom szervezte.\n\nA szakszervezetek nem láthatták el valódi feladatukat, a dolgozók érdekvédelmét. A Szakszervezetek Országos Szövetsége (SZOT) kedvezményes nyaralási lehetőségeket adott.\n\nÉletmód és társadalom\n\nA konszolidáció évei kedveztek a népszaporulatnak, a GYES (fix összegű gyermekgondozási segély) 1967-es bevezetése ösztönözte a gyermekvállalást. Az 1970-es években azonban már csak a Ratkó-gyerekek gyermekvállalása tartotta egyensúlyban a születéseket és halálozásokat. Az 1960-as években a tilalom megszűnésével ez zuhanni kezdett, ám a második világháború miatt ekkor eleve alacsony volt a szülőképes korosztályok létszáma.\n\n• A Kádár-korszakban éppen ezért jóléti intézkedésekkel akarták növelni a születésszámot:\n\nLétrehozták a bölcsődék és óvodák hálózatát, hogy a munkába álló nők elhelyezhessék gyerekeiket.\n\n• Bevezették a gyest (szülési szabadság alatt kapott juttatás), és a családi pótlékot (a gyerek kiskorúsága idején kapott juttatás). A lakáshoz jutásnál előnyben részesítették a gyerekes családokat.\n\n• Mindez azonban csak átmeneti növekedést eredményezett, a születésszám tovább csökkent, majd 1980-tól már évről évre kevesebben születtek, mint ahányan meghaltak, így a lakosság fogyni kezdett. Ezt erősítette, hogy közben a halálozások száma nőni kezdett (különösen a 60 év alatti férfiak körében), csökkenni kezdett ugyanis a születéskor várható életkor. Az 1980-as évektől a negatívba forduló ráta elöregedő társadalom kialakulását alapozta meg. Nem kedveztek a statisztikának az öngyilkossági és az alkoholfogyasztási mutatók kedvezőtlen számai sem.\n\n• A rendszerváltás után a születésszám csökkenése lassult, a halálozási szám pedig újra csökkent, de mindezzel együtt is a népesség tovább fogy. Ennek eredményeképpen a társadalom elöregszik. Nő a nyugdíjasok aránya, ez megnehezíti a jelenlegi nyugdíjrendszer fenntartását: növelni kell a befizetett járulékokat, és fel kell emelni a nyugdíjkorhatárt.\n\nAz egész időszak alatt folytatódott az urbanizáció: ezt elősegítette a szocialista iparfejlesztés, a mezőgazdaság kollektivizálása vagy a Kádár-kori lakótelepépítés.\n\n- A kisebb települések népessége elöregedett, majd megkezdődött az elnéptelenedésük, mivel a fiatalok a városokba költöztek. Ugyanakkor egyre több települést nyilvánítottak várossá. A lakosság belső migrációjában új tendencia van, a zsúfolt városokból kivándorlás kezdődött az agglomeráció városi komfortot biztosító települései felé.\n\nLakókörülmények\n\nA lakhatási problémákat a szocializmus lakótelepek építésével enyhítette. Az 1970-es évek közepére sok nagyvárosban épültek panelházak. A lakás az 1980-as évek közepéig elméletileg szociális juttatásként járt, de mivel kevés volt a „tanácsi bérlakás”, nagyon sokan hosszú évekig voltak kénytelenek öröklakásra gyűjteni. Sokan fogtak családi ház építésébe is. A vidéki lakosság az állam ösztönzésére települt a városokba, elősegítve ezzel az urbanizáció folyamatát. Az 1980-as évekre már a lakások kétharmadában volt vezetékes víz és fürdőszoba. A lakások felszereltsége bővült (általánossá vált a hűtőszekrény, a mosógép).\n\nKözellátás\n\nA Rákosi-korszakot időszakonként jellemző élelemhiányt Kádár a hatvanas évekre kiküszöbölte, az élelemellátás stabillá, kiszámíthatóvá vált. A parasztságot - épp az élelemtermelés folytonosságának biztosítása érdekében - csak 1958-tól kényszerítették újra termelőszövetkezetekbe, 1962-re nagyjából be is fejeződött a paraszti magángazdaságok felszámolása. A háztáji gazdálkodás engedélyezése azonban nagyban hozzájárult az ellátás zavartalanságához. Az életkörülmények fokozatos javulásával módosultak a táplálkozási szokások is: arányeltolódás figyelhető meg a burgonya és tésztafélék felől a húsfélék, zöldségek és tejtermékek javára. Mindezek hatására beépült a köztudatba a Magyarországra, mint a „legvidámabb barakkra” jellemző gulyáskommunizmus elnevezés.\n\nMunkakörülmények\n\nA szocialista iparosító törekvéseknek köszönhetően a mezőgazdasági szektorban dolgozók átáramlása révén a munkások száma nagymértékben növekedett. A szellemi foglalkozásúk száma is megnőtt, ám a vállalati adminisztrációban dolgozók közel harmada érettségivel sem rendelkezett. A foglalkoztatási politikának köszönhetően mindenkinek volt ugyan állása, de kialakult a „gyárkapukon belüli munkanélküliség”.\n\nA mezőgazdaságra is jellemzővé vált a nagyüzemi termelés, aminek következtében szakosodás indult meg. A tervutasításos rendszer következtében - leginkább az acél-, a vas- és a vegyiparban - erőszakos fejlesztések voltak megfigyelhetők. Az állami szférán túl az 1960-as évek végétől a magánszektor is mind nagyobb jelentőségre tett szert: a maszek, azaz magánszektorbeli dolgozók körében a vendéglátóipari egységek üzemeltetésének bérbevétele, az ún. gebin volt a jellemző vállalkozási forma volt. A fusizás mellett az 1980-as évektől megjelent a gyári túlmunka hivatalos formája, a gazdasági munkaközösség (GMK) is, ami tovább növelte a második gazdaság szerepét. Az 1980-as évektől kezdve a munkásság terhei fokozatosan enyhültek: bevezették a szabad szombatot, majd a 40 órás munkahetet.\n\nOktatás, kultúra\n\nA szocializmus éveiben kiszélesedett a közoktatásban részt vevők köre, s az egyetemek is mind nagyobb számban vonzották a továbbtanulni vágyókat. A rendszer egyfajta új értelmiség megteremtésén fáradozott. A fiatalok iskolán kívüli neveléséért a kisdobos- és úttörőmozgalom, valamint a Kommunista Ifjúsági Szövetség (a KISZ) volt felelős.\n\nA kultúrpolitika egészen az 1970-es évek közepéig a párt ideológusa, Aczél György egyszemélyi irányítása alatt állt. Nevéhez köthető az ún. „három T” (tiltás, tűrés, támogatás) elvének alkalmazása bármely művészeti alkotás megjelenésének engedélyezése kapcsán. A kulturális és a művészeti alkotások egy részét támogatták, másik részét csak tűrték, az „ellenséges” alkotásokat pedig tiltották. A korszak végére a cenzúra jelentősen enyhült, a pártállam kritizálása ügyesen álcázott szófordulatok, viccek formájában folyamatosan jelen volt. Értelmiségi körökben a szamizdatok jelentették az ellenállás lehetőségét.\n\n1957-ben kezdte meg működését a Magyar Televízió, amelynek műsorait az 1970-es évek közepére csaknem minden háztartás élvezhette. 1973-tól három rádióadó is sugárzott az országban. Az 1966-ban először megrendezett táncdalfesztivál népszerű előadókat ismertetett meg a közönséggel. A fiatalok figyelmét a rockzene térhódítása, s annak hazai, nem ritkán rendszerkritikus dalszövegeket író képviselői (pl. Illés, Omega, Metró) vonták magukra. A korszak lázadó fiataljainak jelképévé a hosszú haj és a farmernadrág vált. A kulturálódás lehetőségét számos színdarab, táncházak, külföldi filmeket is játszó mozik, vidéken is elérhető filmvetítések, kultúrházak és könyvtárak színesítették.\n\nOKTATÁS\n\nA hetvenes években a felnőtt népesség többsége elvégezte legalább az általános iskola nyolc osztályát. Az egyetemi, ill. főiskolai képzésben részesülők aránya viszont alacsony. Az állam szabályozta a felsőoktatást: a nyolcvanas években a felvételizőknek csak 35-40%-át vették fel a felsőoktatásba.\n\nA gyerekszám folyamatosan csökkent, ugyanakkor csökkent azon nők aránya, akiknek nem született gyereke. Az egy-két gyerekes családok váltak jellemzővé. Az állam gyermekvállalást ösztönző szociálpolitikai intézkedései: az óvodai férőhelyek növelése, a gyermekgondozási segély (GYES) 1967-es bevezetése.\n\nA „marxista-leninista” ideológia hivatalosan meghatározta a tömegtájékoztatást, az oktatást és a művelődést, szabályozta az állami élet rendjét.\n\nA vallásnak a párt ideológiája szerint fokozatosan el kellett volna halnia. Amikor a hetvenes évek végén ismét vizsgálni lehetett az emberek vallásosságát, az eredmények meglepték a pártvezetést: a népesség mintegy fele vallotta magát vallásosnak.\n\nKözlekedés, utazás\n\nAz 1970-es évekre elterjedt a gépkocsi-használat. Az urbanizáció a nagyvárosok (kiemelt helyen a főváros) közlekedési viszonyainak rendezését követelte meg: aluljárók épültek, 1967-ben utolsóként az Erzsébet hidat is újjáépítették, 1970-ben átadták a 2-es metrót.\n\nA rendszer enyhülésével lazábbak lettek az utazási korlátozások is, így a turizmus fokozatos térhódítása figyelhető meg. Kezdetben csak a szocialista országokba lehetett utazni, majd a hatvanas évek közepétől a különutas Jugoszláviába és nyugatra is (3 évente és korlátozott devizakerettel), sőt a hetvenes évek derekától már az 56-os disszidensek is hazalátogathattak. A rendszer végén a Gorenje-korszak néven is ismert bevásárlóturizmus virágzott.\n\nSZABADIDŐ ÉS SPORT\n\nMegváltozott a szabadidő eltöltésének módja is. Új szórakozási formák alakultak ki. Az emberek mind nagyobb mértékben egyedül vagy szűk családi és baráti körben kapcsolódtak ki. A sport elvesztette azt a kiemelt támogatottságát, amelyet az 1950-es években élvezett. Az 1952-es helsinki olimpián elért teljesítményét - 16 aranyérem - a későbbiekben meg sem közelítette a magyar csapat. A magyar társadalomra a hatvanas évektől nagy hatást gyakorolt a nyugati fogyasztói kultúra. A farmer, a rockzene, a fiúk hosszú hajviselete, a miniszoknya kezdetben nem csak a hivatalos szervek, de a felnőtt korosztály egy részének a rosszallását is kiváltotta.\n\nA fogyasztói javak egy részét megpróbálta a hazai ipar helyettesíteni. A szocialista tömbön belül sokáig egyedinek számított, hogy Magyarországon gyártottak farmernadrágot. A nehezen beszerezhető nyugati termékek - orkánkabát, nejlonharisnya, farmer, rágógumi, lemezek, kazetták, kvarcórák, zsebszámológépek - jelentős részben a bevásárló-turizmus és a csempészet révén kerültek forgalomba.\n\nA mindenkinek kijáró nyári szabadságot a külföldi utazási korlátok miatt legtöbben belföldön, jellemzően a Balaton partján épült (szakszervezeti) üdülőkben töltötték el. A fiatalokat a zánkai vagy csillebérci gyermektáborok várták. Sokan töltötték szabadidejüket túlmunka végzésével, akár a hétvégi házak, üdülők környékén is.\n\nA Kádár-korszak a többi szocialista országhoz képest jóval élhetőbb körülményeket biztosított az életszínvonal mesterséges szinten tartásával. Aki nincs ellenünk, velünk van politikája volt jellemző. A „fridzsiderkommunizmus” azonban csak az állam eladósításával volt finanszírozható.\n\n„FRIZSIDERSZOCIALIZMUS”\n\nA XX. század utolsó harmadában a mezőgazdasággal foglalkozók aránya jelentősen csökkent. Az ipari munkások aránya 1970-ben volt a legmagasabb. Ezzel szemben a harmadik szektorban (szolgáltatás, kereskedelem, egészségügy, kultúra, oktatás, közig gátas) folyamatosan nőtt a foglalkoztatottak száma.\n\nA korszakban jelentősen csökkent a szegénység. A Kádár-rendszerben emelkedett szinte valamennyi civilizációs mutató: javultak a lakásviszonyok, a tartós fogyasztási cikkekkel való ellátottság; 100%-os lett a társadalombiztosításban részesülők aránya; javult az iskolázottsági szint; általánosan elterjedt a nyaralás szokása, és bővült a külföldi utazások lehetősége.\n\nA hatvanas években általánossá tették a nyugdíjrendszert. De nem számoltak a lakosság elöregedésével - 1952-ben a nyugdíjasok a lakosság 5,8%-át tették ki, 1990-ben 24,3%-át, 1999-ben pedig már 31%-át. Azzal, hogy az első nyugdíjak egy jelentős részét a korábbi, alacsony bérek alapján számították ki, idővel azonban emelkedtek a bérek, és a nyugdíjakat ez alapján kellett kiszámítani. Míg 1952-ben az átlagnyugdíj az átlagbér 23%-át tette ki, addig 1983-ban már 58,6%-át Míg 1960-ban a nemzeti jövedelem, tehát a GDP 2,5%-a ment nyugdíjakra, 1990-ben már 9,7%-a.\n\nAz életszínvonal emelkedésének árát azonban nemcsak az állam fizette meg, hanem az emberek is, akiknél jelentős része önkizsákmányoló munkát végzett az ún. „második gazdaságban”. „Második gazdaság” alatt a háztájiban, a kisiparban és kiskereskedelemben - legtöbbször nem fő-, hanem mellékállásban - végzett munkát értették, de ide számították a csempészetet és a fusizást is, vagyis a magáncélú termelést az állami tulajdonban lévő eszközökön, munkaidőben. A második gazdaság meghatározó jelentőségű volt például a lakásépítések terén. A hetvenes években a magyar családok mintegy háromnegyede szerzett jövedelmei a második gazdaságból.\n\nA növekvő életszínvonal, a javuló társadalmi közérzet egyelőre elfedte, hogy az elvileg mindenkinek járó társadalmi szoláltatásokhoz mégsem egyenlő mértékben lehet hozzájutni: a keményebb érdekérvényesítésre képes pártelit előnyökhöz jutott.\n\nA hiánygazdaság miatt még a javuló ellátás mellett is gyakran csak hosszas várakozás után lehetett hozzájutni a keresett áruféleségekhez, szolgáltatásokhoz, pl. autóhoz.\n\nEgy átlagos magyar család a szocializmus éveiben többéves várakozás, többéves gyűjtögetés után juthatott autóhoz. Sokaknak csak a keletnémet gyártmányú Trabantra tellett. A kommunista korszak végén a magyar utakon futó kb. kétmillió személygépkocsi csaknem ötöde Trabant volt.\n\nIngázók jártak a városokba dolgozni. A városi lakásépítések ugyanis nem tartottak lépést a városi munkahelyek számának gyarapodásával és a falusi munkahelyek számának csökkenésével. Tömegek kényszerültek arra - a hetvenes évek elején közel egymillió dolgozó, hogy lakóhelyük és munkahelyük között naponta „ingázzanak”.\n\nAz 1960 és 1980 között a várható élettartam ismét csökkent, különösen a középkorú férfiak halálozási arányai romlottak. A halandósági mutatók romlása a rendszer közvetett következménye volt. Nőtt a deviáns jelenségek száma: az öngyilkosságok és az alkoholizmus. Az alkoholisták száma folyamatosan emelkedett, becslések szerint 1988-ban több, mint félmillióan szenvedtek ebben a betegségben. A korszakban a családok élete is jelentősen megváltozott: nőtt a válások száma, 1950-1988 között mintegy a duplájára. Az egészségügy nem tudta mindenkink megadni a törvényben előírt színvonalas ellátást. (Innen a „hálapénz” rendszerré válása.)\n\nGazdaságpolitikája:\n\nKádár tanult a forradalom előtti hibás gazdaságpolitikából, a szövetkezetek létrehozásában enyhébb módszereket alkalmazott. Bár a tervgazdálkodás 1956 után is fennmaradt, a tervutasítás csak 1968-ig. A gazdasági növekedésnek a tervgazdálkodás nem jelenthette szilárd alapját. A mezőgazdaság átszervezésekor például határozottan végrehajtották a téeszesítést, de magántulajdonban hagyták a háztáji földeket, ahol a parasztság önmaga számára és piacra is tudott termelni. Ez a politika annyira sikeresnek bizonyult, hogy a háztájinak hamarosan kulcsszerepe lett az élelmiszerellátásban.\n\nAz életszínvonal emelését és szinten tartását mindennél fontosabbnak tartó politikai szándéknak köszönhető az 1968-ban elindított gazdasági reform is. A reformok elindításában szerepet játszott a nagyhatalmi enyhülés időszaka. A gazdasági reform a hatvanas évek közepére szükségessé vált, de a reform kibontakozásának politikai akadályai voltak. Az életszínvonal emelkedésében, a politikai stabilitás megteremtésében nagy szerepet játszott a „második gazdaság”, a háztáji, a melléküzemágak és a gmk rendszere. Ez ugyanakkor a lakosság túlhajszoltságához vezetett. Magyarország eladósodásában jelentős szerepet játszott a hibás és pazarló gazdaságpolitika, a tervgazdálkodási rendszer anomáliái, a reformok leállítása. A világgazdasági folyamatok, mint pl. a kőolaj-árrobbanás is hozzájárultak a Kádár-rendszer gazdasági-politikai válságához.\n\nA rendszer értékelése:\n\nA Kádár-korszakban engedélyezték az önálló kisiparosok, kiskereskedők tevékenységét. Kádár a kispolgársággal szemben a korábbinál engedékenyebb politikát akart folytatni, felismerte a kispolgárság közvélemény-formáló szerepét. Ez a magánszektor korlátozott engedélyezését jelentette, a „kádári alku” egyik eleme volt. Kádár az engedékenység fejében a rendszer tudomásul vételét várta a kispolgároktól, ezzel a Rákosi-korszak gyakorlatán változtatott.\n\nA reálbérek az 1970-es évek második feléig nőttek, a Kádár-korszak utolsó évtizedében már csökkentek. A reálbérek növekedése az életszínvonal emelkedését jelzi, a fogyasztás bővülését vonta maga után. A reálbérek csökkenése az életszínvonal esésével járt együtt, hátterében az egyre növekvő infláció állt. Ennek következménye volt a „második gazdaság” kialakulása.\n\nA bányászok és a gyári munkások kerestek a legjobban. A legmagasabb és legalacsonyabb átlagkereset között másfélszeres különbség volt. A rendszer ugyanis a munkásosztályt tekintette fő társadalmi bázisának. A munkások viszonylag magas fizetésének ideológiai okai voltak. Ezen túl nem voltak jelentős különbségek ágazatonként az átlagkeresetek között. A rendszer nem tette lehetővé jelentős vagyoni különbségek kialakulását.\n\nAz állam támogatta a művelődési házak építését. A művelődési házak a kulturális élet és a társas élet központjai voltak. A kulturális élet szervezeti kereteit gyakran a párt ifjúsági szervezetei biztosították. Az állam igyekezett mindenki számára biztosítania művelődés lehetőségét, a kultúra az ideológia terjesztésének eszköze volt.\n\nA Rákosi-korszakhoz képest javultak az életkörülmények, a többi szocialista országhoz képest magas volt az átlagos életszínvonal. Az életkörülmények javítása politikai cél volt, ezért szokás „gulyáskommunizmusról” vagy „fridzsiderszocializmusról” beszélni. Igyekeztek megelőzni egy újabb forradalom kirobbanását.\n\nSzociálpolitikai intézkedések pl. GYES, családi pótlék, családtámogatás bevezetése, bölcsődék, óvodák építése, a társadalombiztosítás kiterjesztése. Ezzel a születések számának csökkenését próbálták megállítani, és a nők munkavállalása tette szükségessé. Ez jelentősen növelte az államadósságot.\n\nAz életkörülmények javítását szolgáló további intézkedések: az iskolahálózat bővítése, állami lakásépítések, az élelmiszerárak alacsonyan tartása, a sport támogatása. A sporteredményeket a politikai propaganda is kihasználta. Nőtt az iskolázottság, csökkent a lakáshiány. A lakáshoz jutás ennek ellenére nehézkes volt. A korszakban már nem volt jellemző az éhezés.\n\nA kultúrpolitika fő jellemzője a 3T elvének érvényesülése. A politikai szempontból semleges művek közlését engedélyezték. Nagyobb művészi, tudományos szabadságot biztosítottak a korábbiakhoz képest, de a rendszerrel szembeni nyílt kritika megjelenítését továbbra is tiltották.\n\nA ’70-as, ’80-es években nőtt a lakosság életszínvonala, de Magyarország a ’80-as évekre jelentős hitelek felvételére kényszerült és eladósodott. A viszonylagos jólétnek ára volt. Mivel a politikai vezetők a rendszer stabilitása miatt növelték az életszínvonalat.\n\nA szociális intézkedések bevezetésekor nem számoltak a hosszú távú következményekkel. A költségek növekedése folytatódott a nyolcvanas években is, amikor a gazdaság növekedése már megtorpant, ez vezetett el az 1980-as évek végén a rendszerváltáshoz, a Kádár-rendszer végéhez.', 117, 1, '2026-04-17 09:40:12', '2026-04-17 09:40:12');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(9, 9, 'A határon túli magyarok, a magyarországi nemzetiségek és a cigányság helyzete napjainkban', '9.docx', '9. tétel: A határon túli magyarok, a magyarországi nemzetiségek és a cigányság helyzete napjainkban\n\nA trianoni béke: 1920. június 4.\n\nMagyarország az Osztrák- Magyar Monarchia tagjaként vett részt az első világháborúban a központi hatalmak oldalán, így a vesztes országok közé tartozott. A háború végén, 1918-ban felbomlott a Monarchia. Magyarországon 1918-ban az őszirózsás forradalom, 1919-ben a tanácsköztársaság kikiáltása, majd a fehérterror időszaka alatt nem volt olyan kormány, amelyet a győztes antant hatalmak elfogadtak volna, hogy békét kössenek velünk. Csak 1920-ban jött létre az antant által is elfogadható törvényes kormány, s ezt követően kötöttek Magyarországgal békét 1920. június 4-én a Párizs melletti Trianoni kastélyban. A magyar békedelegáció gróf Apponyi Albert vezetésével érkezett Párizsba 1920 januárjában. A küldöttség kifejthette álláspontját a békekonferencia előtt, de ez nem befolyásolta a győztesek döntését. A magyar küldöttség visszautasította a béketervezetet. Magyarország területi integritásának szükségességét hangsúlyozták, azt, hogy nem lehet egy ország történelmi, földrajzi, gazdasági és kulturális egységét megbontani. Apponyi az elcsatolandó területeken népszavazásra tett javaslatot. Wilson USA elnök önrendelkezési elvére hivatkozott a békeküldöttség: azaz minden nép maga döntse el, hogy melyik országhoz akar tartozni. Gróf Teleki Pál elkészítette Magyarország „vörös térképét”, amely jelöli, hogy mely területeken laknak többségében magyarok (vörös színnel). Az antant vezetői azonban elsősorban a csehszlovák, román, és jugoszláv követeléseket fogadták el, és a Millerand-levélben elutasították a magyarok kéréseit és tiltakozását: mivel Magyarország vesztes ország, nincs abban a helyzetben, hogy feltételeket diktáljon.\n\nA trianoni béke következményei:\n\nMagyarország területe 283.000 km²-ről 93.000-re csökkent, lakossága 18,2 millióról 7,6-re. A magyarság kb. 1/3-a 3,3 millió fő idegen fennhatóság alá került. Magyarország elvesztette a Felvidéket, Kárpátalját, Erdélyt, a Partiumot (Részek), Bánátot, Bácskát, Burgenlandot (Őrvidéket). Romániához kb. 102.000 km² (Erdély és a Részek) és 1,6 millió magyar, Csehszlovákiához 61.000 km² (Felvidék, Kárpátalja) és 1 millió magyar, a Szerb – Horvát - Szlovén Királysághoz, ami 1929-től Jugoszlávia (Bácska, Bánát, Újvidék) 21.000 km² és 0,5 millió magyar, Ausztriához 4.000 km² (Burgenland) és 25.000 magyar.\n\nEredetileg Sopron Ausztriához kerül volna, de a magyar kormánynak sikerült 1921-re népszavazást elérnie. A lakosság a Magyarországhoz való csatlakozás mellett voksolt, ezért Sopront a „leghűségesebb város – civitas fidelissima” címmel tüntették ki. A békeszerződést a Simonyi - Semadam Sándor kormány idején írták alá, ezt követően a kormány lemondott. Az aláíró: Drache – Lázár Alfréd és Benárd Ágoston volt.\n\nA békeszerződés következményei a jóvátétel fizetésén kívül a különböző katonai (max. 35.000 fő katona) és kereskedelmi korlátozások voltak. Az etnikai elvet csak a környező népek esetében vették figyelembe, s azzal nem törődtek, hogy több millió magyar került idegen uralom alá. Súlyos gazdasági válságot okozott Magyarországon, hogy a nyersanyagforrások, bányák, vasúthálózat nagy része az országhatáron kívül maradt.\n\nA trianoni békeszerződés példátlan mértékű területvesztés volt, ezt a magyarság nem tudta elfogadni és tragédiának fogta fel. A kormányok célja ezután a revízió, azaz a béke felülvizsgálata, a határok visszaállítása volt. A békeszerződés újabb háborúba sodorta emiatt Magyarországot, és ez máig is súlyos nemzetiségi problémák forrása.\n\nTerületi tényezők:\n\n282 ezer km2-ből 93 ezer maradt meg (2/3-át elcsatolták)\n\nOMM helyébe újabb soknemzetiségű kis államok jöttek létre\n\nCsehszlovákiához csatolták: É-Mo., Kárpátalja\n\nRomániához: Erdély, Tiszántúl (Partium), Bánság keleti fele\n\nSzerb – Horvát - Szlovén Királysághoz: Bácska, Dél-Baranya, Muraköz, Bánság nyugati fele.\n\nAusztriához: az ún. Őrvidéket (Burgenland)\n\nSopron hovatartozásáról népszavazást írtak ki 1921-ben > a lakosság Mo. mellett döntött-„leghűségesebb város”- civitas fidelissima.\n\nEtnikai tényezők:\n\na zömében nemzetiségek lakta területeket elcsatolták\n\na magyarok 30%-a idegen fennhatóság alá került\n\nMo. nemzetállammá vált: 92%-a magyar\n\nnemzetiségi szempontból a legigazságtalanabb béke: a soknemzetiségű Monarchia helyébe újabb soknemzetiségű államok jöttek létre\n\nTerületi változások:\n\nAz első világháborúból vesztesként kikerülő Magyarország jelentős területeket veszített el az 1920-ban kötött trianoni béke értelmében. A magyar kormányok célkitűzései ezután a revíziós politika, amely újabb világháborúba sodorja az országot.\n\nHitler segítségével az I. bécsi döntés (1938. nov. 2.) értelmében visszakaptuk a Felvidék határ menti területét, közel 12.000 km2-rel bővült az ország területe, melynek lakossága 50-60%-ban magyar volt.\n\n1939. március 15-én elfoglaltuk Kárpátalját. Ezután Németország elkötelezettjeivé váltunk.\n\nA német-olasz területi döntőbíróság 1940-ben kimondta az úgynevezett második bécsi döntést, amelynek értelmében 43 ezer km2 terület került vissza Mo.-hoz. Visszakaptuk Észak- Erdélyt és Székelyföldet. Magyarország így még jobban elkötelezte magát a Németország mellett.\n\n1941. április 11-én Magyarország bekapcsolódik a Jugoszlávia elleni háborúba, és a II. világháborúba (1939-45) Horthy Miklós kormányzó Bárdossy Lászlót nevezte ki kormányfőnek. Elfoglalták a Bácskát, a Muraközt és a baranyai háromszöget. 11.417 km2 terület került vissza Mo.-hoz. A Délvidéket megszállják a csapatok.\n\nMagyarország a németek oldalán hadviselő fél lett.\n\nA bécsi döntések (1938, 1940) következtében a magyarlakta területek nagy része visszakerült Magyarországhoz. A vissza nem csatolt területekről (pl. Dél-Erdélyből) tömegesen települtek át magyarok.\n\n1945 után\n\nA határon túl rekedt magyarok helyzete 1945 után nagymértékben romlott. 1947. február 10-én aláírták a világháborút lezáró párizsi békét. Helyreállították a trianoni határokat, sőt a pozsonyi hídfőt is Csehszlovákiához csatolták 3 faluval: Horvátjárfalu, Oroszvár és Dunacsún. A békeszerződések nem tartalmaztak kisebbségvédelmi kikötéseket, mivel a szövetségesek attól tartottak, hogy ezek újabb viszályok ürügyeivé válhatnak. A kisebbségvédelmi nemzetközi jogi szabályozás hiánya miatt ez az egyes államok belügyének számított.\n\nA helyzetet csak súlyosbította, hogy Magyarország lemondott a határon túliak védelméről, ezért a 2. világháború után akadály nélkül folyhatott az erőszakos beolvasztásuk. A magyar kisebbségek felé fordulás csak a szocialista ideológia gyengülésével, a hetvenes-nyolcvanas évektől bontakozott ki Magyarországon.\n\nMagyarország alaptörvénye a határon túli magyarokat is a nemzet részének tekinti. A magyarországi munkavállalást és a kulturális szolgáltatások kedvezményes igénybevételét tette lehetővé a magyar igazolvány. Ha kérelmezik, a határon túli magyarok állandó magyarországi lakóhely híján is kaphatnak magyar állampolgárságot (kettős állampolgárság).\n\nErdély\n\nA 2. világháború utáni időszakban 1945-47 között a román kormányok még mérsékelt nemzetiségi politikát folytattak. A kommunista hatalomátvétel után kezdődött meg a magyar intézmények felszámolása, 1950-ben a magyar kisebbség vezetői ellen pereket indítottak. Felszámolták a magyar kulturális és tudományos intézményeket, illetve megkezdődött a románok betelepítése a magyarlakta településekre. Az 1952. évi román alkotmány részeként Marosvásárhely központtal létrehozták a 4 székely megyéből álló Magyar Autonóm Tartományt (1968-ig), ahol azonban csak a nyelvhasználat jogát biztosították, viszont a többi magyar lakta területen korlátozták. Ez valódi önigazgatást nem biztosított, sőt lehetőséget teremtett az ezen kívül élők erőszakos asszimilációjára. A magyarnak számító katolikus és református egyházat azonban üldözték. Márton Áron erdélyi katolikus püspököt többször hosszú időre bebörtönözték. 1956 után a magyar kisebbséget a szeparatizmus és a revizionizmus vádjával illették. 1959-ben megszüntetve a kolozsvári magyar Bolyai Egyetem önállóságát, összevonták azt a román Babes Egyetemmel.\n\nA hatvanas évek enyhébb asszimilációs nyomása a hetvenes években erősödött, a nyolcvanas években pedig szinte elviselhetetlenné vált. Falurombolások kezdődtek, aminek következtében rengetegen menekültek Magyarországra az 1980-as években. 1988-ban a falurombolással Ceausescu román diktátor a vidéki lakosságot „agrár-ipari centrumokba” kívánta áttelepíteni a modernizációra hivatkozva. Mindez elsősorban a tömbben élő nemzeti kisebbségek felszámolására irányult, de a rendszerváltás miatt leállt. Az 1989-es romániai forradalom és rendszerváltás után változott a helyzet, de a legsúlyosabb atrocitásokra 1990-ben Marosvásárhelyen került sor (fekete március) az anyanyelvi oktatást követelő magyarsággal szemben. Ezután mégis lehetőség nyílt a kisebbségi jogok érvényesítésére, önálló intézmények létrehozására, bár a székelyföldi autonómiát nem állították vissza. Mindezek ellenére a romániai magyarok száma az évtizedek során kb. l millió 450 ezer.\n\nA rendszerváltás után\n\n• A megnyíló határok megkönnyítették a kapcsolattartást, de egyben ösztönözték a Magyarországra költözést is: éppen a fiatalabbak és iskolázottabbak hagyják el a kisebbségi létet. Ez csökkenti a magyar pártok szavazótáborát és a magyar iskolák tanulószámát.\n\n• A rendszerváltás újra lehetőséget biztosított a kisebbségi magyarság politikai érdekképviseletére, a civil szervezetek és az egyházak szabad működésére. A határon túli magyar pártok magyar szavazatokat kapnak, ami bizonyítja a kisebbségi érdekképviselet szükségességét, de egyben megakadályozza a kisebbségen belüli ideológiai különbségek megjelenítését és a kapcsolódást a többségi pártokhoz.\n\nFelvidék\n\nA második világháború után a nemzetiségi kérdésben a nagyhatalmak újra az 1919-20-as elvekhez nyúltak: nemzetállamok kialakítására törekedtek, de nem határmódosításokkal, hanem az etnikai kisebbségek áttelepítésével. Az 1945-ös potsdami konferencián kimondták a kollektív felelősség elvét, amely alapján Csehszlovákiából, Lengyelországból és Magyarországról megindulhatott a német kisebbség kitelepítése (Magyarországot összességében kb. 200 ezer német hagyta el).\n\nA csehszlovákok Benes vezetésével már 1943-ban fellépett a magyar nemzetiségűek kitelepítésének igényével. 1945 áprilisában a kassai kormányprogram a kollektív bűnösség elvére hivatkozva - az antifasiszták kivételével - megvonta a magyar és német nemzetiségiektől a csehszlovák állampolgárságot. Az erős asszimilációs nyomás mellett deportálásokra és kitelepítésekre is sor került. 1945 augusztusában Benes elnöki dekrétumai: megfosztották a németeket és a magyarokat csehszlovák állampolgárságuktól, elrendelték a német és a magyar férfiak közmunkára rendelését, bezárták a magyar óvodákat, iskolákat.\n\nAz 1946. február 27. lakosságcsere-egyezmény alapján mintegy százezer magyar hagyta el korábbi lakhelyét. Ahány magyarországi szlovák jelentkezik önkéntesen az áttelepülésre, a csehszlovákok ugyanennyi magyart távolíthattak el államukból. A csehszlovák kormány 200 ezer magyartól akart megszabadulni, de végül mindösszesen 70 ezer ember cseréjére került sor. A felvidéki magyarság vezető politikusát, Esterházy Jánost koncepciós perben elítélték, börtönben halt meg. Emellett megindult a reszlovakizációnak nevezett átnevelő program 1946. jún. 17-én. A magyarokat választás elé állították: ha (cseh)szlováknak vallják magukat, akkor visszakapják állampolgárságukat, ha nem, kiutasítják őket. Állami célkitűzés volt a magyar lakosság arányának csökkentése. A reszlovakizáció módszere: arra hivatkozva, hogy valójában elmagyarosodott szlovákokról van szó, megváltoztatták a neveket, kötelezővé tették a szlovák iskolát. Ennek eredményeképpen itt nemcsak a magyarok aránya csökkent, de létszámuk is szinte megfeleződött. Közel 400 ezer magyar nyilvánította magát „szlováknak”. A Csehszlovákiából elmenekült magyarok száma összességében elérte a 150 ezret.\n\n1949-ben létrejött a Csehszlovákiai Magyar Dolgozók Kulturális Szövetsége (CSEMADOK). Az ötvenes évektől korlátozottan a kisebbségi jogok is érvényesültek, létrejöhettek kisebbségi oktatási és kulturális intézmények, csökkent a reszlovakizáció. 1952-ben kormányhatározatban rögzítették a magyarok egyenjogúságát, elfogadták a kétnyelvűség elvét. A jogfosztások következményei azonban végig kísérték a magyar közösség életét. A rendszerváltás után is előfordult a kisebbségi jogok (pl. a nyelvhasználat) korlátozása. A felvidéki magyarok lélekszáma csökkent a rendszerváltásig: kb. 521 ezer fő maradt.\n\nKárpátalja\n\nA legnehezebb sors a kárpátaljai magyarságnak jutott. Ezen a területen a klasszikus sztálinista nemzetiségi politika érvényesült. A hadköteles életkorú férfiakat tízezrével deportálták kényszermunkatáborokba, illetve hadifogolytáborokba. Az enyhülés az ötvenes években csak lassan indult meg. A kisebbségi jogok nem érvényesültek, a kisebbségi érdekérvényesítésre tett kísérleteket megtorolták. Ukrajnában jelenleg kb. 156 ezer magyar él.\n\nVajdaság\n\nJugoszláviában a magyarságot súlyos atrocitások érték. Az újvidéki vérengzés (1942. január) miatti kollektív megtorlások eredményeként több ezer magyart gyilkoltak meg szerb partizánok. Rendszeresek voltak a betelepítések a többségükben magyar településekre. Jugoszláviában Tito ragaszkodott a nemzetek egyenjogúságának látszatához.\n\n1959-ben kimondták valamennyi kisebbség azonos helyzetét. A hatvanas-hetvenes években a helyzet jobbra fordult, az alkotmányba bekerültek a kisebbségi jogok, így lehetőség nyílt az anyanyelv használatára és az anyanyelvi oktatásra. 1974-ben létrejött a Vajdasági Autonóm Tartomány, de ez csak korlátozott önkormányzatisággal rendelkezett. A magyar lett a Vajdaság egyik hivatalos nyelve, de a hitélet és az anyanyelvi oktatás csak korlátozottan érvényesült. Ebben az időszakban gyorsult fel az asszimiláció, mert a rendszer megakadályozta a kisebbségek közösségi szerveződését. A rendszerváltás után a nemzetiségi ellentétek kiéleződtek, Jugoszlávia felbomlott. Szerbiában és Montenegróban: 290 ezer, Horvátországban: l5,5 ezer, Szlovéniában: 6,2 ezer magyar él.\n\nAusztriában kb. 40 ezer magyar él, főleg Burgenlandban.\n\nMagyarok a határon túli országokban:\n\nA magyar nyelv helyzete\n\nA magyar nép és nyelv esetében az országhatárok nem esnek egybe a nyelvhatárokkal. A magyar anyanyelvűeknek kb. a harmada él kisebbségi léthelyzetben Magyarország határain kívül. Őket őshonos népcsoportoknak nevezzük (hasonlóan a magyarországi 13 nemzetiséghez), mert több évszázada élnek ezen a területen. A kisebbségek tömbben (Székelyföld) vagy szórványban (őrvidéki magyarok, csángók) élnek a szomszédos országokban. A nyelv életképessége a tömbben nagyobb, míg a szórványokat az asszimiláció, a beolvadás és a nyelvcsere veszélye fenyegeti. Az országhatáron kívül élő magyarok általában kétnyelvű beszélőközösséget alkotnak, anyanyelvükön kívül a környezeti nyelvet, azaz az adott ország nyelvét is elsajátítják.\n\nA kisebbségek egy másik csoportja a 20-21. század folyamán politikai vagy gazdasági okok miatt hagyta el hazáját. Őket emigránsoknak nevezzük. A magyar történelemben is van példa elvándorlásra. Az 1956-os forradalom alatt közel 200 ezer magyar menekült el az országból (disszidáltak). A legújabb kori magyar emigránsok főként Nyugat-Európában (Ausztria, Németország, Egyesült Királyság, Svédország) és az USA-ban élnek nagyobb számban, összesen kb. 3 millióan a diaszpórában. Pontosan azért nem tudjuk meghatározni létszámukat, mert a kisebbségi kivándorlókat a lakóhelyük után adminisztrálják, így például egy erdélyi magyart román állampolgárként tartanak számon pl. Németországban.\n\nA magyarok száma a Kárpát-medencében\n\nA világon kb. 15 millió magyar él. Az egyes országokban általában 10 évenként tartanak népszámlálásokat. A legutóbbi (2011-és) népszámlálási adatok szerint Magyarország lakossága 9 937628 fő, ebből 8 314 029 vallotta magát magyar nemzetiségűnek. A környező országokban összesen 2.127.048 magyar él. Európa szinte minden országára jellemző a lakosság létszámának fogyása, amelyet 3 tényező befolyásé negatívan: az élve születettek számának csökkenése, az asszimiláció és az elvándorlás. A Kárpát-medencei magyarság létszáma az elmúlt 10 évben kb. 16%-kal csökkent.\n\nPolitikai változás\n\nAz Alaptörvény végrehajtására az országgyűlés által megalkotott, az országgyűlési képviselők választásáról szóló (2011. évi CCIII.) törvényt a 2014-es általános parlamenti választásokon alkalmazták először.\n\nMinden nagykorú magyar állampolgár rendelkezik választójoggal, és ezt Magyarország Alaptörvénye rögzíti. A határon túli magyarok is jogosultak részt venni a magyarországi választásokon. Magyarországon lakóhellyel nem rendelkező személyek egy pártlistára szavazhatnak.\n\nA kettős állampolgárság és az egyszerűsített magyar honosítás\n\nA kettős (vagy többes) állampolgárság azt jelenti, hogy egy személy egyszerre két (vagy több) államnak is a polgára lehet. Ennek feltétele azonban, hogy az adott államok törvényei ezt a kettős állampolgárságot lehetővé tegyék. Környezetünkben Ausztria és Szlovákia törvényei – különböző okokból – nem engedik a kettős állampolgárságot, Ukrajna alkotmánya pedig nem ismeri ezt a jogállást, tehát nem ismerik el, de nem is büntetik a kettős állampolgárságot.\n\nHazánkban 2011-től a törvények lehetővé teszik a határon túli magyarok számára az egyszerűsített (vagy kedvezményes) honosítási eljárást. Ennek során megkaphatja a magyar állampolgárságot az eredeti megtartása mellett az a személy, aki igazolni tudja magyar származását vagy valószínűsíteni tudja magyarországi származását. Ebben az esetben nem feltétel a magyarországi lakóhely, a megélhetés igazolása és a vizsga az alkotmányos alapismeretekből, mint más olyan esetekben, amikor egy külföldi kívánja felvenni a magyar állampolgárságot. Mindez a nemzetegyesítés jegyében hozott intézkedés. A korábbiakhoz képest 2011-től napjainkig több százezerrel nőtt a magyar állampolgárságot elnyert személyek száma anélkül, hogy az illetők elhagyták volna eredeti lakóhelyüket.\n\nNemzet és nemzetiség\n\nA nemzet olyan közös identitáson alapuló közösség, amely politikai közösségként határozza meg magát, és igénye van arra, hogy szuverén módon rendelkezzen magáról, legtöbbször állami formában.\n\nA nemzetiségiek az államalkotó nemzethez viszonyítva kisebbségben élő etnikai csoport. Két típust különböztethetünk még:\n\na nemzeti kisebbséget,\n\nés az etnikai kisebbséget.\n\nHazánkban 13 törvényileg elismert nemzetiség él, amelyek közül 12 nemzeti kisebbség, egy pedig etnikai (a cigányság). A törvényileg elismert nemzetiségek önkormányzatot alakíthatnak: a bolgárok, a cigányok, a görögök, a horvátok, a lengyelek, a németek, az örmények, a románok, a ruszinok, a szerbek, a szlovákok, a szlovének és az ukránok. A Magyarországon élő nemzetiségekről és etnikumokról legfrissebb és legpontosabb adataink a népszámlálás alapján vannak. A 2011-es népszámlálási adatok alapján 10 év alatt a hazai nemzetiségek száma jelentősen növekedett, érdekképviseleti szerveik különösen szorgalmazták ennek feltüntetését. A cigányok (romák) száma 2011-ben 2001-hez képest 190.046-ról 315.583-ra, míg a németeké 62.233-ról 78.5080-ra nőtt.\n\nA legnépesebb etnikum a cigányság, e gyűjtőnév számos olyan népcsoportot takar, amelynek kultúrája nagyban eltér egymástól. Legtöbbjük magyar anyanyelvű, az indiai eredetű romani vagy lovári nyelvet beszéli, de a beás (archaikus román) nyelvet csak kisebb hányaduk beszéli. A németség a legnagyobb létszámú nemzeti kisebbség, őket pedig sorrendben a románok, a szlovákok és a horvátok követik. A hazánkban élő németeket hagyományosan „sváboknak” nevezik, viszont ez nem a valódi származásukat jelenti, hiszen felmenőik - évszázadokkal ezelőtt - a legkülönbözőbb német nyelvterületekről érkeztek.\n\nNemzetiségek Magyarországon\n\nMi a nemzetiség? A nemzetiség valamely állam területén kisebbségben lévő emberek csoportja, akiket elsősorban a nyelv és a kultúra, a közös történelmi múlt, illetve az ezekből fakadó magatartásbeli sajátságok és pszichológiai jellegzetességek, valamint az összetartozás tudata köt össze és választ el más nemzetiségektől és nemzetektől.\n\nA magyar törvények a legalább száz éve nálunk élő népcsoportokat ismerik el nemzetiségként. Ezek a nemzetiségi csoportok nyelvükben, kultúrájukban és vallásukban is különbözhetnek a többségi nemzet lakosaitól. Magyarország alaptörvénye és a nemzetiségek jogairól szóló 2011. évi CLXXIX. törvény értelmében 13 nemzetiség él Magyarországon, amelyek lélekszámukat tekintve csökkenő sorrendben a következők: cigány, német, román, szlovák, horvát, szerb, ukrán, lengyel, bolgár, görög, ruszin, örmény, szlovén. Népszámláláskor rákérdeznek az adott személy nemzetiségére és anyanyelvére is.\n\nA mai Magyarországon élő nemzetiségek lélekszáma az össznépesség 10%-a.\n\nNemzetiségek száma Magyarországon 2011-ben\n\nANYANYELV szerint NEMZETISÉG szerint\n\nmagyarok\n\n8 409 049\n\n8 314 029\n\ncigányok\n\n54339\n\n315 583\n\nnémetek\n\n38248\n\n185 696\n\nrománok\n\n13886\n\n35641\n\nszlovákok\n\n9888\n\n35208\n\nhorvátok\n\n13716\n\n26774\n\nszerbek\n\n3708\n\n10038\n\nukránok\n\n3384\n\n7396\n\nlengyelek\n\n3049\n\n7001\n\nbolgárok\n\n2899\n\n6272\n\ngörögök\n\n1872\n\n4642\n\nruszinok\n\n999\n\n3882\n\nörmények\n\n444\n\n3571\n\nszlovének\n\n1723\n\n2820\n\nNépesség összesen:\n\n9 937 628\n\n9 937 628\n\n(Forrás: ksh.hu)\n\nNemzetiségi politika:\n\nHazánkban 1995 óta december 18-án ünnepeljük a nemzetiségek napját. Az ENSZ ezen a napon fogadta el a nemzeti vagy etnikai, vallási és nyelvi kisebbségek jogairól szóló nyilatkozatát. Ezen a napon adják át a Nemzetiségekért díjat, amelyet a nemzetiségek érdekében a közéletben, az oktatásban, a kultúrában, az egyházi életben, a tudományban, a tömegtájékoztatásban, a gazdasági önszerveződésben kiemelkedő tevékenységet végző magyarországi és határon túli személyek és szervezetek kaphatnak meg.\n\nA kisebbségi törvény (1993. évi 77. tv.) „A nemzeti és etnikai kisebbségek jogairól” után a 2011. évi CLXXIX. törvény a nemzetiségek jogairól szabályozza a nemzetiségek jogait.\n\nA nemzetiségi törvény a nemzetiségek egyenjogúságát szabályozza. A törvény szerint tizenhárom nemzetiségnek van joga kisebbségi önkormányzatokat alakítani: a szlovén, a horvát, a szerb, a román, a ruszin, az ukrán, a szlovák, a német, a bolgár, a görög, a lengyel, az örmény és a roma (cigány) kisebbségnek. A kisebbségi önkormányzatok képviselik a kisebbségek érdekeit és segítik a kulturális örökség ápolását. Külön regisztrálni kell a kisebbségi önkormányzati választásokon való részvételre.\n\nA nemzetiségi iskolákat nem a kisebbségi önkormányzatok tartják fenn, hanem az állam.\n\nAz Alaptörvény szerint a nemzetiségek államalkotó tényezők, ezért az Országgyűlésben képviselőjük vagy szószólójuk van. Nemzetiségi listára a pártlisták helyett szavazhatnak a magukat regisztrált választópolgárok, ha azonban nincs elég szavazat, akkor képviselő helyett szavazati joggal nem rendelkező szószólót küldhetnek az Országgyűlésbe. A kisebbségeket ért jogsérelmek kivizsgálásával a kisebbségi jogok országgyűlési biztosa (ombudsman) foglalkozik. Az Alaptörvény szerint a Magyarországon élő nemzetiségek államalkotó tényezők. Minden, valamely nemzetiséghez tartozó magyar állampolgárnak joga van önazonossága szabad vállalásához és megőrzéséhez. A Magyarországon élő nemzetiségeknek joguk van az anyanyelvhasználathoz, a saját nyelven való egyéni és közösségi névhasználathoz, saját kultúrájuk ápolásához és az anyanyelvű oktatáshoz. A Magyarországon élő nemzetiségek helyi és országos önkormányzatokat hozhatnak létre.\n\nEtnikumok és nemzetiségek a magyar társadalomban\n\nNemzeti és etnikai kisebbség a Magyarország területén legalább egy évszázada honos minden olyan népcsoport, amely az állam lakossága körében számszerű kisebbségben van, tagjai magyar állampolgárok, a lakosság többi részétől saját nyelve és kultúrája, valamint hagyományai megkülönböztetik. Olyan összetartozás-tudatról tesz bizonyságot, amely önazonosságának megőrzésére, közösségi érdekeinek kifejezésére és védelmére irányul. Ezer, magát valamely kisebbséghez tartozónak valló választópolgár népi kezdeményezéssel kérheti kisebbségként való elismerését. Számos településen működnek nemzetiségi iskolák (Budapest, Baja, Pécs) ahol biztosított az anyanyelvű oktatás, de a legtöbb esetben kétnyelvű az iskola (Gara, Komlóska, Piliscsév), vagy az anyanyelvi oktatásnak egy gyengébb formája valósul meg, amikor a nemzetiségi nyelvet idegen nyelvként oktatják.\n\nNemzetiségek Magyarországon\n\nA ma Magyarországon élő legnagyobb nemzetiségi csoport a német (szászok, svábok). Jelenlegi számuk kb. 170 ezer, jellegzetes településeik Baranyában és a Dunántúli-középhegység területén vannak. A németek, mint magyarországi nemzetiségek több évszázada együtt élnek a magyarsággal. Az első német betelepülők iparosok, bányászok voltak, akik külön jogokat kaptak: az erdélyi szászok és a felvidéki (szepességi) cipszerek például. A 18. században, a török hódoltság után a kipusztult területekre (Dunántúl, Tolna, Baranya) szintén sok német telepes (sváb) érkezett, akik ipari és kereskedelmi ismeretekkel gazdagították a magyar kultúrát és nyelvet.\n\nA szlovákok a török pusztítás után, a 18. században telepedtek le nagyobb számban, elsősorban Komárom, Veszprém, Nógrád, Pest és Békés megyében. A szlovákok napjainkban mindössze kb. 80-100 ezren maradtak a gyors elmagyarosodás és az 1946-48-ban lezajlott magyar-szlovák lakosságcsere eredményeként (73 ezer szlovák települt át Csehszlovákiába). Főleg Pest környékén, az Északi-középhegységben és Békés megyében élnek.\n\nA románok a 12. században jelentek meg Erdélyben. A mai Magyarországon, Gyula környékén élnek (pl. Kétegyházán, Méhkeréken). A mai ország területen kis létszámú nemzetiség a román. Jelenleg a román-magyar határ mentén, valamint a fővárosban élnek nagyobb számban, összesen kb. 15-20 ezren.\n\nA horvát-magyar határ mentén (Mohács, Baja) élnek magyarországi horvátok (kb. 35 ezer). A magyarok a horvátokkal évszázadokig szövetségben éltek. A mai Magyarországon a Dráva mellett, Szombathely környékén élnek kisebb számban horvátok.\n\nA lengyelek a II. világháború kirobbanását követően menekültként, majd később vendégmunkásként érkeztek Magyarországra. Napjainkban kb. 8.000-10.000 lengyel nemzetiségű lakos él az országban. A legnagyobb közösség Budapesten található.\n\nAz ortodox vallású szerbek a török kiűzését követően, mint kereskedők jöttek az ország belsejébe. Egykori településeiket a Duna mentén találjuk (Szentendre, Komárom, Dunakeszi, Ráckeve, Mohács). Lélekszámuk ma kb. 5.000 fő. A délszláv háború következtében szerb családok százai telepedtek le a szerb-magyar határ melletti településeken (Szeged, Pécs).\n\nA XVIII. századtól kezdve települtek be az országba a kertészkedéssel foglalkozó bolgárok. A bolgár kertészek utódai - kb. 3.000 fő - ma Budapesten, Pécsen, Miskolcon élnek.\n\nA XVIII. századtól érkeztek az országba a kereskedő görögök. 1948-1950 között, a görög polgárháború következtében mintegy 13 ezer menekült érkezett Magyarországra, akiknek Fejér megyében külön falut is alapítottak (Beloiannisz). Miskolcon a Tátra utcába költöztek. Az 1970-es évektől sokan hazaköltöztek közülük, ezért létszámuk napjainkra 3.000 körüli.\n\nAz Őrség (Vendvidék) Szlovéniával határos falvaiban élő kisebbség a szlovénoké (vendek) kb. kétezren vannak. Magyarországon, Szentgotthárd környékén hét településen élnek.\n\nA rutének (ruszinok) a 18. században vándoroltak be főleg a Hegyalja környéki településekre (Szerencs, Tokaj, Sátoraljaújhely környékére).\n\nA magyarországi romák\n\n• A cigányság több, különböző hagyományú és eredetű csoport gyűjtőneve, akiket a többségi társadalom magától szokásaikban és megjelenésükben különbözőnek vél. Újabban elterjedt a roma megnevezés is, ami eredetileg a cigányok többségének önelnevezése.\n\n• Mivel a cigányság nem egységes csoport, kultúrája, hagyományai is sokszínűek. A korai feljegyzések vándorló csoportként írták le őket, akik különböző iparosmesterségekkel (pl. kovács), valamint kereskedelemmel foglalkoztak (lókupec).\n\nA 19. századra többségük letelepedett, továbbra is főleg iparosként, illetve napszámosként dolgozott. A kevés szakértelmet igénylő javító tevékenységek, illetve a nagyon olcsó nyersanyagból készíthető használati cikkek előállítása jellemző rájuk (pl. üstfoltozó, kosárfonó, teknővájó, vályogvető stb.) A társadalom perifériáján éltek, vándorló életmódot folytattak. Kevés írásos emlék tesz róluk említést.\n\nA II. világháborút követően, a szocializmus idején a cigányság tömegesen állt munkába, főként a szaktudást nem igénylő építőiparban, textiliparban és bányászatban. Többségük az északkeleti megyékben, aprófalvakban élt. Jellemző volt az alacsony iskolázottság, a szakképzettség hiánya, ezért általában alacsony presztízsű, rosszul fizetett nehéz fizikai munkát végeztek. Lakásukból gyakran mindenféle komfort hiányzott. Az 1961-es MSZMP-határozat a cigányság integrálását tűzte ki célul az egészségtelen lakóhelyek felszámolásával és átfogó lakásépítési programmal. Társadalmi integrációjuk érdekében megkezdődött a cigánytelepek felszámolása, de sokukat csak csökkentett komfortfokozatú (ún. ,,Cs”-lakásokba) költöztették. A hetvenes években a modernizáció tovább folytatódott, de életszínvonaluk továbbra is elmaradt a többségi társadalométól. A szocializmus időszakában végképp megszűnt az igény a hagyományos mesterségeikre, de a kiépülő nagyipar képzetlen munkaerőként alkalmazta őket. A kialakult társadalmi előítéletek az 1989/90-es rendszerváltáskor csak átmenetileg enyhültek. A cigányság körében a rendszerváltás után (1989) drasztikusan nőtt a munkanélküliség, a hagyományos cigány mesterségek (pl. kovácsolás, teknőégetés) eltűntek. A rendszerváltással ezek az üzemek jórészt megszűntek, a cigányok között tömegessé vált a munkanélküliség. A rendszerváltás után a gazdaságtalanul működő ipari vállalatokat bezárták, vagy eladták, és így az alacsony képzettségű romák közül sokan munkanélküliek lettek.\n\nElhelyezkedésük: a cigányság zöme hagyományosan az ország észak-keleti (és dél-nyugati) részén él, amely eleve szegényebb, és ahol eleve nagyobb a munkanélküliség. Nagyobb népességtömörülés alakult ki Budapesten. Napjainkban a társadalom legszegényebb rétegeihez tartoznak. A cigányság 40%-a városlakó, elsősorban tehát Budapesten és a régi iparvidékek nagyobb városaiban (pl. Ózd) találhatóak nagy számban. A többiek leszakadó, fejletlen térségekben élnek az ország keleti felében, illetve a Dunántúlon, Baranya megyében.\n\nA cigányság a legnagyobb Magyarországon élő etnikai kisebbség. A romák létszámát a becslések általában 400 ezer és 600 ezer közé teszik.\n\nŐket 2011-ig etnikai kisebbségként jelölték, ugyanis a többségük anyanyelve magyar, de hagyományaik, életmódjuk megkülönbözteti őket a többségi magyar társadalom egészétől. Sajátos, vándorló életmódjuk miatt több száz éven keresztül a társadalom peremén éltek. Az állam sokszor próbálta őket letelepíteni, és asszimilációra kényszeríteni - sikertelenül.\n\nMi a nemzetiség? A valamely állam területén kisebbségben levő emberek csoportját értjük alatta, akiket elsősorban a nyelv és a kultúra, a közös történelmi múlt, illetve az ezekből fakadó magatartásbeli sajátságok és pszichológiai jellegzetességek, valamint az összetartozás tudata köt össze és választ el más nemzetiségektől és nemzetektől. Hazánkban 13 nemzetiségi csoport él, ezek közé tartozik a cigányság is.\n\nA leghátrányosabb helyzetben a legnagyobb nemzetiség, a cigányság van, amelynek nincs anyaországa, és a csoport nagy része mélyszegénységben, hátrányos helyzetben él. A cigányság számát Magyarországon 600 ezerre becsülik. A hazánkban élő cigányoknak nyelvileg három nagy csoportját különböztetjük meg: a magyarul beszélő romungrókat, a romani nyelven beszélő oláhcigányokat, és a román nyelv egy archaikus nyelvjárását beszélő beásokat. Legnagyobb csoportjuk a magyar nyelvű romungrók (magyar cigányok, muzsikus cigányok). Az oláhcigányok az indiai eredetű romani nyelv különböző változatait beszélték eredetileg (egyik törzsük a lovári).\n\nTársadalmi problémák:\n\nElőítéletes gondolkodás: egy személlyel vagy csoporttal kapcsolatos előzetesen kialakult elképzelések, amelyek új információk hatására sem változnak meg. A romákkal kapcsolatos sztereotípiák: buta, koszos, lop, nem szeret dolgozni stb. Ilyen a túlzott szaporaság mítosza: a valóságban a cigány családok gyerekszáma átlagosan megegyezik a hasonló anyagi körülmények között élő nem cigány családok gyerekszámával (a szegény családokban átlagosan több gyerek él). Ilyen a túlsegélyezettség mítosza: a valóságban a segélyek nem nyújtanak méltó megélhetést, összegük pedig a magyar jóléti kiadások töredékét teszi csak ki. Ilyen a „cigánybűnözés” mítosza: a valóságban a cigányság bűnözési statisztikái megegyeznek a hasonlóan szegény nem cigány lakosság statisztikáival. A sztereotípiák azonban előítéletekhez, az pedig diszkriminációhoz (megkülönböztetés) és szegregációhoz (elkülönítés) vezetnek: A szabad iskolaválasztás eredményeképpen kialakultak a középosztályt, illetve a szegényeket (köztük a cigányokat) kiszolgáló iskolák. Sok munkahely nem vesz fel cigány alkalmazottat. Azokról a településekről vagy településrészekről, ahova sok cigány költözik, elköltöznek a nem cigányok, és kialakulnak a cigány gettók. Itt az ingatlanárak csökkennek, ami végleg ideköti a szegényeket (és idevonz újabbakat).\n\nDiszkrimináció, hátrányos megkülönböztetés: a romák hátrányban vannak a munkaerőpiacon, a szórakozóhelyekre nem engedik be őket stb.\n\nA diszkrimináció eredménye: a rossz környéken lakó, rossz iskolába járó, az álláskeresés során kudarcokat megélő cigányok számára nincs követendő pozitív minta.\n\nMásrészt a rossz környéken lakó, szegényesen öltözött, iskolázatlanul beszélő (és sötétebb bőrű) ember valószínűleg rosszabb tanuló vagy munkavállaló lesz, így diszkriminálása az iskola vagy a vállalat szempontjából „érthető”.\n\nAz emiatt a csoport egészét érő kudarcok azonban nem csak dühöt eredményeznek, de csökkentik is a cigányok motivációját, hiszen eredményeik nem az erőfeszítéseiken, hanem a külső megítélésen múlnak.\n\nA cigányság össztársadalmi gondjai:\n\nA cigányság össztársadalmi gondjai: iskolázatlanság, munkanélküliség, szegénység, rossz életkörülmények, vékony az értelmiségi rétegük, megosztottság: egységes politikai fellépés hiánya.\n\n• iskolázatlanság: a szakképzetlen munkaerő elhelyezkedése nehéz. A hagyományos szakmákban szerzett tudásra nem tart igényt a piac.\n\n• munkanélküliség: gyakran már a második, harmadik generációban, így nagyon alacsony a családok jövedelme. A magas gyerekszám, ami a szegénységnek és iskolázatlanságnak oka és következménye is egyben. (A korai családalapítás és a munkanélküliség hajlamosít a gyerekvállalásra.\n\n• rossz életkörülmények, szegénység\n\nA szegénység és iskolázatlanság eredménye a rossz egészségügyi állapot, a többségi társadalomhoz képest korai halálozás. Ez természetesen visszahat a jövedelemszerző képességre, azaz a szegénység oka is egyben.\n\n• vékony az értelmiségi rétegük, illetve megosztottak: hiányzik az egységes politikai fellépés.\n\nKitörési lehetőségek\n\n• tanulás, szakmaszerzés, sport (labdarúgás, boksz pl. a régiónkban Csóka Nándor)\n\n• zene (cigányzene, jazz, pop)\n\nCivil roma szervezetek: 1994-ben alakult meg a Nemzeti és Etnikai Kisebbségi Jogvédő Iroda (NEKJI): jogi tanácsot és védelmet nyújt a romáknak. A cigányság érdekeit védi a Roma Polgárjogi Alapítvány (RPA), amely a jogi segítség mellett számtalan hírértékű akciót, tüntetést szervez. A roma értelmiség új generációja hozta létre a Romaversitast és más szervezeteket.\n\nAz állam és különböző civil szervezetek integrációs programokat hirdetnek a diszkrimináció felszámolására: megpróbálják csökkenteni a többségi társadalom előítéletességét. Megpróbálják az oktatás fejlesztésével csökkenteni a képzettségbeli hátrányokat. Ezzel próbálják meg segíteni a cigányok munkába állását. Az állandó munka és jövedelem javíthatna aztán a lakóhelyen és az egészségügyi állapoton.', 168, 1, '2026-04-17 09:40:12', '2026-04-17 09:40:12');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(10, 10, 'A magyarság és Magyarország története a XIV. század elejéig (magyar őstörténet, honfoglalás, államalapítás, Árpád-kor)', '10.docx', '10. A magyarság és Magyarország története a XIV. század elejéig (magyar őstörténet, honfoglalás, államalapítás, Árpád-kor)\n\nMagyar őstörténet\n\nA magyar nép a finnugor nyelvcsaládba tartozik a nyelvészeti bizonyítékok szerint.\n\nA honfoglalás előtti korból nem maradtak fenn összefüggő nyelvemlékeink, csupán szórványemlékek (jórészt tulajdonnevek), idegen nyelvi környezetben lejegyezve. Pl. a tihanyi apátság alapítólevele. Külső források különböző népneveket alkalmaztak a magyarokra. Bizáncban a szkíta népek közé sorolták, és jórészt türknek mondták őket (emellett a szabir és onogur nevet is használták). A muszlim írók a baskírokkal is összefüggésbe hozták eleinket. A nyugati krónikák jórészt onogur, hun, avar néven nevezték őket. A magyarok ugyanis jellegzetesen sztyeppei, törökös kultúrájú népként kerültek az idegen írók látókörébe: életmódjuk, lovas íjász hadviselésük, anyagi kultúrájuk (viselet, díszítőművészet) egyaránt ezt tükrözte. Erről tanúskodik a rovásírás is, amelyet szintén török népektől vettünk át, és annak eredete végső soron föníciai mintára vezethető vissza. Rovásírásnak nevezik azokat az írásfajtákat, amelyeknek jeleit kemény anyagra (fa, kő, csont stb.) vésték, karcolták. A vándorló magyarokról Bíborbanszületett Konstantinosz bizánci császár, vagy az arab földrajztudósok, Ibn Ruszta és Gardizi is írt. A középkori magyar krónikák már említették a latin betűs írástól eltérő írásjeleket, de régészeti emlékek csak a 15. századból maradtak ránk. A magyar őstörténeti hagyományból értékes elemeket őriztek meg középkori krónikásaink pl. Anonymus Gesta Hungarorum a XIII. századból. Általuk tudjuk, hogy volt saját eredetmítosza a magyar népnek (csodaszarvasmonda), az első uralkodóháznak (turulmonda) és a magyar sztyeppei államnak (vérszerződés mondája). A honfoglalást a fehér ló mondája örökíti meg; hőskultuszra vall a Lehel kürtje-monda. Az első magyar históriát a 11. század második felében írták meg, de a 12. századi folytatásaival együtt elveszett: ezeket a szövegeket 13–14. századi krónikaszerkesztések őrizték meg. Kevés írott adat maradt fenn, ezért az őstörténet-kutatásban nagy szerepük van a más tudományok – nyelvészet, néprajz- és népzenekutatás, régészet, embertan, történeti genetika – által feltárt ismereteknek.\n\nNyelvészet\n\nA nyelvészet az élő nyelvek összehasonlítása és a nyelvemlékek elemzése révén elméletet alkot a nyelv történelméről. A nyelvtani szerkezet és a szókincs hasonlósága alapján a nyelveket családokba sorolják. A napjainkban elterjedt elmélet szerint az uráli nyelvcsalád bomlott finnugor és szamojéd ágra, majd a finnugor nyelvcsalád vált szét tovább finn-permi és ugor ágra, és a magyart az ugor nyelvek közé sorolják. A honfoglalás előtti korból nem maradtak fenn összefüggő nyelvemlékeink, csupán szórványemlékek (jórészt tulajdonnevek), idegen nyelvi környezetben lejegyezve. A 18. század végén az összehasonlító nyelvészet színre lépett. Sajnovics János 1770-ben a magyar és a lapp nyelv azonosságáról értekezett, amivel a figyelmet az Urál-vidéki népek nyelveire irányította. Pray György jezsuita történettudós a hunok, avarok, magyarok és finnek rokonságát vallotta. A XIX. században feltételezték, hogy az Urál hegység vidékén létezett egy uráli ősnép, ami uráli ősnyelvet beszélt, aztán ez az ősnép/ősnyelv vált szét különböző ágakra. Elutasították a magyarság hun hagyományát, és a régi műveltség sztyeppei törökös elemeit átvételnek állították be. Több eredetelmélet is felszínre került például az, hogy a magyarok a sumeroktól származnak. Az uráli ősnép és ősnyelv meglétére nincs egyértelmű bizonyíték, azonkívül több tudományág a sztyeppe övezetébe helyezi a magyar nép kialakulásának tágas terét, az Urál vidékénél délebbre és keletebbre.\n\nNéprajz és népzene\n\nA néprajz- és népzenekutatás a hazai hagyományt és a rokon kultúrák monda- és zenekincsét vizsgálja. Az emlékezet és a hagyományozás módjait ismerő folklorisztika így jórészt az összehasonlító motívumkutatással szólhat a korai múlt mítoszainak kulturális kapcsolatairól. A mondák motívumpárhuzamai döntően a sztyeppei (szkíta, hun, törökös) népekhez vezetnek.\n\nRégészet\n\nAz anyagi műveltség maradványait a régészet hozza felszínre, elsősorban sírok, temetők, valamint telepek, települések feltárásával. A tárgyakból következtetni lehet például néhai tulajdonosaik életmódjára, művészetére, szellemi kultúrájára, hiedelemvilágára. Egy adott régészeti kultúrához azonban több nép is tartozhatott; a sztyeppei nomádoknál általában hasonló volt a fegyverzet és a díszítőművészet. Fejlett díszítőművészetről vallanak a tarsolylemezek, hajfonatkorongok, szablyák, övveretek, lószerszámdíszek, egyéb ékszerek. Embertan és történeti genetika\n\nE két tudomány a tárgyak egykori tulajdonosainak testi jegyeit vizsgálja a ránk maradt csontokból. Az embertan (antropológia) a csontok fizikai jellemzőit, a történeti genetika (archeogenetika) a csontokból kinyert génállományt kutatja. Értékes tudást nyerhetünk általuk a régi emberek testalkatáról, magasságáról, szem- és hajszínéről is.\n\nA magyarok eredete és vándorlása\n\nKr. e. VI.-IV. évezred: A magyarság ekkor még az uráli népek csoportjához tartozott. Nyugat-Szibériában, az Ob alsó folyásának területén éltek, életmódjukra a halászat és vadászat volt jellemző. Kr. e. IV. évezredben a finnugorok (és a szamojédek) kiváltak az uráli népcsoportból. A Kr. e. III. évezredben az ugorok (finn-permiek) nyugatra húzódtak.\n\nKr.e. 2000 körül: megjelent az „előmagyar nép”; délre húzódtak a Tobol és Irtisz folyók környéki ligetes sztyeppre. Az éghajlat itt melegebb és szárazabb volt, kedvezett a földművelésnek és az állattartásnak. A szabad legeltetés mellett istállózó állattartás is megjelent. Egy települést 10-20 nagycsalád alkotott, melyeknek mindegyike saját kurgánba (= temetkezési földhalom) temetkezett.\n\nKr. e. 1000 – Kr. e. 500: a Nyugat-Szibériában élő ugor népesség kettévált. Az északabbra élő közösségek, az obi-ugorok „erdei” életmódot folytattak (halászat, vadászat, gyűjtögetés), míg a délebben élő csoportok – a magyarok elődei – nomád állattenyésztők lettek, „lovas” életmódot folytattak. A magyarok Kr. e. 800 körül váltak önálló néppé.\n\nMAGNA HUNGARIA – BASKÍRIA - Kr.e. 500\n\nAz ősmagyarok Baskíriába (Magna Hungaria) vándoroltak a nomád népmozgások következtében. Török népekkel kerültek kapcsolatba, ezért kultúrájuk, külső megjelenésük és törzsi szervezetük ezekhez a népekhez hasonlóvá vált. A magyarok ekkori életmódjára a ciklikus (nyári) vándorlás (sátorozó életmód), földművelés és a vashasználat volt jellemző; nőtt a fegyverek hatékonysága (íj, nyíl, rövid kard, lándzsa). Létrejött a hét törzs: Nyék, Megyer, Kürtgyarmat, Tarján, Jenő, Kér, Keszi. A XIII. században Julianus barát egy keleti magyar népegységhez érkezett meg 1236-ban. A Volga mellett megtalált Magna Hungaria (Nagy-/Régi-Magyarország) népének ősei korábban válhattak el a többiektől.\n\nLEVÉDIA:\n\nA magyarokat „szabir” és „türk” néven ismertek, Levédiában a Kazár Birodalommal kerültek kapcsolatba (7–9. század). Levédiában a Kazár Kaganátus a 7. század első felében lett önálló sztyeppebirodalom. Levédia feltételezhetően a Don és a Dnyeper folyó vidékére tehető. A magyar nyelv földművelésre és állattenyésztésre vonatkozó szavai erős török kultúrhatást tükröznek. Az állattartást a szabályos legelőváltáson alapuló pásztorkodás határozta meg. Nyáron a szállásterület északi térségein, télen a délebbi, enyhébb éghajlatú területeken legeltették méneseiket és gulyáikat. Ezt a gazdálkodási formát nomádnak vagy félnomádnak szokták nevezni. 750 körül a hét törzs Levédiában (Tarján, Jenő, Kér, Keszi, Nyék, Megyer, Kürtgyarmat) szövetségre lépett egymással. A társadalom élén két fejedelem állt: a kende (vagy kündü), vagyis az uralkodói méltóság viselője és a szakrális hatalom megtestesítője, és a gyula, vagyis a hadvezéri tisztséget viselő hatalomgyakorló személy. A bírói joghatóságot a horka méltóság viselője gyakorolta. Levédia a Kazár Birodalom közvetlen közelében volt, a magyarok szoros kapcsolatba kerültek a kazárokkal. Átvették tőlük a rovásírást, egyes gazdálkodási módszereket, és valószínűleg a kazár kagánt ismerték el uruknak. A magyaroknál kialakult kettős fejedelemség is nyilván kazár mintára jött létre. A névleges hatalommal rendelkező kagánnak őseinknél a kündü (nap; a szakrális fejedelem címe, iszlám forrásokból maradtak ránk), a tényleges uralkodónak a gyula (hold; a hadsereg főparancsnoka, a fegyveres hatalom birtokosa a honfoglalás előtti magyarságnál; a kende mellett vagy után a második legfontosabb személy) felelt meg.\n\nETELKÖZ:\n\nIX. században őseink és a hozzájuk nyolcadik törzsként csatlakozott kabarok nyugat felé húzódtak. Új szállásterületük, Etelköz (jelentése: Folyóköz) a Duna és a Dnyeper között terült el. Etelközben a törzsek vérszerződéssel tették szorosabbá szövetségüket. A hét törzsfő (Álmos, Előd, Ond, Kond, Tas, Huba, Töhötöm) vérszerződést kötött egymással a törzsek közötti szövetség érdekében. Ebben az időszakban a magyar társadalomra már jellemző volt a vagyoni tagozódás. Megjelentek a gazdag és a szegény pásztorok; kialakult az a szokás, hogy a nemzetségi, törzsi tisztségek a legtekintélyesebb családokban öröklődnek. A társadalom egy vékony rétege az állatvagyon egy részét magántulajdonává tette. (Erre utal a barom és a bélyeg szó is, amely eredetileg a jószágra sütött tulajdonosi jegyet jelentette). Őseink Etelközből kiindulva zsákmányszerző hadjáratokat vezettek – egyrészt a szlávok ellen, másrészt nyugat felé, megjelenve a Kárpát-medencében. Az egymással harcoló frankok és morvák felváltva hívták segítségül a magyarokat, akik zsákmány reményében szívesen vállalkoztak a hadjáratokra.\n\nA hét vezér, a „hét fejedelmi személy” közül Álmos emelkedett ki, aki családi hagyománya szerint Attila hun király leszármazottja volt. A hatalmat a 9. század közepén szerezte meg.\n\nA vérszerződéssel olyan erős állami egységbe tömörültek a magyarok. Álmos utódai közül fiát, Árpádot „nagyfejedelem” címmel említik, ezért Álmos sztyeppeállamát Magyar Nagyfejedelemségnek érdemes neveznünk. A fiatal magyar állam erejét jellemzi, hogy még Etelközben csatlakoztak a magyarokhoz a kazároktól elpártolt kabarok (a török eredetű szó jelentése: ’lázadó’). Őket egy törzsbe tömörítették, és katonai segédhadként alkalmazták.\n\nHONFOGLALÁS: 895\n\nA magyar történelemben honfoglalásnak nevezzük azt a folyamatot, melynek során a magyarok a Kárpát-medencét a birtokukba vették.\n\nMár a honfoglalás előtt, Etelközből is folytattak hadjáratokat a magyarok: 862-ben és 881-ben már frank uralom alatti területeket támadtak magyar seregek a Kárpát-medencében. A honfoglalás idején a magyar törzsszövetség élén Álmos (gyula) és Kurszán (kündü) állt. Álmos Erdélyben szakrális gyilkosság áldozata lett, vagyis feláldozták a honfoglalás sikere érdekében. Tisztségét fia, Árpád vette át. 895-ben a magyarság Árpád vezetésével érkezett a Kárpát-medencébe a Vereckei-hágón keresztül. Az 895-ben a magyarokat besenyő támadás érte keleti irányból. A besenyők teljes erejükkel zúdultak rájuk, mivel őket is szorították az úzok, őket pedig az arabok. Tehát egy népvándorlási hullám vette kezdetét az arab hódítás következtében. A magyarok védelmet keresve vonultak be a Kárpát-medencébe. A Kárpátok északkeleti hágóin (Vereckei-, Tatár-szoros) és az erdélyi hágókon (Békás-szoros) át vonultak be, majd leereszkedve az Alföldre, a Garam-Duna vonaláig szállták meg a vidéket. Ezen a területen a bolgárokat leszámítva nem találkozhattak számottevő ellenállással. A honfoglalók számát kb. 200-500 ezerre becsülik. 896 és 899 között a magyarok letelepedtek a Dunától keletre, majd 900-ra az egész Kárpát-medence uralmuk alá került.\n\nBár Szvatopluk morva fejedelem regnálása alatt volt a legnagyobb a Morva Fejedelemség területe, uralkodásának és a morvák térségbeli hegemóniájának a magyarok honfoglalása vetett véget (fehér ló mondája).\n\nA magyarok kettős fejedelemsége 904-ben, Kurszán halálakor szűnt meg. Ugyanis amikor 902-ben a magyarok elfoglalták a Morva völgyét, a bajorok nem nyugodtak bele a terület elvesztésébe, ezért Kurszánt és kíséretét tőrbe csalták, és egy lakomán megölték.\n\nVálaszként a bajorokra mért vereséggel Pozsonynál, 907-ben a magyarok biztosították helyzetüket a Kárpát-medencében. Ezután szinte évente indítottak kalandozó hadjáratokat.\n\nKalandozó hadjáratok:\n\nLeggyakrabban É-Itáliába, Bajorországba, Szászországba és Bizáncba, de eljutottak D-Itáliába és Franciaországba is, sőt átkeltek a Pireneusokon.\n\nA kalandozó hadjáratok elsősorban zsákmányszerző, adóztató és felderítő szerepűek voltak, de a sikeres magyar harcmodor miatt gyakran jártak ún. bérhadjáratban is. (A nyugati területek belső harcaiban szembenálló felek bérelték fel őket.) A zsákmányszerzés helyébe egy idő után az adószedés lépett, így megváltva a területet az évenkénti támadásoktól (pl. német területeken).\n\nA hadjáratok tervezett akciók voltak, a gyors mozgású csapatok, váltott lovakat használtak. A közelharcot igyekeztek elkerülni, inkább az íjaikat használták. Taktikájuk alapja az ellenfél nehézlovas csapatainak fellazítása volt. Nem szemtől szembe támadtak, hanem vagy látszólag menekültek, amikor az ellenség üldözőbe vette őket, megfordultak és nyílzáport zúdítottak rá, vagy cselt vetve maga után csalogatta az ellenséget egy előőrs, a többiek pedig váratlanul bekerítették őket.\n\nMindkét taktika igen fegyelmezett magatartást feltételez, tehát a korabeli források szedett-vedett pogány hordákról szóló írásai erős elfogultságot tükröznek.\n\nA hadjáratokban valószínűleg a katonáskodó középrétegek, ill. a segédnépként szolgáló szabadok vehettek részt. A zsákmányt, ill. az adóból származó bevételt hazaérkezés után osztották szét, ami megnövelte a fejedelmi hatalom súlyát, szerepét.\n\nA sikeres hadjáratok összefogásra késztették a nyugati népeket. I. (Madarász) Henrik szász uralkodó békét vásárolt a magyaroktól, amit 933-ban megszegve Merseburgnál vereséget mért rájuk. A döntő csapást I. (Nagy) Ottó német-római császár mérte a magyarokra 955-ben, az Augsburgnál elszenvedett vereség a kalandozó hadjáratok végét jelentette.\n\nA honfoglaló magyarság társadalma\n\nA szállásfoglalás törzsek szerint történt, így például a középső részre az Árpádok törzse, a nyugati végeken a horka telepedett le. A magyarok törzsenként és nemzetségenként telepedtek le, és alakították ki saját településeiket. A központi település a Megyer törzs szállása volt a mai Csepel-sziget területén. A törzsfők elnevezése úr volt; saját uruszágukat, azaz területüket irányították. Alávetettjeik az ínek, azaz közrendűek voltak.\n\nA kalandozások egyes törzsek saját akciói voltak. A társadalom: a törzsfők, nemzetségfők adják a bőséget, fegyveres kíséretük és a szolgálatra kényszerült szabadok pedig az ínséget. A szabadsággal nem rendelkező rabszolgákat szintén íneknek nevezték.\n\nA kalandozások befejeződésével a magyarság életmódja gyökeresen megváltozott, s ez hatással volt a társadalomra is. A társadalmi differenciálódás alapja a vagyon volt. A legfelső réteget az urak, vagyis a fejedelem és a törzsfők alkották, akik saját szállásterülettel rendelkeztek, melynek neve uruszág volt (ebből keletkezett az „uraság”, de az „ország” szó is). A következő társadalmi csoport a nemzetségfők, vagyis a bők csoportja (lásd: mai „bőség” szavunk). Az urak és a bők hatalmát fegyveres harcosok biztosították, akiket jobbágyoknak neveztek. A következő réteget az ínek alkották (mai „ínség” szó). Ide tartoztak a szolgálatra kényszerített szabad közrendűek, valamint a rabszolgasorba került hadifoglyok is. Külön csoportot alkottak a szabad népek, mint például a székelyek vagy a besenyő határőrök.\n\nA magyar társadalom a X. században\n\nfejedelem és törzsfők\n\nurak (fejedelem, gyula, horka, törzsfők)\n\nszabadok\n\nnemzetségfők\n\nbők\n\nharcosok\n\nfejedelmi kíséret (jobbágyok)\n\nínek = szolgáltató népek (földművelő, pásztor, solymász, kovács, szakács)\n\nszabad köznép\n\n(rab)szolgák\n\nszolgák\n\nÖsszefoglalása:\n\nA 895 és 900 közötti honfoglalás során a magyarok elfoglalták a Kárpát-medencét. Becslések szerint a honfoglaló magyarok lélekszáma 200-500 ezer körül lehetett.\n\nEzt követték a nyugati kalandozások, melyek 955-ig, az augsburgi vereségig tartottak. A magyarok a Kárpát-medencében éltek. A kalandozások zömében nyugati irányú hadjáratok voltak.\n\nA köznép földet is művelő, félnomád életmódot folytatott, és a kalandozásokban a középrétegek vettek részt. A nomád harcmodor szerepet játszott a kalandozó hadjáratok sikerében.\n\nA kalandozások a vezető réteg érdekeit szolgálták, és a kalandozások hatására kialakult az előkelők állandó fegyveres kísérete. A hadjáratok fő célja a zsákmányszerzés, a meggazdagodás és a fegyveres kíséret eltartása volt. A kalandozások következtében nőtt az előkelők hatalma.\n\nA társadalom törzsi jellegű. Rétegei: törzsi-nemzetségi előkelők, fegyveres kíséret, közszabadok, szolganépesség. Az előkelőket „bő”-nek nevezték, a köznépet vagy szolganépet „ín”-nek.\n\nA nomád, illetve félnomád életmód volt jellemző. A nomád társadalom jellemzője az állattartó gazdálkodás, a vándorlás.\n\nA Kárpát-medencében megkezdődött az áttérés a letelepedett életmódra, teret hódított a földművelő életmód.\n\nJurtákban és földbe süllyesztett házakban laktak. A jurta nemezből készült sátor volt, belső kialakítása a családon belüli hierarchiát tükrözte.\n\nKézműipari tevékenységük volt a fazekasság, szövés, bőrfeldolgozás, nemezkészítés, ötvösművészet pl. galgóci tarsolylemez.\n\nAz írásos források hiánya miatt fontosak a régészeti emlékek, a legtöbb tárgyat sírokban találták. Fontos tárgyi emlékeik a tarsolylemezek, ékszerek.\n\nA magyarok ősvallása a sztyepp népei körében általánosan elterjedt a totemizmus örökségét is magán viselő sámánhit. A magyarok sámánjaikat táltosoknak is nevezték A közösség életét érintő jelentős döntések előtt rendszeresen ki is kérték a tanácsukat. A szellemek megnyerése vagy ártó hatásuk elkerülése érdekében áldozatokat is bemutattak. Fontos szimbólumuk az életfa, amely világokat köt össze, a kereszténység előtti magyar hiedelemvilágban központi helyet foglalt el. A fa hármas osztása a világmindenség rendezőelvét képezi le. A fa lombja vagy koronája az égi szféra, a fa törzse a földi, azaz látható világot jelképezi. A földalatti világ az alvilágot vagy szellemvilágot jelenti, ahova a fa gyökerei nyúlnak le. Eredeti írásunk: a rovásírás.\n\nA kereszténység bizánci hatásra jelent meg először a magyarok között. Géza fejedelem (970 k. - 997) azonban a nyugati kapcsolatok erősítése, és a terjeszkedő Bizánc jelentette fenyegetés csökkentése érdekében a nyugati kapcsolatok kiépítését tartotta megoldásnak.\n\nA kalandozó hadjáratok lezárulása után a magyarságnak egyetlen lehetősége volt a hosszú távú fennmaradásra: csatlakozniuk kellett a kialakuló keresztény, feudális Európához.\n\nA nyugati világhoz tartozás szándéka az államforma megváltozásán kívül életmódbeli, vallási és társadalmi változásokat vont maga után. A törzsfők-nemzetségfők hatalmának megtörése Géza fejedelem (972-997) nevéhez fűződik.\n\nGéza és István államalapító tevékenysége\n\nA Kárpát-medence megszerzése után, 907-től szinte évente indultak kalandozó magyar seregek a környező államokba, legtöbbször Bizáncba, Észak-Itáliába és Bajorországba. A magyarok sikereiket elsősorban a könnyűlovas harcmodornak és a széthullott Frank Birodalom belső feszültségeinek köszönhették. A több évtizeden át tartó kalandozások összefogásra kényszeritették a Nyugat népeit, ezért I. (Madarász) Henrik szász uralkodó kilencévi adófizetéssel békét vásárolt a magyaroktól, s ezt az időszakot erőgyűjtésre használta. Így történhetett, hogy a tizedik évben, amikor megtagadta az adó fizetését, 933-ban Merseburgnál vereséget mért a magyarokra. Ez a csatavesztés az erőviszonyok változását jelentette, és végül I. (Nagy) Ottó 955-ben Augsburgnál döntő csapást mért a kalandozó magyarokra.\n\nA kalandozások lezárulása válaszút elé állította a magyarokat. Az egyik út a nomád népek (hunok, avarok) sorsa: rövid tündöklés után a szétszóródás, az enyészet. A másik út: kapcsolódni a kialakuló keresztény feudális Európához. Ez a lehetőség a megmaradást jelentette, ám azt is, hogy a törzsi, nemzetségi előkelőknek önmaguk és kíséretük eltartását a harci vállalkozások helyett biztosabb alapokra kellet helyezniük. Több más európai néppel egyidőben, a magyarság is erre tett kísérletet: erőskezű vezetők emelkedtek ki, legyőzték vetélytársaikat, megszerezve a földek nagy részét, majd csatlakoztak népükkel a kereszténységhez és létrehozták az egyházi hierarchiát.\n\nGéza, Árpád dédunokája 972-ben került a fejedelmi székbe a szeniorátus elve alapján. Ez azt jelenti, hogy egy adott nemzetségben mindig a nemzettség legidősebb férfi tagja örökölte a hatalmat. Géza nevéhez fűződik a törzsfők, nemzetségfők hatalmának megtörése, hiszen, mint azt Szent István király nagy legendájában is olvashatjuk, kezét emberi vér szennyezi be. Géza nagy hangsúlyt fektetett a tudatos házasságpolitikára is. Feleségül vette Saroltot, az erdélyi Gyula lányát, ezzel megszerezve az ország keleti részének támogatását. Felmérve az ország helyzetét nem törekedett újabb támadásokra, hanem békeszándékkal 12 követet küldött 972-ben Quedlinburgba, a német birodalommal szomszédos országok tanácskozására. A tanácskozáson hittérítő papokat kért a magyarok számára és lemondott a Lajtán túli területekről. Személyes távollétével azt akarta kifejezni, hogy a magyarság, bár áttért a keresztény hitre, nem hódolt be a német-római császárnak. A biztos külpolitikai háttér lehetőséget adott Gézának a belső rend megszilárdításában. A hitet erőszakosan és véreskezűen terjesztette, ám a már hivőkkel irgalmasan és bőkezűen bánt. Ő maga bizánci hitre tért át. Fiát, Vajkot (török szó, jelentése hős, vezér) már keresztény szellemben neveltette, de ő a római katolikus hitet vette fel, és az első keresztény vértanúról az István nevet kapta. Géza fejedelem soha sem tért meg teljesen: „Elég nagy úr vagyok, és elég gazdag is ahhoz, hogy két istennek áldozzam”.\n\nSzékhelye Esztergom volt, amelyet ő alapított Székesfehérvárral együtt. 996-ban letelepedtek Pannonhalmán a bencés szerzetesek, és megkezdődött a nyugati kereszténység szerveződése.\n\nHÁZASSÁGPOLITIKÁJA:\n\nLányait a környező uralkodók gyermekeihez adta feleségül. Egyiküket (Judit) Boleszláv lengyel fejedelemhez, másik lányát (Ilona) Orseolo Ottóhoz, a velencei dózséhoz, a harmadikat (Sarolta) Aba Csabához, a kabar törzs vezetőjéhez (az ő fiuk lesz Aba Sámuel, aki 1041-44 között uralkodik). Új külpolitikai irányát jelezte, hogy egy korábbi ellenfélnek, II. (Civakodó) Henriknek a lányát, Gizellát kérte fiának feleségül, ezzel rokonságba kerülve a Szász-dinasztiával és a német-római császárral is. Tovább erősítette ezzel a hatalmát. 995 körül összehívta az ország főembereit, és megeskette külön-külön mindegyiket, hogy halála után fia, István trónra kerülését segítse. Ezzel a döntésével szakított a hagyományokkal, és a szeniorátus elve helyett a Nyugat-Európában elterjedt primogenitúra intézményét támogatta, mely szerint a hatalmat az elhunyt uralkodó elsőszülött fia örökli.\n\nIstván (997/1000/1038)\n\n997-ben, Géza halálakor már majdnem az egész ország az Árpádok kezében volt. Ám a nemzetségen belül, Koppány hatalmi igényekkel lépett föl Istvánnal szemben, korábbi esküjét megszegve. Koppány apja szintén Árpád dédunokája volt, aki bár római szertartás szerint megkeresztelkedett, mégis pogány módon élt. Ezeket az ősi pogány hagyományokat szerette volna Koppány tovább vinni. Trónigényét az ősi öröklődési renddel, a szeniorátussal támasztotta alá és ezt nyomatékosítván – a levirátus szokása szerint – feleségül kérte Géza özvegyét, Saroltot. István a Gizellával érkezett német lovagokkal, skandináv zsoldosokkal, könnyűlovas magyarokkal és besenyőkkel döntő csapást mért Koppány seregeire, a lázadót pedig felnégyelték és az esztergomi, veszprémi, győri és a gyulafehérvári várakra függesztették ki. Ez a büntetés különös volt, hiszen a harc az ősi törvények visszahozatala ellen folyt, s a büntetés mégis ilyen pogány módon történt. Koppány harca azért is volt esélytelen István ellen, mert még Géza szándékosan olyan somogyi területeket jelölt ki Koppány számára, amik a forgalomból kiestek és fejedelmi erősségekkel voltak körbevéve. Istvánnak még több belső harcot kellett vívnia hatalma megszilárdítása érdekében. 1003-ban az erdélyi Gyulát fosztotta meg hatalmától, de nagybátyja életét megkímélte, majd később a Temesköz urát, Ajtonyt kellett legyőznie, hogy aztán az egész Kárpát-medence urává válhasson.\n\nKoppány legyőzésével István kezébe került a fejedelmi hatalom, s ő a nagyobb tekintélyt biztosító királyi címért folyamodott Rómához. Az ország akkori helyzetét és erejét mutatja, hogy II. Szilveszter pápa azonnal megadta a királyi címet, és ezzel Magyarország végképp beilleszkedett az európai keresztény államok közé. 1000 és 1001 fordulóján Esztergomban Asztrik (esztergomi) érsek koronázta meg. A koronázással Istvánnak nem csak a külpolitikai megítélése erősödött meg, hanem a belső hatalma is megszilárdult, s így tevékenysége már az új államszervezet kiépítésére irányulhatott.\n\nDöntő szerepet szánt az önálló magyar egyházszervezet kialakításának.\n\nA keresztény szokásokat törvényekkel tették kötelezővé, az egyházszervezés szorosan összefüggött az államalapítással. Pannonhalmán bencés kolostor létesült, a kolostort még Géza kezdte építtetni. Magyarországon is megjelent a szerzetesség és a plébániahálózat kiépítése. Az egyházszervezet kialakítása két generáció alatt történt, István a kereszténységhez való csatlakozással magyarázza győzelmét, erős kiváltságokat ad. István törvényben rendelte el a keresztény böjtöt, így a kereszténység felvétele új szokások bevezetését is jelentette. A kereszténység felvétele hatalmi szóval történt. A királynak apostoli hatalma, papi szerepe is volt.\n\n10 egyházmegyét hozott létre: Esztergom, Kalocsa, Győr, Veszprém, Pécs, Csanád, Várad, Eger, Vác, Gyulafehérvár központtal. A német külpolitikai függőség elkerülése miatt az egyházszervezet központja az esztergomi érsekség volt, ami közvetlenül a pápasághoz kapcsolódott. Az egyházi hierarchiában az érsekeket a püspökök követik. Még István idején, Kalocsán megalakult a második érsekség. A püspökségek (Győr, Veszprém, Pécs, Csanád, Várad, Eger, Vác, Gyulafehérvár) mellé a század végén két újabb szerveződött (Nyitra, Zágráb). Már István uralkodása alatt megkezdődött a püspöki székesegyházak mellett működő káptalanok alapítása. A káptalan a püspök munkáját segítette, élén a prépost állt, tagjai a kanonokok voltak, akik különböző tisztségeket láttak el. Fontos szerepet játszottak a káptalani iskolák az oktatásban és a káptalanok voltak a magyar középkor „közjegyzőségei”, a hiteleshelyek is. A szerzetesrendek közül az elsőként letelepedett bencések számos kolostort alapítottak (Pannonhalma, Pécsvárad, Zalavár). A magyarországi bencések a pannonhalmi főapáton keresztül közvetlenül kapcsolódtak a pápasághoz. Azt, hogy István életében milyen fontos szerepet töltött be a magyarság megtérítése, abból is láthatjuk, hogy az ő személyes kérésére maradt Magyarországon, és kezdte meg térítői tevékenységét Gellért. Ahogy az Szent Gellért csanádi püspök nagy legendájában is olvashatjuk: „… hatalmat adok neked, hogy országomban bárhol az igét hirdesd, kísérőket adok melléd, akik éjjel nappal szolgálnak neked. Te csak nyisd ki a szádat és vesd el ennek a népnek szívébe az élet magvát.” Gellértet annyira tisztelte és nagyra tartotta, hogy előbb fia, Imre herceg tanítójává fogadta, majd püspökké nevezte ki. A magyar egyházszervezet kialakítása után István hatalmas földadományokkal látta el a püspökségeket és az egyre növekvő számú kolostorokat. Mivel István látta, hogy a pogány hagyományokhoz ragaszkodó néppel nehéz elfogadtatni a kereszténységet, a törvények erejét is felhasználta az új hit előírásainak betartásához. Két törvénykönyvet adott ki, az elsőt közvetlenül a koronázás után. Ebben 35 törvény szerepelt, melyből 12 volt egyházi jellegű. Megkövetelte a böjti időszakok megtartását, a gyónást, a részvételt a vasárnapi misén, és a misén való helyes viselkedést. Az európai gyakorlattal összhangban elismerte az egyház bíráskodási jogát az egyháziak és egyes esetekben (özvegyek, árvák) a világiak felett is. A második törvénykönyvet, mely 21 törvényt tartalmazott, halála előtt adta ki. Bár csak két törvény vonatkozott az egyház szerepére, ezek István király legfontosabb vallási törvényei. Kötelezte a termés egy tizedének beszolgáltatását a püspökségek javára (decima, dézsma = tized), és előírta, hogy minden tíz falu építsen templomot. A templomok berendezését is támogatta: a szentkönyvekről a püspököknek, az egyházi textíliákról a királynak kellett gondoskodnia. (Érdekesség, hogy az 1031-ben a fehérvári egyháznak adományozott koronázási palást Gizella királyné keze munkája.)\n\nFontos szerepet kapott a korábbi vérségi alapon szerveződő közigazgatási rendszer helyett létrejövő vármegyerendszer. A vármegyerendszer a királyi hatalom megerősödésével párhuzamosan épült ki. A megyék nevüket legtöbbször a központjukban álló várról kapták. A királyi vármegye különböző tulajdonú (királyi, egyházi, magán) földekre terjedt ki. Egy-egy vármegye igazgatását az ispán (comes) látta el, akit a király választott. Az ispán megyéjében bíráskodott a király nevében és beszedte a királyi jövedelmeket (szabadok dénárjai, vámok), melynek harmada őt illette, és háború esetén ő vezette a megye haderejét a király seregébe. A vármegyeszervezet vezetője a királyi udvar bírája, a nádorispán volt, a király után az első ember az országban. A vármegye (comitatus) fogalma az Árpád-korban mást is jelentett. Így hívták a várispánságokat is, a királyi várhoz szétszórtan tartozó földeket, melyek feladata a királyi várak eltartása volt.\n\nA magyar társadalom élén a király állt, akinek hatalmát óriási földbirtokai alapozták meg. Ám a szokásjognak megfelelően a fontos döntések előtt kikérte az egyházi és világi előkelők alkotta királyi tanács véleményét. A vezető réteghez tartoztak a birtokadományok és a decima révén megerősödött egyházfők, és a törzsi vezetők (Csákok, Abák) és a bevándorolt lovagok (Hont, Pázmány) leszármazottaiból kialakult világi nagybirtokosok. A középréteget a vitézek alkották, akik saját földbirtokaikat szolgákkal műveltették meg. A földjeiket elvesztett szabadok két megoldás közül választhattak. Vagy a peremterületeken lévő szabad földekre vándoroltak, vagy szabadságukat részben feladva egy nagybirtokos oltalmát választották. A szolgák helyzete volt a legrosszabb, velük uruk korlátlanul rendelkezhetett. A század végén azonban a helyzetükben változás ált be, egy részük terményhányad fejében szabad földet kapott.\n\nKülpolitikája: I. István békére törekedett. II. Konrád német-római császár 1030-ban megtámadja Magyarországot, de sikerül visszaverni. Keleten Bölcs Jaroszláv államával jó viszonyt alakított ki.\n\n8. Az utódlás kérdése: mivel első fia hamar meghalt, az egyházi pályára szánt Imre herceg lett a trón várományosa. Számára íratta meg az Intelmeket, mely arról szól, milyen a jó király és hogy hogyan igazgassa az országot. Imre azonban vadászbalesetben hal meg 1031-ben. Istvánnak olyan utódra volt szüksége, aki folytatja eddigi tevékenységét. Unokatestvére, Vazul szemben állt István törekvéseivel, ezért uralkodásra képtelenné tette, megvakíttatta és süketté tette. I. István nővérének fia, Orseoló Péter bizonyult számára alkalmasnak a feudális állam vezetésére. Így 1038-ban, István halála után ő lett a király 1041-ig, majd 1044-46 között, ugyanis közben Aba Sámuel volt az uralkodó, akinek a vezetésével elűzték Pétert az országból. I. Istvánt egyébként Székesfehérváron temették el, s 1083-ban szentté avatták.\n\nÁm a későbbi uralkodók is belátták, hogy Géza és István államalapító munkássága által megkezdett utat folytatni kell, hogy tovább fejlődjön az ország. Annyira fontosnak találták a követendő példák kitűzését, hogy 1083-ban Szent László uralkodása alatt szentté avatták István királyt, Imre herceget, Gellért püspököt, Gizella királynét pedig boldoggá.\n\nA Szent István-kori (997-1038) társadalom\n\nKirály: István király állandó kormányzati beavatkozásokkal igazította a társadalomhoz az új államszervezetet. Lerombolta a törzsi államokat, és a területi szerveződés eszméjét állította előtérbe (vármegyerendszer). Az ország legnagyobb része az uralkodó magánbirtoka, amely a patrimoniális monarchia alapja is. A kereszténység felvétele után a teokratikus királyságban az uralkodó szakrális személyiség, az egyház feje lett, és a koronázással egyházszervezési jogokat is kapott. Az István-korabeli társadalom élén a király állt, akinek hatalmát óriási, az ország területének kétharmadát kitevő földbirtokai alapozták meg.\n\nA királyi kíséret, a királyi tanács és a tisztségviselők (országosak - pl. a nádorispán -, udvariak - pl. a pohárnokmester) adták a vándorló királyi udvartartás magját. Rajtuk kívül a (vár- és megye-) ispánok és az egyházi személyek segítették a király munkáját. Az Árpád-kor elején a szabadok elitjét (arisztokrácia) a királyi birtokadományok révén megerősödő lovagok, ispánok (comes) és egyházi előkelők alkották. A vitézek (miles) – a szabadok egy másik, kisebb birtokkal rendelkező rétege – a király, illetve az előkelők mellett teljesítettek fegyveres szolgálatot.\n\nA legélesebb jogi választóvonal a szabadok (liber) és rabszolgák (servus) között húzódott. A társadalom legnagyobb részét azonban minden bizonnyal a „köztes” helyzetű kötött szabadok rétege alkotta, akik nem rendelkeztek a szabad költözés, házasság, végrendelkezés, fegyverviselés jogával, és szolgálattal tartoztak uruknak. A XI. század legszélesebb rétegeket érintő folyamata a korábbi szabad harcosok, parasztok (közrendűek, vulgarisok) kötötté válása jelentette. A közrendűek (vulgaris) már adóval (szabadok dénárja) tartoztak a királynak. Az egyházi, illetve világi nagybirtokokat és a királyi várbirtokokat kötött állapotú népességgel műveltették meg. A várispánságok katonái és katonatisztjei (várjobbágyok) is ebbe a csoportba tartoztak, de a várjobbágyok kisebb birtokadományban is részesülhettek, s ezáltal lehetőségük nyílt a felemelkedésre is.\n\nSZENT LÁSZLÓ ÉS KÖNYVES KÁLMÁN\n\nA KIRÁLYI HATALOM MEGSZILÁRDÍTÁSA\n\nA feudális rend - Szent István halála után – I. László király (1077-1095) és Könyves Kálmán (1095-1116) idején szilárdult meg. l. (Szent) László (1077-1095) megszilárdította az ország belső rendjét és külső helyzetét. A XI. századi trónviszályokon I. Béla kisebbik fia, a lovagi erényeiről híres I. László lett úrrá.\n\nl. (Szent) László (1077-1095) tehát megszilárdította az ország belső rendjét és külső helyzetét. Szent László a testvére, I. Géza király (1074-1077) halála után került a trónra. A korábban kettejük által a trónról letaszított Salamonnal (1063-1074) rövid ideig békében éltek, majd miután Salamon összeesküvést szervezett, I. László elfogatta, és Visegrádon börtönbe záratta.\n\nÜgyesen használta ki az ország érdekében a pápaság és a császárság küzdelmét (invesztitúraharc). Ennek eredményeként a pápa hozzájárult István király, Imre herceg és Gellért püspök szentté avatásához (1083). Ez növelte az országban a kereszténység és a királyi család tekintélyét. László a megszilárduló ország erejére támaszkodva meghódította a Dinári-hegység északi részén elterülő fiatal királyságot, Horvátországot (1091). Zágráb központtal új püspökséget alapított. Sikeresen verte vissza a keletről betörő nomádokat (kunok, besenyők). Eredményei és személyes bátorsága rendkívül népszerűvé tették.\n\nTÁRSADALMI viszonyok Szent László uralkodása idején\n\nA XI. század végére az egykori törzsi-nemzetségi vezetők (Csákok, Abák) és a bevándorolt lovagok (Hont, Pázmány) leszármazottaiból - a főpapi rend mellett - kialakult a világi nagybirtokos réteg. A trónharcok során a hatalmas királyi birtokok rovására növelték földjeiket. A társadalom középrétegét a saját földbirtokkal rendelkező szabadok alkották, akik földjeiket szolgáikkal műveltették meg. Valamennyi földbirtokos arra törekedett, hogy a birtokán élőket függőségbe vonja, így a szabadok tömegei - akiknek nem volt földjük, vagy elveszítették azt - lesüllyedtek, szolgáltatásokra kényszerültek (munka és termény).\n\nA XI. századi magyar társadalomban még mindig különbség volt a szabadok és a szolgák között. Létrejött egy új alávetett réteg, melyet a főleg terményszolgáltatásra kötelezett szabadok és a szolgák alkottak. Ezek a földesúrtól használatra kapott földön gazdálkodtak. Az átalakulás hosszú folyamat volt, s ez idő alatt számos átmeneti állapot létezett. A szabadok egy része, hogy elkerülje az alávetést, az ország peremterületeire vándorolt (kóborlók), ahol még nem alakult ki a magánföldesúri hatalom.\n\nSZENT LÁSZLÓ TÖRVÉNYEI\n\n• 3 törvénykönyvét ismerjük: Szent László a kor alapvető problémáit törvényekkel is igyekezett megoldani, melyeket a királyi tanáccsal együttműködve adott ki. Törvényei kiemelten védték a magántulajdont. Erre azért volt szükség, mert az új rend elől a peremvidékek menekülő népesség, a kóborlók megélhetésük érdekében lopni kényszerültek. László keményen fellépett ellenük.\n\n- Az első törvénykönyve az 1092-es szabolcsi zsinat határozatait tartalmazza (ünnepek számának a meghatározása, a tizedfizetés szabályozása, elítélte a nőrablást, a házasságtörést).\n\n- A másik kettő törvénykönyve középpontjában a magántulajdon szigorú védelme és a vándormozgalmak korlátozása állt.\n\n- A tolvajokat tettenérés, vagy egy tyúknál nagyobb értékű lopás esetén megcsonkítással, kéz- vagy orrlevágással, nyelvkitépéssel büntették. Majd pedig ha egy szabad ember egy tyúk értéke felett lopott, tettéért halállal lakolt.\n\n- Törekedett a lecsúszás, függésbe kerülés elől vándorlással, kóborlással menekülő szabadok elfogására, letelepítésére.\n\nBűncselekmények büntetése:\n\n- büntetik a lopáson érteket, a gyilkosokat, a cselszövőket, a hanyagokat, a hatalmaskodó ispánokat; a büntetéseknél jellemző a talio-elv.\n\nÚj birtokrend biztosítása: mindenki szabadon rendelkezhet öröklött és a királytól kapott vagyona felett, amelyet fiai is örökölhetnek; a király csak attól veheti el vagyonát, aki ellene összeesküvést sző, és külföldre menekült.\n\n„4. Ha ezután valakit az egész falu tolvajnak kiált, istenítélettel vizsgálják meg. Ha ennek folytán ártatlannak bizonyul, a falu csupán egy penzát fizessen a papnak. Ha pedig bűnösnek találják, minden vagyonát foglalják le a király részére, amiből negyedrészt a falubelieknek adjanak.\n\n6. Ha a bíró a rabszolga orrát nem vágja le, vagy a szabadot nem akasztja fel, vesszen mindene, fiain és lányain kívül, s magát adják el. Ha pedig ártatlant akaszt fel, száztíz pénzt fizessen, és a felakasztott személy minden vagyonát adja vissza.\n\n12. Ha valamely szabadot vagy rabszolgát lopáson érnek, akasszák fel. Ha pedig, hogy meneküljön az akasztófától, a templomba menekül, kihozván őt a templomból, vakítsák meg. Az olyan rabszolga pedig avagy szabad, aki libát vagy tyúkot lop, fél szemét veszítse, s amit lopott, adja vissza.\n\n14. Ha valamely szabad ember tíz dénár értékűt lop, akasszák fel, ha tíz dénárnál kisebb értékűt lop, a lopott értéket tizenkétszeresen adja vissza, és egy ökröt fizessen.” (I. László II. törvénykönyvéből)\n\nEgyházi intézkedései\n\nAz uralkodó törvényeiben erősítette az egyházi (pl. ismét rendelkezett a tizedről) és fellépett a pogány szokások ellen.\n\n• új birtoklási rend biztosítása (magántulajdon feletti szabad rendelkezés);\n\n• keresztény vallásgyakorlás biztosítása (vasárnap, böjt, gyónás), megzavarásának büntetése;\n\n• erőszakos cselekmények (gyilkosság, gyújtogatás) megakadályozása;\n\n• földesurak jogainak biztosítása népeik felett; szabad ember nem hajtható szolgaságba;\n\n• vendégek, hospesek befogadása; özvegyek és árvák védelme;\n\n• boszorkányok és varázslók büntetése.\n\n• A reformpapság törekvéseinek (pl. cölibátus) megvalósítása, továbbá a papság iskoláztatása és hivatali feladatainak ellátása (hiteleshelyek) érdekében támogatta a káptalani szervezet (világi papokból álló, szabályozott közösségi életet élő testület) kialakítását.\n\nÚj apátságokat alapított (pl. somogyvári bencés).\n\nKülpolitikájának hátterében meghatározó volt a kibontakozó invesztitúra harc.\n\n• 1077-91 között pápapárti politika, okai:\n\n- Salamont a császár támogatta, aki hűbérúri jogot formált Magyarországra.\n\n• 1091-95 között császárpárti politika, okai:\n\n- Meghalt Salamon, ezzel megszűnt az ok, amely szembeállította a császárral.\n\n- 1091-ben László megtámadta és el is foglalta a pápai hűbéres Horvátországot és élére bátyjának kisebbik fiát, Álmost állította, akit örökösének is kijelölt.\n\n• I. László királyt Váradon temették el. 1192-ben III. Béla király avattatta szentté.\n\nLászló végakaratával szemben mégsem Álmos herceg, hanem a papnak tanult Kálmán (1095-1116) foglalta el a trónt. Álmosnak meg kellett elégednie a dukátussal (hercegség). Később is harcoltak egymással. Amikor Álmos 1107-ben jeruzsálemi zarándokúira ment, Kálmán megfosztotta a dukátustól, később merénylet kísérletek miatt a király megvakíttatta Álmost és fiát, Bélát.\n\nKÖNYVES KÁLMÁN (1095-1116)\n\nLászló halálát követően rövid trónharc után (Könyves) Kálmán szerezte meg a trónt (1095-1116). A papnak nevelt uralkodó a kor szokásainak megfelelően igyekezett hódításokkal gyarapítani országát. Megpróbálta elfoglalni a széteső kijevi állam nyugati tartományát (Halics), ám uralmát a Kárpátok keleti oldalán nem tudta megszilárdítani. Kálmán délnyugaton folytatta az előretörést, s megkezdte a dalmát városok (Trau, Zára, Spalato) hódoltatását. Az újlatin nyelven beszélő dalmátok nem fejtettek ki ellenállást, mivel Kálmán nem csorbította önállóságukat, de védelmet biztosított számukra Velencével szemben.\n\nKálmán külpolitikájának jellemzői:\n\n• A pápaság felé orientálódott (ő maga is egyházi személy volt!), jó kapcsolatban volt II. Orbánnal, bár Kálmánnak is meggyűlt a baja az I. keresztes hadjárat Amiens-i Péter vezette „seregével”, akiket az országon való átvonuláskor fegyverrel kellett kordában tartani, és végül kiűzni. Az egyházszervezést befejezve Kálmán megalapította a nyitrai püspökséget.\n\n• 1102-ben Horvátország királyává koronázták, ezután megkezdte a dalmát partvidék kereskedővárosainak a „meghódítását”: Spalato (Split), Raguza (Dubrovnik), Zára (Zadar) és Trau szinte „önként” hódoltak meg, mert számukra kedvezőbb volt a magyarok, mint a kereskedelemben rivális velenceiek uralma.\n\n• Többször vezetett hadjáratot Halicsba, nem sok sikerrel.\n\nKÁLMÁN TÖRVÉNYEI\n\nKálmán is törvényekkel kívánta elősegíteni a feudális rend megszilárdulását. Rendelkezéseiben - László törvényeihez hasonlóan - a magántulajdon védelme állt a középpontban. A viszonyok javulását jelzi, hogy Kálmán enyhített László törvényeinek szigorán. Már „csak” egy négylábú állat értékénél nagyobb vagyon ellopásáért szabtak ki halálos ítéletet. A lesüllyedő szabadok szökése, kóborlása továbbra is gondot okozott. A megoldást - Lászlóhoz hasonlóan - az erőszakos letelepítésben látta. A büntetések során ő már nem tesz különbséget szabadok és szolgák között.\n\nA világi vezető réteg megerősödését mutatja, hogy Kálmán törvénye páncélos vitézek kiállítását írja elő számukra. Tehát képesek voltak előteremteni e költséges fegyverek és felszerelés árát. Ugyanakkor az uralkodó igyekezett a trónviszályok következtében megcsappant királyi birtokállományt pótolni. Elrendelte, hogy a fiúágon kihaló nemzetségek birtokai visszaszálljanak a királyra (háramlási jog).\n\nKálmán a királyi tanáccsal és az egyházi zsinatokkal öt törvénykönyvet adott ki.\n\n• Továbbra is központi szerepe volt az új társadalmi rend megszilárdításának és a magántulajdon védelmének.\n\n- De a törvények már kevésbé szigorú szankciókat tartalmaztak (valószínűleg I. László kegyetlen törvényei megtették hatásukat).\n\n- A kóborlókkal szemben továbbra is a letelepítés politikáját szorgalmazta.\n\n- Megjelentek a reformpápaság törekvései (szabályozták a szerzetesi életet, a cölibátust).\n\n- „A boszorkányokról pedig, mivel ilyenek nincsenek, semmiféle vizsgálatot ne tartsanak” - meglepő, és szokatlan felfogás volt ez abban a korban.\n\nKálmánt 1116-ban Fehérváron temették el, utóda fia, II. István (1116-31) lett.\n\nKálmán halálát követő fél évszázadot folytonos trónharcok jellemezték. A kegyetlen belviszály (megvakítás, tömeges gyilkosságok) ellenére az ország tovább fejlődött. A birtokadományok révén folytatódott a világi vezető réteg megerősödése, a szabadok lesüllyedése és az ország gazdasági átalakulása.\n\nA belső viszályok ismét lehetőséget adtak a külső beavatkozásra. Az újra erőre kapó Bizánc (Mánuel császár) átmenetileg megszerezte a Szerémséget. A bizánci befolyás erősödését az is mutatja, hogy a gyermektelen császár (akinek az édesanyja Szent László leánya, Piroska volt) szorosabbra akarta fonni a dinasztikus kapcsolatot az Árpádokkal.\n\nUtódjául jelölte, és magával vitte Bizáncba Béla herceget (1163), hogy felkészítse a császári szerepre. Ám miután Mánuelnek fia született, Bélát félreállították. A később Magyarország trónját - bizánci segítséggel - megszerző III. Béla (1172-1196) uralkodóként ügyesen felhasználta a bizánci udvarban szerzett tapasztalatait.\n\nLászló és Könyves Kálmán törvényeinek összehasonlítása:\n\nAz uralkodásukat megelőző időszakban trónviszályok és pogánylázadások voltak.\n\nA kereszténységgel kapcsolatos rendelkezéseik pl. a böjtölés, a vasárnapi mise látogatásának előírása, a pogány szokások gyakorlásának büntetése, a tized fizetésének megerősítése. A keresztény vallás gyakorlására kötelezték az alattvalókat, ugyanis a pogányság még jelen volt a társadalomban. A törvényekkel biztosították az egyház működésének anyagi alapját.\n\nA papok házasságával kapcsolatos rendelkezések között eltérés van. Szent László ideiglenesen engedélyezte a papok házasságának fenntartását, Könyves Kálmán viszont már feleségük elbocsátására kötelezte a papokat\n\nA törvények hátterében a papi nőtlenség bevezetése állt, a változás az egyház álláspontjának megszilárdulásával, és az invesztitúra küzdelem alakulásával magyarázható.\n\nMindkét uralkodó büntette a tolvajlást, ez a magántulajdon védelmét szolgálta, hátterében a vagyoni különbségek növekedése állt, László törvényei szigorúbb, Kálmán törvényei enyhébb büntetést szabtak ki.\n\nMindkét uralkodó tiltotta a kóborlást. A kóborlás hátterében a szabadok szolgasorba süllyedése, a megyerendszer megszilárdulása, a magánföldesúri birtok kialakulása állt. A kóborlók gyakran tolvajlásból tartották fenn magukat. A kóborlások a trónviszályok időszakában váltak elterjedtté.\n\nMindkét uralkodó törvényeinek jelentősége: az államalapítással létrejött társadalmi rend megszilárdítása, a királyi hatalom megerősítése. Szent István politikáját folytatták.\n\nIII.Béla (1172-1196)\n\nKorának egyik leggazdagabb európai uralkodója volt. A magyar állam egyik legsikeresebb korszaka kapcsolódik hozzá: a Bizáncban, a császári trón várományosaként szerzett tapasztalatainak köszönhetően sikerült felvirágoztatnia a magyar gazdaságot és a kultúrát, lépéseket tett az írásbeliség általánossá tétele irányába, sikeres külpolitikájának eredményeképp pedig a Magyar Királyság befolyási övezete is gyarapodott. Uralkodásának végére a Magyar Királyság vált az egyik vezető hatalommá Kelet-Közép-Európában. Regnálása az Árpád-kor csúcspontját jelentette. Apja II. Géza magyar király, Álmos herceg unokája. A XII. század Magyarországon a trónviszályok kora. II. Géza király halálát követően III. István (Béla testvére) került hatalomra, azonban nagybátyjaik, István és László a bizánci császár, I. Manuél támogatásával ellenkirályként léptek fel III. István uralma ellen. Manuél sereggel indult Magyarországra, de III. Istvánnak sikerült kiegyeznie a császárral. Béla herceg ekkor került Bizáncba, ahol felvette a görög Alexiosz nevet. I. Manuél Béla számára külön címet is létrehozott: ő lett a császár első embere, a deszpotész. Manuelnek nem volt fiú utóda, ezért Bélát a bizánci trón várományosává tette. Később fia született, emiatt Bélát megfosztotta méltóságától. Béla bátyja, III. István 1172-ben meghalt, hívei Bélának ajánlották fel a magyar koronát. Uralkodása során nemcsak a bizánci császárral volt jó kapcsolata, emellett nyugat- és pápabarát politikát is folytatott Barbarossa Frigyes német-római császárral szemben. A francia-magyar kapcsolatok erősödésével a ciszterci rend magyarországi szerepe megerősödött. Uralkodása alatt, az 1190-es évekre a királyi kancellária oklevéladási gyakorlata megszilárdult. Uralkodásának idején keletkezett az első nagyobb összefüggő magyar nyelvemlék, a Halotti beszéd és könyörgés, illetve ebben az időben végezte jegyzői munkáját „P. mester”, Anonymus is, aki a Gesta Hungarorum szerzője volt. 1185-ben lejegyezték a székesfehérvári törvénylátó napok megtartását. Ez a legrégebbi írásos bizonyíték a törvénylátó napok létéről. A magyar történelemben ezek a törvénylátó napok rendkívüli szereppel bírnak, hiszen belőlük alakult ki a mai országgyűlés. 1185–1186-ban keletkezett az első kimutatás a magyar királyi jövedelmekről. Ebből kiderül, hogy III. Béla éves bevétele egy szinten állt az angol és a francia királyéval, és csak a bizánci és a német-római császár bevételei voltak nagyobbak a korabeli Európában. Túlnyomóan domaniális jövedelmei voltak pl. királyi uradalmak terményjövedelme. III. Béla értékálló pénzt is veret: rézdénárjai bizánci mintára készültek. 1192-ben az ő szorgalmazására emelte a szentek közé III. Celesztin pápa I. László királyt.\n\nAz Aranybulla – mozgalom eredményei (1222)\n\nI. II. András (1205-1235) bel- és külpolitikájának következményei:\n\nA királyi birtok kevés a birtokadományozások miatt.\n\nA királyi vármegyerendszer már nem tudja ellátni katonai és igazgatási feladatait a gyenge királyi hatalom miatt.\n\nA király keresztes hadjáratai a Szentföldre és Halicsba pénzhiányhoz vezet.\n\nA király ezért a regálékat bérbe adja (vámszedés, sóértékesítés, pénzverés) és a kamara haszna érdekében a pénz értékét folyton lerontja.\n\nA gyenge királyi hatalom és a gazdasági válság miatt a nagybirtokosok hatalma megnő,1213-ban összeesküvést szerveznek II. András idegen felesége, Gertrúd ellen.\n\nA paraszti terhek megnövekednek.\n\nA szerviensek (kis-és középnemesek) függetlensége veszélybe kerül, mert a nagybirtokosok állandó katonáskodásra kényszerítik őket a magánhadseregeikben és a királyi hatalom meggyengülése miatt nincs, aki megvédje őket a nagyobb földesurak (főnemesség) hatalmaskodásaitól.\n\nElégedetlenségük miatt 1222-ben a fehérvári törvénylátó napon a királyhoz fordulnak.\n\nArra késztetik a királyt, hogy jogaikat törvénybe iktassa.\n\nEkkor adja ki II. András a díszes külsejű, arany függőpecséttel ellátott királyi oklevelet, az Aranybullát, mely 31 cikkelyből áll.\n\nII. Az Aranybulla (1222):\n\nA serviensek jogai:\n\nAdómentességet élveznek, mint a nagybirtokosok és függetlenséget élveznek tőlük\n\nBirtokaikon senki sem szállhat meg engedély nélkül\n\nCsak az ország védelmében kötelesek hadba vonulni\n\nBírói ítélet nélkül nem lehet felettük ítélkezni\n\nSzabadon végrendelkezhetnek, birtokaikat utódaik örökölhetik\n\nCsak a nádor és a király ítélkezhet felettük\n\nA várjobbágyok érdekében:\n\nTilos tőlük a tizedet pénzben szedni, csak terményben kell\n\nNem lehet bérbe adni a regálékat\n\nTilos a pénzrontás, a király legalább egy évig érvényben hagyja az új pénzt.\n\nA királyra és a bárókra vonatkozó törvények :\n\nA király megígéri, hogy megtartja az idegenek birtokszerzésének tilalmát\n\nA király nem fog egész vármegyéket adományozni\n\nMéltóságok halmozódásának a tilalma\n\nAz Aranybulla az ellenállási záradékkal zárul: ennek értelmében ha valaki, akár a király is megszegi a bulla pontjait, a nemeseknek jogukban áll ellenállni. A király azonban nem tudja betartani és betartatni a bulla pontjait, ezért kétszer is módosítják:\n\nAz Aranybulla1231-es módosítása: az egyháznak kedvez.\n\nKimarad a tized pénzben való szedésének tilalma, bővül az egyház bírói szerepe\n\nAz ellenállási záradék módosul, az ellenállási jogot az esztergomi érsek kapja meg.\n\n1233-as beregi egyezmény\n\nKimondják az egyház teljes adómentességét\n\nVisszaszorítják a zsidókat és izmaelitákat, akik eddig a királyi regálékat bérelték.\n\nAz egyház visszakapja a só kereskedésének jogát.\n\nA szervienseket azonban nem védték meg a törvények a nagybirtokosoktól, ezért 1232-ben a zalai szerviensek (kehidai oklevél) önvédelmükre megszervezik az önkormányzattal bíró nemesi vármegyét. Élén az ispán áll.\n\nIV. Béla (1235-1270)\n\nA tatárjárás előtt:\n\nIV. Béla (1235-1270) - II. András fia – eleinte arra törekedett, hogy az apja által eladományozott birtokokat visszaszerezze. Ez a nemesség ellenállását váltotta ki.\n\nBefogadta az országba a nomád kunokat, ez a magyarok ellenállásába ütközött: Kötöny kánt megölték a magyarok, ezért a kunok emiatt kivonultak az ország, pedig segítséget jelentettek volna a tatárok ellen.\n\n1236-ban Julianus barát megkereste a magyarok elődeit Baskíriában (Magna Hungariában), itt értesült a Mongol Birodalom terjeszkedéséről, a tatár veszélyről, s értesíti erről a királyt is. 1240-ben a tatárok már Kijvet is elfoglalták.\n\nA tatárjárás:\n\n1241 márciusában támadást indított a tatár sereg, Batu kán az Arany Horda élén 1241. április 11-én győzelmet aratott Muhinál a magyarok felett. A királyt nem támogatták a magyar urak, ő maga is nehezen tudott megmenekülni. A német császártól is segítséget kért, de nem kapott. A dalmáciai Trau várában húzódott meg a tatárjárás idején.\n\nA tatárok közben végigpusztították az országot: a pusztítás mértéke 25-50%-os volt. 1242-ben váratlanul elhagyták az országot. Feltételezések szerint Ögödej nagykán halála miatt, mert a kánválasztáson Batu kán is jelen akart lenni.\n\nA tatárjárás után:\n\nIV. Bélát a második honalapítónak nevezzük, ugyanis a tatárok kivonulása után újjáépítette az országot.\n\nBirtokokat adományozott, de katonaállításhoz kötötte az adományt\n\nFelhagyott birtokvisszaszerző politikájával.\n\nVárak építésére ösztönözte a nemeseket védelmi célból, a városokat fallal kell körülvenni\n\nAz elnéptelenedett részeket betelepítette: az Alföldre a kunokat, a Felvidékre szlovákokat, Erdélybe románokat.\n\nA szerviensek (kisnemesek) számára létrehozta a familiárisi rendszert: egy báró tágabb családjába kerültek. Békeidőben a báró birtokát igazgatta, háborúban pedig katonáskodott ura mellett.\n\nA BELPOLITIKAI HELYZET a tatárjárás előtt:\n\nII. András halála után IV. Béla lépett a trónra (1235-1270), aki az apja politikáját élesen bírálta. Arra törekedett, hogy visszaállítsa a királyi hatalom tekintélyét, ezért hozzálátott az apja által eladományozott királyi birtokok visszavételéhez (királyi birtokrendszer restaurációja). Nem volt tekintettel senkire, sorra kerültek a báróknak, a szervienseknek, sőt a várjobbágyoknak adományozott birtokok is. A vezető réteg mindegyik csoportjával szembekerülő uralkodó támasz nélkül maradt. Fokozta az iránta érzett ellenszenvet néhány olyan intézkedése, amely a királyi tekintélyt formálisan erősítette.\n\nleszámolt apja híveivel (pl. Ampod fia Dénest megvakíttatta);\n\na királyi tanácsba saját híveit ültette;\n\nA királyi tanácsban elégettette a bárók székeit, így a főpapok és hercegek kivételével senki sem ülhetett le a király jelenlétében. Míg korábban a bárók előzetes bejelentés nélkül a király elé járulhattak, Béla kérelemhez kötötte ezt.\n\nAz 1236-ban elindult a domonkos rendi szerzetes Julianus barát néhány társával, hogy megkeresse a magyarok elődeit Baskíriában (Magna Hungariában). Hírt hozott a közelgő tatár (mongol) veszedelemről, Béla a védelem érdekében leállította a birtokvisszavételeket. Batu kán 1238-ban meghódolásra szólította fel IV. Bélát, aki nem engedelmeskedett. 1240-ben a tatárok már Kijevet foglalták el. A bárók, sőt a szerviensek jelentős része azonban továbbra is ellenségesen viszonyult az uralkodóhoz.\n\nFokozta a belső feszültséget, hogy a tatárok elől menekülő kunok egy része bebocsátást kért az országba. 1239-ben befogadta az országba a nomád kunokat, akiknek vándorló életmódja, legelésző állataik sok kárt okoztak a földesurak földjein. Mindezen intézkedések a bárók komoly ellenállását váltották ki a mongol támadás előestéjén. Az uralkodó nehéz helyzetbe került. Visszautasítás esetén számíthatott erőszakos betörésükre. Ha viszont befogadja a kb. 40 000 kunt, szembe kell néznie a nomádok és a letelepült magyarok között esetleg kialakuló viszályokkal. Miután az ország védelme érdekében szüksége volt a kun könnyűlovasságra, Béla a bebocsátás mellett döntött. A kun király, Kötöny népével együtt névleg keresztény hitre tért, és az Alföld ritkábban lakott területeire vonult. A kunok azonban nomád módon éltek (lovaik lelegelték a vetést, nőket raboltak el feleségnek), ami folyamatosan összeütközésekhez vezetett a magyar lakossággal. A király a vitás ügyekben - nem dönthetvén másként - többnyire a kunok pártját fogta, így tovább mélyült a király és az alattvalói közötti ellentét. . A magyarok Budára hívták a kunok vezérét, Kötöny kánt, akit meggyilkoltak.\n\nA TATÁRJÁRÁS (1241-1242)\n\nA tatárokról Julianus barát hozott hírt, aki Baskíriában kereste fel a magyarok elődeit. Amikor a tatárok Kijevet is elfoglalták (1240), IV. Béla (1235-1270) segítségért fordult Európa keresztény uralkodóihoz. Ám azokat egymással folytatott küzdelmeik, belső problémáik kötötték le, és nem érezték fenyegetve országukat.\n\nIV. Béla befogadta a tatárok elől menekülő kunokat. A magyarok nem bíztak meg bennük, ugyanis nomád életmódjuk miatt összekeverték a kunokat és tatárokat, és a királyt hibáztatták a kunok behívásáért. Ezután a kunok kivonultak az országból, ezzel a király hadereje gyengült.\n\nA tatárok 1241-ben három irányból törtek Magyarországra. A Vereckei-hágón érkező mintegy 60.000 fős hadat, az Arany Hordát Batu kán vezette. A jobbszárny Lengyelországot, majd Morvaországot dúlva északnyugatról, balszárnyuk Erdélyen át tört az ország belseje felé. Béla fegyverbe szólította az országot (körülhordozták a véres kardot).\n\nA királlyal elégedetlen magyar előkelők azonban csak lassan gyülekeztek (bárói és főpapi bandériumok, a vármegyék hadereje, szerviensek). 1241. március 12-én a tatár fősereg a Vereckei-hágónál elsöpörte Tomaj Dénes nádor seregét. A támadás déli szárnya, Kadan és Bödzsek vezetésével Erdélybe tört be, míg északi szárnya, Orda és Bajdar vezetésével Lengyelország felől később érkezett az országba. A tatárok nagyon gyorsan vonultak át az alföldi területeken, itt nem voltak várak és erődített városok, amelyek megállították volna őket.\n\nA gyors előretörést a főurak a kunok árulásának tudták be, ezért Pesten megölték Kötöny, kun fejedelmet. Válaszul a kunok déli irányba, dúlva, fosztogatva elhagyták az országot. Emiatt tovább gyengült a magyar védelem.\n\nA tatár előőrsök Pestig törtek előre, majd a Sajóig csalták a Pest alatt összegyűlt magyar sereget. Muhi közelében, 1241. április 11-én a tatárok megsemmisítő vereséget mértek a magyar hadseregre. Nomád harcmodor jellemezte a tatárokat, mellyel sikert arattak. A muhi csatában a király serege tehát döntő vereséget szenvedett, előtte már legyőzték a nádor seregét is. Éjszaka kerítették be a király seregét, a szekérvár eredménytelennek bizonyult.\n\nIV. Béla választott taktikáját, hadvezéri képességeit a történészek eltérően ítélik meg. Hagyományosan a király rossz taktikáját, a szekérvár alkalmazását hibáztatták a vereségért. Az új kutatások szerint megfelelő volt a helyszín megválasztása és a szekérvár felállítása, de a szekérvár végül nem volt megfelelő hadászati megoldás.\n\nA király serege a bárók vonakodása miatt sokkal kisebb volt, nem vettek részt a király mellett az ország védelmében. A magyarok között sokan a király vereségét kívánták, hiszen nem tetszett a magyar nemesség számára, hogy még a tatárjárás előtt a király vissza akarta szerezni a földbirtokosoktól a korábbi királyok által eladományozott birtokokat. Még a vereség ellenére sem tört meg teljesen az ellenállás az országban. IV. Béla csak nehezen, kísérete önfeláldozása árán tudott elmenekülni a harcmezőről.\n\nIV. Béla nyugati irányba menekült, segítséget kért a német császártól és a pápától is, de nem kapott. Osztrák földön keresett menedéket Babenberg Frigyesnél. Ám az osztrák őrgróf, kihasználva a magyar uralkodó szorult helyzetét, a királyt megsarcolta, és néhány megye átadására kényszerítette. A király menekülése során az osztrák herceg fogságába került, elzálogosított néhány vármegyét, király Horvátországban / Dalmáciában / Trau várában lelt menedékre, bár a tatárok üldözték a királyt, de az ország vezetése nem semmisült meg. Tehát Béla Dalmáciába menekült tovább, ahol a szigetre épült Trau várába zárkózott. A vereség és a király távozása nyomán az ország védtelenül, kiszolgáltatva állt a tatár hadak előtt.\n\nA nép mocsarakban, erdőkben keresett menedéket a pusztító tatárok elől. A jól megerősített kővárak (Trencsén, Pozsony, Komárom, Fülek) védelmet nyújtottak az oda menekülőknek. A tatárok a tél beálltával a Dunántúlra törtek, a befagyott Dunán keltek át. A dunántúli várakat a tatárok nem tudták elfoglalni, így a Dunántúlon a pusztítás mértéke is kisebb volt, emiatt a tatárjárás után új kővárakat építettek. Központi irányítás hiányában itt is csak néhány kővár tudott ellenállni (Esztergom, Székesfehérvár, Pannonhalma). 1242 márciusában a tatárok - foglyok tömegét magukkal hurcolva - váratlanul kivonultak az országból. A kivonulás pontos oka vitatott: Ögödej nagykán halála miatt az új nagykán választására sietett Batu kán. A másik ok, hogy további támadásokat terveztek, ez a taktikájuk volt, hogy elhagyják az országot, majd visszajönnek, később kisebb hadjáratokra sor is került.\n\nA PUSZTÍTÁS MÉRTÉKE - AZ ORSZÁG ETNIKAI VISZONYAI\n\nA tatárok beszedték az adókat és elvitték a termést, rabságba hurcolták az embereket, kifosztották a lakosságot, elpusztították a városokat. A tatárjárás éhínséget okozott. A magyarországi népesség aránya 20–50%-ot zuhant, az így kieső munkaerőt pótolni kellett, IV. Béla újjáépítette az országot, a betelepítésekkel pótolta a veszteségeket. A tatárjárás után a magyar etnikum mellett más népcsoportok is megjelentek az országban.\n\nA tatárjárás óriási emberveszteséget okozott. Természetesen pontos adatok nem állnak rendelkezésünkre, de a történeti demográfia 20-50% közöttire becsüli a veszteséget (az ország lakossága megközelítette a kétmillió főt a tatárjárás előtt, kb. félmillió volt az emberveszteség). A pusztításról a korabeli Rogerius váradi kanonok tudósított „Siralmas ének” (Carmen miserabile) c. munkájában. Leírása sok szörnyűséget tartalmaz.\n\nA totális vereség okai magyar részről:\n\n• hadvezetés, stratégiai hibák (késlekedés a mozgósításban, Muhinál terepválasztás, szekértábor);\n\n• ellentét a király és a főurak között;\n\n• hiányoztak a várak és a fallal körülvett városok;\n\n• alapvető ok a felbomlóban levő, várispánságokon alapuló királyi hadszervezet miatt nem lehetett hatékony a védelem megszervezése.\n\nA pusztítás elsősorban az alföldön volt jelentős. Mivel elsősorban a magyarság élt ezeken a vidékeken, a tatárjárás kedvezőtlenül hatott az ország nemzetiségi összetételére (etnikai viszonyaira). A lakosság és a települések jelentős része (negyede / harmada) elpusztult, főleg a folyóvölgyekben, síkvidékeken, a keleti országrészben volt nagy a pusztítás. A lakosság az erdőkbe, mocsarakba menekült. A tatárjárást éhínség követte. A tatárjárás után szükség volt a népesség pótlására.\n\nIV. BÉLA POLITIKÁJA A TATÁRJÁRÁST KÖVETŐEN\n\nA népességveszteség pótlását IV. Béla jelentős mértékben külföldiek behívásával oldotta meg (második honalapító). A következő évszázadokban a lakosságon belül a magyarság arányát 80% körülire becsülik. Magyarországon már a tatárjárás előtt is éltek nemzetiségek. Az északi hegyekben szlávok (a későbbi szlovákok ősei), a Szepességben és Dél-Erdélyben szászok. Szétszórtan keletről betelepült nomádok (besenyők, kunok) helyezkedtek el, akik gyors ütemben összeolvadtak a magyarsággal. Ugyanakkor a magyarság egyre inkább benépesítette a Kárpát-medence lakatlan szélső területeit.\n\nA kunok az Alföldre, majd román, szláv bevándorlás folyt a peremterületekre, a németek a Szepességben és Erdélyben települtek le. A tatárok pusztítása elsősorban a síkságokat és a folyóvölgyeket érintette, a népességpusztulás miatt került sor a betelepítésekre, a betelepülők kiváltságokat – adómentesség, önkormányzat – kaptak. A bevándorló népcsoportok mozgásának irányai: az elnéptelenedett középső és keleti területekre nagyarányú vándorlás indult meg.\n\nA külföldről betelepült hospesek szabadon választhatták bíráikat, vásártartási joggal rendelkeztek. A hospesek kiváltságai képezték a magyar városfejlődés alapját. IV. Béla számos településnek adott városi rangot és kiváltságokat. Intézkedései a társadalmi viszonyok átalakulásának felgyorsulásához vezettek, fallal körülvett városok épültek.\n\nA tatárjárás veszteségei megállították a magyarság vándorlását a peremterületekre. E vidékekre bevándorlókat telepítettek: északon szlovákokat, cseheket és lengyeleket, Erdélyben románokat. Az Alföld benépesítése érdekében IV. Béla visszahívta a kunokat (Nagykunság, Kiskunság), s ekkor települtek le a jászok: ez a terület a Jászság. A kunok és jászok - a korábbi nomád népekhez hasonlóan - egy-két évszázad alatt beolvadtak (asszimilálódtak) a magyarságba.\n\nIV. Béla tartott a tatárok újabb támadásától, ezért tudatosan védelmi politikát folytatott. A birtokvisszavételek helyett jelentős adományokat juttatott híveinek. A korábban tiltott várépítés feltétele lett a birtokadományoknak, hogy minél több kővárat emeljenek. A tatárjárás alatt ugyanis bebizonyosodott, hogy a várak hatékony védelmet nyújtanak. S valóban, tömeges várépítés indult meg az országban. Hasonló okokból támogatta a király a városfejlődést, s a városok kőfallal történő megerősítését (Buda, Visegrád).\n\nIV. Béla ösztönözte a tatárok elleni hatékony védekezést szolgáló kővárak építését, és a magánföldesúri várépítést helyezte előtérbe. A várépítést és a bandériumok kiállítását szabta a birtokadományok feltételéül, a király maga is várépítésbe kezdett, ez elsősorban az ország védelmi képességének megerősítését szolgálta. A várépítések erősítették a bárói hatalmat. IV. Béla ezzel az intézkedésével lemondott arról a korábbi szándékáról, hogy a királyi birtokállományt helyreállítsa. A külső fenyegetés a bárókkal való megegyezésre késztette.\n\nTehát összegezve:\n\n• A korábbiakkal ellentétben ő is elkezdett birtokokat adományozni, de feltételekkel: katonaállításhoz kötötte az adományt, megteremtve ezzel a magánhadseregekre épülő banderiális hadszervezet alapjait.\n\n• Nagyarányú nemesítésbe kezdett: a szerviensek mellett sok várjobbágy is nemesi jogokat kapott, ezzel a királyi várszervezet végleg bomlásnak indult.\n\n• Várakat kezdett építeni (pl. Visegrádon), és szorgalmazta a főurak építkezéseit is.\n\n• Igyekezett a városokat is megerősíteni, köréjük falat építtetni (1247. Buda alapítása).\n\n• Szorgalmazta a telepítéseket: a kunokat újra behívta az országba, és az Alföld belső, szinte néptelen területein adott nekik földeket.\n\n• Fejlesztette a hadsereget, megnövelte a nehézlovasság létszámát, besenyőkből, kunokból, jászokból könnyűlovas segédcsapatokat szervezett.\n\n• Békés külpolitikára, szövetséges viszony kialakítására törekedett a szomszéd államokkal.\n\n• Végérvényesen felbomlott az a rend, amely a királyi birtokok túlsúlyán, a királyi közigazgatási rendszeren (királyi vármegyék) alapult.\n\n• A nagy birtokadományok nyomán létrejött egy, az ország nagy területeit birtokló bárói réteg.\n\n• A szerviensekből és várjobbágyokból kialakuló köznemesi réteg saját akarata ellenére kikerült a király felügyelete alól, és kénytelen volt bárói szolgálatba állni kialakult a familiaritás rendszere: ezt erősítette meg az 1267-es törvény.\n\na familiáris (családhoz tartozó „cseléd”) gyakorlatilag élethosszig tartó szolgálatot vállalt (vagy kellett vállalnia) egy bárónál, amiért teljes ellátást és egyéb juttatásokat kapott, de hűbérbirtokot (feudum) nem;\n\na familiáris békeidőben urának birtokát igazgatta, háborúban katonáskodott az úr magánhadseregében (bandérium);\n\na familiáris elméletben sem volt egyenrangú urával, ugyanakkor megpróbálta megtartani a királyi bíráskodás alá tartozás jogát.\n\n• A királyi vármegyerendszert kezdte felváltani a nemesi vármegye, amely élén ugyan a király által kinevezett főispán állt, de a megyei ügyeket a nemesség által választott tisztviselők (szolgabírák) végezték.\n\n• A tatárjárás okozta emberveszteség nagy lökést adott az alávetett rétegek jogi egyesüléséhez. A földbirtokosok, ha dolgozókat akartak a birtokaikra, akkor több kedvezményt kellett adniuk a parasztoknak, így jogilag egységesülő jobbágyság egy, a szolgai állapotnál jóval magasabb jogszinten jött létre. A jobbágyok jogai: szabad költözés; ingóságokkal, szerszámokkal és telkükkel való rendelkezés és örökíthetőség joga.\n\nIV. Béla uralkodása után fia, V. István (1270-1272), IV. (Kun) László (1272-1290) és III. András uralkodott (1290-1301). 1301-ben III. András halálával az Árpád-ház is kihalt.', 260, 1, '2026-04-17 09:40:12', '2026-04-17 09:40:12');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(11, 11, 'Rendi fejlődés Magyarországon', '11.docx', '11. Rendi fejlődés Magyarországon\n\n(Aranybulla, 1351-es törvények, Anjou-kori társadalom, Hunyadi Mátyás központosított állama)\n\nTársadalom az Árpád-korban:\n\nMagyarországos a XI. századtól keresztény feudális királyság működött.\n\nKirály: I. István király (997-1038) még állandó kormányzati beavatkozásokkal igazította a társadalomhoz az új államszervezetet. Lerombolta a törzsi államokat, és a területi szerveződés eszméjét állította előtérbe (vármegyerendszer). Az ország legnagyobb része az uralkodó magánbirtoka, amely a patrimoniális monarchia alapja is. A kereszténység felvétele után a teokratikus királyságban az uralkodó szakrális személyiség, az egyház feje lett, és a koronázással egyházszervezési jogokat is kapott. Az Árpád-korabeli társadalom élén a király állt, akinek hatalmát földbirtokai határozták meg. Ez I.István korában (997-1038) még az ország területének kétharmadát jelentette, később a birtokadományozások miatt ez lecsökkent.\n\nA királyi kíséret, a királyi tanács és a tisztségviselők (országosak - pl. a nádorispán -, udvariak - pl. a pohárnokmester) adták a vándorló királyi udvartartás magját. Rajtuk kívül a (vár- és megye-) ispánok és az egyházi személyek segítették a király munkáját. Az Árpád-kor elején a szabadok elitjét (arisztokrácia) a királyi birtokadományok révén megerősödő lovagok, ispánok (comes) és egyházi előkelők alkották. A vitézek (miles) – a szabadok egy másik, kisebb birtokkal rendelkező rétege – a király, illetve az előkelők mellett teljesítettek fegyveres szolgálatot.\n\nA legélesebb jogi választóvonal a szabadok (liber) és rabszolgák (servus) között húzódott. A társadalom legnagyobb részét azonban minden bizonnyal a „köztes” helyzetű kötött szabadok rétege alkotta, akik nem rendelkeztek a szabad költözés, házasság, végrendelkezés, fegyverviselés jogával, és szolgálattal tartoztak uruknak. A XI. század legszélesebb rétegeket érintő folyamata a korábbi szabad harcosok, parasztok (közrendűek, vulgarisok) kötötté válása jelentette. A közrendűek (vulgaris) már adóval (szabadok dénárja) tartoztak a királynak. Az egyházi, illetve világi nagybirtokokat és a királyi várbirtokokat kötött állapotú népességgel műveltették meg.\n\nA várispánságok katonái és katonatisztjei (várjobbágyok) is ebbe a csoportba tartoztak, de a várjobbágyok kisebb birtokadományban is részesülhettek, s ezáltal lehetőségük nyílt a felemelkedésre is.\n\nA feudális rend - Szent István halála után - László király (1077-1095) és Könyves Kálmán (1095-1116) idején szilárdult meg. l. (Szent) László (1077-1095) megszilárdította az ország belső rendjét és külső helyzetét.\n\nAZ ÁTALAKULÓ TÁRSADALOM A XI. század végére az egykori törzsi-nemzetségi vezetők (Csákok, Abák) és a bevándorolt lovagok (Hont, Pázmány) leszármazottaiból - a főpapi rend mellett - kialakult a világi nagybirtokos réteg. A trónharcok során a hatalmas királyi birtokok rovására növelték földjeiket. A társadalom középrétegét a saját földbirtokkal rendelkező szabadok alkották, akik földjeiket szolgáikkal műveltették meg. Valamennyi földbirtokos arra törekedett, hogy a birtokán élőket függőségbe vonja, így a szabadok tömegei - akiknek nem volt földjük, vagy elveszítették azt - lesüllyedtek, szolgáltatásokra kényszerültek (munka és termény).\n\nA XI. századi magyar társadalomban a legfőbb választóvonal még mindig a szabadok és a szolgák között húzódott. Megszületőben volt azonban egy új alávetett réteg, melyet a főleg terményszolgáltatásra kötelezett szabadok és a szolgák alkottak. Ezek a földesúrtól használatra kapott földön gazdálkodtak. Az átalakulás hosszú folyamat volt, s ez idő alatt számos átmeneti állapot létezett. A szabadok egy része, hogy elkerülje az alávetést, az ország peremterületeire vándorolt (kóborlók), ahol még nem alakult ki a magánföldesúri hatalom.\n\nSZENT LÁSZLÓ és Könyves Kálmán TÖRVÉNYEI védték a magántulajdont. Erre azért volt szükség, mert az új rend elől a peremvidékek menekülő népesség, a kóborlók megélhetésük érdekében lopni kényszerültek. László keményen fellépett ellenük. Törvényei szerint, ha a szabad ember ég tyúk értéke felett lopott, tettéért halállal lakolt. Ugyanakkor előírta a kóborlók befogását és letelepítését. Az uralkodó törvényeiben erősítette az egyházi (pl. ismét rendelkezett a tizedről) és fellépett a pogány szokások ellen. Ez az ősi hitvilág - nyilván egyre gyengülő - jelenlétére utal. A világi vezető réteg megerősödését mutatja, hogy Kálmán törvénye páncélos vitézek kiállítását írja elő számukra. Tehát képesek voltak előteremteni e költséges fegyverek és felszerelés árát. Ugyanakkor az uralkodó igyekezett a trónviszályok következtében megcsappant királyi birtokállományt pótolni. Elrendelte, hogy a fiúágon kihaló nemzetségek birtokai visszaszálljanak a királyra (háramlási jog).\n\nA Kálmán halálát követő fél évszázadot folytonos trónharcok jellemezték. A birtokadományok révén folytatódott a világi vezető réteg megerősödése, a szabadok lesüllyedése és az ország gazdasági átalakulása.\n\nA XII. század közepén a földek többsége a király tulajdonában volt és a hatalom a királyi birtokokon és a várszervezeten alapult. A várgazdaságokban katonai szolgálatra és munka- vagy terményjáradékra kötelezett várnépek éltek, akiknek tisztjei a várjobbágyok voltak. Felső rétegük földmagántulajdonnal is rendelkezett. A XI-XII. században a szabad pásztorok utódai lesüllyedtek, földjeiket a nagybirtokosok beolvasztották saját birtokaikba. A közszabadok azon csoportja, amelyik saját földjén dolgozott, megőrizte gazdasági és jogi önállóságát. Erre az időszakra az addig lakatlan területek lassan benépesültek, királyaink idegeneket (un. hospeseket,azaz vendégeket) telepítettek be.\n\nA XII. századra a trónharcok jelentős mértékben meggyengítették az uralkodó hatalmát. A birtokadományozásoknak köszönhetően az uralkodók már csak az ország területének egyharmadát birtokolta. Az egyházi és világi nagybirtokosok befolyása ezzel párhuzamosan nőtt. Az ispánok és az egyéb fontos tisztséget betöltő emberek a nagybirtokos családokból kerültek ki. A hadseregben a főurak saját zászlaik alatt vezették csapataikat – kialakult a bandérium. A középrétegek helyzete továbbra sem volt egyértelmű. A szabad lakosság földdel rendelkező, katonáskodó része (akiket XIII. századtól servienseknek neveztek) magát csak a király alattvalójának vallotta, s megőrizte függetlenségét. A várjobbágyok módosabb, saját földdel rendelkező része kiváltságokat nyerhetett az uralkodótól, ezáltal lehetőségük nyílt a felemelkedésre. Az uradalmakban továbbra is a szolgák voltak többségben, akik a földbirtokos szerszámaival, annak saját kezelésű földjén dolgoztak, de egyre több szolgának hasítottak ki parcellát terményhányad fejében. Ők voltak a házas-földes szolgák (mansio), akik már önállóan gazdálkodtak és terménnyel tartoztak uruknak. A lesüllyedt szabadok szintén saját földdel rendelkeztek, s csak a termés egy részét voltak kötelesek átadni. Ezt a folyamatot erősítette meg a szabad költözéssel, földdel rendelkező, terményhányadot beszolgáltató hospesek (külföldi telepesek) megjelenése\n\nA renddé fejlődés kialakulása\n\nA XIII. században a társadalmi átrétegződés felgyorsult, megjelentek az új társadalmi rendszer, a rendiség csírái. A III. Béla fiai, Imre (1196-1204) és András közti trónharcok során mindkét fél birtokok adományozásával kívánta erősíteni a táborát. A királyi birtokállomány tekintélyes részét eladományozták, aminek következtében kialakult a későbbiekben báróknak nevezett főnemesi réteg.\n\nA magyar társadalom változásai\n\nXI. század\n\nXIII. század eleje\n\nXIII. század vége\n\nXIV. század\n\nElőkelők\n\nNemesek\n\nBárók\n\nBárók\n\nVitézek\n\nServiensek\n\nNemesek\n\nNemesek\n\nVárjobbágyok\n\nVárjobbágyok\n\nKialakuló polgárság\n\nKözrendűek\n\nJobbágyok\n\nJobbágyok\n\nRabszolgák\n\nAranybulla(1222)\n\nII. András (1205-1235) uralkodása alatt a főurak újabb és újabb birtokadományokat szereztek, így politikai hatalmuk megnőtt. A vármegyerendszer a birtokok drasztikus csökkenése miatt nem tudta ellátni feladatait. A királyi hatalom hanyatlása veszélyt jelentett a királynak katonai szolgálattal tartozó és tőle személyében függő közép- és kisbirtokosok számára, akik - a királyi alárendeltséget hangsúlyozandó - szerviensnek nevezték magukat. Melléjük álltak a szintén az uralkodótól függő várjobbágyok is; elégedetlenségükből olyan mozgalom szerveződött, amely 1222-ben arra kényszerítette a királyt, hogy a különböző társadalmi szerveződések jogait az Aranybullában erősítse meg. Ez meg is történt, a bulla megvalósulása mégis elmaradt, az ellenállási záradék értelmében a szerviensek tehát szervezkedni kezdtek érdekeik érvényesítésére.\n\nII. András (1205-1235) bel- és külpolitikájának következményei:\n\nA királyi birtok kevés a birtokadományozások miatt.\n\nA királyi vármegyerendszer már nem tudja ellátni katonai és igazgatási feladatait a gyenge királyi hatalom miatt.\n\nA király keresztes hadjáratai a Szentföldre és Halicsba pénzhiányhoz vezet.\n\nA király ezért a regálékat bérbe adja (vámszedés, sóértékesítés, pénzverés) és a kamara haszna érdekében a pénz értékét folyton lerontja.\n\nA gyenge királyi hatalom és a gazdasági válság miatt a nagybirtokosok hatalma megnő, 1213-ban összeesküvést szerveznek II. András idegen felesége, Gertrúd ellen.\n\nA paraszti terhek megnövekednek.\n\nA szerviensek (kis- és középnemesek) függetlensége veszélybe kerül, mert a nagybirtokosok állandó katonáskodásra kényszerítik őket a magánhadseregeikben és a királyi hatalom meggyengülése miatt nincs, aki megvédje őket a nagyobb földesurak (főnemesség) hatalmaskodásaitól.\n\nElégedetlenségük miatt 1222-ben a fehérvári törvénylátó napon a királyhoz fordulnak.\n\nArra késztetik a királyt, hogy jogaikat törvénybe iktassa.\n\nEkkor adja ki II. András a díszes külsejű, arany függőpecséttel ellátott királyi oklevelet, az Aranybullát, mely 31 cikkelyből áll.\n\nII. Az Aranybulla (1222):\n\nA serviensek jogai:\n\nAdómentességet élveznek, mint a nagybirtokosok és függetlenséget élveznek tőlük\n\nBirtokaikon senki sem szállhat meg engedély nélkül\n\nCsak az ország védelmében kötelesek hadba vonulni\n\nBírói ítélet nélkül nem lehet felettük ítélkezni\n\nSzabadon végrendelkezhetnek, birtokaikat utódaik örökölhetik.\n\nCsak a nádor és a király ítélkezhet felettük\n\nA várjobbágyok érdekében:\n\nTilos tőlük a tizedet pénzben szedni, csak terményben kell\n\nNem lehet bérbe adni a regálékat\n\nTilos a pénzrontás, a király legalább egy évig érvényben hagyja az új pénzt.\n\nA királyra és a bárókra vonatkozó törvények :\n\nA király megígéri, hogy megtartja az idegenek birtokszerzésének tilalmát\n\nA király nem fog egész vármegyéket adományozni\n\nMéltóságok halmozódásának a tilalma\n\nAz Aranybulla az ellenállási záradékkal zárul: ennek értelmében ha valaki, akár a király is megszegi a bulla pontjait, a nemeseknek jogukban áll ellenállni.\n\nA király azonban nem tudja betartani és betartatni a bulla pontjait, ezért kétszer is módosítják:\n\nAz Aranybulla1231-es módosítása: az egyháznak kedvez.\n\nKimarad a tized pénzben való szedésének tilalma, bővül az egyház bírói szerepe\n\nAz ellenállási záradék módosul, az ellenállási jogot az esztergomi érsek kapja meg.\n\n1233-as beregi egyezmény\n\nKimondják az egyház teljes adómentességét\n\nVisszaszorítják a zsidókat és izmaelitákat, akik eddig a királyi regálékat bérelték.\n\nAz egyház visszakapja a só kereskedésének jogát.\n\nA szervienseket azonban nem védték meg a törvények a nagybirtokosoktól, ezért 1232-ben a zalai szerviensek önvédelmükre megszervezik az önkormányzattal bíró nemesi vármegyét. Élén az ispán áll (kehidai oklevél).\n\nIV. Béla (1235-1275)\n\nAz 1235-ben trónra kerülő IV. Béla kísérletet tett a királyi birtokállomány visszaállítására. Intézkedései a vezetőréteg ellenállásába ütköztek, ezért Béla kénytelen volt leállítani a birtokvisszavételeket. A tatárjárás (1241-42) jelentős mértékben megváltoztatta az erőviszonyokat. IV. Béla az ország talpra állítása érdekében birtokadományozásokba kezdett, az adományokat azonban feltételekhez (katonaállítás, várépítés) kötötte. Számos települést emelt városi rangra, elősegítve ezzel a polgárság növekedését. Ny-Európához képest azonban a polgárság aránya ekkor még igen csekély volt.\n\nA tatárjárás népességcsökkenése lendületet adott a jobbágyság kialakulásának: a hospesek és a határokon belül vándorló földművesek azokon a birtokon telepedtek csak le, amelyeken bizonyos kiváltságokat biztosítottak számukra. A munkaerőhiány miatt a birtokosok elismerték, hogy a jobbágyok telküket szabadon örökíthetik, szabadon költözhetnek. Az ilyen módon kialakult és egységesült réteg jobbágy elnevezése (eredetileg: „jobb ember”) kifejezte a paraszti népesség felemelkedését.\n\nIV. Béla uralkodásának utolsó éveit a fiával, Istvánnal folytatott küzdelem keserítette meg. Harcuk az adományozások révén a bárók megerősödését eredményezte. Egyes családok (Csákok, Kőszegiek, Kánok) egybefüggő, hatalmas területek uraivá váltak, akik a befolyásuk alá került területek kisebb birtokosaiból szervezték meg uradalmaik irányítását, fegyveres kíséretük, bandériumaik tisztjeit. Ezt a jelenséget familiaritásnak nevezzük. A familiaritás nem azonos a hűbériséggel: a familiáris a birtokát a királytól kapta, s nem urától. Az úr és familiárisainak viszonya így lazább volt, és nem öröklődött.\n\nAz 1260-as évekre a középréteg jogi helyzete megszilárdult. Az 1267-es törvények a servienseket már nemeseknek (köznemesek) nevezték, és megerősítették az Aranybullában megfogalmazott szabadságjogaikat. A királyi hatalom igyekezett a bárók ellenében felhasználni ezt a réteget, s a törvény értelmében a köznemesek képviseltethették magukat az évente rendezett székesfehérvári törvénynapon – ez az intézkedés a későbbi rendi országgyűlés egyfajta, nagyon korai előzményének is tekinthető. A szintén a királyt szolgáló, kötött várjobbágyok birtokkal rendelkező része nemesítések révén ugyancsak ebbe a társadalmi rétegbe emelkedhetett. Tehát megerősítette a szerviensek jogait, és 1267-ben már nemesként hívta őket az országgyűlésre. (A nagybirtokosok bárói címet kaptak.) A várjobbágyok jelentős hányada lesüllyedt, a földesúr fennhatósága alá került, és ők adták a nevüket a jogilag csaknem teljesen egységes paraszti osztálynak, a jobbágyságnak. Mivel a köznemeseknek nem volt elég erejük a bárókkal szembeszállni, valamelyik nagyúr szolgálatába álltak (harcoltak magánhadseregében, részt vettek a birtokigazgatásban stb.). Őket nevezzük a nagybirtokos familiárisainak.\n\nIV. Bélát a második honalapítónak nevezzük, ugyanis a tatárok kivonulása után újjáépítette az országot.\n\nBirtokokat adományozott, de katonaállításhoz kötötte az adományt\n\nfelhagyott birtokvisszaszerző politikájával.\n\nVárak építésére ösztönözte a nemeseket védelmi célból, a városokat fallal kell körülvenni\n\nAz elnéptelenedett részeket betelepítette: az Alföldre a kunokat, a Felvidékre szlovákokat, Erdélybe románokat.\n\nA szerviensek (kisnemesek) számára létrehozta a familiárisi rendszert: egy báró tágabb családjába kerültek. Békeidőben a báró birtokát igazgatta, háborúban pedig katonáskodott ura mellett.\n\nA kiterjedt latifundiumokkal (nagybirtokokkal) rendelkező bárók (kiskirályok) megakadályozták a köznemesség érvényesülését országos szinten. Így a köznemesek helyi szinten kezdtek szervezkedni érdekeik védelmében, s kialakították a nemesi vármegyét. Ennek első dokumentuma a Zala megyei serviensek kehidai oklevele volt (1232), amely rögzítette, hogy a helyi nemesség tisztségviselőket (szolgabírók) választhat saját soraiból. A nemesi vármegye a helyi nemesség érdekeinek védelme mellett átvette az ekkorra már meggyengült királyi vármegye funkcióit is.\n\nMagyarország tatárjárás előtti népességét 1,5-2 millióra becsülik; a többség magyar volt, de számos más etnikum is színesítette az ország térképét. A honfoglalást megelőző kortól itt élő szláv népesség mellé számos más népcsoport költözött be, ill. szervezett telepítési akciók is indultak, mind a király, mind egyes nagybirtokosok részéről. A nyugatról érkező – flamand, vallon, itáliai, szász, stb. – hospesek száma a tatárjárás után tovább növekedett. A kereskedelemmel foglalkozó zsidók és izmaeliták (muszlimok) mellett a korszak elején települtek be a török besenyők, a XIII. században az ugyancsak török kunok, illetve iráni jászok. A XIII. század elejétől rendelkezünk biztos forrásokkal a románság magyarországi jelenlétéről.\n\nAz Anjou-kori társadalom\n\nAndrás halálával 1301-ben kihalt az Árpád-ház. Az ezt követő időszak, az un. interregnum korában oligarchák, azaz különböző területi hatalommal rendelkező kiskirályok irányították az országot. Mindenképpen szükség lett volna királyra, azonban a különböző társadalmi csoportok nem tudtak megegyezésre jutni. Az ország tehát jogilag egységes maradt, de a hatalom a tartományurak kezébe került. A kiskirályok szerezték meg a főméltóságokat (nádor, vajda, bánok), és sajátjukként kezelték a méltóságaik révén birtokolt királyi várakat. Az új király megválasztását saját joguknak tartották. A trónharcokból Károly Róbert, a magyarországi Anjou-dinasztia első tagja került ki győztesen.\n\nVégül az Anjou-dinasztia egyik tagja, Károly Róbert (1308-1342) került a trónra, akit 1310-ben koronáztak meg, de már ezt megelőzően (Gentilis bíboros pápai követ segítségével), 1308-ban elismerték Magyarország királyának. Uralkodásának első időszakát az oligarchák elleni küzdelem jellemezte, ebben az egyház, a köznemesség, a városok és a falvak is mellette álltak. A harcokat követően, ezeket a rétegeket támogatva, új nagybirtokos arisztokrácia jelent meg pl. Szécsiek, Széchenyiek, kiemelt védelmet élvezett az egyház, megindult a városok fejlődése. A régi kiskirályok eltűnnek pl. Csákok, Abák.\n\nA feudális kereteket egyre inkább szétfeszítette a rendi átalakulás, ennek köszönhetően az I. (Nagy) Lajos (1342-1382) által a köznemesség nyomására 1351-ben megújított Aranybullát követően három elkülönülő rendről - főpapokról, főurakról és nemesekről -, valamint a szabad királyi városok polgárairól beszélhetünk. Pl. Buda, Kassa, Bártfa, Eperjes, Sopron, Pozsony, Nagyszombat.\n\n1351-ben Nagy Lajos király felújítja az Aranybullát:\n\n1351-ben I. (Nagy) Lajos a Budán összehívott országgyűlésen került sor az egy és ugyanazon nemesi szabadság elvének meghirdetésére, amely kimondja, hogy minden nemes ugyanazon jogokkal és kiváltságokkal rendelkezik. Így jött létre a jogilag egységes nemesség. Egységesítette a jobbágyság terheit.\n\nAz ősiség törvényének AVITICITAS (1351) bevezetésével a nemesi birtokot nem lehet elidegeníteni, tehát nem lehet eladni, idegennek átadni. Csak családon belül öröklődhet, és ha a család kihalt, a birtok visszaszáll a királyra (háramlási jog).\n\nEgységes nemesi jogok bevezetése: minden nemes ugyanazokat a szabadságjogokat élvezi:\n\nAdómentességet élveznek, mint a nagybirtokosok és függetlenséget élveznek tőlük\n\nBirtokaikon senki sem szállhat meg engedély nélkül\n\nCsak az ország védelmében kötelesek hadba vonulni\n\nNem szabadon végrendelkezhetnek, birtokaikat csak utódaik örökölhetik.\n\nBírói ítélet nélkül nem lehet felettük ítélkezni. Csak a nádor és a király ítélkezhet felettük.\n\nA kilenced bevezetése: amit a jobbágyok fizetnek földesuraiknak, ha nem szedik be, a király szedi be.\n\nNagy Lajos 1351-es törvényeiben megerősítette az egyes társadalmi csoportok jogállását. Az Aranybulla megújítása a nemesség alapvető szabadságjogait biztosította. Az egyetlen módosítás a szabad örökítési jog megszüntetése volt: az ősiség törvénye értelmében a birtok nemzetségen belül apáról fiúra szállt, a fiúágon kihalt nemzetségek birtokai pedig a háramlási jog révén a királyra szálltak vissza (Könyves Kálmántól).\n\nA nemességet erősítette az „egy és ugyanazon szabadság” kimondása, valamint a jobbágyi terhek egységes szabályozása. Az udvari nemesség gondolkodásmódja az Anjouk idején kezdett különválni a vármegyei nemesekétől. Az udvari társadalom észjárását a királyság tisztelete határozta meg, míg az udvaron kívül rekedtek, a vidéki nemesek elsősorban a nemesi szabadság szószólói lettek. A tisztsége révén a királyi székhelyhez, Budához kötődő udvari nemesség tagjai egyre sűrűbben kapták meg az úgynevezett szabadispánságot. Ez a később pallosjognak nevezett kiváltság feljogosította őket arra, hogy a kézre került jobbágy bűnösöket – a megyei törvényszék mellett – ők is kivégeztessék. Úriszék: bíráskodhat jobbágyai fölött.\n\nA nemességhez hasonlóan a jobbágyság kialakulása is a XIV. századra fejeződött be. Apró falvakban éltek, gazdálkodásuk és szolgáltatásaik alapja a telek volt, mely belső (ház és kert) és külső (szántó, rét és erdőrész) telekből állt. A szántót – a nyomáskényszernek megfelelően – minden évben máshol mérték ki. A jobbágy a telek alapján rótta le szolgáltatásait földesurának (cenzus = pénzadó két részletben; kilenced = terményadó; évi háromszori ajándék; munkajáradék (robot) = fuvarozás); az egyháznak (tized a gabona és a bor után) és az államnak (kapuadó). A jobbágyok helyzete a XIV. században viszonylag kedvező volt; szabadon költözhettek adójuk megfizetése után.\n\nAz Anjouk kora a társadalomfejlődés egy hosszú folyamatát zárta le. Az ország különböző állapotban élő és különböző lakosai két alapvető csoportban egységesültek.\n\nAz egyik csoportba tömörülők földbirtokuk révén a nemesség soraiba tartoztak. Földjükre megkapták az uralkodótól az adómentességet, és csupán katonáskodási kötelezettségük volt. A másik csoport tagjai, a földtulajdonnal nem rendelkező jobbágyok a földesurak földjein telkeket vettek használatba. A használatba kapott telek fejében a földesúr, az egyház és az állam szolgáltatásokra kötelezte őket. Az egységes nemesség és jobbágyság kialakításában a királyi hatalom döntő szerepet játszott.\n\nA városi polgárság megjelenése:\n\nA XIV. században a városok száma jelentősen emelkedett. A szabad királyi városok és a bányavárosok mellett megjelentek a mezővárosok is.\n\nA polgárság fejlődése és renddé szerveződése szinte egybeesik a városfejlődéssel és a városi kiváltságok bővülésével. Ezt elősegítették az Anjouk, elsősorban Károly Róbert reformjai is az árutermelés és pénzgazdálkodás kialakulásával, a kereskedelem és a bányászat fejlesztésével, és az értékálló pénz bevezetésével. Elindult Magyarországon a városfejlődés, melynek lakói a polgárok: a kereskedők, iparosok.\n\nKiváltságosok és a városok adói:\n\nA legnagyobb városok (Buda, Pest) együttes lakossága 15-25 ezer lehetett.\n\nA határszéli városok zöme német anyanyelvű volt, a középkor végén Budán már a magyarok voltak többségben (Szeged, Székesfehérvár, Esztergom, Pest magyar város volt). A lakosság zöme mezőgazdaságból élt, különösen fontos szerepe volt a szőlőművelésnek, amely lehetőséget nyújtott a borkereskedelem kialakítására.\n\n• Céhes ipar\n\n• A XIV. században, Nagy Lajos korában megjelentek a céhek is, de számuk és politikai súlyuk elmaradt a nyugat-európai céhekétől.\n\n• A városok éltető eleme a távolsági kereskedelem volt, a kézműiparnak kisebb volt a szerepe.\n\n• A mezőváros, vagy agrárváros (oppidum) földesúri hatalom alatt álló, nagyra nőtt falu volt, amely rendelkezett a piactartás és általában az egyösszegű adófizetés jogával. Később bírót és tisztviselőket is szabadon választhattak, és így korlátozott önkormányzati jogokhoz jutottak.\n\n• A mezővárosok XIV. századi nagy számú megjelenése a távolsági kereskedelem fellendülésének volt köszönhető.\n\n• A piacokat tartó mezővárosokban idővel megjelent a szolgáltató ipar (kádár, kovács, szabó, kötélverő stb.) is. A mezővárosok általában nem voltak fallal körülvéve a mezőváros elnevezés is erre utal - a település a nyílt mezőn, nem falak között terül el.\n\nSzabad királyi városok\n\n• Legelőkelőbb csoportja a tárnokmester bírósága alá tartozó nyolc, fallal körülvett város: Buda, Pozsony, Nagyszombat, Sopron, Kassa, Bártfa, Eperjes és Mátyás király korától Pest.\n\n• Ugyancsak jelentős város volt az erdélyi szászok 3 nagy városa: Nagyszeben, Brassó és Beszterce.\n\n• Másodrangú királyi városnak számítottak az ún. személynöki városok: Zágráb, Székesfehérvár, Esztergom, Lőcse, Visegrád, Kolozsvár, illetve néhány mezővárosi jellegű város (Szeged).\n\nA nemesfémbányászat fellendülésével a Felvidéken és Erdélyben bányavárosok jöttek létre nagy számban. „Szabad” bányavárosok:\n\n• keleten: Nagybánya és Felsőbánya;\n\n• alsó-magyarországi bányavárosok: Körmöc-, Selmec-, Beszterce-, Baka-, Libet-, Új- és Bélabánya.\n\nA korszakban ez a folyamat Luxemburgi Zsigmond (1387-1437) idején tetőzött, aki 1405-ben már a városok képviselőit is meghívta a királyi tanácsba (országgyűlésbe), 1435-ben pedig a középnemesség képviselőit is, így vonva be őket az aktív politizálásba.\n\nA magyar társadalom változásai\n\nXI. század\n\nXIII. század eleje\n\nXIII. század vége\n\nXIV. század\n\nElőkelők\n\nNemesek\n\nBárók\n\nBárók\n\nVitézek\n\nServiensek\n\nNemesek\n\nNemesek\n\nVárjobbágyok\n\nVárjobbágyok\n\nKialakuló polgárság\n\nKözrendűek\n\nJobbágyok\n\nJobbágyok\n\nRabszolgák\n\nMátyás erős kézzel látott hozzá hatalma megszilárdításához. Nem vette feleségül a politikai alku során neki szánt Garai Annát, Garai Lászlót pedig eltávolította nádori tisztségéből. Nagybátyját, Szilágyi Mihályt a déli végekre küldte harcolni a török ellen, majd kormányzóságáról is lemondatta. Ezután a hatalomból kisemmizett Garai-Újlaki liga III. Frigyest választotta királlyá, de Mátyás visszaverte a német támadásokat. Végül tárgyalóasztal mellett simították el az ellentéteket. A megállapodás értelmében a Szent Korona visszakerült Magyarországra, de Frigyes megtarthatta a magyar királyi címet. Mátyás ígéretet tett arra is, hogy ha törvényes örökös nélkül hal meg, akkor a magyar trónt a Habsburgok öröklik. 1464-ben Mátyást a Szent Koronával királlyá koronázták, ez végleg törvényesítette hatalmát.\n\nMátyás az államélet minden területén a központosított, csak tőle függő hivatalnokszervezet létrehozását tűzte ki célul. Uralkodása alatt minden fontos tisztség betöltése csak az ő akaratától függött, tisztségviselői főként a Hunyadi-család familiárisai közül és a polgárság soraiból kerültek ki, akiktől az uralkodó a feltétlen hűség mellett a szakértelmet is elvárta. Az átszervezett királyi kancellária élére egyik legmegbízhatóbb emberét, Vitéz Jánost ültette.\n\nMátyásnak nagyra törő külpolitikai céljai voltak, ennek megvalósításához szüksége volt egy olyan állandó zsoldosseregre, amellyel függetleníteni tudta magát a bárói bandériumoktól. A hadsereg állandó létszáma 8-10 ezer fő lehetett, a zsoldosok egy részét csak a nagyobb háborúk idején fogadták fel, ekkor a sereg 15-20 ezer főre is emelkedhetett, ami európai mércével is igen jelentősnek mondható. A sereg magvát a meghódolt felvidéki husziták alkották, a zsoldosok többsége pedig cseh, lengyel, német származású volt. Mátyás hadseregét az utókor fekete seregnek nevezte el, az elnevezés eredete ma is vitatott.\n\nA központosított államigazgatás és a zsoldos hadsereg igen sok pénzbe került. Mátyás a török veszélyre hivatkozva rendszeressé tette a Zsigmond óta ismert rendkívüli hadiadó szedését. Voltak olyan évek, amikor ezt többször is beszedték, évi értéke egy aranyforint volt, kb. egy hízott disznó ára. Ezek mellett természetesen további fontos jövedelemforrások maradtak a királyi regálék, a szabad királyi városok adója, a külkereskedelmi vámok stb. Mátyás bevételei e korban igen tekintélyesnek számítottak, kb. évi 500–750 ezer forint között mozogtak. Ennek felét-harmadát a jobbágyok által fizetett központi adók tették ki. Ez a jövedelem megközelítette a francia vagy a spanyol király bevételeit!\n\nMátyás uralma nem volt népszerű, hiszen uralkodása alatt mind a bárók, mind a köznemesek kiszorultak a hatalomból, a parasztság pedig a királyi adókat nyögte. Az azelőtt ismeretlen jobbágyokat terhelő tetemes királyi adók sértették a földesúri érdekeket. A hatalomból kiszorítottak, később még Mátyás hívei közül is számosan szembefordultak a király központosító szándékaival. De szemére vetették azt is, hogy elhanyagolja a török elleni védekezést és erőit nyugat felé fordítja. A Csehország elleni hadjárat volt az utolsó csepp a pohárban. A mozgalom élére Vitéz János esztergomi érsek és Janus Pannonius pécsi püspök állt, az összeesküvők a lengyel uralkodó kisebbik fiát, Kázmér herceget léptették fel Mátyással szemben. A szervezkedés azonban hamar kudarcba fulladt, Janus Pannoniusnak menekülni kellett, Vitéz Jánost pedig haláláig “házi őrizetben” tartották. Az összeesküvés kívánt céljának éppen ellenkezőjét érte el. Mátyás gyanakvása fokozódott, az udvarban egyre több külföldi hivatalnok jelent meg, a törvények felett álló király pedig továbbra is saját elképzelései szerint kormányozta az országot.\n\nMátyás uralkodása volt az utolsó korszak a középkori magyar történelemben, amikor egy különleges képességekkel rendelkező uralkodó “nagyhatalommá” tette a magyar királyságot. Mátyás központosító törekvéseinek azonban nem voltak meg a gazdasági és társadalmi feltételei, hiányzott az erős polgárság, amely adóival támogathatta volna a centralizációt. Mátyás uralmát személyes tekintélye és tehetsége tartotta fenn, ezért lehetett, hogy halálával alkotásai napok alatt veszendőbe mentek. Az igazságos Mátyás király képét népmeséink őrizték meg. A maga korában zsarnoknak tartott király uralma Mohács után, a török elnyomás alatt élő nemzedékek emlékezetében szépült meg, az “elnyomás kora” a béke és az igazságosság aranykorává magasztosult – talán nem érdemtelenül.\n\nPobjebrád Katalin halála után Mátyás a nápolyi király lányát, Aragóniai Beatrixot vette feleségül, de mindkét házassága gyermektelen maradt. Házasságon kívül viszont született egy fia, Corvin János, akit trónja örökösének szánt.\n\nAntonio Bonfini olasz humanista tudósMátyás királytól kapott megbízást a magyarok történetének megírására.', 156, 1, '2026-04-17 09:40:23', '2026-04-17 09:40:23');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(12, 12, 'A KÖZÉPKOR ÉS A KORA ÚJKOR KULTÚRÁJA Európában és Magyarországon', '12.docx', '12. tétel: A KÖZÉPKOR ÉS A KORA ÚJKOR KULTÚRÁJA Európában és Magyarországon\n\n(egyházi és lovagi kultúra, középkori egyetemek, román, gótikus és reneszánsz építészet, barokk)\n\nA középkori művelődés: oktatás és tudomány\n\nA középkort a Nyugat-római Birodalom bukásától (476) számítjuk, és Amerika felfedezésének időpontjáig tart (1492). Három időszakra szoktuk felosztani: korai, érett és késő középkorra.\n\nA keresztény világkép a középkori ember életének minden szegmenségben érvényesült, sok esetben a vallás határozta meg tetteit. Életét születésétől kezdve a tanuláson, munkáján át - ami „Istennek tetsző dolog - a szórakozásig vagy a magánélet rendjéig az egyház határozta meg.\n\nA kora középkorban Frank Birodalomban Nagy Károly aacheni udvara Aachenben (Alkuin iskolája) volt a művelődés és a művészet középpontja is. A Karoling virágzás IX. századi letűnte után sokáig, a skolasztika fénykoráig kellett várni, hogy a hanyatlófélben lévő vagy szűkös befogadóképességű kolostori, káptalani iskolákat felváltsák a megszülető egyetemek.\n\nA középkori oktatás ugyanis kezdetben kolostori, káptalani és székesegyházi iskolákban folyt. A kolostori iskolákban 5-15 éves koruk között tanulták a diákok a latin nyelvtant, az írást, a számolást, az éneket, vagy a természetrajz alapjait. Ezután kerülhettek a székesegyházi iskolákba vagy az egyetemekre. A káptalani és székesegyházi iskolák nagyobb városokban jöttek létre. Az oktatás nyelve a latin.\n\nEgyetemek\n\nA középkori egyetemek Nyugat-Európában jellemzően a XI–XIII. században, Közép-Európában a XIV–XV. században jöttek létre. Az egyetemek alapításának térbeli háttere elsősorban a nyugat-európai és itáliai térség városaiban jön létre pl. Bologna, Párizs, Oxford. Az egyetemek általában pápai elismeréssel működtek. Az egyetemek létrejöttének oka: szükség volt az egyházi és állami ügyek intézéséhez szakemberekre. Az egyre több tudás egyre több szakembert követelt. A bürokrácia fejlődése hozzáértő embereket kívánt, akár az egyházról, akár a világi adminisztrációról legyen szó. Az ő képzésükre jöttek létre az első egyetemek. A kora középkorban már létező kolostoriskolák mellett, a városokban székesegyházi, káptalani iskolák létesültek. Ez utóbbiakból fejlődtek ki az egyetemek:\n\n• XII. század második felében a bolognai 1088. Európa legrégebbi egyeteme, a párizsi (Sorbonne) 1150 körül és az oxfordi (1167); a párizsi egyetem pápai támogatással működött.\n\n• XIII. században: padovai (1222), cambridge-i (1233),\n\n• XIV. században: prágai (1348), krakkói (1364), bécsi (1365), pécsi (1367) – Nagy Lajos alapította, majd az óbudai (1395) – Luxemburgi Zsigmond alapította.\n\nAz oktatók és a hallgatók többsége egyházi személy volt, az oktatók jelentős része valamelyik szerzetesrendhez tartozott, jellemző oktatási forma volt a lectio – felolvasás. A hét szabad művészet (septem artes liberales) volt az egyetemi oktatás első szintje, ennek részeit a trivium: grammatika, retorika, dialektika, illetve a quadrivium: aritmetika, asztronómia, geometria, musica.\n\nAz egyetemek alapítása összefüggött a középkori városok fejlődésével. A városi keretek és érdekszövetségek segítették az egyetemi autonómiát.\n\nAz egyetemek céhszerű autonómiával rendelkeztek, a vezetője a tanárok által választott rektor volt. Az egyetemi autonómia kiterjedt a tananyag szabad megválasztására, és a tanárok és diákok mindennapi életének irányítására is. Ha például egy diák a városban bűncselekményt követett el, felette nem a város, hanem az egyetem bírósága ítélkezett (a tanárok és a diákok is egyetemi polgárnak számítottak, rájuk az egyetem szabályai vonatkoztak). Az universitas – a tanárok és diákok összessége. A pápaság és az uralkodók voltak a támaszai a helyi egyházi és világi hatalommal szemben.\n\nTehát az egyetem (universitas) a tanárok (magiszterek) és diákok testületét jelentette, akik (a céhekhez hasonlóan) kiváltságokkal (immunitásokkal) rendelkeztek:\n\n• Az egyetemeken az állam tisztviselői nem járhattak el.\n\n• Az egyetemi polgárok (tanárok és hallgatók) az egyetem vezetőjének, a rektornak a bírói hatalma alá tartoztak. Az egyes karok élén a dékán állt.\n\n• Az egyetem maga alkotta meg szabályzatát is, és az ügyeket saját választott tisztségviselői intézték.\n\n• Az egyetemeknek ezen szabadságukat a helyi püspökkel és/vagy királlyal és/vagy várossal szemben kellett kivívniuk. Ugyanakkor a tanárok és a hallgatók is klerikusoknak számítottak, és a papi rend tagjainak tartották őket Az egyetemek általában a pápa védelmét élvezték. (Előírták az egyházi ruha viselését, a misehallgatást és a nőtlenséget.)\n\n• Az egyetem Alma Mater („tápláló anya”), amely a hallgatókat tudománnyal „táplálja”.\n\nA magiszterek tandíjból (amit a diákkal kötött magánszerződés rögzített) és egyházi javadalmakból éltek (kivéve a koldulórendi tanárok).\n\nA diákok általában nagy szegénységben éltek, kollégiumokban laktak, ugyanakkor féktelen életmódjukkal sokszor rettegésben tartották a városokat.\n\nAz oktatás elvilágiasodása hozta létre a goliardokat (vándordiákokat), akik egyetemről egyetemre járva tanultak. Az ő életüket örökítette meg a diákdalokból álló Carmina Burana. Leghíresebb éneke a Gaudeamus igitur.\n\nAz egyetemek felépítése\n\nA képzés egymásra épül: a hét szabad művészetet mindenkinek el kellett végeznie, először magiszteri, majd doktori címet lehetett szerezni. A diákok több egyetemen is megfordultak. Az egyetemi oktatás latin nyelvű, mely hozzájárult a középkori Európa szellemi egységéhez. Az egyetemekről kikerülő diákok fontos szerepet játszottak az állam és az egyház működésében, magas tisztségeket töltöttek be, kulturális szerepük volt.\n\nA teljes egyetemeknek négy fakultása (kara) volt: egy alapozó (szabad művészetek), és három felső (jogi, orvosi és teológiai).\n\n1. Az alapozó fakultáson oktatott hét szabad művészet (septem artes liberales) Szent Ágoston szerinti felosztása:\n\nTrivium: grammatika (latin nyelvtan és latin írók olvasása), retorika (latin beszéd és fogalmazás), dialektika (formális logika, vitatkozás és érvelés művészete).\n\nQuadrivium: aritmetika (számtani alapműveletek), geometria (szerkesztések), asztronómia (csillagászat és földrajz, egyházi ünnepek idejének meghatározása), muzsika (egyházi énekek).\n\nÁltalában 14-20 éves kor között jártak ide. Tananyag: főleg görög (Arisztotelész, Hippokratész), római (Cicero), hellenisztikus (Ptolemaiosz, Galénosz), arab (Averroes) és korai egyházatyák (Szent Ágoston) műveit tanították.\n\nA tanulmányok második éve után meg lehetett szerezni a baccalaurátust (BA) (babérkoszorús), a licentiatus, majd a hatodik év végén a doktorátus, magiszteri (MA) fokozatot. A további karok ezen tanulmányok elvégzése után következhettek. A tanulmányok befejezése után magiszterek is lehettek.\n\n2. A három felső fakultás\n\nAz egyetemet végzettek magas hivatalokat töltöttek be a középkori államok hivatalaiban, vagy magas egyházi méltóságokat. A diákok natiókba, nemzetekbe tömörültek. Az oktatás módszere az előadás (lectio), a vita (disputatio) és a kérdések megvitatása (quastiones).\n\n• Orvosi Kar és Jogi Kar: kb. 20-25 éves kor között jártak ezekre a karokra. Az orvosi karon Hippokratész és Galenus kivonatos műveit tanulták. A jogi karon egyházi jogot és világi jogot (római jog) tanítottak. • Később a filozófiai kar.\n\n• Teológiai Kar: általában felnőtt fejjel, 30-36 éves korra végezték el a hallgatók. Ez adta a legmagasabb képesítést. A Bibliát és egyházi műveket (XIII. sz. után: Aquinói Szt. Tamás: Summa teologiae-t) tanították.\n\nA klasszikus középkor tudománya Aquinói Szt. Tamás skolasztikája, vagyis az a tudomány, amit az iskolában, az egyetemeken tanítottak. Legfőbb törekvése az antik (pogány) filozófia (Arisztotelész) összeegyeztetése a keresztény hitelvekkel. A korabeli felfogás szerint a filozófia nem kerülhetett szembe a teológiával. A hit mellett az észérvek is a megismerés alapjául szolgálta.\n\nA skolasztika a virágzó, érett középkori (Nyugat-) Európára jellemző.\n\nA skolasztika a középkori nyugati kereszténység filozófiája, amely összeegyeztette az antik természettudományt (és logikát) a keresztény teológiával.\n\n• A korai középkorban az egyházatyák (Szent Ágoston, Nagy Szent Gergely) műveinek tanulmányozása folyt az iskolákban.\n\n• A XII. században a keresztes hadjáratok után a mohamedán-keresztény kölcsönhatás eredményeként felpezsdült a szellemi élet. A XII. századra arab közvetítéssel (D-Itália, Ibériai-fsz.) újra széles körben ismertté váltak Arisztotelész munkái, továbbá a mohamedán Averroes, Arisztotelész műveihez írt kommentárjai. Ezekkel megjelent a kételkedő, okokat kereső gondolkodás, fejlődött a logika. Új szemlélettel közeledtek a hit kérdéséhez is, megszületett a teológia.\n\n• A hit (teológia) és a tudás (filozófia és más tudományok) között a kényes egyensúlyt Aquinói Szt. Tamás (1225-74) Domonkos-rendi szerzetes találta meg. Fontos kérdéssé (talán a legfontosabbá) vált az, hogy milyen módon lehet összeegyeztetni a hitet és a tudományokat. A választ a dominikánus barát, Aquinói Szent Tamás adta meg Summa teologica (A teológia foglalata) című írásában: szétválasztotta egymástól a kettőt, és az elsőbbséget a teológiának adta. Tehát szétválasztotta az isteni kinyilatkozáson alapuló teológiát és az emberi értelemmel vizsgálódó filozófiát. Rámutatott, hogy a hit nincs ellentétben az értelemmel, sőt segítik egymást - a hit révén felismert igazságok hozzájárulnak az értelem megvilágosodásához. Ez azért volt fontos, mert viszonylag szabad utat engedett a tudományok fejlődésének. A skolasztika Arisztotelész metafizikáját használta fel érvelésként.\n\nAquinói Tamás művének lényege: Isten létének bizonyítása, ez a keresztény világnézet egyik alapvető kérdése. A hit és Isten létének kérdésére logikai magyarázatot keres. Alkalmazott módszerei: érvek és ellenérvek rendszere, elméleti logikai levezetés, kérdés és válaszok rendszere. A tudományos érvek a hit szolgálatában állnak.\n\nAquinói Tamás skolasztikája megkülönböztette a hitbéli és a tudományos igazságot, és lényegi megállapítást tesz a viszonyukat illetően: a hitbéli igazság magasabb rendű, a két igazság sosem állhat ellentétben egymással. A tudományos igazság ésszel felfogható – a hitbéli elfogadásához viszont akarat is kell. A skolasztika lehetővé tette a tudományok szabadabb művelését pl. egyetemek alapítása, antik szerzők újrafelfedezése.\n\nA skolasztika képviselői:\n\n• Pierre Abélard, Aquinói Szt. Tamás — a hit és az értelem, a gondolkodás, a filozófia viszonyát kutatták.\n\n• Roger Bacon oxfordi ferences gondolkodó a tudomány feladatának az egyetemes természeti törvények megállapítását tartotta: a tapasztalat, a kísérlet és a bizonyítás alapján.\n\nA lovagi kultúra\n\nA lovagok\n\nA XI. századig a lovag: teljes páncélzattal harcoló lovas katona, illetve a kíséretében szolgáló hasonlóan felszerelt nemes; A középkori Európában a lovas haderő vált jellemzővé. A VIII-IX. századtól a vitézek fegyverzete egyre erősebb lett. Páncéllal védték a katonát és a lovát is. A felszerelés nagyon drága volt. Csak az katonáskodhatott, akinek elegendő vagyona, földbirtoka volt ehhez. Azt a földbirtokost, aki nehézpáncélos lovasként katonáskodással foglalkozott, lovagnak nevezték. A költséges felszerelés miatt kevés volt a lovag. Ezért a királyok is megbecsülték őket, kedvezményeket (kiváltságokat) adott nekik. Ők lettek később a nemesek.\n\nA XI-XIII. században: alacsonyabb rangú fegyverforgató; A lovagok korában megváltozott a háborúskodás. A szemben álló seregek hosszú lándzsákkal (kopjákkal) rohantak egymás felé. Ehhez nagy mező kellett, így megesett, hogy a vezérek előre megbeszélték a csata helyét. Az ember ember elleni küzdelemben az győzött, aki a másikat kivetette a nyeregből. A legyőzött ellenséget nem ölték meg, hiszen érte váltságdíjat kérhettek. Fegyverét és páncélját azonban zsákmányként elvették - mely olykor egy falu ára volt.\n\nA XIII. századtól: a nemesség alsó részének elnevezése (az eredeti katonai funkciót sokszor már nem is gyakorolták).\n\nA lovagi cím örökletes volt, ezért az ősök emléke, a leszármazás, a rokoni kapcsolatok ismerete fontos volt. A lovagok alkották a középkori európai hadseregek gerincét. Fegyverzetük az egész testüket borító páncélból, dárdából, nehéz, hosszú és egyenes kardból állt, ezért lovuknak nagy teherbírásúnak kellett lennie. Ez a felszerelés természetesen rendkívül drága volt, úgyhogy csak a nemesek tudták kiállítani. A lovagi kultúra tehát a középkori nemesi kultúra szinonimája.\n\nLovaggá avatás:\n\nHatéves kora körül áll be apródnak általában családja hűbérurának a szolgálatába, 7 éves korban elkezdődött (fegyverforgatás, lovaglás, írás-olvasás);\n\n12 éves kortól az uralkodói és főúri udvarokban, mint apród/fegyvernök tevékenykedett.\n\nTizennyolc éves kor körül, amikor már rendelkeztek a 7 lovagi készséggel (lovaglás, úszás, nyilazás, vívás, vadászat, táblajátékok ismerete, verselni tudás), lovaggá avatják. Mindig valamilyen ünnepnapon történik a lovaggá avatás.\n\nA XII. századtól kezdett a lovaggá avatás ritualizálódni:\n\nA szertartás előtti napon a lovag meggyónt és fürdőt vett (megtisztult). Az éjszakát virrasztással és imával töltötte. Az avatás: az apa, a nagybáty vagy a hűbérúr adta át a lovagi hivatás jelképeit, a kardot és az övet, majd az avató karddal a vállára ütött (esetleg arcul csapta, ami Jézus szenvedésére emlékeztetett, amit majd meg kell bosszulnia); ezután felkötötték a sarkantyúkat, feladták a sisakot és a pajzsot; végül a lovag megesküdött, hogy a lovagi élet szabályait betartja.\n\nA lovagi erények: a 7 fő lovagi erény: mértékletesség, állhatatosság, hűség, erkölcsösség, bőkezűség, becsületesség, bátorság.\n\nA lovag fő feladata a harc, legfőbb erénye a vitézség, bölcsesség és a bőkezűség (a munka és a vagyongyűjtés megvetendő volt).\n\nA lovagi esküben is megjelenő erények: naponta misehallgatás; élete kockáztatása a hitért; az egyház, az özvegyek, az árvák, az ártatlanul fogságba kerültek védelme; a nők tisztelete; az igazságtalan háborúk elkerülése.\n\nA lovagnak álcáznia kellett fájdalmát, nem kelthetett szánakozást maga iránt. A szenvedés és a gyötrelem paraszti tulajdonságnak számított.\n\nA lovagi életmód\n\nA harcban való jártasság megszerzése:\n\n• Vadászatok: kutyák és szolgák hadával vadak tömeges elejtése.\n\n• Lovagi tornák: sport, szórakozás és hadgyakorlat volt egyszerre:\n\n- párban, dárdával mérkőző lovagok (a győztesé a vesztes lova, fegyvere);\n\n- csapatok mérkőzése (itt is párok csaptak össze, de tömegesen, tompított fegyverekkel;\n\na legyőzött lovagok fogságba estek, váltságdíjat kértek értük);\n\n- a XII. századtól a lovagi tornák harci jellege háttérbe szorult, a lovagok választott hölgyük\n\nszámára akarták bizonyítani bátorságukat, erejüket.\n\nA lovagok a királyi, főúri udvarokban rendeztek lovagi tornákat. Ezeken győzni nagy dicsőség volt. A részvétel azonban nem volt veszélytelen. Ezért egyre erősebb páncélokat, zárt sisakokat használtak. Hogy megismerjék egymást, a pajzsokra ráfestették a nemes vitéz címerét. Ezt a lovag fiatal segédje, az apród vitte körbe, aki maga is lovagnak készült. A torna végeztével lakomát rendeztek. A lovagi lakomákhoz tartozott a lovagi költészet. Képzett énekmondók sorolták el a vitézek hőstetteit. Verseiket énekelték, közben lanton játszottak.\n\nHelyi összecsapások: Ha nem volt háború, akkor a lovagok egymás ellen csatáztak, vagy falvak, városok ellen vonultak (földért, foglyokért, váltságdíjért, hírnévért). Leginkább a nemesi famíliák örökségből kimaradt fiatalabb fiai (kóbor lovagok) vettek ezekben részt. Az egyház megpróbálta ezeket az összecsapásokat korlátozni: Franciaországból indult az Isten békéje (Treuga Dei) mozgalom, amely ünnepnapokon, a hét utolsó 3 napján megtiltotta a hadakozást, illetve a fegyvertelen emberek bántalmazását.\n\nA lovagok lakóhelye:\n\n• A lovagok kezdetben egyszerű udvarházakban, később fából, majd kőből készült lakótornyokban, majd várakban éltek.\n\n• A XIII. században kezdtek kényelmesebb lakóépületeket emelni konyhával, díszteremmel (fűtés: cserépkályhával, világítás: fáklyákkal, gyertyával).\n\nA lovagi kultúra\n\nViselkedésszabályok: alapelv a természetes érzelmek és ösztönök (étkezés, szerelem) elfojtása: kialakultak a közös étkezések és a társadalmi érintkezés szabályai (köpködés, illetlen orrfújás, meztelenkedés tilalma). Illett másokat végighallgatni, előre engedni, megkínálni, és ha volt rá ok - elnézést kérni.\n\nMűveltség:\n\nA lovagi kultúra a spanyol, francia, német királyi és főúri udvarokban alakult ki, és a korábbi vad, harcos nyerserő-kultuszt váltotta fel. Az elsősorban katolikus indíttatásra létrejött kultúra eszménye „kétarcú\" volt: a lovag legyőzhetetlen, hős harcos és gyengéket, nőket és elesetteket védelmező, érzékeny férfi volt egy személyben (nem mellékesen az sem ártott, ha valaki költői-énekesi tehetséggel is rendelkezett - gondoljunk a lovagi költőkre, pl. Walter von der Vogelweidére).\n\nA lovagi kultúra példái: az udvarokban élő lovagok hölgyüket költeményekben és dalokban magasztalták: udvari szerelem. Udvari költészet, trubadúrlíra: igazi lovagköltők (trubadúrok, minnesengerek) írtak verseket, amelyeket sokszor elő is adtak; Pl. Walter von der Vogelveide\n\nLovagi epika: Sándor-regény (Nagy Sándor); Roland-ének (Nagy Károly); Breton mondakör (Arthur király, Parszifál, Trisztán és Izolda); Trója-regény.\n\nA lovagrendek:\n\n• A keresztes hadjáratokhoz kapcsolódóan jöttek létre az egyházi lovagrendek, amelyek a Szentföld és a zarándokok védelme mellett betegápolással is foglalkoztak:\n\n• Templomosok: 1119-ben jött létre a rend, amelynek fő hivatása a védelem, a harc lett a Szentföldön. A rend idővel meggazdagodott - IV. Szép Fülöp (1285-1314) francia király szemet vetett vagyonukra, és egy koncepciós per után vezetőit kivégezték. A Templomos lovagrendet 1312-ben a pápa feloszlatta.\n\n• Johanniták (ispotályosok): 1137 körül szerveződött lovagrenddé a jeruzsálemi Alamizsnás Szent János Kórház (ispotály) betegápoló közössége. Később Ciprusra, Rodoszra, majd Máltára települtek át (elnevezésük ezután: Máltai Lovagrend).\n\n• Német Lovagrend: az 1192-ben alapított rend előbb betegápoló, később harcos feladatokat látott el. Kivonulva a Szentföldről Európába tette át székhelyét, a mai Lengyelország északi részén.\n\nA KORA KÖZÉPKORI EGYHÁZ SZEREPE, KULTÚRÁJA, HITTÉRÍTÉSE\n\nA keresztény egyház megerősödését elősegítette, hogy a kereszténység a Kr.u.4. század végén államvallássá vált a Római Birodalom területén. Theosodius császár ugyanis 391-ben államvallássá tette. A kora középkorban gyorsan terjedt a kereszténység. Kialakult az egyházszervezet.\n\nEurópa kereszténnyé válásában a frank, ír és angolszász térítők játszottak kiemelkedő szerepet. A germán, szláv és magyar területeken a térítés során kolostorokat és püspökségeket alapítottak. A térítés során sokan vértanúhalált szenvedtek.\n\nA nyugati keresztény egyház felépítése: gyülekezet – egyházmegye – egyháztartomány – egyetemes egyház. Élén: plébános – püspök – érsek – pápa. Tehát hierarchikus felépítésű. Vezetője a római pápa.\n\nKülönleges tekintélyre tett szert Róma püspöke, a pápa, amely Szent Péter utóda.\n\nA pápa fölött csakis Isten áll, a világi hatalom nem vonta a befolyása alá, mint a konstantinápolyi egyházi vezetőt.\n\nA Pápai Állam 756-os létrejöttében jelentős szerepe volt a frank uralkodónak, Kis Pippinnek. A pápa cserében elismerte a Karolingok frank uralmát. 800-ban Rómában császárrá koronázta Nagy Károlyt, a Frank Birodalom uralkodóját. A Frank Birodalom Nyugat-Európában helyezkedett el.\n\nNagy Károly a törvényeivel is védte az egyházat, és támogatta a kereszténység elterjesztését. Törvényeiben bünteti a pogány szokásokat, kötelezővé teszi a kereszténység felvételét. Az uralkodó és az egyház egymás támaszai voltak. Központja Aachen volt, uralkodásának időszakát Karoling-reneszánsznak nevezzük. Az uralkodó tanácsadói általában egyházi személyek voltak. A királyi adminisztráció tagjai a klérusból (papságból) kerültek ki. Jellemzően latin nyelvű egyházi írásbeliség volt.\n\nA térítő tevékenységben szerzetesek is részt vettek. Az első európai szerzetesrend 529-től a bencés rend volt, amely Monte Cassinoban jött létre. Szent Benedek hozta létre. Regulája szerint a szerzeteseknek nem lehetett tulajdonuk, naponta rendszeresen imádkozniuk és dolgozniuk kellett: „Ora et labora!” Fogadalmat kellett tenniük: szegénységi, tisztasági (lelki), engedelmességi. A szerzetesek kolostorokban /apátságokban éltek.\n\nAz apátságok közvetlenül a pápa irányítása alatt álltak. Eleinte román stílusban épültek, tekintélyes méretűek, háromhajós felépítésűek. A kolostor lakóinak életmódjára utalnak az épületek: a templomot kerengő, cellák és gazdasági épületek egészítették ki.\n\nA szerzetesek tevékenysége: mezőgazdasági munka, imádkozás (napi 7x), kódexmásolás. Jelentős szerepük volt a kereszténység elterjesztésében. A kódexek másolásával az ókor kulturális kincseit mentették át, de főleg szent iratokat másoltak. Latin nyelvű írásbeliség volt jellemző.\n\nCluny reformok: a Cluny kolostor a klérus (papság) belső megtisztulásáért indított mozgalmat pl. cölibátus bevezetése.\n\nA szerzetesek:\n\nA szerzetesek kezdetben magányos remetékként éltek, majd keleten, elsőként Egyiptomban jöttek létre szerzetesi közösségek. Szigorú belső előírások szabályozták életüket, s elsősorban a hit elvont kérdéseinek tanulmányozásával foglalkoztak.\n\nNyugaton a szerzetesség gyakorlatiasabb formája terjedt el. Bár a szerzetesi élet célja az istenhez leginkább méltó élet, amelyet pontos szabályok szerint élő közösségekben véltek megvalósíthatónak (a szerzetesek szüzességi, szegénységi és engedelmességi fogadalmat tettek), az itteni kolostorok lakói a hitéleten kívül földet műveltek, könyveket másoltak, hozzájárulva az antik műveltség és elsősorban a latin írásbeliség átmentéséhez. A kora középkorban jelentős részt vállaltak a térítő munkából, s nagyrészt nekik köszönhető, hogy Közép-Európa a latin kereszténységhez csatlakozott.\n\nA kereszténység nyugat-európai térhódításában egyaránt jelentős szerepet játszottak a kontinens északnyugati peremvidékén élő írek Szent Patrick (385-461) tevékenysége nyomán. Az ír kereszténység kolostorok rendszerén alapult.\n\nA szerzetesrendek közül a Nursiai Szent Benedek (480-543) által alapított rend volt az első, amely elfogadta a pápa vezető szerepét. Monte Cassinóban jött létre első kolostoruk Itáliában 529-ben, de a kora középkor folyamán a bencések rendházai behálózták az egész nyugati keresztény világot. A X. században Cluny bencés kolostorából belső megújulás, megtisztulás folyamata indult el.\n\nA legjelentősebb közösséget tehát 529-ben Nursiai Szent Benedek hozta létre Monte Cassino magaslatán (Bencés rend).\n\n• 73 fejezetből álló, igen szigorú és a kolostori életet részletesen szabályozó regulát készített.\n\n• A szerzetesi élet színtere a kolostor, amit a szerzetes nem hagyhatott el.\n\n• A szerzetesnek nem lehetett magántulajdona (de a kolostornak lehetett).\n\n• A szerzetesi élet vezérelve: Ora et labora - imádkozzál és dolgozzál!\n\n• Napközben 7 közös ima + éjszakai imaóra.\n\n• A munka részben szellemi (a Szentírás és más könyvek olvasása és másolása, részben fizikai (pl. földművelés) volt.\n\n• Napi két közös, hústalan étkezés.\n\n• A szerzetessé válás útja: egy évig jelölt (novícius) volt, majd szerzetessé avatáskor le kellett tennie a hármas (szegénységi, tisztasági, engedelmességi) fogadalmat.\n\n• A rend, illetve a kolostor élén az apát állt, akit a közösség választott, és akinek engedelmességgel tartoztak; az apát helyettese a perjel.\n\nA X. században a burgundiai Cluny bencés kolostorból elindult a reformmozgalom:\n\n• visszatértek az eredeti, szigorú bencés regulához;\n\n• visszautasították a világi befolyást;\n\n• a kolostort a helyi püspök joghatósága alól kivéve a pápa védelme alá helyezték.\n\n• A reform sikeres volt, Clunyhoz több mint ezer bencés kolostor csatlakozott, létrejött az ún. Cluny Kongregáció, amelynek vezetője a cluny apát lett. Ebből a reformból nőtt ki a XI. században az egész egyház reformja (gregorián reform - VII. Gergely).\n\nA nyugati kereszténység során kísérlet történt a pápaság alárendelésére: a német-római császár (IV. Henrik) megpróbálja hatalmát kiterjeszteni az egyházra, és a püspökök beitatásának jogát (invesztitúrajog) követeli. VII. Gergely pápasága (1073-85) alatt, 1075-től kezdődtek az invesztitúraharcok, a pápaság és a német-római császárság között. VII. Gergely a pápát a császár fölé emeli (Dictatus Papae). A X-XI. századra megerősödik az egyház. A pápaság kerül ki győztesen a háborúból.\n\nÚj szerzetesrendek a XI. század végétől:\n\nA X. században induló clunyi reformmozgalom jegyében a XI-XIII. század folyamán új szerzetesrendek jöttek létre pl. ciszterci, karthausi, premontrei. A XI. és XII. században a ciszterciek a mezőgazdasági módszerek fejlesztésében vettek részt. A szerzetesrendek fontos szerepet játszottak az írásbeliségben és az oktatásban. A szerzetesrendek jelentős szerepet játszottak a gazdasági és a kulturális életben.\n\nA cluny reform után is voltak olyanok, akik a bencés kolostorokat túl gazdagnak, templomaikat túl fényűzőnek tartották: ezek nem keltették az evangéliumi szegénység látszatát sem. Ezért több kísérlet is történt az eredeti bencés regula szerinti szerzetesség visszaállítására.\n\n• Kölni Szent Brúnó reimsi kanonok alapította a karthauziak rendjét (1084):\n\nszemlélődő remete rend; tagjai csaknem állandó hallgatást fogadtak.\n\n• Szent Róbert Citeaux-ban (latinul Cistercium) megalapította a ciszterci szerzetesrend anyakolostorát (1098). Igazi felvirágzása akkor kezdődött, amikor Szent Bernát 1115-ben Clairvaux-ban ciszterci kolostort alapított — ő lett korának egyik legbefolyásosabb egyházi személyisége. Igen nagy hangsúlyt fektettek a munkálkodásra, a rendnek komoly szerepe volt a korszerű mezőgazdasági módszerek elterjesztésében.\n\n• A korban gyorsan terjedtek az ágostonos rendek, amelyek szabályzatukat Szent Ágoston gondolatai alapján dolgozták ki. Két csoportjuk volt:\n\n• Szabályozott kanonokok rendje: ezek közösségben élő világi papok voltak, akik lelkipásztorkodással foglalkoztak. A legismertebb ilyen rend a Szent Norbert által 1121-ben alapított premontreiek kongregációja volt. Fő feladatának ez a rend a prédikálást és a lelkipásztorkodást tartotta.\n\n• Ágostonos remeték rendje: ide tartozik, pl. az egyetlen magyar alapítású rend, a Remete Szt. Pálról elnevezett pálos rend. Özséb esztergomi kanonok szervezte közösséggé 1250 körül a Pilisben élő remetéket.\n\n• Sok betegápoló (pl. Lázár-rend) és rabkiváltó (pl. trinbitárius rend) közösség is szerveződött.\n\nA szerzetesrendek behálózták az egész katolikus világot. Jelentős szerepet játszottak a katolikus hit terjesztésében (bencések), vagy a fejlettebb gazdálkodási eljárások meghonosításában (ciszterciek).\n\nA XIII. században a koldulórendek – ferencesek, domonkosok – a városokban telepedtek meg, tevékenységüket a tömegek körében fejtették ki.\n\nA koldulórendek\n\nKialakulásuk okai: • A szerzeteseknek nem lehetett magánvagyonuk, de a kolostoroknak igen - a kolostori vagyonok pedig egyre gyarapodtak az újonnan alapított rendeknél is.\n\n• Felgyorsult az urbanizáció, egyre többen laktak városokban, őket az erdőben, távoli tájakon élő ciszterciek, premontreiek nem tudták megszólítani.\n\n• A XII. században Nyugat-Európában kibontakozott a szegénységi mozgalom, amely az őskeresztények szegény egyházához való visszatérését hirdette - számos eretnekmozgalom (albigensek, valdensek) terjedt el rövid idő alatt.\n\n• Az egyház a szegénységi (eretnek) mozgalmakra adott első kemény válasz (eretneküldözés - inkvizíció) után támogatni kezdte a koldulórendek kialakulását. III. Ince pápa hozza létre az inkvizíciót, ahol bíróság elé állítják az eretnekeket.\n\nA kolduló rendeknek nem lehetett vagyona, földbirtoka, rendszeres jövedelme - magukat koldulásból kellett fenntartaniuk.\n\n• A koldulórendek: élén a generális állt; fő törvényhozó szerve a generális káptalan volt;\n\nLegfőbb rendek: ferencesek, domonkosok, karmeliták, szerviták.\n\n• Ferencesek vagy Kisebb Testvérek Rendje: 1223\n\n- Assisi Szt. Ferenc alapította, III. Ince pápa 1209-ben szóban jóváhagyta működését, majd 1223-ban elfogadta írott szabályzatát.\n\n- A rend bekapcsolódott az egyetemi oktatásba.\n\n- Hosszú viták után 1517-ben kettévált a rend: a szegénységet Szt. Ferenc szellemében értelmezőkre (obszervánsok), illetve a gyakorlati élet követelményeihez jobban alkalmazkodókra (konventuálisok vagy minoriták). 1525-ben egy harmadik irányzat is önállósult, a kapucinusok.\n\n• Domonkosok vagy Prédikáló Testvérek Rendje: 1216\n\nA rendet egy, a kathar eretnekekkel küzdő kasztíliai pap, Guzman Domonkos alapította.\n\nAz első rendház Toulouse-ban volt. III. Ince pápa 1216-ban hagyta jóvá a szabályzatát.\n\nA rend komoly szerepet játszott az egyetemi teológia - oktatásban pl. Aquinói Szt. Tamás skolasztikája, amely a hitet a tudománnyal egyeztette össze, mindent alárendelt a vallásnak.\n\nA domonkosok voltak az inkvizíció (egyházi bíróság) működtetői is. Nem számított számukra a vagyon, így nem voltak megvesztegethetők.\n\nA MŰVÉSZETI STÍLUSOK:\n\nA kora középkor kezdetén az építészetben a román stílus volt jellemző, amelyet csak a XII. századtól váltott fel a gótika. A képzőművészet, az irodalom és a zene egyházi töltetű, tematikájú, amibe csak a humanista világnézetű reneszánsz hozott változást. A román építészeti stílus leghíresebb emléke a wormsi székesegyház, és a magyar jáki, lébényi, zsámbéki templom. Jellemzői: zömök, erődszerű falak, lőrésszerű ablakok, gyakran védelemül is szolgált.\n\nRomán építészet\n\nXI-XII. századi nyugat-európai, a harcos egyház stílusa.\n\nStílusjegyei, épülettípusai elterjesztésében a szerzetesrendek (bencések, premontreiek, ciszterek) játszottak jelentős szerepet.\n\nFőleg templomokat építettek.\n\nA román épületet a zártság jellemzi. A formák tömbszerűek, az arányok vaskosak, a szerkezet világosan tagolt. A félkörív jellemző kívül-belül. Lehet boltozati elem, ablak, ajtó íve vagy díszítő szerepű galéria.\n\nA templom alaprajza meghatározott formát követ. Jellemző típus a háromhajós bazilika. A főhajó kereszthajóval bővülhet, a kereszthajó négyezeti toronnyal. A szentélyt olykor kápolnakoszorúval veszik körül.\n\nA homlokzat súlyos zárt tömegét a bélletes-oszlopos főkapu és a kisméretű ablakok tagolják. A homlokzatot tornyok fogják közre. Legegyszerűbben a dongaboltozatot lehetett megépíteni. Két dongaboltozat derékszögű áthatásából született meg a keresztboltozat. A templombelsőben oszlopok és pillérek váltják egymást.\n\nAz épületek veszélyeztetett pontjai voltak a homlokzat és a mellékhajók falai is, a problémát a falak megvastagításával és vaskos támfalak alkalmazásával igyekeztek megoldani.\n\nCluny apátsági templom, wormsi székesegyház, pisai dóm, pármai dóm, veronai San Zeno templom, mainzi dóm, speyeri székesegyház,\n\nRomán építészet:\n\nXI-XIII. század\n\nfal: vastag, várszerű. Feladata: védelem is.\n\nfélköríves boltív\n\nrómai keresztboltozat\n\nalaprajz: hajók, szentély, négyzet. Kötött boltozás.\n\nbélletes kapuzat\n\nikerablakok fent, rózsaablak. Lent lőrésszerű ablakok.\n\nPisai templomegyüttes, jáki templom, esztergomi vár és várkápolna, wormsi dóm.\n\nRomán szobrászat, festészet:\n\ntársművészet, az építészet kiegészítője\n\n„szegények Bibliája”: szentírási történeteket magyaráz\n\nnem az anatómiai pontosság a fontos, a lényeget emeli ki\n\nKalocsai királyfej\n\nA GÓTIKA\n\nA gótika a győztes egyház építészeti stílusa. 1200 és 1450 között virágzott. Jellemző stílusjegyei a keresztboltozatos, bordás födémek, a támpillérek, utóbbiaknak köszönhetően a vékony és magas falak, oszloperdő, óriási rózsaablakok, magas, égbe törő, keskeny, csipkézett tornyok. Csúcsíves ablakok, valamint díszítőelemek (szobrok, vízköpők) alkalmazása tették teljessé az építményeket. Jellemző példája a kölni dóm. Miskolcon pl. a Diósgyőri vár, Avasi templom.\n\nAz európai középkor második nagy nemzetközi stíluskorszaka, mely a XII. századtól a XVI. század elejéig tartott. A gótika Franciaországban született.\n\nLegfőbb jellegzetességei: csúcsív, bordás keresztboltozat, támszerkezet támívekkel és támpillérekkel, mérmű, fiatorony, rózsaablak.\n\nVilági épületeket is építettek gótikus stílusban.\n\nA gótikus templomok építészeti szempontból a következő elveknek feleltek meg: megtartották a bazilika alaptípusát, egységesebb és nagyobb belső térre törekedtek. Az alaprajz kereszt alakú, a kereszthajó rövidebb és szorosabban kapcsolódik a főhajóhoz. A főbejárat a kereszt hosszanti szárnyának nyugati oldalán van, a szentély keletre néz. A főhajó általában magasabb a mellékhajóknál. A főhajót a mellékhajóktól pillérkötegeken és féloszlopokon nyugvó csúcsíves árkádok választják el. A boltozat megterhelését pillérkötegeken vezetik le.\n\nLegfontosabb újítás: a boltozati terhelést nem a falak hordják, hanem a boltozatot zárókövétől kezdve bordákon és pillérkötegeken át az épület külsejéhez illesztett támszerkezet hordozza.\n\nÉgbe szökő pillérek, karcsú arányok, csúcsívek, mérműves üvegablakok, elegáns, könnyed szobrok, magas boltozat.\n\nKatedrálisok: a párizsi Notre Dame, Reims katedrálisa, Chartres katedrálisa, kölni dóm, budai Mátyás-templom.\n\nGótikus építészet:\n\nXIII-XV. század\n\nfal: vékony, csak határol. Oszlop, pillér, borda, támpillér\n\ncsúcsíves boltív\n\nbordás keresztboltozat\n\nkötetlen boltozás\n\nbélletes kapuzat\n\nikerablak, rózsaablak, nincs lőrés.\n\nfal helyett lehet üvegablak\n\nPárizsi Notre Dame, Velencei Doge palota,\n\nGótikus szobrászat\n\népítészet kiegészítője, főleg domborművek\n\nS alak (kontraposzt)\n\nKolozsvári testvérek: Szent György; Szent László hermája\n\nGótikus festészet:\n\nüvegablakok\n\ntáblakép-festészet\n\nszárnyasoltárok\n\nArnolfini házaspár, Genti oltár; Avignoni Pieta, M.S. mester: Mária és Erzsébet találkozása.\n\nA RENESZÁNSZ:\n\nA középkor végére, a XIV-XVI. században új stílusirányzat jelenik meg, a reneszánsz; a francia eredetű szó újjászületést jelent, az ókori római-görög kultúra és művészet újjászületésére utal. A reneszánsz kezdetét Itáliában a 14. századra, Firenzében alakult ki, Európa többi részén többnyire a 16. századra teszik. Tudományos forradalmat, művészeti átalakulást, megújulást hozó, meghatározó kulturális mozgalom volt. Egyben művelődéstörténeti és művészettörténeti korszak is, amely a középkor végét és az újkor elejét (korai újkor) felölelő átmeneti időszakra esik. A reneszánsz stílus ezenkívül a művészettörténetben jellegzetes korstílust is jelöl. A reneszánsz korban megszűnik a vallásos témák hegemóniája, a művészetben megjelenik a természetábrázolás. A kor szellemi irányzata a humanizmus volt, amely az embert helyezte a középpontba. A humanisták az ókori forrásokat (filozófiát és irodalmat) tanulmányozták, és szabadgondolkodóként jó néhányan kritikával illették az egyházat. A kor embereszménye a sokoldalúan képzett polihisztor volt. A mecénások pártolták a művészeteket, hatalmas pénzeket áldoztak templomok, paloták építtetésére. Őket nevezzük mecénásnak (ilyen volt pl. Firenzében a Medici család).\n\nKorszakolása:\n\n14. század (Trecento, vagyis 1300-as évek) – proto-reneszánsz (előreneszánsz): csak az irodalomban jelenik meg. A többi művészeti ágban még a gótika uralkodik. Pl. Petrarca, Boccaccio.\n\n15. század (Quattrocento, 1400-as évek) – kora reneszánsz: törekvés a tökéletesnek tartott antik művészet színvonalának elérésére, minden művészeti ágban. 1480-tól érett reneszánsz.\n\n16. század (Cinquecento, 1500-as évek) – eléri, sőt meghaladja az antikvitás színvonalát.\n\n1520-1600 között: késő reneszánsz, illetve manierizmus: a reneszánsz harmónia felbomlása, formanyelvének modorossá válása (maniera: modor)\n\nKét szellemi irányzata volt, a humanizmus és a reformáció. A humanisták körében fontos az általános műveltség és a latin nyelv ismerete. A reformáció hívei hitújításra törekedtek. Az emberi értékek közé tartozott a tudás, valamint egyházi és a világi műveltség. Embereszménye a tudós humanista, aki beszéli az ókori nyelveket, jártas a filozófiában, filológiában, archeológiában. Boncolás segítségével tanulmányozták az emberi és állati testeket. Az emberek érdeklődési köre a természet és az emberi test megfigyelésére összpontosul. Az életet az ókorral szemben nem siralomvölgynek tartják, hanem gazdag és értékes létezésnek. A reneszánsz irodalomban fontos a nemzeti nyelvek ismerete, az arányosság, a harmónia. Gyakori műfaj: a dal, a novella, a szonett, a tragédia és a komédia.\n\nItt alkotott a korai reneszánsz művész, Dante, az első író, aki személyében megtestesítette a reneszánsz szellemiségét. A másik korai reneszánsz művész, Petrarca, ő humanizmust hirdette.\n\nA vallási témák helyett nagy számban a kereszténység előtti ókori római és görög időkhöz nyúltak vissza: a rómaiak között Cicero, Horatius, Sallustius és Vergilius, a görögök között Arisztotelész, Homérosz, Platón és Szókratész volt a minta.\n\nA politikai filozófus, Machiavelli fő műve, A fejedelem - eszerint az erkölcsi elveket teljesen alá kell rendelni a célszerűség, a cél elérése által és érdekében diktált szempontoknak\n\nA képzőművészetek közül először a szobrászat mutatott reneszánsz vonásokat. Michelangelo a Dávid című szobrával a meztelen emberi testet ábrázolta. Híres még a Pietája vagy a Mózes szobra. A reneszánsz festészet a realizmus perspektívájáról vált ismertté, valamint eltávolodásáról a vallási témáktól, ami a középkori művészet velejárója volt. Ehelyett az emberi test és a tájképek kerültek a figyelem középpontjába. A figurák a gótikus festészet laposságához képest forradalmi újítást hoztak térhatású megformálásukkal. A legismertebb festők ebben a korban Donatello, Raffaello, Leonardo da Vinci, Dürer és Michelangelo voltak. Leonardo da Vinci: Az Utolsó vacsora, az Athéni iskola, a Mona Lisa és a Szent Család mind perspektivikus, élő és természetes bemutatásai embereknek és tájaknak.\n\nÉpítészet pl. Firenzei dóm, Szent Péter templom (Róma), esztergomi Bakócz-kápolna.\n\nMagyarországon a 15. század közepén jelent meg a reneszánsz Mátyás király udvarában. Sok itáliai humanistát vonzott a budai és visegrádi királyi udvarba (például Galeotto Marziót és Antonio Bonfini történetírót). Több itáliai tudós és művész 1476-ban Mátyás második feleségének, a nápolyi Beatrixnak a kíséretében érkezett Budára. Mátyás könyvtára, a Bibliotheca Corviniana, Európa legnagyobb történelmi, filozófiai és tudományos kódexgyűjteménye volt. A kor költője Janus Pannonius. A XVI. században Balassi Bálint, és az angol Shakespeare volt a reneszánsz híres képviselője.\n\nA reneszánsz átalakulási folyamatainak sebességét Európában a könyvnyomtatás feltalálására szokták visszavezetni. (Johannes Guttenberg).\n\nA reneszánsz új korszakot hozott a történelemben. A megerősödő polgárság szellemi irányzata. Harmóniára, szimmetriára törekvés jellemzi.\n\nA BAROKK\n\nA BAROKK: a katolicizmus megújulásával együtt született meg az új korstílus, a barokk. A XVI. század eseményei a reneszánsz embert és művészt a hit felé fordították. Másrészt a katolikus egyház a művészetet a hit erősítésére szolgáló eszköznek tekintette. Ösztönözte azokat a műalkotásokat, amelyek az érzelmekre, érzékekre hatottak. Ezt támogatták a megerősödő katolikus fejedelmek és főurak. Megrendeléseik nyomán sorra épültek gazdagon díszített templomok, pompás kastélyok és paloták, születtek zenei, képzőművészeti alkotások. A XVII. században uralkodó irányzatot az érzelmi túlfűtöttség, túldíszítettség, mozgalmasság, változatosság jellemzi minden művészeti ágban. Az egyház célja a túldíszített templomokkal a hívek visszahódítása, ámulatba ejtése, az egyház nagyságának érzékeltetése.\n\nA barokk születése\n\nA barokk kialakulása és térnyerése a 16. század második feléhez köthető, és a 18. század második feléig volt meghatározó. A név az olasz ’barocco’ szóból származik, amelynek jelentése ’különös, szokatlan’, nyakatekert okoskodás. Többnyire azokra a művészeti alkotásokra alkalmazták eleinte, amelyeket körülményesnek, túldíszítettnek, bizarrnak tartottak. A barokk kialakulása és elterjedése mindenhol szorosan kapcsolódik az ellenreformáció folyamatához. A protestantizmus nagyarányú elterjedésének visszaszorítására a római pápa zsinatot hívott össze. Az ellenreformáció vagy rekatolizáció ezzel a gyűléssel, az 1545–1563-ig tartó tridenti zsinattal vette kezdetét. A katolikus egyház belső megújulását hirdető, a protestantizmus visszaszorítását és a katolikus hit újjáélesztését szorgalmazó mozgalomban jelentős szerepet játszott a jezsuita rend. A jezsuita rendet (jelentése: Jézus Társasága) a spanyol katolikus szerzetes, Loyolai Szent Ignác alapította.\n\nFormanyelve: a pompa, a túldíszítettség, a monumentalitás és a körvonal váltja fel. Világképe is más, mint a reneszánszé: az emberközpontú, földi lét hangsúlyait az új korstílus – a középkorhoz hasonlóan – a tapasztalaton túli világ, a vallásos hit felé tolta el. Hite szerint a folyton és mozgalmasan változó világban minden csak Isten által és Istenben nyerhet értelmet.\n\nA barokk egyik legjelentősebb művésze Lorenzo Bernini, Róma barokk arculatának megteremtője. Szökőkútjai és terei ma is meghatározzák az olasz főváros városképét. Ő alakította ki például a Szent Péter tér mai formáját. Szobrászként is jelentős, az egyik római templom számára készített oltárszobra, a Szent Teréz eksztázisa a vallásos elragadtatottságot szinte testi eksztázisként jeleníti meg. A festészetet tekintve kiemelhetjük a Toledóban élő El Greco valószerűtlen térábrázolásának köszönhető látomásszerű festményeit (pl. Az ötödik pecsét feltörése), vagy a flamand Peter Paul Rubens képeit, amelyek lendületes vonalvezetésükkel, a test ábrázolásának módjával jelentős mértékben meghatározták az európai barokk festészetet. A barokk festészetre jellemző illúziókeltés szép példája a római Loyolai Szent Ignác-templom fent látható mennyezetfreskója. A kép Szent Ignác megdicsőülését ábrázolja, és a sík mennyezeten egy felfelé nyitott, mennyei alakokkal benépesített tér hatását kelti. A zenei barokk kezdetét és végét egyaránt egy-egy szimbolikus eseményhez kötik a történészek: az opera műfajának megjelenéséhez (1600), illetve a nagy német zeneszerző, Johann Sebastian Bach halálához (1750). Rajta kívül a barokk zene kiemelkedő képviselői az itáliai Antonio Vivaldi, a XIV. Lajos udvarában dolgozó Jean-Baptiste Lully, valamint az Angliában élő Georg Friedrich Händel.', 225, 1, '2026-04-17 09:40:23', '2026-04-17 09:40:23');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(13, 13, 'Rendi és abszolutista törekvések Magyarországon, a magyar rendek és a Habsburg udvar konfliktusai és együttműködése', '13.docx', '13. Rendi és abszolutista törekvések Magyarországon, a magyar rendek és a Habsburg udvar konfliktusai és együttműködése\n\na 17-18. században\n\nELŐZMÉNYEK:\n\nA Habsburgok hatalomra kerülése Magyarországon – előzmények a XVI. században\n\nAz 1526-os mohácsi csatavesztés után, a király és hadsereg nélkül maradt országra már 1526. október 25-én bejelentette igényét Habsburg Ferdinánd, aki az északi és nyugati részeket Bécs védelmének rendelte alá.\n\nKét politikai tábor alakult ki:\n\n• Habsburg-pártiak (II. Lajos özvegye, Habsburg Mária királyné körül Pozsonyban);\n\n• Szapolyai pártiak (Szapolyai János körül).\n\n1526 novemberében a fehérvári országgyűlésen 22 megye követe Szapolyait királlyá (1526-40) választotta, akit ezután a rangidős nyitrai püspök meg is koronázott.\n\n1526 decemberében a Pozsonyba összehívott országgyűlés viszont Habsburg Ferdinándot (1526-64) választotta királlyá. Ferdinánd volt nehezebb helyzetben, de mögötte állt a testvére, Habsburg V. Károly császár.\n\nHabsburg berendezkedés Magyarországon:\n\n1526 után fokozatosan alakult ki az egykori magyar királyságból a királyi Magyarország, a török hódoltsági terület és az Erdélyi Fejedelemség. A királyi Magyarország a nyugati és északi országrészeket foglalta magában. Védelmét hat főkapitány, száz végvár és 15-20 ezer katona látta el. A zsold, valamint az erősségek korszerűsítése a kincstárt terhelte. A Német-római Birodalom rendjei tetemes összeggel támogatták Magyarország védelmét. Mivel ezekhez a pénzforrásokhoz csak a Habsburgokon keresztül lehetett hozzájutni, a kortársak szerint Magyarország az ő segítségük nélkül nem tarthatná magát, nemcsak koncentrált támadás, de akár kisebb török haderővel szemben sem.\n\nMagyarország politikai és igazgatási rendszerében az udvar országon kívülre helyeződése és a törökellenes harc követelményei okoztak változást.\n\nBécsben már korábban kialakultak a központi hivatalok. Ferdinánd Magyarországon felállította a magyar központi kormányszékeket: a helytartótanácsot, a magyar kancelláriát és a magyar kamarát. Az átalakulásokat a magyar rendiség intézményrendszerének zöme, pl. a nádori tisztség, az országgyűlés és a nemesi vármegye átvészelte. A főkapitányi tisztet is magyar nagybirtokosok töltötték be, így a végvári katonaságot fölhasználhatták a rendiség védelmében. A nagybirtokosok komoly magánhadsereggel rendelkeztek, törekvéseik arra irányultak, hogy megőrizzék a magyar királyság önállóságát.\n\nA rendi törekvésekre a Habsburgok a nádori szék betöltetlenül hagyásával, olykor pedig az országgyűlések megritkításával válaszoltak, igaz, az utóbbi összehívására az adók megajánlása miatt mégiscsak rákényszerült. A belügyekben a rendek nagyobb önállósággal rendelkeztek, ami tulajdonképpen az uralkodó és a rendek közötti hatalommegosztást tükrözte. Idegen uralom alatt kibontakozó rendi dualizmusról beszélhetünk tehát. Téves nézet Habsburg-ellenes küzdelemről beszélni már a XVI. században. Az udvar és a rendek „küzdelme” 1604-ig alkotmányos keretek között folyt.\n\nA Bocskai-szabadságharc (1604-1606)\n\nA felkelés a rendi intézményrendszer és a protestáns vallásszabadság megsértése miatt indult 1604-ben. A tizenöt éves háború költségeinek fedezésére az uralkodó felségsértési pereket indíttatott. A Bocskai-felkelés a tizenöt éves háború (1591-1606) végén tört ki és a bécsi béke zárta le 1606-ban.\n\nOkai: megromlott Bécs és a magyar rendek viszonya. A Habsburg Birodalom pénzügyi nehézségekkel küzdött. A háború terheiből sokat a magyar nemesekre hárított. Felségsértési pereket indított a vállalkozó kedvű főurak, így Illésházy István országbíró ellen, ami fej-és jószágvesztéssel végződött. A protestánsok ellen hozott korlátozó intézkedések elmérgesítették az udvar és a rendek viszonyát.\n\nA katolikus Habsburg uralkodók az ellenreformációt támogatták, és a felkelés egyik kiváltó oka az erőszakos rekatolizáció volt. A Habsburgok az abszolutizmus bevezetésével próbálkoztak, a kiváltságaikat és politikai jogaikat féltő rendek ezért csatlakoztak Bocskaihoz. A felkelés konkrét kiváltó oka a Bocskai ellen indított per volt.\n\n1604-ben fegyveres felkelés tört ki a Habsburgok ellen Kelet-Magyarországon. A felkelést Belgiojoso Bocskai bihari várai ellen intézett támadása váltotta ki. Sérelmei miatt kezdetben Bocskai vonakodott az uralkodó ellen fordulni, majd Bethlen Gábor biztatására elindította a magyar rendek első fegyveres mozgalmát a Habsburgok ellen. Bocskai a hozzá átállt hajdúk segítségével győzelmet aratott a császáriak fölött. A hajdúk a legfőbb problémának a protestánsok üldözését tartják, hiszen maguk is protestánsok voltak. A felkelés katonai erejét ők adták. Segítségükkel Bocskai elfoglalta az egész Felvidéket és birtokba vette Erdélyt, ahol fejedelemmé választották.\n\nBocskai tehát Erdély fejedelme lett (1605-1606), és egy időre a Felvidéket is elfoglalta. Erdély szerepe a jövőben a rendiség és a protestantizmus védelmezése lett. 1605-ben a szerencsi országgyűlés is fejedelemmé választotta. A I. Ahmed szultán koronát küldött Bocskainak, aki csak ajándékként és nem felségjelvényként fogadta el. I. Rudolf császár (1576-1608), miután a Német-római Birodalomban és szövetségeseitől nem kapott segítséget, hajlott a béketárgyalásokra. Nemkülönben a felkelők, hiszen időközben tapasztalniuk kellett a török támogatás veszélyességét. 1606-ban a bécsi béke zárta le a felkelést, mely kimondta a rendi alkotmány biztosítását, a protestánsok vallásszabadságát, és elismerte Erdély önállóságát. A bécsi béke a protestáns rendek vallásszabadságát biztosítja, és ebbe a végvári katonákat is beleértették. A bécsi béke a nádort a király helyetteseként említi, ez visszatérést jelent a rendi kormányzáshoz. 1608-ban a rendek (a király katolikus és protestáns jelöltjei közül) nádort választhattak, ez azt mutatja, hogy a bécsi béke előírásai érvényesültek. A bécsi béke helyreállította a rendiséget és a vallásszabadságot, az új egyensúly évtizedekig működött.\n\nA Habsburgok és a törökök közötti háborút az 1606-os zsitvatoroki béke zárta le, mely a tényleges helyzet alapján rendezte a határokat, a szultán egyenrangú félnek nyilvánította a magyar királyt, és végleg lemondott a Bécs által fizetendő évi adóról.\n\nBocskai a hajdúk sorsát is rendezte. Több mint tízezer hajdúvitézét telepítette le szabolcsi birtokaira. Katonás vonásaikat megőrizték, de lassan áttértek a földművelésre. A hajdúszabadság elnyerésével az állami és földesúri szolgáltatások alól mentesítve voltak, így a paraszttársadalom felett állóknak tekintették magukat.\n\nBocskai 1606-os politikai végrendelete fordulatot jelzett a XVI. századi országegyesítő törekvések sorában. Az egységes Magyarországot csakis abban az esetben tartotta ugyanis kívánatosnak, ha a magyar korona valóban magyar kézben maradna. Bocskai Erdély önállósága mellett érvel, és erre szerinte a magyar rendek jogainak védelmében van szükség, amíg nincs önálló magyar királyság. A felkelés megváltoztatta az Erdély szerepéről vallott felfogást: ezután nem az országegyesítésre törekedtek, hanem Erdélyben a rendi kiváltságok és a protestantizmus védelmezőjét látták.\n\nA XVII. században olyan felfogás is terjedt, hogy a megosztottságból szintén származhatnak előnyök. E nézet szerint a királyi Magyarország biztosítja a török megfékezéséhez a külső segítséget, Erdély pedig - magyar vezetés alatt, török segítséggel - a királyi Magyarországon is korlátozni tudja a Habsburgokat abban, hogy a magyar nemességet kisemmizze a hatalomból.\n\nBethlen Gábor erdélyi fejedelem politikája (1613-1629)\n\nAz Erdélyi Fejedelemség virágkora\n\nElőzmények: az 1606. évi bécsi béke a magyar rendek megerősödését hozta. 1608-ban - II. Mátyás megválasztása érdekében - szövetségre léptek az osztrák és morva rendekkel. Mátyás az egész birodalom támogatásával Habsburg Rudolfot a maga javára lemondatta a magyar koronáról és az osztrák örökös tartományokról.\n\nII. Mátyásnak cserében fel kellet adnia a központosítási igényét. Az 1608. évi törvényekkel megerősítették a bécsi békét. Az uralkodó helyettesítését teljes jogkörrel a nádorra bízták. Amíg a magyar rendek egységesen léptek fel Béccsel szemben, addig Erdély politikai életének megítélésében különböző álláspontra helyezkedtek. Az újraegyesítés kérdésében például a katolikus főurak támogatták, a protestánsok ellene foglaltak állást.\n\nBocskai István 1606-os halála után Rákóczi Zsigmond, majd Báthori Gábor lett Erdély fejedelme. Báthori Gábor (1608-13) fejedelemsége alkalmat adott, hogy beavatkozzanak Erdély zavaros belpolitikai életébe. Az erdélyi fejedelem sok ellenséget szerzett magának: a szászoktól el akarta venni kiváltságaikat; hajdúknak megölette a vezetőjét; tanácsosainak vagyona és feleségei is veszélyben voltak; a törökök amiatt ellenezték, mert el akarta foglalni Havasalföldet. Az elégedetlen rendek az 1613-ban Kolozsvárott leváltották Báthoryt, botrányos élete és kalandor politikája miatt a Porta mellőzte, száműzte, majd Váradon megölték.\n\nA török támogatását is élvező Bethlen Gábort választották fejedelemmé (1613-29).\n\nBethlen Gábor kül- és belpolitikája\n\na törökök segítségével jutott hatalomra, aminek ára volt: 1616-ban a törököknek átadta Lippa várát, miután az ellenálló őrségtől erővel elfoglalta azt, de ügyes politizálással a török szultántól való függést névlegessé tudta tenni, a vazallusi viszony ellenére megőrizte Erdély szuverenitását.\n\nKemény kézzel látott hozzá a fejedelmi hatalom megerősítéséhez: elrendelte a kincstári birtokok összeírását, elkobozta az érdemtelenül adományozott javakat.\n\nVisszaadta a szászoknak a Báthory által elfoglalt Nagyszebent, a székelyeknek pedig megígérte jogaik tiszteletben tartását.\n\nGazdaságpolitikája:\n\nA kereskedelem fejedelmi monopólium lett. Állami monopóliumot vezetett be a higany, méz, só, viasz, marha, nemesfémek kereskedelmében, tehát az ezzel való kereskedés joga csak a fejedelmet illette meg. Bethlen igyekezett betörni az itáliai piacra, sőt a svédekkel közösen tervezte az európai rézpiac meghódítását.\n\nA pénzverés is fejedelmi monopólium volt.\n\nAz iparfejlesztést külföldiek behívásával támogatta. Bányászokat hívott Erdélybe (pl. Körmöcbányából); kézműveseket telepített le Erdélyben (Morvaországból anabaptista habán fazekasokat).\n\nNem beszélhetünk Bethlen Gáborral kapcsolatban klasszikus értelemben vett fejedelmi merkantilizmusról, ugyanis ebbe beletartozna a manufaktúraépítés is, pedig az iparcikkellátásban nagy hiányok mutatkoztak. A jövedelmek jelentős hányada nyersanyagok vagy félkész termékek forgalmából származott.\n\nKultúrpolitikája: késő reneszánsz gyulafehérvári udvartartás; jelentős fejedelmi könyvtárat hozott létre, támogatta a könyvnyomtatást (Misztótfalusi Kis Miklós). A tehetséges jobbágy fiatalokat támogatta, külföldi egyetemen tanulhattak (pl. Heidelbergben). Jövedelméből jelentős összeget fordított kultúrára. Gyulafehérváron protestáns főiskolát alapított (1622);\n\n11 számos tanár érkezett Erdélybe, pl.: Apáczai Csere János, aki a Magyar enciklopédia - az első magyar tudományos gyűjtemény írója volt;\n\nUralkodása: célja az ország egyesítése volt a törököktől való függés fenntartása mellett.\n\nFő feladatának a belső rend megteremtését tekintette.\n\nRendezte a szászokkal való viszonyt (törölte Szeben fejedelmi birtok státusát), ezzel megszilárdította a három nemzet unióját.\n\nCsökkentette az országgyűlések számát, szabadon alakította összetételét. A rendi szervek megmaradtak, de alig korlátozták a fejedelmi hatalmat.\n\nAnyagiakban is függetlenítette magát a rendi erőforrásoktól. A kincstári javak visszaszerzésére törekedett, ezzel a főurakat középnemesi szintre süllyesztette. Szabályozta az állami adóztatást.\n\nBethlen Gábor intézkedéseivel korlátlan fejedelmi hatalmat épített ki, szilárd gazdasági alappal, jól fizetett - főleg székelyekből és hajdúkból álló - fegyelmezett hadsereggel. Uralkodása kedvezően hatott a társadalom egészére. Külső támadás nem érte, megszűntek a belpolitikai küzdelmek. A nemzetközi politikába is beleszólt.\n\nKülpolitikájában a török bizalmát igyekezett megnyerni, felvette a kapcsolatot a román vajdákkal. 1618-ban, amikor a cseh rendek Prágában Habsburg-ellenes felkelést robbantottak ki, Bethlen nemzetközi szövetség tagjaként 1619-ben a 30 éves háborúban a csehek oldalán indult II. Ferdinánd ellen. Hadai csekély ellenállásba ütköztek a királyi Magyarország területén. A magyar főurak örömmel fogadták, de katonai segítséget nem adtak. Elfoglalta Kassát, Pozsonyt. Az egyesült cseh, morva és erdélyi hadsereg Bécs ostromára készülődött. 1620-ban Pozsonyban Magyarország fejedelmévé, 1620-ban a besztercebányai országgyűlés királlyá választotta Bethlen Gábort, ő azonban nem látta biztosítva helyzetét sem a török, sem a magyar rendek oldaláról, így nem koronáztatta meg magát. Tudta, hogy a törökök nem egyeznek bele a két országrész egyesítésébe.\n\nA csehek 1620-as fehérhegyi veresége után a magyar rendek sietve visszatértek a király mellé, hiszen nem akarták elveszíteni rendi jogaikat, mint a csehek, így Bethlen békekötésre kényszerült. 1621-ben Nikolsburgban kedvező feltételekkel kötött békét II. Ferdinánddal. Bethlen lemondott az általa megszállt területekről, kivonult Alsó-Magyarországról és lemondott a királyi címről. Megkapott két sziléziai hercegséget, valamint hét felső-magyarországi vármegyét: élete végéig megkapta Szabolcs, Szatmár, Bereg, Borsod, Abaúj, Zemplén, Ugocsa jövedelmeit és birtokadományozási jogát. Még kétszer (1623, 1626) avatkozott be a 30 éves háborúba, de végül nem sikerült megvalósítania nagy tervét: Magyarország egyesítését. Bethlen Gábor 1629-ben halt meg, felesége, Brandenburgi Katalin.\n\nBethlen politikájának értékelése:\n\nBethlen eszménye az erős fejedelmi hatalom, uralma az abszolutizmus egyes jegyeit is mutatja. Az erdélyi rendek viszonylagosan gyengék voltak, ez megkönnyítette az erős fejedelmi hatalom megteremtését. Bethlen a királyi Magyarország és Erdély egyesítése érdekében bekapcsolódott a harmincéves háborúba (1618-1648), de szövetségesei kudarcai miatt csak részeredményeket ért el. Bethlen gazdasági reformjai biztosították háborúinak pénzügyi alapját. Bethlen gazdaságpolitikája merkantilista. Uralkodásának időszaka Erdély aranykora volt. Az Erdélyi Fejedelemség erőforrásai korlátozottak voltak, ennek ellenére a hadi kiadásokon kívül futotta a fejedelmi udvar fényének megteremtésére, a kultúra, a kálvinista egyház támogatására is. A fejedelem kényszerű realitásnak fogja fel a török hatalmát. Külső segítség híján megpróbálja befolyásolni a portát, elhárítva ezzel Erdély török megszállását. Bethlen békét kötött a Habsburg uralkodóval, és ennek bel- és külpolitikai okai egyaránt voltak.\n\nA hajdúk és a törökök nyomására, a váradi és a székely főkapitányok támogatásával az 1630-as segesvári országgyűlés I. Rákóczi Györgyöt választotta fejedelemmé 1630-ban.\n\nI. Rákóczi György (1630-1648) megfontolt, megbízható politikus volt. Fejedelmi hatalmát magánbirtokaira alapozta. A „bibliás, őrálló fejedelem” őrködött a protestánsok vallásszabadsága felett. 1643-ban a svédekkel szövetkezve a Habsburgok ellen kapcsolódott be a harmincéves háborúba. Brünnél egyesültek a svéd sereggel. Elfoglalta Felső-Magyarországot (1644). 1645-ben az erdélyi hadak Nagyszombatot elfoglalva folytatták az előrenyomulást, pedig ezt a Porta egyenesen megtiltotta.\n\nAz 1645. évi linzi békében megerősítette az 1606-os bécsi békét, Rákóczi is megkapta élete végéig, a Bethlennek a nikolsburgi békében juttatott 7 vármegyét, sőt a protestánsok vallásszabadságát kiterjesztette a mezővárosok és a falvak lakosságára is.\n\nII. Rákóczi György fejedelemsége idején (1648-1660) Erdély helyzetét az európai események jelentősen befolyásolták. A vesztfáliai békétől (1648) a katolikus főurak a török kiűzését remélték. Ezt várták a fejedelemtől is. Tekintélyét katonai és diplomáciai sikerek növelték. 1657-ben a svédek és a franciák szövetségeseként betört Lengyelországba, bár anyja, Lorántffy Zsuzsanna és tanácsadói óvták e kalandtól. A Porta engedélye nélkül vezette az erdélyi hadakat. A svéd szövetségesek visszavonultak, a kozák és román csapatok is elhagyták Rákóczit. A Porta a krími tatárokat küldte a fejedelem hátbatámadására, akik az egész erdélyi sereget fogságba ejtették, a Székelyföldet pedig földúlták. A szászfenesi csatában a fejedelem is életét vesztette. 1660-ban Erdélyre sorozatos török-tatár támadások zúdultak.\n\nZrínyi Miklós tevékenysége és törökellenes küzdelmei\n\nAz egyik legnagyobb magyarországi birtokos, később horvát bán Zrínyi Miklós (1620-1664) élete során jelentős szerepet vállalt a törökök elleni harcokban. Zrínyi Miklós horvát katolikus főúr; családja birtokai az ország délnyugati részén terültek el, a tengerhez vezető útvonalak mentén Csáktornyától az Adriáig. A tengeri kikötők nagy jövedelmet biztosítottak a családnak, emiatt portyázásaival a török gyakran háborgatta. Zrínyi a végek harcaiban lett politikus. Zrínyi katonai teljesítménye mellett irodalmi munkái is jelentősek, amelyek között több is haditechnikai, politikai tartalmú, és mindegyik a törökök legyőzésének a lehetőségével foglalkozik. Felismeri, hogy ezt csak nemzetközi összefogással lehet megvalósítani, ugyanakkor fontosnak tartja egy erős, önálló magyar hadsereg kiképzését, hogy a felszabadulás utáni esetleges idegen elnyomást meg lehessen akadályozni.\n\nZrínyi Miklóst III. Ferdinánd 1647-ben nevezte ki horvát bánnak, ezzel a déli részek őrzőjévé vált. Ő is várta a Habsburgok segítségét, de hamar ráébredt, hogy előbb az országnak is meg kell újulnia: fel kell számolni a belső megosztottságot, modernizálni kell a közigazgatást, a hadsereget. Műveiben ezeket a feladatokat írta le.\n\nAz egész Európára kiterjedő 30 éves háború Magyarországon háttérbe szorította a török-kérdést, de lezárulta után újból előkerült a törökök kiűzésének ideája.\n\n1648-ban a vesztfáliai békével a Habsburgok nagy háborúja befejeződött, azután lehetőség kínálkozott a török elleni összefogásra. Lengyelországban tárgyalások folytak egy nemzetközi összefogással szervezendő törökellenes hadjáratról Velence és a pápa szövetségével, de számítottak a Habsburgokra is. II. Rákóczi György szintén felajánlotta részvételét, bár a török fennhatósága alatt uralkodott.\n\nIII. Ferdinánd azonban szélnek eresztette hadseregét, ezzel kinyilvánította, hogy a béke mellett döntött. A magyarországi főrendek körében ez a lépés nagy felháborodást váltott ki. Kinyilvánította nemtetszését Zrínyi Miklós horvátországi bán is, aki azonban a megoldásra javaslatokat tett. Elképzeléseit nádorként szerette volna megvalósítani, de 1655-ben nem őt, hanem Wesselényi Ferencet választották nádorrá.\n\nA gyakorlat tanulságait a könyvekből vett ismeretekkel gazdagította. Magyarország akkoriban leggazdagabb magánkönyvtárát gyűjtötte össze. Vitézi híre Európa-szerte ismert, az országgyűléseken tekintélyes politikus volt. Eposza és hadtudományi művei:\n\n• Szigeti veszedelem (1645/46): példát állít a nemzet elé.\n\n• Tábori kis tracta (1649): hadseregszervezés elméleti munkája.\n\n• Vitéz hadnagy (1653): elmélkedés a jó hadvezérről.\n\n• Mátyás király életéről való elmélkedések (1656): bírálja a döntésképtelen Habsburg uralkodókat, hangsúlyozza az aktív török-ellenes külpolitikát.\n\n• Az török áfium ellen való orvosság, avagy az töröknek magyarral való békessége ellen való antidotum [ellenméreg] (1661): „Aki békét akar, készüljön a háborúra\" - meghirdette a nemzeti (nemesekből, hajdúkból, jobbágyokból álló) hadsereg kialakításának programját, amelynek 3 alapfeltételét jelölte meg:\n\n- pénzügyi alapok megteremtése;\n\n- a kapcsolatok rendezése Ausztriával;\n\n- a magyar közigazgatás korszerűsítése.\n\nZrínyi Miklós a török elleni harc szolgálatába állította munkásságát. A „Szigeti veszedelem” c. eposzával a hősi halált halt dédapjának 1566-ban folytatott harcát írta le, de saját kortársait akarta buzdítani a török hódoltság felszámolására, az ország egyesítésére. Hadtudományi munkáiban („Tábori kis trakta”, „Vitéz hadnagy”) a felkészülés gyakorlati feladatait fogalmazta meg. A „Mátyás király életéről való elmélkedések” c. munkájában a korszerű uralkodó példáját állította kortársai elé. Keményen bírálta a rendi államot, a kusza magyarországi állapotokat. Mátyás kormányzását felidézve az abszolutista állam híve volt. Erős kezű uralkodó vezette, jól szervezett országban látta Magyarország jövőjét. Ezután fordult II. Rákóczi György erdélyi fejedelem (1648-60) felé, aki azonban meggondolatlan lengyelországi hadjáratával kivívta a török haragját, és állandóan menekülésben volt, így nem lehetett a nemzeti összefogás vezetője.\n\nA magyar királyi trónra II. Rákóczi György erdélyi fejedelmet szánta, aki svéd szövetségben a lengyel trón megszerzéséért szállt hadba, de vereséggel tért vissza. Az egész erdélyi sereg tatár fogságba esett, valamennyiüket a Krímbe hurcolták. A tatárok Erdélyt is feldúlták. 1660-ban a Porta megtorló hadjárata Erdély ellen szomorú következményekkel járt. Várad elesett, a várral együtt óriási terület veszett el, az ország védelmi rendszere megroppant. A velencei útjáról hazatérő Zrínyi mozgósította hadseregét, Kanizsát ostrom alá vette, de Bécs ezt megtiltotta. Erre Zrínyi a Mura partján Kanizsa ellenében végvárat épített: Zrínyi-Újvárat.\n\n• Zrínyi ezekben a zavaros időkben (trónharcok Erdélyben, a törökök elfoglalták Váradot, vallási viták az országgyűléseken, hideg telek és éhínségek) fogott hozzá - a török engedélye nélkül - a Mura bal partján Zrínyi-Újvár építéséhez.\n\nAz udvar hosszú ideig mellőzte, sem nádornak, 1663-ig pedig még fővezérnek sem nevezték ki. Ekkor azonban az udvar engedélyt adott a Zrínyi által kitervelt téli hadjáratra, amelynek során az újdonsült fővezér mélyen behatolt a hódoltsági területre.\n\n1661 őszén Köprülü Mehmed helyébe lépő fia, Köprülü Ahmed új hódítási tervekkel akarta feleleveníteni az oszmán terjeszkedő politikáját. Erre bátorították erdélyi sikerei és a magyarországi állapotok, az udvar és a főrendek, illetve a vármegyék ellentétei.\n\nA török kérdés túlnőtt a Habsburg Birodalom határain, kezdett kialakulni a törökellenes nemzetközi koalíció körvonala. Szervezője a Rajnai Szövetség, melynek vezetője János Fülöp mainzi választófejedelem, legfőbb tényezője pedig Franciaország. A koalícióhoz tartozott volna még Lengyelország, a pápai állam, Velence, Erdély, Moldva, Havasalföld. Lipót császár éppoly kevéssé maradhatott volna távol tőle, bár a Habsburg-dinasztiára nézve a koalíció veszélyeket is rejthetett volna.\n\nUgyanekkor, 1663-ban jelent meg Zrínyi híres röpirata, „Az török áfium ellen való orvosság”. Ebben fejtette ki legrészletesebben a magyar nemzeti hadsereg felállításának szükségességét. A röpirat aktuális politikai céllal készült. Állandó, jól szervezett hadsereget, nemesi adófizetést követelt. Mindkettő a korszerű abszolutista állam követelménye.\n\nKüprülü Ahmed nagyvezír 1663-ban nagy hadjáratra indult, célja Bécs volt, de egy 40 napos eső Budán tartotta.\n\n1663-ban körülzárta Érsekújvárt. Terve az volt, hogy egész Magyarországot a szultán hatalma alá vonja. Elfoglalta viszont a Forgách Ádám védte Érsekújvárt, de hadjáratát nem folytathatta, így nagyratörő politikai elgondolása is kudarcba fulladt. Időközben a magyar főrendek félretették egymás közötti ellentéteiket, elfogadták Zrínyi külpolitikai elképzeléseit, támadási haditervét, és hozzákezdtek a háború országos feltételeinek megteremtéséhez. Zrínyi közös cselekvésre szólította az ország legbefolyásosabb főurait. A kibontakozás alapfeltételének a közügyek iránti közöny leküzdését tekintette. Az ország vezetői, Wesselényi Ferenc nádor, Nádasdy Ferenc országbíró, Lippay György esztergomi érsek, Batthyány Ádám dunántúli főkapitány, továbbá a vármegyék vezetői csatlakoztak, de még Erdélybe is elértek a szervezkedés szálai. 1663-ban konföderációt kötöttek. Wesselényi nádor nemesi felkelést hirdetett.\n\nZrínyi tekintélye megnövekedett udvari körökben. I. Lipót is biztosította bizalmáról, és a magyar csapatok főparancsnokának nevezte ki. Montecuccolival közös haditervet dolgoztak ki, de a magyar és a császári haderőt nem tudták összehangolni, így Érsekújvár felmentéséről elkéstek. Közben Zrínyi a Dunántúl déli részén aratta sikereit. Tekintélye Magyarországon immár az uralkodóéval vetekedett.\n\n• A Rajnai Szövetség Zrínyi kezdeményezésére döntött úgy, hogy téli támadással kezdi meg a háborút, melynek előkészítő hadművelete a téli hadjárat és Kanizsa ostroma. Zrínyi Miklós eközben sikeresen harcolt a Muraközben, majd hozzákezdett az ún. téli hadjárathoz (1664. jan. 21-febr. 9.):\n\n• célja: elfoglalni Kanizsát; elfoglalta Babocsa várát és Pécset;\n\n• majd a török utánpótlást megakadályozandó felégette az eszéki Dráva-hidat. Zrínyi a lovassággal elérte és felgyújtotta az eszéki fahidat, a török birodalom egyik legfontosabb nyugati átkelőhelyét. Elvágták a török utánpótlási vonalát, és Kanizsa várát minden segítségtől elszigetelték. A szövetséges csapatok sikerrel verték vissza a nagyvezír támadásait. Zrínyi-Újvár négy hétig állta a törökök ostromát.\n\n• E sikerek után a német birodalomból érkezett seregekkel kiegészült haderő - parancs híján - csak késlekedve kezdte meg Kanizsa ostromát, így az Eszéknél új hidat építő törökök fel tudták menteni a várat.\n\nAz udvar a Habsburg-dinasztia ellen irányuló veszedelmes politikának látta a magyar mozgalom és a nemzetközi szövetség összefogását. A császár közvetlen környezete azon munkálkodott, hogy az események irányítását kézbe ragadja. I. Lipót 1664-ben felfüggesztette a nádor helytartói és Zrínyi főparancsnoki hatáskörét, és ragaszkodott Montecuccoli fővezérségéhez. Köprülü Kanizsáról kiindulva a Rába déli partján vonult Nyugatra, hogy Bécs irányában törjön előre. Sikerült magához ragadni a kezdeményezést, és a szövetségesek haderejével szemben kierőszakolta a döntő összecsapást Szentgotthárd alatt. A szövetségesek azonban hét órán át tartó csatában győzelmet arattak a török főseregen. Mindez a nemzetközi koalíció erőfölényét és nagy lehetőségeit bizonyította.\n\n• Zrínyi győzelmei nem voltak tartósak, mivel I. Lipót új fővezért nevezett ki, az olasz Montecuccolit, aki hagyta, hogy az ellentámadó török seregeknek sikerüljön elfoglalni a Zrínyi által építtetett Új-Zrínyivárat.\n\nTehát Zrínyit leváltották a dél-dunántúli erők éléről, és Montecuccoli tábornokot nevezték ki főparancsnoknak, azzal az utasítással, hogy Stájerországot és Bécset védje. Ezért Zrínyi-Újvárat feladták.\n\n• A törökök megindultak Bécs felé. Amikor Küprülü Ahmed 1664. aug. l-jén Szentgotthárdnál át akart kelni a Rábán, Montecuccoli csatát vállalt, és véres ütközetben győzött. A legyőzött törökök visszavonultak, de közben a kezükben lévő Zrínyi-Újvárat felrobbantották. 1664. augusztus 1-jén ugyan a szentgotthárdi csatában legyőzte Ahmed vezír seregét, de a győzelmet követő vasvári békében az udvar meghagyta a törökök területi szerzeményeit.\n\nMégis I. Lipót - a szövetségesek tudta nélkül - megalázó békét kötött 1664-ben Vasváron. Török kézen hagyta az előző évek foglalásait, ígéretet tett az erdélyi várakból a német katonaság kivonására. A felek kötelezték magukat, hogy a magyarokat nem segítik, sőt tájékoztatják egymást azok ellenséges terveiről. Bécs ezzel biztosítékot kapott, hogy a magyar rendek nem támadhatnak ellene török segítséggel.\n\n• A („szégyenteljes”, „siralmas”) vasvári béke (1664. aug. 10.):\n\n• a zsitvatoroki béke alapján 20 évre kötött béke;\n\n• elismerte, és a török kezén hagyta hódításait (Várad, Érsekújvár);\n\n• a Habsburgok és a törökök is kivonulnak Erdélyből;\n\n• Zrínyi- Újvárat lerombolják, nem szabad újjáépíteni;\n\n• a Habsburg uralkodó 200 ezer forint ajándékot küld a szultánnak;\n\n• a két fél kereskedelmi szerződést köt.\n\n• A vasvári béke igen nagy felháborodást keltett Európában és Magyarországon is:\n\n• a császár a békét a szövetségesek tudta nélkül kötötte meg;\n\n• olyan feltételekkel, mintha a törökök győztek volna.\n\nA Wesselényi-összeesküvés\n\nA gyors vasvári békekötés magyarázata: Bécs francia támadástól tartott. A béke csalódást, országos elégedetlenséget váltott ki, ami egy Habsburg-ellenes rendi szervezkedést indított el Wesselényi nádor vezetésével.\n\n• Zrínyi Miklós a harcok befejeztével több európai országban is tárgyalásokat folytatott, hogy támogatókat szerezzen az országegyesítés programjához, de eredménye már nem volt ezeknek, mert 1664. nov. 18-án Zrínyi egy vadkanvadászaton halálosan megsebesült. (Londonban gyászversek füzérét adták ki: „Velence védőbástyája”, „A keresztény szabadság megmentője”, „Magyarország erős Marsa”, „Európa csillaga” címekkel.)\n\nZrínyi ugyan tiltakozott, de 1664. november 18-án a kursaneci erdőben egy vadászbalesetben kétes körülmények között életét vesztette.\n\nA vasvári béke után a rendek rájöttek, hogy a Habsburgokban nem bízhatnak meg: megkezdődött a Wesselényi-féle rendi szervezkedés (1666-71).\n\nTagjai: Wesselényi Ferenc, Nádasdy Ferenc, Zrínyi Péter, I. Rákóczi Ferenc, Frangepán Ferenc. Probléma: nincs megfelelő bázisuk.\n\nI.Lipót nyílt abszolutizmusa volt a válasz (a jogeljátszás elméletére hivatkozva megszüntették a nádori tisztséget, felállították helyette a Guberniumot, kemény ellenreformációs intézkedések).\n\nAz abszolutizmusra válasz: a Thököly-felkelés 1678-1685.\n\nA Thököly-felkelés 1678-1685.\n\nVálasz a Habsburg-abszolutizmusra.\n\nSzakaszai: 1672-78: I. szakasz, még Thököly nélkül; 1678-81: II. szakasz Thököly Imre vezetésével sikeres, elfoglalták a felvidéki bányavárosokat). Kurucok felkelése és harca a labancokkal (császári katonákkal). A Thököly-felkelés hatására I. Lipót 1681-ben Sopronba országgyűlést hívott össze, és enyhített az abszolutizmuson. Thököly azonban tovább folytatja harcát, 1682-ben elfoglalta Kassát és Füleket, létrehozta a Felső-magyarországi Fejedelemséget (1682-85: rövid ideig így az ország 4 részből állt).\n\nA török kiűzése (vázlat)\n\n1683: Kara Musztafa, IV. Mehmed nagyvezíre sikertelenül ostromolta Bécset.\n\n1684: XI. Ince pápa szervezésében megalakult a török-ellenes Szent Liga (Liga Sacra) a Habsburgok, Lengyelország, Velence részvételével. A Szent Liga seregei Lotharingiai Károly, II. Miksa Emánuel bajor választó és Sobieski János lengyel király vezetésével 1686 szeptemberében visszafoglalták Budát, amelyet Ali Abdurrahman pasa védett.\n\nAz ország felszabadítása:\n\n• 1686-90\n\n- 1687: a nagyharsányi (második mohácsi) győztes csata a török ellen;\n\n- 1688: Bádeni Lajos elfoglalta Belgrádot.\n\n• 1690-99\n\n- 1690: a törökök visszafoglalták Belgrádot, Lippát, Kanizsát;\n\n- 1697: a zentai csatában Savoyai Jenő legyőzte a Tiszán átkelő törököket.\n\n- Békekötés: 1699 - karlócai béke a törökkel.\n\n• Habsburg - török béke (II. Musztafa és I. Lipót kötötte 25 évre):\n\nA Temes-vidék kivételével az összes magyarországi terület és Horvátország a Habsburgok fennhatósága alá került.\n\n• Orosz-, lengyel-, velencei - török békék: a törökök területeket veszítettek.\n\n1718. pozsareváci béke – a Temes-vidék is a Habsburgok kezére került.\n\nA török kiűzése (kifejtés)\n\nAz oszmán seregek egyik legfontosabb prioritása Európában Bécs városának, így az egyik legjelentősebb európai uralkodóháznak térdre kényszerítése volt. A feladattal többször is próbálkoztak sikertelenül (1529-ben és 1532-ben). A IV. Mehmed által nagyvezírré kinevezett Kara Musztafa újabb kísérletet tett 1683 márciusában, I. Lipót (1657-1705) azonban széles koalíciót szervezett a város védelmére (többek között III. Sobieski János lengyel király, II. Miksa Emánuel bajor és III. János György szász választófejedelmek bevonásával). A város védelméről Starhemberg gróf gondoskodott, de a nagy erejű török támadást (amely Bécs felé menet számos magyar várat - így Veszprémet, Pápát, Tatát - elfoglalt) csak szeptember közepére sikerült teljesen visszaverni. A csatában főszerepet játszó Lotharingiai Károly menetben visszafoglalta Párkányt és Esztergomot, így a török kiűzése kézzelfogható közelségbe került. Ezt ismerte fel XI. Ince pápa is, aki óriási anyagi támogatással 1684-ben létrehozta a Szent Ligát Habsburg, lengyel, velencei, pápai és 1686-tól orosz részvétellel. A francia XIV Lajost pedig húszéves békére kényszerítette a célból, hogy a szövetség csak a keleti frontra koncentrálhasson. Bár 1684 májusában még sikertelen volt Buda visszafoglalási kísérlete, az 1686. június 18-án kezdődő ostrom során szeptember elejére sikerült visszaszerezni a várat Abdurrahman budai pasától. A csatában a kor jellemző várostromtechnikáit (így robbanóanyagokat, sáncrendszert) alkalmazták. A siker után folytatódott az előrenyomulás a hódoltsági területeken: Lotharingiai Károly vezetésével a Duna mentén haladva foglalták vissza a várakat, majd a nagyharsányi győzelem (1687. augusztus 12.) után ő maga Erdély felé vette az irányt, amelyet a balázsfalvi szerződéssel behódoltatott. A fő-vezéri poszton Miksa Emánuel váltotta fel.\n\nA visszalépés évei\n\nBelgrád, Havasalföld és Albánia bevétele után 1690-ben fordulat következett be a császári stratégiában. Egyrészt ezeket a területeket egyre nehezebb volt ellenőrzés alá vonni, másrészt XIV Lajos féltékenyen szemlélte a Habsburgok közép-európai sikereit, így - a békeszerződést megszegve - arra kényszerítette I. Lipótot, hogy legkiválóbb hadvezéreit és csapatainak egy részét a rajnai frontra vezényelje át. A frissen kinevezett Köprülü Musztafa nagyvezír ezt kihasználva a balkáni területeket Belgráddal együtt gyorsan visszafoglalta. Közel tíz évig egyik fél sem tudott jelentős előrelépést elérni - ez alól csak az 1691-es császári győzelmet jelentő véres szalánkeméni csata volt kivétel. 1697-ben Savoyai Jenő herceg, a tehetséges francia hadvezér lett a főparancsnok, aki a hegyaljai felkelés leverése után Zentánál óriási győzelmet aratott a török felett, ami egyúttal a harci cselekmények lezárását és a béketárgyalások kezdetét is jelentette.\n\n1699 januárjában Karlócán kötötték meg a békét William Paget konstantinápolyi angol követ közvetítésével, amely a fennálló viszonyok (status quo) alapján rendezte az osztrák és oszmán fél helyzetét: a Temesköz kivételével a magyar és horvát területek Habsburg fennhatóság alá kerültek, ezen felül Velence, Oroszország és Lengyelország is gazdagodtak területekkel. Magyarország számára azonban a politikai következmények ennél sokkal súlyosabbnak bizonyultak.\n\nA török kiűzésének közjogi és politikai következményei\n\nA Wesselényi-féle összeesküvés után az I. Lipót által bevezetett abszolutisztikus intézkedések már bebizonyították, hogy a Habsburgok minél jobban igyekeznek az irányításuk alá vonni a rendeket és rajtuk keresztül az országot. Bár az 1681-ben összehívott soproni országgyűlés beismerően eltörölte a lipóti korlátozásokat, a töröktől való megszabadítás ismét okot szolgáltatott arra, hogy növekedjék a Habsburgok befolyása. A magyar rendek által vallott önrendelkezés igényének illúzióját hamar eloszlatta az a bécsi tétel, miszerint Magyarországot fegyverrel meghódított területként kezelték, s ennek megfelelő szerepet szántak az országnak a birodalomban.\n\nA béke után az ország területi széttagoltsága megmaradt, és létrehozták az udvari irányítás alá eső, széles körű autonómiával rendelkező szerbek lakta Határőrvidéket is. Erdély különállását az I. Lipót által 1691. december 4-én kiadott Diploma Leopoldium rögzítette, így nem egyesült Magyarországgal. Az erdélyi vallási tagozódást, adomány- és hivatalrendszert érintetlenül hagyta. Ugyanakkor Erdély seregeit német tábornok vezette, igazgatását pedig egy Bécs alá tartozó gubernátor (Bánffy György, 1661-1708) végezte.\n\nAmi a magyar területeket illeti: az adóterhek és különböző illetmények száma és mértéke ismét növekedett. Bevezetésre került a porció (a katonaság elszállásoltatása) és a forspont (fuvaroztatás). Azoknak, akik vissza kívánták kapni birtokaikat, a hivatalos okiratok bemutatása mellett a földbirtok értékének 10%-át fegyverváltság címén be kellett fizetniük az Újszerzeményi Bizottságnak, azaz a Neoacquistica Commissio. A katolikusok ezen intézkedések alól mentességet kaptak. Az uniformizálás jegyében betiltották a protestánsok számára 1681-ben rögzített, korlátozott vallásszabadságot, a magyar várrendszert pedig módszeresen leépítették, és a katonai állományt császári katonákkal töltötték fel.\n\nÉrtékelés\n\nA török mintegy másfél évszázados uralmának ugyan vége lett, de ezt a Habsburgok még hosszabb ideig tartó irányítása váltotta fel. A politikai és katonai téren bevezetett abszolutisztikus intézkedések azonban sorozatos ellenállásokba ütköztek, és ezeknek a megmozdulásoknak a leverése a Habsburgok szemében csak igazolta politikájukat.\n\nA Rákóczi-szabadságharc\n\nA török kiűzése Magyarországról döntően idegen segítséggel történt. Ez a tény felerő-sítette Bécs abszolutisztikus törekvéseit, így az 1687. évi országgyűlésen I. Lipót elfogadtatta a szabad királyválasztásról és az ellenállási záradékról való lemondást. Állami adókkal terhelték a jobbágyságot, de kísérlet történt a nemesség megadóztatására is. Hírhedtté váltak Caraffa generális fosztogatásai és kivégzései a nemesség és polgárság körében („eperjesi mészárszék”). A vallásüldözéseket rendkívüli bizottság folytatta.\n\nA Neoacquistica Commissio a nemesség anyagi érdekeit sértette. Erdélyt különválasztva katonai igazgatás alá helyezték. A nemesség és jobbágyság sérelmei Habsburg-ellenes felkeléshez vezettek.\n\n1697-ben Tokaji Ferenc vezetésével felkelés.\n\nA Felső-Tisza vidékén bujdosó szegénylegények felkelését a császári katonaság elfojtotta. A nemesség között is megindult a szervezkedés. II. Rákóczi Ferenc, az ország egyik legnagyobb birtokosa XIV. Lajos támogatását kérte. Levelei a császáriak kezébe kerültek. Letartóztatták, a bécsújhelyi börtönbe zárták. Innen megszökött Lengyelországba, csatlakozva barátjához, Bercsényi Miklóshoz. Brezán várában kereste fel Esze Tamás, kérve, hogy álljon az elkeseredett parasztság élére. Rákóczi vállalta a vezetést, és a brezáni kiáltványban harcba szólította a Habsburgok ellen az ország minden lakosát, nemeseket és címnélkülieket egyaránt. A szabadságharc kiinduló területe Északkelet–Magyarország. Bár Károlyi Sándor 1703-ban Dolhánál szétverte a felkelő sereget, Rákóczi átlépve a magyar-lengyel határt, a felkelés élére állt. Az átadott zászló Cum Deo pro patria et libertate (Istennel a hazáért és a szabadságért) felirattal mozgósító érövei hatott.\n\nA felkelés kedvező nemzetközi helyzetben indult. A spanyol örökösödési háborúban francia sikerek születtek; úgy látszott, hogy XIV. Lajos nemcsak pénzzel segíti majd Rákóczit, hanem a két sereg összehangolt támadására is lesz lehetőség. A kuruc sereg létszáma rohamosan nőtt, főleg a jobbágyok csatlakozása nyomán.\n\nAz 1703-ban kiadott vetési pátensnek nagy szerepe volt a parasztság tömeges csatlakozásában. Ugyanakkor Rákóczi a nemesség megnyugtatására eltiltotta a katonaságot a kastélyok megtámadásától. A pátens a hadba vonuló jobbágyokat és családtagjaikat mentesítette nemcsak a közterhek, hanem a földesúri szolgáltatás alól is.\n\nRákóczi elutasította a jobbágyok felszabadítását, és emiatt a jobbágyság egy része elfordult a szabadságharctól. A jobbágykérdés a szabadságharc folyamán visszatérő probléma maradt. A szabadságharc alapvetően rendi mozgalom maradt.\n\nA kuruc hadak sikereket értek el a Felvidéken, a Duna-Tisza közén, a Maros vidékén, ám a szerb határőrök szembefordultak a felkeléssel.\n\n1704-ben változás állt be a nyugati fronton. Rákóczi szövetségesei, a franciák a höchstadti csatában vereséget szenvedtek a szövetségbe tömörült angol-holland, valamint császári csapatoktól, melyeket Marlborough herceg és Savoyai Jenő vezetett. A császári sereg győzelme hatással volt a szabadságharc további menetére is. Katonai sikerek és kudarcok váltogatták egymást 1704-1705-ben. Rákóczi csapatai vereséget szenvedtek Heister császári tábornagytól a Dunántúlon, Rabutintól pedig Erdélyben. Ugyanakkor 1705 végére Bottyán János csaknem az egész országot megtisztította a császáriaktól. A sikerek hatására a kuruc sereg létszáma megnőtt. Rákóczi a maga seregének magvát a társadalom kiváltságokkal nem rendelkező rétegeiből építette ki: a végvárrendszer felszámolt hivatásos magyar katonáiból, örökös jobbágyokból, megélhetésüket vesztett vállalkozó parasztokból (mint amilyen pl. a só-kereskedésből élő Esze Tamás volt). Rákóczi fokozatosan akarta megerősíteni állandó haderejének gerincét. A hadsereget nem tudták korszerű fegyverekkel egyenletesen ellátni. A fegyvernemek között a lovasság fölénye érvényesült. A korszerű hadviselés ellenben erős gyalogságot és jó tüzérséget kívánt volna. A tüzérséget és műszaki alakulatokat francia tisztek és hadmérnökök segítségével szervezték meg. A zsold fedezése érdekében Rákóczi kénytelen volt adókat kivetni, majd a pénzrontás eszközéhez folyamodni.\n\n1705-ben a szécsényi országgyűlés Rákóczit vezérlő fejedelemmé választotta. Az új államformát rendi konföderációban jelölte meg. A hadügyi, külügyi és pénzügyi kérdésekben a fejedelem döntött. A fejedelem mellett 28 tagú szenátus működött. Hatásköre csak belpolitikai kérdésekre terjedt ki. A fejedelmi kancelláriát Ráday Pál vezette. A Gazdasági Tanács legfőbb feladata a hadsereg fegyverrel, felszereléssel és élelemmel való ellátása. Fegyvergyártó manufaktúrákat alapított, az élelmezés megkönnyítésére tárházakat állított föl.\n\nA szabadságharc összeomlásának legfontosabb okai közé az tartozik, hogy a császáriak katonailag fölényben voltak. Rákóczi a vereségek egyik okát tisztjei felkészületlenségében látta. A rajtaütéses harcmodor csak akkor lehetett hatékony, ha a lakosság is támogatta.\n\nI. József a felkelés felszámolása helyett kereste a megegyezés útját. A tárgyalást szorgalmazta annak ellenére, hogy 1707-ben az ónodi országgyűlés kimondta a Habsburg-ház trónfosztását. Az ónodi országgyűlésen a nemesi adózás, a közteherviselés elrendelésével próbálták biztosítani a szabadságharc pénzügyi hátterét. Ez az egyik rendi kiváltság sérelmét jelentette, elidegenítette a nemesség egy részét. Az országgyűlésen erőszakot alkalmaztak. Problémát jelentett az is, hogy a szabadságharc állandó pénzügyi gondokkal küzdött, a kibocsátott rézpénz inflálódott.\n\nA Habsburgok részt vettek a spanyol örökösödési háborúban, így fő ellenfelük Franciaország volt. A Rákóczi-szabadságharc kimenetele a francia sikerektől függött. Franciaország meggyöngülése arra késztette Rákóczit, hogy másutt keressen támogatást. Követei tárgyalásokat folytattak a porosz, a dán udvarban, a svéd, a lengyel királynál, de eredménytelenül. XIV. Lajos - miután békét kötött a Habsburgokkal - még az anyagi támogatást is megvonta. Nem véletlen, hogy a francia vereségek után a Rákóczi-szabadságharc katonailag elbukott.\n\nMegnőtt viszont az orosz kapcsolatok jelentősége. Varsóban a fejedelem szerződést kötött 1707-ben I. Péter cárral. A svédek újabb támadása Péter ellen azonban néhány hónap alatt tárgytalanná tette a szerződést; csupán diplomáciai támogatást kapott Rákóczi a cártól. Rákóczi oroszbarát jelölt volt a lengyel trónra. Rákóczi orosz támogatást akart szerezni a Habsburgok ellen, de Oroszország nem tudott tényleges segítséget nyújtani.\n\n1707-ben Erdély és a Dunántúl egyidejűleg kuruc fennhatóság alá került. 1708-ban Heister császári tábornagy megalázó vereséget mért a Rákóczi vezette hadakra. Ezután a kuruc sereg felére csökkent, a katonák vagy szétszéledtek, vagy - több főtiszt ezredével együtt - átpártoltak a császáriakhoz. 1708-ban Béri Balogh Ádám győzelmet aratott a császáriak fölött Kölesdnél, de 1709-re Heisterrel szemben kiüríteni kényszerült a Dunántúlt. Az 1710. évi romhányi csata után kibontakozó offenzíva, melynek célja a Dunántúl visszaszerzése volt, gyorsan összeomlott. A kurucok ellenőrzése alatt álló terület Felső-Magyarországra zsugorodott össze.\n\nA kuruc hadsereg gerincét a vitézlő rend adta, főleg könnyűlovasokból állt, létszáma nagyon hullámzó volt, szervezete, felszerelése elmaradt a nyugati seregekhez képest. Nem volt alkalmas nyílt csaták megnyerésére, várak megostromlására, alulmaradt a kisebb létszámú császári seregekkel szemben, fenntartása így is megoldhatatlan pénzügyi nehézséget okozott.\n\nA külpolitikai elszigeteltséghez járult a belső helyzet erős romlása. Károlyi tárgyalásokat kezdett Pálffy János császári tábornaggyal, és a majtényi síkon letette a fegyvert 1711-ben. Az orosz szövetség ügyében volt távol Rákóczi a fegyverletételkor. 1711-ben a szatmári gyűlésen a rendek elfogadták a békeokmányt. A béke amnesztiát ígért, ami mindenkire kiterjed, amennyiben visszatér. A földesurak visszakapják elkobzott birtokaikat. Érvényben maradnak a parasztkatonák Rákóczitól kapott kiváltságai. Az uralkodó tiszteletben tartja az alkotmányt, biztosítja a protestánsok vallásszabadságát. Az adott külpolitikai viszonyok között ennél többet még győzelem esetén sem remélhettek volna Rákóczi hívei. Az elért kompromisszum lehetővé tette, hogy helyreálljon a rend, és a korábbinál kedvezőbb feltételek közt indulhasson el az ország a felemelkedés útján.\n\nAz 1711-es szatmári békében ígéretet tett az uralkodó az országgyűlés összehívására, a rendi kormányzás és a protestáns vallásgyakorlás szabadságának helyreállítása, az Újszerzeményi Bizottság megszüntetése. Ezzel helyreállt a rendi dualizmus, biztosította a birodalmon belüli rendi önállóságot, és ezzel a szabadságharcot kiváltó sérelmeket részben orvosolták. Meg nem valósult követelések: szabad királyválasztás, ellenállási záradék helyreállítása. A Habsburgok a birodalmi egységet mindenáron fenn akarták tartani, az erőviszonyok a dinasztia javára tolódtak el.\n\nA XVIII. század elején két jelentős változás erősítette a Habsburgok helyzetét. Nyugaton megtört Franciaország hegemóniája, s ezzel meggyengült Ausztria legfőbb riválisa, miközben Anglia vette át a vezető szerepet. Keleten Bécs a török kiűzése után egy nagyobb birodalom központja lett. A Rákóczi-szabadságharc kompromisszummal zárult, ami javított Magyarország helyzetén, és biztosította a magyar állam létét.\n\nHabsburg berendezkedés a Rákóczi-szabadságharc után:\n\nA XVIII. század az ország fokozatos felemelkedésének, belső erőgyűjtésének időszaka volt. A rendi szabadságharcot a rendi kompromisszum követte, melyhez III. Károly (1711-1740) is hozzájárult. Apja, I. Lipót abszolutizmusával szemben hangoztatta, hogy a magyarokat „jósággal és elővigyázattal” kell kormányozni. Az 1712-1716-ig ülésező országgyűlésen megerősítette a szatmári békét és lefektette az új politikai berendezkedés alapjait.\n\nA kompromisszumot a bécsi udvar és a magyar rendek kötötték, amelyek a rendi önállósággal együtt feudális kiváltságaikat is átmentették. Míg az osztrák és cseh tartományokban Bécs abszolutisztikus kormányzást vezetett be, addig Magyarországon kétközpontú politikai rendszer alakulhatott ki, amelyben a központi hatalom az uralkodóé, a rendi hatalom pedig a kiváltságosoké volt.\n\nElőtérbe került a hadsereg kérdése, délen ugyanis a török még mindig jelentős erőt képviselt, nem mondott le elveszett hódításainak visszaszerzéséről. A XVIII. században innen érték támadások az országot. 1716-ban Savoyai Jenő visszafoglalta a Bánságot, 1718-ban a pozsareváci békében a Porta elvesztette a Temes-vidéket. A nemesi felkelés immár nem biztosította a kellő védelmet, szükség volt tehát az állandó hadsereg felállítására. Erről az 1715. évi 8. törvénycikkely intézkedett. A magyar haderő a bécsi haditanács irányítása alá került, vezényleti nyelve a német lett, tisztikara pedig amúgy is császári szellemű volt. A hadügy uralkodói hatáskörbe tartozott. A rendek joga volt az újoncozás megszavazása, a hadiadó, amely a jobbágyok terheit növelte. A déli terület határőrvidékként katonai igazgatás alá került. A Temes-vidék is külön közigazgatást kapott.\n\nAz újjászervezett közigazgatás fő szervei a kormányszékek, amelyek a központi hatalomtól függtek, s az országgyűlésnek nem tartoztak felelősséggel. A kancellárok a főnemesség soraiból kerültek ki. Az ország belső igazgatását a helytartótanács irányította. Pozsonyban, majd Budán működött. Feladatköre sokrétű volt (pl. megyék irányítása, hadiadó beszedése, rendeletek végrehajtásának ellenőrzése, vallási, tanügyi problémák; intézkedési joga azonban korlátozott volt). A Magyar Királyi Kamara a pénzügyekkel foglalkozott, gyakorlatilag teljesen alá volt rendelve az udvari kamarának.\n\nA Rákóczi-szabadságharc és nemzetközi összefüggései (kifejtős)\n\n1703-1711\n\nElőzmények:\n\nA török kiűzése Magyarországról\n\n1683-ban a török nagy erejű támadást indított Bécs ellen. I. Lipótnak sikerült megnyernie Lengyelország és Velence támogatását, s 1684-ben megalakult a török kiűzésére szerveződött Szent Liga. Ettől kezdve az 1699-es békéig háborús helyzet állt fönn Magyarországon, mely a lakosságnak óriási károkat okozott. Az elhúzódó harcok nyomán falvak, sőt, egész vidékek néptelenedtek el. A magyar lakosság helyzete azonban a karlócai béke (1699) után sem javult. Mivel a török kiűzése főként a császári seregek érdeme volt, a Habsburgok helyzete megerősödött, s ez felerősítette Bécs abszolutista törekvéseit. Ezzel felborult az egyensúly az uralkodó I. Lipót és a magyar rendek között.\n\nA rendek az 1687-es pozsonyi országgyűlésen kénytelenek voltak lemondani a szabad királyválasztásról és az 1222-es Aranybulla ellenállási záradékáról.\n\nEközben Antonio Caraffa tábornok - miután kiraboltatta az amúgy is sokat szenvedett Debrecen városát - Eperjesen Thököly-párti felkelés koholt vádjával 24 nemest és polgárt végeztetett ki. Az udvar az 1687-es országgyűlésen kárpótolta az „eperjesi mészárszék” áldozatainak hozzátartozóit, a nép helyzetén azonban nem javítottak.\n\nAz ország lakosságára óriási terhek nehezedtek. Az adókat a hadsereg ellátása és kiteleltetése miatt többszörösére emelték, s kísérletet tettek a nemesség megadóztatására is.\n\nAz udvar a töröktől visszaszerzett területeket új szerzeményeknek tekintette, s csak akkor szolgáltatta vissza egykori birtokosaiknak, ha azok törvényesen tudták igazolni arra való jogosultságukat, és emellé kifizették a kincstárnak a 10 %-os fegyverváltságot. Ezt a procedúrát a direkt erre a célra kialakított, az Udvari Kamara alá tartozó Újszerzeményi Bizottság (latinul Neoacquistica Commissio) bonyolította le. Mivel sok volt földbirtokos nem tudta törvényesen igazolni, hogy valóban jogosult az adott területre, és még ha tudta is bizonyítani, akkor sem mindig volt elég pénze a fegyverváltság megfizetésére, az udvar óriási földterületekhez jutott, melyeket hadvezéreik, hitelezőik és a hadsereg szállítói között osztott szét.\n\nAz uralkodó elbocsátotta a feleslegessé váló magyar várrendszer katonáit, majd 1702-től kezdve elrendelte a várak megsemmisítését, mert félt, hogy azok a magyar ellenállás fészkeivé válhatnak.\n\nA szabadságharc közvetlen előzményei:\n\nI. Lipót politikája és a háború okozta szenvedés a magyar társadalom jelentős részét szembeállította a dinasztiával.\n\n1697-ben lázadás tört ki Tokaj-Hegyalján, a bujdosó szegénylegények felkelését azonban a császári haderő leverte. A rendi sérelmek miatt a nemesség is mozgolódni kezdett. A szervezkedést a felvidéki főnemes, Bercsényi Miklós indította meg, s megnyerte az ügynek II. Rákóczi Ferencet, az erdélyi fejedelmek örökösét, aki akkor az ország legnagyobb birtokosa volt. Rákóczi XIV. Lajos francia uralkodó támogatását kérte. Levelei azonban a császáriak kezébe jutottak, őt elfogták, s a bécsújhelyi börtönbe zárták. Innen megszökött, s Lengyelországba menekült.\n\nAz 1700-ban - a Habsburgok spanyol ágának kihalása miatt - kitört spanyol örökösödési háború szembeállította a franciákat a Habsburgokkal. A harcok Spanyolország, Spanyol-Németalföld, a Német-Római Birodalom és Észak-Itália területein folytak. Mivel emiatt a Habsburgok nem tudták erőiket a magyarországi problémákra koncentrálni, ez jó lehetőséget teremtett egy szabadságharc kibontakozásához. Másfelől XIV. Lajos (a Napkirály) kész volt támogatni minden Habsburg-ellenes mozgalmat, így a magyar törekvéseket is.\n\nA szabadságharc kitörése: 1703.\n\nRákóczit másodszor lengyelországi menedékhelyén, Brezánban keresték fel a felső-Tisza-vidéki lázadó nép követei, élükön Esze Tamással, s kérték, hogy álljon az elkeseredett nép élére. Rákóczi vállalta a vezetést. 1703-ban a brezáni kiáltványban szólította harcba a Habsburgok ellen az ország népét, nemeseket és címnélkülieket egyaránt, mert tudta, hogy csak úgy érhetnek el sikereket, ha mind a nemesség, mind a parasztság támogatja a mozgalmat, s nem egymás ellen, hanem egymás mellett harcolnak.\n\n1703 augusztusában kiadta a vetési pátenst, melyben a hadba lépő jobbágyok és közvetlen családtagjaik számára az állami és földesúri szolgáltatások alól mentességet ígért. Egyúttal azonban a gyalui pátensben megtiltotta a harcra készülő parasztságnak, hogy a nemesség, vagy kastélyaik ellen forduljon. Ezzel a két rendelkezésével rengeteg parasztot sikerült megnyernie, s a nemesség zömét is maga mellé tudta állítania.\n\nA felduzzadt létszámú kuruc csapatok gyorsan elfoglalták a Felvidéket, a Tiszántúlt és a Duna-Tisza közét. A Dunántúl és Erdély felváltva volt császári (gúnynevükön labanc) és kuruc kézen.\n\nA kuruc hadsereg nagyrészt lovasságból állt, kevés volt a gyalogos és a tüzérség nem volt elég jól felszerelt, ami pedig a korszerű hadviselés alapfeltétele volt akkor. A hadsereget jórészt nem képzett tisztek irányították, hanem a mozgalom mellé állt nemesek - mint Károlyi Sándor gróf, Szatmár vármegye főispánja, Bercsényi Miklós gróf, felvidéki nagybirtokos, illetve Béri Balogh Ádám középbirtokos nemes - vagy a kiemelkedő címnélküliek, azaz nem nemesek, mint az eredetileg sókereskedéssel foglalkozó Esze Tamás. A rendezett, fegyelmezett, összehangolt manőverekben ezért a császáriak voltak fölényben, s így a kuruc sereg a nagy csatákban általában alulmaradt. A bravúros portyákkal azonban szép sikereket értek el, bár a rajtaütéses harcmodor csak akkor volt hatékony, ha a lakosság is támogatta.\n\nKülpolitikai háttér: a szabadságharc sorsa alapvetően mégsem a magyarországi hadszíntéren dőlt el. A spanyol örökösödési háború alakulásának döntő szerepe volt benne. A franciák 1704-es höchstadti veresége fordulópontot jelentett mind az örökösödési háború, mind a magyar szabadságharc szempontjából. A XIV. Lajos évtizedes háborúi következtében kimerült Franciaország nem bírta tovább a terheket. A magyar ügy egyetlen nemzetközi támogatójának összeomlásakor már érezhető volt, hogy a magyarok helyzete egyre romlik. Egyfelől a francia támogatás csökkenése, majd eltűnése miatt, másfelől azért, mert a császár ismét magyar területekre összpontosíthatta hadseregét (főleg miután az egyesült angol-osztrák seregek 1709-ben győzelmet arattak, és a francia sereget Párizsig szorították vissza). Ezután a szabadságharc reális célja már csak a rendi jogok biztosítása lehetett.\n\nA szabadságharc belpolitikája: Rákóczit 1704-ben az erdélyi rendek fejedelmükké választották. Az 1705-ös szécsényi országgyűlésen a magyarországi rendek (nemesek, jászok, kunok, hajdúk és a vitézlő rend) szövetséget kötöttek és megválasztották Rákóczit vezérlő fejedelmükké. Az új államformát rendi konföderációnak nevezték. A hadügyi, külügyi és pénzügyi kérdésekben a fejedelem döntött. A fejedelem mellé 24 tagú szenátust rendeltek, melynek hatásköre csak belpolitikai kérdésekre terjedt ki. Tagjait a fejedelem nevezte ki.\n\nAz iratok kiadását és a külügyek irányítását a kancellária végezte, az igen művelt költő s egyben politikai író, Ráday Pál vezetésével. A gazdasági ügyek intézésére Besztercebányán létrehozták a Gazdasági Tanácsot, melynek fő feladata a hadsereg ellátása volt. A költségek fedezésére a fejedelem pénzt veretett. A rézből készült, libertásnak nevezett pénz azonban - melyet a szabadságharc jelszava, a „Cum Deo pro patria et libertate” (Istennel a hazáért és a szabadságért) felirat díszített - hamar elértéktelenedett.\n\nA fegyverhiányt állami manufaktúrák létrehozásával próbálták csökkenteni, azonban az „igényesebb” fegyvereket importálniuk kellett. A pénzügyi alapot egyre nehezebb volt előteremteni a hadsereg ellátásához és a katonák zsoldjához, s a XVI. Lajos által folyósított havi 10 000 tallér elenyészően kis összegnek bizonyult.\n\nRákóczi a végsőkig kitartóknak hajdúszabadságot - földet, adómentességet és kollektív nemességet - ígért. Ez is nagyban hozzájárult ahhoz, hogy a kuruc sereg létszáma megközelítette a 70 000 főt. A vallási megosztottság problémáját úgy orvosolták, hogy engedélyezték mindhárom nagy felekezet, a katolikus, az evangélikus, és a református szabad működését.\n\nA katonai helyzet 1706-1707-ben jellemzően nem változott, az 1707-es ónodi országgyűlésre mégis sűrűsödő gondok közepette került sor. Ezúttal azonban a probléma a kuruc hadseregen belül jelentkezett. A parasztság elkedvetlenedett az elhúzódó háború miatt - amíg harcolt, nem tudta művelni a földjét, ami nagy károkat okozott számára akkor is, ha a hadseregtől szolgálataiért kapott fizetést. Az ónodi országgyűlés által megszavazott adók, melyeket a közteherviselés alapján a nemesekre is kivetettek, ezt a réteget is szembefordították a fejedelemmel, hiszen ez a nemesség ősi szabadságjogát sértette - miszerint a magyar nemes a vérével adózik.\n\nA rendek az I. Lipót halála után 1705-ben trónra került I. Józsefet - szintén az ónodi országgyűlésen, 1707-ben - megfosztották trónjától, azaz a Habsburg-házat detronizálták (a Habsburg-ház trónfosztása). Ennek célja az volt, hogy a kuruc államot nemzetközileg is elfogadtassák, s egyúttal lehetetlenné tegyék a dinasztiával történő megegyezést. Az európai hatalmi egyensúly miatt azonban fontos volt a Habsburg Birodalom egysége, ezért a nagyhatalmak nem támogatták Magyarország önállósodási törekvéseit.\n\n1708-ban Trencsénnél a kuruc főerők vereséget szenvedtek a labanc hadseregtől. A császáriak könnyedén szétverték a magyarok seregét, mely még csatarendbe sem sorakozott, amikor a labancok megtámadták. A csatában a fejedelem lebukott lováról és megsérült, s bár túlélte az ütközetet, a csata alatt elterjedt halálának híre, ami az amúgy is vesztésre álló sereget végképp félelemmel töltötte el. Ez a csata egyértelműen fordulópont volt a szabadságharc történetében. A vereség után sokan nem tértek vissza a seregbe, s ezután a kuruc sereg létszáma egyre gyorsabban fogyott. Megszaporodtak az árulások és az átállások, például áruló lett Bezerédi Imre, vagy az egész ezredével átálló Ocskay László brigadéros is, s bár mindkettőjüket kivégezték, a helyzeten ezzel már nem segíthettek. A csapatokat tovább apasztotta az egyre terjedő pestisjárvány is.\n\nA fejedelem az 1708-as sárospataki országgyűlésen még tett egy kísérletet a hadsereg újraszervezésére, s a jobbágyságnak újra hajdúszabadságot ígért a szolgálat fejében - a nép azonban már nem bízott a győzelemben.\n\nA Béri Balogh Ádám vezette seregek még diadalt arattak Kölesdnél, de ezzel nem tudták ellensúlyozni a trencséni vereséget. Az utolsó jelentős kuruc győzelem 1710 januárjában, Romhánynál született. Érsekújvárt már nem sikerült felmenteni, s őszre a szabadságharc az északkelet-magyarországi területekre szorult vissza.\n\nAz 1709-es malplaquet-i francia vereség után XIV. Lajos nyíltan tudatta Rákóczival, hogy békét köt a Habsburgokkal, s beszünteti a magyar mozgalom támogatását. Ezzel a francia segély végleg elapadt. Rákóczi próbálkozott megnyerni más országokat a magyar ügy mellett. Követei tárgyaltak porosz, dán, svéd és lengyel vezetőkkel, de hiába. Az orosz kapcsolatok jelentősége azonban megnőtt, s a fejedelem még 1707-ben, Varsóban szerződést kötött I. Péter cárral. Az oroszoknak viszont nem állt érdekükben új frontot nyitni a Habsburg birodalommal szemben, s a svédek újabb támadása Oroszország ellen végképp tárgytalanná tette a szerződést (északi háború: 1700-1721 a Balti-tenger térségének uralmáért folyt.)\n\nA külpolitikai elszigeteltség és a súlyos belpolitikai problémák az eseményeket a megegyezés felé sodorták. Az örökösödési háború tapasztalatai alapján I. József is hajlott a kompromisszumos megoldásra a magyarokkal kapcsolatban. 1710-ben Savoyai Jenő, Habsburg hadvezér egy magyar labanc főurat, Pálffy Jánost nevezte ki a magyarországi császári erők élére, aki tárgyalásokat kezdeményezett.\n\nAmikor a fejedelem 1711-ben Lengyelországba utazott, hogy a cárral tárgyaljon, távollétében felhatalmazta főparancsnokát, Károlyi Sándort, hogy időhúzó tárgyalásokat folytasson. Károlyi gróf jó politikai érzékkel, ügyesen manőverezett. Eleinte csak saját személyére és vagyonára vonatkozó ajánlatot kapott Pálffytól, azonban többszöri levélváltás és személyes találkozás után kibontakozott a szélesebb körű megegyezés lehetősége.\n\nEközben Károlyinak vissza kellett tartania a tisztikart az egyéni megadástól, hogy előnyös feltételeket harcolhasson ki, és szembekerült Rákóczival és a vitézlő renddel is, akik - külső, elsősorban orosz segítségben bízva - mindenképpen folytatni akarták a küzdelmet.\n\nKárolyi Szatmárban gyűlést hívott össze, ahol a béke mellett döntöttek. 1711. május elsején ünnepélyes keretek közt a majtényi síkon a maradék kuruc sereg letette a fegyvert.\n\nA szatmári béke 1711-ben a résztvevők számára amnesztiát biztosított. Az uralkodó ígéretet tett az alkotmány visszaállítására, a szabad vallásgyakorlásra, az országgyűlés összehívására, és a vitás kérdések országgyűlési megvitatására. A rendeket sértő idegen intézményeket és méltóságokat megszüntették, s a megegyezés értelmében érvényben maradtak a parasztkatonák Rákóczitól kapott kiváltságai.\n\nA béke nem állította vissza a szabad királyválasztást, az ellenállás jogát és nem hozott létre magyar hadsereget, azaz a magyar rendi alkotmánynak azon részei maradtak ki, melyek sértették a birodalom egységét, azonban nem álltak szemben a rendi gondolkodással, mivel javarészt királyi felségjog alá estek.\n\nAz adott külpolitikai viszonyok között ennél többet még győzelem esetén sem remélhettek volna a magyar rendek. A kuruc mozgalom biztosította, hogy Magyarország elkerülje a csehek Fehér-hegy utáni sorsát, azaz megkímélték az országot, a magyar rendi jogok megmaradtak bizonyos formában, nem volt erőszakos germanizáció és véres megtorlás a szabadságharc után, mint amiket a cseheknek korábban, az 1620-as csatavesztés után el kellett szenvedniük. Magyarországon fennmaradt a rendi dualizmus.\n\nII. Rákóczi Ferenc, több hívével, köztük Bercsényivel és Esterházyval, nem tért haza, nem kért a kegyelemből. Az újrakezdés lehetőségét keresve Franciaországba utazott, ám a franciák változtattak a Habsburg Birodalomhoz fűződő viszonyukon, s nem kívánták támogatni Rákóczit. Az újra fellángoló török harcok idején az emigráció nagy része a fejedelmet követve Törökországba utazott. Megérkezésük idejére (1717) azonban az oszmánok már békét kötöttek. A Porta Rodostóban jelölt ki lakhelyet a magyar emigránsok számára.\n\nA bujdosók emigrációban töltött éveit Mikes Kelemen elképzelt nénjéhez írt leveleiből ismerhetjük meg: Törökországi levelek. A székely nemesi családból származó Mikes 1707-ben került Rákóczi udvarába, s ura hűséges kísérőjeként követte őt a száműzetésbe is, ahol 1735-ben halt meg a fejedelem.\n\nA szabadságharc értékelése:\n\nA Habsburg-magyar viszony romlásában, illetve a szabadságharc kibontakozásában meghatározó szerepet játszott I. Lipót politikája. Rákóczi Ferenc a Habsburg-ellenes felkelés élére állt, ennek jogosságát elsősorban a rendi sérelmekre alapozta.\n\nRákóczi képes volt a helyi felkelést nemzeti szabadságharccá változtatni (nemesség csatlakozása), így a spanyol örökösödési háborút kihasználva az ország nagy részét hatalmába kerítette. A szabadságharc kibontakozásának kedvezett a nemzetközi helyzet (pl. spanyol örökösödési háború, északi háború).\n\nMagyarország (a török kiűzése után) nem volt képes hosszú háborút vívni. A kuruc hadsereg nem volt valódi ellenfele a császáriaknak. Okai: fegyelmezetlenség, fegyvernemek aránytalansága, szervezetlenség, technikai-anyagi hátrányok.\n\nA katonáskodó jobbágyoknak hajdúszabadságot ígértek, és ezzel Rákóczi a szabadságharc katonai bázisát kívánta kiszélesíteni. A parasztság azonban csalódott, a nemesség pedig a királlyal kötendő kompromisszumra hajlott. Rákóczi ezt sikertelenül próbálta megakadályozni.\n\nA szabadságharcot valójában az európai erőviszonyok döntötték el, a francia vereség után a fegyverletétel maradt az egyetlen lehetőség. Rákóczi a szabadságharc sikerét a nemzetközi katonai helyzettől remélte, de ez már az 1704-es höchstadti csatavesztéssel irreálissá vált. A császári hadak létszáma folyamatosan nőtt, míg a kurucoké a kezdeti sikerek után csökkent. A vereség a nemzetközi erőviszonyok függvénye is volt.\n\nA kuruc seregek katonai helyzetéhez és minőségéhez képest a császári seregek mind kiképzésben, mind létszámban fölényben voltak. A kuruc hadsereg viszonyai (létszám, fegyverzet és kiképzés hiánya) nem tették lehetővé a nyílt ütközetek megnyerését, és a katonai vereségek hozzájárultak a kuruc hadsereg széteséséhez.\n\nAz ónodi országgyűlésen kimondták a Habsburgok trónfosztását. A Habsburg-magyar viszony a trónfosztás idején jutott mélypontra, ennek ellenére a szatmári béke méltányos volt, nem járt a magyarokra nézve súlyos következményekkel. A kényszerű békekötéshez több tényező járult hozzá (pl. az európai pénzügyi, katonai és diplomáciai támogatás hiánya, a francia seregek kudarcai).\n\nA béke kompromisszumos jellegét, illetve a viszony javulását segítette Lipót utódainak rugalmassága és a Habsburgok külpolitikai helyzete. A szabadságharc folyamán változott Rákóczi nézőpontja is: Rákóczi 1704-ben még hajlott a békekötésre, de a szabadságharcot lezáró kompromisszumot már nem tudta elfogadni.\n\nAz 1711-es szatmári béke kompromisszumos béke volt.\n\nMária Terézia, II. József uralkodása\n\nA XVIII. században Magyarország a Habsburg Birodalom része, mely a felvilágosult abszolutizmus kora volt. A felvilágosult abszolutizmus szellemében uralkodók az abszolutista hatalomgyakorlási módszereket a felvilágosodás eszméivel ötvözik.\n\nEgyrészt tehát jellemzi őket a rendi országgyűlés mellőzése, a rendeleti kormányzás és a bürokráciára, a jól fölépített hivatalnoki apparátusra való támaszkodás;\n\nmásrészt uralkodói szerepfölfogásuk különbözik elődeikétől: már nem „Isten kegyelméből”, hanem a népért, a nép szolgálatában uralkodnak.\n\nA felvilágosult abszolutizmus jellemzője a modernizálási szándék (különösen az oktatás, az egészségügy és a középkori szokások elleni küzdelem területén). Lebontották a belső vámokat, pártolták az iparfejlődést, védték a jobbágyokat a túlzott nemesi követelésekkel szemben és megadóztatták a nemességet.\n\nNem véletlen, hogy Európa kevésbé fejlett területein érvényesült:\n\nPoroszországban (I. Frigyes, I. Frigyes Vilmos, II. Frigyes), a Habsburg Birodalomban, Portugáliában, Spanyolországban, Oroszországban (I. Nagy Péter, II. Katalin), Dániában, Svédországban. Legjellegzetesebb magyarországi képviselőjének Habsburg Mária Terézia és II. József tekinthető. Gazdaságpolitikáját a gyarmatosítás hiánya miatt a merkantilizmusnak az egyik ága, a kameralizmus jellemzi, amely elsősorban védvámokkal, illetve a bányászat és az ipar erősítésével próbálta a kincstári bevételeket növelni.\n\nMária Terézia (1740-1780), a tapintatos reformer\n\nVI. Károly (magyar királyként III. Károly 1711-1740) halálával fiúágon kihalt a Habsburg-ház. Károly azonban még életében jelentős erőfeszítéseket tett annak érdekében, hogy elismertesse a nőági trónutódlást: 1723-ban sikerül törvénybe iktatnia a Pragmatica Sanctiót. E jogforrás azon túl, hogy lehetővé tette Mária Terézia 1740-es trónra lépését, rögzítette, hogy az örökös tartományokban és Magyarországon a Habsburg-ház ugyanazon tagja uralkodik. Kimondja, hogy Magyarország és az örökös tartományok elválaszthatatlanok és feloszthatatlanok. A Pragmatica Sanctio több mint egy évszázadra rendezte a birodalom közjogi státuszát, értelmezésének kérdése az 1867-es kiegyezés kapcsán merült fel újra.\n\nKülpolitikája:\n\nA birodalom élére így került Mária Terézia, de a környező hatalmak megtámadták. Mária Terézia 1741-ben, rögtön megkoronázása után nehéz helyzettel találta szembe magát: az 1740-1748 közötti osztrák örökösödési háború során II. Frigyes porosz király Sziléziát fenyegette, addig Károly Albert egyenesen a trónjára aspirált. A királynő a szorult katonai helyzetben csak a magyar rendek segítségére számíthatott. A nemesség „Életünket és vérünket királyunkért, Mária Teréziáért!” (Vitam et sanguinem pro nostro rege, Maria Theresia!”) felkiáltással támogatásáról biztosította az uralkodónőt, aki cserébe megerősítette a nemesi szabadságjogokat. Az 1748-ig elhúzódó osztrák örökösödési háborúban jelentős volt a magyar huszárság támogatása a császári hadtestek mellett, s bár Szilézia elveszett, azért Mária Teréziának sikerült megerősítenie hatalmát. Később, az 1756-tól 1763-ig tartó hétéves háborúban még tett egy sikertelen kísérletet az értékes terület visszaszerzésére - ekkor a magyarok már a reguláris hadseregben szolgáltak. Sziléziát nem tudta visszaszerezni.\n\nBelpolitikája, reformtörekvései:\n\nHatalma megszilárdítása után hozzáláthatott a reformok végrehajtásához. A felvilágosodás jegyében kormányzati és közigazgatási reformokat vezet be.\n\nLényege: a felvilágosodás eszméinek hatására javítani akart birodalma helyzetén, de felülről kezdeményezett óvatos reformokat vezetett be, ezért tekinthető ez a felvilágosult abszolutizmus módszerének.\n\nÚgy akart modernizálni, hogy az alapvető politikai viszonyok, és az uralkodó érdeke sértetlen maradjon. Így rendeletekkel kormányzott, 1765-től nem is hívta össze az országgyűlést. Mária Terézia Gerhard van Swieten udvari tanácsadójának hatására a monarchia modernizálásának érdekében nem zárkózott el a felvilágosodás eszméitől. Kormányzati és közigazgatási reformintézkedéseket dolgoztak ki. Központosított szakigazgatást szolgáló intézményeket hoztak létre: az Államtanácsot és a Kereskedelmi Tanácsot.\n\nMária Terézia és a magyar nemesség:\n\nMária Terézia trónra léptekor dinasztikus konfliktus alakult ki: kirobbant az osztrák örökösödési háború, a német fejedelmek nem ismerték el Mária Terézia jogát a császári trónra. A magyar nemesség az országgyűlésen azonban megszavazta a háborúhoz szükséges adót és újoncokat. A hagyomány szerint a magyar nemesek az „életünket és vérünket” felkiáltással álltak ki uralkodójuk mellett. Az örökösödési háborúban Mária Terézia oldalán magyar huszárok is harcoltak. Mária Terézia a magyar nemesek támogatását kiváltságaik megerősítésével biztosította.\n\nMária Terézia modernizálni akarta a birodalmat. Tanácsadója, Kaunitz az országgyűlések mellőzését és a megyék külön-külön történő megnyerését javasolta. Ez abszolutista törekvéseket tükröz. Ez a változás az 1760-as években történt. Ezután rendeletekkel kormányzott. Ez az addigi kompromisszum felrúgását jelentette, és a rendszer abszolutisztikus jellegét erősítette. Ennek ellenére nem váltott ki komolyabb ellenállást a rendekből.\n\nFontosnak tartotta a köznemesség és kisnemesség megnyerését a reformokhoz.\n\nMária Terézia megalapította a Szent István rendet, a magyar (nemesi) testőrséget, ez egy gesztus volt a magyar nemesek felé. Célja egy udvarhű nemesi réteg kialakítása volt.\n\nKésőbb Mária Terézia meg akarta adóztatni a magyar nemeseket, ez a kiváltságok megsértését jelentette volna, de az országgyűlés nem fogadta el.\n\nMária Terézia kiadta az Urbáriumot: rendeletben szabályozta az úrbéri viszonyt, pedig az országgyűlés korábban elutasította az erre vonatkozó törvényjavaslatot. Az uralkodó ezzel beavatkozott a nemesek és jobbágyaik viszonyába. A nemesek nem növelhették majorságuk területét, sértette az árutermelést folytató nemesek érdekeit.\n\nRendeletei:\n\n1754-ben kettős vámhatárt vezetett be: míg a külső vámhatár az egész Habsburg Birodalmat védte a külföldi árukkal szemben, addig a belső Magyarország és az örökös tartományok között húzódott. Belső vámhatárt állított fel a tartományok közé, hogy ne legyen vetélytársa az osztrák és a cseh iparnak, és hogy a magyar nyersanyagok és mezőgazdasági termékek a birodalom határain belül maradjanak. Habsburg Birodalmon belül munkamegosztás jött létre Magyarország és az örökös tartományok között: Magyarország elsősorban élelem- és nyersanyagtermelő terület volt, míg az osztrák és a cseh tartományok ipari termékekkel látták el országunkat. Így a magyar ipar viszont nem fejlődött, hanem piaca lett az osztrák és a cseh ipari termékeknek. A bécsiek gazdaságpolitikáját a merkantilizmus jellemzi. Védővámokkal próbálták ugyanis megóvni a belső piacot a külföldi manufaktúrákban termelt olcsó árukkal szemben. Korszerűsíteni akarták a gazdaságot állami támogatással serkenteni az ipar fejlődését, de csak az örökös tartományok részére.\n\nA XVIII. századi magyarországi jobbágyság a földesuraknak robottal, kilenceddel és különféle szolgáltatásokkal tartozott, mely az úrbéri rendeletig eltérő volt. Az államnak hadiadóval, porcióval (a beszállásolt katonák élelmezésével) és forsponttal (a katonák szállításával) tartozott. A vármegyének háziadót, az egyháznak tizedet fizetett. Több probléma indokolta a jobbágykérdés rendezését. Az állami terhek ellen tört ki a békésszentandrási parasztfelkelés 1735-ben. 1763-ban az udvar határőrvidéket akart szervezni Erdélyben, de a székelyek vonakodtak katonának állni, féltették ősi szabadságukat. Megtorlásul a császári csapatok 1764. január 7-én Mádéfalvánál több száz székelyt megöltek: mádéfalvi veszedelem. A jobbágykérdést 1767-ben rendeleti úton (az Urbáriumrendeletben) szabályozta. Ez a földbért l forintban állapította meg, a földesúr számára végzendő ingyen munkát pedig heti egy nap igás vagy két nap kézi robotban határozta meg, és továbbra is kilencedet fizet neki. A jobbágyok továbbra is fizették a tizedet az egyháznak, a kilencedet a földesúrnak, és az 1 Ft fejadót az államnak. Anton von Raab alkotta meg a rendeletet. Megszűnt a jobbágy földhöz kötöttsége. meghatározta az egész jobbágytelek nagyságát: 16-40 hold tájegységektől függően.\n\nÉrtékelése:\n\nA rendelet kiadására az erdélyi román parasztfelkelés után került sor. Mária Terézia tehát a jobbágytelkek és jobbágyterhek felmérésére adott utasítást. Rendeletében rögzítette a jobbágytelkek és a majorság arányát, meghatározta a robot maximális mértékét. Lehetővé vált a szabad költözködés, házasodás, tanulás, az ingó javakról való szabad rendelkezés a jobbágyok számára. Ez csökkentette a jobbágyok kiszolgáltatottságát, de ez nem jelentett jobbágyfelszabadítást. A magyarországi jobbágyok jelentős része azonban a rendelet előtt is szabad költözködésű volt. Az úrbéri rendelet kiadása mögött álló egyik mozgatórugó: az adóalap védelme, a jobbágyterhek egységesítése. Hátterében az állt, hogy az árutermelést folytató földesurak növelték a majorságot és a robot mértékét; a nemesek tiltakoztak az ellen, hogy az uralkodó beavatkozott az úrbéri viszonyba. Az uralkodó javítani akarta a parasztok életkörülményeit, szabad munkaerőt akart biztosítani az ipar számára. Magyarországon, megindult a telekaprózódás, zselléresedés folyamata.\n\nKultúra:\n\nAz analfabetizmus visszaszorítását és a műveltségi szint emelését célzó Ratio Educationis (1777) 6-12 éves korig tankötelezettséget vezetett be, valamint a felvilágosodás szellemében összeállította és egységesítette a tananyagot. Bevezeti az intézményes tanítóképzést és az anyanyelvi elemi népiskolákat. Minden iskola felett állami felügyeletet rendelt el. A rendelet megfogalmazója: Ürményi József kancelláriai tanácsos volt. A nyári munkálatok idején a tanítás szünetelt.\n\nA rendelet az ország minden lakosára nyelvi, vallási és társadalmi különbség nélkül kiterjedt, és különböző iskolák felállítását írta elő. Az oktatás felügyeletét, szabályozását uralkodói feladatnak tekinti, ez a felvilágosodás hatását mutatja. Célja a parasztság iskoláztatása. A mezőgazdasághoz igazították a tanítás idejét. Az iskolába járásra ösztönöz a rendelet, de nem ír elő tankötelezettséget. Ehhez nem is lett volna elegendő iskola. Ez az első egységes oktatási rendszer Magyarországon. Ezzel az állam ellenőrzi a zömében egyházi fenntartású iskolákat is. Meghatározza a tananyagot, a tanári képesítés feltételeit és az iskolák költségvetését. Célkitűzése: az általános műveltség fejlesztése, a vallásos erkölcsi nevelés, a hűséges alattvalók nevelése és praktikus ismeretek oktatása. Az állam nem vette át az iskolafenntartást. A rendelet hatására terjedt az iskolázottság és csökkent az analfabétizmus.\n\n1749-ben Bécsben felállította az állami hivatalnokok képzéséért felelős Theresianumot. Szerepe volt a magyar nemes ifjak nevelésében, és a magyar nemesi testőrség megszervezésében (1760) is, mely a magyar nemesek hivatali és katonai előmenetelét segítette. Bessenyei György is tagja volt, akinek az Ágis tragédiája című drámájától, 1772-től számítjuk a magyar felvilágosodást. Bessenyei Magyar tudós Társaság létrehozását szorgalmazta, melynek feladata az anyanyelv ápolása lett volna. A bécsi udvar korszerűsítő törekvéseit a magyar nemesség és értelmiség is támogatta.\n\nII. József (1780-1790), a türelmetlen reformer\n\nII. József 1780-ban, 39 évesen került trónra. 1765-től német-római császár, édesanyja mellett társuralkodó volt, aki azonban nem sok beleszólást engedett neki az államügyekbe.\n\nNem koronáztatta meg magát, mert nem volt hajlandó fölesküdni a magyar törvényekre, ezzel is jelezte, hogy nem ismeri el a magyar rendek jogait. Ezért „kalapos király”-nak gúnyolták. Felvilágosult abszolutizmusát, elveit és kormányzási gyakorlatát jozefinizmusnak hívjuk, híveit pedig jozefinistáknak (a polgárság és az értelmiségiek köréből).\n\nA birodalom egységesítése volt a célja, rendeletekkel kormányzott, ezért nem hívta össze az országgyűlést sem. Elve: „mindent a népért, semmit a nép által.” Célja: a jólét biztosítása, de módszerei ellen sokan felléptek. A felvilágosult abszolutizmus tudományos alapjait az osztrák „kameralisták”, Karl Anton von Martini, majd Joseph von Sonnenfeld dolgozták ki. nézeteik szerint az állam felelős a lakosság anyagi, kulturális és egészségi jólétéért.\n\nRendeletei, intézkedései:\n\nFelvilágosult szellemiségének jele volt a vallási ügyekhez való viszonya is. Fölújította a királyi tetszvényjogot (placetum regium), amelynek értelmében a pápai bullák érvényességéhez uralkodói jóváhagyás kellett. 1781-es türelmi rendelete:\n\negyenjogúvá tette a protestáns és a görögkeleti felekezet tagjait, biztosította továbbá vallásuk szabad gyakorlását, a nem katolikusok is szabadon viselhettek hivatalt,\n\nelőírta a zsidó vallás tolerálását is.\n\n1782-es rendeletében feloszlatta a „hasznos tevékenységet nem végző” szerzetesrendeket. Törekvéseit VI. Pius pápa nem nézte jó szemmel, és személyesen próbálta rávenni az uralkodót rendeletei megváltoztatására - sikertelenül. Ez volt az ún. fordított Canossa-járás.\n\nKésőbbi rendeletei, mindenekelőtt az 1784-es nyelvrendelet, ellenszenvet váltottak ki. Ez az addigi latin helyett - a birodalom egységesítésének szándékával - a németet tette meg hivatalos nyelvvé, átszervezi a közigazgatást. Az intézkedés sértette a magyar nemzeti érzést.\n\nMeg akarta adóztatni a nemesi és az egyházi birtokot. II. József birtokösszeírást rendelt el, a nemesség megadóztatását tervezte, az adóztatást osztrák mintára vezették volna be. Ez nyilván a nemesi kiváltság eltörlését jelentette volna, a birodalom egységesítését is szolgálta, növelte a nemesek ellenszenvét II. József politikájával szemben. Magyarországon ez nem valósult meg, mert a magyar rendek ellenállásába ütközött. A nemesi adózás tervezett bevezetése és a birodalom modernizálását szolgáló rendeletek kivívták a magyar nemesség ellenállását. Egyes arisztokraták – kezdetben – támogatták II. József reformjait, a kerületek létrehozása a vármegyerendszer felszámolását jelentette, a közigazgatás átalakítása sértette a rendi jogokat.\n\n1784-ben Horea és Kloska vezetésével parasztfelkelés tört ki Erdélyben. Ennek hatására ugyanebben az évben megszületett a jobbágyrendelet (1785), amely megtiltotta a „jobbágy” megnevezést, eltörölte a röghöz kötést. Személyükben szabaddá tette a jobbágyokat, lehetővé téve számukra a szabad költözködést, a szabad házasodást és az ingóvagyon fölötti rendelkezést, és a szabad pályaválasztást. Ez a jobbágyok személyes függőségének lazulását eredményezte pl. a szabad költözködés, a szabad végrendelkezés joga. Jogi értelemben már ekkor egységesnek tekinthető a paraszti réteg. Nem történt jobbágyfelszabadítás.\n\nNépszámlálást és birtokösszeírást rendelt el (1784). A népszámlálás és a földek felmérése az úgynevezett fiziokrata gazdaságpolitikát szolgálta, a nemesi birtok megadóztatását készítette elő. Az ország lakossága ekkor már 9,3 millió a betelepítéseknek és a vándorlásoknak köszönhetően, illetve annak, hogy az országot ekkor már nem sújtották háborúk, mint a török korban. Mária Terézia és II. József politikájának következtében az ország népessége növekedett. A lakosságból 3,5 millió magyar, 1,5 millió román, 1,25 millió szlovák, 1,1 millió német, 0,8 millió horvát, 0,6 millió szerb, 0,3 millió ruszin, 0,3 millió zsidó, örmény, görög. Tehát 5,8 millió lakos idegen ajkú Magyarországon, így a magyarok számaránya nem éri el az 50 %-ot sem. Soknemzetiségű országgá váltunk, ahol a lakosságnak csak 39 %-a magyar.\n\nKormányzati reformok:\n\nösszevonta az országos főhivatalokat.\n\naz országot 10 kerületre osztotta, élükre királyi biztosokat állított. Ezzel megsértette a vármegyei önkormányzatot.\n\nKülpolitikája:\n\nII. József uralkodásának végén kedvezőtlen külpolitikai helyzettel kellett szembenéznie a birodalomnak. József 1788-ban II. Katalin orosz cárnővel szövetségben megtámadta Törökországot, a háború azonban nem hozott mást, mint katonai kudarcot, nélkülözést a nép, és maláriát az uralkodó számára.\n\nA francia forradalom fontos szövetségesétől, XVI. Lajostól fosztotta meg, akinek felesége József húga, Maria Antoinette volt.\n\nBelgiumban felkelés tört ki, aminek következtében a gazdag tartomány kimondta függetlenségét. Mindezeken túl az országnak Poroszország fenyegetésével is szembe kellett néznie.\n\nHeves nemesi ellenállás bontakozott ki a nyelvrendelete, a földek megadóztatása, a vármegyék lefokozása miatt. Mikor 1790-ben már halálos ágyán feküdt, általános ellenszenv övezte a meghasonlott Józsefet. Ekkor olyat tett, amire még nem volt példa az ország történetében: nevezetes tollvonásával visszavonta minden Magyarországgal kapcsolatos rendeletét. Mindössze három királyi rendeletet tartott hatályban. Megtartotta a türelmi rendeletet, a jobbágyrendeletet és az alsópapság támogatásáról szólót.\n\n(Magyarország államszervezete a Habsburg Birodalomban:\n\nMagyarország a Habsburg Birodalom része, de elvben biztosították Magyarország különállását a birodalmon belül. Ezt garantálták a magyar rendek jogai és kiváltságai, adómentessége, illetve a magyar országgyűlés. A had-, pénz- és külügy azonban királyi felségjog volt. Ezt még III. Károly vezette be.\n\n1. A kormányszékek: a közigazgatás szervei, melyeket a Habsburgok vezettek be, s csak a király irányítása alatt álltak. Ide tartozik a kancellária Bécsben, mely az uralkodók rendeleteit továbbította, a kamara, mely Pozsonyban a pénzügyeket intézte és a Helytartótanács, mely Pozsonyban, majd Budán székelt. Elnöke a nádor. Ez volt a tulajdonképpeni végrehajtó hatalom.\n\n2. Az országgyűlésen /diéta/ az adók és az újoncok megszavazása zajlott. Kétkamarás: alsó- és felsőtáblából állt. Elnöke a nádor (a király helyettese). A felsőtáblán a főnemesek és a főpapok személyesen jelentek meg. Az alsótáblára az 52 vármegye mindegyike 2-2 követet, a szabad királyi városok 1-1 követet küldhettek. A diétát a király hívja össze és rekeszti be, ahol a rendekkel együtt alkotja meg a törvényeket. Az országgyűlésen és a vármegyékben a rendek akarata érvényesült. A felvilágosult uralkodók nem hívták össze az országgyűlést, rendeleti úton kormányoztak.\n\n3. A vármegye a rendiség védőbástyája volt. Ez volt a nemesség autonóm szervezete, saját rendelkezéseket alkothatott. Élén a király által kinevezett főispán állt, de tisztviselőit a közgyűlés maga választotta. Itt szavazták meg az országgyűlési követutasításokat is. Minden nemes jelen lehetett.)\n\nII. József után II. Lipót uralkodott 1790-1792, aki 1791-ben összehívja a magyar országgyűlést, ahol megerősíti a magyar rendek jogait.', 269, 1, '2026-04-17 09:40:23', '2026-04-17 09:40:23');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(14, 14, 'Az emberi jogok és a jogegyenlőség elve, az állampolgári jogok, kötelességek', '14.docx', '14. Az emberi jogok és a jogegyenlőség elve, az állampolgári jogok, kötelességek\n\n(felvilágosodás, Magyarország Alaptörvénye)\n\nA FELVILÁGOSODÁS\n\n• Mi a felvilágosodás?\n\n• Immánuel Kant meghatározása: Sapere aude! - Merj gondolkodni!\n\n• A felvilágosodás a kapitalista fejlődésben élenjáró Angliában jött létre a XVII. században, és Franciaországban bontakozott ki a XVIII. században.\n\nA korszak polgári gondolkodói hittek a tapasztalatra támaszkodó ész mindenhatóságában. Meg voltak győződve arról, hogy a szabadon terjesztett gondolat (a „felvilágosítás”) az emberiség tökéletesedéséhez vezet, és megvalósítja a születési előjogokat nem ismerő, politikai egyenlőségen alapuló társadalmat.\n\nA felvilágosodás eszmei mozgalom, amely szakítani akar a feudalizmus uralkodó ideológiájával, a katolikus egyház által intézményesített vallással;\n\nreformokkal korszerűsíteni akarja a gazdaságot és a társadalmat;\n\núj erkölcsöt hirdet egy emberközpontú értékrend alapján; célja: az embert, mint individuumot felszabadítani, boldoggá tenni, és terjeszteni a „világosságot”, tehát a tudomány eredményeit.\n\n• Előzménye: a természettudományok robbanásszerű fejlődése (Newton, Kepler, Galilei);\n\n• empirizmus: a tapasztalat minden ismeretünk forrása (Bacon);\n\n• racionalizmus: a világ megismerése az ész által (Descartes).\n\nAz új fizikai világkép a felvilágosodás eszmekörének közvetlen ihletője.\n\nTermészettudományos felfedezések:\n\nCsillagászat\n\n• Kopernikusz (1473-1543): „Égitestek körforgása” c. mű (1543): heliocentrikus (Nap-központú) világkép; - a bolygók a Nap körül keringenek.\n\n• Kepler (1571—1630): „Új csillagászat, avagy az ég fizikája” c. mű: felállította a bolygómozgás alaptörvényeit.\n\n• Galilei (1564-1642): „Dialógus” c. mű:\n\nmechanika megalapozása;\n\nmegszerkesztette az első ingaórát;\n\nfelfedezte a Jupiter holdjait;\n\na heliocentrikus világkép egyik bizonyítéka: feltárta a Vénusz Holdhoz hasonló fázisait (amely csak úgy lehetséges, ha a Föld és a Vénusz is a Nap körül kering).\n\nFizika\n\n• Newton (1643-1723): a természetfilozófia matematikai alapelvei: feltárta a mechanika alapelveit és az általános tömegvonzás törvényét.\n\n• Torricelli, Pascal: a levegőnyomás mérése.\n\nKémia\n\n• Boyle és Mariott: a levegőrészecskék mozgása.\n\nOrvostudomány\n\n• Vesalius: emberi anatómia.\n\n• Harvey: vérkeringés és a szívműködés leírása.\n\nEmpirizmus\n\n• Francis Bacon (1561-1626): „Nóvum Orgánum” (Új Logika, 1620)\n\nA tapasztalatokból kell kiindulni, és elméleti rendszerezés után oda is kell visszatérni.\n\nMódszere az indukció. A tapasztalat, a kísérletek, az egyesből az általánosra történő következtetés. Új ismeretekhez vezet, de a tévedés lehetősége is fennáll.\n\nUtópista gondolkodók\n\n• Utópia: megvalósíthatatlan elképzelés, terv, vágy. Olyan művek megnevezésére használjuk, amelyek dialógus vagy regény formában az emberi tökéletlenségtől mentes államot írnak le.\n\n• Morus Tamás: „Utópia” (1516): a társadalmi egyenlőség és igazságosság szigete. Morus metsző kritikával tárta fel a korabeli közállapotokat, szembeállítva Utópia egyenlőségen alapuló társadalmával.\n\n• Francis Bacon: „Nova Atlantis” (Új Atlantisz): tudósok által irányított világ.\n\n• Tomasso Campanella: Napállam” (1620): Ceylon szigetén, a Nap városában minden ember egyenlő, nincs magántulajdon, nincsenek születési előjogok, minden közös, mindenki dolgozik a képességei szerint. A legfőbb hatalom a Nap, illetve annak megszemélyesítője, a filozófus.\n\nAz angol felvilágosodás gondolkodói:\n\n• John Locke (1632-1704): az angol „alkotmányos monarchia filozófusa”:\n\n- „Két értekezés a polgári kormányzásról” c. művében a politikai liberalizmus eszméjének alapjairól ír (társadalmi szerződés). A fölvilágosodás legnagyobb angol alakja, Newton barátja. Azt hirdette, hogy az ember természeti jogait önkéntes szerződésben átruházza az államra, de joga van ezt a szerződést („társadalmi szerződés”) fölbontani, ha a hatalom az egyéni szabadságot és a (polgári) tulajdont megsérti. Locke tökéletes államformának az angol alkotmányos monarchiát tekintette.\n\n- „Értekezés az emberi természetről” c. művében írja: velünk született eszmék nem léteznek, az újszülött tudata tiszta lap (tabula rasa), amelyre az érzéki tapasztalat, a nevelés írja rá a külvilágból érkező információkat (szenzualizmus).\n\nRacionalizmus\n\n• René Descartes (1596-1650): „Értekezés a módszerről” (1637):\n\nAz első igazán újkori gondolkodó, aki megpróbálta kiszabadítani a filozófiát a „teológia szolgálóleánya” státuszából. Az értelemből való kiindulás (ratio = értelem), a gondolkodás a világ megismerésének az alapja.\n\nA gondolkodás alapeleme a kételkedés: „Cogito ergo sum” (Gondolkodom, tehát vagyok). Mindenben kételkedni kell, de a gondolkodó szellem létezése ez alól kivétel, mert a gondolkodó nem gondolhatja el magát nemlétezőnek.\n\nMódszere a dedukció: általánosból következtet az egyesre: Ez általában mindig helyes eredményre vezet, de új ismerteket nem nyújt.\n\nKözgazdasági gondolkodás: fölvilágosodás korának közgazdászai a szabad verseny hívei voltak.\n\n• Adam Smith („A nemzetek gazdasága” 1776): a gazdasági fejlődés hajtómotorja a munka.\n\nA megtermelt áru értékét az „előállításához a társadalomban szükséges munka”, tehát a ráfordított munka mennyisége határozza meg (munkaérték-elmélet).\n\nA német felvilágosodás\n\n• Gottfried Wilhelm Leibniz (l 646-1716)\n\n• Az általunk ismert világ a világok lehető legtökéletesebbike, mert ha ennél is tökéletesebb lehetett volna, akkor Isten olyannak teremti. Az ember képes a végtelen világ megismerésére. Ezt a filozófiát cáfolja meg Voltaire a Candide avagy az optimizmus című utaztató regényében.\n\n• Immánuel Kant (1724-1804)\n\n• „A tiszta ész kritikája”; „A gyakorlati ész kritikája” c. művei: Kant az észt állította a középpontba. Vannak velünk született (a priori) ismereteink. Az értelem, miközben törvényei alá vonja az érzékelést és a képzeletet, lehetővé teszi a természetet kormányzó elsődleges törvények felállítását. Szerinte a felvilágosodás „az ember kilábalása a maga okozta kiskorúságából.”\n\nA francia felvilágosodás:\n\nA felvilágosodás eszmeköre Franciaországban teljesedett ki, és előkészítette a francia forradalmat.\n\nI. szakasza (1680-1715): a hagyományos értékrend elleni támadás\n\n• Voltaire (1694-1778) (művei: „Candide”, „Filozófiai ábécé”)\n\nTámadta az egyházat, mint az elnyomó hatalom ideológiai támaszát: antiklerikalizmus.\n\nDeista volt: Isten létét elismerte, de szerepét csak a teremtésre korlátozta. Az egyház félelemben, sötétségben, babonában tartja az emberiséget a tudás birtokosaiként: „tiporjátok el a gyalázatost!” (= az egyházat. Vallási toleranciára kell törekedni.\n\nA fölvilágosodás új irodalmi műfaját teremtette meg, a filozófiai elbeszélést. Fantasztikus vagy keleti környezetben játszódó regényei és elbeszélése bírálták az önmagukat túlélt feudális viszonyokat. Az emberi életet Voltaire szerint az ésszerűségnek, a rációnak kell kormányoznia.\n\nVoltaire legélesebben a vallási vakbuzgóságot támadta, pedig hitt a jutalmazó és büntető Istenben.\n\n• Montesquieu (1689-1755)\n\n„Először szükségszerűen ember vagyok és csak véletlenül francia.”\n\n- „Perzsa levelek” (1721): elképzelt perzsiai és franciaországi állapotok párhuzamos bemutatása révén bírálta a franciaországi viszonyokat.\n\n- „A törvények szelleméről” (1748) c. munkájában:\n\n1. A társadalmak életét a földrajzi környezetük szabja meg. A társadalmi haladásra a mérsékelt övben, ezen belül is Európában a legkedvezőbb a helyzet, itt is leginkább a közepes méretű országokban.\n\n2. Definiálta a szabadságot is: az a jog, hogy mindenki megteheti azt, amit a törvények megengednek. A politikai szabadság szerinte a vagyonbírás biztonságából származik, ezt kell szolgálnia a politikai intézményrendszernek is.\n\n3. Hatalommegosztás elve: szétválasztja a törvényhozói, a végrehajtói és a bírói hatalmat, kizárólag e hatalmi ágak egymástól való függetlensége biztosíthatja a zsarnokság felszámolását. „Ha a törvényhozó hatalom a végrehajtó hatalommal ugyanabban a személyben vagy ugyanabban a hatósági testületben egyesül, nincsen szabadság, mivel attól lehet tartani, hogy az ilyen uralkodó vagy az ilyen testület zsarnoki törvényt fog hozni, és azokat zsarnoki módon fogja végrehajtani. Akkor sincsen szabadság, ha a bírói hatalom nincsen elválasztva a törvényhozó, valamint a végrehajtó hatalomtól.\n\nAz a helyes, ha minden fontosabb helyen a lakosok maguk választanak maguk számára képviselőket. Nem szükséges, hogy a képviselők minden egyes ügyre nézve külön utasítást kapjanak... minden állampolgárt meg kell, hogy illessen az a jog, hogy szavazhasson a képviselőválasztáson...\n\nA törvényhozó hatalmat mind a nemesek testülete, mind a nép által választott képviselők testületére kell bízni, melyek külön kell, hogy ülésezzenek és tanácskozzanak...\n\n..a törvényhozó hatalomnak... lehetősége kell, hogy legyen arra, hogy megvizsgálja, miként hajtják végre az általa hozott törvényeket.”\n\nPascal- gondolkodó nádszál hasonlata – az ember olyan törékeny, mint a nádszál, de ha meghal, tudatában van annak, mi történik vele.\n\nII. szakasz (1715-1760): a „felvilágosodás virágzása” Franciaországban\n\n• Az „Enciklopédia, avagy a tudományok, művészetek, mesterségek értelmező szótára”: a felvilágosodás szellemében értelmezik újra a világot, az eddigi világot.\n\n- angol mintája: 1728 - Chambers-féle Cyclopaedia;\n\n1751-1772 között 28 kötete jelent meg, szerkesztői és szerzői: Diderot filozófiai cikkeket írt; Condorcet márki (1743-94) közgazdasági cikkeket, D\'Alembert (1717-1789) matematikai és fizikai cikkeket (további munkatársak: Helvetius, Holbach). A Sorbonne elítélte, a királyi tanács elkobzását írta elő, az egyház betiltotta, így titokban terjesztették. Nagy szerepe volt a modern kori szókincs megteremtésében. A mechanika törvényeit alkalmazták az élő szervezetre is, amelyet géphez hasonlítottak. Egy jellemző cím: „Az embergép”.\n\nIII. szakasz (1760-) az eszmék elterjedése\n\n• Jean-Jacques Rousseau (1712-78)\n\n„Az emberek közti egyenlőtlenség eredetéről” (1754):\n\nösszevetette a társadalom emberének állapotát a vademberével. Jelszava: „Vissza a természethez” (többek közt az egyenlőség állapotába). Úgy gondolta, hogy bár a társadalmi szerződés szükségszerű, az emberek természetes állapotukban, azaz a vagyoni egyenlőség állapotában voltak boldogok. „Az első ember, akinek eszébe jutott, hogy egy darabka földet elkerítvén így szóljon: ez az enyém, s aki elég együgyű embereket talált, hogy ezt elhiggyék, volt a polgári társadalom igazi megalapítója. Mennyi bűntől, háborútól és gyilkosságtól, mennyi nyomorúságtól mentette volna meg az emberi nemet, aki ekkor kihúzza a karókat, betemeti az árkot, s azt kiáltja felebarátainak: Őrizkedjetek attól, hogy erre a csalóra hallgassatok! Elvesztek, ha elfelejtitek, hogy a föld gyümölcse mindenkié, a föld pedig senkié!”\n\n- „Társadalmi szerződés” (1762): a szerződés az egyének és a közösség között áll fenn, és nem a fejedelem és az alattvalók között (Aquinói Szent Tamás, Locke). A közvetlen demokráciát alkalmazó köztársaság a legtökéletesebb államforma. A társadalmi szerződés elméletét továbbfejlesztette. Megállapította, hogy az állam létrejöttét megelőzte a magántulajdon és a vagyoni egyenlőtlenség. Rousseau államelméletének lényege a nép legfőbb hatalmának, a népfelségnek az elve, azaz a népszuverenitás. Gondolatmenetéből következik, hogy a társadalmi szerződést föl kell bontani, ha azt a hatalom birtokosa megszegi. (A francia forradalmat harcosai egy elavult és megszegett szerződés radikális fölbontásának tekintették.) Nem véletlen tehát, hogy a legtökéletesebb államformának a köztársaságot tartotta.\n\n- „Vissza a természetbe!”, ahol ismét emberek lehetünk.\n\nKözgazdasági gondolkodás: fiziokratizmus\n\n• Francois Quisney (1697-1774)\n\nGazdasági áttekintés c. munkájában (1758) alapozta meg a fiziokratizmust (= „természet uralma”): a gazdaságot nem kell mesterségesen szabályozni, hagyni kell, hogy a „dolgok a maguk útján haladjanak” (laissez fairé, laissez passer). Az államnak csak az a feladata, hogy biztosítsa a piac normális működését: éjjeliőr szerepet szán az államnak. Haszon csak termelésből származhat, termelő ágazat pedig csak egy van: a mezőgazdaság.\n\n• Ann Robert Turgot (1727-1781)\n\n1774-76 között Franciaország pénzügyi főellenőre volt, fiziokrata szellemben fellépett a (merkantilista) protekcionizmus ellen, elősegítette a szabad kereskedelmet.\n\nA felvilágosodás hatása:\n\n• Megjelentek a demokratikus eszmék: hatalom megosztása, népszuverenitás, természetes és elidegeníthetetlen emberi jogok.\n\n• A tudományok kitörtek az egyházi felügyelet alól, és lendületesen fejlődtek.\n\n• Megjelent a haladás eszméje.\n\n• A francia forradalomban az egyes irányzatoknak megvoltak a felvilágosodás kori ideológiai előképeik (Montesquieu - Saint-Just; Rousseau - Robespierre; Voltaire - Desmoulins, Diderot - Danton).\n\nA felvilágosult abszolutizmus:\n\nA XVIII. század a felvilágosult abszolutizmus kora. A felvilágosult abszolutizmus szellemében az uralkodók az abszolutista hatalomgyakorlási módszereket a felvilágosodás eszméivel ötvözik.\n\nJellemzi őket a rendi országgyűlés mellőzése, a rendeleti kormányzás és a bürokráciára, a jól fölépített hivatalnoki apparátusra való támaszkodás;\n\nMásrészt uralkodói szerepfölfogásuk: már nem „Isten kegyelméből”, hanem a népért, a nép szolgálatában uralkodnak.\n\nA felvilágosult abszolutizmus jellemzője a modernizálási szándék (különösen az oktatás, az egészségügy és a középkori szokások elleni küzdelem területén). Lebontották a belső vámokat, pártolták az iparfejlődést, védték a jobbágyokat a túlzott nemesi követelésekkel szemben és megadóztatták a nemességet.\n\nNem véletlen, hogy Európa kevésbé fejlett területein érvényesült:\n\nPoroszországban (I. Frigyes, I. Frigyes Vilmos, II. Frigyes), a Habsburg Birodalomban, Portugáliában, Spanyolországban, Oroszországban (I. Nagy Péter, II. Katalin), Dániában, Svédországban. Legjellegzetesebb magyarországi képviselőjének Habsburg Mária Terézia és II. József tekinthető. Gazdaságpolitikáját a gyarmatosítás hiánya miatt a merkantilizmusnak az egyik ága, a kameralizmus jellemzi, amely elsősorban védvámokkal, illetve a bányászat és az ipar erősítésével próbálta a kincstári bevételeket növelni.\n\nAz Emberi és polgári jogok nyilatkozata\n\nAz Emberi és polgári jogok nyilatkozata Franciaország egyik alapvető dokumentuma, mely az emberek egyéni és közösségi jogait határozza meg. Az 1789. július 14-i francia forradalom után fogalmazták meg. 1789. augusztus 26-án fogadta el az Alkotmányozó Nemzetgyűlés. Ez a dokumentum az 1791-es alkotmányt készíti elő. La Fayette készítette el, és az amerikai Thomas Jefferson is átnézte.\n\nA francia forradalom megszűntette az abszolutizmust, az abszolút monarchiát alkotmányos monarchia, ill. később köztársasági államforma váltotta fel (1792. szept.20). Az abszolutizmus lényege volt, hogy az „Isten kegyelméből” uralkodó király a három hatalmi ág: a törvényhozó, igazságszolgáltató, végrehajtó hatalom egy kézben való egyesítésével teljhatalomra tett szert, és nem felelt tetteiért az alattvalóknak. Az alkotmányos monarchia a hatalmi ágak megosztására épült. Az új állam az egyéni szabadságjogok és a politikai egyenlőség megvalósítása során a népfelség elvét juttatta érvényre.\n\nA nyilatkozat alapelvei a felvilágosodás filozófiai és politikai alapelveiből származtak, szerepeltek benne többek között\n\na Jean-Jacques Rousseau (’russzó’) által megfogalmazott egyén és társadalmi szerződés, a népszuverenitás fogalmai,\n\na Montesquieu (’monteszkiő’) által kidolgozott hatalmi ágak megosztásának elmélete.\n\nelőzménye volt a Thomas Jefferson által készített amerikai Függetlenségi nyilatkozat 1776.\n\nilletve az angol Bill of Rights (1689).\n\nA feudalizmus eltörlése után, a nyilatkozat népszuverenitást és esélyegyenlőséget hirdetett. A jogokat a nyilatkozat az „közakarat kifejezéseként” kezeli, így hirdet jogegyenlőséget és „csak a társadalomra nézve ártalmas cselekedeteket” tiltja. A bevezető a racionalizmusra utal, ill. arra, hogy az embereknek ismerniük kell a jogaikat. Az ember természetes jogait fogalmazza meg, melyet kivétel nélkül mindenkire érvényesnek tekintettek:\n\nMinden ember szabadnak és jogokban egyenlőnek születik és marad; a társadalmi különbségek csakis a közösség szempontjából való hasznosságon alapulnak. Nincsenek születési előjogok, szembefordul a nemesi kiváltságokkal.\n\nMinden politikai társulás célja az ember természetes és elévülhetetlen jogainak megőrzése. E jogok: a szabadságjog, a tulajdonjog, a biztonság s az elnyomással szemben való ellenállás. A polgári társulás célja az ember jogainak megőrzése.\n\nMinden szuverenitás elve természeténél fogva a nemzetben lakozik; sem testület, sem egyén nem gyakorolhat hatalmat, ha (az) nem határozottan tőle ered. - Ez eltér a forradalom előtti helyzettől, ahol a királyság politikai forrásjoga a királyok isten adta jogának elvéből származott. A népfelség elve: hatalom forrása a nép. Hatalommegosztás elve (törvényhozó és végrehajtó hatalom van kezdetben, majd később lesz a 3 hatalmi ág. Locke szerint 2 hatalmi ág szükséges, Montesquie 3 hatalmi ágat tart fontosnak.\n\nA szabadság annyit jelent, hogy mindent szabad, ami másnak nem árt. Az egyes ember természetes jogainak gyakorlása tehát más korlátokba nem ütközhetik, mint azokba, amelyek a társadalom többi tagjai számára ugyanezen jogok élvezetét biztosítják; s e korlátokat a törvény határozhatja meg. Ezek alapvető polgári szabadságjogok. Szabadság = mindent szabad, ami másnak nem árt.\n\nA törvénynek csak a társadalomra nézve ártalmas cselekedetek megtiltására van joga. Amit a törvény nem tilt, azt senki nem akadályozhatja meg, s amit a törvény el nem rendel, arra senkit kényszeríteni nem lehet.\n\nA törvény a közakarat kifejezése; alkotásában minden polgárnak joga van személyesen vagy képviselői révén közreműködnie. A törvény egyformán törvény mindenki számára, akár védelmez, akár büntet; s mivelhogy a törvény előtt minden polgár egyenlő, tehát minden polgár egyformán alkalmazható minden közhivatalra, állásra és méltóságra, erényeik és képességeik különbözőségén kívül egyéb különbséget nem ismerve. – Ez eltér a forradalom előtti helyzettől, ahol a francia társadalom rendekre volt felosztva: papságra, nemességre valamint a népesség többi részét kitevő harmadik rendre, és ahol az első két rendnek külön jogai voltak. Főleg a született nemesség elvével áll szemben. E pont megfogalmazója érdekes módon Talleyrand, az arisztokrata származású püspök volt. A törvényalkotásban minden polgárnak joga van közreműködni.\n\nVád alá helyezni, letartóztatni s fogva tartani bárkit is csak a törvény által meghatározott esetekben s a törvény által előírt formák között lehet. Mindenki büntetendő, aki önkényes rendelkezéseket szorgalmaz, kiad, végrehajt vagy végrehajtat; viszont minden polgárnak, akit a törvény értelmében megidéznek vagy őrizetbe vesznek, haladéktalanul engedelmeskednie kell – s ha ellenállást tanúsít, bűnösnek vallja magát vele.\n\nA törvény csak szigorúan és nyilvánvalóan szükséges büntetési tételeket állapít meg, s büntetéssel sújtani senkit másként nem lehet, mint a bűncselekmény elkövetése előtt meghozott és kihirdetett, valamint szabályszerűen alkalmazott törvény értelmében.\n\nMindaddig, amíg bűnössé nem nyilvánítják, minden ember ártatlannak vélelmezendő. Ha tehát letartóztatása mégis elkerülhetetlenné válik, a törvénynek szigorúan meg kell torolnia minden olyan keményebb rendszabályt, amelyet a szökés megakadályozásának szükségessége nem indokol. - A nyilatkozat tiltja a gyanúsítottal szembeni indokolatlan durvaságot, ugyanakkor az ártatlanság vélelmét hirdeti. A forradalom előtti Franciaországban, miután az illetékes hatóságok vád alá helyezték, technikailag azonnal bűnösként kezelték az embert.\n\nSenkit meggyőződése, vallási s egyéb nézetei miatt háborgatni nem szabad, feltéve, hogy e meggyőződés s e nézetek megnyilvánulása a törvényes rendet nem sérti.\n\nA gondolatok és vélemények szabad közlése az embernek egyik legértékesebb joga; ennélfogva minden polgár szabadon szólhat, írhat s nyomtathat ki bármit, felelősséggel tartozván viszont e szabadsággal való visszaélésért a törvény által meghatározott esetekben. - A nyilatkozat szólásszabadságot és a sajtószabadságot biztosít.\n\nAz ember és a polgár jogainak biztosítása karhatalom fenntartását teszi szükségessé; e karhatalomnak tehát az összesség hasznára kell szolgálnia, nem pedig azoknak külön céljaira, akiknek személyére e karhatalom rábízatik. A polgári jogok megvalósulásához karhatalomra van szükség.\n\nA karhatalom és a közigazgatás költségeinek fedezésére nélkülözhetetlenül szükséges mindenkinek közös hozzájárulása; s e hozzájárulást, kinek-kinek képessége szerint, a polgárok összessége közt egyenlően kell elosztani. - Az amerikai alkotmányhoz hasonlóan megemlíti a karhatalom szükségességét és a közigazgatás fenntartásához szükséges adózás alapelveit, amiben az egyenlőség elve kitüntetett szerepet kap. Lényeges különbség a forradalom előtti időkhöz képest, amikor az egyház és a nemesség mentes volt a legtöbb adónem alól.\n\nA polgároknak saját személyükben vagy képviselők útján joguk van e közös hozzájárulás szükségszerűségét megállapítani s azt szabadon megszavazni, valamint felhasználását nyomon követni, s meghatározni mennyiségét, alapját, elosztását, behajtását és időtartamát.\n\nA társadalomnak joga van a közigazgatás minden tisztviselőjét számadásra vonni.- Meghatározza a nyilvánosság előtti felelősség fogalmát.\n\nAz olyan társadalomnak, amelyből e jogok biztosítékai hiányoznak, s ahol a törvényhozó és a végrehajtó hatalom szétválasztását nem hajtották végre, semmiféle alkotmánya nincs. Ahol mindez hiányzik, annak a társadalomnak nincs alkotmánya.\n\nTulajdonától – lévén a tulajdonjog szent és sérthetetlen – senki meg nem fosztható, legfeljebb csakis oly esetekben, amikor ezt a közösség érdekéből fakadó nyilvánvaló és törvényes úton megállapított szükségesség követeli meg – ám ekkor is csak igazságos és előzetes kártalanítás fejében. A tulajdon szent és sérthetetlen.\n\nA LIBERALIZMUS\n\nA XIX. századi liberális eszme fő elemei:\n\naz egyén fontos szerepe, a tolerancia, az egyenjogúság hangsúlyozása,\n\naz állam háttérbe szorulása (éjjeliőr szerep)\n\na liberalizmus alapja a szabadságeszmény.\n\nA liberalizmus kialakulása összefüggött a kor társadalmi változásaival, a forradalmi mozgalmak segítették terjedését.\n\nA liberalizmus kialakulása összefüggött még a felvilágosodás eszmerendszerével.\n\nA francia forradalom, illetve a napóleoni háborúk segítették terjedését.\n\nA liberális eszme elfogadja az eltérő nézeteket, a különböző életformákat. Egyik képviselője az angol John Stuart Mill:\n\n„Hasznos az, ha eltérő nézetek léteznek, ha szabad teret kapnak a legkülönbözőbb jellemek, míg másoknak nem ártanak, ha mindenki a gyakorlatban próbálja ki a különböző életformák értékét.” (J.S.Mill)\n\nA tolerancia alapja a szabadságeszmény.\n\nA szabadság korlátja a másik ember szabadságának tiszteletben tartása.\n\nA liberális eszme egyik fő eleme az emberek közötti egyenlőség, az egyenjogúság hirdetése pl. választójog megadása, férfi és nő közötti egyenjogúság.\n\nA liberalizmus nem hisz a hagyományokra, erős államra épülő közösségben.\n\nA liberalizmus az egyén szerepét, illetve az ésszerűséget tarja fontosnak.\n\nFontos számára a szabadság és felelősség kapcsolata.\n\nSzabályozza a kormányzati hatalomhoz való viszonyt: az állam szerepét korlátozza.\n\nA liberalizmus a szabad verseny híve - ennek hátterében a kapitalizmus állt.\n\nA 19. századi politikai irányzatai a francia forradalom eszméiből alakultak ki, amelyek átalakították Európa feudális társadalmi berendezkedését. A napóleoni háborúk felélesztették az európai népek nacionalizmusát is. A „szabadság, egyenlőség, testvériség” jelszava, a francia forradalmi eszmék beépültek az európai polgárság politikai törekvéseibe. A bécsi kongresszus (1814–1815) szellemisége ókonzervatív volt ezzel szemben. A kialakuló Szent Szövetség rendszere az 1789 előtti állapotokat szerette volna restaurálni, így a Metternich által működtetett titkosrendőrség és cenzúrahivatal korlátozta a polgári szabadságjogokat, illetve a sajtószabadságot. A liberalizmus politikai áramlata a szabadságeszme megteremtését tűzte ki célul a 19. század első felében. A szabadelvű gondolkodók a felvilágosodás eszméit fejlesztették tovább. Céljuk: a polgári állam megteremtése.\n\nEgyéni szabadságjogok: a tulajdonhoz való jog, a szólás- és véleménynyilvánítási szabadság, a vallásszabadság.\n\nTársadalmi és politikai szabadságjogok: gyülekezés szabadsága, sajtószabadság, parlamentnek felelős kormány.\n\nA 19. századi liberálisok szerint csak a művelt és megfelelő anyagi háttérrel rendelkező polgárság tud működőképes demokráciát kialakítani. Úgy vélték, a polgári állam kiépülése megteremti az alsóbb rétegek felemelkedését, ezután kibővülhet a politizálók köre.\n\nA liberalizmus és a konzervativizmus eszméinek kialakulása összefüggött az ipari forradalom gazdaság- és társadalomalakító tényezőivel, ezért ezek az eszmék meghatározói lettek a XIX. századi pártrendszerek megszületésének. Pl. Anglia: whig (liberális) és tory (konzervatív).\n\nA nacionalizmus összekapcsolódott a liberalizmussal, a szabadsággal és a függetlenséggel.\n\nA nacionalizmus főbb jellemzői és céljai: nemzeti eszme (náció = nemzet) A nacionalizmus lényege a nemzeti összetartozás-tudat, a XIX. század első felében keletkezett, bontakozott ki Európában és Amerikában. A nemzeti eszme forradalmi volt.\n\nAz emberi jogok\n\nAz állampolgári jogok a demokráciákban annyiban választhatók csak külön az emberi jogoktól, hogy míg az állampolgári jogokból egy adott ország polgárai részesülnek, addig az emberi jogok – elvben – egyetemesek. Az emberi jogok kialakulásának, deklarálásának és biztosításának története csaknem kétezer éves. Pál apostol hirdette, hogy Isten előtt minden ember egyenlő, és az emberi élet szent. A középkor századaiban a katolikus kánonjog képviselte az emberi jogok elemeit. Máig érvényes meghatározása a felvilágosodás vívmánya.\n\nAz emberi jogokra vonatkozó első állami dokumentumok a 18. század végén születtek. Az emberi jogok között az első az élethez való jog, de idesorolták az élet olyan területeit, ahol az állam nem korlátozhatja az egyén szabadságát. Ilyen például a gondolkodás, a szabad véleményalkotás, a vallás szabad megválasztása és a másokkal való társulás. Ezek a jogok idővel jelentősen bővültek.\n\nA második világháborút követően az ENSZ Közgyűlése elfogadta az Emberi jogok egyetemes nyilatkozatát (1948), melynek jelentősége az Emberi és polgári jogok nyilatkozatáéval vetekszik. Ezt követően az 1950-ben alakult Európa Tanács elfogadta az Emberi jogok európai egyezményét, amely 1953-ban lépett hatályba. Az egyezmény kötelezte a szervezetben részt vevő államokat, hogy biztosítsák a benne meghatározott jogokat és szabadságokat a joghatóságuk alatt élő minden egyén számára. Ennek végrehajtása érdekében létrehozták az Emberi Jogok Európai Bizottságát (1954), majd az Emberi Jogok Európai Bíróságát (1959). Az utóbbi szervezet ítéleteinek a végrehajtását az Európa Tanács Miniszteri Bizottsága ellenőrzi.\n\n1966-ban az ENSZ Közgyűlése elfogadta a Polgári és politikai jogok és Gazdasági, szociális és kulturális nemzetközi egyezségokmányát. Az 1980-as években született meg az Európa Tanácsban A kínzás és embertelen vagy megalázó büntetések vagy bánásmód megelőzéséről szóló, illetve az ENSZ-ben A gyermekek jogairól szóló egyezmény. Az emberi jogok tehát kellően körülbástyázottak a nemzetközi jogban.\n\nMagyarország alaptörvénye\n\nHazánkban a 2012. január 1-jén hatályba lépett Alaptörvény Szabadság és felelősség című fejezete 31 cikkben sorolja fel az alapvető jogokat és kötelezettségeket, de ezek betartatását külön törvény is biztosítja. Minden magyar állampolgár jogosult arra, hogy igénybe vegye a különféle állami szolgáltatásokat, főleg az egészségügyi, oktatási és művelődési intézményeket, melyeket viszont az adófizető polgárok kötelezően befizetendő járulékaiból tartanak fenn. Az alapfokú és középfokú oktatás igénybevétele mindenki számára ingyenes (az alapfokú kötelező is), míg a felsőoktatás a képességei alapján mindenki számára hozzáférhető. Minden magyar polgárnak joga van külföldre utazni, akár azzal a céllal is, hogy ott letelepedjen. Ugyanakkor háboríthatatlanul tartózkodhat itthon, kiutasítani, más államoknak kiadni nem lehet. Minden állampolgár részt vehet a közügyek gyakorlásában, ami azt is jelenti, hogy 18 év felett választó és választható. A nemzetiségek sajátos jogai közé tartozik az anyanyelv használata, a saját kultúrához és az anyanyelvi oktatáshoz, valamint a helyi és országos önkormányzat alakításához való jog. Természetesen mindez az állampolgári jogok felsorolásának csekély szelete. Az állampolgárokat ugyanakkor kötelességek is terhelik. Ezek közül a legfontosabb a törvények és jogszabályok betartása, az adó fizetése és a honvédelmi kötelezettség. Ez utóbbi lehet fegyveres (a katonai szolgálatot teljesítőké), fegyver nélküli (rendkívüli állapot esetén) és polgári szolgálat (például katasztrófavédelmi feladatok ellátása). Szerepel az Alaptörvényben a szülők gondoskodási kötelessége kiskorú gyermekükről, de a nagykorú gyermek hasonló kötelezettsége is a rászoruló szülőkről. Kötelességünk még az épített és természeti környezet védelme is.\n\nJogvédelem a jogállamban\n\nA jogállam a közhatalom jognak való alávetettségét jelenti, azaz a demokratikusan létrehozott jogszabályok alapján működnek arra felhatalmazott szervezetek és személyek. A demokratikus állam jogállam, melyben a hatalommal bíró emberek sem állnak a jog felett. Kiemelkedően fontos szerepet tölt be a jogvédelem élén az Alkotmánybíróság, az Alaptörvény őre.\n\nFeladata a jogszabályok alkotmányosságának vizsgálata, az alkotmányos rend és az Alkotmányban biztosított alapjogok védelme. Az Alkotmánybíróság a „rendes” (polgári és büntető) bíróságoktól is függetlenül működik, döntéseit nem lehet felülbírálni, kötelező érvényűek. Ennek a 15 fős, az országgyűlési képviselők kétharmados többségével megválasztott testületnek a tagjai kiemelkedő felkészültségű jogászok lehetnek.\n\nA bírói szervezet, az ügyészség és a rendvédelmi szervek (rendőrség, büntetés-végrehajtás, katasztrófavédelem, polgári nemzetbiztonsági szolgálatok) feladata, hogy gondoskodjanak az állampolgárok jogainak védelméről, védjék az alkotmányos rendet, és fellépjenek a bűncselekmények elkövetői ellen. Az igazságszolgáltatás szervei függetlenek.\n\nSajátos, az Országgyűlésnek alárendelve működő szervezet az Állami Számvevőszék, az Országgyűlés legfőbb pénzügyi és gazdasági ellenőrző szerve. Főleg a közpénzekkel, az állami és önkormányzati vagyonnal való felelős gazdálkodás ellenőrzése tartozik a hatáskörébe. Feladata a közpénzekből, állami támogatásból gazdálkodó pártok pénzügyi ellenőrzése is. Viszonylag új szervezet a Költségvetési Tanács, melynek fő feladata az állami költségvetés ellenőrzése. Vétójoggal rendelkezik. Az Országgyűlés alapvető jogok biztosa (svédül ombudsman, jelentése: panaszokat vizsgáló tisztviselő) az emberi és a különböző szabadságjogokkal kapcsolatban tudomására jutott visszásságokat vizsgálja vagy vizsgáltatja ki, és orvoslásukra intézkedéseket hoz. A biztost és az Állami Számvevőszék elnökét is az országgyűlési képviselők kétharmada választja. Az alapvető jogok biztosának két helyettese van. Az egyik a jövő nemzedékek érdekeinek a védelmét ellátó, a másik a nemzetiségek jogainak védelmét ellátó helyettes.\n\nA magyar és európai állampolgárság legfontosabb ismérvei\n\nAz állampolgár valamely állam tagja, akit az állam jogokkal és kötelességekkel ruház fel. Az állampolgárság az adott állam és személy közötti sajátos jogviszonyt jelenti. Az állampolgárságban egyrészt az állami szuverenitás fogalmazódik meg – az egyén államának hatalma alatt áll –, másrészt jelen van benne az államot alkotó polgár szabadsága, és ebben az értelemben az állampolgárság nem egyoldalú, „alávetett” jogviszony. Az állam főhatalom a terület és a lakosság felett. Nemzetközi jogi értelemben a lakosság az állam területén tartózkodó személyek összessége. Ezeken belül az állam saját polgárai az állampolgárok, más állam polgárai a külföldiek, és az állampolgárság nélküliek a hontalanok. Egy állam szuverenitása saját polgáraira terjed ki akkor is, ha azok az országot átmenetileg elhagyják.\n\nKétféleképpen lehet egy adott ország állampolgára valaki. Egyrészt vér szerinti jogon (ius sanguinis), ha a szülők az adott állam polgárai. Amennyiben a szülők különböző államok polgárai, a gyermek mindkét szülő állampolgárságát megszerzi. Másrészt terület szerint (ius soli), ami azt jelenti, hogy az állam területén született egyén megkapja az állampolgárságot. Ez főleg azokra az országokra érvényes, ahová nagyszámú bevándorló érkezik (például Amerikai Egyesült Államok, Kanada). Hazánkban (és Európában) ezt csak sajátos esetekben alkalmazzák (például a talált gyermek magyar állampolgár addig, amíg ki nem derül, hogy kik a szülei).\n\nA kettős állampolgárság és az egyszerűsített magyar honosítás\n\nA kettős (vagy többes) állampolgárság azt jelenti, hogy egy személy egyszerre két (vagy több) államnak is a polgára lehet. Ennek feltétele azonban, hogy az adott államok törvényei ezt a kettős állampolgárságot lehetővé tegyék. Környezetünkben Ausztria és Szlovákia törvényei – különböző okokból – nem engedik a kettős állampolgárságot, Ukrajna alkotmánya pedig nem ismeri ezt a jogállást, tehát nem ismerik el, de nem is büntetik a kettős állampolgárságot.\n\nHazánkban 2011-től a törvények lehetővé teszik a határon túli magyarok számára az egyszerűsített (vagy kedvezményes) honosítási eljárást. Ennek során megkaphatja a magyar állampolgárságot az eredeti megtartása mellett az a személy, aki igazolni tudja magyar származását vagy valószínűsíteni tudja magyarországi származását. Ebben az esetben nem feltétel a magyarországi lakóhely, a megélhetés igazolása és a vizsga az alkotmányos alapismeretekből, mint más olyan esetekben, amikor egy külföldi kívánja felvenni a magyar állampolgárságot. Mindez a nemzetegyesítés jegyében hozott intézkedés. A korábbiakhoz képest 2011-től napjainkig több százezerrel nőtt a magyar állampolgárságot elnyert személyek száma anélkül, hogy az illetők elhagyták volna eredeti lakóhelyüket.\n\nRÉSZLETEK MAGYARORSZÁG ALAPTÖRVÉNYÉBŐL\n\nIsten, áldd meg a magyart! Legyen béke, szabadság és egyetértés.\n\nHatályát veszti a Magyar Köztársaság Alkotmányáról szóló 1949. évi XX. törvény. Az Országgyűlés képviselői, akiket 2010-ben választottak meg, élve alkotmányozó hatalmukkal, Magyarország első egységes Alaptörvényét fogalmazták meg 2011. április 25-én, és 2012. január 1-jén lépett hatályba.\n\nNEMZETI HITVALLÁS *\n\nMI, A MAGYAR NEMZET TAGJAI, az új évezred kezdetén, felelősséggel minden magyarért, kinyilvánítjuk az alábbiakat:\n\nBüszkék vagyunk arra, hogy Szent István királyunk ezer évvel ezelőtt szilárd alapokra helyezte a magyar államot, és hazánkat a keresztény Európa részévé tette.\n\nBüszkék vagyunk az országunk megmaradásáért, szabadságáért és függetlenségéért küzdő őseinkre.\n\nElismerjük a kereszténység nemzetmegtartó szerepét. Becsüljük országunk különböző vallási hagyományait.\n\nÍgérjük, hogy megőrizzük az elmúlt évszázad viharaiban részekre szakadt nemzetünk szellemi és lelki egységét. Kinyilvánítjuk, hogy a velünk élő nemzetiségek a magyar politikai közösség részei és államalkotó tényezők.\n\nTiszteljük más népek szabadságát és kultúráját, együttműködésre törekszünk a világ minden nemzetével.\n\nValljuk, hogy az emberi lét alapja az emberi méltóság.\n\nValljuk, hogy az egyéni szabadság csak másokkal együttműködve bontakozhat ki.\n\nValljuk, hogy a közösség erejének és minden ember becsületének alapja a munka, az emberi szellem teljesítménye.\n\nValljuk, hogy a polgárnak és az államnak közös célja a jó élet, a biztonság, a rend, az igazság, a szabadság kiteljesítése.\n\nValljuk, hogy népuralom csak ott van, ahol az állam szolgálja polgárait, ügyeiket méltányosan, visszaélés és részrehajlás nélkül intézi.\n\nTiszteletben tartjuk történeti alkotmányunk vívmányait és a Szent Koronát, amely megtestesíti Magyarország alkotmányos állami folytonosságát és a nemzet egységét.\n\nValljuk, hogy a történeti alkotmányunkban gyökerező önazonosságunk védelmezése az állam alapvető kötelessége.\n\nNem ismerjük el történeti alkotmányunk idegen megszállások miatt bekövetkezett felfüggesztését. Tagadjuk a magyar nemzet és polgárai ellen a nemzetiszocialista és a kommunista diktatúra uralma alatt elkövetett embertelen bűnök elévülését.\n\nNem ismerjük el az 1949. évi kommunista alkotmányt, mert egy zsarnoki uralom alapja volt, ezért kinyilvánítjuk érvénytelenségét.\n\nEgyetértünk az első szabad Országgyűlés képviselőivel, akik első határozatukban kimondták, hogy mai szabadságunk az 1956-os forradalmunkból sarjadt ki.\n\nHazánk 1944. március tizenkilencedikén elveszített állami önrendelkezésének visszaálltát 1990. május másodikától, az első szabadon választott népképviselet megalakulásától számítjuk. Ezt a napot tekintjük hazánk új demokráciája és alkotmányos rendje kezdetének.\n\nAlaptörvényünk jogrendünk alapja, szövetség a múlt, a jelen és a jövő magyarjai között. Élő keret, amely kifejezi a nemzet akaratát, azt a formát, amelyben élni szeretnénk.\n\nMi, Magyarország polgárai készen állunk arra, hogy országunk rendjét a nemzet együttműködésére alapítsuk.\n\nALAPVETÉS\n\nHAZÁNK neve Magyarország.\n\n(1) Magyarország független, demokratikus jogállam.\n\n(2) Magyarország államformája köztársaság.\n\n(3) A közhatalom forrása a nép.\n\n(4) A nép a hatalmát választott képviselői útján, kivételesen közvetlenül gyakorolja. (1) A magyar állam működése a hatalom megosztásának elvén alapszik.\n\nMagyarország az egységes magyar nemzet összetartozását szem előtt tartva felelősséget visel a határain kívül élő magyarok sorsáért,\n\n(1) Magyarország az európai népek szabadságának, jólétének és biztonságának kiteljesedése érdekében közreműködik az európai egység megteremtésében.\n\n(2) * Magyarország az Európai Unióban tagállamként való részvétele érdekében nemzetközi szerződés alapján - az alapító szerződésekből fakadó jogok gyakorlásához és kötelezettségek teljesítéséhez szükséges mértékig - az Alaptörvényből eredő egyes hatásköreit a többi tagállammal közösen, az Európai Unió intézményei útján gyakorolhatja. Az e bekezdés szerinti hatáskörgyakorlásnak összhangban kell állnia az Alaptörvényben foglalt alapvető jogokkal és szabadságokkal, továbbá nem korlátozhatja Magyarország területi egységére, népességére, államformájára és állami berendezkedésére vonatkozó elidegeníthetetlen rendelkezési jogát.\n\n(4) A (2) bekezdés szerinti nemzetközi szerződés kötelező hatályának elismerésére adott felhatalmazáshoz az országgyűlési képviselők kétharmadának szavazata szükséges. *\n\n(1) Magyarország fővárosa Budapest.\n\n(2) Magyarország védelmezi állampolgárait.\n\n(3) Senkit nem lehet születéssel keletkezett vagy jogszerűen szerzett magyar állampolgárságától megfosztani.\n\n(1) Magyarországon a hivatalos nyelv a magyar.\n\n(1) Magyarország címere hegyes talpú, hasított pajzs. Első mezeje vörössel és ezüsttel hétszer vágott. Második, vörös mezejében zöld hármas halomnak arany koronás kiemelkedő középső részén ezüst kettős kereszt. A pajzson a magyar Szent Korona nyugszik.\n\n(2) Magyarország zászlaja három, egyenlő szélességű, sorrendben felülről piros, fehér és zöld színű, vízszintes sávból áll, amelyben a piros szín az erő, a fehér szín a hűség, a zöld szín a remény jelképe.\n\n(3) Magyarország himnusza Kölcsey Ferenc Himnusz című költeménye Erkel Ferenc zenéjével.\n\n(1) Magyarország nemzeti ünnepei:\n\na) március 15. napja, az 1848-49. évi forradalom és szabadságharc emlékére;\n\nb) augusztus 20. napja, az államalapítás és az államalapító Szent István király emlékére;\n\nc) október 23. napja, az 1956. évi forradalom és szabadságharc emlékére.\n\n(2) A hivatalos állami ünnep augusztus 20. napja.\n\nMagyarország hivatalos pénzneme a forint.\n\n(1) * Magyarország védi a házasság intézményét mint egy férfi és egy nő között, önkéntes elhatározás alapján létrejött életközösséget, valamint a családot mint a nemzet fennmaradásának alapját. A családi kapcsolat alapja a házasság, illetve a szülő-gyermek viszony. Az anya nő, az apa férfi.\n\n(2) Magyarország támogatja a gyermekvállalást.\n\n(3) A családok védelmét sarkalatos törvény szabályozza. *\n\n(1) Magyarország gazdasága az értékteremtő munkán és a vállalkozás szabadságán alapszik.\n\n(2) Magyarország biztosítja a tisztességes gazdasági verseny feltételeit. Magyarország fellép az erőfölénnyel való visszaéléssel szemben, és védi a fogyasztók jogait.\n\n(1) Magyarország a kiegyensúlyozott, átlátható és fenntartható költségvetési gazdálkodás elvét érvényesíti.\n\n(1) Alaptörvény elfogadására vagy az Alaptörvény módosítására irányuló javaslatot a köztársasági elnök, a Kormány, országgyűlési bizottság vagy országgyűlési képviselő terjeszthet elő.\n\n(2) Alaptörvény elfogadásához vagy az Alaptörvény módosításához az országgyűlési képviselők kétharmadának szavazata szükséges.\n\nHa a köztársasági elnök úgy ítéli meg, hogy az Alaptörvénynek vagy az Alaptörvény módosításának a megalkotására vonatkozó, az Alaptörvényben foglalt eljárási követelményeket nem tartották meg, ennek vizsgálatát kéri az Alkotmánybíróságtól.\n\n(1) * Általánosan kötelező magatartási szabályt az Alaptörvény és az Alaptörvényben megjelölt, jogalkotó hatáskörrel rendelkező szerv által megalkotott, a hivatalos lapban kihirdetett jogszabály állapíthat meg. Sarkalatos törvény eltérően is megállapíthatja az önkormányzati rendelet és a különleges jogrendben alkotott jogszabályok kihirdetésének szabályait. *\n\n(1) Az 1990-ben lezajlott első szabad választások révén a nemzet akaratából létrehozott, a jog uralmán alapuló állami berendezkedés és a megelőző kommunista diktatúra összeegyeztethetetlenek.\n\nSZABADSÁG ÉS FELELŐSSÉG\n\n(1) AZ EMBER sérthetetlen és elidegeníthetetlen alapvető jogait tiszteletben kell tartani. Védelmük az állam elsőrendű kötelezettsége.\n\n(2) Magyarország elismeri az ember alapvető egyéni és közösségi jogait.\n\nAz emberi méltóság sérthetetlen. Minden embernek joga van az élethez és az emberi méltósághoz, a magzat életét a fogantatástól kezdve védelem illeti meg.\n\n(1) Senkit nem lehet kínzásnak, embertelen, megalázó bánásmódnak vagy büntetésnek alávetni, valamint szolgaságban tartani. Tilos az emberkereskedelem.\n\n(1) Mindenkinek joga van a szabadsághoz és a személyi biztonsághoz.\n\nMindenkinek joga van törvényben meghatározottak szerint a személye, illetve a tulajdona ellen intézett vagy az ezeket közvetlenül fenyegető jogtalan támadás elhárításához.\n\n(1) Mindenkinek joga van ahhoz, hogy magán- és családi életét, otthonát, kapcsolattartását és jó hírnevét tiszteletben tartsák. A véleménynyilvánítás szabadsága és a gyülekezési jog gyakorlása nem járhat mások magán- és családi életének, valamint otthonának sérelmével. (3) Mindenkinek joga van személyes adatai védelméhez, valamint a közérdekű adatok megismeréséhez és terjesztéséhez.\n\n(1) Mindenkinek joga van a gondolat, a lelkiismeret és a vallás szabadságához\n\n(1) Mindenkinek joga van a békés gyülekezéshez.\n\n(2) Mindenkinek joga van szervezeteket létrehozni, és joga van szervezetekhez csatlakozni.\n\n(3) Pártok az egyesülési jog alapján szabadon alakulhatnak és tevékenykedhetnek.\n\n(1) Mindenkinek joga van a véleménynyilvánítás szabadságához.\n\n(2) Magyarország elismeri és védi a sajtó szabadságát és sokszínűségét, biztosítja a demokratikus közvélemény kialakulásához szükséges szabad tájékoztatás feltételeit.\n\n(3) * (4) * A véleménynyilvánítás szabadságának a gyakorlása nem irányulhat mások emberi méltóságának a megsértésére.\n\n(5) * A véleménynyilvánítás szabadságának a gyakorlása nem irányulhat a magyar nemzet, a nemzeti, etnikai, faji vagy vallási közösségek méltóságának a megsértésére.\n\n(1) Magyarország biztosítja a tudományos kutatás és művészeti alkotás szabadságát, továbbá - a lehető legmagasabb szintű tudás megszerzése érdekében - a tanulás, valamint törvényben meghatározott keretek között a tanítás szabadságát.\n\n(1) Minden magyar állampolgárnak joga van a művelődéshez.\n\n(2) Magyarország ezt a jogot a közművelődés kiterjesztésével és általánossá tételével, az ingyenes és kötelező alapfokú, az ingyenes és mindenki számára hozzáférhető középfokú, valamint a képességei alapján mindenki számára hozzáférhető felsőfokú oktatással, továbbá az oktatásban részesülők törvényben meghatározottak szerinti anyagi támogatásával biztosítja.\n\n(1) Mindenkinek joga van a munka és a foglalkozás szabad megválasztásához, valamint a vállalkozáshoz. Képességeinek és lehetőségeinek megfelelő munkavégzéssel mindenki köteles hozzájárulni a közösség gyarapodásához.\n\n(1) Mindenkinek joga van a tulajdonhoz és az örökléshez. A tulajdon társadalmi felelősséggel jár.\n\n(1) * Magyarországra idegen népesség nem telepíthető be.\n\n(2) * Magyar állampolgár Magyarország területéről nem utasítható ki, és külföldről bármikor hazatérhet. Magyarország területén tartózkodó külföldit csak törvényes határozat alapján lehet kiutasítani. Tilos a csoportos kiutasítás.\n\n(5) * A menedékjog biztosításának alapvető szabályait sarkalatos törvény határozza meg.\n\n(1) A törvény előtt mindenki egyenlő. Minden ember jogképes.\n\n(2) Magyarország az alapvető jogokat mindenkinek bármely megkülönböztetés, nevezetesen faj, szín, nem, fogyatékosság, nyelv, vallás, politikai vagy más vélemény, nemzeti vagy társadalmi származás, vagyoni, születési vagy egyéb helyzet szerinti különbségtétel nélkül biztosítja.\n\n(3) A nők és a férfiak egyenjogúak.\n\n(1) * Minden gyermeknek joga van a megfelelő testi, szellemi és erkölcsi fejlődéséhez szükséges védelemhez és gondoskodáshoz. Magyarország védi a gyermekek születési nemének megfelelő önazonossághoz való jogát, és biztosítja a hazánk alkotmányos önazonosságán és keresztény kultúráján alapuló értékrend szerinti nevelést.\n\n(2) A szülőknek joguk van megválasztani a gyermeküknek adandó nevelést.\n\n(3) A szülők kötelesek kiskorú gyermekükről gondoskodni. E kötelezettség magában foglalja gyermekük taníttatását.\n\n(4) A nagykorú gyermekek kötelesek rászoruló szüleikről gondoskodni.\n\n(1) A munkavállalók és a munkaadók - a munkahelyek biztosítására, a nemzetgazdaság fenntarthatóságára és más közösségi célokra is figyelemmel - együttműködnek egymással.\n\n(2) (3) Minden munkavállalónak joga van az egészségét, biztonságát és méltóságát tiszteletben tartó munkafeltételekhez.\n\n(4) Minden munkavállalónak joga van a napi és heti pihenőidőhöz, valamint az éves fizetett szabadsághoz.\n\n(1) Gyermekek foglalkoztatása - testi, szellemi és erkölcsi fejlődésüket nem veszélyeztető, törvényben meghatározott esetek kivételével - tilos\n\n(1) * Magyarország arra törekszik, hogy minden állampolgárának szociális biztonságot nyújtson. Anyaság, betegség, rokkantság, fogyatékosság, özvegység, árvaság és önhibáján kívül bekövetkezett munkanélküliség esetén minden magyar állampolgár törvényben meghatározott támogatásra jogosult.\n\n(4) Magyarország az időskori megélhetés biztosítását a társadalmi szolidaritáson alapuló egységes állami nyugdíjrendszer fenntartásával és önkéntesen létrehozott társadalmi intézmények működésének lehetővé tételével segíti elő.\n\n(1) Mindenkinek joga van a testi és lelki egészséghez.\n\n(1) Magyarország elismeri és érvényesíti mindenki jogát az egészséges környezethez.\n\n(1) * Az állam jogi védelemben részesíti az otthont. Magyarország törekszik arra, hogy az emberhez méltó lakhatás feltételeit és a közszolgáltatásokhoz való hozzáférést mindenki számára biztosítsa.\n\n(3) * Tilos az életvitelszerű közterületen tartózkodás\n\n(1) Minden nagykorú magyar állampolgárnak joga van ahhoz, hogy az országgyűlési képviselők, a helyi önkormányzati képviselők és polgármesterek, valamint az európai parlamenti képviselők választásán választó és választható legyen.\n\n(2) Az Európai Unió más tagállamának magyarországi lakóhellyel rendelkező minden nagykorú állampolgárának joga van ahhoz, hogy a helyi önkormányzati képviselők és polgármesterek, valamint az európai parlamenti képviselők választásán választó és választható legyen.\n\n(3) Magyarországon menekültként, bevándoroltként vagy letelepedettként elismert minden nagykorú személynek joga van ahhoz, hogy a helyi önkormányzati képviselők és polgármesterek választásán választó legyen.\n\n(4) Sarkalatos törvény a választójogot vagy annak teljességét magyarországi lakóhelyhez, a választhatóságot további feltételekhez kötheti. *\n\n(5) A helyi önkormányzati képviselők és polgármesterek választásán a választópolgár lakóhelyén vagy bejelentett tartózkodási helyén választhat. A választópolgár a szavazás jogát lakóhelyén vagy bejelentett tartózkodási helyén gyakorolhatja.\n\n(6) Nem rendelkezik választójoggal az, akit bűncselekmény elkövetése vagy belátási képességének korlátozottsága miatt a bíróság a választójogból kizárt. Nem választható az Európai Unió más tagállamának magyarországi lakóhellyel rendelkező állampolgára, ha az állampolgársága szerinti állam jogszabálya, bírósági vagy hatósági döntése alapján hazájában kizárták e jog gyakorlásából.\n\n(7) Mindenkinek joga van országos népszavazáson részt venni, aki az országgyűlési képviselők választásán választó. Mindenkinek joga van helyi népszavazáson részt venni, aki a helyi önkormányzati képviselők és polgármesterek választásán választó.\n\n(8) Minden magyar állampolgárnak joga van ahhoz, hogy rátermettségének, képzettségének és szakmai tudásának megfelelően közhivatalt viseljen. Törvény határozza meg azokat a közhivatalokat, amelyeket párt tagja vagy tisztségviselője nem tölthet be.\n\n(7) Mindenkinek joga van ahhoz, hogy jogorvoslattal éljen az olyan bírósági, hatósági és más közigazgatási döntés ellen, amely a jogát vagy jogos érdekét sérti.\n\n(1) A Magyarországon élő nemzetiségek államalkotó tényezők. Minden, valamely nemzetiséghez tartozó magyar állampolgárnak joga van önazonossága szabad vállalásához és megőrzéséhez. A Magyarországon élő nemzetiségeknek joguk van az anyanyelvhasználathoz, a saját nyelven való egyéni és közösségi névhasználathoz, saját kultúrájuk ápolásához és az anyanyelvű oktatáshoz.\n\n(2) A Magyarországon élő nemzetiségek helyi és országos önkormányzatokat hozhatnak létre.\n\n(1) Minden magyar állampolgár köteles a haza védelmére.\n\n(2) Magyarország önkéntes honvédelmi tartalékos rendszert tart fenn.\n\n(4) Magyarországi lakóhellyel rendelkező, nagykorú magyar állampolgárok számára rendkívüli állapot idejére - sarkalatos törvényben meghatározottak szerint - honvédelmi munkakötelezettség írható elő.\n\n(5) Magyarországi lakóhellyel rendelkező, nagykorú magyar állampolgárok számára honvédelmi és katasztrófavédelmi feladatok ellátása érdekében - sarkalatos törvényben meghatározottak szerint - polgári védelmi kötelezettség írható elő. *\n\n(6) Honvédelmi és katasztrófavédelmi feladatok ellátása érdekében - sarkalatos törvényben meghatározottak szerint - mindenki gazdasági és anyagi szolgáltatás teljesítésére kötelezhető. *\n\nAZ ÁLLAM – a 3 hatalmi ág szétválasztása. törvényhozó, végrehajtó (kormány), igazságszolgáltató.\n\n(1) MAGYARORSZÁG legfőbb népképviseleti szerve az Országgyűlés.\n\n(2) Az Országgyűlés\n\na) megalkotja és módosítja Magyarország Alaptörvényét;\n\nb) törvényeket alkot;\n\nc) elfogadja a központi költségvetést, és jóváhagyja annak végrehajtását;\n\nd) felhatalmazást ad a feladat- és hatáskörébe tartozó nemzetközi szerződés kötelező hatályának elismerésére;\n\ne) * megválasztja a köztársasági elnököt, az Alkotmánybíróság tagjait és elnökét, a Kúria elnökét, az Országos Bírósági Hivatal elnökét, a legfőbb ügyészt, az alapvető jogok biztosát és helyetteseit, valamint az Állami Számvevőszék elnökét;\n\nf) megválasztja a miniszterelnököt, dönt a Kormánnyal kapcsolatos bizalmi kérdésről;\n\ng) feloszlatja az alaptörvény-ellenesen működő képviselő-testületet;\n\nh) határoz a hadiállapot kinyilvánításáról és a békekötésről;\n\ni) különleges jogrendet érintő, valamint katonai műveletekben való részvétellel kapcsolatos döntéseket hoz;\n\nj) közkegyelmet gyakorol;', 299, 1, '2026-04-17 09:40:23', '2026-04-17 09:40:23');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(15, 15, 'A modern demokráciák 17-18. századi gyökerei', '15.docx', '15. tétel: A modern demokráciák 17-18. századi gyökerei\n\n(angol alkotmányos monarchia, az USA alkotmánya)\n\nAz angol alkotmányos monarchia\n\nElőzmények:\n\nAz alkotmányos monarchia Angliában jött létre először a XVII. században. Angliában alakult ki a kapitalizmus is a XVI. században. A mezőgazdaság és az ipar tőkés átalakulása után a politikai rendszer is átalakulást indukált. Angliában ugyanis abszolutizmus volt: Stuart I. Jakab (1603-1625) 1611-től nem hívta össze a parlamentet, kegyencével, Buckingham herceggel kormányzott.\n\nI. Károly (1625-49) folytatta apja abszolutizmusát, de 1628-ban össze kellett hívnia a parlamentet, amely az adók megszavazása helyett azonban a Jogok Kérvényét (Petition of Rights) állította össze, mire a király ismét feloszlatta.\n\nParlamenti szakasz (1640-42):\n\n• A királynak ismét adómegszavazásra volt szüksége a skót felkelés miatt: 1640. ápr. 13.: „Rövid” parlament összehívása, majd feloszlatása.\n\n1640. nov. 3.: „Hosszú” parlament összehívása: a király kénytelen volt elfogadni a parlamenti ellenzék, a puritánok (kerekfejűek) követeléseit.\n\n• Utcai harcok kezdődtek a kerekfejűek és a gavallérok (királypártiak) között.\n\nPolgárháború (1642-49)\n\n• 1642. jan. 10-én a király Észak-Angliába szökött Londonból, ezzel kitört a polgárháború.\n\nA polgárháború során (1642-1649) a parlament tábora volt az erősebb, és főleg a gazdagabb. Ezt támogatták az iparilag fejlett déli, délkeleti országrészek, a virágzó városok, a hajóhad. A király csak a fejletlenebb nyugati és északi területek nemességére, a meggyöngült anglikán egyházra és - felesége révén - némi francia támogatásra számíthatott.\n\nAz abszolutizmus fölszámolása után azonban a parlament egysége megbomlott. Az újnemességre és a jómódú polgárságra támaszkodó presbiteriánusok a megegyezést keresték a királlyal. A presbiteriánus hadvezérek vereséget szenvedtek. 1642-ben Edge-hillnél: a király seregei győztek. A király lovassága és „fehérkabátos” gyalogsága Londont fenyegette.\n\nEzután Olivér Cromwell vezetésével megszervezték a New Modell Armyt. A parlament independens szárnya így magához ragadta a kezdeményezést az új mintájú hadsereggel. A katonákat a jómódú parasztokból és kézművesekből toborozták. A fanatikus puritán harcosok jelszava: „Bízz Istenben és tartsd szárazon a puskaport!” A harcok egészen 1648-ig elhúzódtak. A skótok először az angol parlament, utóbb a király oldalán küzdöttek (aki ismételten polgárháborút támasztott). A döntő ütközeteket - Marston Moor, Nasbey és Preston mellett Cromwell nagyszerű katonái sorra megnyerték: 1644. júl. 2.: Marston Moor; 1645. jún. 14.: Naseby.\n\n• A király Skóciába szökött, majd tárgyalásokat kezdett Cromwellel.\n\nA mérsékelt puritán parlamenti képviselők (presbiteriánusok) támogatták a megegyezést, a király mellé akartak állni; a radikálisabb hadsereg (independensek) viszont elutasította. A győzelmek a presbiteriánusok és independensek ellentétét tovább élezték. Nehezítette Cromwell helyzetét, hogy egyre erőteljesebben jelentkezett a levellerek (egyenlősítők) kistulajdonosi irányzata, amely teljes jogegyenlőséget, és polgári köztársaságot akart. Cromwell azonban összefogott a levellerekkel, lezárta a hadműveleteket.\n\nMiután a hadsereg 1648-ban Prestonnál újra legyőzte a királyi csapatokat, és a győztes forradalmi hadsereggel bevonult Londonba (1648. december 2.).\n\nA királlyal kiegyező 150 presbiteriánus képviselőt dragonyosok távolították el a parlamentből, amelyben mindössze 100 independens képviselő maradt: „csonka parlament”. A király a hadsereg foglya lett. Ezután a királyt bíróság elé állították, és halálra ítélték, majd 1649. jan. 30-án kivégezték. Elhárultak az akadályok a tőkés fejlődés, a szabad vállalkozás kibontakozása elől. Ezért játszódott le Angliában polgári forradalom.\n\nKöztársaság (1649-60)\n\n• Anglia a király kivégzése után köztársaság lett, amit a Cromwell által vezetett 41 tagú államtanács irányított.\n\nCromwell a leveller katonák zendüléseit letörte, és a leveller irányzatot fölszámolta.\n\nA népi mozgalmak letörése az angol forradalom történetében a fordulópontot jelenti. A forradalomban eddig mindig a radikálisabb irányzat (és társadalmi réteg) került hatalomra, szövetségben az alatta állóval. A levellerek mozgalmának elfojtásával a polgári köztársaság támogatóinak száma megfogyatkozott.\n\nA fegyvereket ezután Cromwell az ír fölkelők ellen fordította. A háborúban Írország lakossága felére csökkent, a „zöld sziget” nagyobb részét az angol telepesek gyarmatává tette. Skócia is hasonló sorsra jut, bár a helyi vezető réteget ott az angolok nem számolták föl. Miután leverték az írek és a skótok ellenállását, az angol katonai sikerek nyomán létrejött Anglia, Skócia és Írország politikai egysége - a későbbi Nagy-Britannia. A hatalmi vetélkedésben és a belső nyomással szemben megnőtt a hadsereg szerepe, fejlesztette a hadiflottát is.\n\n- 1651-ben kiadták a „Hajózási törvényeket”, amelyek a holland tengeri kereskedelmi fölényt voltak hivatottak megtörni. Ez „a tenger fuvarosaival” sorozatos tengeri háborúkhoz vezetett. Rövid háború után, 1654-ben Hollandia a törvények betartására kényszerült.\n\n• Az újabb tömegmozgalmak (pl. diggerek - ásók) hatására, Cromwell 1653-ban szétzavarta a döntésképtelennek bélyegzett „csonka, parlamentet”, majd új alkotmányt fogadtatott el, amelyben megkapta az „állam védnöke” - Lord Protector címet.\n\n• Cromwell 1655-től katonai diktatúrát vezetett be, a parlamentet csak néha hívta össze. 1658-ban Cromwell meghalt, fia Richárd követte, aki azonban hatalmát megtartani nem tudta.\n\nA restauráció (1660-88)\n\n• A hadsereg 1660-ban bevonult Londonba, új parlamentet hívtak össze, amely visszahívta a trónra a Stuartokat (I. Károly fiát).\n\n• II. Károly (1660-1685) tervbe vette az abszolutizmus visszaállítását, és kísérletet tett a katolikusok egyenjogúsítására. Válaszul a parlament elfogadta a Test Act-et (1673), amely kizárta a katolikusokat a hivatalviselésből. A király önkényeskedései nyomán született meg a Habeas Corpus Act, amely a bíráskodást szabályozta.\n\n• II. Jakab (1685-88) folytatta apja politikáját (ő már katolikus vallású volt). II. Károly, és különösen utódja, II. Jakab semmit sem tanultak elődjük végzetéből. A tulajdonviszonyokat ugyan nem merték megbolygatni, de a parlamentet fokozatosan kikapcsolták a kormányzásból. A király 1687-ben teljes vallási türelmet hirdetett, amelyet a parlament és az anglikán egyház is a katolikus hatalomátvétel előkészítéseként értelmezett. A parlament ezért meghívta a trónra a király protestáns hiten megmaradt lányának, Máriának a férjét, Orániai Vilmost, Hollandia kormányzóját.\n\nA dicsőséges forradalom (1688-89)\n\nAZ ANGOL ALKOTMÁNYOS MONARCHIA KIALAKULÁSA\n\n• Az angol alkotmányos monarchia kialakulását megelőzte az angol polgári forradalom 1640-ben, majd a polgárháború, amely 1642-49. között zajlott. Ezt Cromwell diktatúrája követte, utána 1660-88 között pedig a Stuart-restauráció, melyet az 1688/89-es dicsőséges forradalom követett.\n\nOrániai Vilmost - aki Stuart Mária férje volt, és Hollandia helytartója - meghívják a trónra. Orániai Vilmos 1688. nov. 5-én seregeivel partra szállt Angliában, és harc nélkül elfoglalhatta a trónt: „dicsőséges” vagy „vér nélküli” forradalom. II. Jakab Franciaországba szökött. A dicsőséges forradalom zárta le végleg a polgárháborút, a Stuart-abszolutizmus, és ez után alakult ki az alkotmányos rendszer.\n\nVilmos feleségével 1689-ben elfogadta az Angliát alkotmányos királysággá alakító Jognyilatkozatot, majd III. Vilmos néven királlyá koronázták (1688-1706). A Stuart dinasztiát a Hannoveri-dinasztia váltotta fel.\n\n• A Londonban összehívott parlament 1689. december 16-án cikkelyezte be a Jogok törvényét (Bill of Rights), amelynek rendelkezései meghatározták az alkotmányos monarchia alapelveit, intézményeit és a később hozott törvényeket.\n\nA király:\n\n• „A király uralkodik, de nem kormányoz”, az állam élén álló király kezében nem összpontosult valódi hatalom, a parlament lett az állam életének az igazi irányítója. Ezzel korlátozták a király hatalmát, hiszen a parlament válik a legfőbb hatalmi szervvé.\n\n• A törvényhozói és bírói hatalom függetlenedett a királytól.\n\n• A királynak szentesítő és korlátozott vétójoga van. Formálisan szentesíti a törvényeket, kinevezi a miniszterelnököt. A felvilágosult államelméletek mintája lesz ez a rendszer.\n\nAz államháztartás költségeit különválasztották a királyi udvar költségeitől, és ezt is a parlament hagyta jóvá.\n\n• A király, a parlament és a kormány közötti munkamegosztás csak évtizedek alatt formálódott ki: a király a XVIII. század második felétől már nem vett részt a kormány ülésein.\n\nVégrehajtó hatalom: a kormány\n\n• a választásokon győztes párt vezetőjét a király nevezte ki miniszterelnöknek, de a parlament beleegyezésével; a parlamentnek tartoztak felelősséggel a kormány tagjai.\n\nA miniszterek egy-egy részterületet irányítottak, de a kormány tetteiért közösen vállalták a felelősséget a parlament előtt.\n\nKialakul a miniszterelnöki pozíció, a kabinetrendszer.\n\nA miniszterelnök felel a teljes végrehajtásért.\n\nA király csak a miniszterelnököt nevezi ki.\n\nEgypárti kormányok működnek. A whig és tory párt versenyzett a kormányalakításért\n\nParlament – törvényhozó hatalom\n\nA törvényeket a 3 évenként szabadon választott és rendszeresen ülésező parlament alkotja, rendelkezik a hadsereggel és a pénzügyekkel.\n\nA parlament továbbra is kétkamarás: Lordok Házából és Közrendűek Házából áll.\n\nA király formálisan szentesíti a törvényeket.\n\nCsak a parlament módosíthatja és vonhatja vissza a törvényeket.\n\nA parlament által megszavazott és elfogadott törvényeket kötelező végrehajtani.\n\nParlamenti váltógazdálkodás alakult ki két párt között.\n\nA parlamenti többségben lévő párt vezetője lesz a miniszterelnök.\n\nA whigek a városi, kereskedői érdekeket képviselték a parlamentben, ők a Liberális Párt.\n\nA toryk a vidéki földbirtokos érdekeket képviselték, ők a Konzervatív Párt.\n\nMár nem rendi kiváltságokhoz kötötték a választójogot.\n\nA vagyoni cenzus értéke csökkenni fog.\n\nCsak a társadalom töredékének volt választójoga.\n\nProbléma volt a választókerületek aránytalansága.\n\nMinden választókerületben a többségi rendszer működött: a többséget kapott jelölt lesz a képviselő.\n\nA vesztes jelöltekre adott szavazatok elvesznek, a rendszer a győztes javára torzít.\n\nÍgy a kisebb pártoknak nincs esélyük, hogy bejussanak a parlamentbe.\n\nEz a rendszer a kétpártrendszernek, a nagy gyűjtőpártoknak kedvez.\n\nEz segíti a stabil kormányzást, és egyértelmű kormányzati alternatívát kínál.\n\nTilos parlamenti hozzájárulás nélkül adóztatni, hadsereget fenntartani, ebből alakul ki a felelős kormányzás gyakorlata.\n\nIgazságszolgáltató hatalom\n\n• A polgárok szabadságát biztosító törvény (Habeas Corpus) kimondta, hogy\n\nvádemelés nélkül senkit sem lehet őrizetben tartani,\n\na törvény korlátozza a vádemelés előtti fogva tartást,\n\nbiztosítható az ártatlanság vélelme,\n\na sheriffeknek engedelmeskedniük kell a bíróság utasításainak,\n\nérvényesült a szabadsághoz való jog,\n\nszabadságjogok: szólásszabadság, gyülekezési szabadság, érvényesül a protestánsok vallásszabadsága – de a katolikusokra korlátozó intézkedések vonatkoznak.\n\nÉrvényesül a törvény előtti egyenlőség.\n\nAz állam tiszteletben tartja a tulajdonjogot.\n\nAz igazságszolgáltatás elválik a végrehajtástól.\n\nAz igazságszolgáltatás ellenőrzi a végrehajtást, amely a jogállamiság biztosítéka.\n\n1707-ben egyesül Anglia és Skócia, melyből létrejön Nagy-Britannia.\n\nNagy-Britannia és Észak-Írország egyesülésével pedig létrejön az Egyesült Királyság. Az egyesülések a parlamentek egyesülését is jelentette. Skócia esetében egyenjogúságot, Írországnál viszont alávetettséget jelentett. Az egyesítést még Oliver Cromwell hódításai tették lehetővé.\n\nAz 1707-es Uniós törvények kimondták, hogy Anglia, Wales és Skócia királysága Nagy-Britannia néven egyesül egy királyságba. Az Egyesült Királyság kifejezést alkalmanként használták Nagy-Britannia szinonimájaként, de a hivatalos neve 1800-ig Nagy-Britannia volt. Az 1800-as törvények a következő évben egyesítették Nagy-Britannia és Írország királyságát, amelyek az Egyesült Királyságot, hivatalos nevén Nagy-Britannia és Észak-Írország Egyesült Királyságát megalkották.\n\n• Parlamentarizmus = anarchia? A XVIII. században is még sokan úgy gondolták, hogy ahol a királyi hatalom gyenge, ott anarchia uralkodik (pl. Lengyelország). Anglia erre azonban rácáfolt - a szabadság és a rend együttesen létezett, a kulcsfontosságú pénzügyeket is eredményesen irányították.\n\n• Parlamentarizmus = demokrácia? A parlamenti kormányzás még nem egyenlő a demokráciával, hiszen a választások vagyoni cenzushoz voltak kötve (jómódú birtokosok, jómódú birtokosokat küldtek a parlamentbe), a választókörzetek a népességhez viszonyítva aránytalanul voltak kialakítva, és a választásokon rendszeresen előfordultak csalások.\n\nA francia felvilágosodás képviselői mintának tekintették az angol társadalmi átalakulást.\n\nAz angol alkotmányos monarchia kormányzati rendszerének összefoglalása:\n\nA forradalom és a restauráció alatt többféle kormányzati rendszer került kipróbálásra,\n\naz átalakulás a „dicsőséges forradalom” és a Jognyilatkozat elfogadása zárta le.\n\nAz alkotmányos királyság rendszerében a parlamentnek felelős kormány játszotta a főszerepet.\n\nAz uralkodó szerepe névleges volt: a király uralkodik, de nem kormányoz.\n\nA végrehajtó hatalom a kormány kezében összpontosul.\n\nA királyi hatalmat a választott törvényhozás ellenőrizte. A parlament jogot formál az állam ügyeibe való beleszólásra, és ennek garanciájaként fogalmazták meg a Jogok törvényét.\n\nA rendszer támogatói a polgárság mellett a nemesség (az arisztokrácia) vállalkozásokból élő rétegéből kerültek ki.\n\nA választójog magas vagyoni cenzushoz kapcsolódott. Az arisztokrácia domináns szerepet játszott az angol társadalomban, az arisztokraták polgári vállalkozóként is gazdálkodtak.\n\nAz alkotmányos monarchia elemei: a miniszterelnököt a király nevezi ki a többségi képviselőcsoportból.\n\nAz igazságszolgáltatás független volt a másik két hatalmi ágtól.\n\nA hatalmi ágak szétválasztása volt az alkotmányos rendszer egyik alapja.\n\nAz alkotmányos monarchia elméleti kidolgozásában John Locke játszott főszerepet, legfőbb gondolata a hatalommegosztásról és a közjóról szól.\n\nAZ USA KIALAKULÁSA\n\nÉszak-Amerikának azon a területein, ahová a spanyol gyarmatosítás nem ért el, a XVII. századtól egyre nagyobb számban jöttek létre angol, illetve francia telepek.\n\n1587: az első angol gyarmat, Virginia megalapítása (1606), majd 1620-ban a Mayflower hajó puritán utasai Észak-Amerikában megalapították Plymouth városát, és megindult a keleti partvidék benépesítése.\n\nÉszak-Amerika keleti partvidékén 1606-tól (Virginia) 1733-ig tizenhárom angol gyarmat alakult ki, amelyek rendkívül gyorsan fejlődtek az Angliából folyamatosan érkező kivándorlásnak köszönhetően. A gyarmatok társadalma alapvetően agrár jellegű volt. Mivel a gyarmatok késői felfedezése miatt eleve kikerülték a feudális termelési módot, azonnal a tőkés árutermelés alakult ki rajtuk, amit megkönnyített a földbőség is. Jóllehet az agrárfejlődés tőkés útjára léptek, mégis két eltérő fejlődési utat figyelhetünk meg. Az északi területeken jórészt kisparaszti farmergazdálkodás folyt, míg a déli gyarmatokon a rabszolga munkaerőt alkalmazó ültetvényes gazdálkodás honosodott meg. Anglia és a gyarmatok kapcsolata a merkantilista politikán alapult, az angolok elsősorban nyersanyagforrást és felvevőpiacot láttak gyarmataikban, és akadályozták rajtuk a konkurenciát jelentő iparosítást, hajóépítést és a növekvő külkereskedelmi aktivitást. A gyarmatok termékeit angol kereskedők vásárolták föl, akik monopóliumokat élveztek a gyarmati kereskedelemben.\n\nA gyarmatokon gyorsan fejlődtek a tőkés viszonyok, és minél fejlettebb lett gazdaságuk, annál terhesebbnek érezték az anyaország gyámkodását. Érdekeik védelmében először 1754-ben Benjámin Franklin kezdeményezésére tartottak közös kongresszust, ekkor azonban még nem kerültek élesen szembe az angol koronával, mert a francia gyarmatok fenyegetése miatt rászorultak Anglia fegyveres erejére. A hétéves angol-francia háború (1756-1763) után, melyben a franciák elvesztették észak-amerikai gyarmataikat, megszűnt az egymásrautaltság.\n\nAz angolok a háború költségeinek megfizetésére új adókat és illetékeket vezettek be. A gyarmatokon tiltakozási mozgalom bontakozott ki ez ellen. Az Angliához fűződő viszonyt illetően a gyarmatok lakossága azonban nem volt egységes. A hivatalnokok, az ültetvényesek egy része és a monopóliumok kedvezményezettjei loyalista (királypárti), Angliához hű álláspontot képviseltek. A gyarmati lakosság többsége, a farmerek, kereskedők, polgárok, a patrióták, vagyis hazafiak azonban annak az elvnek az alapján, hogy „nincs adóztatás képviselet nélkül”, készek voltak szembefordulni a brit koronával. A gyarmatok az angol tradíciók alapján álltak, s mint brit állampolgárok, úgy vélték, hogy csak akkor adóztathatók, ha az adott törvény választott képviselőiknek a közreműködésével készült, márpedig a gyarmatoknak nem volt képviselőjük a brit alsóházban. A sorozatos tiltakozó akciók, a bojkottmozgalom és a tüntetések hatására az angol kormány végül semmisnek nyilvánította a rendeleteit. Kivételt képezett a teavám, amivel azt kívánták kifejezésre juttatni, hogy az angol parlament gyakorolja a fennhatóságot az amerikai gyarmatok felett. A gyarmati polgárok számára viszont az adózási elv volt a fontos, ezért az angol politika elleni tiltakozásul 1773-ban dec. 16-án a bostoni kikötőben egy angol hajóról a tengerbe dobálták a teás ládákat -bostoni teadélután-, amire az angolok erőszakkal válaszoltak. A bostoni teadélután nyomán Anglia szigorú intézkedéseket vezetett be (katonai kormányzás).\n\n• A XVIII. sz. közepén tehát a 13 angol gyarmatnak az anyaországgal egyre nagyobb ellentétei támadtak (pl. adóztatás: cukortörvény, bélyegtörvény - 1765).\n\n1774-ben Philadelphiában a tizenhárom gyarmat képviselői összeültek az első Kontinentális Kongresszusra, amelyen természetes emberi jognak nyilvánították az önkényuralommal való szembeszegülést, fegyveres harcra szólították a gyarmatokat, noha még keresték a megegyezés lehetőségeit Angliával, III. György király azonban le akart számolni a lázadókkal.\n\nA 1775-1783 közötti függetlenségi háború:\n\n1775-ben Lexingtonban dördült el az a sortűz, a vitát most már a fegyvereknek kellett eldönteniük. Májusban összeült a második Kontinentális Kongresszus. George Washingtont kinevezték a kontinentális hadsereg parancsnokává, az angol hatóságoktól „biztonsági bizottságok” vették át a hatalmat, melyek irányították a helyhatóságokat, a bíráskodást, toborozták a hadsereget.\n\nA Függetlenségi Nyilatkozat:\n\n• 1776-ban a Kontinentális Kongresszus utasítására Thomas Jefferson és Benjamin Franklin megfogalmazta a Függetlenségi Nyilatkozatot, melyet mind a tizenhárom gyarmat képviselői július 4-én elfogadtak, amely megalapozta az USA politikai rendszerét: „Minden ember egyenlőnek teremtetett”, olyan jogok illetik meg, mint az „élet, a szabadság, a boldogságra törekvés”.\n\nAz amerikai Függetlenségi nyilatkozatban és az alkotmányban a felvilágosodás hatását és az alkotmányosság alapelveinek az érvényesülését figyelhetjük meg. Az amerikai Függetlenségi nyilatkozat kiadására 1776. július 4-én került sor, és alapvető szerepet játszott az Amerikai Egyesült Államok létrejöttében. A nyilatkozat kiadásának körülményei: a 13 amerikai angol gyarmat adja ki, az amerikai függetlenségi háború részének tekinthető. A déli és az északi államok egységesen lépnek fel az angolok ellen. Ez az az esemény az USA megalakulásáig, a függetlenség kivívásáig vezet.\n\nA felvilágosodás hatása egyértelműen kimutatható a nyilatkozatban pl. megjelenik a népfelség elve (népszuverenitás), a zsarnok uralkodó eltávolítható, az észelvűségre hivatkozik. Az alkotmányosság alapelvei jelennek meg: az egyenlőséghez, szabadsághoz, élethez való jog, tehát az emberi jogok érvényesülését fontosnak tartják. Az ember természetes jogainak biztosítását később törvénybe is foglalják. Az alkotmányosság alapelvei: a hatalmi ágak elválasztása, a népszuverenitás, a törvények uralma, az emberi és polgári jogok. A nép jogának tekinti a fennálló rend megváltoztatását. A nyilatkozatban az emberi jogok érvényesülésének igénye elsődleges, megjelenik a népszuverenitás érvényesülésének a fontossága.\n\nEzután teljes erővel megindult a függetlenségi háború. A hivatásos katonákból és német zsoldosokból álló angol erők jelentős fölényben voltak, ennek ellenére nem tudtak elbánni az amerikai csapatokkal, sőt 1777-ben Saratogánál Washington jelentős győzelmet aratott (porosz, lengyel katonákkal; francia támogatással). A siker hatására Franciaország elismerte az Egyesült Államok függetlenségét, és szövetséget kötött vele Anglia ellen. A döntő összecsapásra 1781-ben Yorktownnál került sor, ahol a francia segítségnek köszönhetően az amerikaiak győztek. A sorozatos vereségek hatására az angol parlament többsége a békekötés mellett döntött. A szerződést 1783-ban Versailles-ban írták alá - Anglia elismerte a 13 gyarmat függetlenségét.\n\nAz alkotmány:\n\n• A függetlenség kivívása után nehéz helyzetben volt az új állam. Tetemes volt az államadósság, nőtt az infláció, a hagyományos kereskedelmi kapcsolatok megszakadtak. A gazdasági nehézségeket fokozták a politikai problémák. A tizenhárom gyarmat 1781-től laza konföderációt alkotott, a kongresszus lényegében a királyi jogköröket vette át. A tizenhárom független állam külön irányította magát. A probléma megoldására 1787-ben szövetségi alkotmányozó gyűlés ült össze, s kidolgozta az USA alkotmányát, amely 1789-ben lépett hatályba. Ezzel megalakult az Amerikai Egyesült Államok, melynek első elnökévé George Washingtont választották.\n\nAz Egyesült Államok alkotmánya szétválasztotta a hatalmi ágakat, a törvényhozói, a végrehajtó és a bírói hatalmat, s igyekezett egyensúlyt teremteni közöttük. Ez az első, a hatalommegosztás elvére (Montesquieu) épülő, modern köztársasági alkotmány volt: szövetségi állam, széles körű elnöki hatalommal.\n\n• Jelentősége:\n\nA Függetlenségi Nyilatkozatban megfogalmazott jogok biztosítékául hozták létre 1787-ben az alkotmányt. Ennek értelmében szétválasztják a törvényhozó, végrehajtó és igazságszolgáltató hatalmat (hatalommegosztás elve), és ezek egyensúlyát teremtették meg, egymást ellenőrzik, és egymásnak felelősséggel tartoznak. Ezek az alapvető elvek a mai napig érvényesek az USA-ban. Megteremtették a demokráciát, a népszuverenitás elvét. Az alkotmányban érvényesül a képviseleti elv. Általános választójoggal rendelkezik. Megteremtették a politikai szabadságjogokat, a gyülekezés, a szólás és a sajtó szabadságát, szabad versenyt, vállalkozás szabadságát. Az egyházat és az államot szétválasztották egymástól, de vallásszabadságot biztosítottak. A feketéket, és a rabszolgákat azonban nem illették meg a polgárjogok.\n\nAz USA politikai berendezkedése, demokratikus intézményei\n\n1. A végrehajtó hatalom a négy évre választott elnök kezében összpontosul. Szövetségi rendszeréből adódóan az elnöki hatalom erős. Ő a végrehajtó hatalom feje. Tehát a kormány élén áll. A rendkívül széles jogkörrel rendelkező elnök nem tartozik felelősséggel a kongresszusnak, sőt határozatait meg is változtathatja, a hivatali idejében lényegében elmozdíthatatlan posztjáról.\n\nKétpárti váltógazdaságról beszélhetünk az USA-ban; a Demokrata és a Republikánus Párt (Köztársaságpárt) jelöltjeiből kerülnek ki az elnökök, a kormány tagjai és a képviselők. Az elnököt állam- és kormányfőként a pártok jelölése alapján az egyes államok választói közvetve, elektorok útján választják meg négy évre. Egyszeri újítás lehetséges, de Roosevelt elnök kivételt képezett, mert őt négyszer is megválasztották, így 1933-tól 1945-ig volt elnök. Az elnök nevezi ki a minisztereket. Munkáját az alelnök segíti, aki az elnököt helyettesítheti. Az elnököt csak közjogi vádemelés alapján lehet elmozdítani. Politikailag a Kongresszus, alkotmányjogilag a Legfelső Bíróság ellenőrzi.\n\n2. A törvényhozó hatalom: a kétkamarás Kongresszus\n\n2 kamarás törvényhozás (kongresszus): szenátus: államonként 2-2 fő, és a képviselőház: az államokból lakosság-arányosan érkező küldöttek. A képviselők eltérő módon kerülnek a két fel nem osztható házba. Az egyik a Képviselőház, melynek tagjait két évre közvetlenül választják. Itt helyezkednek el a demokraták és a republikánusok. A másik a Szenátus, melyben államonként (52 állam) 2 képviselő vesz részt benne 6 évre. Kétévente azonban a szenátorok egyharmadát újraválasztják. Az elnök a vétójogával és a Legfelső Bíróság felügyeli a törvényhozást, tehát működik a hatalmi ágak egymás fölötti ellenőrzése. A szenátus beleegyezése kell a fontosabb állami állások betöltéséhez, a képviselőház pedig az adókat szavazza meg.\n\n3. Az igazságszolgáltató hatalom: a Legfelsőbb Bíróság\n\nAz alkotmány és a törvényhozás jogi felügyeletét gyakorolja. 9 tagja van, amely az elnöktől független, s élethossziglan nevezik ki őket, melyet a szenátus erősít meg. A Legfelsőbb Bíróság egyben alkotmánybíróságként is működik.\n\nAz alkotmány első módosítása 1791-ben (Bill of Rights: állampolgári jogok rögzítése).\n\nAz alapvető emberi szabadságjogok kimaradtak az alkotmányból. Ezeket 1791-ben az első tíz alkotmány-kiegészítés csatolta az alaptörvényhez.', 130, 1, '2026-04-17 09:40:23', '2026-04-17 09:40:23');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(16, 16, 'A reformkor, a forradalom és a szabadságharc', '16.docx', '16. A reformkor, a forradalom és a szabadságharc\n\n(a reformkor fő kérdései, Széchenyi és Kossuth programja és vitája, a rendi országgyűlés és a megyerendszer, a pesti forradalom és az áprilisi törvények, a szabadságharc)\n\nMagyarország része volt a Habsburg Birodalomnak, és Magyarországra 1848-ig a feudális berendezkedés volt jellemző.\n\nMagyarország történetében az 1825/1830/1832 - 48 közé eső időszak a reformkor, amelyben a polgári-nemzeti átalakuláshoz vezető új politikai mozgalmak kibontakoztak. Kezdete: 1830 - Széchenyi „Hitel” c. könyvének megjelenése, vége: az 1848-as forradalom. 1832-36 között zajlott az első igazi reformországgyűlés.\n\n• Célkitűzései: „Jelszavaink valának: haza és haladás” (Kölcsey), azaz a nemzeti kultúra, nyelv ápolása, és gazdasági-társadalmi átalakulás a liberalizmus és a nacionalizmus jegyében.\n\nA XIX. századra kialakult polgári nemzeteszme nyelvi, etnikai alapú volt, de a nemesi nemzetfelfogás számos elemével (történelmi múlt, nemzeti erények, nemzeti viselet és szokások) kibővült. A reformok jegyében a nemesség fog síkra szállni, mert gyenge a polgárság. A „harmadik rend” szerepét tehát a nemesség képviselte, elsősorban a nemzeti önrendelkezés igényét hangoztatva, bár a társadalmi átalakulástól féltette a kiváltságait. A feudális rendszer válsága a nemességet saját helyzetének megváltoztatására késztette, hogy a polgárosodásban keresse a kiutat. A reformok fórumai a reformországgyűlések: 1825-27, 1830, 1832-36., 1839-40, 1844, 1847/1848. A reformok legfőbb elindítója Széchenyi István volt, reformpolitikusok: Wesselényi Miklós, Kölcsey Ferenc, Kossuth Lajos, Deák Ferenc.\n\nPOLITIKAI ELKÉPZELÉSEK ÉS IRÁNYZATOK:\n\nSzéchenyi István (1791-1860)\n\n1791-ben, Bécsben született arisztokrata családban, 1809-ben részt vett a napóleoni háborúban, mint tiszt, majd az 1810-es évektől utazásokat tesz Angliától Törökországig, csatlakozott hozzá Wesselényi Miklós erdélyi arisztokrata is. Ekkor tapasztalta, hogy Magyarország mennyire elmaradott a nyugati országokhoz képest, elhatározta, tenni fog hazája érdekében, s erkölcsök által akar nemzetet teremteni. 1825-től az országgyűlések résztvevője a felsőház tagjaként. Itt ajánlotta fel birtokainak egy évi jövedelmét a Magyar Tudományos Akadémia megalapításának javára. Az arisztokráciát tartotta alkalmasnak a reformok irányítására. A nemességet hívta össze a reformok elterjedésének érdekében a kaszinók létrehozásával és a lóverseny meghonosításával. A lótenyésztésről ír a Lovakrul (1828) című írásában. Birtokait modernizálni kívánta, de az ehhez szükséges hitelt visszautasította a bécsi bank, mert a magyar nemesség birtokait az ősiség törvénye (1351) miatt nem lehet az adósság fejében elárverezni, vagy eladni.\n\nÍrása: Ekkor írta meg a Hitel (1830) című munkáját, melyben reformelképzeléseit foglalja össze:\n\n”Magyarország volt, de én azt szeretném hinni, hogy lesz!” Ebben megállapítja, hogy Magyarország állapota elmaradott. Gazdasági elmaradottságunk oka szerinte az, hogy a rendszer a kiváltságokat élvező nemesség számára már előnytelen, mert az ősiség akadályozza a hitelfelvételben, hogy modernizálhassa birtokát: „magyar birtokos szegényebb, mint birtokához képest lennie kellene.” A jobbágyok robotmunkája nem eredményes, hatékonyabb lenne a bérmunkások alkalmazása. A haladást a bécsi udvar egyetértésével kívánta elérni, s nem azzal szemben. A reformok vezetését pedig egy politikai elitre bízná a főnemesek köréből. Ennek ellenére nem az arisztokrácia, hanem a középbirtokos nemesség fogja lelkesedéssel fogadni Széchenyi elképzeléseit. Dessewffy József Taglalat című munkájában bírálja a Hitelt, erre megírja Széchenyi a Világ (1831) című munkáját, ahol világosabban próbálta kifejteni elgondolásait. A Stádium (1833) címe a változtatások szakaszaira (12 pont) utal, melyben Széchenyi rendszerbe foglalta a reformgondolatait: 1. hitel, 2-3. az ősiség (Aviticitas) törvényének és a háramlási jognak az eltörlése (ezután a birtokot el lehet adni, el lehet idegeníteni, s ha nincs örökös, nem a királyra hárulna a birtok - fiscalitas). 4. a nem nemeseknek is lehetősége legyen a földszerzésre (birtokbírhatás joga - jus proprietatis). 5. a törvény előtt is egyenlőknek kell lenniük a tulajdonnal rendelkezőknek, 6. törvényes védelem biztosítása a bírósági tárgyalásokon. 7. a terheket együtt kell viselni (részleges közteherviselés), 8. vízszabályozás, útkarbantartás szükségessége. 9. a céheket, árszabást, monopóliumokat el kell törölni, korszerűbb módszereket kell alkalmazni a szabad verseny érdekében. 10. a magyar legyen a hivatalos nyelv a latin helyett, 11. meg kell növelni a Helytartótanács szerepét, 12. a változásoknak a nyilvánosság biztosításával kell megtörténniük (nyilvános törvényszéki tárgyalás). A reformokat a Habsburg Birodalmon belül kívánta végrehajtani a bécsi udvar beleegyezésével, lassú reformok útján, „kiművelt emberfők” segítségével. Gyakorlati tevékenysége: az Akadémia, a lóversenyek, és a kaszinó megalapítása után a közlekedés fejlesztését tűzte ki célul: az Al-Duna szabályozása (Vaskapu sziklazátonyainak felrobbantása), Tisza-szabályozás, az óbudai hajógyár és a pesti téli kikötő létesítése, a balatoni gőzhajózási társaság létrehozása, Balaton - Duna-csatorna, a budai alagút létrehozása, a Lánchíd felépítése (1842-48. Clark-fivérek; hídvám!). A Budapest központú vasúthálózat kiépítését szorgalmazta a helytartótanács közlekedésügyi osztályának vezetőjeként 1845-től. Ezen kívül a selyemhernyó-tenyésztést és a gőzmalmok létrehozását segítette elő. A 48-as forradalom után a Batthyány-kormány közmunkaügyi minisztere lesz, de 1848 szeptemberében idegösszeroppanást kap, Döblingben gyógykezelésben fog részesülni. A reformok elindítójaként magát tette felelőssé, hogy reformjai hova vezettek, bár ő sosem akart forradalmat, se szabadságharcot. 1859-ben a Bach-rendszert támadja Ein Blick című írásában. 1860-ban öngyilkos lesz Döblingben. Tevékenysége alapján nevezte őt Kossuth Lajos „a legnagyobb magyar”-nak.\n\nSzéchenyi és Kossuth vitája: a reformok végrehajtásának ütemében és módjában térnek el. Széchenyi lassú, felülről jövő reformokat akart, s egy politikai elitre bízta volna a vezetést, szem előtt tartva a bécsi udvar érdekeit. Kossuth és a középnemesség továbbfejlesztette az ő reformját, tisztelik Széchenyit, de ők érdekegyeztetés révén mindenkit be akarnak kapcsolni a reformokba a középnemesség és a nemesi vármegyék vezetésével. Szerintük épp az arisztokraták a fejlődés akadályozói, míg Széchenyi épp az arisztokrácia érdekeinek figyelembe vételével hajtaná végre a változásokat. Kossuth modorát bírálja, valójában a továbbfejlesztett reformjait. Széchenyi a Kelet Népe (1841) című vitairatában, Kossuth a Pesti Hírlapban (1841-44) reagál Széchenyi vádjaira.\n\nKossuth Lajos (1802-1894)\n\nMonokon született középbirtokos családban, jogi tanulmányokat folytat, majd z 1831-es kolerajárvány idején kolerabiztos volt Zemplénben. 1832-től az országgyűlések résztvevője Pozsonyban, 1832-36 között írja az Országgyűlési Tudósításokat, majd a Törvényhatósági Tudósításokat (1836-37), melyekben beszámol az országgyűlésen történtekről. Ezeket kézzel másolják, majd illegális nyomda segítségével terjesztik, ezért bebörtönzik, itt angolt és közgazdaságtant tanul. Az 1839-40-es országgyűlés amnesztiát ad, s ezután a Pesti Hírlap szerkesztésével bízzák meg (1841-44), s aktívan fog politizálni. A reformnemesség élére áll, a Pesti Hírlapban fejti ki politikai elképzeléseit, itt összegzi a reformelképzeléseket. Célja: a reformok és a haladás sürgetése. Módszere a politikai vezércikk. Vezérelvei:\n\n1. a liberális jogok megadása, a jogkiterjesztés,\n\n2. a kiváltságrendszer felszámolása,\n\n3. Magyarország polgárosodása,\n\n4. az érdekegyeztetés, hogy minél több társadalmi osztályt be lehessen vonni a reformok végrehajtásába saját érdekeik egyeztetésével, de a liberális középnemesség vezetésével.\n\n5. a parasztság megnyerése: kötelező örökváltsággal. Lényege, hogy a parasztság örökre megváltaná magát a jobbágyterhek alól, állami támogatással törlesztene, s így szabad földtulajdonhoz jutna.\n\n6. ehhez hitelre van szükség, viszont el kell törölni az ősiség törvényét, hogy hitelhez jussanak, s így kialakulhatnak a polgári tulajdonviszonyok.\n\n7. A nemesség megadóztatásával közteherviselés jön létre.\n\n8. A népképviseletet szorgalmazza,\n\n9. független nemzeti államot akar a birodalmon belül, a magyar nyelv államnyelvvé tételével (ez 1844-ben megvalósul).\n\n10. Szólásszabadság.\n\n11. Önálló nemzeti ipar, melynek segítségével a polgárságot kívánta megnyerni. Iparfejlesztő tevékenységéhez tartozik az Iparegyesület, a Magyar Kereskedelmi Társaság és az 1. ipari kiállítás (1842) létrejötte. A liberalizmus szellemében a szabad kereskedelem híve. Eleinte a birodalom vámhatárain belül képzelte el az iparfejlesztést, de 1843-tól azt vallotta, hogy a magyar ipar fejlesztéséhez védővámok kellenek, mert a magyar ipart megfojtaná a fejlettebb osztrák és cseh ipar. Az 1843/44-es országgyűlésen ezt a király visszautasítja, ezért a magyar ipar védelmére Védegyletet (1844) hoz létre, melynek lényege, hogy 6 évig csak magyar árut fognak az egylet tagjai vásárolni, hogy ezzel is elősegítsék a magyar ipar fellendülését. A kereskedelem fejlesztésére ad Vukovár – Fiume vasút tervét szorgalmazta, hogy a tenger felé is legyen lehetőségünk kivinni az áruinkat.\n\nKossuth nemzetiségpolitikája: egy politikai nemzetben gondolkodott kortársaihoz hasonlóan, s az a magyar politikai nemzet. Céljuk Magyarország függetlensége, nemzetté válása, egyelőre még a Habsburg-birodalom határain belül. Az 1844-es országgyűlés a magyart tette államnyelvvé a latin helyett. Ezt a nemzetiségek negatívan fogadták. A reformerek a jogkiterjesztést, az érdekegyeztetést faji, nemzetiségi és vallási megkülönböztetés nélkül kívánták megvalósítani, s úgy vélték, ezek megadásával a nemzetiségek is csatlakozni fognak a magyarokhoz. A nemzetiségeknek azonban ez kevés volt, fenyegetve látták saját nyelvüket, kultúrájukat, ők is önállóak akartak lenni, ez pedig nemzeti ellentétekhez vezetett. Ehhez járult még az a tény is, hogy a nemzetiségek földesurai magyarok voltak, s ez társadalmi ellentéthez is vezetett, s vallási tekintetben is eltértek (görög keleti). A nemzetiségek így a Habsburgoktól várják inkább a támogatást, mert nem bíznak a magyarokban. Ezért tudta ellenünk fordítani a bécsi udvar a nemzetiségeket a szabadságharc idején. 1851-es alkotmánytervében és a dunai konföderációs tervében már szövetséges államokról ír Kossuth, a föderáción belüli önállóság megadásával, de ez nem valósult meg.\n\n(Kossuth a forradalom és a szabadságharc idején: az ellenzéki kör tagjaként, Pest megye követeként részt vett az 1847/48-as országgyűlésen. Az 1848-as európai forradalmak hatására március 3-án felirati javaslattal áll elő: kötelező örökváltságot, közteherviselést, felelős kormányt, és az osztrák örökös tartományok számára alkotmányt követelt. A bécsi forradalom (márc. 13.) hatására elfogadta az országgyűlés a javaslatot, majd Kossuth vezetésével Bécsbe mentek, hogy V. Ferdinánd királlyal is elfogadtassák. Közben Pesten is kitört a forradalom (márc.15.), s áprilisban az uralkodó a parlamentnek felelős kormányt nevezett ki Batthyány vezetésével, melyben Kossuth pénzügyminiszter lett. 1848. július 11-én 200000 újonc katona költségeinek megszavazását érte el Kossuth. Szeptemberben kibocsátják az ún. Kossuth-bankót, s létrehozzák az Országos Honvédelmi Bizottmányt Kossuth elnökletével, ez lett a végrehajtó hatalom a szabadságharc idején. 1848 szept. alföldi toborzókörútra indult, a szabadságharcot szervezi. 1849. április 14-én a Habsburg-ház trónfosztását javasolja, s kormányzóvá választják. 1849 augusztus 11-én lemond, a teljhatalmat Görgeynek adja át, aki leteszi a fegyvert.\n\nKossuth emigrációba vonul, Törökországba (Kütahyai alkotmány), majd az USA-ba, s Angliába utazott, hogy népszerűsítse a magyar szabadságharc ügyét. Ellenzi a kiegyezést, s Itáliából próbál szabadságharcot szervezni, de sikertelenül. Duna-konföderációs terve, 1861. 1894-ben, Torinóban hal meg.)\n\nSzéchenyi és Kossuth vitája:\n\nTevékenysége alapján Kossuth Lajos „a legnagyobb magyar”-nak nevezte Széchenyit.\n\nA reformok végrehajtásának ütemében és módjában térnek el: Széchenyi lassú, felülről jövő reformokat akart, s egy politikai elitre bízta volna a vezetést, szem előtt tartva a bécsi udvar érdekeit.\n\nKossuth és a középnemesség továbbfejlesztette az ő reformját, tisztelik Széchenyit, de érdekegyeztetés révén mindenkit be akarnak kapcsolni a reformokba a középnemesség és a nemesi vármegyék vezetésével.\n\nKossuth szerint épp az arisztokraták a fejlődés akadályozói, míg Széchenyi épp az arisztokrácia érdekeinek figyelembe vételével hajtaná végre a változásokat.\n\nSzéchenyi Kossuth modorát bírálja, valójában a továbbfejlesztett reformjait.\n\nSzéchenyi a Kelet Népe (1841) című vitairatában, Kossuth a Pesti Hírlapban (1841-44) reagál Széchenyi vádjaira.\n\nMindketten egyetértettek abban, hogy hazánknak függetlenednie kell az osztrákoktól, de kettejük eszközrendszere különbözött, ugyanis Széchenyi Habsburg-párti volt, tehát a Habsburgok segítségével, egyetértésével szerette volna véghezvinni a reformokat, ellentétben Kossuthtal, aki vállalta a dinasztiával való szembefordulást is.\n\nSzéchenyi hangoztatta, hogy Magyarország számára stabil, erős gazdaság kiépítése az elsődleges szempont, e nélkül nem lehet hatékonyan egyeztetni a Birodalommal. Széchenyi megfontolt, óvatos, lassabb reformpolitikát támogatott, míg Kossuth a gyorsabb változások híve volt.\n\nSzéchenyi az arisztokráciára, mint a politika vezető rétegére támaszkodott volna, míg Kossuth a középnemesség segítségére kívánta alapozni a reformok véghezvitelét, ugyanis szerinte a Habsburg-hű arisztokrácia nemzetietlen.\n\nSzéchenyi elzárkózott mindenfajta törvénytelen lépéstől, így a forradalomtól is, Kossuth viszont a néptömeget használta volna bázisául.\n\nTörekvéseik közül sok minden megvalósult: az 1839/40-es országgyűlés megszavazta az önkéntes örökváltságot, és engedélyezték az ipari üzemek szabad alapítását. 1844-ben elfogadták, hogy a törvényhozás, a közigazgatás, az oktatás, illetve az igazságszolgáltatás hivatalos nyelve a magyar legyen.\n\nMindketten szerepet vállaltak az első felelős magyar kormányban. Az 1848-as forradalom eredményeként V. Ferdinánd jóváhagyta az áprilisi törvényeket, s megalakult az első független, országgyűlésnek felelős magyar kormány. Közlekedés- és közmunkaügyi miniszterévé Széchenyi Istvánt, pénzügyminiszterévé Kossuthot nevezték ki.\n\nSzéchenyi és Kossuth gazdasági elképzelései\n\nSzéchenyi reformkori programjának középpontjában a gazdasági kérdések álltak. Nyugat-Európában ekkorra kibontakozott az ipari forradalom, de Magyarország elmaradott volt Nyugat-Európához képest. Széchenyi elképzeléseire hatással voltak angliai tapasztalatai. Célja a magyar gazdaság felzárkóztatása, modernizációja volt. A gazdaság fejlesztése azonban politikai kérdéssé vált, összefüggött a polgári átalakulással. Széchenyi gazdasági vonatkozású javaslata: az ősiség, a céhek, a monopóliumok, a hatósági árszabás eltörlése. Szerinte fontos lenne a részleges közteherviselés bevezetése, a birtokbírhatás jogának megadása, a hitelfelvétel lehetősége és a piaci verseny kibontakozása, amely növekvő állami bevételekhez vezetne. Széchenyi szerint nem az uralkodót kell hibáztatni az elmaradottság miatt. A Hitelben a földbirtokosokhoz szól, ugyanis a földbirtokosokat tekinti a haladás gátjának. A saját társadalmi rétege, az arisztokraták vezetésével képzelte el az átalakulást. Nem kívánt szembe fordulni az udvarral, mert bízott az udvar együttműködésében. Széchenyi reformkori gazdasági vállalkozásokban vett részt pl. vasútépítés, Pesti Magyar Kereskedelmi Bank, gőzmalom, Lánchíd, a Vaskapu hajózhatóságának könnyítése, a Tisza szabályozásának előkészítése. Ezzel a gazdasági fejlődés infrastrukturális, pénzügyi feltételeit kívánta megteremteni. Ebben szerepe volt annak is, hogy jelentős vagyonnal rendelkezett. Széchenyi a gőzhajózás beindításától a [szén- és vasérc-] bányászat fellendülését várta. Kezdeményezte a (balatoni) gőzhajózás beindítását.\n\nKossuth rámutatott az ipar jelentőségére a korabeli európai gazdaságban, az ipart a politikai függetlenség feltételének tekintette. Kossuth az ipar fejlesztése mellett érvelt. Igazságtalannak tartotta a birodalom vámrendszerét, a méltányos vámrendszer kialakítását követelte. Kossuth szerint a vámrendszer gátolta a magyar ipar fejlődését. A vámrendszer az örökös tartományok iparát támogatta a magyarral szemben. Kossuth ekkor már nem akarta eltörölni a belső vámhatárt. Kossuth szerepet vállalt a Védegylet megalapításában. A tagok vállalták, hogy lehetőség szerint magyar árut vásárolnak. Működésének inkább politikai jelentősége volt. Kossuth javasolta a Fiumébe vezető vasútvonal megépítését, ez biztosította volna a magyar áruk kijutását a tengerre, és lazította volna az Ausztriától való gazdasági függést, Széchenyi nem értett vele egyet.\n\nJOBBÁGYKÉRDÉS A REFORMKORBAN:\n\nA jobbágyság jellemzői:\n\nAz egész korszakban a jobbágyság a legnépesebb társadalmi réteg (kb. 90%). Szolgáltatásai: a földesúrnak kilenceddel és robottal tartoztak; a telki állomány és a közös területek használati jogával rendelkeztek; ők voltak elsősorban az állami adók fizetői. A jobbágyrendszer ekkor már csak Közép-Kelet-Európára volt jellemző és a gazdasági fejlődés gátja volt. Ellentétes volt a felvilágosodás, a liberalizmus és a nacionalizmus eszméivel).\n\nA jobbágyság helyzete: az átlagos teleknagyság csökken, de a jobbágyok száma növekszik. A népességnövekedés telekaprózódáshoz vezetett, így nőtt a zsellérek száma. A jobbágyok többsége tehát nem rendelkezett földdel. A földesuruktól függtek, nem voltak tulajdonosai telküknek, az általuk használt telek fejében szolgáltatásokkal tartoztak földesuruknak. Nem rendelkeztek politikai jogokkal, nem tekintették őket a nemzet részének, a magyar társadalom ugyanis rendi társadalom volt.\n\nA Habsburg uralkodók az állami adóalapot akarták védeni, bővíteni. A nemesség magánjogi viszonynak tekintette a jobbágyságot. A XVIII. században az uralkodók rendeleti úton, a rendi országgyűlés nélkül szabályozták a kérdést.\n\nA jobbágyrendszer fenntartása volt a gazdasági lemaradás egyik oka.\n\nSzéchenyi álláspontja a Hitel című művében 1830-ban: a robot gazdaságtalan, a bérmunka sokkal gazdaságosabb. Ezzel Széchenyi a robot és a jobbágyrendszer eltörlése mellett érvel. A Hitelben kifejtett gondolatai indították el a reformmozgalmat.\n\nAz ország északkeleti megyéiben történt 1831-es kolerafelkelés oka: a járvány miatt elrendelt vesztegzár a jobbágyok megélhetését veszélyeztette, a jobbágyok bizalmatlanok voltak uraikkal szemben, és csak a hadsereg tudta őket megfékezni. Ez ráirányította a figyelmet a jobbágykérdésre.\n\nKölcsey utalt az 1831-es jobbágyfelkelés veszélyére, megkérdőjelezte a jobbágyokkal szemben alkalmazott megtorlás értelmét, a jobbágyok felszabadítását javasolta. Megfogalmazta az érdekegyesítés, a polgári átalakulás és a jogkiterjesztés gondolatát, ez liberális eszméket tükrözött.\n\nA jobbágykérdés az 1832–36. évi országgyűlésen kerül középpontba\n\nAz érdekegyesítés programja fogalmazódik meg a jobbágykérdéssel összefüggésben.\n\nItt vetődik fel az önkéntes örökváltság fogalma: a jobbágy örökre megválthatja úrbéri terheit, ha megegyezett földesurával. Az önkéntes örökváltság ügye ekkor még elbukott az országgyűlésen, megvalósítása nehézségekbe ütközött. A felszabaduló jobbágyok szabad munkaerővé váltak. Az örökváltság a jobbágyi terhek örökre szóló, egy összegben való megváltását jelenti; végeredményben a jobbágyok nem voltak képesek megváltani magukat.\n\nKossuth álláspontja: a jobbágyok nem képesek magukat megváltani, mindenképpen el kell törölni a jobbágyrendszert; a cél az érdekegyesítés és a nemzeti egység. Kossuth kötelező örökváltságot javasolt állami kártalanítással.\n\nAz 1847-es Ellenzéki Nyilatkozat már a kötelező örökváltságot követeli.\n\nA kötelező örökváltságot az 1848. április 11-i ún. áprilisi törvények tartalmazzák\n\nAz 1848. március 15-i forradalom és hatása: RÖVID\n\n1848-ban több európai államban is kitört a forradalom, ezért nevezik ezt az időszakot a népek tavaszának. Magyarország ennek a forradalmi hullámnak lett az egyik állomása. 1848 januárjában Szicíliában, februárban Párizsban, majd márciusban Münchenben (4.), Prágában (11.), Bécsben (13.), Pesten (15.) Ezek az események felgyorsították a reformfolyamatot, amely megelőzte a forradalmat. Kossuth ezt kihasználva 1848. március 3-án felirati javaslattal állt elő, melynek lényege, hogy Magyarországnak és az örökös tartományoknak alkotmányt követel, továbbá jobbágyfelszabadítást, közteherviselést és független nemzeti kormányt. Bécsbe utazik V. Ferdinánd királyhoz, hogy javaslatát elfogadtassa, közben pedig kitör a forradalom Bécsben is és Pesten is.\n\nMárcius 15-én vér nélkül győzött a magyar forradalom márciusi fiatalság vezetésével (Petőfi Sándor, Vasvári Pál, Jókai Mór), ezzel meggyorsították az országgyűlés munkáját. Követelésüket 12 pontban foglalták össze. A március 15-ei forradalom hatására a bécsi udvar kénytelen volt elfogadni az országgyűlés követeléseit, az áprilisi törvényeket és az első független, felelős magyar kormányt gróf Batthyány Lajos vezetésével. További tagjai: Szemere Bertalan belügy, Kossuth Lajos pénzügy, Mészáros Lázár honvédelmi, Széchenyi István közmunka és közlekedésügy, Eötvös József vallás és közoktatás, Deák Ferenc igazságügy, Klauzál Gábor földművelés, ipar és kereskedelemügy, Esterházy Pál a király személye körüli miniszter.\n\nA forradalom követelései a 12 pont alapján: a márciusi ifjak fogalmazták meg\n\nsajtószabadság, cenzúra eltörlése,\n\nfüggetlen / felelős kormány,\n\névenkénti országgyűlés,\n\ntörvény előtti egyenlőség,\n\nközteherviselés,\n\nnemzetőrség felállítása,\n\njobbágyfelszabadítás,\n\nfüggetlen bíróságok,\n\nunió Erdéllyel.\n\nLiberális és nemzeti követeléseket is tartalmazott, egybeestek az országgyűlési reformellenzék követeléseivel, a forradalom célkitűzései a polgári átalakulást célozták.\n\nAZ ÁPRILISI TÖRVÉNYEK\n\n1848. április 11-én adták ki az áprilisi törvényeket, amely a március 15-én kivívott függetlenség és polgári átalakulás 31 törvénycikkből álló dokumentuma. Bécsben szentesíti a Habsburg uralkodó, V. Ferdinánd (1835-1848). Ez egyben a Batthyány-kormány programja.\n\nPolitikai:\n\nparlamentnek felelős, független magyar minisztérium létrehozása (a végrehajtó hatalmi szerv, azaz a kormány élén Batthyány Lajos áll).\n\névenkénti országgyűlés Pesten, melyet a király hív össze. Ülései nyilvánosak és magyar nyelven folynak. Továbbra is kétkamarás (alsó ház és felső ház). Az alsóházba népképviseleti választások útján kerülhetnek be a követek, és 3 évre választják őket. A felső házban a főnemesek és a főpapok személyesen vesznek részt az üléseken.\n\n3 évenként választásokat tartanak. Cenzusos rendszert vezetnek be, tehát az választhat, aki vagyonnal rendelkezik, hiszen van mit veszítenie. Választhat: az a 20 éves magyar vagy honosított férfi, aki nem áll büntetés alatt, házzal, földdel, s legalább egynegyed telekkel, vagy gyárral, műhellyel rendelkezik, vagy értelmiségi. Választható (képviselő lehet) mindaz, aki választó és 24. életévét betöltötte.\n\nA nádor jogkörét kiterjesztik (pl. hadseregparancsnok is).\n\nAz állam egysége: unió Erdéllyel és Partiummal (azaz az Erdély alatti Részekkel).\n\nPolitikai szabadságjogok biztosítása: sajtószabadság a cenzúra eltörlésével, de a lapalapításra biztosítékot kell fizetni, szólásszabadság, a gyülekezés szabadsága (liberális szabadságjogok), törvény előtti egyenlőség, a polgári tulajdon szabadsága, vallásszabadság.\n\nGazdasági reformok: a feudalizmus felszámolására törekedtek.\n\njobbágyfelszabadítás, általános és kötelező örökváltság, tehát az úrbéri terheket és szolgáltatásokat megszüntetik, de a földesurakat az állam kárpótolja majd,\n\neltörlik a papi tizedet és az úriszéket (földesúri bíráskodás a jobbágyok felett),\n\naz ősiség eltörlése (a birtokot most már el lehet adni, elidegeníthető),\n\nközteherviselés (egyenlően és arányosan fizet mindenki adót),\n\nhitelintézet felállítása (a földbirtokokat most már lehet hitellel terhelni).\n\nHiányosságai: 1. nem számolta fel teljesen a feudalizmus maradványait, pl. a földesúri szolgáltatások egy része megmarad (szőlődézsma stb.), 2. nem törölték el a céheket, nem foglalkoztak a nemzetiségi kérdéssel, egy politikai nemzetben gondolkoztak, ez a magyar, 3. a lakosság szegényebb része kiszorult a választójogból, 4. a nemesség vezető szerepe megmaradt, a nemesi vármegyéket nem számolták fel.\n\nJelentősége: A nacionalizmus és a liberalizmus szellemében megfogalmazott törvények. A polgári haladás és a nemzeti függetlenség biztosítéka, mely a reformkori küzdelmek és a vértelen forradalom vívmánya. Az érdekegyesítés szellemében jött létre. Előrelépést jelentett a feudális maradványok felszámolásában.\n\nKIFEJTÉS:\n\nAZ ÁPRILISI TÖRVÉNYEK: 1848. április 11-én\n\nA törvények jogerőre emelkedésével Európa más országaihoz képest a magyarországi forradalmi helyzet viszonylag gyorsan konszolidálódhatott. Az első független, felelős magyar kormány 1848 áprilisára megalkotta az alkotmányos berendezkedést biztosító törvényeket, amelyeket az uralkodó április 11-én szentesített.\n\n• Az áprilisi törvények értelmében a végrehajtó hatalom feje a törvényhozásnak felelős, de az uralkodó akaratától független kormány. Az új magyar kormány tehát az országgyűlésnek volt felelős: az uralkodó nevezte ki a miniszterelnököt, aki kijelölhette kormányának tagjait. Az uralkodó rendeletei csak az illetékes miniszterek ellenjegyzésével voltak érvényesek. Ezt a koncepciót a centralisták dolgozták ki. A megyék (az „alkotmányosság védőbástyái”) népképviseleti alapra történő helyezését elhalasztották, de a megyegyűlések tagjainak sorát kibővítették a községek küldötteivel. A városok irányítását választott testületekre bízták.\n\n• A népképviseleti országgyűlés évenként összeül Pesten. Az uralkodó szerepköre már csak szervezési funkciókra, terjedt ki, így az országgyűlés összehívására, meghosszabbítására, berekesztésére és feloszlatására. Zárszámadás és a költségvetés megszavazása nélkül nem lehetett berekeszteni az országgyűlést. Feloszlatás esetén pedig új képviselőválasztást kellett elrendelni. Ülései nyilvánosak és magyar nyelven folynak. Továbbra is kétkamarás (alsó ház és felső ház). Az alsóházba népképviseleti választások útján kerülhetnek be a követek, és 3 évre választják őket. Az alsótábla jogai kibővültek: megszavazta a költségvetést, hozzájárulása nélkül nem lehetett feloszlatni. A felső házban a főnemesek és a főpapok személyesen vesznek részt az üléseken. A kötött mandátum eltörlésével, népszuverenitás és népképviselet jegyében szervezett választás eredményeként juthattak a szabad mandátumú, azaz a vármegyéjük által nem utasítható képviselők a parlamentbe.\n\n• A magyar választójog, követve a nyugat-európai mintát, cenzusos volt, így nemi, korbeli, vallási, vagyoni és műveltségi korlátok szűkítették az aktív választójogot. A volt nemesség megtarthatta választójogát, a passzív választójog magasabb életkort és a magyar nyelv ismeretét kívánta meg. A választójogot vagyoni vagy műveltségi cenzushoz kötötték (itt volt a legalacsonyabb vagyoni cenzus Európában). A cenzusos rendszer lényege: az választhat, aki vagyonnal rendelkezik, hiszen van mit veszítenie. Választhat: az a 20 éves magyar vagy honosított férfi, aki nem áll büntetés alatt, házzal, földdel, s legalább egynegyed telekkel, vagy gyárral, műhellyel rendelkezik, vagy értelmiségi. Választható (képviselő lehet) mindaz, aki választó és 24. életévét betöltötte.\n\n• A nádor jogkörét kiterjesztik (pl. hadseregparancsnok is).\n\n•Politikai szabadságjogok biztosítása: a polgári berendezkedésre jellemző jogegyenlőség a közteherviselés kimondásában, valamint a jobbágyfelszabadításban valósult meg, amely állami kártérítéssel és kötelező örökváltsággal történt, valamint megszüntették az úriszéket és a papi tizedet. Az úrbéres szolgáltatások megszűntek, a parasztok az általuk használt úrbéres földet szabad tulajdonként kapták meg. A földesurak kármentesítését az állam magára vállalta, de gyakorlati megvalósításról nem rendelkeztek. Ez a leghaladóbb jobbágyfelszabadítás volt: nem vettek el a paraszti földekből, a megváltást az állam vállalta.\n\nGazdasági reformok: a feudalizmus felszámolására törekedtek.\n\n- jobbágyfelszabadítás, általános és kötelező örökváltság, tehát az úrbéri terheket és szolgáltatásokat megszüntetik, de a földesurakat az állam kárpótolja majd,\n\n- eltörlik a papi tizedet és az úriszéket (földesúri bíráskodás a jobbágyok felett),\n\n- az ősiség eltörlése (a birtokot most már el lehet adni, elidegeníthető),\n\n- közteherviselés (egyenlően és arányosan fizet mindenki adót),\n\n- hitelintézet felállítása (a földbirtokokat most már lehet hitellel terhelni).\n\n• Liberális szabadságjogok: szólásszabadság, a gyülekezés szabadsága, törvény előtti egyenlőség, a polgári tulajdon szabadsága, vallásszabadság. A polgári rendszerek alapja, hogy a polgárok politikai jogokkal is rendelkeznek. Részletes sajtótörvényt alkottak. A sajtószabadság a cenzúra eltörlésével valósult meg, de a lapalapításra biztosítékot kell fizetni.\n\n• Rögzítették a keresztény felekezetek egyenjogúságát.\n\n• A politikai jogok területén megszűntek a származási különbségek.\n\n• Kimondták Erdély és a Partium egyesítését Magyarországgal (Unió), és a Határőrvidéket is a magyar kormány alá rendelték. 1848 nyarán létrejött az Unió Erdéllyel, így alkotmányjogi szempontból a felelős kormány hatásköre kiterjedt az egész történelmi ország területére.\n\nAz áprilisi törvények nem rendezték a birodalommal való viszonyt, mert a birodalmi egység és a nemzeti függetlenség ellentmondására ekkor még nem találtak megfelelő megoldást. 1848. áprilisi törvények értelmében alkotmányos parlamenti berendezkedés jött létre. Ausztria és Magyarország viszonyát a gyakorlatban is csupán nagyjából perszonáluniós kapcsolattá szűkítették (a külügyek önálló intézésének hiánya csorbította csak az önállóságot a birodalmon belül; ugyanakkor a nádor széles, a királyt helyettesítő jogköre túlmutatott a perszonálunión). Az áprilisi törvényekben kialakított politikai berendezkedéshez az 1831-es belga alkotmány szolgált mintaként.\n\nKimondták az ország Habsburg Birodalmon belüli különállását, így egy perszonáluniós kapcsolat jött létre. A perszonáluniónál lazábbnak tekinthető a kapcsolat, mert a nádor lett a király teljhatalmú helyettese, ha az uralkodó nem tartózkodott az országban (márpedig általában Bécsben volt).\n\nA perszonáluniónál szorosabbnak tekinthető a kapcsolat, mert az ország nem intézhette önállóan a külügyeket, és a hadüzenet, illetve a békekötés joga is az uralkodónál maradt.\n\n„Törvényesítette” a forradalmat, magába foglalva a polgári átalakulás legfontosabb törvényeit. Lehetővé tette a gyors konszolidációt. Több törvény ideiglenes jellegű volt, továbbfejlesztésre várt.\n\nProblémák és bizonytalanságok:\n\n• A jobbágyfelszabadítás nem terjedt ki az irtványok, szőlők és általában a nem úrbéres földekre; bizonytalan volt a majorsági földekre települt zsellérek sorsa (bár személyükben ők is felszabadultak). Nem számolta fel teljesen a feudalizmus maradványait, pl. a földesúri szolgáltatások egy része megmarad (szőlődézsma).\n\n• Elmaradtak a nemzetiségekkel kapcsolatos törvények: egy politikai nemzetben gondolkoztak, ez a magyar. Szerintük a politikai szabadságjogok mindenkire kiterjednek.\n\n• Megmaradtak a céhek.\n\n• Elhalasztották a zsidók teljes emancipációját.\n\n• Bizonytalanság maradt az Ausztriával tartandó kapcsolatban: részt kell-e vállalni az államadósságból, és szükséges-e katonailag segítséget nyújtani Ausztriának.\n\nA lakosság szegényebb része kiszorult a választójogból, a nemesség vezető szerepe megmaradt, a nemesi vármegyéket nem számolták fel.\n\nJelentősége: A nacionalizmus és a liberalizmus szellemében megfogalmazott törvények. A polgári haladás és a nemzeti függetlenség biztosítéka, mely a reformkori küzdelmek és a vértelen forradalom vívmánya. Az érdekegyesítés szellemében jött létre. Előrelépést jelentett a feudális maradványok felszámolásában.\n\nKövetkeztetés:\n\nAz áprilisi törvények kimondták, hogy a végrehajtó hatalmat a felelős magyar kormány képviseli. A kormány a törvényhozásnak volt felelős, Magyarország alkotmányos monarchiává vált, a kormányszékek megszűntek. A kormányzati rendszer szerkezete több tárcából áll. A demokratikus működés biztosítéka pl. miniszteri felelősség elve, hatalmi ágak szétválasztása.\n\nAz országgyűlés működése: évenként és Pesten ülésezik, az uralkodó hívja össze, a képviselőket három évre választják, az ülések nyilvánosak, az uralkodó jogai korlátozottak. A rendi gyűlést népképviseleti országgyűlés váltotta fel, az országgyűlésnek lett felelős a kormány. Az országgyűlés az ország függetlenségének kérdésében jelentős szerepet tölt be.\n\nA korábban választójoggal rendelkezők továbbra is rendelkeznek választójoggal pl. a nemesség. A polgárság választójoga megmaradt (korábban városok képviselői), vagyoni, műveltségi cenzust vezettek be. Megvalósult a népképviselet. A nők nem rendelkeztek választójoggal.\n\nAz országgyűlés ellenőrző szerepet tölt be, a polgári állam kiépítése jellemző. A liberális eszme néhány követelése megvalósult pl. választásra jogosultak magas aránya, jogok kiterjesztése.\n\nA rendi országgyűlés által kidolgozott és az uralkodó által szentesített reformok lerakták Magyarországon a polgári átalakulás alapjait.\n\nAz áprilisi törvények felszabadították a jobbágyságot. A jobbágyok úrbéres földjeik tulajdonosává váltak, s az állam kötelezettséget vállalt a földesurak kárpótlásáért. A Kossuth által javasolt módszert iktatták törvénybe.\n\nAz áprilisi törvények felszámolták a rendi jellegű kiváltságokat.\n\nA törvények nem szabályozták egyértelműen az Ausztriához fűződő viszonyt. A rendszer lényegében perszonáluniónak felelt meg. Magyarországot csak a közös uralkodó személye kötötte össze a birodalom másik felével, nem rendezték a hadsereg kérdését, a külképviseletek is birodalmi kézben maradtak.\n\nA külügy, a hadügy és az ezekre vonatkozó pénzügy körüli tisztázatlanságok vitához vezettek. A végrehajtó hatalom a felelős magyar kormány kezébe került, míg Bécs ezeket a területeket továbbra is királyi felségjognak tekintette.\n\nAz 1848-49-es szabadságharc\n\nElőzmények:\n\nAz 1848. március 15-i forradalom után létrejött az első független, a parlamentnek felelős magyar kormány. Vezetője, Batthyány Lajos gróf április elejére alakította meg kormányát. Programja a forradalom vívmányainak konszolidálása, melyhez pénzre és hadseregre volt szüksége, de más problémák is felmerültek.\n\nA parasztmozgalmak és a nemzetiségi kérdés\n\nAz úrbéri viszonyok megszüntetésének hiányosságai miatt parasztmozgalmak bontakoztak ki. Ezekben eleinte nemzetiségre való tekintet nélkül vettek részt a parasztok.\n\nAz áprilisi törvények hiányossága, hogy nem foglalkozott a nemzetiségekkel, a nemzetiségi jogok külön biztosításával. A nemzetiségek mozgalmai is paraszti követelésekkel indultak, majd az értelmiség az anyanyelv használatának jogát, és területi különállást is követelt; a Batthyány-kormány viszont arra az álláspontra helyezkedett, hogy Magyarországon egy politikai nemzet van. A nemzetiségi vezetők egyre inkább Bécs felé fordultak.\n\n1848 nyár-ősz\n\n1848. június végén megtartották a népképviseleti választásokat; a polgári átalakulás hívei elsöprő győzelmet arattak.\n\nA kormány hiába kérte, az udvar nem küldte haza az idegenben szolgáló magyar ezredeket, így még májusban fölállították a nemzetőrségnek álcázott első 10 honvédzászlóaljat, majd július 11-én Kossuth javaslatára az országgyűlés további 200.000 katonát szavazott meg.\n\nA Délvidéken júniustól egymást követték a véres összecsapások a szerb fölkelőkkel. Horvátországban Jellasics hazánk ellen készülődött.\n\nAugusztus végén királyi leirat követelte a magyar hadügy- és pénzügyminisztérium beolvasztását a bécsi minisztériumokba, szeptember 4-én Jellasics pedig királyi megerősítést kapott. Bizonyossá vált, hogy nem a kormány intézkedésein múlt a béke; a tárgyalásokkal most már a magyar kormány is csak időt akart nyerni. Mindeközben folytatták az újoncok összeírását, új honvédzászlóaljak alakultak. Kossuth utasítást adott a szabadcsapatok toborzására. Megkezdték a Kossuth-bankó kibocsátását. Szeptember 15-én eltörölték a szőlődézsmát.\n\nAz új végrehajtó hatalom – OHB\n\nA Batthyány-kormány látva a békítő politikai kudarcát, lemondott (IX. 10-én). Szeptember 16-án hattagú bizottságot: az Országos Honvédelmi Bizottmányt (OHB) választották, ideiglenes végrehajtó hatalomnak. Elnöke Kossuth.\n\n● 1848. szeptember 11-én Jellasics 35.000 főnyi seregével átlépte a Drávát, majd Pest felé indult. Kossuth szeptember 24-én toborzókörútra indult az Alföldre.\n\n● Szeptember 29-én Pákozd és Sukoró között a magyar sereg vereséget mért a kétszeresen túlerőben lévő ellenségre. Jellasics fegyverszünetet kért, melyet kihasználva megszökött, és Győr felé menekülve elhagyta az országot. A határig üldöztük, majd megtorpantunk.\n\nA Bécs elleni magyar támadás kudarca\n\n● Október 4-én V. Ferdinánd föloszlatta az országgyűlést, és Jellasicsot kinevezte Magyarország katonai biztosává. Latour (hadügymin.) kiadta a parancsot: a császári haderő intézzen támadást Mo ellen, de a 2. bécsi forradalom (okt. 6.) következtében fölakasztották.\n\n● Október 30-án a magyar sereg 3 heti tanakodás után végre átlépte a Lajtát, hogy a bécsi felkelők segítségére siessen. A népfelkelőkből álló hadat azonban Schwechatnál visszaverték 1848. október 30-án.\n\nAz OHB legfontosabb feladata az erős, rendezett hadsereg megszervezése. Leküzdhetetlen nehézséget jelentett a fegyverek, a lőszer, és az egyenruhák előteremtése.\n\nV. Ferdinándot a kamarilla (1848. dec. 2-án) lemondatta, helyette Ferenc Józsefet nyilvánította osztrák császárrá és magyar királlyá. Néhány nap múlva megindult Windischgrätz hazánk ellen. Ferenc József általános támadást indított hazánk ellen.\n\nTÉLI HADJÁRAT – 1848. december – 1849. március\n\nA császári fősereg 44.000 sorkatonájával 25.000 honvéd nézett szembe Görgei Artúr parancsnoksága alatt. (É-on: Klapka György, Ny-on: Görgei, K-en: Bem, D-en: Damjanich János védekezett, az ország belsejében aktív védekezés folyt, főleg a Dunántúlon, hogy Windischgrätz ne érje el a fővárost).\n\n● A Délvidéken már nyár óta folytak a harcok. Galíciából betört Schlick hadteste, elfoglalta Kassát, és Miskolcot fenyegette. Ekkorra már Erdély is elveszett.\n\n● Kossuth kérésére Görgei Pozsony térségéből, Perczel pedig a Muraközből húzódott, még a főváros előtt egyesülniük kellett volna Windischgrätz feltartóztatására. Görgei a túlerő elől visszavonult, Perczel tábornok Mórnál veszített (dec. 30).\n\n● Dec. 31-én a törvényhozó hatalom (OHB) + az országgyűlés átköltözött Debrecenbe.\n\n● Január 5-én Batthyány Lajos és Deák Ferenc békeküldöttséggel fölkereste az akkor már Pesten tartózkodó Windischgrätzet. A császári főparancsnok feltétlen megadást követelt, a visszautasítás után Batthyányt letartóztatta.\n\n● Görgei január 5-én Vácott kiáltványt bocsátott ki, amelyben a 48-as alkotmány védelme mellett tört lándzsát, de az OHB-tól és a köztársasági törekvésektől elhatárolta magát (belső megosztottság). I. 24-én Lipótvár felmentése helyett a bányavárosokba vonult téli pihenőre, ott beszorult.\n\n● Perczel január 22-én győz Szolnoknál.\n\n● Január 31-én Klapka Tokajnál megállította Schlicket.\n\n● Február 5-én Guyon Richárd áttört a jeges Branyiszkói-hágón. Ezzel a fel-dunai hadtest (Görgei) előtt megnyílt az út a Tiszához.\n\nAz országgyűlés ismét működőképessé vált. A baloldal követelésére a hazaárulókat törvényen kívül helyezték. Fölállították a vésztörvényszéket. Dolgozni kezdett a nagyváradi fegyvergyár, működött a bankóprés, létrejött az egészségügyi és a postaszolgálat. A szabadságharc anyagi és katonai ereje tovább nőtt.\n\n● Kossuth Dembinski Henriket nevezte fővezérré, aki Kápolna térségében ellentámadást indított, de vereséget szenvedett, majd a honvédcsapatokat a tiszti tiltakozások ellenére a Tisza mögé vonta vissza 1849. febr. 26-27-én Görgei az elégedetlenek élére állt, és megtagadta az engedelmességet Dembinskinek. Kossuth Görgeit haditörvényszék elé akarta állítani. A táborban azonban maga is meggyőződött arról, hogy az OHB tagjai is alkalmatlannak tartják Dembinskit, így Görgeire bízta a fősereget.\n\n● Windischgrätz és az udvar 1849. március 4-én Olmützben kiadott egy nyilatkozatot, melyben megszüntette Magyarország függetlenségét (túlértékelték a kápolnai győzelmet).\n\nTéli hadjárat – Erdélyben\n\n● Bem karácsonyra visszaszerezte Kolozsvárt.\n\n● 1849. március 21-ére egész Erdélyből kitakarította az osztrák és az első ízben beavatkozó orosz csapatokat. A levert nemzetiségi fölkelőknek büntetlenséget adott.\n\nA DICSŐSÉGES TAVASZI HADJÁRAT – 1849. IV.1 – V.21.\n\n● 1849. március végén, a Tiszánál összevont 50.000 honvéd támadásba lendült és alig 4 hét alatt a Tiszától Pozsonyig űzte az ellenséget (IV. 2. Hatvan, IV. 4. Tápióbicske, IV. 6. Isaszeg, IV. 10. Vác, IV. 19 Nagysalló).\n\n● Gerillák szabadították föl a bányavárosokat, és a Szepességet.\n\n● A Bácskát és a Temesközt Perczel és az Erdélyből odasiető Bem tisztította meg az ellenségtől.\n\n● Május közepére Magyarország egész területe, május 21-ére Pest-Buda is fölszabadult.\n\nA Habsburg-ház trónfosztása\n\nKossuth április 14-én a képviselőháznak debreceni nagytemplomban tartott nyilvános ülésén kimondatta a Habsburg-ház 2. trónfosztását és Magyarország függetlenségét. A Függetlenségi Nyilatkozat nem szólt az államformáról, így Magyarország király nélküli királysággá vált, ezért kapott Kossuth kormányzó-elnöki címet.\n\nÚj kormány létrehozása\n\nDebrecenben létrehozzák az új kormányt Szemere Bertalan elnökletével. Kossuth kormányzó-elnöki tisztségének hatásköre csökkent. Rendeletei csak miniszteri ellenjegyzéssel voltak érvényesek, és nem volt joga a képviselőház feloszlatásához sem.\n\nAz orosz beavatkozás\n\nBécs április elején I. Miklós cárhoz fordult. Az orosz önkényuralkodó május 9-én kiáltványban tudatta a világgal, hogy Ausztria segítségére siet. Ezzel a magyar szabadságharc végzetesen elszigetelődött, sorsa eldőlt.\n\n● Június elején megindult a császári és cári hadsereg (200 ezer orosz + 170 ezer osztrák katona 132 ezer magyarral szemben) összehangolt támadása. A császári hadsereg új főparancsnokot kapott: Haynaut, az orosz hadsereget Paszkievics vezette.\n\n● A magyar kormány általános népfölkelést hirdetett, de a gerillaakciókat az orosz hadvezetés kegyetlenül megtorolta.\n\n● Kézzelfogható eredmény született a nemzetiségi megbékélésben: legtöbb helyen beszüntették a harcot, az országgyűlés pedig megszavazta az Európában sokáig egyetlen nemzetiségi törvényt.\n\nMagyar részről két terv volt a védelemre:\n\n1. Komáromnál összpontosítani minden erőt (Görgei) az utolsó percig várta, h kedvező ajánlatot kapjon és túl későn vette fel a harcot, túl későn indult el Komáromból.\n\n2. Perczel + Dembinszki terve: Szeged felé vonulni (kormány + hadsereg) előnye, hogy veszély esetén közel van a semleges török terület a menekülésre. Megindultak SZEGEDRE.\n\n● 1849. VI végére a Dunántúl elveszett → utolsó remény: összpontosított támadás az oroszok ellen a Tisza-Maros szögénél, még Haynau oda nem ér → DE Görgey nem ért oda időben, VII. 2-án Komáromnál súlyos vereséget szenvedett és csak ezután indult D-K Mo felé, hogy egyesüljön a Dembinski vezette fősereggel Aradon.\n\n● A szabadságharc utolsó győzelmét Guyon Richárd tábornok aratta Délvidéken: Jellasicsot júl. 14-én a Dunától délre kergette.\n\n● 1849. VIII. 9-én ért Aradra Görgei. Dembinszkinek a fősereggel Szeged feladása után szintén Aradra kellett volna mennie, de helyette az ellenség kezében lévő Temesvárra indult (Erdélybe akart jutni, hogy segítsen Bemnek, 1849 augusztusig tartotta Bem Erdélyt). A kormány az engedetlen Dembinskit leváltotta, helyére kinevezte Bemet, aki augusztus 9-én Temesvárnál csatát vállalt Haynau ellen. A szabadságharc utolsó nagy csatája a honvédsereg vereségével végződött.\n\n1849. VIII. 11. Kossuth és Szemere lemondtak, Görgei teljhatalmat kapott, az utolsó ütőképes sereg parancsnoka volt, kizsarolta tőlük, megígérte, hogy tisztes feltételekkel köt majd békét.\n\n1849. VIII. 13-án Világosnál az orosz csapatok előtt feltétel nélkül letette a fegyvert.\n\n1849. X. 2-ig csak Komárom maradt meg (Klapkával) – az utolsó ellenálló erőd.\n\nA bosszú\n\nAnglia és Oroszország kegyelmet és mérsékletet javasoltak, de a 19 éves Ferenc József és Haynau a megtorlást választották: 1849. október 6-án Aradon kivégeztek 13 honvéd főtisztet, Pesten agyonlőtték Batthyány Lajost.', 191, 1, '2026-04-17 09:40:36', '2026-04-17 09:40:36');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(17, 17, 'A polgári nemzetállam jellemzői, alkotmányosság és jogegyenlőség (Németország, USA, Magyarország)', '17.docx', '17. A polgári nemzetállam jellemzői, alkotmányosság és jogegyenlőség (Németország, USA, Magyarország)\n\nA XIX. századi liberalizmus és a nacionalizmus\n\nmindkét eszme Nyugat-Európában született,\n\nkeletkezésük a XVIII - XIX. századhoz kapcsolódik.\n\nA LIBERALIZMUS\n\nA XIX. századi liberális eszme fő elemei:\n\naz egyén fontos szerepe, a tolerancia, az egyenjogúság hangsúlyozása,\n\naz állam háttérbe szorulása (éjjeliőr szerep), hiszen szabadversenyes kapitalizmus van\n\na liberalizmus alapja a szabadságeszmény.\n\nA liberalizmus kialakulása összefüggött a kor társadalmi változásaival, a forradalmi mozgalmak segítették terjedését.\n\nA liberalizmus kialakulása összefüggött még a felvilágosodás eszmerendszerével.\n\nA francia forradalom, illetve a napóleoni háborúk segítették terjedését.\n\nA liberális eszme elfogadja az eltérő nézeteket, a különböző életformákat. Egyik képviselője az angol John Stuart Mill:\n\n„Hasznos az, ha eltérő nézetek léteznek, ha szabad teret kapnak a legkülönbözőbb jellemek, míg másoknak nem ártanak, ha mindenki a gyakorlatban próbálja ki a különböző életformák értékét.” (J.S.Mill)\n\nA tolerancia alapja a szabadságeszmény.\n\nA szabadság korlátja a másik ember szabadságának tiszteletben tartása.\n\nA liberális eszme egyik fő eleme az emberek közötti egyenlőség, az egyenjogúság hirdetése pl. választójog megadása, férfi és nő közötti egyenjogúság.\n\nA liberalizmus nem hisz a hagyományokra, erős államra épülő közösségben.\n\nA liberalizmus az egyén szerepét, illetve az ésszerűséget tarja fontosnak.\n\nFontos számára a szabadság és felelősség kapcsolata.\n\nSzabályozza a kormányzati hatalomhoz való viszonyt: az állam szerepét korlátozza.\n\nA liberalizmus a szabad verseny híve - ennek hátterében a kapitalizmus állt.\n\nA 19. századi politikai irányzatai a francia forradalom eszméiből alakultak ki, amelyek átalakították Európa feudális társadalmi berendezkedését. A napóleoni háborúk felélesztették az európai népek nacionalizmusát is. A „szabadság, egyenlőség, testvériség” jelszava, a francia forradalmi eszmék beépültek az európai polgárság politikai törekvéseibe. A bécsi kongresszus (1814–1815) szellemisége ókonzervatív volt ezzel szemben. A kialakuló Szent Szövetség rendszere az 1789 előtti állapotokat szerette volna restaurálni, így a Metternich által működtetett titkosrendőrség és cenzúrahivatal korlátozta a polgári szabadságjogokat, illetve a sajtószabadságot. A liberalizmus politikai áramlata a szabadságeszme megteremtését tűzte ki célul a 19. század első felében. A szabadelvű gondolkodók a felvilágosodás eszméit fejlesztették tovább. Céljuk: a polgári állam megteremtése.\n\nEgyéni szabadságjogok: a tulajdonhoz való jog, a szólás- és véleménynyilvánítási szabadság, a vallásszabadság.\n\nTársadalmi és politikai szabadságjogok: gyülekezés szabadsága, sajtószabadság, parlamentnek felelős kormány.\n\nA 19. századi liberálisok szerint csak a művelt és megfelelő anyagi háttérrel rendelkező polgárság tud működőképes demokráciát kialakítani. Úgy vélték, a polgári állam kiépülése megteremti az alsóbb rétegek felemelkedését, ezután kibővülhet a politizálók köre.\n\nNACIONALIZMUS:\n\nA nacionalizmus lényege a nemzeti összetartozás-tudat, a XIX. század első felében keletkezett, bontakozott ki Európában és Amerikában. A nemzeti eszme forradalmi volt. A nacionalizmus összekapcsolódott a liberalizmussal, a szabadsággal és a függetlenséggel.\n\nA nacionalizmus főbb jellemzői és céljai: nemzeti eszme (náció = nemzet)\n\na nacionalizmus a francia forradalom hatására (és ellenhatására) kialakult politikai eszme. Franciaország egyszerre volt minta és ellenségkép.\n\nA nacionalizmus teremti meg a modern nemzetet.\n\nA nacionalizmus termékenyítő hatással volt a nemzeti kultúrára.\n\nA nacionalizmus célja a nemzetállam létrehozása volt, pl. ez egyesítési vagy függetlenségi mozgalmak a nacionalizmus jegyében jöttek létre.\n\nAz államhatalmat a nemzettől és nem az uralkodótól eredeztette.\n\nA későbbiekben konfliktusokat okozott a nemzetek között.\n\nKapcsolatban áll a liberalizmussal:\n\nközös céljuk volt az állampolgárok, azaz nemzettársak jogegyenlősége;\n\nközös céljuk volt az alkotmányos állam / népszuverenitás / ellenőrzött hatalom.\n\nA nacionalizmus a XIX. század első felében tehát összefonódott a liberalizmussal. Mindkettő forradalmi eszme.\n\nMazzini szerint a nemzetet összetartó kapcsok: a közös nyelv és kultúra; közös terület; közös történelem.\n\n„Huszonegy-huszonkétmilliós nép vagyunk, melyet emberemlékezet óta ugyanazzal a névvel illetnek, az olasz névvel, melyet az Isten által valaha húzott legpontosabb természetes határok, zárnak körül, mely ugyanazon nyelvet beszéli. Ugyanazon hitet vallja, melynek ugyanazok a szokásai és hagyományai, […] amely büszke Európa szerte ismert politikai, tudományos és művészeti múltjára.” (Giuseppe Mazzini: Itália,1845)\n\nA nacionalizmus a nemzetet „öröktől” létezőnek tartotta. A nacionalizmusban nagy szerepe volt a „nemzeti dicsőségnek” pl. a franciák dicsőséges forradalma és terjeszkedése. Franciaországban ennek nemzeti jelképe a trikolór. A forradalmárok képviselik a nemzet tagjait. Pl. Delacroix: A szabadság vezeti a népet, 1830 című festményén egy nőalak harcba hívja a franciákat, mely a szabadságot jelképezi. A művészetek fontos szerepet játszottak a nemzeti eszme elterjedésében.\n\nMagyarországon a nacionalizmus és a liberalizmus együtt jelenik meg. „Jelszavaink valának: haza és haladás.” (Kölcsey) A két eszme jegyében születtek a reformkori költemények: Kölcsey Ferenc: Himnusz, Vörösmarty Mihály: Szózat; nemzeti drámánk Katona József: Bánk bán, melynek Erkel Ferenc komponálta az operaváltozatát, ezt mutatták be 1848. március 15-én.\n\nAz újfajta nemzeti eszme, a nacionalizmus a napóleoni háborúk alatt bontakozott ki Európában. Mindenhol háttérbe szorult a rendi nemzetfelfogás, amely évszázadokon keresztül csak a kiváltságosakat tekintette a nemzet részének. A kibontakozó mozgalmak széles körű nemzeti megújulást hirdettek (például nyelvújítás, irodalom, képzőművészet). A nemzet felemelésébe beletartozott a közös azonosságtudat (identitás) kialakítása, a történelmi múlt feltárása és újraértelmezése. A soknemzetiségű, idegen dinasztiák által irányított birodalmak népei sokszor a másikkal szemben is meghatározták magukat, és a történelmi gyökereket gyakran hamis színben tüntették fel. A nacionalizmus változatai:\n\na nemzet nagyságát hirdető franciák\n\na soknemzetiségű birodalmak népeinek nemzeti törekvései\n\naz egységesítés igénye a több uralkodó fennhatósága alatt álló olaszok és németek estében.\n\nNemzetállami törekvések a XIX. század első felében\n\nA SZENT SZÖVETSÉG Európája\n\n1815. szeptember 26-án I. Sándor orosz cár, I. Ferenc osztrák császár és III. Frigyes Vilmos porosz király aláírt egy nyilatkozatot, amelyben kifejtették a vallás szent elveit és a testvéri összefogás szükségességét a politikában: ez a Szent Szövetség.\n\n1815. november 2-án orosz-osztrák-porosz-angol „Négyes Szövetség” létrehozása - az aláírók meghatározott időközökben találkozókat rendeznek, ahol megtárgyalják és megoldják a felmerülő kérdéseket. A Négyes Szövetség tagjai egy pár évig a megállapodásnak megfelelően tanácskoztak és döntöttek:\n\n• Első ülésük 1818. Aachen: Franciaország csatlakozik a szövetséghez (XVIII. Lajos).\n\n• Második ülésük 1819. Karlsbad: német területek diákmozgalmainak megfékezése.\n\n• 1820-21: Troppau és Laibach: nápolyi alkotmányos mozgalom megfékezése.\n\n• 1822. Verona: a spanyol alkotmányos mozgalom megfékezésére francia csapatokat küldtek.\n\nGörög szabadságharc (1820-21)\n\n• 1821-ben kezdődött a görögök szabadságharca, amelyben a nagyhatalmak a görögök oldalára álltak, és segítségükkel a görögök győztek a törökök ellen.\n\n• 1830-ban a londoni konferencián független királysággá nyilvánították Görögországot.\n\nDekabrista felkelés (1825) Oroszországban: I. Miklós kegyetlenül leverte.\n\nA „Szent Szövetség”, vagy inkább a nagyhatalmi Ötös Szövetség az 1820-as évek elején elég jól működött, a forradalmi jellegű mozgalmakat, ha kellett, erővel, de elfojtották.\n\n1830-ban azonban forradalmi megmozdulások kezdődtek.\n\n• Franciaország: „júliusi forradalom” - július 27-29.: a párizsi munkások, értelmiségiek, polgárok felkelése elsöpörte Bourbon X. Károly (1824-1830) uralmát, és Lajos Fülöpöt választották királlyá (1830-48).\n\n• Belgium: függetlenedés a Németalföldi Királyságtól (1830. október 4-én).\n\n• Lengyel területeken felkelés kezdődött a cári hatalom ellen: a lengyelek kinyilvánították függetlenségüket (1831. január 25.), de az orosz csapatok 1831. május 14-én Osztrolenkánál legyőzték a lengyel seregeket, ezután Paszkievics nagyherceg bevonult Varsóba.\n\nAz 1848-as forradalmak\n\nA kontinens nyugati felén a választójog és a munkáskérdés, középső és keleti felén a nemzeti-függetlenségi törekvések és a jobbágykérdés tovább növelték a feszültséget. 1848 tavaszán Anglia és Oroszország kivételével (a legfejlettebb és a legelmaradottabb) egész Európában „láncreakcióként”, egymást erősítve robbantak ki a forradalmak. Franciaországban – mivel a feudális kötöttségek már jórészt megszűntek – demokratikus alkotmányt, köztársaságot, Németországban alkotmányosan is biztosított nemzeti egységet, Magyarországon polgári alkotmányt, jogkiterjesztést, a feudális rend felszámolását majd függetlenséget, Itáliában függetlenséget és az olasz egység létrehozását, a Balkánon pedig nemzeti felemelkedést, autonómiát kívántak. 1847-ben a svájci liberális és katolikus kantonok közötti polgárháború eredményezett új szövetségi liberális alkotmányt, majd Itáliában bontakoztak ki függetlenségi, Habsburg- és Bourbon-ellenes megmozdulások (1847 Ferrara, 1848 január, Palermo). Az 1848 február 22-24-i párizsi forradalom megdöntötte a monarchiát (Lajos Fülöp, 1830-48), létrejött a Második Köztársaság, mely a munkáskérdés megoldása érdekében számos áttörést jelentő intézkedést hozott (általános választójog, tízórás munkanap, munkához való jog). A Habsburg Birodalom területén 1848 tavaszán mindegyik 100 ezer főnél nagyobb városban felkelés tört ki (március 13. Bécs, március 15. Pest, március 18. Milánó, március 22. Velence). Az osztrák csapatok kiűzése, ill. kivonulása után sorra alkotmányos kormányok alakultak (Nápoly, Firenze, Róma), sőt, Piemont hadat is üzent Ausztriának. Magyarországon 1848. március 15-én tört ki forradalom, majd 1848. szeptember 11-én elindult a szabadságharc. Bár eredetileg nem volt cél a Habsburg Birodalomtól való függetlenség, de Ferenc József 1849. március 4-i olmützi alkotmányára (tartományi szintre süllyeszti Magyarországot) válaszul 1849. április 14-én Debrecenben Kossuth Lajos kinyilvánította a függetlenségünket és a Habsburg-ház trónfosztását (detronizáció).\n\nA galíciaiak körében is sor került csekély erejű megmozdulásra, a cseh radikálisok is felkelést robbantottak ki 1848 júniusában. Metternich bukásával Ausztriában és Magyarországon alkotmányos kormányok alakultak, az új alaptörvények felszámolták a jobbágyságot. A berlini forradalom (1848. március 18.) következtében létrejött liberális kormány az általános választójog alapján összehívta a porosz alkotmányozó nemzetgyűlést, majd Frankfurtban összeült az első össznémet nemzetgyűlés. Még a román fejedelemségek, Moldva és Havasalföd területén is – melyek 1829 óta a Porta fennhatósága, de orosz protektorátus alatt voltak – mozgolódás volt tapasztalható.\n\nA forradalmak – kevés kivétellel- hasonló módon zajlottak le Európa-szerte. A különböző ellenzéki erők együttesen megdöntötték a kormányzatot (1848. február-április), majd a liberálisok kiválásával a korábbi egység felbomlott, s a különböző társadalmi-politikai erők ellentétbe kerültek egymással (1848. május-június). A következő szakaszban a radikálisok, illetve a munkásság megkísérelték saját erejükből folytatni a forradalmat, de leverték őket (1848 június-október). Végül az ellenforradalom felülkerekedése a liberálisokat is elsöpörte (1848 október-december). 1848-ban úgy tűnt, hogy az európai hatalmi rendszer összeomlik, és a meghirdetett célok Európa-szerte megvalósulnak (nemzeti önrendelkezés, modernizáció, nemzetállamok megteremtése, liberális politikai rendszerek létrehozása).\n\nA forradalmakat azonban leverték, melyekben a következők játszottak szerepet:\n\n1.) A liberális és radikális erők közötti szakadás.\n\n2.) A kibontakozó gazdasági fellendülés következményeként a forradalmak egymást erősítő hatása, a „láncreakció” lefékeződött.\n\n3.) Az eltérő, és sokszor csak egymás rovására megvalósítható célok nem tették lehetővé a forradalmi térségek aktív együttműködését.\n\n4.) A paraszti tömegek általában közömbösen figyelték az eseményeket, így a forradalmak többnyire városi jelenségek maradtak (kivétel Magyarország).\n\n5.) A fegyveres erők hűek maradtak a konzervatív kormányzatokhoz, és segítettek a „rendcsinálásban”.\n\n6.) A meghatározó európai hatalmak külpolitikai magatartása (Anglia passzivitása, és aggodalma a status quo felborulása miatt, Oroszország ellenforradalmi aktivitása, intervenciós hajlama a Szent Szövetség szellemében).\n\n7.) Az európai dinasztiák (Hohenzollern, Romanov, Habsburg) ereje, kemény fellépése, és egymás közti szolidaritása.\n\n8.) A politikai-gazdasági széttagoltság (Itália, német területek).\n\n9.) A birodalmi keretek között élő, függetlenségre törekvő népeket szembeállító türelmetlen nacionalizmus (pl. Magyarország).\n\nA forradalmak mégsem maradtak következmények nélkül: néhány liberális alkotmány, valamint a jobbágyfelszabadítás, Franciaországban az általános választójog érvényben maradtak, Közép-és Kelet-Európa területén pedig felgyorsult a modernizáció, a feudális rendszerek megszűnésével ill. gyengülésével megkezdődhetett a polgári-tőkés viszonyok kialakulása, a dinasztikus nagyhatalmi politika átrendeződése.\n\nAz olasz egység létrejötte\n\n1848-1849-ben az olasz forradalmi és egységmozgalmakat az osztrákok és a franciák leverték. A forradalmi úton nem valósult meg Itália egysége1848-ban.\n\nAz egységet majd dinasztikus úton, az alkotmányos Szárd Királyság (Piemont) valósította meg. Az események irányítója a Piemont miniszterelnöke, a tehetséges Cavour lett. Cavour az egység fő akadályát jelentő Ausztriával szemben igyekezett hatalmi támogatást szerezni. Felismerte, hogy a franciákkal és az osztrákokkal nem képes egyszerre szembeszállni. A franciák és az angolok jóindulatának megnyerése érdekében jelentős szárd hadsereget küldött a krími háborúba (1853-56). III. Napóleon francia császárt Savoya és Nizza átengedésével nyerte meg az Ausztria elleni fellépésre. A kirobbanó francia-szárd-osztrák háborúban az osztrák haderő vereséget szenvedett (Solferino, 1859).\n\nNapóleon becsapta Cavourt. Nizzát és Savoyát megkapta Piemonttól, majd gyorsan fegyverszünetet kötött az osztrákokkal (Villafranca). A megállapodás csak Lombardiát adta Piemontnak, míg Ausztria kezén hagyta Velencét. A kirobbanó közép-itáliai Habsburg-ellenes mozgalmakat az osztrákok nem tudták leverni. A Piemonttal korábban szövetséges franciák pedig nem léphettek fel nyíltan, így a közép-itáliai kis államok kimondták egyesülésüket Piemonttal (1860). A tömegmozgalmak Dél-Itáliára is kiterjedtek. Garibaldi vörösingesei és a magyar emigránsok támadást indítottak a Nápolyi Királyság ellen. Szicíliában partra szálltak (1860), majd a népfelkelésre támaszkodva megdöntötték a királyi hatalmat. Megnyílt az út Dél-Itália csatlakozásához. Ekkor mutatkozott meg Cavour politikai éleslátása. Seregeit ő is Nápoly ellen küldte, hogy megakadályozza Garibaldi Róma ellen vonulását, mely kiválthatta volna III. Napóleon beavatkozását. Ezzel Róma és Velence kivételével egész Itália az új olasz királyság fennhatósága alá került (1861) amelynek uralkodója a szárd király lett: II. Viktor Emánuel. Az egységfolyamat teljes győzelmét nem az olaszok vívták ki. A német egységért folyó harcokban Poroszország először Ausztriára (1866), majd Franciaországra (1870) mért vereséget. A német győzelmek először Velence (1866), majd Róma felszabadulását (1870) hozták meg. Dél-Európában több mint 30 millió lakosú új állam született, amelynél az óriási belső problémák (pl. az északi és déli rész közötti különbségek) ellenére is az egységes politikai irányítás megteremtette a gyorsabb fejlődés lehetőségét.\n\nA német egység létrejötte\n\n1806-ban felbomlott a Német-római Császárság a napóleoni háborúk alatt.\n\n1815 (bécsi kongresszus) óta a német területeket a Német Szövetség (Bund) fogta össze.\n\n1839-től 18 állam részvételével megalakult a Német Vámszövetség (Zollverein), ez elősegítette a gazdasági integrálódást.\n\nAz 1848/49-es forradalmak idején felvetődött az egység kérdése (frankfurti parlament), de sikert nem tudtak elérni.\n\n1849 után 2 útja kínálkozott a német egység létrehozásának:\n\n• Nagynémet egység: A katolikus Habsburg-dinasztia vezetésével\n\na német államok viszonylag laza föderációja, amelyhez a Habsburg Birodalom nem német tartományai is hozzá tartoznak.\n\n• Kisnémet egység: A protestáns Poroszország vezetésével, a Habsburg Birodalmat nem magába foglaló német nemzetállam kialakítása.\n\nA német egység-folyamat vezetéséért Poroszország és Ausztria versengett, amiből Poroszország került ki győztesen:\n\n• Gyorsabban modernizálódott, azaz gyorsan növekedett az ipari termelése; átalakult a mezőgazdaság, modernizálták a junker nagybirtokokat; nagy ütemű vasútépítés zajlott le.\n\n• Tehetséges politikus irányította: Ottó von Bismarck (vaskancellár 1862-1890):\n\n— sikeres hadseregfejlesztés (3 év szolgálati idő, modern fegyverek);\n\n— ragyogó külpolitikai stratégia (szövetségesek szerzése, Ausztria elszigetelése).\n\n• Nagyon jó felkészültségű volt a hadvezetése (Moltke).\n\nA porosz-osztrák konfliktus az 1860-as években éleződött ki:\n\n• 1863: Ferenc József a frankfurti birodalmi gyűlésen császárrá akarta választatni magát — sikertelenül;\n\n• 1863—65: Schleswig-holsteini konfliktus: Dániát még közösen megleckéztetik, de vita lesz a hercegségek sorsáról.\n\nA porosz (olasz) - osztrák háború (1866):\n\n• Poroszország jó külpolitikai légkörben, egy szövetségessel, míg Ausztria elszigetelődve vágott neki az elkerülhetetlen testvérháborúnak.\n\n• Bár az osztrákok az olasz fronton győztek (Custozza, 1866. június 24.), de a porosz hadseregtől vereséget szenvedtek (Königgrátz, 1866. július 3.).\n\n• 1866. augusztus 23-án Prágában kompromisszumos békekötés:\n\n— Feloszlatták a Német Szövetséget (helyébe Poroszország 1867-ben megszervezte a Majnától északra fekvő államokból az Észak-Német Szövetséget.\n\n— Az egységes német államból kimaradt a Habsburg Birodalom, hadisarcot is kellett fizetnie.\n\n— Ausztria területeket veszített (Olaszországnak át kellett adnia Velencét), és kimaradt az új német államból, de nem omlott össze, nem gyengült meg végzetesen.\n\nHatása: A porosz-osztrák háború során - ahol a Habsburgok veszítettek - kiszorultak a német egységből, ezért megegyezést kerestek a magyarokkal.\n\nA külpolitikai tényezők hatására 1867. februárjában megszületett az osztrák – magyar kiegyezés (1867/ 12. törvénycikk). Az új állam neve Osztrák – Magyar – Monarchia (OMM), uralkodója Habsburg Ferenc József.\n\nA porosz-francia háború (1870):\n\n• A francia—porosz viszonyban Luxemburg kérdése okozott feszültséget (végül 1867-ben kimondták semlegességét és önállóságát), és a dél-német, főként a Rajna menti területek.\n\n• Bismarck 1870-ben kiprovokálta a háborút, amelyet a poroszok gyorsan megnyertek (Sedan, 1870. szeptember 2. - III. Napóleon francia császár letette a fegyvert). • 1871. január 18-án a versailles-i palota tükörtermében a német fejedelmek proklamálták a Német Császárság létrejöttét. I. Vilmos porosz királyt a Német Birodalom császárává kiáltották ki. A német egység nem alulról szerveződve, nem demokratikus úton, hanem háborúk révén, dinasztikus úton jött létre.\n\n• A békekötésre 1871. május 10-én Majna-Frankfurtban került sor:\n\nNémetország megkapta Elzász-Lotharingiát; Franciaországnak 5 milliárd frank hadisarcot kellett fizetnie. Fenntartotta a külpolitikai veszélyérzetet Franciaországgal szemben.\n\nMegmaradt az állam mozaikos (szövetségi) jellege, domináns volt Poroszország szerepe.\n\n• A Birodalom szervei:\n\nSzövetségi Tanács (Bundesrat): a szövetségi államok küldöttjei alkotják, hatásköre: hadügy, külügy, közlekedés, valamint a vámok és a kereskedelem ügyei;\n\nBirodalmi Gyűlés (Reichstag) megszavazta (jóváhagyta) a törvényjavaslatokat és a költségvetést. A kormány: vezetője a kancellár, aki a külügyek teljhatalmú irányítója.\n\n• Bismarck, a vaskancellár törekedett a heterogén birodalom egységesítésére:\n\n• Kultúrharcot hirdetett meg (Kulturkampf): 1872-86: a protestáns többségű birodalomban megkezdődött a katolikus egyház világi befolyásának visszaszorítása. Pl. polgári házasság.\n\nAz egységes Németország nagyhatalmi igényekkel lép föl, mely az első világháború kitöréséhez vezet 1914-ben. A 2. ipari forradalom legdinamikusabban fejlődő állama.\n\nAz USA kialakulása\n\n• 1587: az első angol gyarmat, Virginia megalapítása, majd 1620-ban a Mayflower hajó puritán utasai északabbra megalapították Plymouth városát, és megindult a keleti partvidék benépesítése.\n\n• A XVIII. sz. közepén 13 angol gyarmat volt, amelynek az anyaországgal egyre nagyobb ellentétei támadtak (pl. adóztatás: cukortörvény, bélyegtörvény - 1765).\n\n• 1773. dec. 16.: a bostoni teadélután nyomán Anglia szigorú intézkedéseket vezetett be (katonai kormányzás).\n\n• 1775-1783: függetlenségi háború\n\n• 1775: a második kontinentális kongresszus G. Washington vezetésével felállította a gyarmatok hadseregét;\n\n• 1776. júl. 4.: Függetlenségi Nyilatkozatot fogadott el a kongresszus, amely megalapozta az USA politikai rendszerét: „...Minden ember egyenlőnek teremtetett”, olyan jogok illetik meg, mint az „élet, a szabadság, a boldogságra törekvés”,\n\n• az amerikai hadsereg (porosz, lengyel katonákkal; francia támogatással) 1777-ben Saratogánál, majd 1781-ben Yorktownnál legyőzte az angolokat;\n\n• 1783: versailles-i béke - Anglia elismerte a 13 gyarmat függetlenségét.\n\n• 1787-ben elfogadták az USA alkotmányát, amely az első, a hatalommegosztás elvére (Montesquieu) épülő, modern köztársasági alkotmány volt: szövetségi állam, széles körű elnöki hatalommal.\n\n• 2 kamarás törvényhozás (kongresszus): szenátus: államonként 2-2 fő, és a képviselőház: az államokból lakosság-arányosán érkező küldöttek;\n\nJelentősége:\n\nA Függetlenségi Nyilatkozatban megfogalmazott jogok biztosítékául hozták létre 1787-ben az alkotmányt. Ennek értelmében szétválasztják a törvényhozó, végrehajtó és igazságszolgáltató hatalmat (hatalommegosztás elve), és ezek egyensúlyát teremtették meg, egymást ellenőrzik, és egymásnak felelősséggel tartoznak. Ezek az alapvető elvek a mai napig érvényesek az USA-ban. Megteremtették a demokráciát, a népszuverenitás elvét. Az alkotmányban érvényesül a képviseleti elv. Általános választójoggal rendelkezik. Megteremtették a politikai szabadságjogokat, a gyülekezés, a szólás és a sajtó szabadságát, szabad versenyt, vállalkozás szabadságát.. Az egyházat és az államot szétválasztották egymástól, de vallásszabadságot biztosítottak. A feketéket, és a rabszolgákat azonban nem illették meg a polgárjogok.\n\nAz USA politikai berendezkedése, demokratikus intézményei\n\nAz amerikai Függetlenségi nyilatkozatban és az alkotmányban a felvilágosodás hatását és az alkotmányosság alapelveinek az érvényesülését figyelhetjük meg. Az amerikai Függetlenségi nyilatkozat kiadására 1776. július 4-én került sor, és alapvető szerepet játszott az Amerikai Egyesült Államok létrejöttében. A nyilatkozat kiadásának körülményei: a 13 amerikai angol gyarmat adja ki, az amerikai függetlenségi háború részének tekinthető. A déli és az északi államok egységesen lépnek fel az angolok ellen. Ez az az esemény az USA megalakulásáig, a függetlenség kivívásáig vezet.\n\nA felvilágosodás hatása egyértelműen kimutatható a nyilatkozatban pl. megjelenik a népfelség elve, a zsarnok uralkodó eltávolítható, az észelvűségre hivatkozik. Az alkotmányosság alapelvei jelennek meg: az egyenlőséghez, szabadsághoz, élethez való jog, tehát az emberi jogok érvényesülését fontosnak tartják. Az emberi jogok biztosítását később törvénybe is foglalják. Az alkotmányosság alapelvei: a hatalmi ágak elválasztása, a népszuverenitás, a törvények uralma, az emberi és polgári jogok. A nép jogának tekinti a fennálló rend megváltoztatását. A nyilatkozatban az emberi jogok érvényesülésének igénye elsődleges, megjelenik a népszuverenitás érvényesülésének a fontossága.\n\nA végrehajtó hatalom a négy évre választott elnök kezében összpontosul. Szövetségi rendszeréből adódóan az elnöki hatalom erős. Ő a végrehajtó hatalom feje. Tehát a kormány élén áll. Kétpárti váltógazdaságról beszélhetünk az USA-ban; a Demokrata és a Republikánus Párt (Köztársaságpárt) jelöltjeiből kerülnek ki az elnökök, a kormány tagjai és a képviselők. Az elnököt állam- és kormányfőként a pártok jelölése alapján az egyes államok választói közvetve, elektorok útján választják meg négy évre. Egyszeri újítás lehetséges, de Roosevelt elnök kivételt képezett, mert őt négyszer is megválasztották, így 1933-tól 1945-ig volt elnök. Az elnök nevezi ki a minisztereket. Munkáját az alelnök segíti, aki az elnököt helyettesítheti. Az elnököt csak közjogi vádemelés alapján lehet elmozdítani. Politikailag a Kongresszus, alkotmányjogilag a Legfelső Bíróság ellenőrzi.\n\n2. A törvényhozó hatalom: a kétkamarás Kongresszus\n\nA képviselők eltérő módon kerülnek a két fel nem osztható házba. Az egyik a Képviselőház, melynek tagjait két évre közvetlenül választják. Itt helyezkednek el a demokraták és a republikánusok. A másik a Szenátus, melyben államonként (52 állam) 2 képviselő vesz részt benne 6 évre. Kétévente azonban a szenátorok egyharmadát újraválasztják. Az elnök a vétójogával és a Legfelső Bíróság felügyeli a törvényhozást, tehát működik a hatalmi ágak egymás fölötti ellenőrzése.\n\n3. Az igazságszolgáltató hatalom: a Legfelsőbb Bíróság\n\nAz alkotmány és a törvényhozás jogi felügyeletét gyakorolja. 9 tagja van, amely az elnöktől független, s élethossziglan nevezik ki őket, melyet a szenátus erősít meg.\n\nAz alkotmány első módosítása 1791-ben (Bill of Rights: állampolgári jogok rögzítése).\n\nA függetlenség kivívása után folyamatosan növekedett az USA területe:\n\n• I. hullám (1803-19): Louisiana (Franciaországtól), Florida;\n\n• II. hullám (1845-53): Texas, Oregon, Új-Mexikó, Kalifornia;\n\n• 1867: Alaszka (Oroszországtól).\n\nAz újonnan csatlakozott területek őslakóit, az indiánokat egyre nyugatabbra szorították.\n\nA gyors gazdasági fejlődés tényezői:\n\n• hatalmas szabad területek vonzották a betelepülőket (olcsó földvásárlás);\n\n• munkaerőhiány: vonzotta a betelepülőket (magasabb munkabér) és inspirálta a műszaki fejlesztést (gépesítés Északon) és felgyorsította a rabszolgaság terjedését Délen.\n\n• tőkehiány: Anglia biztosított tőkét;\n\n• egyre bővülő piac és termelés.\n\nKIFEJTÉS\n\nAZ USA KIALAKULÁSA\n\nÉszak-Amerika azon területein, ahová a spanyol gyarmatosítás nem ért el, a XVII. századtól egyre nagyobb számban jöttek létre angol, illetve francia telepek. Észak-Amerika keleti partvidékén 1606-tól (Virginia) 1733-ig tizenhárom angol gyarmat alakult ki, amelyek rendkívül gyorsan fejlődtek az Angliából folyamatosan érkező kivándorlásnak köszönhetően. A gyarmatok társadalma alapvetően agrár jellegű volt. Mivel a gyarmatok késői felfedezése miatt eleve kikerülték a feudális termelési módot, azonnal a tőkés árutermelés alakult ki rajtuk, amit megkönnyített a földbőség is. Jóllehet az agrárfejlődés tőkés útjára léptek, mégis két eltérő fejlődési utat figyelhetünk meg. Az északi területeken jórészt kisparaszti farmergazdálkodás folyt, míg a déli gyarmatokon a rabszolga munkaerőt alkalmazó ültetvényes gazdálkodás honosodott meg. Anglia és a gyarmatok kapcsolata a merkantilista politikán alapult, az angolok elsősorban nyersanyagforrást és felvevőpiacot láttak gyarmataikban, és akadályozták rajtuk a konkurenciát jelentő iparosítást, hajóépítést és a növekvő külkereskedelmi aktivitást. A gyarmatok termékeit angol kereskedők vásárolták föl, akik monopóliumokat élveztek a gyarmati kereskedelemben.\n\nA gyarmatokon gyorsan fejlődtek a tőkés viszonyok, és minél fejlettebb lett gazdaságuk, annál terhesebbnek érezték az anyaország gyámkodását. Érdekeik védelmében először 1754-ben Benjámin Franklin kezdeményezésére tartottak közös kongresszust, ekkor azonban még nem kerültek élesen szembe az angol koronával, mert a francia gyarmatok fenyegetése miatt rászorultak Anglia fegyveres erejére. A hétéves angol-francia háború (1756-1763) után, melyben a franciák elvesztették észak-amerikai gyarmataikat, megszűnt az egymásrautaltság.\n\nAz angolok a háború költségeinek megfizetésére új adókat és illetékeket vezettek be. A gyarmatokon tiltakozási mozgalom bontakozott ki ez ellen. Az Angliához fűződő viszonyt illetően a gyarmatok lakossága azonban nem volt egységes. A hivatalnokok, az ültetvényesek egy része és a monopóliumok kedvezményezettjei loyalista (királypárti), Angliához hű álláspontot képviseltek. A gyarmati lakosság többsége, a farmerek, kereskedők, polgárok, a patrióták, vagyis hazafiak azonban annak az elvnek az alapján, hogy „nincs adóztatás képviselet nélkül”, készek voltak szembefordulni a brit koronával. A gyarmatok az angol tradíciók alapján álltak, s mint brit állampolgárok, úgy vélték, hogy csak akkor adóztathatók, ha az adott törvény választott képviselőiknek a közreműködésével készült, márpedig a gyarmatoknak nem volt képviselőjük a brit alsóházban. A sorozatos tiltakozó akciók, a bojkottmozgalom és a tüntetések hatására az angol kormány végül semmisnek nyilvánította a rendeleteit. Kivételt képezett a teavám, amivel azt kívánták kifejezésre juttatni, hogy az angol parlament gyakorolja a fennhatóságot az amerikai gyarmatok felett. A gyarmati polgárok számára viszont az adózási elv volt a fontos, ezért az angol politika elleni tiltakozásul 1773-ban a bostoni kikötőben egy angol hajóról a tengerbe dobálták a teás ládákat -„bostoni teadélután-, amire az angolok erőszakkal válaszoltak.\n\n1774-ben Philadelphiában a tizenhárom gyarmat képviselői összeültek az első Kontinentális Kongresszusra, amelyen természetes emberi jognak nyilvánították az önkényuralommal való szembeszegülést, fegyveres harcra szólították a gyarmatokat, noha még keresték a megegyezés lehetőségeit Angliával, III. György azonban le akart számolni a lázadókkal. 1775-ben Lexingtonban dördült el az a sortűz, a vitát most már a fegyvereknek kellett eldönteniük. Májusban összeült a második Kontinentális Kongresszus. George Washingtont kinevezték a kontinentális hadsereg parancsnokává, az angol hatóságoktól „biztonsági bizottságok” vették át a hatalmat, melyek irányították a helyhatóságokat, a bíráskodást, toborozták a hadsereget.\n\n1776-ban a Kontinentális Kongresszus utasítására Thomas Jefferson megfogalmazta a Függetlenségi Nyilatkozatot, melyet mind a tizenhárom gyarmat képviselői július 4-én elfogadtak. Ezután teljes erővel megindult a függetlenségi háború. A hivatásos katonákból és német zsoldosokból álló angol erők jelentős fölényben voltak, ennek ellenére nem tudtak elbánni az amerikai csapatokkal, sőt 1777-ben Saratogánál Washington jelentős győzelmet aratott. A siker hatására Franciaország elismerte az Egyesült Államok függetlenségét, és szövetséget kötött vele Anglia ellen. A döntő összecsapásra 1781-ben Yorktownnál került sor, ahol a francia segítségnek köszönhetően az amerikaiak győztek. A sorozatos vereségek hatására az angol parlament többsége a békekötés mellett döntött. A szerződést 1783-ban Versailles-ban írták alá.\n\nA függetlenség kivívása után nehéz helyzetben volt az új állam. Tetemes volt az államadósság, nőtt az infláció, a hagyományos kereskedelmi kapcsolatok megszakadtak. A gazdasági nehézségeket fokozták a politikai problémák. A tizenhárom gyarmat 1781-től laza konföderációt alkotott, a kongresszus lényegében a királyi jogköröket vette át. A tizenhárom független állam élte a maga külön életét. A probléma megoldására 1787-ben szövetségi alkotmányozó gyűlés ült össze, s kidolgozta az Unió alkotmányát, amely 1789-ben lépett hatályba. Ezzel megalakult az Amerikai Egyesült Államok, melynek első elnökévé George Washingtont választották.\n\nAz Egyesült Államok alkotmánya szétválasztotta a hatalmi ágakat, a törvényhozói, a végrehajtó és a bírói hatalmat, s igyekezett egyensúlyt teremteni közöttük.\n\nA végrehajtói hatalmat közvetlenül a négy esztendőre választott, rendkívül széles jogkörrel rendelkező elnök gyakorolja, aki nem tartozik felelősséggel a kongresszusnak, sőt határozatait meg is változtathatja, a hivatali idejében lényegében elmozdíthatatlan posztjáról.\n\nA törvényhozó hatalmat a kongresszus gyakorolja, mely két házból, a szenátusból és a képviselőházból áll. A szenátusban minden államot két-két szenátor képvisel, a képviselőházba pedig a lakosság arányában választják államonként a képviselőket. A szenátus beleegyezése kell a fontosabb állami állások betöltéséhez, a képviselőház pedig az adókat szavazza meg.\n\nA legmagasabb bírói hatalmat a Legfelsőbb Bíróság gyakorolja, melynek tagjait élethossziglan az elnök nevezi ki, a szenátus beleegyezésével. A Legfelsőbb Bíróság egyben alkotmánybíróságként is működik.\n\nAz alapvető emberi szabadságjogok kimaradtak az alkotmányból. Ezeket 1791-ben az első tíz alkotmány-kiegészítés csatolta az alaptörvényhez.\n\nAz Egyesült Államok önálló állami élete mellett nagyarányú terjeszkedési politikába fogott. Fél évszázad alatt - Kanada kivételével - vásárlással (Louisiana, 1803), beszivárgással (Texas, 1844) vagy háborúval (Új-Mexikó, 1848) az egész észak-amerikai kontinenst birtokába vette. A nyugati irányú terjeszkedést a földszerzés hajtotta. Sorra alakultak az államok a nyugati területeken, és váltak az Államok tagjává.\n\n1818-ban Missouri állammá alakulásakor azonban egy később súlyos problémákat okozó kérdés került előtérbe. Mely területeken megengedett a rabszolgaság az USA-ban, s mely területeken nem? Az északi államokban (a Mason-Dixon-vonaltól északra) a XVIII. század végén, a XIX. század elején fokozatosan megszűnt a rabszolgaság. A déli államokban azonban az alkotmányt is csak akkor fogadták el, ha nem tiltotta. Az 1800-as évek elején a cukomádtermesztés meghonosítása és a gyapottisztító gép alkalmazása a rabszolgatartó ültetvényes gazdaságot megerősítette, aminek következtében a déliek nagyobb befolyásra kívántak szert tenni a kormányban.\n\n1820-ban még kiegyenlítettek voltak az erőviszonyok. Az északi és déli államok a status quo megőrzésére törekedtek, aminek az eredménye a Missouri-kompromisszum volt, mely kimondta, hogy Északon tilos a rabszolgatartás. S hogy a szenátusi arányok föl ne boruljanak, ezentúl alkalmanként egyszerre egy rabszolgatartó és egy szabad államot fognak fölvenni az Unióba.\n\nMAGYARORSZÁG POLGÁRI NEMZETÁLLAMA\n\nElőzmény: A KIEGYEZÉS\n\nI. A kiegyezéshez vezető út: kísérletek Magyarország beolvasztására:\n\n1849. augusztus 13-án a Habsburgok az oroszok segítségével leverik a magyar szabadságharcot. Ezután Haynau rémuralma következett 1850-ig. Több száz embert börtönöztek be vagy végeztek ki, pl. a 13 tábornokot Aradon és Batthyányt Pesten 1849. október 6-án.\n\nMagyarországgal és a birodalommal kapcsolatban 2 elképzelés merült fel:\n\n1. Schwarzenberg  centralizáció: szerinte a beolvasztás után Magyarország Ausztriával centralizált állam legyen (központosítás). Az elnémetesítés folyamatát akarta beindítani  nyílt germanizáció\n\n2. Windischgrätz: a föderáció híve volt (laza államszövetség), bizonyos ügyekben a magyarok önállóak lehetnek\n\n1850-59 között Alexander von Bach belügyminiszter által vezetett időszak  a Bach-korszak (Neoabszolutizmus) Intézkedései:\n\n1.- Mo. területét feldarabolta:- leválasztották Erdélyt, Horvátországot, Vajdaságot és a határvidéket (ezeket a területeket teljesen Ausztria irányította). A maradék területet 5 kerületre osztotta 5 fő központtal: Pozsony, Buda, Sopron, Kassa, Nagyvárad\n\n2. - Bevezette az osztrák adótörvényt 1850-től, nyílt germanizálás folyt\n\n3. - 1852-től az osztrák büntető-törvénykönyvet és polgári törvénykönyvet is\n\n4. - 1853-tól törvénybe foglalta a jobbágyfelszabadítást\n\n5. - egységesítették az oktatást, bevezetik 1851-től az érettségit\n\n6. - Bevezették az államrendőrséget és a csendőrséget, és rengeteg besúgót, kémet alkalmaztak. A hivatali tisztségviselőket Bach-huszároknak nevezték.\n\nA magyar társadalom rétegeiben ellenállás fedezhető fel.\n\n1. Aktív ellenállók: fegyvert ragadtak a rendszer ellen pl. Libényi János, Noszlopy Gáspár\n\n2. Passzív ellenállók: Deák Ferenc és hívei  közhivatalokban nem vállaltak szerepet és nem fizettek adókat\n\n3. Emigránsok: olyan politikusok, akik harcoltak a szabadságharc idején, majd 1949\n\nfolyamán külföldre menekültek. Vezetőjük: - Kossuth Lajos\n\n(„beavatkozás a be nem avatkozásért politika)\n\n-1851-ig Törökországban élt, majd az USA-ban, Angliában, Olaszországban a magyar szabadságharcért szólalt fel, szervezkedett, 1894-ben halt meg.\n\nDunai-konföderációs terve 1861-ben: Magyarország és a kisebb államok Horvátország, Románia, Szerbia és Erdély egy szövetséges államot alakítana ki.\n\nII. Az önkényuralom csődje és a kiegyezéshez vezető út:\n\n1. 1859-ben az olaszokkal folytatott sikertelen háború után Bachot menesztették\n\n- 1860-ban lett Döblingben öngyilkos Széchenyi István, előtte írta meg röpiratát: Ein Blich\n\n- 1860. okt. 20. Ferenc József kiadja az októberi diplomát:\n\ntartalma kompromisszumos: helyreállította Magyarországon az országgyűlés jogkörét és az önkormányzatokat – ez egy konzervatív alkotmánytervezet\n\n- 1861-ben kiadja a februári pátenst: a birodalmi gyűlés összetételéről\n\n-a 100 tagú Birodalmi Tanács helyett 343 tagú parlamentet hozott létre, melybe 120 képviselő ment Magyarországról -a magyarok ezt sem fogadták el\n\n- a protestáns pátens a protestáns egyházak önkormányzatát sérti\n\n2. A kiegyezés előtti politikai viszonyok: 2 politikai párt alakult meg a kiegyezés előtt:\n\na Felirati és a Határozati Párt. 1848-as alapra helyezkedtek, és elutasították a pátenseket.\n\n- Deák Ferenc vezetésével: (1861) a Felirati Párt:\n\nelismerték Ferenc Józsefet törvényes uralkodónak, de ragaszkodtak ahhoz, hogy az országgyűlés javaslatait felirati formában juttassák el az uralkodónak.\n\n- Teleki László vezetésével: (1859) Határozati Párt. Nem fogadták el Ferenc Józsefet törvényes uralkodónak, s az uralkodó törvényjavaslatait határozat formájában utasítják el. A 48-as törvényeket minimumnak tartják, az 1849-es állapotok visszaállítását követelik. 1861-ben összeült az országgyűlés, de sikertelenül, s Teleki öngyilkos lesz.\n\n3. 1861-65. Schmerling-provizórium (átmeneti állapot) időszaka: nyílt önkényuralomhoz tértek vissza a Habsburgok\n\n4. 1865-ben Deák Ferenc a Pesti Hírlapban a Húsvéti cikkben fogalmazta meg a kiegyezés magyar álláspontját: Magyarország érdekeit a birodalom érdekeivel kell összhangba hozni. Megegyezést keres.\n\n-1866-ban kitört a porosz-osztrák háború, ahol a Habsburgok veszítettek, kiszorultak a német egységből, ezért megegyezést keresnek a magyarokkal.\n\nIII. 1867. februárjában megszületett az osztrák – magyar kiegyezés (1867/ 12. törvénycikk)\n\n1. Az új állam neve Osztrák – Magyar Monarchia (OMM)\n\n- dualista = két központú alkotmányos monarchia, mely 1918-ig állt fenn\n\n- közös uralkodó köti össze: Ferenc József (1867-ben megkoronázzák)\n\n2. három közös ügy: külügy, hadügy, pénzügy\n\n3. közös minisztereket neveztek ki, akiket delegációk (küldöttek) ellenőriztek:60-60 fő\n\n4. Végrehajtó hatalom: parlamentnek felelős önálló magyar kormány alakult meg 1967-ben. Miniszterelnök: gr. Andrássy Gyula.\n\nA megyerendszer önkormányzattal rendelkezik.\n\n5. Közös hadsereg: K.u.K. (császári és királyi) az uralkodó vezetésével\n\n6. Magyar törvényhozó szerv az országgyűlés, megy felsőházból és alsóházból áll, s a választójogot műveltségi, vagyoni és jövedelmi feltételekhez kötik.\n\n7. Igazságszolgáltatás: korszerűbb bíróságok és büntetőtörvénykönyv. Államrendőrség és csendőrség működése.\n\nGazdasági kiegyezés 1867-ben\n\nMagyarország és Ausztria gazdasági életében vám- és kereskedelmi szövetséget kötött (10 évre szólt). Közös pénzrendszert (korona) és jegybankot vezettek be.\n\nMagyarország a közös terhek 36,4%-át vállalta magára. Eltörölték a céheket. Új ipartörvényt vezettek be. A jobbágyfelszabadítás ügyeit törvényesen rendezték.\n\n1868-ban kiegyezés a horvátokkal: Horvátország autonómiát kapott (önálló kormánya lehetett) a Parlamentbe 43 képviselőt küldhettek (ezt a lehetőséget csak ők kapták meg)\n\n1868-ban kiadták a nemzetiségi törvényt  Európában az első olyan törvény, amelyben a nemzetiségeknek jogokat adtak. Eötvös József dolgozta ki\n\nTartalma: biztosította nemzetiségek nyelvhasználatát. Ahol 50%-ban laktak a nemzetiségek, ott az iskoláztatás nemzetiségi nyelven folyhatott. Ahol 20%-os arányban éltek, ott a közhivatalokban nemzetiségi nyelven lehetett beadni a beadványokat. Az autonómiára törekvést és a kollektív jogokat nem engedték. Kimondták, hogy egy nemzet létezik, az a magyar.\n\n1868. a kötelező népoktatás bevezetéséről szóló törvény 6-tól 12 éves korig (Eötvös József)\n\nIV. A kiegyezés értékelése\n\n- A kiegyezés megkötése előtt Kossuth Lajos nyílt levelet intézett Deák Ferenchez, melyben ellenezte a kiegyezést. Ez volt a híres „Kasszandra-levél”: Kossuth Lajos megjósolta Magyarország tragédiáját, ha kiegyeznek az osztrákokkal (Kasszandra az ókori trójai király lánya volt, aki előre látta Trója elestét, de senki sem hitt neki.)\n\n- Az erőviszonyoknak megfelelően azonban reális kompromisszum volt a kiegyezés. Az állami önállóság egy részének föladásával alkotmányos rendezés jött létre. A kiegyezés gazdasági fellendülést hozott, megindulhatott az ipari forradalom (vasútépítés, malomipar, bankhálózat, tőkés szabad verseny). 1873-tól Budapest ekkor fejlődik nagyvárossá.\n\nPOLGÁRI ÁLLAM A DUALIZMUS IDEJÉN\n\nA kiegyezés elfogadásakor (1867) kétközpontú államalakulat, a dualista Osztrák-Magyar Monarchia jött létre. Az államforma alkotmányos monarchia lett, a neoabszolutista berendezkedést felszámolták. A két tagállam az uralkodó személye és a közös ügyekre létrejött közös minisztériumok (külügy, hadügy és ezek fedezésére szolgáló pénzügy) útján kapcsolódott egymáshoz, minden más kérdésben független volt.\n\nA közös ügyek minisztériumainak alkotmányos felügyeletét a 60-60 főt számláló delegációk látták el, amelyek a két törvényhozás képviselőiből álltak össze és egymástól elkülönülve tanácskoztak, hogy megakadályozzák egy birodalmi gyűlés létrejöttét, amely veszélyeztette volna a fennálló rendszert.\n\n1867-ben létrejött a második független, felelős kormány Andrássy Gyula miniszterelnökletével. A kialakult parlamentáris rendszer a Montesquieu-féle hatalommegosztás elvén szerveződött.\n\nA kétkamarás népképviseleti törvényhozás alsó- és felsőházból állt. Az uralkodó és az országgyűlés szorosan együttműködött a törvényhozásban, visszaállították a neoabszolutizmus korában felfüggesztett szakminiszteri ellenjegyzés intézményét. Az uralkodónak előszentesítési joga volt. A kormány mint végrehajtó szerv a parlamentnek volt felelős. 1869-ben a közigazgatást elválasztották a bíráskodástól, így létrejött a három független, de egymást ellenőrző hatalmi ág.\n\nMagyarországon a polgári állam létrejöttét az 1867-es kiegyezés tette lehetővé, kialakulása összefüggött a polgári átalakulással, a rendiség felszámolásával, eszmei hátterét a liberalizmus jelentette, alapjait az 1848-as áprilisi törvények teremtették meg.\n\nA dualizmus kora 1867-től 1918-ig tartott. A polgári állam kiépülése a XIX. század utolsó évtizedeire tehető. A polgári állam kiépülése Magyarországon nyugati mintát követett.\n\nA polgári államra jellemző politikai rendszer alapvető összetevője: alkotmány, hatalommegosztás, a szabadságjogok biztosítása, jogegyenlőség.\n\nA dualista monarchia Magyarországán a kiegyezés után, illetve az 1890-es években születtek a legjelentősebb reformok, és egyre erőteljesebben érvényesül területileg is az önálló magyar kormány akarata.\n\nReformok pl. az állami anyakönyvezés bevezetése, az izraelita vallás bevetté nyilvánítása, a közigazgatás és az igazságszolgáltatás teljes szétválasztása, az igazságszolgáltatás reformja, a rendőrség és a csendőrség megszervezése, a közegészségügy megszervezése.\n\nAz állam szerepe megnőtt, az állami hivatalok és hivatalnokok létszáma nőtt.\n\nAz egyházpolitikai reformok a kormánypárt tagjait is megosztották. A reformok kiváltották az egyházak és az uralkodó ellenkezését.\n\nAz izraelita vallás bevett vallássá nyilvánítása a zsidók emancipációját segítette elő.\n\nTöbb ember számára vált elérhetővé az egészségügyi ellátás.\n\nAz igazságszolgáltatás szakszerűbbé vált, hatékonyabb lett a rendfenntartás.\n\nAz 1870-es évektől érvényesülő szabadelvű politika (Tisza Kálmán 1875-1890 vezetésével) számos intézkedésével segítette a modern állam kiépítését, de a reformok felgyorsulása Wekerle Sándor miniszterelnökségéhez kapcsolódik. A változások nyomán vált a XX. század elejére modern polgári állammá Magyarország.\n\nA polgári típusú közigazgatás kiépülése összefüggött a dualista államon belüli önálló magyar belpolitikával. A vármegye élén a kormány álláspontját képviselő főispánok álltak jelentős hatáskörrel. Jogkörük a dualista rendszer idején folyamatosan bővült, ezzel is erősítve a helyi szintű állami befolyást.\n\nA felszámolt kiváltságolt területek: szász székek, székely székek, jász-kun kerület, Határőrvidék. Ez a rendiség felszámolásának, a polgári jogegyenlőség kiterjesztésének egy lépése volt, ezzel egységes megyerendszer jött létre.\n\nA közigazgatási változások az állam szerepének erősödését eredményezték. Pl. a polgári házasság és polgári anyakönyvvezetés jelentős lépés volt az állam és egyház szétválasztásában.\n\nA polgári házasság, az anyakönyvvezetés mellett más progresszív reformok is születtek, pl. vallások liberalizációja (bevett, elismert és el nem ismert vallások kategóriája). A törvényi szabályozás következtében elhárult az akadály a különböző nemzetiségek és vallások emancipációja elől.\n\nAz 1868-ban elfogadott Eötvös-féle népiskolai törvény mérföldkő a magyar oktatás történetében, és hatására nemcsak az általános művelődési szint emelkedett, hanem megteremtődtek a tudomány fejlesztésének legfontosabb feltételei is.\n\nAz 1868-as népiskolai törvény általánosan kötelezővé tette 12 éves korig a tankötelezettséget (az oktatás anyanyelven folyhatott). Ez a törvény szabadelvűen kezelte a nemzetiségi oktatást, és eredményesen hozzájárult az analfabétizmus megszüntetéséhez. A polgári államra jellemző az állampolgárokról való gondoskodás szándéka, az intézkedés következtében csökkent tehát az analfabéták száma, az állam iskolák építésével és a tanítóképzés megszervezésével biztosította a feltételeket.\n\nA reformok ellenére továbbra is jelentős maradt a konzervatív arisztokrácia befolyása és a dzsentri mentalitás „mintaképző” szerepe. A reformfolyamat sokat változtatott a korabeli Magyarországon, közelítette az országot Nyugat-Európa fejlettebb régióihoz.\n\nA lemaradást csak részben tudta felszámolni, és számos fontos társadalmi kérdést (nemzetiségi, föld, választójog) nem tudott kezelni.\n\nA dualista monarchia létrejötte megfelelő alapot teremtetett a modern állam és intézményeinek kiépítéséhez.\n\nA dualizmus kora\n\nA kiegyezési rendszer merevsége\n\n• A magyar politikai élet aszerint tagolódott, hogy ki fogadta el a kiegyezést (Deák-párt) és ki utasította el (ellenzéki pártok).\n\n• A kiegyezés egy végletekig kifinomított kompromisszum eredménye volt, amely igen rugalmatlanná tette a rendszert minden változtatással szemben. A legkisebb változtatás is a rendszer összeomlását eredményezhette volna, ezért Magyarországon mindig biztosítani kellett a kiegyezéspárti politika túlsúlyát, azaz a kormánypárt győzelmét. Ennek a technikái a következők voltak:\n\n- a választókerületeket nem lakosság-arányosán alakították ki, hanem úgy, hogy az általában kiegyezés-ellenes magyar lakosságú területeken kevesebb, a kiegyezés-párti vegyes etnikumú, vagy nemzetiségi területeken több kerületet hoztak létre;\n\n- általánossá tették a nyílt szavazást, így a kormány az erőszakszervezeteken, állami hivatalokon, vállalatokon keresztül (megfélemlítés, elbocsátással fenyegetés) befolyásolni tudta a szavazókat;\n\n- a választójognál megmaradt a vagyoni cenzus, ezzel a szegényebb, kiegyezés-ellenes rétegeket kizárták a választásokból.\n\nA kiegyezési rendszer rugalmassága\n\n• A közjogi kérdések merev szabályozottsága két módon volt oldható: az uralkodónak elég tág szerepe volt: törvényeket kezdeményezhetett, előszentesítési joga volt, ha kellett kisebbségi kormányt nevezhetett ki (ha „véletlenül” az ellenzék győzött a választásokon, pl. 1905-ben). Gazdasági, hadügyi, külpolitikai téren lehetőség nyílt a vitákra, amelyek levezethették a feszültségeket.\n\nPolgári alkotmányos viszonyok\n\n• 1874-ben alkották meg a választójogi törvényt, amely az 1848-as törvényen alapult (vagyoni és műveltségi cenzus):\n\n• míg 1848-ban a lakosság 7-8%-ának volt választójoga, és ez megfelelt a korabeli nyugat-európai szintnek;\n\n• 1905-ben már csak a lakosság 6,2%-a szavazhatott, miközben Nyugat-Európában már 20-30%!\n\n• Már az Andrássy-kormány (1867-70) idején megkezdődött a megyék feladatának és jogkörének újraértelmezése, az „állam és a megye kiegyezése”:\n\n• fennmaradt a megyék helyi ügyekben meglévő önkormányzata, de élükre a kormány által kinevezett főispán került;\n\n• a megyegyűlések továbbra is foglalkozhattak országos ügyekkel, de kötelezték őket az országgyűlés törvényeinek és a kormány rendeleteinek betartására és végrehajtására.\n\n• Tisza Kálmán folytatta a reformot:\n\n• megtörte a megyék hagyományos autonómiáját, hivatali rendszerüket alárendelte a központi kormányzatnak;\n\n• a Tiszához hű főispánok kibővített jogkörrel teljesítették a „Generális” parancsait;\n\n• elterjedt a virilizmus rendszere: a megyei önkormányzatok és a saját törvényhatósággal rendelkező városok képviselőinek csak a felét választották, a másik felét a legtöbb adót fizetők (virilisták) közül jelölték ki.\n\nAz Andrássy-kormány alatt megkezdődött a jog és az igazságszolgáltatás reformja:\n\ntörvény előtti egyenlőség, bírók jogi képzettségének előírása, a bírók függetlenségének megteremtése, a büntetőjogból törölték a kirívó embertelenségeket. Tisza Kálmán idején, 1878-ban lépett életbe a modern büntető törvénykönyv (Csemegi-kódex). 1867-ben kimondták a zsidóság teljes polgári egyenjogúságát (emancipációját).\n\nWekerle Sándor kormánya (l892-95) végrehajtotta az állam és az egyház szétválasztását:\n\n• bevezették a kötelező polgári házasságot (és annak felbonthatóságát);\n\n• bevezették az állami anyakönyvezést;\n\n• kimondták a szabad vallásgyakorlást;\n\n• az izraelita is bevett vallás lett.\n\n1868-ban a parlament elfogadta az Eötvös József által kidolgozott népiskolai törvényt:\n\n• 6-12 év között kötelezővé tették az iskolába járást;\n\n• az elkövetkező 50 évben 4000 új népiskola épült;\n\n• jelentősen csökkent az analfabéták aránya: 1867-ben 69%, míg 1910-ben már csak 31%.\n\n1883: középiskolai törvény; 1891: kisdedóvókról szóló törvény. 1871-72: a Kolozsvári Tudományegyetem megalapítása; 1912: a pozsonyi és a debreceni egyetem megalapítása.\n\nA magyar politikai élet alapvető kérdése az Ausztriához és a kiegyezéshez fűződő viszony (közjogi kérdés) volt, így a magyar pártok a közjogi kérdés mentén szerveződtek, tehát nem a Nyugat-Európára jellemző politikai ideológiák szerint.\n\nAz 1861-ben létrejött Felirati Pártból és a csatlakozó konzervatívakból jött létre 1867-ben a Deák-párt. A nagybirtokosokat képviselte, támogatta a kiegyezést és a liberális Magyarország kiépítését tűzte ki célul.\n\nA 1861-és országgyűlés után a Határozati Pártból kivált a Tisza Kálmán vezette Balközép Párt, amely a középbirtokosokat képviselte. Elismerte a kiegyezést, de a perszonáluniót támogatta.\n\nA Határozati Párt másik része, a parasztság által támogatott Országos 48-as Párt elutasította a kiegyezést és függetlenedni akart. 1874-től Függetlenségi Párt néven működött tovább.\n\n1868-ban a németajkú munkásokból szerveződött az Általános Munkásegylet, amely 1890-tól a Magyarországi Szociáldemokrata Pártként a munkásokat képviselte, fő célja az általános és titkos választójog megszerzése volt. A centrista irányzatot követte.\n\nMivel az ellenzék győzelme a kiegyezés megkérdőjelezését és a dualista állam létét veszélyeztette volna, a választásokon biztosítani kellett a kormánypárt többségét, ezért a dualizmus idején nem merült fel a cenzusos választójog kiszélesítése.\n\n1867-ben a választójogot Kiterjesztették az izraelita férfiakra, teljessé téve a zsidóság emancipációját. 1874-ben vagyoni cenzus helyett adócenzust vezettek be.\n\nAz 1875-ös közigazgatási reform megerősítette a polgári közigazgatás kiépülését (átalakították a megyerendszert, növelték az állam szerepét a megyékben, a korábbi kiváltságos területeket megszüntették). A polgári államban kiépült a rendőrség és csendőrség szervezete.\n\nA Monarchia felbomlása és az első világháború után 1918-ban a Nagy Nemzeti Tanács „Néphatározata” már a titkos, egyenlő, általános, közvetlen, nőkre is kiterjedő választójogról rendelkezett. A Monarchia gyakorlati szétesésével párhuzamosan megalakuló Károlyi-kabinet eltörölt minden addigi cenzust, a választójoggal csak a politikai jogaiktól megfosztottak, a csőd alatt állók, a közsegélyből élők és azok nem élhettek, akiknek kiskorúságát meghosszabbították vagy erkölcsrendészeti felügyelet alatt álltak. A korszakban mégis fokozatosan teret nyert a politikai elitizmus, ami a közéletben való részvételt a felsőbb társadalmi rétegek privilégiumaként kezelte.\n\nEzen intézkedések a dualista állam meggyengülésére, ezáltal a függetlenedési törekvések megerősödésére vezethetők vissza.', 296, 1, '2026-04-17 09:40:36', '2026-04-17 09:40:36');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(18, 18, 'Az Európai Unió és Magyarország az Európai Unióban', '18.docx', '18. Az Európai Unió és Magyarország az Európai Unióban\n\nAz Európai Unió létrejötte és intézményrendszere\n\nFranciaország és Németország történelmi megbékélésével Nyugat-Európából indult a második világháború után. Az európai országokat sok évszázados kulturális és történelmi hagyományok fűzik egymáshoz. 1946-ban Churchill zürichi beszédében Európai Egyesült Államokról beszélt. Az 1949 óta Strasbourgban működő intézmény, az Európa Tanács viszonylag laza együttműködést valósít meg a demokratikus európai államok között. (Magyarország 1990-ben lépett be az Európa Tanácsba). Jelenleg Donald Tusk a Tanács elnöke.\n\nAz európai integrációs folyamat okai: a béke és a jólét iránti vágy, a hidegháború, illetve a szovjet fenyegetettség segítette az egységfolyamatot. Európa egységesülése a politikain túl gazdasági érdek is, hiszen versenyben áll az USA-val és az ázsiai térséggel. A globális versenyben az integráció versenyelőnyt jelenthet a nemzetgazdasági léttel szemben.\n\nAz európai integráció rövid története: az európai integráció elindítói: Adenauer, Monnet, Schumann\n\nAz európai integráció az 1950-es Schumann-tervvel indult. A 6 országot összefogó együttműködés legfontosabb elemét a német-francia kapcsolat jelentette, hiszen 1945-ig még háborús ellenfelek voltak. 1950. május 9-én Robert Schumann francia külügyminiszter előterjesztette a megbékélésről és az európai együttműködésről szóló tervét, felvázolta a „konkrét lépések politikáját”. (azóta ez a nap az Európa-nap).\n\n1951. április 18-án hat ország (Franciaország, Német Szövetségi Köztársaság, Olaszország, Belgium, Hollandia és Luxemburg) aláírta az ún. kölcsönös függőség megteremtését célzó Európai Szén- és Acélközösség (ESZAK vagy Montánunió) létrehozásáról szóló szerződést. Cél: közösen ellenőrizzék a tagállamok szén- és acéltermelését.\n\n1957. március 25-én ugyanezek az államok aláírták a római szerződést is, amely megteremti az Euroatomot és az Európai Gazdasági Közösséget (EGK, közkeletű nevén: „Közös Piac”), melynek célja a tagországok közötti vámunió létrehozása volt, a belső piac, közös agrárpolitika, strukturális politika. A tőke, az áruk, a munkaerő és a szolgáltatások szabadsága érvényesül.\n\nAz integrációt az 1962-ben bevezetett közös agrárpolitika és az 1968-ban elfogadott vámunió mélyítette tovább.\n\n1968-ban a Közös Piac Európai Közösséggé (EK) alakult.\n\nBővülés:\n\nNagy-Britannia is kifejezte csatlakozási szándékát, először 1963-ban, majd 1967-ben. Amikor azonban benyújtotta felvételi kérelmét, De Gaulle francia köztársasági elnök vétót emelt, mert versenytársnak érezte az angolokat. 1973-ban végül mégis csatlakozott az Egyesült Királyság, illetve Írország és Dánia. Ekkor vált szokássá, hogy a csatlakozó országok türelmi időt kapnak.\n\nEzt követően az ún. déli bővítés került napirendre: 1981-ben Görögország, 1986-ban pedig Spanyolország és Portugália csatlakozott. Így az EK a világ legnagyobb gazdasági egységévé vált, s népessége meghaladta mind a Szovjetunióét, mind az Egyesült Államokét.\n\nA hidegháború befejeződése (1990) felvetette az európai integráció jövőjének kérdését. A közösség az integráció elmélyítése és kibővítése mellett döntött: 1991-ben a hollandiai Maastrichtban elfogadták az integráció továbbfejlesztésének programját, majd 1993-ban lép érvénybe:\n\n- az európai valuta; a közös kül- és biztonságpolitika;\n\n- az egységes vízumpolitika;\n\n- a közös intézmények – Európa Parlament, Európai Bizottság - szerepének kiszélesítése;\n\n- az EK elnevezése 1992-től Európai Unióvá (EU) változott.\n\n1995-ben Ausztria, Finnország és Svédország csatlakozott.\n\n1995-ben életbe lépett a luxemburgi Schengenben aláírt egyezmény, amely az unió tagállamai között „lebontotta a határokat”, viszont a külső határokon szigorúbb ellenőrzést írt elő.\n\nA 2000. decemberi nizzai csúcsértekezleten megállapodás született az Európai Unió új működési szabályairól, lehetővé teszik az új csatlakozók beillesztését. A 2002. decemberi koppenhágai csúcsértekezleten döntés született az időpontról is.\n\n2002-ben 12 tagállam megszüntette saját valutáját, bevezette helyette az eurót. Nagy-Britannia, Dánia és Svédország nem vezette be.\n\nA nagy bővítést 2004. május l-je jelentette, amikor 10 új tagállam, vagyis Észtország, Lettország, Litvánia, Lengyelország, Csehország, Szlovákia, Szlovénia, Ciprus és Málta mellett Magyarország is csatlakozott az EU-hoz. A tagállamok jelenlegi száma (28) a 2007-ben csatlakozott Romániával és Bulgáriával alakult ki. 2013-ben Horvátországgal bővült.\n\nAz európai integráció a nemzetek feletti egység (szupranacionális) megteremtésének irányába tett lépés. Az integráció a nacionalizmusok korának meghaladását ígérte, a kilencvenes évekre ez a folyamat azonban megtorpanni látszik.\n\nAz uniós együttműködésben rejlő nehézségek:\n\na nemzeti érdekek és nemzetek feletti érdekek, nettó befizetők és nettó részesedők konfliktusa, nagy és kis országok eltérő érdeke.\n\nA különböző érdekek és értékek egyeztetése konfliktusok forrása is lehet.\n\nProblémás: a bonyolult döntéshozatali rendszer, a demokratikus deficit, és a túlbürokratizáltság. A nemzetállamok feletti békés és erős Európa eszméje a gyakorlatban nehezen működik.\n\nGazdasági és politikai félelmek: a piacvesztés és a nemzeti hagyományok háttérbe szorulása akadályozhatják az egység megvalósulását.\n\nA közös biztonságpolitikához a tagállamok biztosítják a katonai eszközöket, ez az érdekellentétek miatt gyakran megbénul; a tagállamok nem feltétlenül érdekeltek a katonai képességek növelésében; az EU-nak nincs saját katonai ereje.\n\nVita van a közös intézményeknek átadandó jogkörökről, pl. ezt a szuverenitás, függetlenség feladásaként, veszélyeztetéseként is értelmezik. Nem alakult ki közös európai nemzeti identitás. A közös intézmények demokratikus kontrollja nem teljesen megoldott.\n\nAz intézményrendszer átalakulásának lépcsőfokait a Brüsszeli Szerződés (1967), az Egységes Európai Okmány (1986), a Maastrichti Szerződés (1993), az Amszterdami Szerződés (1999) és a Nizzai Szerződés (2000) jelentette, az integráció pedig tovább szélesedett például a Schengeni Szerződés hatálybalépésével (1995) vagy az euró (€) bevezetésével (2002). 2009. december l-jén hatályba lépett a Lisszaboni Szerződés.\n\nAz EU jogi rendszere\n\nAz Európai Unió sajátos jogi struktúra, erősebb az országok konföderációjánál, de nem szövetségi állam, ugyanakkor nemzetközi közjogi értelemben jogi személy. Alapját az ún. elsődleges jog képezi, ami az Európai Uniót megalapító szerződések összessége. Ezeket módosítja és foglalja egységes keretbe a 2009-es Lisszaboni Szerződés, vagy más néven Reformszerződés. A legfontosabb szerződések közé tartozik az Európai Unióról szóló (Maastrichti) szerződés és az Európai Unió működéséről szóló (Római) szerződés is; a Lisszaboni Szerződéssel megszűnt a korábbi hármas pillérrendszer (Európai Közösségek, közös kül- és biztonságpolitika, rendőri és bírói együttműködés).\n\nErre épül az ún. másodlagos jog; ez olyan területekre terjedhet ki, amelyekre az elsődleges jog is kiterjed, és az EU intézményei által elfogadott minden tagállamra kötelező érvényű, közvetlen hatályú rendeletekből, kötelező célokat megfogalmazó, de a megvalósítás módját nem részletező irányelvekből, konkrét ügyre és csak a címzettre vonatkozó határozatokból áll. Ez kiegészül a nem kötelező érvényű ajánlásokkal és véleményekkel.\n\nEzeket a döntéseket az egyes tagállamok kormányait képviselő Tanácsból, az európai állampolgárokat képviselő Parlamentből, és az EU egységes érdekeit képviselő Bizottságból álló intézményi háromszög hozza meg (döntéshozatali háromszög).\n\nAZ EURÓPAI UNIÓ FELÉPÍTÉSE főbb intézményei, döntési mechanizmusai\n\nAz Európai Bizottság tekinthető az EU kormányának, az Európai Parlament pedig az EU parlamentjének, egyik sem rendelkezik kiterjedt jogkörrel. Az Unió legfontosabb döntéseit az egyes tagállamok kormányai által alkotott testületek, a tagállamok állam- és kormányfőiből álló Európai Unió Tanácsa határozza meg (ez nem azonos az 1949-ben létrehozott Európa Tanáccsal!).\n\n1. Az Európai Unió Tanácsa (Miniszterek Tanácsa) - Brüsszel\n\nEz az EU fő döntéshozó szerve. Elsősorban politikai testület, a politikai kompromisszumok színtere, amely évente négyszer ülésezik, a jelenlegi gazdasági válság idején gyakrabban. Elnökét a Tanács választotta meg két és fél évre, a Lisszaboni Szerződés szerint azonban 2009-től félévente rotációs rendszerben végzik. Az elnöki tisztet betöltő tagállamok hármas csoportokban, az úgynevezett elnökségi triókban szorosan együttműködnek egymással. Elnökét (a Lisszaboni Szerződés szerint már 2009-től) a Tanács választja két és fél évre. A 2009. december 1-jén életbe lépett Lisszaboni szerződés létrehozta az Európai Tanács állandó elnöki posztját, így annak már nincs köze az elnökséget aktuálisan ellátó országhoz. Jelenleg Charles Michel az állandó elnök. Minden államot annak államfője vagy miniszterelnöke, illetve egy-egy minisztere képvisel, attól függően, hogy milyen ügy szerepel a napirenden (pl. külügyek, mezőgazdaság, környezetvédelem stb.), és a testületben helyet foglal az Európai Bizottság elnöke is. Ezt a két szintet (Európai Tanács, Miniszterek Tanácsa) egészíti ki a tagállami szakminisztériumok tisztségviselőinek szintje (COREPER 1. és COREPER 2.), illetve az előkészítő szakértői munkacsoportok szintje.\n\nA Tanács a Parlamenttel közösen felelős az EU költségvetéséért, valamint jogalkotói hatáskörrel rendelkezik. Döntéseit konszenzussal vagy szavazással (egyszerű többséggel, egyhangú döntéssel vagy minősített többséggel) hozza. 2014-től a minősített többség tekintetében az eddigi hármas többség (tagállamok száma, lélekszáma és szavazati súlya) megváltozik. 2014-től a minősített többség tekintetében a kettős többség elvét vezetik be a Tanácsban a döntéshozatal terén: a tagállamok 55%-ának kell támogatnia egy javaslatot, és az igennel szavazó országok lélekszámának el kell érnie az Unió teljes lakosságának 65%-át. A másik oldalról az ún. blokkoló kisebbséget legalább négy tagállamnak kell alkotnia, ha ez nem valósul meg, akkor el kell tekinteni a lélekszámbeli kritériumtól.\n\n2. Az Európai Parlament – Strasbourg, Brüsszel, Luxemburg\n\nAz Európai Parlament a politikai viták és a döntéshozatal fontos uniós szintű fóruma. Az Európai Parlament az EU egyetlen közvetlenül megválasztott intézménye. 705 EP-képviselője van. Az Európai Parlament képviselőit közvetlenül választják valamennyi tagállamban abból a célból, hogy képviseljék az emberek érdekeit az uniós jogalkotás során, és hogy biztosítsák a többi uniós intézmény demokratikus működését.\n\nA Parlament társjogalkotóként, a Tanáccsal együtt jogosult jogalkotási javaslatok elfogadására és módosítására, illetve az uniós költségvetésről szóló döntéshozatalra. A Parlament emellett felügyeli a Bizottság és más uniós szervek munkáját, és együttműködik az uniós tagállamok nemzeti parlamentjeivel, kikérve azok véleményét.\n\nA Parlament 1979 óta a tagállamok polgárai által közvetlenül, ötévente választott testület. A Parlament képviselői politikai alapon frakciókra tagolódnak. A Parlament plenáris üléseit Strasbourgban, a bizottsági üléseket és a frakciók üléseit Brüsszelben tartják. A hivatali apparátus Luxemburgban van.\n\nFelügyeli az EU intézményeit, és jogalkotói hatáskörrel is rendelkezik. 705 képviselője van, ebből 21-t választhatnak a magyar állampolgárok. A Parlament az ún. együttdöntési eljárásban egyes jogalkotási területeken a Tanáccsal egyenrangú döntéshozónak minősül. A Lisszaboni Szerződés az együttdöntést kiterjesztette a jogalkotási területek többségére; ilyen terület az Unió költségvetésének egésze is.\n\nA Parlament választja - a Tanács javaslatára - a Bizottság elnökét, és hozzá kell járulnia a külügyi és biztonságpolitikai főképviselő személyéhez is. Nagyon erős jogköre, hogy kétharmados többségű bizalmatlansági indítvánnyal feloszlathatja a Bizottságot. A képviselők emellett kérdéseket intézhetnek a Bizottsághoz és a Tanácshoz. Elnöke Roberta Metsola.\n\nAz elnököt két és fél éves hivatali időre, azaz a parlamenti ciklus felére választják, amelynek leteltével újraválasztható.\n\n3. Az Európai Bizottság – Brüsszel\n\nJelenlegi elnöke Ursula von der Leyen. A Bizottság irányítja az EU napi működését, feladata az EU, mint közösség egységes érdekeinek támogatása és képviselete, vagyis teljesen független az egyes országok nemzeti kormányaitól, illetve parlamentjeitől. A Bizottság végzi az egyes javaslatok hatásvizsgálatát és folytatja le a konzultációt a döntésekben érintett felekkel, amelyeket végül a Tanács és a Parlament több olvasatban vitat meg és fogad el.\n\n2009-től a Lisszaboni Szerződéssel létrejött az Unió külügyi és biztonságpolitikai főképviselői tisztsége, aki egyben alelnöki tisztséget tölt be az Európai Bizottságban. 2014-től kezdve a tagországok kétharmada jelölhet biztost (a Parlament hozzájárulásával öt évre), mégpedig rotációs elven (addig minden tagállamból l fő tagja a Bizottságnak).\n\nA Lisszaboni Szerződéssel lehetőség nyílt a petícióra is, hogy több tagország állampolgárai egymillió aláírással kezdeményezzék a Bizottságnál egy adott javaslat beterjesztését.\n\nAz Európai Unió további intézményei:\n\nAz Európai Bíróság (27 fős) feladata a közösségi jog érvényesítésének, valamint a szerződések alkalmazásának és helyes értelmezésének biztosítása. Székhelye Luxembourg, a testületbe minden tagállam egy-egy bírót delegál hat évre.\n\nA Számvevőszék (27 fős) tagjait szintén a tagállamok és szintén hat évre delegálják, a Parlamenttel való konzultációt követően. A testület feladata az unió költségvetésének ellenőrzése, mind a szabályszerűség, mind a hatékonyság szempontjai szerint. Székhelye Luxembourg.\n\nAz Európai Gazdasági és Szociális Bizottság és a Régiók Bizottsága a Tanács és a Bizottság munkáját segítő, azoktól független szerv; az egyik az egyes civil gazdasági és társadalmi érdekcsoportokat, a másik a tagállamok helyi és regionális választott testületeit képviseli. Tagjait a Tanács nevezi ki négy évre.\n\nAz Európai Beruházási Bank kölcsönökkel segíti az EU egyes elmaradottabb területeinek fejlesztését és versenyképességét, míg a frankfurti központú Európai Központi Bank az euró stabilitásáért és az Európai Unió monetáris (pénzügyi) politikájáért felelős.\n\nKifejtés:\n\nAz Európai Unió Tanácsa\n\nAlapítás éve: 1958 (az „Európai Gazdasági Közösség Tanácsa” néven)\n\nSzékhely: Brüsszel (Belgium)\n\nJelenlegi elnöke: Charles Michel\n\nSzerep: az EU-tagállamok kormányait képviselő intézmény, mely uniós jogszabályokat fogad el, és összehangolja az uniós szakpolitikákat\n\nTagok: az uniós országoknak a megvitatandó szakpolitikai területért felelős miniszterei\n\nElnök: rotációs alapon mindegyik uniós ország 6 hónapig tölti be az elnöki tisztet.\n\nA Tanács elnökségét félévente más-más uniós tagállam adja. E féléves időszak során minden szinten a soros elnökség vezeti a tanácsi üléseket, így biztosítva a Tanácsban az Unió munkájának folytonosságát.\n\nAz Európai Unió Tanácsának belga elnöksége: 2024. január 1. – június 30.\n\nMagyarország: 2024. július – december\n\nLengyelország: 2025. január–június\n\nAz Európai Unió Tanácsában – nem hivatalos nevén a Tanácsban – az egyes EU-országok miniszterei találkoznak egymással, hogy jogszabályokat vitassanak meg, fogadjanak el vagy módosítsanak, illetve hogy uniós szinten összehangolják a különböző szakpolitikákat. A miniszterek felhatalmazással bírnak arra nézve, hogy kormányuk nevében kötelezettséget vállaljanak a Tanács ülésein elfogadott intézkedések végrehajtására. A Tanács Brüsszelben ülésezik, kivéve három hónapot (április, június és október), amikor is az üléseknek Luxembourg ad otthont.\n\nAz Európai Parlamenttel együtt a Tanács az Európai Unió fő döntéshozatali szerve.\n\nAz Európai Unió Tanácsa nem tévesztendő össze:\n\naz Európai Tanács elnevezésű uniós intézménnyel, melynek keretében az uniós országok vezetői találkoznak negyedévente, hogy meghatározzák az uniós szakpolitikai döntéshozatal általános irányvonalát;\n\nsem az Európa Tanács nevű, az Európai Uniótól teljesen független szervezettel.\n\nMilyen feladatokat lát el a Tanács?\n\nAz Európai Parlamenttel közösen uniós jogszabályokat vitat meg és fogad el az Európai Bizottságtól beérkező jogszabályjavaslatok alapján.\n\nÖsszehangolja az uniós országok szakpolitikáit.\n\nAz Európai Tanács iránymutatásai alapján kialakítja az EU kül- és biztonságpolitikáját.\n\nMegállapodásokat köt az EU és más országok vagy nemzetközi szervezetek között.\n\nAz Európai Parlamenttel közösen elfogadja az éves uniós költségvetést.\n\nÖsszetétel\n\nAz Európai Unió Tanácsának nincsenek állandó tagjai. A Tanács 10 különböző formációban ülésezik a megvitatásra kerülő szakpolitikai terület függvényében. Az egyes tagállamokat az adott formációnak megfelelően a kérdéses szakpolitikai területért felelős miniszterek képviselik az ülésen.\n\nÍgy például a Gazdasági és Pénzügyi Tanács ülésein (az ún. Ecofin Tanácsban) a tagállamok pénzügyminiszterei vesznek részt.\n\nAz ülések elnöklete\n\nA Külügyek Tanácsának állandó elnöke van: az Unió külügyi és biztonságpolitikai főképviselője. A Tanács összes többi ülésén az EU soros elnökségét betöltő országnak az a minisztere elnököl, aki az ülés tárgyát képező szakpolitikai területért felelős.\n\nHa például Észtország tölti be a soros elnökséget, akkor a Környezetvédelmi Tanács elnöke az észt környezetvédelmi miniszter lesz.\n\nA különböző formációkban végzett munka következetességét az Általános Ügyek Tanácsa biztosítja az Állandó Képviselők Bizottságának támogatásával. Az Állandó Képviselők Bizottságát az uniós országok EU melletti állandó képviselői, vagyis a tagállamok EU mellé rendelt nagykövetei alkotják.\n\nEuróövezet\n\nAz euróövezetbe tartozó országok gazdaságpolitikáját az eurócsoport hangolja össze, mely az euróövezeti országok gazdasági és pénzügyminisztereiből áll. Az eurócsoport mindig a Gazdasági és Pénzügyi Tanács ülése előtti napon ül össze. Az eurócsoport ülésein megszülető megállapodásokról másnap döntenek hivatalosan a Gazdasági és Pénzügyi Tanács tagjai – kizárólag az euróövezeti országok minisztereinek szavazataival.\n\nHogyan végzi munkáját a Tanács?\n\nAz EU-országok miniszterei nyilvánosan üléseznek, amikor jogszabálytervezetekről tárgyalnak vagy szavaznak.\n\nA döntések elfogadásához rendszerint ún. minősített többségre van szükség. A minősített többséghez az kell, hogy:\n\na döntést az uniós országok 55%-a támogassa (az Uniót jelenleg 27 tagállam alkotja, így ez az arány 15 tagországnak felel meg),\n\ntovábbá hogy az igennel szavazó tagországok lakosainak száma együttesen elérje vagy meghaladja az Unió teljes lakosságának 65%-át.\n\nA Tanács nyilvános ülései itt követhetők élőben, illetve nézhetők meg utólag az EU bármely hivatalos nyelvén. Amikor a Tanács nyilvánosan ülésezik, az ülésről készült jegyzőkönyv és a szavazás eredménye is nyilvános.\n\nAhhoz, hogy megakadályozhassák a döntés elfogadását, legalább 4 tagországnak nemmel kell szavaznia. (További feltétel, hogy e 4 tagország népessége együttesen legalább 35%-át alkossa az EU teljes lakosságának.)\n\nKivételt képeznek az érzékeny témákkal – pl. a külpolitikai és az adóügyi kérdésekkel – kapcsolatos döntések, melyek meghozatalához a tagállamok egyhangú szavazatára (azaz az összes tagország támogatására) van szükség.\n\nEljárási és adminisztratív ügyekben a döntéshozatal egyszerű többséggel történik.\n\nAz Európai Parlament\n\nSzerep: jogalkotási, felügyeleti és költségvetési hatáskörrel rendelkező, közvetlenül választott uniós intézmény\n\nTagok: 705 európai parlamenti képviselő\n\nElnök: Roberta Metsola\n\nAlapítás éve: 1952-ben alapították „az Európai Szén- és Acélközösség Közgyűlése” néven, jelenlegi nevét 1962-ben kapta, az első közvetlen európai parlamenti választásokra pedig 1979-ben került sor\n\nSzékhely: Strasbourg (Franciaország), Brüsszel (Belgium), Luxembourg (Luxemburg)\n\nHonlap: Európai Parlament\n\nAz Európai Parlament az EU jogalkotó intézménye, melynek tagjait ötévente közvetlenül választják meg az uniós választópolgárok. Legutóbb 2019 májusában voltak európai parlamenti választások.\n\nVálasztások\n\nAz utolsó európai parlamenti választásokra 2019. május 23–26-án került sor.\n\nMi a Parlament feladata?\n\nA Parlament három fő feladatot lát el:\n\nJogalkotás\n\nUniós jogszabályokat fogad el az Európai Unió Tanácsával együtt, az Európai Bizottság által előterjesztett javaslatok alapján.\n\nNemzetközi megállapodások elfogadásáról határoz.\n\nDönt az Európai Unió bővítéséről.\n\nEllenőrzi a Bizottság munkaprogramját, és jogszabályjavaslatok előterjesztésére kéri fel az intézményt.\n\nFelügyelet\n\nDemokratikus ellenőrzést gyakorol az összes uniós intézmény felett.\n\nMegválasztja a Bizottság elnökét, és jóváhagyja a biztosi testületet. Bizalmatlansági indítványt fogadhat el a Bizottsággal szemben, lemondásra kötelezve a testületet.\n\nMentesítést ad a Bizottságnak, azaz elfogadja a Bizottság zárszámadását az EU-költségvetés előző évi végrehajtásáról.\n\nKivizsgálja az uniós polgárok által benyújtott petíciókat, és egyéb vizsgálatokat indít.\n\nA monetáris politika témájában megbeszéléseket folytat az Európai Központi Bankkal.\n\nKérdéseket intéz a Bizottsághoz és a Tanácshoz.\n\nVálasztási megfigyelést végez.\n\nKöltségvetés\n\nA Tanáccsal együtt kialakítja az uniós költségvetést.\n\nJóváhagyja az EU hosszú távra szóló költségvetését, az ún. többéves pénzügyi keretet.\n\nÖsszetétel\n\nAz egyes uniós tagállamok nagyjából a népességük arányában részesülnek az európai parlamenti mandátumokból, de a csökkenő (degresszív) arányosság elve szerint: egyik országnak sem lehet 6-nál kevesebb, illetve 96-nál több képviselője, a képviselők összlétszáma pedig nem haladhatja meg a 705 főt (704 képviselő plusz az elnök). A képviselők politikai hovatartozásuk, nem pedig állampolgárság szerint alkotnak csoportokat (frakciókat).\n\nA Parlamentet az elnök képviseli a többi uniós intézmény és a külvilág felé, és az elnök mondja ki az utolsó szót az uniós költségvetés jóváhagyása során.\n\nHogyan végzi munkáját a Parlament?\n\nA Parlament munkája két fő szakaszra bontható:\n\nJogszabályok előkészítése – bizottságok:\nAz Európai Parlamenten belül húsz bizottság és három albizottság működik. Mindegyikük egy adott szakpolitikai területtel foglalkozik. A bizottságok górcső alá veszik a jogszabályjavaslatokat, melyeket a képviselőcsoportok is megvitatnak. A képviselők és a képviselőcsoportok módosításokat terjeszthetnek elő, illetve a jogszabályjavaslat elutasítását is kezdeményezhetik.\n\nJogszabályjavaslatok elfogadása – plenáris ülések:\nAz összes európai parlamenti képviselő megjelenik az ülésteremben, hogy részt vegyen a jogszabályjavaslat és az előterjesztett módosítások sorsát eldöntő zárószavazáson. A plenáris üléseknek, melyek havonta négy napon át zajlanak, rendes körülmények között Strasbourg ad otthont, de néha további ülésekre is sor kerül Brüsszelben.\n\nA Parlament és Ön\n\nHa Ön azt szeretné, hogy a Parlament intézkedjen valamilyen ügyben, petíciót nyújthat be az intézménynek (postai úton vagy az interneten).\n\nEurópai Bizottság\n\nSzerep: előmozdítja az EU általános érdekeinek érvényesülését azáltal, hogy jogszabályjavaslatokat dolgoz ki, érvényt szerez a már elfogadott uniós jogszabályoknak, továbbá végrehajtja a szakpolitikákat és az uniós költségvetést\n\nTagok: a biztosi testület, melybe mindegyik uniós tagállam 1 biztost delegál\n\nElnök: Ursula von der Leyen\n\nAlapítás éve: 1958\n\nSzékhely: Brüsszel (Belgium)\n\nAz Európai Bizottság az EU politikailag független végrehajtó szerve. Amellett, hogy kizárólagos hatáskörével élve új uniós jogszabályjavaslatokat dolgoz ki, ez az intézmény hajtja végre az Európai Parlament és az Európai Unió Tanácsa által hozott döntéseket.\n\nMilyen feladatokat lát el a Bizottság?\n\nJogszabályjavaslatokat dolgoz ki\n\nA Bizottság az egyedüli EU-intézmény, amely uniós jogszabályjavaslatokat terjeszt elfogadás céljából az Európai Parlament és a Tanács elé. A javaslatok:\n\narra irányulnak, hogy védelmezzék az Európai Unió és az uniós polgárok érdekeit olyan kérdésekben, melyeket nem lehet hatékonyan kezelni tagállami szinten;\n\nszakmailag megfelelően elő vannak készítve, mivel kidolgozásuk során a Bizottság szakértőkkel és a lakossággal is konzultál.\n\nVégrehajtja az EU szakpolitikáit és elosztja az uniós forrásokat\n\nA Tanáccsal és a Parlamenttel közösen meghatározza az EU kiadási prioritásait.\n\nKidolgozza az EU éves költségvetését, melynek jóváhagyásáról a Parlament és a Tanács dönt.\n\nFelügyeli az uniós források elköltését. A Bizottság ez irányú tevékenységét a Számvevőszék ellenőrzi.\n\nÉrvényt szerez az uniós jogszabályoknak\n\nAz Európai Unió Bíróságával közösen gondoskodik arról, hogy az EU jogszabályait mindegyik uniós ország megfelelően alkalmazza.\n\nKépviseli az Európai Uniót a nemzetközi színtéren\n\nAz uniós országok nevében eljárva részt vesz a nemzetközi szervezetek munkájában, különösen a kereskedelempolitika és a humanitárius segítségnyújtás területén.\n\nNemzetközi megállapodások megkötésére irányuló tárgyalásokat folytat az EU képviseletében.\n\nÖsszetétel\n\nAz intézmény politikai vezetéséről a biztosok testülete gondoskodik, melyet tagállamonként egy, összesen tehát 27 biztos alkot. A testület vezetője, a Bizottság elnöke dönt arról, hogy melyik biztos melyik szakpolitikai területért legyen felelős.\n\nA biztosi testület tagjai a következők: a Bizottság elnöke, nyolc alelnök, köztük három ügyvezető alelnök és az Unió külügyi és biztonságpolitikai főképviselője, valamint 18 biztos. A biztosok mindegyike más-más szaktárcáért felel.\n\nA Bizottságot napi szinten az intézmény dolgozói (ügyvédek, közgazdászok stb.) működtetik, akik főigazgatóságoknak nevezett szervezeti egységekben végzik munkájukat. A főigazgatóságok mindegyike meghatározott szakpolitikai területért felelős.\n\nAz elnök kinevezése\n\nAz európai bizottsági elnöki posztra az Európai Tanácsban ülésező állam- és kormányfők állítanak jelöltet az európai parlamenti választások eredményének figyelembevételével. A jelöltnek az európai parlamenti képviselők többségének támogatását el kell nyernie ahhoz, hogy megválasszák.\n\nAz alelnökök és biztosok kiválasztása\n\nAz elnökjelölt – az uniós országok indítványai alapján – kiválasztja, kiket javasol az alelnöki és a biztosi tisztségekre. Az alelnök- és biztosjelöltek listáját jóvá kell hagyniuk az Európai Tanács tagjainak, azaz a tagállamok vezetőinek.\n\nMindegyik jelölt meghallgatáson vesz részt az Európai Parlament előtt, hogy ismertesse a pozícióval kapcsolatos elképzeléseit, és megválaszolja a képviselők kérdéseit. Ezt követően a Parlament tagjai szavaznak arról, hogy jóváhagyják-e a jelöltekből álló testület egészét. Végezetül az Európai Tanács minősített többséggel kinevezi a hivatalba lépő Bizottságot.\n\nA most hivatalban lévő Bizottság megbízatása 2024. október 31-ig tart.\n\nHogyan végzi munkáját a Bizottság?\n\nStratégiai tervezés\n\nAz elnök jelöli ki a Bizottság szakpolitikai tevékenységének irányvonalát, amelynek mentén a biztosok együttesen stratégiai célkitűzéseket határoznak meg, és kidolgozzák az éves munkaprogramot.\n\nTestületi döntéshozatal\n\nA Bizottság testületileg felelős az általa meghozott döntésekért. A biztosok a döntéshozatal során egymással egyenrangúak, és a meghozott döntésekért azonos mértékben felelnek. Az egyes biztosok egyénileg nem hozhatnak döntéseket, kivéve ha erre bizonyos helyzetekben felhatalmazást kapnak.\n\nAz alelnökök az elnök nevében járnak el, és több biztossal közösen koordinálják a felelősségi körükbe tartozó területeken folyó munkát. A Bizottság kiemelt fontosságú projekteket határoz meg annak érdekében, hogy a biztosok szorosan együttműködjenek egymással, ugyanakkor rugalmasan végezhessék munkájukat.\n\nAz alelnökök a biztosok támogatásával javaslatokat terjesztenek a testület egésze elé. A testület rendszerint konszenzussal dönt, de időnként az is előfordul, hogy szavazással határoz a benyújtott javaslatokról. Utóbbi esetben a biztosok egyszerű többséggel hoznak döntést a kérdésben. A szavazás során a biztosok fejenként egy szavazattal rendelkeznek.\n\nA biztosi testület döntéseinek megvalósításával az adott szakpolitikai területért felelős főigazgatóság foglalkozik (a főigazgató irányítása alatt, aki az illetékes biztosnak tartozik beszámolási kötelezettséggel). Ez a gyakorlatban az esetek többségében jogalkotási javaslattervezetek kidolgozását jelenti.\n\nA tervezeteket ezt követően a főigazgatóságok felterjesztik a biztosok elé, akik heti üléseiken döntenek róluk. Az elfogadott szövegeket – immár hivatalos jogalkotási javaslat formájában – a Bizottság megküldi a Tanácsnak és a Parlamentnek, a jogalkotási folyamat további résztvevőinek.\n\nMagyarország és az Európai Unió\n\nMagyarország 2004. május 1-je óta az Európai Unió teljes jogú tagja. A több évig tartó csatlakozási tárgyalások lezárulta után az EU-val való csatlakozási szerződést 2003 áprilisában írták alá Athénban.\n\nMagyarország 2007. december 21-én vált a schengeni megállapodás teljes jogú tagjává és ezzel a közös, belső határellenőrzések nélküli európai térség részévé.\n\n2011. január 1-től Magyarország látta el az EU Tanácsának soros féléves elnökségét.\n\nMagyarország az európai uniós támogatások egyik legnagyobb haszonélvezője. Az országba naponta átlagosan több mint 3 milliárd forinttal több EU-s pénz érkezik, mint amennyit Magyarország az Unió költségvetésébe befizet.\n\nA csatlakozással Magyarország a világ legfejlettebb és legnagyobb egységes piacának vált szerves részévé, és a többi országgal egyenrangú szereplője lett az uniós döntéshozatalnak. Az EU-nak köszönhetően a magyar polgárok is szabadon utazhatnak, tanulhatnak, dolgozhatnak bármelyik uniós tagállamban. A határok átjárhatósága a határon túli magyarokkal való kapcsolattartást is megkönnyítette.\n\nAz egységes európai piacnak köszönhetően nemcsak olcsóbban vásárolunk, ráadásul biztonságosabb termékeket, de a magyar vállalatok és gazdálkodók is óriási lehetőségekhez jutnak. Az agrárkivitel például a csatlakozás óta csaknem a két és félszeresére nőtt, és nagymértékben az EU-tagságnak köszönhető, hogy számos világvállalat Magyarországon telepedett meg, ezzel is jelentősen támogatva az ország fejlődését.\n\nA Bizottság magyar tagja\n\nAz Európai Bizottság magyar tagja Várhelyi Olivér szomszédságpolitikáért és bővítésért felelős biztos.\n\nFőbb feladatai közé tartozik többek között:\n\naz EU szomszédos országaival fenntartott kapcsolatok megerősítése,\n\na csatlakozási folyamat folytatása a Nyugat-Balkán országaival,\n\nszoros együttműködés Törökországgal, a közös kihívások kezelése,\n\na keleti partnerországokkal fenntartott kapcsolatok elmélyítése, és új, hosszú távú politikai célkitűzések megfogalmazása a keleti partnerségre vonatkozóan,\n\naz Ukrajnával, Grúziával és Moldovával megkötött társulási megállapodás végrehajtásának, valamint az ezekkel az országokkal létrehozandó mélyreható és átfogó szabadkereskedelmi térségek kiépítésének felgyorsítása.\n\nA Bizottság korábbi magyar tagjai\n\n2014-2019\n\nNavracsics Tibor - kultúra, oktatás, ifjúságpolitika és sport\n\n2010-2014\n\nAndor László - foglalkoztatás, szociális ügyek és társadalmi összetartozás\n\n2004-2009\n\nKovács László – adó- és vámügyek\n\n2004\n\nBalázs Péter – regionális politika\n\nMagyarok más uniós intézményekben\n\nMagyarország 21 képviselőt delegál az Európai Parlamentbe. Magyar képviselők és delegáltak további uniós intézmények munkájában is fontos szerepet játszanak.\n\nMagyarország az EU-ban\n\nEurópai Parlament\n\nMagyarország 21 képviselőt delegál az Európai Parlamentbe. Ha szeretné megtudni, ki képviseli a magyar választópolgárokat az Európai Parlamentben.\n\nEurópai Unió - választások\n\n2024. június 6-9.\n\nAz Európai Unió Tanácsa\n\nAz Európai Unió Tanácsában a tagállami miniszterek üléseznek. Rendszeres találkozóikon megtárgyalják és elfogadják az uniós jogszabályokat, és összehangolják a szakpolitikai intézkedéseket. A Tanács ülésein a magyar kormány képviselői is rendszeresen részt vesznek – hogy éppen ki, az attól függ, hogy az ülésen melyik szakpolitikai terület kérdései vannak napirenden.\n\nAz Európai Unió Tanácsának elnöksége\n\nAz EU Tanácsának nincs állandó elnöke, aki egyedül áll az intézmény élén (szemben például a Bizottsággal és a Parlamenttel). A testület munkáját félévente más ország irányítja – az a tagállam, amelyik betölti a Tanács hathavonta cserélődő soros elnöki tisztségét.\n\nE hat hónap alatt a soros elnökséget ellátó ország miniszterei elnökölik a Tanács üléseit, segítenek kialakítani a találkozók napirendjét az egyes szakpolitikai területeken, és egyeztetnek a többi uniós intézménnyel.\n\nA magyar soros elnökség időszaka:\n\n2011. január–június\n\nAz Európai Unió Tanácsának elnöksége\n\nAz EU Tanácsának jelenlegi elnöksége\n\nEurópai Bizottság\n\nAz Európai Bizottság magyar tagja Várhelyi Olivér, aki a szomszédságpolitikáért és a bővítésért felel.\n\nA Bizottság az egyes EU-országokban helyi irodát, ún. képviseletet működtet.\n\nA Bizottság Magyarországi Képviselete\n\nA Bizottság korábbi magyar tagjai\n\n2014-2019\n\nNavracsics Tibor - kultúra, oktatás, ifjúságpolitika és sport\n\n2010-2014\n\nAndor László - foglalkoztatás, szociális ügyek és társadalmi összetartozás\n\n2004-2009\n\nKovács László – adó- és vámügyek\n\n2004\n\nBalázs Péter – regionális politika\n\nEurópai Gazdasági és Szociális Bizottság\n\nMagyarországnak 12 képviselője van az Európai Gazdasági és Szociális Bizottságban. Az Európai Gazdasági és Szociális Bizottság a munkaadók, a munkavállalók és más társadalmi érdekcsoportok képviseletét látja el. Uniós tanácsadó szervként azzal kapcsolatban kérik ki a véleményét, hogy a javasolt jogszabályok milyen változásokat eredményezhetnek a tagállamok munkaerőpiaci és társadalmi viszonyaiban.\n\nRégiók Európai Bizottsága\n\nMagyarországnak 12 képviselője van a Régiók Európai Bizottságában, a regionális és helyi képviselők európai uniós közgyűlésében. A Régiók Európai Bizottsága tanácsadó szerv, melynek véleményét annak érdekében kérik ki, hogy az uniós régiók érdekei kellő súllyal essenek latba az uniós jogalkotás során.\n\nAz EU melletti állandó képviselet\n\nMagyarország a brüsszeli állandó képviseletén keresztül is kapcsolatot tart az uniós intézményekkel. A brüsszeli állandó képviselet tulajdonképpen nagykövetségi funkciót lát el: feladata, hogy az ország érdekeit és céljait a lehető leghatékonyabban érvényesítse az EU-ban.\n\nKöltségvetés és finanszírozás\n\nMennyit fizet be Magyarország a közös kasszába, és mennyit kap onnan?\n\nAz EU méltányosan, az országok anyagi lehetőségeinek figyelembevételével állapítja meg, hogy az egyes tagállamoknak mennyit kell befizetniük az uniós költségvetésbe. Minél nagyobb gazdasággal rendelkezik az adott ország, annál többel járul hozzá a közös kasszához.\nAz uniós költségvetés célja nem az anyagi javak újraelosztása, hanem hogy forrásokat biztosítson olyan közérdekű célok megvalósításához, amelyek minden európai számára fontosak.\n\nAdatok az EU költségvetéséről, bevételeiről és kiadásairól:\n\nUniós költségvetés\n\nUniós kiadások és bevételek éves és országok szerinti bontásban\n\nUniós finanszírozású projektek Magyarországban\n\nA Magyarország által az uniós költségvetésbe befizetett pénz – a többi tagállam befizetéseihez hasonlóan – EU-szerte számos program és projekt finanszírozását teszi lehetővé, így például utak építését, a tudományos kutatás támogatását és a környezet védelmét.\n\nGazdasági kapcsolatok\n\nAz EU-n belüli kereskedelem a magyar export 78%-át teszi ki (ezen belül a kivitel 28%-a Németországba, valamint 5–5%-a Romániába, Szlovákiába, Ausztriába és Olaszországba irányul). Ami az EU-n kívülre irányuló exportot illeti, a magyar termékek 3%-a az Egyesült Államokban, 3%-a pedig az Egyesült Királyságban talál vevőre.\n\nA Magyarországra behozott termékek 71%-a tagországból érkezik (24%-uk Németországból, 6%-uk Lengyelországból, 5%-uk pedig Hollandiából). Ami a nem uniós országokat illeti, a Kínából érkező import részaránya 9%, a Koreai Köztársaságból behozott termékeké pedig 4%.', 245, 1, '2026-04-17 09:40:36', '2026-04-17 09:40:36');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(19, 19, 'A mai Magyarország politikai intézményrendszere és választási rendszere', '19.docx', '19. A mai Magyarország politikai intézményrendszere és választási rendszere\n\nDemokratikus jogállamiság Magyarországon:\n\n1989 előtt Magyarországon pártállami diktatúra volt, a rendszerváltás fő tartalma ennek felszámolása volt. Magyarországon a rendszerváltás időszaka 1989–1990. Magyarország a szovjet tömb szétesésével visszanyerte szuverenitását. A demokratikus jogállami viszonyok hazánkban a keleti tömbben lezajlott változásokkal egy időben lezajlott rendszerváltozáskor teremtődtek meg. A rendszerváltó politikai erők a modern alkotmányosság alapján álltak. A harmadik magyar köztársaság parlamentáris kormányrendszerben működik. Magyarország államberendezkedésének alapjait az Alkotmány rögzíti, és garantálja a három hatalmi ág szétválasztásának és egyben együttműködésének alapelveit. Magyarországon tehát a hatalommegosztás elve érvényesül, ezt az Alkotmány, 2012-től pedig az Alaptörvény deklarálja. Magyarország államberendezkedésének alapjait tehát az Alkotmány rögzíti, amely garantálja a három hatalmi ág szétválasztásának és egyben együttműködésének alapelveit. Magyarországon a nép választja a törvényhozói hatalom képviselőit, a parlamentben többséget szerző párt által jelölt miniszterelnök alakít kormányt. Hazánkban a demokratikus országok többségére jellemző parlamentáris kormányzati rendszer működik, ahol a kormány elsősorban a törvényhozásnak felelős. A magyar bíróságok függetlenek és ennek a függetlenségnek törvényi és intézményi garanciái is vannak. Az államszervezet demokratikus működése felett őrködik a köztársasági elnök és az Alkotmánybíróság. Ezek az intézmények az államszervezet demokratikus működése felett őrködnek. A végrehajtó hatalomtól független hatalmi ágak és ellenőrző szervezetek működnek. Ezek a fékek és ellensúlyok szerepét töltik be, biztosítják a törvények uralmát, az emberi jogok és az állampolgári jogegyenlőség érvényesülését. A magyar demokratikus átalakulás az egyetemes európai értékekhez alkalmazkodva történt meg. A demokratikus értékek garanciái: a civil társadalom, versengő pártok, a nyilvánosságot teremtő média, a többi demokratikus intézmény.\n\nA választási rendszer és az ombudsmanok 1990-2011 között (régi!!)\n\n• Országgyűlési választásokra ebben az időszakban is négyévente került sor:\n\nA választójog a rendszerváltás óta általános és egyenlő, a választás közvetlen és titkos.\n\nA választási rendszer vegyes. A képviselők egy részét egyéni választókerületekben választják (176 mandátum), más részét pedig területi (megyei és fővárosi) pártlistákról (legfeljebb 152 mandátum). A töredékszavazatok alapján az országos kompenzációs listáról is bekerültek képviselők (legalább 58 mandátum).\n\n• Képviselőjelölt az lehetett egyéni választókerületben, aki elegendő ajánlást gyűjtött össze a választópolgároktól, területi listát pedig az a párt állíthatott, amelynek elegendő számú egyéni képviselőjelöltje van.\n\nA mandátumot nem eredményező, un. töredékszavazatok az országos listára kerültek. Töredékszavazatnak csak az egyéni választókerületben a vesztes jelöltekre leadott szavazat minősült. Listáról csak olyan párt küldhetett képviselőt az Országgyűlésbe, amely elérte országosan eleinte a 4%-ot, majd az 5%-ot (parlamenti küszöb).\n\n• 2011-ig négy ombudsman tevékenykedett. Az állampolgári jogok biztosa. Köznapi nevén általános ombudsman: bármilyen emberi és állampolgári jog sérelme esetén eljárhatott, figyelmeztethette a jogsértőt és beszámolt az Országgyűlésnek.\n\nAz adatvédelmi biztos értelemszerűen az adatkezelés jogszerűségét, a személyes adatokkal való visszaélést vizsgálta.\n\nA kisebbségi jogok biztosa a nemzeti és etnikai kisebbségekhez tartozó állampolgárokat ért jogsérelmek ügyében járt el.\n\nA jövő nemzedékek jogainak biztosa elsősorban a környezetvédelmet érintő kérdéseket vizsgálta. Ezt a tisztséget az állampolgári jogok biztosának helyettese pozíciót megszüntetve hozta létre az Országgyűlés.\n\nJELENLEG:\n\nAlkotmányos alapok\n\nA rendszerváltáskor - az 1949. évi XX. törvény módosításaként - elfogadott köztársasági alkotmányt 2012. január l-jén Magyarország alaptörvénye váltotta fel. Az alaptörvény nemcsak nevében, hanem kifejezett rendelkezései szerint is a jogrendszer legfőbb jogi normája: magát Magyarország jogrendszerének alapjaként határozza meg, ami mindenkire kötelező; kimondja továbbá, hogy az alaptörvénnyel egyetlen jogszabály sem lehet ellentétes. Nevünk Magyar Köztársaság helyett Magyarország lett. Alaptörvényünk meghatározza az államformát (köztársaság), valamint deklarálja a főbb alkotmányos alapelveket, amelyek a rendszerváltás óta meghatározzák a magyar állam működését.\n\nA jogállamiság elvében fejeződik ki a jog uralmának, az állam joghoz kötöttségének követelménye. A népszuverenitás (népfelség) elvének megfelelően az államhatalom forrása csak a nép lehet, vagyis a közhatalom gyakorlására adott felhatalmazásnak minden esetben a néptől kell származnia. A népszuverenitás mellett a demokratikus hatalomgyakorlás másik alappillére a néprészvétel elve: a döntések meghozatalában a nép közvetve (választott képviselői útján) vagy közvetlenül (népszavazás, népi kezdeményezés keretében) vesz részt. Az általános és egyenlő választójog birtokában a politikai közösség minden tagja azonos jogokkal rendelkezik a közösség ügyeinek eldöntésében. Az állam működése a hatalommegosztás elvén alapszik: a közhatalom több intézmény között oszlik meg, amelyek egymás hatalomgyakorlását ellenőrzik és korlátozzák: törvényhozó, végrehajtó, igazságszolgáltató hatalom.\n\nAz alaptörvény az alapelveken túl deklarálja és garantálja az alapjogokat, vagyis az egyéneket megillető és egyúttal az államhatalmat korlátozó legalapvetőbb jogosultságokat; illetve rögzíti az államszervezetre vonatkozó legfőbb szabályokat.\n\nA demokratikus hatalomgyakorlás\n\nA magyar alkotmányos rendszer főbb intézményei\n\nMagyarország parlamentáris kormányzati rendszerét erős törvényhozó hatalom, stabil kormány és reprezentatív államfői hatáskörök jellemzik. A képviseleti hatalomgyakorlás elsődlegességéből kifolyólag az országgyűlés lényegében minden életviszonyt szabályozhat, legfontosabb feladata a törvényalkotás. Emellett a parlament fő funkciója a végrehajtó hatalom ellenőrzése, hiszen a kormány az országgyűlésnek felelős. A kormányt rendszeres beszámolási, tájékoztatási kötelezettség terheli; a képviselők interpellációt és kérdést intézhetnek a kormány tagjaihoz; továbbá az országgyűlés szakosított szervein (alapvető jogok biztosa, Állami Számvevőszék) keresztül is ellenőrzést gyakorol a kormány felett. A konstruktív bizalmatlansági indítvány segítségével az országgyűlés megvonhatja a bizalmat a miniszterelnöktől (és ezzel a kormánytól), ha a parlamenti többség megegyezik az új miniszterelnök-jelölt személyében. A végrehajtó hatalmat gyakorló kormány meghatározó tényezője a miniszterelnök, aki a köztársasági elnök javaslatára az országgyűlés többségének támogatásával nyeri el megbízatását. A kormány a miniszterek kinevezésével alakul meg. A kormány feladata az államügyek irányítása, a közigazgatás működtetése, valamint jelentős a jogalkotásban végzett munkája is.\n\nAz országgyűlés által választott köztársasági elnök (Magyarország államfője) a végrehajtó hatalom gyakorlásában nem vesz részt, fő funkciója az államszervezet demokratikus működése feletti őrködés és a nemzet egységének kifejezése; nagyrészt reprezentatív jellegű, többségében miniszteri ellenjegyzéshez kötött hatáskörei ehhez igazodnak. Az igazságszolgáltatást független, négyszintű bírósági rendszer látja el, élén a Kúriával. Az igazságszolgáltatásban közreműködő legfőbb ügyész és az ügyészség meghatározó feladata a vádemelésről való döntés, illetve a vád képviselete a büntetőügyekben. A Kúria elnökét és a legfőbb ügyészt a köztársasági elnök javaslatára az országgyűlés választja. A jogszabályok alaptörvénnyel való összhangjának ellenőrzése és az alkotmányellenesnek talált jogszabály megsemmisítése az Alkotmánybíróság feladata. Az Alkotmánybíróság 15 tagú testület, amelynek tagjait szintén az Országgyűlés választja. Az alapvető jogok biztosa az alapjogok védelme érdekében intézkedéseket kezdeményezhet. Helyettesei a jövő nemzedékek érdekeinek, valamint a nemzetiségek jogainak védelmét látják el. Központi bankunk a Magyar Nemzeti Bank, amely jegybanki feladatokat végez.\n\nAz országgyűlési választási rendszer működése Magyarországon\n\nAz Alaptörvény végrehajtására az országgyűlés által megalkotott, az országgyűlési képviselők választásáról szóló (2011. évi CCIII.) törvényt a 2014-es általános parlamenti választásokon alkalmazták először.\n\nAz országgyűlési képviselők választásáról szóló törvény alapján a választások alapelvei: a választójog általános és egyenlő, a szavazás közvetlen és titkos. Általános = minden nagykorú állampolgárt megillet; egyenlő = minden szavazat azonos mértékű; közvetlen = közvetlenül a jelöltekre szavazunk; titkos = a szavazat utólag személyhez nem köthető/nem beazonosítható). A választóknak két szavazatuk van: egy-egy voksot lehet leadni az egyéni jelöltek, illetve az országos pártlisták valamelyikére. Ezt nevezik vegyes választási rendszernek; a választás egyfordulós).\n\nEgyéni mandátumot az a jelölt szerez, aki a legtöbb érvényesen leadott szavazatot kapta, mindez független a megjelentek számától, nincs érvényességi küszöb; nem kell abszolút többséget elérni, tehát nincs eredményességi küszöb. A vesztes és a nyertes jelöltek után is jár töredékszavazat. Országos listáról akkor lehet mandátumot szerezni, ha a listára leadott szavazatok aránya meghaladja az 5%-ot (parlamenti küszöb). A pártok az országos listákra leadott szavazatok arányában kapnak mandátumot. A rendszer a győztest túljutalmazza; a kisebb parlamenti pártoknak hátrányos; a választások eredményei esetenként kevéssé tükrözik a választói akaratot. Az alacsony választási részvétel / hajlandóság jellemzője a magyarországi lakosságnak.\n\nMagyarországon érvényesül a népszuverenitás: a közhatalom forrása a nép; a nép hatalmát elsősorban választott képviselői útján/a választásokon gyakorolja. Magyarországon képviseleti, azaz közvetett demokrácia működik.\n\nMagyarországon a törvényhozó szerv a magyar Országgyűlés. Az Országgyűlés egykamarás; tagjait négyévente az országgyűlési választások során választja a nép. Minden nagykorú magyar állampolgár rendelkezik választójoggal, és ezt Magyarország Alaptörvénye rögzíti. A határon túli magyarok is jogosultak részt venni a magyarországi választásokon. Valakit a választójogától megfosztani csak a törvény által előírt esetekben, bírósági ítélettel lehet. Az országgyűlési képviselők száma 199, 106 országgyűlési képviselőt egyéni választókerületben, 93 országgyűlési képviselőt országos listán választanak. A választásokon a politikai pártok képviselőjelöltjei, illetve független jelöltek indulnak. A győztes párt vagy pártkoalíció (kormányzati szövetség) jelöltje lesz a miniszterelnök és alakít kormányt.\n\nA vegyes magyar választási rendszer kombinálja a többségi (egyéni) és az arányos (pártlistás) rendszert. Előnye: arányos rendszer = pontosabban tükrözi a választói akaratot, a kisebb pártok is esélyesek. Hátránya: széttöredezettebb parlamentet eredményez. Többségi rendszer = erősebb a személyes kapcsolat a képviselő és a választók között, a nagy pártok felülreprezentáltsága, lehetőség a stabilabb kormányzásra.\n\nA választójogot és a választásokat Magyarország Alaptörvénye, illetve az országgyűlési képviselők választásáról szóló (2011. évi CCIII.) törvény szabályozza. Négyévente tartanak országgyűlési választásokat; a választásra az adott év április vagy május havában kerül sor; a választások konkrét időpontját a köztársasági elnök tűzi ki; a külföldön tartózkodó választópolgárok a külképviseleten is szavazhatnak; a választások lebonyolításában közreműködnek/törvényessége felett választási bizottságok őrködnek.\n\nAz egyéni jelöltek megválasztása választókerületenként történik, a jelöléshez legalább ötszáz választópolgár ajánlása szükséges; a választókerületek kialakításának egyik fontos elve, hogy bennük a választásra jogosultak száma megközelítőleg azonos legyen; a választókerületek kialakítása politikai viták alapját képezheti.\n\nA határon túli magyarok is választhatnak.\n\nA demokratikus hatalomgyakorlás a közvetett népképviseletet megjelenítő választási rendszeren és a választott képviselők útján történő döntéshozatalon alapul. „Minden nagykorú magyar állampolgárnak joga van ahhoz, hogy az országgyűlési képviselők, a helyi önkormányzati képviselők és polgármesterek, valamint az európai parlamenti képviselők választásán választó és választható legyen.” A magyar állampolgárt tehát aktív és passzív választójog illeti meg. A választójog gyakorlásának elvei: általános, egyenlő, közvetlen és titkos. Hazánkban az országgyűlési képviselők 1990 óta rendszeres és szabad választások alkalmával vegyes választási rendszerben négy évre nyerik el megbízatásukat. A 2012 óta hatályos és a következő országgyűlési képviselő-választáson alkalmazandó szabályozás szerint 106 egyéni választókerületi és 93 országos listás mandátum osztható ki. A választás egyfordulós. Az egyéni választókerületekben a szavazatok többségét megszerző jelölt nyeri el a mandátumot, ez a választási rendszer többségi eleme. A pártok országos listát akkor állíthatnak, ha legalább 9 megyében és a fővárosban 27 egyéni választókerületben állítottak jelölteket. Azok a pártok részesülhetnek a listás mandátumokból, amelyek megszerzik az országos listás szavazatoknak legalább 5 százalékát, tehát teljesítik a parlamentbe jutási küszöböt. Azok az egyéni választókerületi szavazatok, amelyek nem eredményeznek mandátumot; valamint azok is, amelyeket a győztes jelöltre a mandátumszerzéshez szükséges minimális szavazatszámon felül adnak le, töredékszavazatként hozzáadódnak az adott - küszöböt teljesítő - pártlistás szavazataihoz (kompenzációs elem). A listás mandátumok kiosztására az egyes pártok támogatásának arányában kerül sor, ez a választási rendszer arányossági eleme. Az országos nemzetiségi önkormányzatok a pártok országos listáihoz hasonlóan nemzetiségi listákat állíthatnak.\n\nMagyarországon többpártrendszer működik. A parlamenti választásokon többséget elért párt/pártkoalíció alakíthat kormányt. Jelenleg az országgyűlésben a pártok frakciók szerint tagolódnak, és független képviselőkkel működik. A közvetlen demokrácia gyakorlásának klasszikus intézménye a népszavazás (referendum). Magyarországon minden érvényes és eredményes népszavazás ügydöntő, azaz köti a jogalkotót. A népi kezdeményezés arra irányul, hogy az országgyűlés egy meghatározott kérdést a napirendjére tűzzön és megtárgyaljon.\n\nA választójogi rendszer változása (összegzés)\n\nAz országgyűlési képviselők számát 386-ról 199-re csökkentették, így az Országgyűlés munkája olcsóbb lett,\n\nNagyobbak lettek a választókerületek, ezzel együtt megszűntek a területi listák\n\nA választás kétfordulósból egyfordulós lett, ez a nagyobb pártoknak kedvez, összefogásra ösztönzi a kis pártokat,\n\nA választási eljárás egyszerűbb, gyorsabb, a szavazás a résztvevők számától függetlenül érvényes.\n\nMagyarországon a választójog általános és egyenlő, a választás pedig titkos és közvetlen. Ez megfelel a modern demokráciáknak, ezt az 1989-es Alkotmány és a 2011-es Alaptörvény is rögzíti. 18 év felett lehet választani.\n\nEgyéni és listás mandátumokat lehet szerezni.\n\nEgyszerre érvényesül a többségi és az arányos elv.\n\nA korábbi rendszerben területi listák voltak. Volt országos – kompenzációs – lista. Az új rendszerben országos pártlista van - ami a töredékszavazatokon keresztül kompenzál is -, az egyéni választókerületek a nagyobb pártoknak kedveznek.\n\nA választási ciklus négyéves. A pártoknak bejutási küszöbe van: 5%\n\nA választások tisztaságát választási bizottságok ellenőrzik. A választási bizottságokba a pártok delegálnak tagokat.\n\nA választásokat kampány előzi meg. A kampányra költött pénzről el kell számolni.\n\nIdőközi választásokat is lehet tartani. A bejutási küszöböt emelték, módosították.\n\nMagyarországon az alkotmány szerint minden állampolgárt általános és egyenlő választójog illeti meg, a szavazás pedig mindenkor közvetlen és titkos. Négyévente országgyűlési, a legújabb, 2012. január 1-jével hatályba lépett választási törvény szerint pedig ötévente önkormányzati választásokat kell tartani; az országgyűlési választás időpontját legkésőbb 72 nappal a választások előtt a köztársasági elnök tűzi ki.\n\nA magyar választási rendszert a 2011. évi CCIII. törvény szabályozza. Eszerint a választások egyfordulós, kétszavazatos rendszerben kerülnek lebonyolításra. A magyar választási rendszer úgynevezett vegyes rendszer. A választandó országgyűlési képviselők száma 386-ról 199-re csökkent, ebből 106 képviselőt területi-perszonális elv alapján egyéni választókerületben, közvetlen választás útján, relatív többségi rendszerben választanak. A fennmaradó 93 képviselő az országos listáról kerül a parlamentbe – amennyiben nem sikerült kedvezményes mandátumot szereznie nemzetiségi képviselőnek –, mely zárt listára a választók közvetlenül szavaznak. Az a párt kaphat innen mandátumot, melynek listája elérte a szavazatok arányában az 5%-ot. Lehetőség van közös pártlistát indítani – például 2014-ben a Fidesz-KDNP és az Összefogás listája is ilyen volt –; kétpárti lista számára 10%, kettőnél több párt listája számára pedig 15% a küszöb.\n\nJelentős változás a korábbi választási rendszerhez képest az is, hogy a szavazás érvényességéhez nem szükséges 50% feletti részvétel.\n\nJelöltállítás\n\nEgyéni képviselőjelöltként annak a legalább 18 éves, magyar állampolgárságú személynek a neve kerülhet a szavazólapra, aki legalább 500, az ajánló személyi számával és aláírásával ellátott ajánlószelvényt tudott összegyűjteni. Egy választópolgár érvényesen a lakóhelye szerinti választókerületben több jelöltet is támogathat. Egyéni képviselőjelölt lehet független vagy párt jelöltje. A pártok állíthatnak közös jelöltet is.\n\nOrszágos listát az a párt állíthat, amely – legalább 9 megyében és Budapesten – legalább 27 egyéni választókerületben önállóan jelöltet állított.\n\nA nemzetiségi listát állíthatnak az országos nemzetiségi önkormányzatok.\n\nSzavazás: Magyarországon lakóhellyel rendelkező személyek egy egyéni választókerületi jelöltre és egy pártlistára szavazhatnak.\n\nMagyarországon lakóhellyel rendelkező, a névjegyzékben nemzetiségi választópolgárként szereplő személyek egy egyéni választókerületi jelöltre és nemzetiségének listájára, annak hiányában egy pártlistára szavazhatnak.\n\nMagyarországon lakóhellyel nem rendelkező személyek egy pártlistára szavazhatnak.\n\nA választás eredményének a megállapítása\n\nAz egyéni választókerületben az a jelölt lesz országgyűlési képviselő, aki a legtöbb érvényes szavazatot kapta. Nem szerezhet mandátumot az a pártlista, amely a pártlistákra és a nemzetiségi listákra leadott összes érvényes szavazat legalább 5%-át nem érte el. Közös pártlistánál ez a szám 10%, illetve 15%.\n\nAz egyéni választókerületekben továbbá keletkeznek töredékszavazatok is az egyéni jelöltek választása során. Töredékszavazatnak minősülnek az azon egyéni képviselőjelöltekre leadott szavazatok, akik végül nem szereztek mandátumot az adott kerületben, illetve a mandátumot szerzett képviselőjelölt és a másodiknak végzett jelölt közötti szavazatkülönbség eggyel csökkentett értéke. Ez természetesen csak akkor érvényes, ha átlépték az 5%-os országos küszöböt. Független jelöltnél nincs töredékszavazat.\n\nA töredékszavazatok számítása\n\nA töredékszavazatok az országos pártlistákra leadott szavazatokhoz adódnak hozzá.\n\nTöredékszavazat keletkezik a mandátumot nem szerzett egyéni jelöltek szavazataiból, valamint\n\ntöredékszavazat keletkezik a mandátumot szerző jelölt szavazataiból a második legtöbb szavazatot elérő jelölt eggyel növelt szavazatainak kivonása után fennmaradó szavazataiból is.\n\nAz országos listáról megszerezhető mandátumok kiosztása\n\nÖssze kell adni a töredékszavazatokat, a pártlistás szavazatokat és a nemzetiségi listára leadott szavazatokat, majd az így kapott számot el kell osztani 93-mal, ezt a számot el kell osztani 4-gyel, ez az egész szám lesz a kedvezményes kvóta. Az a nemzetiségi lista kaphat 1 kedvezményes mandátumot, ahol a szavazatok száma meghaladja az előbb megállapított számot.\n\nAz országos listán megszerezhető 93 mandátumot annyival kell csökkenteni, amennyi kedvezményes mandátum ki lett osztva. Például ha 1 német és 1 cigány kedvezményes mandátumot osztanak ki, akkor már csak 91 kerül kiosztásra a pártok és a nemzetiségek között.\n\nAz így fennmaradó mandátumok d’Hondt-mátrix segítségével kerülnek kiosztásra azzal a kiegészítéssel, hogy a pártlisták összesített szavazatai mellé felírjuk még a nemzetiségi listák kedvezményes kvótával csökkentett szavazatait is. Így még ők is kaphatnak mandátumot a kedvezményesen felül.\n\nAz országos lista által megszerzett mandátumokat a jelöltek az országos listán elfoglalt helyük sorrendjében szerzik meg úgy, hogy a listáról törlésre kerülnek az egyéni választókerületben mandátumot szerző jelöltek. Amennyiben az országos listán maradt jelöltek száma kevesebb, mint a kiosztható mandátumok száma, akkor a ki nem osztott mandátum betöltetlen marad.\n\nNemzetiségi szószóló\n\nLehetőség van nemzetiségi szószólót küldeni az Országgyűlésbe azoknak a nemzetiségi listát állító nemzetiségeknek, melyek nem érték el a kedvezményes mandátumhoz szükséges szavazatszámot. A szószóló a listájukon 1. helyen szereplő személy lesz.\n\nIdőközi választások\n\nEgyéni kerületben időközi választást kell tartani, ha a választáson nincs jelölt, egyenlő szavazatszám esetén, vagy ha a megválasztott egyéni választókerületi képviselő megbízatása megszűnik. Ha országos listán mandátumhoz jutott képviselő megbízatása szűnik meg, akkor a listán szereplő következő jelölt lesz képviselő. Szószólónál szintén.\n\nA választási szervek\n\nA 2013. évi XXXVI. törvény szabályozza a választási eljárást. A választásokat lebonyolító és felügyelő szervek a választási bizottságok és ezek végrehajtó apparátusai, a választási irodák. Ötféle választási bizottság van:\n\na szavazatszámláló bizottság (azokon a településeken, ahol csak egy szavazókör van, nem választanak ilyet),\n\na helyi választási bizottság,\n\naz országgyűlési egyéni választókerületi választási bizottság (OEVVB),\n\na területi választási bizottság és\n\na Nemzeti Választási Bizottság (NVB).\n\nA választási bizottságok független, csak a törvénynek alárendelt szervek. Feladatuk az eredmények megállapítása, a választások törvényességének biztosítása, a pártatlanság érvényesítése és szükség esetén a választás törvényes rendjének helyreállítása. A választási eredmény megállapítását követően a választási bizottságok adják át a megbízatást a képviselőknek.\n\nAz NVB öt tagját és a szükséges számú póttagot legkésőbb 51 nappal az első választási forduló előtt az Országgyűlésnek kell megválasztania a belügyminiszternek a pártok javaslatait figyelembe vevő indítványa alapján. Az egyéni választókerületi, illetve a területi választási bizottságok legalább 3-3 tagját a fővárosi, illetve a megyei közgyűlések választják meg a területi választási iroda vezetőjének indítványa alapján, ugyancsak legkésőbb 51 nappal az első választási forduló előtt. A 11 ezer szavazatszámláló bizottság 3-3 tagját és a szükséges póttagokat a választások első fordulója előtt legkésőbb húsz nappal választják meg az önkormányzatok képviselőtestületei a helyi választási iroda vezetőjének indítványa alapján. A választási bizottságok végrehajtó szervei mind az öt szinten a választási irodák. Feladatuk a választások lebonyolításához szükséges számítógépes rendszer üzemeltetése, a helyiségek biztosítása és a jelöltek választási jegyzékbe vétele. Az Országos Választási Iroda (OVI) működését a belügyminiszter felügyeli.\n\nJogorvoslat\n\nA szavazatszámláló bizottság tevékenysége vagy döntése elleni kifogásról az OEVVB dönt. Az OEVVB határozata ellen fellebbezést lehet benyújtani az NVB-hez, az NVB határozataival szemben pedig a Kúriához lehet bírósági felülvizsgálati kérelemmel fordulni. A kampányban tapasztalt törvénysértés gyanújával kapcsolatban az OEVVB-hez vagy az NVB-hez kell fordulni.\n\nKritikák\n\nAz új választási rendszert az ellenzéki pártok és néhány civil szervezet már elfogadásakor támadta. A legkeményebben támadott módosítás, az előzetes regisztrációhoz kötött voksolás ügyében a kormánypárt végül engedett, és nem vezette be. Az intézkedés a lefizetéses választási csalást tette volna sokkal nehezebbé, ugyanakkor kizárta volna a közvetlenül a választás előtt, az utolsó pillanatban magukat elhatározó szavazókat is.\n\nA Társaság a Szabadságjogokért (TASZ) szerint ezáltal jelentősen csökkenti a saját politikai befolyását, aki a kisebbségi listás szavazást választja. Ennek kapcsán egy nemzetiségi párt, a Magyarországi Cigány Párt (MCP) felszólította a nemzetiségi választópolgárokat, hogy ne éljenek a lehetőséggel, ugyanis véleményük szerint a kisebbségek azáltal, hogy nem adhatják le szavazatukat a pártlistára, súlyos jogfosztást szenvednek el.\n\nAz új választási rendszer létrehozásának egyik indoka a korábbi választásoknak visszaélésre lehetőséget teremtő elemei voltak, melyeket kihasználva számos csalás történt az előző hat választáson. Az új választási rendszer sem zárja ki teljesen a csalást, néhány esetben választópolgárok aláírását hamisították rá olyan pártok ajánlóíveire is, melyeket az illető választópolgárok nem kívántak támogatni. Bár az ügyben a Nemzeti Adatvédelmi és Információszabadság Hatóság (NAIH) a rendkívül nagy munkára hivatkozva (vagyis azt megtudni, pontosan melyik aláírás valódi és melyik hamis) elutasította a vizsgálatot.\n\nA népfelség érvényesülése Magyarországon – a mai magyar demokrácia\n\nDemokratikus választásokat a rendszerváltás után, 1990 óta tartanak,\n\nAz Alaptörvényt 2011-ben fogadták el, 2012-ben lépett hatályba.\n\nA népfelség fogalma: népszuverenitás\n\na hatalom forrása, gyakorlója a nép,\n\na nép hatalmát képviselők útján és közvetlenül gyakorolhatja,\n\na népfelség elve a felvilágosodás korában jelent meg, ez a demokrácia alapja.\n\nA népszavazás lehet országos vagy helyi REFERENDUM\n\naz érvényes népszavazás eredménye kötelező az országgyűlés számára,\n\na népszavazás érvényes, ha a választópolgárok több mint fele érvényesen szavazott, eredményes, ha résztvevők több mint fele azonosan szavazott\n\naláírásgyűjtéssel lehet népszavazást kezdeményezni,\n\na kormány és a köztársasági elnök is kezdeményezhet népszavazást,\n\na népszavazást az országgyűlés rendeli el,\n\nszigorodtak az érvényes népszavazás feltételei, ez a közvetlen hatalomgyakorlás eszköze.\n\nAz országgyűlési választások:\n\nAz országgyűlési választásokat négyévente tartják.\n\nAz országgyűlési választásokon, a határon túli magyarok is részt vehetnek,\n\n106 választókerület van, a választókerületek száma csökkent.\n\nAz országgyűlés Budapesten ülésezik.\n\nA választások alapelvei: a választójog általános és egyenlő, a szavazás közvetlen és titkos:\n\náltalános = minden nagykorú állampolgárt megillet;\n\negyenlő = minden szavazat azonos értékű;\n\nközvetlen = közvetlenül a jelöltekre szavazunk;\n\ntitkos = a szavazat utólag személyhez nem köthető, nem beazonosítható.\n\nAz országgyűlési választásokon egyéni mandátumot az a jelölt szerez, aki a legtöbb érvényesen leadott szavazatot kapta. Ajánlásokkal lehet valaki képviselőjelölt.\n\nA választási győzelem független a megjelentek számától, nincs érvényességi küszöb, nem kell abszolút többséget elérni.\n\nNincs eredményességi küszöb, a vesztes és a nyertes jelöltek után is jár töredékszavazat, ez a nagypártoknak kedvez.\n\nA pártok az országos listákra leadott szavazatok arányában kapnak mandátumot.\n\nAz országos listáról akkor lehet mandátumot szerezni, ha a listára leadott szavazatok aránya meghaladja az 5%ot.\n\nArra a pártra lehet szavazni, aki képes országos listát állítani, a töredékszavazatok itt érvényesülnek, ez tükrözi jobban a pártszimpátiát.\n\nAz országgyűlés:\n\naz országgyűlés hozza a törvényeket,\n\na köztársasági elnök írja alá és hirdeti ki a törvényeket\n\na nép a képviselők révén – közvetett módon – szólhat bele a törvényalkotásba,\n\nvannak egyszerű és minősített, azaz kétharmados többséggel elfogadott törvények,\n\na törvényjavaslatokat bizottsági, plenáris üléseken vitatják meg.\n\nAz elfogadott törvényt az Alkotmánybíróságon lehet megtámadni,\n\na köztársasági elnök visszaküldheti a törvényt újratárgyalásra.\n\nA kormány: az országgyűlésnek felelős, ezt nevezik parlamentáris kormányzásnak.\n\na miniszterelnököt az országgyűlés választja és válthatja le,\n\na miniszterelnök-váltás módja a konstruktív bizalmatlansági indítvány.\n\nIgazságszolgáltató hatalom, azaz bírói hatalom a Kúria.\n\nEmberi jogok:\n\nAz emberi jogokat az alkotmány, jelenleg az Alaptörvény ismeri el. Az emberi jogok a rendszerváltás (1989/90) óta érvényesülnek teljes mértékben, majd 2012-ben új Alaptörvény lépett életbe Magyarországon.\n\nAz emberi jogok fogalma: az embert eredendően megillető, tőle meg nem vonható, az állam által csak elismert jogok. Az ombudsman garantálja az emberi jogokat.\n\nAz állam feladata az emberi jogok védelme. Az emberi jogok bizonyos feltételekkel korlátozhatók. Beszélhetünk egyéni és közösségi emberi jogokról.\n\nAz emberi jogok egyenlően illetnek meg mindenkit. Az emberi jogok eredendően, emberi mivoltukból fakadóan, tehát születésüktől fogva illetik meg az embereket.\n\nA modern alkotmányosság feltételei az emberi jogok elismerése, védelme. Az emberi jogok bizonyos feltételekkel korlátozhatók, a korlátozás feltétele a szükségesség és arányosság. Az emberi jogokat csak más emberi jogok érvényesülése érdekében lehet korlátozni. Az emberi jogok csak törvényben korlátozhatók, az emberi jogok korlátozhatóságát az Alkotmánybíróság vizsgálja. A szabályozás célja az állami visszaélés kizárása. Az Alkotmánybíróság feladata az alkotmány értelmezése.\n\nAz emberi jogokra érvényes a jogegyenlőség elve. Az emberi jogokat a felvilágosodás és a francia forradalom óta ismerik el. Emberi jogok: élethez, emberi méltósághoz való jog, szabadsághoz való jog, azaz szabadságjogok, tulajdonjog. Ezeket nevezik első generációs emberi jogoknak. Az egyént védik az állami túlkapásoktól. A Függetlenségi Nyilatkozatban, illetve az Emberi és Polgári Jogok Nyilatkozatában fogalmazódtak meg először. További emberi jog: a munkához való jog, művelődéshez való jog, egészségügyi ellátáshoz való jog, választójog, békéhez való jog, egészséges környezethez való jog. Ezek jogalanyai csak az állampolgárok, ezekhez a jogokhoz az állam aktív szerepvállalása szükséges.\n\nAz emberi jogok három generációját szokás elkülöníteni: az első generációs jogok a XVIII. század vége óta ismertek. A második generációs jogokat a XIX. században fogalmazták meg. A harmadik generációs jogokat pedig a XX. század második fele óta emlegetik. Az első generációs jogok az államot korlátozzák, a második generációs jogok az állam szerepvállalását feltételezik, a harmadik generációs jogok az államok együttműködését feltételezik. Az emberi jogok egyben állampolgári jogok is. Az alkotmányos államnak kötelessége elismerni azokat, bizonyos jogokat mindenki csak saját államában kényszeríthet ki.\n\nEmberi és állampolgári jogok, kötelességek\n\nEmberi jogok: veleszületett és ezért elidegeníthetetlen jogok. Alapvető szabadságjogok:\n\n• gondolat-, szólás-, lelkiismereti- és sajtószabadság - a modern demokráciákban (elvileg) érvényesülhetnek. Ideológiai forrás: az angol és francia felvilágosodás.\n\nFőbb dokumentumai:\n\n• Amerikai Függetlenségi Nyilatkozat (1776)\n\n• Emberi és Polgári Jogok Nyilatkozata (1789)\n\n• Az ENSZ Emberi Jogok Egyetemes Nyilatkozata (1948)\n\nA jogok korlátai:\n\n• mások jogai\n\n• törvények\n\n• rendkívüli helyzet.\n\nÁllampolgári jogok\n\nI. szabadságjogok\n\n• egyesülés és gyülekezési jog\n\n• szólás- és sajtószabadság\n\n• lelkiismereti és vallásszabadság\n\n• tulajdonhoz való jog\n\n• személyi sérthetetlenség\n\n• levéltitok sérthetetlensége\n\n• lakás sérthetetlensége\n\n• II. Gazdasági, szociális és kulturális jogok\n\n• munkához való jog\n\n• pihenéshez való jog\n\n• egészséghez és a szociális biztonsághoz való jog\n\n• művelődéshez való jog\n\n• III. Az állam tevékenységében való részvételt biztosító jogok\n\n• választójog\n\n• panaszjog\n\n• közügyekben való részvétel\n\n• népszavazás\n\n• falugyűlés\n\n• IV. Az állampolgárok egyenjogúsága\n\n• nemek egyenjogúsága\n\n• nemzetek és nemzetiségek egyenjogúsága\n\n• egyházak egyenjogúsága\n\nÁllampolgári kötelezettségek\n\n• honvédelem\n\n• adófizetés\n\n• törvények betartása\n\n• kiskorú gyermekek taníttatása\n\nA gyermek jogai\n\n• A gyermek érdekei mindenek felett állnak.\n\n• A gyereket ne válasszák el szüleitől. Tilos minden, bármely formában jelentkező megkülönböztetés.\n\n• A gyermek minden őt érdeklő kérdésben szabadon kinyilváníthatja véleményét.\n\n• Egyéb szabadság-, gazdasági-, szociális és kulturális jogok illetik meg.', 183, 1, '2026-04-17 09:40:36', '2026-04-17 09:40:36');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(20, 20, 'Ókori államberendezkedések', '20.docx', '20. tétel: Ókori államberendezkedések\n\n(Athén, Caesar, Augustus principátusa)\n\nATHÉN\n\nA demokrácia kialakulása Athénban a Kr.e. VII-V. században zajlott, Szolón reformja Kr.e. 594-ben, Kleiszthenészé Kr.e. 508-ban, a periklészi virágkor a Kr.e. V. században (Kr.e. 443 – 428) volt.\n\nKezdetben a származási elv érvényesült, az arisztokrácia ez alapján birtokolta a politikai jogokat, Szolón ezt a vagyoni elvvel helyettesítette, de az arisztokrácia befolyása továbbra is fennmaradt, Kleiszthenésznél már a területi elv alapján kerülhettek be a politikai életbe az athéni származású nagykorú férfi polgárok.\n\nKezdetek: Athénban az archaikus kor kezdetén a királyság intézményének keretei fokozatosan beszűkültek. Az uralkodó mellé előbb hadvezért (polemarkhoszt), majd arisztokrata tisztviselőt (arkhónt) választottak, így a király szerepe már csak a vallási teendőkre korlátozódott. Létrejött az arisztokratikus köztársaság. A démosz politikai jogaiért indított küzdelem elsősorban a vagyonosabb rétegek között zajlott Athénban. A királyság fokozatosan átadta helyét az arisztokratikus köztársaságnak, ahol minden politikai hatalmat az arisztokrata tisztségviselők gyakoroltak. A legfontosabb hivatal az arkhóni méltóság volt. Először egy, majd három, végül kilenc arkhón intézte az ügyeket. A hivatali idő: kezdetben életük végéig, majd tíz évre, végül évente választották őket. Az arkhóni tisztséget viselt arisztokraták testülete az Árész-dombi tanács (Areioszpagosz) lett.\n\nAz arisztokrácia mellett a másik társadalmi réteg az iparosokból, kereskedőkből, földművesekből álló démosz. Az i. e. VII. századra a társadalmi viszonyok is átrendeződtek. A vert pénz megjelenése lehetővé tette, hogy az arisztokratákon kívül a kereskedők is vagyont halmozhassanak föl, de a pénz jelenléte vezetett az adósrabszolgaság intézményének kialakulásához is.\n\nDRAKÓN arkhón: Kr. e. 621-ben (magyarul: sárkány) azzal, hogy írásba foglalta a törvényeket, ezzel gátat szabott a szokásjog önkényes értelmezésének. A rendkívül szigorú törvények - innen a „drákói szigor” kifejezés - továbbra is elsősorban az arisztokrácia érdekeit védték, de a törvényesség kialakítása fontos lépés volt a démosz számára.\n\nA gyarmatosításba bekapcsolódó görög poliszokban az arisztokrácia fokozatosan vesztett gazdasági erejéből, míg az iparosok, kereskedők s a földművesek egy része egyre gazdagodott, erősödött. A földművesek másik része továbbra is nehéz helyzetben volt, s teljes tönkremenetele esetén az adósrabszolgaságba került.\n\nSZOLÓN Kr. e. 594-ben volt arkhón, ám törvényhozói munkája hosszabb időszakot ölelt fel, s a Kr. e. 570-es évekre tehető. Szólón eltörölte az adósrabszolgaságot, és elengedte az adósságokat (szeiszakhteia - teherlerázás).\n\nTimokratikus alkotmányt hozott létre.\n\nA lakosságot vagyoni helyzet alapján 4 csoportba osztotta, s ez határozta meg politikai jogaikat és az általuk betölthető hivatalokat, s ezzel a démosz jómódú rétegét előnyös helyzetbe hozta. Ezzel Szolón új alkotmányt adott Athénnak. Ez a jövedelmi - vagyoni viszonyok alapján történő beosztás, azaz a timokrácia elvét követte, s a négy athéni törzs (phülé) lakóit a következő kategóriákba sorolta: ötszázmérősök (pentakosziomedimnosz), lovagok (hippeusz), ökörfogatosok (zeugithész) és napszámosok (thész). A beosztás nemcsak az adófizetés, de a katonai szolgálat teljesítésének alapjául is szolgált. Ez sok földműves számára tette lehetővé a föld megtartását, aminek katonai jelentősége is volt, hiszen Athénban csak szabad, és vagyonnal bíró polgár katonáskodhatott. Kr. e. VI. századra a nehézgyalogos hoplita (jómódú parasztok, kézművesek) és a flotta (kereskedők) váltak döntő fegyvernemekké.\n\nA politikai jogokat kiterjesztette a legszegényebb polgárokra is, szót adva nekik a (eklésziában) népgyűlésen és az általa megszervezett esküdtbíróságokban (héliaiában), így biztosította számukra is a beleszólást a polisz életébe. Megszervezte a bulét: a 400-ak tanácsát, ezáltal a démoszt is bevonta az államügyek intézésébe.\n\nEzekkel az intézkedésekkel Szólón megteremtette a demokrácia (népuralom) alapját, vagyis azt a rendszert, melyben az államhatalom (törvényhozás, kormányzás, bíráskodás) nem egy kiváltságos réteg, hanem a nép kezében is van. Az arisztokraták elvesztették korábbi kedvező helyzetüket, míg a démosz vezetői kevesellték jogaikat, hiszen a vezető tisztségeket még mindig az arisztokraták töltik be. A gazdasági fejlődés hatására az arisztokrácia gazdasági súlya tovább csökkent, de politikai hatalma jelentős maradt. A démosz esetében a fordítottja igaz: növekvő gazdasági erő, és ehhez képest még mindig csekély a politikai befolyás. Ez a helyzet lehetőséget adott arra, hogy egyes politikusok az arisztokrata családok közül egyeduralmat vezessenek be. Ezt a rendszert zsarnokságnak (türannisz), vezetőjét zsarnoknak (türannosz) nevezték a görögök.\n\nPeiszisztratosz i. e. 560-ban államcsínyt követett el, és bevezette a zsarnokság (türannisz) rendszerét, ami fiai uralkodásával együtt i. e. 510-ig állt fenn. Athén türannosza Peiszisztratosz (Kr. e. 560-527) türannosz elsősorban a démoszra támaszkodott. Hatalmának megszilárdítása érdekében az ellenálló arisztokraták földjeit - akik külföldre menekültek - kiosztotta a földnélküliek között, hogy támogatóinak számát növelje. Vidékre „kiszálló” bíróságokat szervezett, s így a parasztoknak nem kellett a városba menniük peres ügyeikkel, s neki sem kellett tartania a hatalmát veszélyeztető gyülekezéstől. Évi adót vezetett be, melyből fenntartotta Athén katonai erejét, s fedezte jelentős építkezéseit. A türannoszok nagy építtetők voltak, s templomok, kikötők, vízvezetékek, városfalak hirdetik ma is tevékenységüket. E nagy vállalkozások megrendeléseket jelentettek a kézműves, kereskedő réteg részére. Peiszisztratosz külpolitikájában is a kereskedelem és az ipar érdekeit vette figyelembe: előnyös szerződéseket kötött más poliszokkal. Peiszisztratosz támogatta a Fekete-tenger felé való terjeszkedést, támaszpontok létesítését, gazdaságilag megerősítette a démoszt, de a politikától távol tartotta. Nem zsarnok módjára uralkodott.\n\nA türannoszok hatalmuk biztosítása érdekében a démoszt támogatták az arisztokráciával szemben. A gazdaság fejlődése megerősítette a démoszt. Athénban Peiszisztratosz halála után fiainak, Hippiasznak és Hipparkhosznak már növekvő belső elégedetlenséggel kellett számolniuk, ők már zsarnok módjára uralkodtak. Hipparkhoszt egy felvonuláson meggyilkolták, de testvére, Hippiász sem tudta a hatalmat sokáig megtartani. A türannoszt Kr. e. 510-ben elűzték Athénből, s Perzsiába menekült.\n\nKleiszthenész reformjai Kr. e. 508.\n\nA türannisz megszűnése után a démosz olyan intézményrendszer kialakítását szorgalmazta, amely minden szabad athéni polgárnak esélyt adott arra, hogy a hatalomból részesedjen. Kleiszthenész kezébe adták a változtatás jogát az athéniak, aki a türannoszok elűzésében is kitűnt. Kleiszthenész fontosnak tartotta, hogy eleve lehetetlenné tegye a zsarnokság újjáéledését. Ezt a cserépszavazás (osztrakiszmosz) bevezetésével kívánta elérni. Ha valakit a polgárok veszélyesnek ítéltek, tartottak attól, hogy zsarnokságra tör, cserépszavazást tartottak. A gyanúsítottak nevét cserépdarabokra írták, s aki a legtöbb szavazatot kapta, azt 10 évre száműzték a városból, de vagyonát nem vették el. A szavazás akkor volt érvényes, ha legalább hatezren részt vettek benne.\n\nEgy korszerűbb berendezkedésre volt szükség, amit Kleisztenész i. e. 508-as reformjai hoztak el. A phüléket területi felosztás szerint szervezte át, azokon belül pedig városi (asztü), tengerparti (paralia) és vidéki (meszogeiosz) trittüszöket (3 rész) alakított ki. A demokrácia érvényesülését a szolóni alkotmányban is meglévő népgyűlés (ekklészia), esküdtbíróság (héliaiai) és bulé (itt 500-ak tanácsa) intézményei biztosították, illetve az az új eljárás, amely során véletlenszerűen, sorsolással jutottak tisztségekhez. Kleisztenész nevéhez fűződik a cserépszavazás (osztrakiszmosz) bevezetése is, amit a türannisz megelőzése érdekében hozott létre.\n\nAz új berendezkedés alapja a területi felosztás volt. Ez vált a korábbi származási, majd vagyoni alapon történő besorolás helyett a politikai, katonai, közigazgatási rendszer alapjává. Ez a demokrácia irányába tett lépés volt, mivel megszüntette a szabad polgárok közötti különbségeket.\n\nAttikát három részre osztotta: egy városira (Athén), egy tengerpartira, s a belső (azaz mezőgazdasági) területekre. Mindegyik harmad további tíz egységre oszlott, s ezekből egy-egy alkotott egy phülét (a phülé korábban törzset jelentett). Vagyis egy phülé egy tengerparti, egy városi és egy szárazföldi részből állt. Ez a politikai egység biztosította a démosz fölényét az arisztokráciával szemben, hiszen a három alkotóelemből kettőben (város, tengerpart) bizonyosan a démosz volt többségben. Minden phüléből 50 főt sorsoltak ki a buléba, a 10 phüléből összesen 500-an kerültek be az ötszázak tanácsába, azaz a buléba.\n\nA legfőbb hatalom a népgyűlés kezébe került, amelynek munkájában minden athéni polgár részt vehetett: aki 20 év feletti athéni származású férfi polgár. Az ekklészia (népgyűlés) hozta a törvényeket, kezében volt a háború és a béke kérdése, és általában minden fontos kérdésben a döntő szót e szervezet mondta ki. A népgyűlés sűrűn ülésezett, de nem folyamatosan. Ezért Kleiszthenész is meghagyta a fontos államhatalmi szervezetként korábban is létező bulét (tanács), de összetételét és létszámát megváltoztatta. Minden szabad polgár bekerülhetett ide. Az ötszázak tanácsa javaslatokat tehetett a népgyűlésnek, amelyeket már előre megtárgyalt, kisebb jelentőségű kérdésekben döntéseket is hozhatott.\n\nKleiszthenész nem szüntette meg az arkhóni intézményt és az arkhónok tanácsát, az Areioszpagoszt sem. Jelentős lépés volt a hadsereg átszervezése, aminek alapja szintén a területi felosztás lett, a 10 phüléből 1-1 sztratégoszt választottak, itt a kiválóság számított, és nem sorsolták. A katonai vezetők (sztratégoszok) az athéni állam tényleges vezetői voltak. Ezt a kiemelt szerepet mutatja az is, hogy ez volt az egyetlen tisztség, melyre az egyéves hivatali idő lejárta után ugyanazt a személyt ismét meg lehetett választani. Így lett 15 évig sztratégosz Periklész.\n\nA demokrácia kiteljesedése:\n\nMíg Athén győztesen vívta a perzsák elleni harcát (Kr.e. 490-ben Dareiosz ellen, Kr.e. 480-479. Xerxes ellen), folytatódott a demokrácia kiteljesedése. A Kr. e. V. század közepe a demokrácia virágkora Athénban, s ennek vezető politikusa Kleiszthenész unokaöccse, Periklész volt, aki a meggyilkolt reformer helyébe lépett.\n\nKr.e. 443-tól 15 éven át évről évre megválasztották első sztratégosznak, s így az athéni állam tényleges vezetője volt. A kleisztenészi államszervezet és a demokrácia kisebb változtatásokkal a periklészi évek alatt is működött. Kr. e. 462-ben az Areioszpagosz hatalmát jelentősen csökkentették, feladata a tisztviselők ellenőrzésére szűkült. Az arkhónokat eddig választották, de Periklész korában már sorsolták. A szegényebbek megélhetését veszélyeztette a politikában való részvétel, ami igen sok időt vont el a termelőmunkától. Ezért a kiesett jövedelem pótlására bevezették a napidíjat a népgyűléseken való részvételért. Periklész az ötszázak tanácsában és az esküdtbíróságokon végzett munkáért, majd később a görög politikai életben sajátos szerepet játszó színházi előadásokon való megjelenésért is napidíjat fizettetett az athéni állammal. Pontosan meghatározták, hogy ki tekinthető athéni polgárnak, elzárva ezzel az utat a polgárjog bővítésétől. Az athéni államnak nem okozott jelentősebb megterhelést a napidíjak rendszere.\n\nAz i.e. V. századi Athénban a demokrácia kiteljesedése Periklész idején történt. Ez azonban csak a 20 év feletti athéni férfi állampolgárokra vonatkozott. Ők a lakosság kb. 10 %-át tették ki. A nők, gyerekek, rabszolgák és a városba betelepülő idegenek, azaz metoikoszok nem vehettek részt az állam irányításában. A demokrácia akkor működött jól, amikor a polgárok nagy része érdekelt volt abban, hogy részt vegyen a politikai döntéshozatalban. A polgárok ugyan nem fizettek adót, de a metoikoszok és felszabadítót rabszolgák igen. Jelentős volt a kereskedelemből, a kikötői forgalomból, a bírságokból és a laurioni ezüstbányákból befolyó jövedelem. Komoly bevételt jelentett Athén számára a déloszi szövetségesek hozzájárulása, amelyet a perzsa háborúk után sem szüntettek meg, hanem tovább emeltek, s így az adóvá vált. Athén jóléte a gazdaság virágzásán nyugodott.\n\nA mezőgazdaság továbbfejlődött: szőlőt, olajbogyót, gyümölcsöket termesztettek. Az iparban is jelentős fejlődés volt tapasztalható: virágzott a kerámia-, a fémipar, a hajóépítés, és a nagy építkezések az építészetét is külön iparággá tették.\n\nAz iparban két fontos jelenség volt megfigyelhető: az egyes iparágai szakosodtak. Tért hódított a rabszolgamunka alkalmazása a műhelyekben, de főleg a bányákban.\n\nA legjobban fejlődő ágazat a kereskedelem volt. Egyrészt lebonyolította Athén növekvő behozatalát és kivitelét, másrészt Athén tengeri fölénye folytán jelentős volt a közvetítő kereskedelem is. Athén lakosságának közel fele a virágkorban is a polgárjoggal rendelkezők és családtagjaik közül került ki. A jogi egyenlőség létrejött a polgárok között, a vagyoni különbségek azonban nőni kezdtek. Ez elsősorban a rabszolgamunka előretörésének a következménye, de a szabadok is munkához jutottak, s a rabszolgáknak lehetőségük volt arra, hogy megválthassák magukat. A különbségeket enyhítették Periklész intézkedései: a vagyonosokra többletkiadásokat rótt, a szegényeket pedig napidíjakkal támogatta. Ez a viszonylagos vagyoni egyensúly és a politikai jogok egyenlősége tette lehetővé, hogy az athéni demokrácia egy-két nemzedék idejére ténylegesen biztosítsa az athéni polgárok egyenlőségét.\n\nA demokráciának és Athén virágzásának az Athén (déloszi szövetség) és Spárta (peloponnészoszi szövetség) között zajlott peloponnészoszi háború vetett véget: Kr. e. 431-404. Ennek során halt meg pestisjárványban Periklész. Spárta a perzsákkal is szövetségre lépett Athén ellen. Athén meggyengült. Ezután már pénzért árulták a szegényebbek a polgárjogukat, s ez a demokrácia hanyatlásához vezetett. Mintául szolgált a későbbi korok számára is ez az államrendszer.\n\nA demokrácia értékelése:\n\nMinden (felnőtt, férfi) polgár részt vehetett a népgyűlésen.\n\nA népgyűlés a legfontosabb politikai intézmény.\n\nA társadalom többsége (bevándorlók, rabszolgák, nők) nem rendelkezett politikai jogokkal.\n\nMinden athéni polgár egyenrangú.\n\nA népgyűlésen való részvételért napidíj jár.\n\nA tisztségekre választják (sztratégosz) és sorsolják a polgárokat.\n\nA sorsolás miatt a kiválóság nem érvényesül.\n\nA társadalom többsége (kiválóságától függetlenül) sem vehet részt a politikai életben.\n\nJULIUS CAESAR EGYEDURALMA RÓMÁBAN\n\nAZ ELSŐ TRIUMVIRÁTUS Kr.e. 60.\n\nElőzményei és létrejötte\n\nAz I. századra a Római Birodalomban a római köztársaság (Kr.e. 510 – Kr.e. 27.) válságba került. A külső-belső háború, a néppártiak és az optimaták közötti polgárháború Sulla diktatúrája után (Kr.e. 79.) és a Spartacus-féle rabszolgafelkelés leverése (Kr.e. 71.) után is folytatódott. A korszak három kiemelkedő személyisége: Pompeius, Crassus és Julius Caesar. A három férfi Kr.e. 60-ban titkos szövetséget kötött, ez az 1. triumvirátus. TAGJAI: Pompeius, Crassus, Julius Caesar\n\nPompeius: népszerűségét a senatus megpróbálta háttérbe szorítani azzal, hogy veteránjainak nem szavazta meg a földosztást. A csalódott Pompeius ezért keresett kapcsolatot.\n\nCrassus: Sulla hadvezére és feltétlen híve volt. Ő verte le a Spartacus-féle rabszolgalázadást. Kr. e. 70-ben Pompeiussal párban consulok lettek.\n\nCaius Julius Caesar\n\nPatrícius családból származik, de rokoni szálak fűzik a néppárti Mariushoz. Céltudatos néppárti politikájával hatalmas népszerűségre tett szert. Népszerű cirkuszi játékokat szervezett. A Kr. e. 60-as évek végére Pompeius és Crassus egyaránt a népszerű Caesar felé közeledett, mivel a senatus egyikük hatalmi ambícióját sem volt hajlandó támogatni.\n\nAz első triumvirátus (Kr. e. 60.)\n\nA három államférfi Kr. e. 60-ban titkos megállapodást kötött egymás kölcsönös politikai támogatására. E szövetséget nevezte el az utókor a három férfi szövetségének, latinul triumvirátusnak.\n\nKr. e. 59-bea Caesar lett a consul. Befolyása ekkor olyan nagy volt, hogy ezt az évet Caius és Caesar évének nevezték az akkoriak. Földet osztott Pompeius veteránjainak Campaniában. Megerősítette Pompeius keleti intézkedéseit. A Crassust támogató lovagrendiek számára előnyös adóbérleti összegeket állapított meg Asiában.\n\nEzek után Caesar 5 évre Gallia és Illíria helytartója lett. A két másik triumvir consuli éveik után szintén provinciákba távoztak:\n\n- Crassus Syriában helytartó lett, de Kr. e. 53-ban a parthusokkal vívott csatában meghalt.\n\n- Pompeius Hispániában kapott helytartóságot.\n\nA galliai hadjárat, Julius Caesar hatalomra jutása és háborúi\n\nKr. e. 58-51 között Caesar győzelmeket aratott a birodalmat folytonosan támadó barbár törzsek ellen. Legyőzte a helvetiusokat, belga törzseket, aquitanusokat, egyéb germán törzseket. Kétszer átkelt a Rajnán, harcolt Britanniában is. Legnagyobb győzelmét Kr. e. 52-ben Alesia ostrománál aratta Galliában. Gallia provinicát szervezte meg. Jövedelmeit nem szolgáltatta ki az adóbérlő lovagrendieknek. Erős, jól szervezett légiók fölött parancsolt.\n\nKözben Rómában súlyos utcai harcok dúltak Caesar hívei és a senatus emberei között. Pompeius, aki nem bírt úrrá lenni a lázadó, fegyvereseken, a senatus felé közeledett. Az újabb polgárháború a győztes Caesar és a senatus által támogatott Pompeius között elkerülhetetlennek látszott. A senatus Caesartól azt követelte, hogy hivatali idejének végeztével oszlassa fel hadseregét és térjen vissza Rómába, ismét fellángolt a polgárháború. Kr. e. 49. Caesar a seregével átlépte a Gallia és Itália határát jelképező Rubico határfolyót (ma Fiumicino). Ekkor mondta: Alea iacta est - A kocka el van vetve.\n\nPompeius a hír hallatára elmenekült Rómából. Caesar először Hispániát rendelte hatalma alá, majd Kr. e. 48-ban Pharszalosznál Pompeius csapatait győzte le. Pompeius Egyiptomba menekült, ahol a Ptolemaioszok meggyilkolták.\n\nGyőzelme után Caesar Egyiptomba vonult. Bevette Alexandriát és trónra emelte a Ptolemaioszok utolsó uralkodóit, XIV. Ptolemaioszt és testvérét, VII. Kleopátrát. Ekkor égett le Alexandria híres könyvtára.\n\nInnen seregeit Pontus ellen vezette. Kr. e. 47-ben Zelánál legyőzte Pharnakészt (VI. Mithridatész fiát) - e csatáról küldte a hadtörténet legrövidebb jelentését: veni, vidi, vici - jöttem, láttam, győztem. Hadjáratot vezetett még Pompeius maradék hívei ellen Africában (Kr. e. 46.) és Hispániában (Kr. e. 45) is.\n\nJulius Caesar egyeduralma\n\nCaesar rövid ideig tartó egyeduralma során számos intézkedésével megalapozta a későbbi monarchiát. Tisztségei, méltóságai:\n\n- dictator (Kr. e. 46-tól 10 évre, Kr. e. 44-től élethossziglani kinevezést kap), dönthetett háború és béke kérdésében, ő vezette a hadsereget (imperium maior);\n\n- consul;\n\n- néptribunus, személye szent és sérthetetlen volt, vétójoggal rendelkezett;\n\n- örökös censor, ő állította össze a senatus névjegyzékét;\n\n- pontifex maximus, vagyis főpap;\n\n- questor: rendelkezett államkincstár felett;\n\n- a közerkölcsök felügyelője és a haza atyja is volt;\n\n- imperátor: a főhatalom birtokosa, a győztes hadvezér.\n\nTeljhatalommal rendelkezett, de a királyi címet elutasította.\n\nIntézkedései:\n\n- Naptárreformot hajtott végre, bevezette a 365 napos évet, a szökőnapot, születése hónapját júliusnak nevezték el. Nem márciustól, hanem már januártól kezdik az év.\n\n- Földosztást rendelt el, amely során letelepítette veteránjait.\n\n- Gabonát osztott a városi proletároknak. A rabszolgaság háttérbe szorítása érdekében az állattenyésztő latifundiumokon a pásztorok 1/3-a szabad ember kellett, hogy legyen.\n\n- Rendezte a gazdasági ügyeket, elengedte a tartozások 25%-át, Kr. e. 48 és 47-ben pedig a földbérleti díjakat.\n\n- A tartományok kormányzására legátusokat nevezett ki. Az adóbérlők helyett ők hajtották be a jövedelmeket, számos provinciabelinek római polgárjogot adományozott.\n\n- Új, értékálló pénzt vezetett be, a denariust.\n\n- A senatus létszámát 900-ra emelte, csökkentve ezzel a testület tekintélyét. Tagjai közé a provinciákból is hívott polgárokat.\n\n- Bővítette a kereskedelemi kapcsolatokat, egységesítette a súly- és mértékrendszert.\n\n- Építkezéseket folytatott pl. Circus Maximus kibővítése\n\n- Utakat és középületeket emelt. Postát és hírszolgálatot szervezett.\n\n- Az ő nevéhez fűződik a világtörténelemben elsőként kiadott újság.\n\nCaesar - a rómaiak számára botrányos módon - semmibe vette a köztársaság intézményrendszerét. A hagyományokkal gyorsan szakított, így számos ellensége lett.\n\nKr. e. 44. március 15-én - idusán - Brutus és Cassius vezetésével az arisztokraták egy csoportja a senatus épületében meggyilkolta Caesart. (Et tu mi fili Brute - Te is fiam, Brutus.)\n\nA MÁSODIK TRIUMVIRÁTUS: Kr.e. 43.\n\nCaesar gyilkosai nem rendelkeztek kellő politikai előrelátással, hiszen tettüket megtorolták.\n\nA kezdeményezést két határozott politikus, Marcus Antonius és Octavianus ragadta meg.\n\n- Antonius: Caesar hűséges híve, anyai ágon rokona, a Kr.e. 44-ben consul. Ügyes politikával ellenőrzése alatt tudta tartani az itáliai hadsereget és maga mellé állította a népet.\n\n- Octavianus: Caesar nővérének az unokája, és Caesar fogadott fia. A Kr. e. 44-ben 19 éves. Végrendeletében Caesar őt jelölte örökösének.\n\nSzövetségük: Kr. e. 43-ban Antonius, Octavianus és Lepidus, a lovasság parancsnoka, rendezik konfliktusaikat, és Caesar gyilkosainak megbüntetésére megalapítják a 2. triumvirátusnak nevezett szövetséget.\n\n- A proscriptio módszerével leszámoltak Rómában köztársaságpárti ellenfeleikkel. (300 szenátor, köztük Cicero is, 2.000 lovag, sok polgár: a köztársaság előkelőinek színe-java veszett el a mészárlások során.)\n\n- Kr. e. 42-ben Philippinél - két csatában - legyőzték Brutus és Cassius hadseregét. Mindezek után Octavianus és Antonius felosztották maguk között a birodalmat.\n\n- Octavianus Itáliát és a nyugati provinciákat kapta,\n\n- Antonius a parthusok elleni hadműveletek irányítását és a keleti provinciákat,\n\n- Lepidus Africába távozott és hamarosan eltűnt a politikai életből. Octavianus megszilárdította helyzetét Itáliában, majd Hispániában legyőzte az ellene fellépő Sextus Pompeiust, eredményesen harcolt Illyricumban. Antonius Keleten, kezdeti kudarcai után, elfoglalta Arméniát, majd Alexandriába ment, ahol házasságot kötött Kleopátra egyiptomi királynővel.\n\nSzembefordulásuk: a két hadvezért közt egyre növekvő feszültség hamarosan háborúhoz vezetett. Octavianus azt terjesztette Antoniusról, hogy Róma érdekei ellen Egyiptom javára politizál. Octaviusnak sikerült Antoniust és Kleopátrát a „nép ellenségévé” nyilvánítani. Az ellenük küldött hadjárat döntő ütközetére Kr. e. 31-ben Actium közelében, Hellász nyugati partjainál egy tengeri csatában került sor. A csatából Kleopátra, majd Antonius is elmenekült. A magára maradt sereget Agrippa - Octavianus hadvezére - megsemmisítette.\n\nA következő évben Octavianus bevonult Alexandriába. Egyiptom, az utolsó hellenisztikus állam, római provincia lett, majd Augustus magánprovinciája.\n\nA principátus: Augustus (Kr. e. 27 .- Kr. u. 14.)\n\nOctavianus győzelmei után, Kr. e. 27-ben felvette az Augustus nevet. (Augustus = isteni, istenek által nagyra növelt férfiú)\n\nHatalomra jutása a polgárháborúk korának végét, a tartós egyeduralom kezdetét jelentette a római történelemben. A „köztársaság helyreállítója” Augustus, okulva Caesar halálából, látszólagosan a köztársaság megmentőjének tüntette fel magát. Olyan államrendszert épített ki, amelyben megmaradtak a hagyományos intézmények (senatus, magistratusok), de a tényleges politikai döntéshozatal már egy örökletes, abszolút személyi hatalom kezében volt.\n\nAugustus principátusa\n\nElőzmények: Julius Caesar hatalomra kerülése\n\nA Római Birodalomban a Kr.e. I. század polgárháborúi megmutatták, hogy a köztársaság intézményrendszere már nem alkalmas a megnövekedett birodalom igazgatására. A sikeres hódítások révén Róma világbirodalmat szerzett, de ennek irányítására és a belső társadalmi feszültségek kezelésére a köztársasági államrend már nem volt alkalmas, így a köztársaság politikai válságba került. A korszakban felértékelődött a hadsereg szerepe, az egyeduralomra törekvők a hadsereget saját politikai céljaik elérésére használták. Az i.e. I. században a köztársaság meggyengül (pl. Sulla diktatúrája, a néppárt megtörése, polgárháborúk, Spartacus-féle rabszolgafelkelés). A szenátus ellen Caesar titkos szövetséget kötött Crassusszal és Pompeiusszal i.e. 60-ban, ez volt az első triumvirátus (3 férfi szövetsége). A szövetség értelmében Caesar consul lett i.e. 59-ben, majd felosztották egymás között a hatalmat. Crassus meghal, Pompeius kibékül a szenátussal és szembekerül Caesarral, aki i.e. 48-ban Pharszalosznál legyőzi. Ezután Julius Caesar egyeduralmat alakított ki. Leszámol a köztársasággal, minden hatalom a saját kezébe került, több tisztség birtokosa, de elutasítja a királyi címet. Intézkedései népszerűek voltak, de a köztársasági hagyományokat megsértette, ezért a Brutus és Cassius által vezetett köztársaságpárti összeesküvés áldozata lett i.e. 44. március idusán (15-én).\n\nOctavianus (Augustus) hatalomra kerülése:\n\nCaesar halála után, Kr.e.44-ben újra polgárháború tört ki a Római Birodalomban. Ezért Octavianus, Caesar fogadott fia, és Antonius, Caesar egykori conzultársa, illetve Lepidus, a lovasság parancsnoka vezetésével újabb szövetség jött létre. A második triumvirátus létrejötte: i.e. 43. Octavianus, Antonius és Lepidus. Legyőzik Brutus és Cassius seregét i.e. 42-ben Philippinél. Majd felosztották egymás között a birodalmat. Lepidust lemondatják, Antonius keleten, Octavianus a birodalom nyugati részén uralkodott. I.e. 31-ben Actiumnál azonban megütköznek egymással, s a tengeri csatában Octavianus legyőzi az egyiptomi Kleopátrával szövetkező Antonius seregét, s megszerzi Egyiptomot is, ami római provincia lett, pontosabban Augustus magánprovinciája. A principátus kezdete: Kr. e. 27.\n\nA principátus – Augustus egyeduralma (i.e. 27 - i.sz. 14.)\n\nBelpolitikája:\n\nA szenátus Augustus (isteni, fenséges) névvel ruházza fel Octavianust, s a számára dicsőséget hozó hónapot is augusztusnak nevezi el. Augustus a birodalom egyeduralkodója lesz. Az egyeduralmi rendszert nem nyilvánvaló szándékkal, a diktátori tisztség fenntartásán keresztül próbálta megvalósítani, hanem burkolt formában. A köztársaság megmentőjének tartja magát, ezért a köztársaság látszatának és hagyományainak fenntartására törekszik. Még néhány évig megválasztatta magát consulnak is, Kr. e. 27-ben váratlan fordulatot hajtott végre: ünnepélyesen lemondott rendkívüli hatalmáról, és bejelentette a köztársaság helyreállítását. A senatus azonban újra felruházta a legtöbb tisztség viselésével, s azok legitimitását így már senki nem vonhatta kétségbe.\n\nI. e. 27-ben a szenátus új címmel (princeps) és több hivatallal ruházta fel, így a consulsággal is, így lett Octavianusé a proconsuli, a consuli, pontifex maximus, az imperatori és az életfogytig tartó tribunusi tisztség. Látszólag lemondott a hatalomról, s csak megtiszteltetésből fogadott el címeket. Ő lett az első polgár, azaz princeps, aki először szavazott, így létrejött a principátus rendszere. Meghagyta a köztársasági hivatalokat, de az ő irányítása alá kerültek. A köztársaság látszanának fenntartására törekedett. Octavianus a „köztársaság helyreállítójaként” jelent meg.\n\nAugustus princeps tisztsége volt a rendszerének névadója: a principátus. Többször, de nem folyamatosan viselte a consuli, néptribunusi hivatalt, és intézkedéseit – elvileg – köztársasági tisztségviselőként hajtotta végre. A tisztségeire elvileg megválasztották, ezzel kevésbé sértette meg a köztársasági hagyományokat, mint Caesar. Voltak hivatali társai is. Augustus önéletrajza propagandisztikus célokat szolgált, amellyel saját tevékenységét igazolja. Augustus nem fogadta el a dictatori címet, ezzel elhatárolódott Caesar politikájától. Ezzel jelezte a köztársasági hagyományok tiszteletét. Nem hivatali hatalom, hanem tekintély alapján uralkodott, ennek ellenére katonai diktatúrát vezetett be. Augustus együttműködött a senatussal, de censorként ő állította össze a senatus névsorát. A senatuson keresztül biztosított karrierlehetőséget a római politikusoknak. Továbbra is a senatus felügyelte az államkincstárat.\n\n• Uralmának törvényes és jogi kereteit különböző tisztségei adták: consul, censor (ő állíthatta össze a szenátus névsorát), tribunus (minden állami ügyben vétójoggal rendelkezett), pontifex maximus (rendelkezhetett a templomok kincseivel), imperator (hadsereg főparancsnoka).\n\n• Egy valami nem volt: dictator - okult Caesar hibáiból, nem akart zsarnoknak látszani.\n\n• Kr. e. 27-től ő volt a szenátus első embere (princeps senatus), innen a kialakított rendszer elnevezése: principátus. A principátus burkolt egyeduralom volt, ahol az uralkodó (caesar = császár) a köztársaság politikai intézményein keresztül gyakorolta hatalmát.\n\n• A principátus tényleges kezdetének a Kr. e. 27-et tartjuk, mert Octavianus ekkor mondott le rendkívüli triumvíri hatalmáról, és „adta át a szenátusnak és a római népnek” a hatalmat.\n\n• Ekkortól hivatalos neve: Imperator Caesar Augustus divi filius (Augustus=„fenséges”; divi filius =„az isteni fia”, azaz a Kr. e. 42-ben istenné nyilvánított Caesar fia).\n\nA hatalom névleges birtokosa a szenátus, mely Augustus híveiből állt. Tehát a szenátussal kormányzott, de első szavazatával ő irányított. Nem tagadja meg a köztársaságot, de új államformát hozott létre, a császárságot (Caesar nevéből). A győzelmét diadalmenettel ünneplő Octavianus bejelentette, hogy helyreállítja Róma békéjét, a pax Románál, majd megkezdte terve megvalósítását. Előbb a censor tisztségét vette fel, amelynek birtokában alapos tisztogatást tudott végezni a senatus soraiban. A névjegyzék élére magát állította, innen ered a rendszer elnevezése: princeps senatus, azaz a senatus első embere. A népgyűlések elvesztették jelentőségüket, a senatus pedig – bár formailag a legfőbb törvényhozó testület maradt - azáltal vált formálissá, hogy a császáré lett a törvények kezdeményezésének joga. A censori tisztség megszűnt ugyan, de a senatus névjegyzékét továbbra is Augustus állította össze. A consul és a praetor (bírói) jogköre visszaszorult. Ugyanakkor továbbra is ő maradt a hadsereg főparancsnoka, és a külügyek intézését is rábízták.\n\nTámaszai:\n\nHatalmát erősítették a csak Augustustól függő hivatalnokok és a testőrgárda (praetorianusok). Augustus megteremtette a belső rendet. Csökkentette a köztársasági hivatalok szerepét, velük párhuzamosan pedig elkezdte kiépíteni a császári intézményeket, a pénzügyek és a provinciák igazgatása területén (első császári provincia: Egyiptom). Ellenfeleit megölette, vagy megfélemlítette vagy megnyerte. Augustus igyekezett a polgárháborúban megfogyatkozott senatori rend és lovagrend létszámát és támogatását fenntartani, a fellazult erkölcsöket újból megszilárdítani. Meghagyta a szenátori rend és a lovagok gazdasági hatalmát, de politikai jogaikat korlátozta.\n\nAugustus nagy tömegben telepített le veteránokat, gondoskodott a római proletárok gabonaellátásáról, és ezzel nagyrészt felszámolta a társadalmi válságot.\n\nAugustus elve: Panem et circenses, azaz kenyeret és cirkuszt, folytatja Caesar politikáját. A politikai életbe való beleszólás helyett cirkuszi játékokkal szórakoztatta és ingyen gabonával biztosította Róma lakosságának ellátását. Hatalmát erősítette, hogy Egyiptomot magánprovinciájává tette, ahonnan a gabonát biztosítani tudta. Erkölcsi és családvédelmi törvényeket hozott (pl. büntette a részegeskedést), tűzoltóságokat szervezett, újjászervezte a bíróságokat, építkezésekbe kezdett Rómában.\n\n• Családjogi törvényei: büntette a házasságtörést, kötelezővé tette a házasságkötést, támogatta a gyermekvállalást.\n\n• Középítkezésekkel munkalehetőséget teremtett. Igyekezett a (felszabadított) rabszolgák megnövekedett társadalmi szerepét visszaszorítani, szabályozta a rabszolga-felszabadítás idejét, módját. Befejezték „Marcellus színházának” építését, újjáépítették a Circus Maximust, új fórumot építtetett (Augustus fóruma), megépült a Pantheon és Caesar temploma.\n\n• Szerette és támogatta a művészetet: barátjával, Maecenasszal sokat tett a művészek támogatásáért. Költészetben: Vergilius (Aeneis), Horatius (Ódák), Ovidius (Átváltozások).\n\nA döntő fordulatot az i. e. 23-as összeesküvés leleplezése után érte el, amikor jogkörei további szélesítését sikerült elfogadtatni a megriadt szenátorokkal, így proconsulként az egész birodalomra kiterjesztették az intézkedési hatáskörét. Külön kincstárat állítottak fel, melynek bevételei felett Octavianus rendelkezhetett. Ettől kezdve megindult a principátus hivatali szervezeteinek kiépítése. Octavianus mellett egy külön tanácsadó testület alakult, amely a birodalmi ügyek vitelében meghatározó szerepet vívott ki magának. A princeps elnyerte a törvénykezdeményezés jogát is, sőt a szenátorok listájának felülvizsgálatát is. Így a politikáját ellenző személyeket könnyen félreállíthatta. Mindehhez járult még hatalmas magánvagyona, amit Egyiptom is növelt, mivel ezt az országot saját tulajdonává nyilvánította.\n\nKülpolitikája: békére törekedett – Pax Romana.\n\nA Római Birodalom a Földközi-tenger medencéjére terjedt ki. Róma / Itália volt a birodalom központja. Tartós természetes határokat hozott létre, melyek jól védhetők voltak. A Római Birodalom senatusi, vagyis köztársasági és császári provinciákra volt osztva. A senatusi provinciák helytartóit a senatus nevezte ki. A senatusi provinciák régebbi, romanizált, békésebb provinciák voltak. A senatusi provinciák területén nem tartózkodott hadsereg. A stratégiailag fontos, a Római Birodalom határán lévő területek császári kézben voltak. Egyiptom császári magánprovincia volt, ahonnan az ingyen gabonát biztosította.\n\nKülpolitikában teljhatalmúan döntött. A „Pax Romana” jegyében célja a birodalom határainak a természetes védővonalakig való kiterjesztése, és ezen határok védelme volt. A hadsereg nagyságát a polgárháború korához képest a felére csökkentette, a légiókat a határ menti provinciákban állomásoztatta. Határfolyók: Rajna, Duna, Eufrátesz.\n\nEgyetlen nagy veresége: Kr. u. 9-ben a teutoburgi erdőben a germánok legyőztek és lemészároltak 3 római légiót. Ezután Augustus lemondott a Rajnán túli hódításról.\n\nI.e. 9-ben meghódította Pannóniát. A provinciákat két csoportra osztották, a katonailag fontosabb határ menti tartományok igazgatását a princeps kapta meg, míg a belső területeket a szenátus által kinevezett helytartók irányították. Új területeket hódított meg Közép-Európában: az Alpok és a Duna felső folyásának vidékén: Raetia és Noricum provincia. A Duna középső folyásánál: Kr. e. 12-9 között elfoglalt Pannónia provincia, a Duna alsó folyásánál: Moesia. Augustusnak fiú örököse nem volt, 76 évesen meghalt, utóda Tiberius.\n\nÖsszegzés:\n\nA principátus alkalmasabb volt a megnőtt birodalom igazgatására, mint a meggyengült köztársaság. A tartós belső béke kedvezett a gazdasági fejlődésnek is. Octavianus halálakor (i. sz. 14) fel sem merült a köztársasági formákhoz való visszatérés. . Caesar sikertelen kísérlete után tehát Augustusnak sikerült olyan államszervezetet létrehoznia, ami még több mint négy évszázadon keresztül kiszolgálta a Római Birodalmat. A szenátus az Octavianus által kijelölt utódot, az elhunyt princeps által örökbefogadott Tiberius Claudiust ruházta fel elődje összes jogaival 14-ben. A principátusnak Diocletianus császár (284-305) vetett véget, amikor bevezette a dominátus rendszerét, a nyílt egyeduralmat.\n\nÉrtékelése: néhány római szerző a következőképpen vélekedik Augustusról\n\n- Appianosz szerint a régi kormányzati rendszer megváltoztatása erőszakos úton következett be, világosan ír a fegyveres jelenlétében végrehajtott népgyűlésről és a politikai tisztogatásokról.\n\n- Tacitus a hatalom octavianusi gyakorlásának módszereit mutatja be: tisztséghalmozás, a szenátorok megvásárlása, a népnek osztott ajándékok, amivel szolgalelkűvé tette a rómaiakat. Tacitus a béke megteremtését egyértelműen Octavianushoz kapcsolja, elismeri, hogy intézkedései egyes csoportok anyagi biztonságát és gyarapodását eredményezték, s így népszerű volt.\n\n- Augustus (Octavianus), a princeps önéletírása: törvényes, a hagyományokat betartó, a nép és a szenátus által szentesített átalakulásról beszél, idealizálja az eseményeket: „a párturalomtól elnyomott államot felszabadítottam”, „egy olyan tisztséget sem fogadtam el, melyet őseink szokása ellenére ruháztak rám”. Ellentmondások: „a magam elhatározásából és a magam költségén hadsereget szerveztem”, „én egy olyan tisztséget sem fogadtam el, melyet őseink szokása ellenére ruháztak rám”. Életrajza propaganda célokat szolgált.', 136, 1, '2026-04-17 09:40:36', '2026-04-17 09:40:36');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(21, 21, 'A kereszténység története', '21.docx', '21. A kereszténység története\n\nA kereszténység története az ókorban, a középkorban és a kora újkorban (a kereszténység kialakulása, tanai, elterjedése, az egyházi hierarchia és intézményrendszer, a szerzetesség, az egyházszakadás, a nyugati és a keleti kereszténység fő jellemzői, a reformáció, az ellenreformáció, a katolikus megújulás)\n\nA kereszténység a Római Birodalomban jött létre az I. században. Előzménye: a Kr.e. I. században a köztársaság válságba került: Sulla diktatúrája, rabszolgafelkelések, egyeduralom, polgárháborúk. A zsidók a Római Birodalom fennhatósága alatt álltak, itt alakult ki a kereszténység. A kereszténység Palesztina hellenizált zsidó közösségében, felfokozott messiásváró légkörben született meg, ahol a Messiás-várás összekapcsolódott a megváltáshittel. A zsidóság már régóta várta a Megváltót (Messiás), aki megszabadítja elnyomóitól, a sok szenvedéstől. Az Ószövetség tele van ilyen utalásokkal, jövendölésekkel. A zsidók azonban egy harcos Messiást vártak, aki felszabadítja őket az idegen uralom alól. Jézus hiába teljesíti be a próféták jóslatait, mégis istenkáromlónak tartják, mert Isten fiának nevezi magát, ezért keresztre feszítik. Jézus tanítása eltért a zsidók tanításaitól pl. a szemet szemért elv (talió-elv) helyett a megbocsátás és a szeretet parancsát hirdeti.\n\nA zsidóságon belüli vallási csoportok közül az esszénusok: a társadalomtól és a politikától teljesen elfordultak, Messiás-váró szerzetesi közösséget alkottak. A kereszténység gyökereit az esszénusok gondolatvilágában lehet keresni.\n\nA Megváltó közeli eljövetelét hirdette Keresztelő Szent János. Augustus principátusa alatt született Jézus Krisztus Betlehemben. Názáreti Jézus már a megváltást hirdette.\n\nA keresztény vallás tanai\n\nA kereszténység a Kr.u. I. században keletkezett, Jézus születése időszámításunk kezdete. Jeruzsálemből indult ki, amely Palesztinában található, ami ekkor a Római Birodalom fennhatósága alá tartozott. Innen terjedt tovább Európába Pál apostol segítségével. Későbbi központjai: a pápák központja Róma, a keleti egyház központja Konstantinápoly.\n\nSzent könyve a Biblia – nemcsak az Ószövetség, hanem az Újszövetség is. Isteni kinyilatkoztatások jelennek meg benne pl. prófétákon keresztül. Az Újszövetséget Jézus tanítványai, az apostolok írták görög, illetve latin nyelven terjedt.\n\nHittétele: szeretet Isten és az embertársak iránt. Hisz az üdvözülésben, alaptétele a megbocsátás és a bűnbocsánat. isten előtt mindenki egyenlő. Gyámolítja a szegényeket, támogatja a böjtöt. Jézus tanítása épít a zsidó törvényekre és az ószövetségi prófétákra. Jézus tulajdonképpen beteljesíti az ószövetségi próféták jóslatait. Jézust a keresztények a megjövendölt Messiásnak, Megváltónak tartják. Jézus nem prófétának, hanem Isten fiának tartotta magát. Emiatt a zsidók keresztre feszítik, hiszen istenkáromlónak tartják. Jézus feltámad a halálból\n\nMonoteista vallás a kereszténység, amely a zsidó-izraelita vallást tekintette előzményének.\n\nMisszióra: a hit terjesztésére törekszik a későbbiekben, de terjesztését üldözik, és csak a 4. századtól kap állami támogatottságot. Kezdetben 5 nagy egyházi központ alakult ki: Antiochia, Alexandria, Jeruzsálem, Róma, Konstantinápoly. Az első három arab befolyás alá fog kerülni, az utolsó kettő között pedig egyházszakadás jön létre 1054-ben az eltérő fejlődés miatt. A római pápa függetleníteni tudta magát a világi uralkodók befolyásától.\n\nA keresztények hite szerint a zsidóság által várt megváltó Krisztus személyében érkezett el a földre, aki kereszthalálával nemcsak a zsidókat, de az egész emberiséget megváltotta, tehát feloldozta őket az eredendő bűn alól, s megnyitotta számukra a mennyország kapuit. A keresztények tehát abban hisznek, hogy Isten új szövetséget kötött az emberiséggel, amelynek megpecsételéseként fiát küldte a földre, hogy megtanítsa az embereket az egyetemes szeretet parancsára, s hogy elhozza számukra a megváltást. A kereszténység fontos erkölcsi iránymutatását képezi az Ótestamentumból ismert tízparancsolat is, amelyet Mózes kapott Istentől az első szövetségkötés alkalmával.\n\nJézus élete és működése\n\n• Jézus Krisztus történelmi személy volt. Születési ideje bizonytalan (Kr. e. 8-4 között).\n\n• Gyermekkorát Galilea tartomány Názáret nevű városában töltötte.\n\n• 30 éves kora körül kezdte meg működését.\n\n• 33 éves korában Judea helytartója, Pontius Pilátus, a zsidó főpapság kérésére keresztre feszíttette. A zsidók istenkáromlónak tekintik, hiszen Isten fiának vallja magát. A zsidók egy harcos Messiást vártak, aki felszabadítja őket az idegen uralom alól.\n\n• Krisztus = Khriszthosz [görög] = Messiás [héber]=fölkent; Jézus= Jahve a segítség.\n\n• Keresztény lett az, aki hitt abban, hogy Jézus az Istentől megígért Megváltó, és\n\nmegtartotta parancsait:\n\n• egyetemes szeretet: Istent és a felebarátokat; megbocsátás; tevékeny szeretet;\n\n• a menny, Isten országa az elérendő cél; a belső tisztaság a legfőbb erény.\n\n• Jézus elítélte a vagyonszerzést, a kapzsiságot, a gyűlöletet, az erőszakot; életével pedig minderre példát mutatott. A halálát követő harmadik napon feltámadt, megjelent tanítványai előtt és megígérte, hogy a világ végén másodszor is eljön, és ítéletet tart az emberiség felett. Példázatokban tanított pl. a tékozló fiú – a megbocsátásról szól.\n\nA vallás fontos elveit Jézus tanításaiból, köztük a Hegyi beszédből ismerhetjük:\n\nA felebarátok szeretetéről: „Hallottátok, hogy megmondatott: Szeresd felebarátodat és gyűlöld ellenségedet. Én pedig azt mondom nektek: szeressétek ellenségeiteket, áldjátok azokat, a kik titeket átkoznak...” Máté 5, 43-44.\n\nMások megítéléséről: „Ne ítéljetek, hogy ne ítéltessetek.” Máté 7, 1.\n\nA megbocsátásról: „Ha pedig meg nem bocsátjátok az embereknek az ő vétkeiket, a ti mennyei Atyátok sem bocsátja meg a ti vétkeiteket.” Máté 6, 15.\n\n„Boldogok az irgalmasok: mert ők irgalmasságot nyernek\" (a nyolc boldogság). Máté 5, 7.\n\nAz Isten országáról: „Menjetek be a szoros kapun. Mert tágas az a kapu és széles az az út, a mely a veszedelemre visz, és sokan vannak, a kik azon járnak. Mert szoros az a kapu és keskeny az az út, a mely az életre visz, és kevesen vannak, a kik megtalálják azt.” Máté 7,13. (Károli G. fordítása)\n\nJézus cselekedeteinek és a kereszténység tanainak leírása a bibliai Újszövetségbe található.\n\nRészei:\n\n• A 4 evangélium (evangélium = jó hír, örömhír: megszületett a Megváltó). Jézus megjelenéséről, működéséről és tanításáról szólnak;\n\n- Máté, Márk, Lukács evangéliuma párhuzamos eseményekből építkezik, hasonlóan írnak Jézusról (szinoptikusok: együttlátók);\n\n- János evangéliuma mélyebb teológiai értelmezést ad Jézus tanításáról. Inkább isteni eredetét hangsúlyozza.\n\n• Apostolok cselekedetei (apostol = küldött) két központi alak - Péter és Pál - életén keresztül mutatja be, hogyan jött létre az ősegyház.\n\n• Apostoli levelek: az apostolok egy-egy keresztény közösséghez írott, tanító levelei.\n\n• János jelenései: az utolsó ítélettel kapcsolatos látomások leírása (apokalipszis).\n\nA kereszténység terjedése\n\n• Krisztus Tiberius császár idején halt meg, tanítványaiból alakult ki Jeruzsálemben az első kis keresztény közösség, Péter (Petrus =„kőszikla”) vezetésével.\n\n• 48-ban Jeruzsálemben az apostolok és a presbiterek tanácskozásán (zsinat) a pogány, nem zsidó keresztényeket is elismerték az egyház teljes jogú tagjának.\n\n• A zsidóságtól való eltávolodás nyomán a kereszténység egybeolvadt a görög-római kultúrával (nyelv, filozófia).\n\nJézus halála után a követőinek szembe kellett nézni a zsidó vallási közösség ellenállásával, miután Jézus tanai több ponton nem voltak összeegyeztethetőek a zsidó vallással (pl. Jézus Isten fia).\n\n• A kereszténység terjedésének, a térítésnek kiemelkedő alakja Pál apostol volt.\n\n• Eredeti neve Saul, aki a kis-ázsiai Tarsis városában született római polgárként - szülei farizeus nevelésben részesítették.\n\n• Kezdetben szemben állt a kereszténységgel, üldözte őket, ám a Damaszkusz felé vezető úton megjelent előtte Jézus és Pál megtért (pálfordulás).\n\n• Pál lett a pogányok apostola — térítő útjai 45-61 között - nyomán Cipruson, Kis-Ázsiában, Egyiptomban, Szíriában sorra jöttek létre a keresztény közösségek. Levelezése pl. Rómába, Thesszalonikibe, Epheszoszba, Korinthoszba.\n\n• Pál tevékenységének is köszönhetően a kereszténység megbékélt az állammal, a társadalmi különbségekkel (az embernek nem kell a sorsa ellen lázadni).\n\nA kereszténység terjedése a II. században gyorsult fel: a I. század végén kb. 10 000, a II. sz. végén kb. 100 000, a III. sz. végén már kb. 2 millió keresztény élt a Római Birodalomban.\n\nAz egyház kialakulása\n\n• Az első keresztény közösségek az I. században összejöveteleiket éjszaka tartották, közös étkezéssel, imádsággal, énekléssel. Nem voltak kötött szertartásaik, papjaik, tisztségviselőik. Nem gyűjtöttek vagyont. Templomaik, temetkezési helyeik a földalatti katakombák voltak. Minden keresztény vagyonának és jövedelmének egy részét a közös kasszába adta, ebből segélyezték a nélkülözőket. Összejöveteleiket rendszerint vasárnap tartották: imádkoztak, a Bibliát magyarázták, zsoltárokat énekeltek, úrvacsorán, áldozáson vettek részt.\n\n• A közeljövőben várt végítélet elmaradásának Pál apostol által megfogalmazott gondolata ezeket a kis közösségeket megváltoztatta.\n\nKialakultak az állandó tisztségek:\n\n• Episzkoposz (püspök): eredetileg a közösség pénzügyeit intézte, később a hitéletet, szertartásokat irányító személlyé vált - minden városi közösség élén egy-egy püspök állt.\n\n• Diakónosz (szolga): eredetileg a szegényeknek rendezett szeretetlakomák (agapé) felszolgálói voltak, majd a papok segítői lettek.\n\n• Presbiter (idősebb): a közösség idősebb, tekintélyesebb tagjai, akikből kialakult a papság (klérus), amely fokozatosan elkülönült a világiaktól (laikusok).\n\n• A gyülekezetek közös étkezései is átalakultak: az együtt töltött idő (mise) szertartásrendjében, a liturgiában már csak Krisztus utolsó vacsorájának emlékét idéző momentumok (bor, kenyér) maradtak meg.\n\nÜldözések:\n\n• A principátus idején többször is sor került keresztényüldözésre:\n\n- Néró császár: Szekta jellegük miatt sok rémhír terjedt a keresztényekről, ezért Néró Róma égéséért bűnbakot teremthetett belőlük (ekkor végezték ki nyilvánosan Pétert és Pált is).\n\n- 250 után több császár a belső válság kezelése során kemény rendteremtő módszereket alkalmazott, ami a keresztények tömeges üldözésére is kiterjedt (igaz, hogy Gallienus császár 260-as türelmi rendelete ellenkező példát is nyújt).\n\n- A legsúlyosabb üldözés Diocletianus császár idején történt, aki 303-ban törvényileg fosztotta meg a keresztényeket szabadságuktól és szavazati joguktól, templomaikat lerombolták. Az üldözés oka: a császárkultusz megtagadása. A IV. század elejéig a Birodalomban még üldözték a keresztényeket. Az üldözés jellegzetessége: a polgárjog elvesztése, kínzások, vértanúság. Ennek ellenére a keresztények száma folyamatosan növekedett. Amphiteátrumokban vadállatok elé vetik őket: hitükért halnak meg és Jézusért, ezért keresztény vértanúknak nevezik őket, akik mártírhalált haltak.\n\n• Az üldözésnek Nagy Constantin (313-337) császár vetett véget: 313-ban kiadta a milánói ediktumot, amely vallásszabadságot biztosított a birodalom lakosságának. A császár álláspontjának megváltozásában politikai, illetve személyes indokok is szerepet játszhattak.\n\n- Keresztény bazilikák és templomok építését kezdeményezte.\n\n- 325-ben a kis-ázsiai Niceában - 318 püspök részvételével egyetemes zsinatot hívott össze (első ökumenikus zsinat), itt egységesítik a hitelveket. Mivel ekkor még nem volt keresztény, pontifex maximusként elnökölt a gyűlésen. Elfogadták a Szentháromság tanát, amelyet az evangélium és Szent Pál tanítása alapján Athanasius püspök képviselt (Jézus maga is isteni személy - azaz az egy isteni lényeg 3 önálló létezőben nyilvánul meg: Atya, Fiú, Szentlélek = homousion). Az egységes tanítás és kiépülő hierarchikus szervezet segíti az egyház birodalomszintű kiterjedését.\n\n- A zsinat elvetette az Arius püspök által képviselt nézetet, amely szerint Jézus Krisztus nem egy-lényegű csak hasonló lényegű az Atyával (= homoiusion). Az ariánus tanokat vallókat eretneknek (kiváltak) nevezték. Megfogalmazták a Hitvallást (Credo).\n\n- Constantin császárt a „külső ügyek” püspöke címmel ruházták fel, amely neki és utódjainak jogalapot biztosított az egyházi ügyekbe való beavatkozásra.\n\n• Az egységes Római Birodalom utolsó császára, Nagy Theodosius 391-ben államvallássá tette a kereszténységet, és ezzel párhuzamosan betiltotta a régi római istenek tiszteletét és a pogány kultuszokat (pl. az olümpiai sportversenyeket; az eretnekek üldözését is kimondta).\n\nKimondta továbbá, hogy csak egy igaz katolikus vallás (una vera catholica fides) létezik.\n\nA kereszténység a IV. századra a Római Birodalom egész területén elterjedt.\n\nAz elkövetkező évszázadokban több ökumenikus zsinatot is tartottak, ezeken tovább folytatódott a hittételek tisztázása.\n\nA pápaság létrejötte\n\nA Római Birodalomban a kereszténység államvallássá válása után az egyház felett a császárok hatalma érvényesült. Vezető egyházi szerepe lett öt nagyvárosnak (metropolisznak), ahol a patriarchák (az egyházmegyei székvárosok püspökei) székeltek, ezek Róma, Jeruzsálem, Antióchia, Alexandria és Konstantinápoly voltak. A Nyugat-római Birodalom 476-os bukása után Konstantinápoly vált a hit központjává („a második Rómává”), de Európa új barbár államainak keresztény hitre térése után Róma, mint a latin rítusú keresztény világ egyedüli központja nyerte vissza jelentőségét. A keleti kereszténység területén több patriarchátus is kialakult, ám a vezető szerepet Konstantinápoly, 1453-as bukása után pedig Moszkva („a harmadik Róma”) vette át (s viseli a mai napig).\n\n395-ben a birodalmat kettéválasztotta Theodosius császár Nyugatrómai és Keletrómai Birodalomra. A nyugati részen a barbár támadások egyre gyakoribbak voltak, keleten a helyzet változatlan maradt, a Konstantinápolyban székelő császárok fennhatósága töretlenül fennállt az egyház felett. Nyugaton azonban a birodalom szétesésével eltűnt az egyházat uraló világi hatalom, s Róma püspökei idővel a keleti császároktól is függetlenítették magukat.\n\nAz eltávolodás következtében különbségek alakultak ki a birodalom két részének kereszténysége között. Míg a nyugati egyház nyelve a latin maradt, a göröggé váló keleten a görög lett a papság nyelve. A szertartások is egyre inkább eltérővé váltak a két területen.\n\nRóma helyzetét jelentősen javította, hogy a keleti központok közül Alexandriai, Jeruzsálemet és Antiochiát a VII. században elfoglalták az arabok. Ugyanakkor az V-X. században Róma eredményes térítő munkája nyomán a latin kereszténység hódított tért Európában a germánok, majd a dánok, a csehek, a lengyelek és a magyarok között.\n\nA pápák székhelye, Róma a gót állam összeomlása után, a sok pusztítás ellenére is fennmaradt. A nyugati egyház térnyerését eredményező folyamatok megindítója a kiemelkedő képességű Nagy Szent Gergely (590-604) pápa (pápa = atya) volt. A pápa a római püspökök különleges tekintélyének kifejezője lett. Szent Gergely rendbe hozatta az egyházi birtokokat, lazított a Konstantinápolyhoz fűződő szálakon, s támogatta a pogányok közötti térítő munkát, pártolva és igénybe véve a szerzetesek tevékenységét.\n\nAz új germán hódítók, a longobárdok azonban veszélyeztették az „Örök Várost”, s útjában álltak a pápaság megerősödésének. Ezért Róma a nyugati katolikus (= egyetemes, általános) keresztény hitre tért frankoktól kért segítséget. II. István pápa Martell Károly fiához, Kis Pippinhez fordult, aki cserében királyi hatalmának szentesítését kérte (751). A frankok, átkelve az Alpokon, visszaszorították a longobárdok hatalmát (754). Az új Karoling-király a longobárdoktól megszerzett területek jelentős részét, Róma és Ravenna vidékét a pápáknak adományozta (756). Ezen a területen az egyházfők - mint világi uralkodók - gyakorolhatták hatalmukat. Ezzel létrejött a Pápai Állam, ami Róma tekintélyét nagyban növelte. III. Leó pápa a Frank Birodalom uralkodóját, Nagy Károlyt 800. december 25-én császárrá koronázta Rómában, ezzel a pápaság végérvényesen nyugat felé fordult, így nemcsak liturgiájában, de a világi hatalomhoz való viszonyában is jól elkülönült a keleti egyháztól.\n\nAz egyházszakadás (skizma): 1054-ben\n\nA pápák megerősödése tovább élezte a helyzetet Konstantinápollyal, ami 1054-ben a keresztény egyház kettészakadásához vezetett. A pápa és a konstantinápolyi pátriárka kölcsönösen kiátkozta egymást. Létrejött a nyugati, latin nyelvű római katolikus és a keleti, görög nyelvű ortodox (hithű, igazhitű, óhitű) egyház.\n\nA római katolikus egyház hierarchiája: pápa, bíborosok, érsekek, püspökök, kanonokok, plébánosok\n\nA keleti és a nyugati egyház közötti különbség:\n\na nyugati és keleti kereszténység 1054-ben vált el egymástól, központjaik Róma, ill. Konstantinápoly vagy Bizánc.\n\na bizánci császár az egyház tekintélyének megerősítésére törekszik, és a hittételek védelmét ígéri. keleten a császári hatalom befolyása alá került az egyház. a keleti, azaz ortodox egyház feje (eredetileg) a konstantinápolyi pátriárka. a pátriárkák egyenrangúak. keleten a görög volt az egyház nyelve. a volt Kelet-római Birodalom területe tartozik az egyházhoz. csak korlátozottan van cölibátus keleten, eltérőek a templomépítési sajátosságok is. térítést folytatnak Dél- és Kelet-Európában. bevezetik a bolgár nyelvet az egyházban. a bolgár egyház azonban önállósodási igénnyel lép fel. megszerzik a pátriárkai rangot. a bolgár uralkodó jelentős szerepet tölt be ebben a folyamatban. önálló, autokefál nemzeti egyházak jöttek létre keleten, pl. bolgár pátriárka. az egyházi vagyon szerepe keleten kisebb, a két egyház között kulturális határvonal húzódott. Nincs purgatórium szerintük. Két szín alatt áldoznak (kenyér és bor). Térítő tevékenységet folytatott: Cirill és Metód.\n\na nyugati, katolikus egyház feje a római pápa. nyugaton a latin az egyház nyelve. a volt Nyugat-római Birodalom területe tartozik az egyházhoz. sikeres térítést folytatnak Észak- és Közép-Európában. nyugaton egységes maradt és egységesült az egyházszervezet. az egyház függetlenedni próbált a világi hatalomtól. a nyugati szerzetességnek nagyobb szerepe volt a technikai, kulturális fejlődésben.\n\nA KORA KÖZÉPKORI EGYHÁZ HITTÉRÍTŐ TEVÉKENYSÉGE\n\nA keresztény egyház megerősödését elősegítette, hogy a kereszténység a Kr.u.4. század végén államvallássá vált a Római Birodalom területén. Theosodius császár ugyanis 391-ben államvallássá tette. A kora középkorban gyorsan terjedt a kereszténység. Kialakult az egyházszervezet.\n\nEurópa kereszténnyé válásában a frank, ír és angolszász térítők játszottak kiemelkedő szerepet. A germán, szláv és magyar területeken a térítés során kolostorokat és püspökségeket alapítottak. A térítés során sokan vértanúhalált szenvedtek.\n\nA nyugati keresztény egyház felépítése: gyülekezet – egyházmegye – egyháztartomány – egyetemes egyház. Élén: plébános – püspök – érsek – pápa. Tehát hierarchikus felépítésű. Vezetője a római pápa.\n\nKülönleges tekintélyre tett szert Róma püspöke, a pápa, amely Szent Péter utóda.\n\nA pápa fölött csakis Isten áll, a világi hatalom nem vonta a befolyása alá, mint a konstantinápolyi egyházi vezetőt.\n\nA Pápai Állam 756-os létrejöttében jelentős szerepe volt a frank uralkodónak, Kis Pippinnek. A pápa cserében elismerte a Karolingok frank uralmát. 800-ban Rómában császárrá koronázta Nagy Károlyt, a Frank Birodalom uralkodóját. A Frank Birodalom Nyugat-Európában helyezkedett el.\n\nNagy Károly a törvényeivel is védte az egyházat, és támogatta a kereszténység elterjesztését. Törvényeiben bünteti a pogány szokásokat, kötelezővé teszi a kereszténység felvételét. Az uralkodó és az egyház egymás támaszai voltak. Központja Aachen volt, uralkodásának időszakát Karoling-reneszánsznak nevezzük. Az uralkodó tanácsadói általában egyházi személyek voltak. A királyi adminisztráció tagjai a klérusból (papságból) kerültek ki. Jellemzően latin nyelvű egyházi írásbeliség volt.\n\nA térítő tevékenységben szerzetesek is részt vettek. Az első európai szerzetesrend 529-től a bencés rend volt, amely Monte Cassinoban jött létre. Szent Benedek hozta létre. Regulája szerint a szerzeteseknek nem lehetett tulajdonuk, naponta rendszeresen imádkozniuk és dolgozniuk kellett: „Ora et labora!” Fogadalmat kellett tenniük: szegénységi, tisztasági (lelki), engedelmességi. A szerzetesek kolostorokban /apátságokban éltek.\n\nAz apátságok közvetlenül a pápa irányítása alatt álltak. Eleinte román stílusban épültek, tekintélyes méretűek, háromhajós felépítésűek. A kolostor lakóinak életmódjára utalnak az épületek: a templomot kerengő, cellák és gazdasági épületek egészítették ki.\n\nA szerzetesek tevékenysége: mezőgazdasági munka, imádkozás (napi 7x), kódexmásolás. Jelentős szerepük volt a kereszténység elterjesztésében. A kódexek másolásával az ókor kulturális kincseit mentették át, de főleg szent iratokat másoltak. Latin nyelvű írásbeliség volt jellemző.\n\nCluny reformok: a Cluny kolostor a klérus (papság) belső megtisztulásáért indított mozgalmat pl. cölibátus bevezetése.\n\nA szerzetesek:\n\nA szerzetesek kezdetben magányos remetékként éltek, majd keleten, elsőként Egyiptomban jöttek létre szerzetesi közösségek. Szigorú belső előírások szabályozták életüket, s elsősorban a hit elvont kérdéseinek tanulmányozásával foglalkoztak.\n\nNyugaton a szerzetesség gyakorlatiasabb formája terjedt el. Bár a szerzetesi élet célja az istenhez leginkább méltó élet, amelyet pontos szabályok szerint élő közösségekben véltek megvalósíthatónak (a szerzetesek szüzességi, szegénységi és engedelmességi fogadalmat tettek), az itteni kolostorok lakói a hitéleten kívül földet műveltek, könyveket másoltak, hozzájárulva az antik műveltség és elsősorban a latin írásbeliség átmentéséhez. A kora középkorban jelentős részt vállaltak a térítő munkából, s nagyrészt nekik köszönhető, hogy Közép-Európa a latin kereszténységhez csatlakozott.\n\nA kereszténység nyugat-európai térhódításában egyaránt jelentős szerepet játszottak a kontinens északnyugati peremvidékén élő írek Szent Patrick (385-461) tevékenysége nyomán. Az ír kereszténység kolostorok rendszerén alapult.\n\nA szerzetesrendek közül a Nursiai Szent Benedek (480-543) által alapított rend volt az első, amely elfogadta a pápa vezető szerepét. Monte Cassinóban jött létre első kolostoruk Itáliában 529-ben, de a kora középkor folyamán a bencések rendházai behálózták az egész nyugati keresztény világot. A X. században Cluny bencés kolostorából belső megújulás, megtisztulás folyamata indult el.\n\nA legjelentősebb közösséget tehát 529-ben Nursiai Szent Benedek hozta létre Monte Cassino magaslatán (Bencés rend).\n\n• 73 fejezetből álló, igen szigorú és a kolostori életet részletesen szabályozó regulát készített.\n\n• A szerzetesi élet színtere a kolostor, amit a szerzetes nem hagyhatott el.\n\n• A szerzetesnek nem lehetett magántulajdona (de a kolostornak lehetett).\n\n• A szerzetesi élet vezérelve: Ora et labora - imádkozzál és dolgozzál!\n\n• Napközben 7 közös ima + éjszakai imaóra.\n\n• A munka részben szellemi (a Szentírás és más könyvek olvasása és másolása, részben fizikai (pl. földművelés) volt.\n\n• Napi két közös, hústalan étkezés.\n\n• A szerzetessé válás útja: egy évig jelölt (novícius) volt, majd szerzetessé avatáskor le kellett tennie a hármas (szegénységi, tisztasági, engedelmességi) fogadalmat.\n\n• A rend, illetve a kolostor élén az apát állt, akit a közösség választott, és akinek engedelmességgel tartoztak; az apát helyettese a perjel.\n\nA X. században a burgundiai Cluny bencés kolostorból elindult a reformmozgalom:\n\n• visszatértek az eredeti, szigorú bencés regulához;\n\n• visszautasították a világi befolyást;\n\n• a kolostort a helyi püspök joghatósága alól kivéve a pápa védelme alá helyezték.\n\n• A reform sikeres volt, Clunyhoz több mint ezer bencés kolostor csatlakozott, létrejött az ún. Cluny Kongregáció, amelynek vezetője a cluny apát lett. Ebből a reformból nőtt ki a XI. században az egész egyház reformja (gregorián reform - VII. Gergely).\n\nA nyugati kereszténység során kísérlet történt a pápaság alárendelésére: a német-római császár (IV. Henrik) megpróbálja hatalmát kiterjeszteni az egyházra, és a püspökök beitatásának jogát (invesztitúrajog) követeli. VII. Gergely pápasága (1073-85) alatt, 1075-től kezdődtek az invesztitúraharcok, a pápaság és a német-római császárság között. VII. Gergely a pápát a császár fölé emeli (Dictatus Papae). A X-XI. századra megerősödik az egyház. A pápaság kerül ki győztesen a háborúból.\n\nÚj szerzetesrendek a XI. század végétől:\n\nA X. században induló clunyi reformmozgalom jegyében a XI-XIII. század folyamán új szerzetesrendek jöttek létre pl. ciszterci, karthausi, premontrei. A XI. és XII. században a ciszterciek a mezőgazdasági módszerek fejlesztésében vettek részt. A szerzetesrendek fontos szerepet játszottak az írásbeliségben és az oktatásban. A szerzetesrendek jelentős szerepet játszottak a gazdasági és a kulturális életben.\n\nA cluny reform után is voltak olyanok, akik a bencés kolostorokat túl gazdagnak, templomaikat túl fényűzőnek tartották: ezek nem keltették az evangéliumi szegénység látszatát sem. Ezért több kísérlet is történt az eredeti bencés regula szerinti szerzetesség visszaállítására.\n\n• Kölni Szent Brúnó reimsi kanonok alapította a karthauziak rendjét (1084):\n\nszemlélődő remete rend; tagjai csaknem állandó hallgatást fogadtak.\n\n• Szent Róbert Citeaux-ban (latinul Cistercium) megalapította a ciszterci szerzetesrend anyakolostorát (1098). Igazi felvirágzása akkor kezdődött, amikor Szent Bernát 1115-ben Clairvaux-ban ciszterci kolostort alapított — ő lett korának egyik legbefolyásosabb egyházi személyisége. Igen nagy hangsúlyt fektettek a munkálkodásra, a rendnek komoly szerepe volt a korszerű mezőgazdasági módszerek elterjesztésében.\n\n• A korban gyorsan terjedtek az ágostonos rendek, amelyek szabályzatukat Szent Ágoston gondolatai alapján dolgozták ki. Két csoportjuk volt:\n\n• Szabályozott kanonokok rendje: ezek közösségben élő világi papok voltak, akik lelkipásztorkodással foglalkoztak. A legismertebb ilyen rend a Szent Norbert által 1121-ben alapított premontreiek kongregációja volt. Fő feladatának ez a rend a prédikálást és a lelkipásztorkodást tartotta.\n\n• Ágostonos remeték rendje: ide tartozik, pl. az egyetlen magyar alapítású rend, a Remete Szt. Pálról elnevezett pálos rend. Özséb esztergomi kanonok szervezte közösséggé 1250 körül a Pilisben élő remetéket.\n\n• Sok betegápoló (pl. Lázár-rend) és rabkiváltó (pl. trinbitárius rend) közösség is szerveződött.\n\nA szerzetesrendek behálózták az egész katolikus világot. Jelentős szerepet játszottak a katolikus hit terjesztésében (bencések), vagy a fejlettebb gazdálkodási eljárások meghonosításában (ciszterciek).\n\nA XIII. században a koldulórendek – ferencesek, domonkosok – a városokban telepedtek meg, tevékenységüket a tömegek körében fejtették ki.\n\nA koldulórendek\n\nKialakulásuk okai: • A szerzeteseknek nem lehetett magánvagyonuk, de a kolostoroknak igen - a kolostori vagyonok pedig egyre gyarapodtak az újonnan alapított rendeknél is.\n\n• Felgyorsult az urbanizáció, egyre többen laktak városokban, őket az erdőben, távoli tájakon élő ciszterciek, premontreiek nem tudták megszólítani.\n\n• A XII. században Nyugat-Európában kibontakozott a szegénységi mozgalom, amely az őskeresztények szegény egyházához való visszatérését hirdette - számos eretnekmozgalom (albigensek, valdensek) terjedt el rövid idő alatt.\n\n• Az egyház a szegénységi (eretnek) mozgalmakra adott első kemény válasz (eretneküldözés - inkvizíció) után támogatni kezdte a koldulórendek kialakulását. III. Ince pápa hozza létre az inkvizíciót, ahol bíróság elé állítják az eretnekeket.\n\nA kolduló rendeknek nem lehetett vagyona, földbirtoka, rendszeres jövedelme - magukat koldulásból kellett fenntartaniuk.\n\n• A koldulórendek: élén a generális állt; fő törvényhozó szerve a generális káptalan volt;\n\nLegfőbb rendek: ferencesek, domonkosok, karmeliták, szerviták.\n\n• Ferencesek vagy Kisebb Testvérek Rendje: 1223\n\n- Assisi Szt. Ferenc alapította, III. Ince pápa 1209-ben szóban jóváhagyta működését, majd 1223-ban elfogadta írott szabályzatát.\n\n- A rend bekapcsolódott az egyetemi oktatásba.\n\n- Hosszú viták után 1517-ben kettévált a rend: a szegénységet Szt. Ferenc szellemében értelmezőkre (obszervánsok), illetve a gyakorlati élet követelményeihez jobban alkalmazkodókra (konventuálisok vagy minoriták). 1525-ben egy harmadik irányzat is önállósult, a kapucinusok.\n\n• Domonkosok vagy Prédikáló Testvérek Rendje: 1216\n\nA rendet egy, a kathar eretnekekkel küzdő kasztíliai pap, Guzman Domonkos alapította.\n\nAz első rendház Toulouse-ban volt. III. Ince pápa 1216-ban hagyta jóvá a szabályzatát.\n\nA rend komoly szerepet játszott az egyetemi teológia - oktatásban pl. Aquinói Szt. Tamás skolasztikája, amely a hitet a tudománnyal egyeztette össze, mindent alárendelt a vallásnak.\n\nA domonkosok voltak az inkvizíció (egyházi bíróság) működtetői is. Nem számított számukra a vagyon, így nem voltak megvesztegethetők.\n\nA reformáció és a katolikus megújulás Európában és Magyarországon\n\nI. A reformáció előzményei, okai:\n\nA XVI. századi Német-római Császárságot anarchia, a fejedelmek hatalmaskodásai s társadalmi feszültségek jellemezték. Ehhez járult még az egyház tekintélyének romlása, mely az egyházzal szembeni elégedetlenséghez vezetett. X. Leó pápa a büntetéstől való feloldozást búcsúcédulák árusításával szorgalmazta. Hatalmas vagyon halmozódott már fel eddig is az egyház kezében, birtokokkal, kiváltságokkal rendelkezett. Korábban, 1415-ben már Husz János is az egyház megreformálását hirdette, de akkor elbukott ez a kezdeményezés.\n\nII. A lutheri reformáció – az ágostai evangélikus vallás létrejötte\n\n1517. október 31-én Luther Márton Ágoston-rendi szerzetes 95 pontból álló tételeit kitűzi a wittenbergi templom kapujára.\n\nTézisei: 1. Elítéli az egyház üzérkedéseit - egyedül csak Isten bocsáthatja meg bűneinket, s az pénzért nem váltható meg. 2. Csak a hit által üdvözülhetünk. 3. Az ember és Isten között nincs szükség közvetítőre (gyónás eltörlése). 4. A szerzetesrendek megszüntetése. 5. Az egyházi birtokok világi kézbe adása (szekularizálása). 6. Meg kell szüntetni a pápai hatalmat. 7. Egyszerűbb szertartások. 8. Anyanyelvű istentisztelet. 9. Két szín alatti áldozás (kenyér, bor)\n\nTámogatói: Luther elvei minden társadalmi rétegre hatottak, főleg a nemességre, hiszen részesülni akartak az egyházi vagyonból is. A protestáns fejedelmek, köznemesek, az alsópapság, a polgárság egy része és a gazdagparasztság támogatta. Közép- és Észak – Európában terjedtek el tanai. A lutheri reformáció szellemében működött Philip Melanchton.\n\nKövetkezmények: a pápa kiátkozza ezért Luthert, s 1521-ben V. Károly a wormsi birodalmi gyűlésen birodalmi átokkal sújtja, mint eretneket.\n\nBölcs Frigyes Wartburg várában menedéket ad neki, ahol Luther lefordítja németre a Bibliát. 1529-ben a speyeri birodalmi gyűlés kimondja, Luther hívei megmaradhatnak vallásukban, de hitüket nem terjeszthetik. Ez ellen protestálni (tiltakozni) fognak.\n\n1530-ban az augsburgi gyűlésen a protestáns tanok beterjesztése történik meg, létrejön az evangélikus hitvallás. Mivel Luther Ágoston-rendi szerzetes volt korábban, innen az elnevezés: ágostai evangélikus hitvallás. A vallási harcok azonban továbbra is folytak.\n\n1555. augsburgi vallásbéke jön létre a katolikusok és a protestánsok között. A lutheránusok megtarthatták a katolikusoktól elfoglalt egyházi javakat és kimondták az alábbi elvet: Cuius regio, eius religio. Azaz „Akié a föld, azé a vallás!” Ez azt jelenti, hogy amilyen vallás híve egy-egy tartomány fejedelme, olyan vallást kell követnie az alattvalóinak is. Ha nem teszik, elköltözhetnek.\n\nIII. A svájci reformáció – képviselői: Kálvin János és Ulrich Zwingli\n\nAz 1530-as években bontakozik ki a reformáció svájci (helvét) irányzata, az úgynevezett polgári irányzat, ugyanis főleg a polgárság körében talál követőkre Európában. A vallás követőit reformátusoknak is hívjuk. Kálvin műve A keresztény vallás tanítása, ebben fejti ki elveit: Isten korlátlan úr; az uralkodó hatalma isteni eredetű, de nem zsarnokoskodhat; az eleve elrendelés, azaz a predestináció híve (az embernek még születése előtt eldönti a gondviselés a sorsát). Az egyszerű istentiszteletet szorgalmazza (a freskókat bemeszelik, a szobrokat eltávolítják). Köztársasági elveket vall az egyház felépítésével kapcsolatban (presbiterium: nemcsak egyházi személyek irányítják az ügyeket). Svájcban, Genfben dolgozzák ki és valósítják meg először. A svájci polgárság és a fejlett európai térségek polgársága körében terjedt el, s népszerűbb lett, mint a lutheri vallás. Svájc, Franciaország, Skócia, Németalföld és Lengyelország azok a területek, ahol leginkább elterjedt.\n\nIV. A népi reformáció az 1520-as években bontakozott ki Münzer Tamás vezetésével\n\nŐket anabaptistáknak, vagyis újrakeresztelőknek is nevezik. Elvetették ugyanis a csecsemőkeresztséget, a felnőttkori, tudatosan vállalt keresztség hívei. A jézusi szegénységet hirdetik. Szerintük nemcsak a túlvilágon, hanem a földön is boldogulhatunk. Vagyonközösséget hirdetnek. Radikálisak az elképzeléseik. Parasztfelkelés lesz a következménye: 1524-ben Svábföldön, majd 1525-ben Frankföldön Geyer Flórián vezetésével, de a nemesség leveri. Elsősorban Németországban és Németalföldön terjed el.\n\nV. A szentháromságtagadók (antitrinitáriusok) Vezetőjük: Servét Mihály spanyol orvos. A szélsőséges irányzat szerint Isten egy és oszthatatlan, ezért tagadják a Szentháromságot (Atya, Fiú, Szentlélek). Kálvin János máglyahalálra ítéli Servét Mihályt. Hívei Erdélybe menekülnek, s Európában csak ott gyakorolhatták vallásukat. Elnevezésük: unitáriusok.\n\nA reformáció hatása: az emberek többsége legfeljebb nemzeti nyelven volt képes tanulmányozni a Szentírást. A reformáció hatására elszaporodtak a nyomdák, ami lehetővé tette a megnövekedett könyvigény kielégítését, s hogy ennek piaca legyen, kiterjesztették az iskolai népoktatást is. A reformáció gyarapította tehát az alsó- és középfokú intézmények számát, valamint létrejöttek az első protestáns egyetemek a Német-római Császárság területén és Németalföldön.\n\nA tétel kifejtése bővebben:\n\nLUTHER FELLÉPÉSE:\n\nX. Leó pápa a római Szent Péter-székesegyház építési költségeinek egy részét a búcsúcédulák bevételéből kívánta fedezni. A német egyházfők pedig ebből akarták visszafizetni a méltóságuk megvásárlására felvett hiteleket. A bocsánatos bűnök vagy a vezeklés alól már korábban is lehetett pénzért felmentést nyerni, megszabadulva ezáltal a tisztítótűztől. Az emiatti felháborodás azonban ekkor párosult a papság fényűző élete és a reneszánsz pápák világias életmódja miatt fellépő elégedetlenséggel.\n\nLuther Márton római útja során meggyőződött az egyház és a pápaság világias, romlott erkölcseiről. A búcsúcédulák árusítása miatt érzett felháborodása késztette arra, hogy összefoglalja kifogásait a katolikus egyházi gyakorlattal szemben, és 1517. október 31-én a wittenbergi vártemplomba érkezők tudomására hozza azt. Luther tanítása szerint az ember egyedül Isten kegyelméből, a hit által nyerheti el a megigazulást, azaz bűnei bocsánatát.\n\nA lutheri teológia alapelvei szerint\n\n• „a bűnt egyedül Isten bocsáthatja meg”, nincs szükség olyan közvetítőkre, mint a pápai egyház, s az egyes emberek csak saját hitük által nyerhetik el az üdvösséget.\n\n• Emellett az evangélikusok alapelvei közé tartozik még a „solus Christus”-elv, a szentek és Szűz Mária tiszteletének elvetése;\n\n• a „sola fide”-elv, vagyis hogy az üdvösség elnyerésében egyedül a hit számít, nem pedig a jó cselekedetek (ehhez még a „sola gratia”, Isten irgalma szükséges);\n\n• valamint a „sola Scriptura” elve: az isteni kinyilatkoztatás egyetlen formája a Biblia.\n\nNincs szükség költséges egyházi szertartásokra, egyházi adókra, sőt még egyházi vagyonra sem. Luther támogatta a szekularizációt, az egyházi birtokok világi kézbe adását. Megkérdőjelezte a pápa hatalmát az egyházon belül, elvetette a szerzetesség intézményét. Hitet tett a két szín alatti áldozás és az anyanyelvű igehirdetés mellett, melyben a főszerepet a Bibliát magyarázó prédikációnak szánta.\n\nA pápa elutasította Luther kritikáját, és kiátkozta. A wormsi birodalmi gyűlésen V. Károly meghallgatta Luthert (1521), de ő is veszélyesnek nyilvánította az új tanokat, és eretneknek nevezte Luthert az 1521-es wormsi birodalmi gyűlésen és birodalmi átokkal sújtotta Luthert, aminek folytán bárki bárhol szabadon megölhette. Bölcs Frigyes szász választófejedelem vette pártfogásába a reformátort, aki ez idő alatt Wartburg várában lefordította német nyelvre a Bibliát. Úgy tartotta, hogy a hit és az egyházi gyakorlat ellentmondásaiban csak a Szentírás alapján lehet igazságot tenni, ezért lefordította a Bibliát, hogy a hívek is olvashassák.\n\nErősítette az emberekben a közösséghez, gyülekezethez tartozás érzését. Luther a katolikus hét szentségből (keresztség, bérmálás, oltáriszentség, bűnbocsánat, egyházi rend, házasság, utolsó kenet) csak kettőt hagyott meg (keresztség, úrvacsora), mivel felfogása szerint az egyetlen igaz forrásnak tekintett Bibliában csak e kettő szerepel. A közösen vett úrvacsora a bűnök megosztását, a hit megerősítését jelképezte. Luther követői az evangélium szó után az evangélikusok.\n\nA kezdetben egységesnek tűnő mozgalom hamarosan különböző irányzatokra bomlott.\n\nVALLÁSHÁBORÚ NÉMETORSZÁGBAN\n\nAz 1529-es speyeri birodalmi gyűlés határozata alapján Luther követői megmaradhattak hitükön, de nem terjeszthették azt. A lutheránusok tiltakoztak (protestáltak) a határozat ellen, ezért kapták - a reformáció többi irányzatával együtt - a protestáns nevet. A következő évben Luther tanítványa, Philipp Melanchton az augsburgi gyűlés elé terjesztette az új vallás alapelveit. Az augsburgi (magyarul ágostai) hitvallás hangsúlyozta a protestáns és a katolikus tanok közös gyökerét. Fellépett a gyónás, a szerzetesi fogadalom, a böjt és a püspökök bíráskodása ellen. Mivel a császár nem engedett, a protestáns fejedelmek létrehozták a schmalkaldeni szövetséget. Az egyházi birtokok elfoglalását és a kolostorok megszüntetését tűzték ki célul. A fejedelmek és a császár között kitört a háború, melyben a katolikus I. Ferenc hatalmi okokból a protestánsokat támogatta. A császár sikereket ért el, s 1555-ben megkötötték az augsburgi vallásbékét. Ennek értelmében a fejedelmek szabadon választhattak vallást („cuius regio, eius religio” = akié a föld, azé a vallás), és alattvalóiknak is követniük kellett őket.\n\nA vallásbéke csak a Német-római Birodalom területére, valamint csak az evangélikus vallás elfogadására vonatkozott. A béke az evangélikusok kezén hagyta a már megszerzett földeket, de megtiltotta a további szekularizációt. Az egyházzá szerveződő lutheránusok az északi német területeken és Skandináviában hódítottak tért. Evangélikussá vált Csehország, Ausztria és Magyarország németajkú (szász) lakossága.\n\nA NÉMET PARASZTHÁBORÚ\n\nLuther reformer volt, követői között azonban akadtak szélsőségesebb elveket vallók is. Münzer Tamás vezetésével Zwickauban kialakult az anabaptisták (újrakeresztelők) irányzata. Az államhatalom megszüntetését és vagyonközösséget követeltek. A parasztok tömegei saját vágyaikat olvasták ki a reformációból, ami az 1524-1526-os német parasztháborúhoz vezetett. Ezt a fejedelmek leverték.\n\nAz anababtisták azt hirdették, hogy az ember csak felnőtt fejjel dönthet világnézetéről, csak ekkor lehet megkeresztelni. Támadták a gazdagságot, a krisztusi szegénységet tekintették mintának a keresztények számára. Azt vallották, hogy Isten birodalmát a Földön kell megvalósítani.\n\nA német parasztháború széttagolt mozgalom volt. 1524-ben megfogalmazták a svábföldi mozgalom programlevelét. 1525 tavaszán megindult a frankföldi mozgalom. A thüringiai felkelőket Münzer vezette. Mühlhausenben a javak közös birtoklását és munkakötelezettséget vezettek be. Válaszul a nemesség egységesen lépett fel, a felkeléseket leverték. A változtatás vágya a kisnemességet, a lovagokat is csatasorba állította. Franz von Sickingen és Ulrich von Hutten a lecsúszó réteg élén a „nemesi demokrácia” megvalósítását tűzte ki célul, de a fejedelmek és a papság elfojtották mozgalmukat.\n\nA SVÁJCI REFORMÁCIÓ KEZDETE - ZWINGLI és KÁLVIN\n\nNéhány évvel Luther fellépése után, 1523-ban Ulrich Zwingli, Zürich lelkésze összefoglalta tanításait. Fellépett az egyházi hierarchia, a szentmise és a cölibátus ellen, követelte a nemzeti nyelvű igehirdetést, a két szín alatti áldozást, a szekularizációt, vitás kérdésekben a Bibliát tekintette forrásnak. Egyszerű és demokratikus egyházszervezet kiépítését kívánta megvalósítani.\n\nZwingli és hívei fegyverrel is tanaik terjesztésébe fogtak, megtámadták a katolikus svájci kantonokat (1531), de Zwingli elesett a harcokban. Halála után hívei megegyeztek Kálvinnal, a reformáció másik svájci képviselőjével, hogy egységesen léphessenek fel a katolikusokkal szemben.\n\nA KÁLVINI REFORMÁCIÓ A francia születésű Kálvin János a reformátorok második nemzedékéhez tartozott. Jogot tanult Franciaországban, de el kellett hagynia hazáját. Egy egyházat megújítani akaró szervezkedés miatt Svájcba menekült. A kereszténységről vallott önálló elképzelései „A keresztény vallás tanítása” (Institutio) címen jelentek meg. Genf prédikátora lett (1541), ahol később teológiai akadémiát alapított. Kálvin az uralkodók hatalmát Istentől eredeztette, de úgy gondolta, ha visszaélnek a hatalommal, a nép soraiból választott vezetők szembeszállhatnak velük.\n\nKálvin, Lutherhez hasonlóan, az istentiszteleteken az imát, a közös éneklést, valamint a prédikációt helyezte előtérbe. Egyszerű és szegény egyházat hozott létre; templomaiban semmiféle képet nem tűrt meg. Kálvin szerint Isten hatalma végtelen. Az emberek sorsát a mindenható „eleve elrendelte” (PREDESTINÁCIÓ), sorsuk cselekedeteiktől függetlenül az üdvösség vagy a kárhozat. A kálvinizmus a munkát, a polgári erényeket megbecsülte, követendővé tette. A kálvinista erkölcsnek megfelelően a vagyont nem az élet élvezetére kellett fordítani, hanem a közösség és az egyén javára újra befektetni. Az uzsorát tiltotta, de a tisztes kamatra történő kölcsönzést elfogadta.\n\nA kálvini (református) egyház elvetette a hierarchiát, s a városi önkormányzati szervezet mintájára épült fel. Az egyes közösségek csak lazán kötődtek egymáshoz. A hitközségek életében szerepet kaptak világiak is. A presbiterek (világi egyházfelügyelők) a prédikátorokkal (papok) együtt vettek részt a kálvinista egyház igazgatási testületeiben.\n\nA kálvinizmus gyorsan terjedt: Svájc, Franciaország (hugenották), Németalföld, Skócia, Anglia (anglikán egyház, 1531. VIII. Henrik) és Magyarország lakóinak jelentős része hívéül szegődött.\n\nAZ ANTITRINITÁRIUSOK\n\nAz antitrinitáriusok (Szentháromság-tagadók) tagadták a Szentháromságot, azaz Krisztus isteni természetét és a Szentlélek létezését. Tanításaik szerint Jézus Isten fia volt, de végleg emberré lett, és kereszthalála az emberi áldozatvállalás példája. Demokratikus elveik miatt a kálvinistákhoz álltak közel, de tagadták a predesztinációt. Legjelentősebb képviselőjük a spanyol orvos, Szervét Mihály volt. Szervét az inkvizíció elől Genfbe menekült. Hitvitát folytatott Kálvinnal, de mivel Isten hármas természetének kérdésében nem tudtak megegyezésre jutni, a genfi nagytanács Szervétet börtönbe vettette, majd kivégeztette. Szervét tragédiája mutatja, hogy az újító gondolatoknak, ha egyházzá szerveződtek, meg kellett magukat védeni a régi és a születő új tanokkal szemben is.\n\nAz üldözött antitrinitáriusok Lengyelországban és Magyarországon leltek menedéket. Az Erdély területén élő Szentháromság-tagadók mérsékelt irányzatából szerveződött meg az unitárius egyház.\n\nA HIT TERJESZTÉSE, a reformáció kulturális hatása:\n\nA reformáció, hittételeinek ismertté tétele érdekében, nagymértékben támaszkodott Gutenberg újítására, a könyvnyomtatásra. Enélkül elképzelhetetlen lett volna a hitviták röplapjainak és az anyanyelvű Bibliáknak tömeges terjesztése. A reformátorok nagy jelentőséget tulajdonítottak a közös éneklésnek, ezt szolgálták a nyomtatott kották. A reformációnak tömegesen volt szüksége képzett lelkipásztorokra, hitvitázókra, ugyanakkor a hívek széles rétegéhez is el akarta juttatni a Biblia tanításait. Ezért nagy fontosságot tulajdonított az iskoláztatásnak az elemi szinttől az egyetemekig. Mindezek fejlesztőén hatottak a művelődésre, különösen az anyanyelvi kultúrára. Pl. Bibliafordítások, anyanyelvű istentiszteletek.\n\nAz ellenreformáció (rekatolizáció)\n\nA katolikus egyház célja reformáció (1517) során elpártolt hívek visszahódítása. Az egyház belső megreformálására létrehozza a tridenti zsinatot. 1540-ben megalakul Loyolai Ignác vezetésével az 1540-ben alapított Jezsuita rend, mely a visszatérítésen fáradozott. Loyolai Ignác 1540-ben alapította a jezsuita rendet. Az egyház problémáinak rendezésére egyetemes zsinatot hívott össze 1545-ben Trident városába. Az 1563-ig tartó zsinaton a katolikus egyház belső megreformálása történt meg. Az inkvizíció (egyházi bíróság) eszközét is alkalmazták. A hívek visszahódításának szelídebb módja a túldíszített barokk templomok, amelyek ámulatba ejtették a hívőket. A reformáció után azonban elterjedtek a protestáns vallások, ezt megakadályozni már nem tudták.\n\nA katolikus megújulás, azaz ellenreformáció a reformációt követő, illetve azzal párhuzamosan jelentkező folyamat, mely a XVI. században indult, és a XVII. században teljesedett ki a katolicizmus számos országban - pl. a Habsburg Birodalomban, Franciaországban - való megerősödésével.\n\nA katolikus egyház megújulási folyamatának legfontosabb állomásai: a jezsuita rend megalapítása, az inkvizíció működtetése, a tiltott könyvek jegyzékének összeállítása és a trienti zsinat összehívása a reformpápák hatására. Az ellenreformáció sikerének köszönhetően Spanyolország és Itália meg tudta őrizni sajátos katolikus arculatát. Franciaországban, a Habsburg és a Német-római Birodalomban, valamint Lengyelországban is a lakosság jelentős része tért vissza Róma hűségére, és mindezeknek köszönhetően gyengültek a protestantizmus pozícióit. A reformátorokkal való szakítás után a XVI. században a katolikus egyházban is megkezdődött a megújulás, melynek sikeressége több tényező eredményeként alakult ki pl. a protestánsok megosztottsága, a katolikus uralkodók szerepe, az újlatin ajkú területek lakosságának egyházhűsége. A kor pápái a helyzet megoldását a politikai hatalomtól várták, V. Károly pedig egyre sürgette a kérdés rendezésére az egyetemes zsinat összehívását. Erre azonban 1545-ig nem került sor.\n\nA vallásháború a Német-római Császárságban az 1529-es speyeri birodalmi gyűlésen robbant ki. Kimondták a lutheri tanok terjesztésének tilalmát, ami ellen a reformáció hívei tiltakoztak (protestáltak), innen ered a protestáns elnevezés. A protestáns fejedelmek 1531-ben Schmalkaldenben, a katolikus rendek 1538-ban Szent Liga néven léptek szövetségre egymással. 1545-ben háború robbant ki közöttük, amely a kezdeti protestáns sikerek után 1547 tavaszán Mühlberg mellett a császár győzelmével végződött. Végül 1555-ben Augsburgban vallásbékét mondtak ki, amely a „cuius régió, eius religio” (akié a föld, azé a vallás) elvén nyugodott. A tartományok urai szabadon választhatták meg vallásukat, amelyet az alattvalóik is kötelesek voltak követni. A katolikus egyház belső megújulását, s egyben a reformáció elleni küzdelmét III. Pál pápa (1534-1549) alatt kezdte meg. A pápa célja a tévtanok felszámolása volt, ennek érdekében létrehozta a Sanctum Officiumot (Szent Hivatal), amely az egykori inkvizíció utódszerveként működött, és megalapozta az egyházi cenzúrát, vagyis könyveket csakis a Szent Hivatal engedélyével lehetett nyomtatni. Megindította a reformmunkákat (elsősorban Spanyolországban és Itáliában), amelyek egyrészt teológiai és erkölcsi, másrészt egyházszervezeti és fegyelmi kérdésekre terjedtek ki. Ennek kiindulópontjai a már meglévő szerzetesrendek és a szigorú szabályzatú, általános életvitelű betegápoló, prédikátor- és tanító rendek voltak. Ezek közül is a legjelentősebb szerepet a Loyolai Ignác által 1540-ben alapított jezsuita rend töltötte be. Az egyház problémáinak rendezésére egyetemes zsinatot hívott össze 1545-ben Trident városába. Az 1563-ig tartó zsinaton dogmatizálták a katolikus álláspontot a reformáció által vitatott kérdésekben. Megerősítették a pápa egyházfőségét, a papi rendet, a cölibátust, a misét, a fülbe gyónást és a szentek tiszteletét. IV. Pál (1555-1559) 1559-ben pápai indexet, azaz tiltott könyvek jegyzékét jelentetett meg. IV. Pius (1559-1565) összeállította a Tridenti Hitvallást. A tridentinum határozatainak végrehajtása elsőként V. Piusra. (1566-1572) várt, aki kiadta a római katekizmust (hittankönyvet) és a római breviáriumot (papi zsolozsmáskönyvet). 1570-ben pedig kötelezővé tették a római misekönyv használatát. Utóda, XIII. Gergely (1572-1585) folytatta reformjait, ő vezette be a naptárreformot és alapította meg a római egyetemet, a Gregorianát. A kor pápái emellett elősegítették a barokk szellemiség kibontakozását, de a reformáció prédikátoraihoz hasonlóan anyanyelven prédikáltak, gyóntattak, és nagy gondot fektettek az ifjúság nevelésére -iskolarendszerük a korban a legmodernebbnek számított.\n\nA BAROKK: a katolicizmus megújulásával együtt született meg az új korstílus, a barokk. A XVI. század eseményei a reneszánsz embert és művészt a hit felé fordították. Másrészt a katolikus egyház a művészetet a hit erősítésére szolgáló eszköznek tekintette. Ösztönözte azokat a műalkotásokat, amelyek az érzelmekre, érzékekre hatottak. Ezt támogatták a megerősödő katolikus fejedelmek és főurak. Megrendeléseik nyomán sorra épültek gazdagon díszített templomok, pompás kastélyok és paloták, születtek zenei, képzőművészeti alkotások. A XVII. században uralkodó irányzatot az érzelmi túlfűtöttség, túldíszítettség, mozgalmasság, változatosság jellemzi minden művészeti ágban. Az egyház célja a túldíszített templomokkal a hívek visszahódítása, ámulatba ejtése, az egyház nagyságának érzékeltetése.\n\nELLENREFORMÁCIÓ, azaz KATOLIKUS MEGÚJULÁS összefoglalása:\n\nAz új hit követői ellenreformációnak, a katolikusok pedig megújulásnak nevezték. A katolikus egyház ellenállt a reformoknak. A katolikus vallás következetes hívei (a délnémet, az itáliai, a spanyol és a francia területek lakói) magukénak érezték a reformáció által támadott egyházat, ezért mozgalmat indítottak egyházuk megtisztítására. Róma támogatta az új mozgalmat. III. Pál (1534-1549), az utolsó reneszánsz és az első ellenreformációs pápa felhasználta világi hatalmát, a pápai diplomáciai hálózatot és vagyont a katolicizmus megmentéséért.\n\n1540-ben III. Pál jóváhagyta a Loyolai (Szent) Ignác által alapított jezsuita rend működését. Az új szerzetesrend célja a „lelkeknek a keresztény életben és a keresztény tanításban való előmenetele, a hit terjesztése” volt. Katonai rend szerint felépülő szervezete élén a generális állt, tagjaitól fegyelmet, valamint tökéletes engedelmességet követelt. A jezsuiták lettek a pápaság diplomatái, a királyok és a fejedelmek gyóntatói. Ennek révén befolyásolni tudták a korszak politikai életét. A reformáció nyomán felismerték az oktatás fontosságát, s magas színvonalú iskolahálózatot hoztak létre. A Pápai Államban újra felállították az inkvizíció intézményét 1542-ben Szent Hivatal néven, hogy gátat szabjanak az új tanok terjedésének. Az inkvizíció a katolikus területeken működött.\n\nTridentben 1545 és 1563 között ülésezett a legjelentősebb egyházi fórum, a zsinat, hogy tanácskozzon a reformációs mozgalom megállításáról, a szükségessé vált belső reformokról. A résztvevők pontosan megfogalmazták, és részletesen kifejtették a reformáció által vitatott hittételeket. Orvosolták azokat a sérelmeket, melyeket az alapvető katolikus hittételek torzulása nélkül meg lehetett tenni. Megtiltották a búcsúcédulák árusítását. Megfogalmazták, hogy a papság elsődleges feladata a szolgálat, a hívek lelki gondozása. Ezért a főpapok tartózkodjanak az egyházmegyéjükben, és ügyeljenek annak hitéletére, a papság erkölcseire, és kötelességeinek teljesítésére. A papság iskolázottságának növelése érdekében papnevelő intézeteket, szemináriumokat állítottak fel, a hit terjesztése érdekében nyomdákat alapítottak. Népszerűek lettek a zarándoklatok, búcsújárások. Általánossá váltak a körmenetek és a színpadias megoldások az egyházi ünnepeken.\n\nNem mondtak le sem a pápa egyházfőségéről, sem a szerzetességről, sem a szentségekről, sem a szentek tiszteletéről. Felhasználta a könyvnyomtatást tételei terjesztésére. IV. Pál pápa (1555-1559) utasítására összeállították az Indexet (1559), a tiltott könyvek jegyzékét, mellyel az általuk károsnak ítélt könyveket akarták távol tartani híveiktől. A reformok eredményeként a reformáció terjedése megállt. Azokban az országokban, ahol az ellenreformáció összekapcsolódott a politikai küzdelmekkel: Franciaországban, Csehországban, Ausztriában és részben Magyarországon a katolicizmus visszaszerezte korábbi tekintélyét. Indexre került sok olyan munka is, melyek új tudományos tételeket fogalmaztak meg, mint például Kopernikusz 1543-ban megjelent „Az égi pályák körforgásáról” című műve. Ebben azt a nézetét fejtette ki, hogy a világegyetem középpontja nem a Föld, hanem a Nap. Az új természettudományos tételek elutasítása azonban mindegyik felekezetre jellemző volt. Galileo Galileit az 1632-ben napvilágot látott „Párbeszéd két világrendszerről” című művéért a szent törvényszék elé idézték. Tanait azért tartották veszélyesnek, mert fizikai kísérleteivel helyesnek nyilvánította Kopernikusz világképét. Az inkvizíció a tanításai visszavonására kényszerítette. Azonban azt vallotta: „és mégis mozog a Föld.”\n\nA BAROKK\n\nA katolicizmus megújulásával együtt született meg az új korstílus, a barokk. A XVI. század eseményei a reneszánsz embert és művészt a hit felé fordították. Másrészt a katolikus egyház a művészetet a hit erősítésére szolgáló eszköznek tekintette. Ösztönözte azokat a műalkotásokat, amelyek az érzelmekre, érzékekre hatottak. Ezt támogatták a megerősödő katolikus fejedelmek és főurak. Megrendeléseik nyomán sorra épültek gazdagon díszített templomok, pompás kastélyok és paloták, születtek zenei, képzőművészeti alkotások. A XVII. században uralkodó irányzatot az érzelmi túlfűtöttség, túldíszítettség, mozgalmasság, változatosság jellemzi minden művészeti ágban. Az egyház célja a túldíszített templomokkal a hívek visszahódítása, ámulatba ejtése, az egyház nagyságának érzékeltetése.', 208, 1, '2026-04-17 09:41:02', '2026-04-17 09:41:02');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(22, 22, 'Az iszlám vallás és az arab hódítás', '22.docx', '22. Az iszlám vallás és az arab hódítás\n\nA VALLÁS KIALAKULÁSA\n\nAz iszlám Arab-félszigeten jött létre a VII–VIII. században. A muzulmánok egyedüli istenségnek fogadják el Allahot. Az iszlám vallás monoteista (egyistenhívő) - a zsidó és keresztény valláshoz hasonlóan.\n\nVálságjelenségek a VI. században: az Arab-félsziget - korlátozott eltartó képességű terület. Jellegzetessége: sivatagok tevés nomád beduinokkal és partvidéki városok: kereskedők, kézművesek (tömjénút). Az Arábiát lakó arabok zöme ló- és tevetenyésztő nomád beduin volt. Az arabok egy része kereskedéssel foglalkozott.\n\nJelentős települések alakultak ki a karavánutak mentén. Ilyen város volt Mekka, a későbbi világvallás, az iszlám bölcsője. Az iszlám jelentése: teljes meghódolás istennek.\n\nMohamed élete (kb. 570-632)\n\n• Mekkában született a várost vezető Kurais törzs egyik elszegényedett nemzetségében.\n\n• A Mekkában élő Mohamed (kb. 570-632) tevehajcsárból lett kereskedő. Korán árvaságra jutott, tevehajcsár, karavánvezető lett, majd házassága révén gazdag karavántulajdonos.\n\n• 40 éves korában látomásai támadtak, ennek hatására kezdett Mekkában prédikálni olyan törzsi alapon nyugvó vallási közösségről, amelyben nincsen helye (vagyoni) megkülönböztetésnek. Mohamed kereskedő volt. Látomások hatására kezdett tanítani. Elítélte a túlzott vagyont, egységet hirdetett, Mekkában kezdett működni. Utazásai során ismerkedett meg az egyistenhívő vallásokkal. Tanításait követői jegyezték le. Kezdetben a szegények támogatták. Felülemelkedett a törzsi ellentéteken. Medinába kellett menekülnie\n\n• Beutazta Arábiát. Utazásai során megismerkedett a zsidó és a keresztény vallással, melyekből sokat merített, mielőtt látomásai nyomán 610 táján új tanokkal lépett fel. Úgy vélte, hogy az isten, Allah, Gábriel arkangyal útján kinyilatkoztatta számára igazságait, parancsait és várakozásait az emberekkel szemben. Mohamed hamar követőkre talált a szegények között, mivel ostorozta az uzsorát, s isteni parancsként hirdette az elesettek gyámolítását, a törzsi ellentétek beszüntetését, így rövidesen összeütközésbe került a Mekkát vezető gazdag kereskedőkkel, s híveivel együtt menekülni kényszerült Medinába. 622-ben tehát a mekkai előkelők elűzték a városból. Mohamed Jathribba költözött (később Medina = a Próféta városa). 622-ben ez volt a Hidzsra, amely a mohamedán időszámítás kezdete lett. Medinában (Medinat-al-Nabi = a próféta városa, így nevezik később) talált menedéket és támogatókat. A Mekkából való kivonulás éve (622), a hidzsra vált a mohamedán időszámítás kezdetévé. Medinában megerősödött az új hit, és sok követőre talált a nomádok között. Mohamed eszméi, miután a mekkai kereskedőkkel is egyezségre jutott (mekkai zarándoklat), gyorsan kezdett terjedni.\n\n• 630-ban, miután katonák élén visszatért Mekkába, megegyezett a mekkai vezetőkkel: megígérte, hogy fenntartja a Kába kövének tiszteletét, és ezzel továbbra is biztosítja a város kultikus központ jellegét. 632-ben meghalt. 2 fia és 4 lánya közül már csak lányai éltek halálakor. Mohamedet Medinában temették el.\n\nA TANOK\n\nAz iszlám jelentős mértékben épített a zsidó és a keresztény hagyományokra. Mohamed ezen vallások prófétáit, Ábrahámot (Ibrahim), Salamont (Szulejmán), Mózest (Musza), Jézust (Isa) eszmerendszere előkészítőinek tekintette. Másrészt jelentős hatást gyakorolt tanaira a pogány arab hitvilág. Maga Allah korábban csupán egy törzsi istenség volt, s pogány eredetű a mekkai szent helyen a Kába-kő (egy meteoritdarab) tisztelete.\n\nAz iszlám gondolatvilágát szent könyve, a Korán (hirdetés, zsolozsmázás) tartalmazza. A hagyomány szerint szerzője személyesen Allah, aki Mohamed közvetítésével juttatta el művét az emberekhez. Szövegét Mohamed tanítványai közvetlenül mesterük halála után jegyezték le.\n\nA Korán 114 szúrából, azaz fejezetből áll, arab nyelven írták.\n\nKoránnal kapcsolatban - az iszlám szent könyve; egy angyal nyújtotta át Mohamednek a kinyilatkoztatást; a Koránt Isten, Allah szavának tartják. Mohamed prófétaként Isten akaratát közvetíti. Ez tartalmazza az ún. öt pillért; ez az iszlám jog alapja.\n\nA Korán alapján a hívő moszlimnak a következő öt alapvető parancsot kell betartania:\n\nA „hit 5 oszlopa”:\n\n1. Allahban, az egyetlen istenben, és prófétájában, Mohamedben való hit: SAHADA\n\n2. Mekka, a szent város irányába végzett napi ötszöri ima: SZALÁT. Ezt müezzin jelenti be a mecset tornyából, azaz a minaretből. A férfiak csoportosan, nyilvánosság előtt, a nők otthon.\n\n3. Kötelező alamizsnaosztás a szegényeknek. (ZAKAT: a szegény hívők megsegítésére a termés egy tizedét, 5 teve után l juhot be kellett szolgáltatni);\n\n4. A Ramadan havi böjt betartása, mikor napkeltétől napnyugtáig tilos enni és inni. (holdév 9. hónapja) SZAUM. A böjtölés alamizsnálkodással megváltható.\n\n5. Minden igazhitű életében legalább egyszer zarándokoljon el a szent városba, Mekkába a Kába-kőhöz: HÁDDZS (a muzulmán év 12. hónapjában)\n\nMohamedhez köthető a Kába-kő tisztelete, de a Kába-követ már az iszlám előtt is tisztelték. Az iszlám átvette az arab törzsi vallás egyes elemeit, Mohamed rendelte el a mekkai zarándoklatot, tehát a mekkai zarándoklat iszlám vallási előírás.\n\nMohamed ismerte a zsidó és keresztény vallás tanításait. Az iszlám gyökerei a zsidó és keresztény vallásig nyúlnak vissza. Az iszlám elismeri a zsidó és keresztény prófétákat. Mohamedet tartják az utolsó prófétának. Az iszlám magát a zsidó és keresztény vallás betetőzésének tartja.\n\nAz öt fő előírás mellett további követelmények is megfogalmazódtak a Koránban: pl. a sertéshús és a szeszes italok fogyasztásának tilalma, a többnejűség korlátozása (csak négy feleséget engedélyez). Nagy fontosságú az iszlám történetében a dzsihád, a szent háború. A dzsihád szerint a moszlimok feladata hitük terjesztése minden eszközzel, akár erőszakkal is. A harcosokat lelkesítette, hogy a dzsihád során elesettek azonnal a paradicsomba kerülnek.\n\nSzigorú monoteizmus jellemezte. Nem játszik fontos szerepet a papság.\n\nA mohamedán világban nem voltak külön világi törvények, mivel végső soron a Korán alapján bíráskodtak. A szövegek elméleti elemzését az ulemák (hittudósok) végezték, s a gyakorlatban ez alapján ítélkeztek a bírák, a kádik. A mohamedánoknál az államhatalom és az egyházi hatalom sem különült el: Mohamed utódai, a kalifák (kalifa = helyettes), egy személyben voltak vallási és állami vezetők. Az iszlám: arab szó, jelentése: engedelmesség, odaadás, belenyugvás Allah akaratába. Az iszlám a zsidó, a keleti keresztény, a perzsa vallásokból és pogány kultuszokból jött létre. Tanításaiban: Ádám és Éva az első emberpár.\n\n• Az arabok ősapja Ábrahám próféta egyik fia, Izmael. Mózes és Jézus is próféta, Mohamed elődei. Az iszlám vallásnak 3 fő dogmája van:\n\n• A vallás középpontjában az egy isten, Allah áll (monoteizmus);\n\n• Allah kinyilatkoztatása a Korán(= tanítás): ez 114 szúrából (=fejezet) áll;\n\n• utolsó ítélet tana: Allah döntése nyomán a bűnösök a pokolba, az igazhívők mennyországba kerülnek.Életrendi és egyéb szabályok, kötelességek:\n\n• sertéshús evésének tilalma; bor és részegítő italok fogyasztásának tilalma;\n\n• az iszlám hit védelme, később az iszlám területek kiterjesztése (dzsihád - szent háború).\n\n• Szertartáshelyek: kisebb imaház a mecset, nagyobb a dzsámi. A híveket imára a külön épített toronyból (minaret) a müezzin éneke hívja.\n\nMohamednek nem volt törvényes örököse, utódai a kalifák (helyettesek).\n\nA HÓDÍTÁSOK KEZDETE az iszlám egyesítette a korábban egymással harcoló arab törzseket, kezükbe került Szíria, Palesztina, Mezopotámia (635-641 között), Egyiptom (639-642 között). Tarik vezér 711-ben átkelt a Gibraltári-szoroson (Gebel al Tarik = Tarik sziklája) és Hispánia nagy része arab fennhatóság alá került. 732-ben Poitiers-nál Martell Károly frank katonái, 740-ben Kis-Ázsiában a bizánciak mértek vereséget az arabokra.\n\nAbbaszida vagy Bagdadi Kalifátus (750-1258)\n\n„Véres” Abbasz legyőzte az utolsó Omajjád uralkodót és megalapította a Bagdad székhelyű új kalifátust. A Omajjád család kiirtását egyetlen herceg, Abd ár Rahman élte túl úgy, hogy Hispániába menekült, ahol megalapította és Bagdadtól függetlenítette a Cordobai Omajjád Emirátust (929-től teljesen önállósult és kalifátus lett).\n\nA Bagdadi Kalifátus virágkora: az Ezeregyéjszaka meséiből is ismert Harún ar-Rashid ó/uralkodása (786-809) volt.\n\nKésőbb gyors hanyatlás következett be: a peremterületek függetlenedtek. A bagdadi kalifa hatalma csökkent, a birodalom bomlásnak indult.\n\n1258-ban a mongolok döntötték meg a Kalifátust.\n\nBERENDEZKEDÉSÜK\n\nAz iszlám uralom megszilárdulásával kiépült az arab állam, melyet bizánci mintára szerveztek meg. A kalifák despotikus uralkodókká váltak, akik megközelíthetetlenek voltak hatalmas palotáikban. Az arab katonai vezető réteg földbirtokos arisztokráciává alakult, igaz, a kalifák hatalmát nem tudták korlátozni, mivel azok elvehettek, kicserélhették birtokaikat. A tulajdonos ugyanis elvben a kalifa (az állam) maradt. A szolgálati birtokok rendszere biztosította a központi hatalom erejét.\n\nA földeket szabadok és részben rabszolgák művelték meg. A városok fennmaradtak, sőt virágzásnak indultak, mivel a közvetítő kereskedelem jelentős része az arabok kezébe került.\n\nAz arabok Damaszkuszból irányított hatalmas birodalma Hispániától Indiáig terjedt.\n\nAz Omajjádokat egy másik dinasztia, az Abbászidák (751-1258) megfosztották hatalmuktól. A központ átkerült Szíriából Mezopotámiába, Bagdad városába. A jelentős Abbászida-uralkodók közül kiemelkedik az Ezeregyéjszaka meséiből ismert Harún al-Rasid (786-809), Nagy Károly kortársa, a kultúra pártfogója.\n\nVirágzó korszak kezdődött, az egységes hatalmi ellenőrzés alatt levő óriási területeken fellendült a kereskedelem, a Kelet városai meggazdagodtak. Rendkívül fejlett volt a kézműipar, egy-egy város speciális termékei messzi vidékekre eljutottak (damaszkuszi acél -Damaszkusz; kordován csizma - Córdoba; muszlinszövet - Moszul).\n\nAz arabok számára a hódítás egyben a fejlett közel-keleti hellenisztikus műveltség átvételét jelentette, így vált lehetségessé, hogy az iszlám művelődés központjaiban arab fordítás készült az antik, a zsidó és más keleti kultúrák alkotásairól. Kölcsönhatásuk okozta az arab tudományosság fellendülését a csillagászatban, a kémiában (alkímia, elixír), a matematikában (algebra). Az arab kultúra megőrizte az antik műveltséget, s később közvetíthette az ismét felemelkedő Európa felé.\n\nA hatalmas birodalom kereskedői bejárták a világot, Kínától Afrika közepéig, s egy részük feljegyzéseket készített, mely a földrajztudomány fejlődését segítette. Arab kereskedők eljutottak a sztyepp nomádjai közé, ahol őseinkkel is találkoztak, s leírásaik őstörténetünk becses forrásai közétartoznak. (Dzsajháni, Ibn Ruszta, Gardízi leírásai ismertek - bár nem volt mindegyikük kereskedő.)\n\nAz óriási területet már nem bírták egyben tartani. Először a szélső tartományok szakadtak le és önállósultak (Córdobai emírség és Egyiptom). Nemsokára a belső terület is felbomlott. A későbbiek során egy-egy országrész tett szert vezető szerepre. Ennek ellenére a X. században Európa felé újabb hullámban támadtak az arabok, ezúttal elsősorban a tengeren. A megerősödő Európa azonban hamarosan visszaverte őket.\n\nAz iszlám és a kereszténység összehasonlítása\n\nIDŐ:\n\nA kereszténység a Kr. u. I. században keletkezett. Jézus születése az időszámításunk kezdete.\n\nAz iszlám időszámítás Mohamed futásával 622-ben kezdődött, az iszlám a VII. században alakult ki.\n\nTÉR:\n\nA kereszténység Jeruzsálemből indult ki, Palesztina volt a kereszténység bölcsője, a Római Birodalom keleti területein terjedt el Judea provinciából, majd Pál apostol térítő útjainak segítségével szinte az egész birodalomban, később Róma lett a pápák központja, a keleti egyház központja pedig Konstantinápoly.\n\nAz iszlám térbeli terjedése: Mekka a vallás legszentebb városa, Mohamed Medinába menekült 622-ben, Jeruzsálemben található a Sziklamecset. A vallás először az Arab-félszigeten terjedt el, majd Ázsiában, Észak-Afrikában, az iszlám rövid idő alatt elérte Európát is. (711. Gibraltár)\n\nHASONLÓSÁGOK ÉS KÜLÖNBSÉGEK:\n\nAz iszlám és a kereszténység is egyistenhívő, azaz monoteista.\n\nMindkét vallás fontosnak tartotta a szegények gyámolítását és a böjtöt, a kereszténység a hit megélését a formai előírások elé helyezi, az iszlámnak nincsenek bonyolult hittételei, a két vallás előírásai sok tekintetben hasonlók.\n\nA kereszténység szent könyve a Biblia. Az iszlám vallás szent könyve a Korán. A szent könyvekben az isteni kinyilatkoztatások jelennek meg, az iszlám a Bibliát elfogadja szent könyvnek. A Koránt Mohamed tanítványai, az Újszövetséget pedig Jézus tanítványai, az apostolok írták le. Az iszlámban a Korán inkább a jog alapja, míg a kereszténységben a Biblia a teológia alapja.\n\nAllah a prófétákon keresztül került kapcsolatba az emberekkel, elfogadja a bibliai prófétákat, Jézust is prófétának tartja, de csak Allahot fogadja el istennek.\n\nMohamed az utolsó próféta, Jézust csak küldöttnek tartja, Máriát tisztelet övezi, elutasítja a Szentháromság tanát.\n\nA keresztények Jézust istennek tartják, a keresztények számára a Messiás zárta a prófétákat.\n\nmindkét vallás a zsidó vallást tekintette egyik előzményének; Jézus a zsidó vallást, Mohamed a zsidó és a keresztény vallást is átértelmezte.\n\nMindkét vallás kinyilatkoztatott vallásnak tartja magát.\n\nTársadalmi tanítása:\n\na kereszténység társadalmi tanítása: Isten előtti egyenlőséget hirdetett, a zsidó és a pogány szokások eltörlését ígérte, a hívő az egyház közösségén keresztül juthat el az örök életre, cél volt a hit békés terjesztése. A korai keresztény közösségek vagyonközösségek voltak.\n\nA vallási parancsok már Mohamed életében összekapcsolódtak társadalmi, politikai célokkal pl. vallási közösség a vérségi, törzsi kötelékek helyett, a hívők egyenlőségén alapuló társadalmi rend kialakítása, előírás volt a hit terjesztése a szent háború – dzsihád – útján is.\n\nMindkét vallás kezdetben a szegények között terjedt, mindkét vallást a kialakulásakor üldözték, a kereszténység a tanai miatt, míg az iszlám a mindennapi életben is könnyen betartható előírásai miatt terjedt. A kereszténység csak a IV. századtól kapott állami támogatást (313. milánói edictum). Az iszlám valláson alapuló társadalmi és államrend is a hitterjesztést szolgálta, az iszlám türelmesebb volt más vallásokkal szemben, mindkét vallás a gyors terjeszkedés következtében több irányzatra bomlott.\n\nMindkét vallásban továbbélnek a korábbi hagyományok:\n\nPl. december 25. a Napisten ünnepe volt, a keresztények részt vettek pogány ünnepeken, Jézus születésének ünnepét a Napisten ünnepének időpontjára helyezték.\n\nMohamed helyezte el a szentélybe a Kába követ, amely az arabok szent köve volt a muszlim vallás kialakulása előtt is. Mohamed zarándoklatot végzett a Kábánál.\n\nA keresztény és a muszlim egyház átalakította, új tartalommal töltötte meg a pogány ünnepeket. Az átalakított pogány kultuszok átvétele felgyorsította a vallások terjedését, mindkét esemény a két vallás fontos ünnepévé vált.\n\nA kereszténység alapvető hittétele, tanítása:\n\nszeretet Isten és az embertársak iránt, hit az üdvözülésben, bűnbocsánat, megbocsátás.\n\nKeresztény az, aki hisz abban, hogy Jézus az Istentől megígért Megváltó.\n\nJézus tanításának központi eleme a szeretet és a megbocsátás. Tanítása a zsidó vallás parancsaira épül, pl. a 10 parancsolat.\n\nJézus Isten fia. A Szentháromság szerint: Atya, Fiú, Szentlélek.\n\nA keresztények hite szerint a zsidóság által várt megváltó Krisztus személyében érkezett el a földre, Jézus is megkeresztelkedett, tanított, gyógyított, kereszthalálával nemcsak a zsidókat, de az egész emberiséget megváltotta bűneitől, feloldozta őket az eredendő bűn alól.\n\nA keresztények tehát abban hisznek, hogy Isten új szövetséget kötött az emberiséggel, amelynek megpecsételéseként fiát küldte a földre, hogy megtanítsa az embereket az egyetemes szeretet parancsára, s hogy elhozza számukra a megváltást.\n\nA kereszténység fontos erkölcsi iránymutatását képezi az Ótestamentumból ismert tízparancsolat is, amelyet Mózes kapott Istentől az első szövetségkötés alkalmával.\n\nAz iszlám alapvető tanítása:\n\nAllahban való hit, napi ötszöri ima, alamizsna, böjt, zarándoklat Mekkába\n\nA „hit 5 oszlopa” tehát\n\n1. Allahban, az egyetlen istenben, és prófétájában, Mohamedben való hit: SAHADA\n\n2. Mekka, a szent város irányába végzett napi ötszöri ima: SZALÁT. Ezt müezzin jelenti be a mecset tornyából, azaz a minaretből. A férfiak csoportosan, nyilvánosság előtt, a nők otthon.\n\n3. Kötelező alamizsnaosztás a szegényeknek. (ZAKAT: a szegény hívők megsegítésére a termés egy tizedét, 5 teve után l juhot be kellett szolgáltatni);\n\n4. A Ramadan havi böjt betartása, mikor napkeltétől napnyugtáig tilos enni és inni. (holdév 9. hónapja) SZAUM. A böjtölés alamizsnálkodással megváltható.\n\n5. Minden igazhitű életében legalább egyszer zarándokoljon el a szent városba, Mekkába a Kába-kőhöz: HÁDDZS (a muzulmán év 12. hónapjában)\n\nA dzsihád, a szent háború szerint a moszlimok feladata hitük terjesztése minden eszközzel, a dzsihád során elesettek azonnal a paradicsomba kerülnek.\n\nAz iszlám jelentős mértékben épített tehát a zsidó és a keresztény hagyományokra. Mohamed ezen vallások prófétáit, Ábrahámot (Ibrahim), Salamont (Szulejmán), Mózest (Musza), Jézust (Isa) eszmerendszere előkészítőinek tekintette. Másrészt jelentős hatást gyakorolt tanaira a pogány arab hitvilág. Maga Allah korábban csupán egy törzsi istenség volt, s pogány eredetű a mekkai szent helyen a Kába-kő (egy meteoritdarab) tisztelete.\n\nTehát hasonlóságok (egyistenhit, próféták, korábbi hagyományok továbbélése, böjt, alamizsna, korai üldözés stb.) és különbségek (békés, illetve háborús hitterjesztés, más hittételek stb.) is felfedezhetők az iszlám és a keresztény vallás között.', 94, 1, '2026-04-17 09:41:02', '2026-04-17 09:41:02'),
(23, 23, 'A francia forradalom és következményei', '23.docx', '23. A francia forradalom és következményei\n\n(az Emberi és polgári jogok nyilatkozata, a jakobinus diktatúra, a napóleoni háborúk és a bécsi kongresszus)\n\nA francia forradalom előzményei:\n\nA 18. század végén Franciaország Európa legjelentősebb és leggazdagabb állama volt. A kincstár mégis kiürült a háborús kiadások és az ország vezetőinek pazarlása miatt. A királyi hatalom elvesztette tekintélyét. 1789-ben kitört a forradalom, amely nemcsak Franciaországot, hanem egész Európát megrengette. Franciaország fegyverrel és katonákkal is támogatta az amerikaiak függetlenségi harcát Anglia ellen. A költséges háborúskodáshoz a király hatalmas kölcsönöket vett fel, amiket nem tudott visszafizetni. Pénzre volt szüksége, ezért arra kényszerült, hogy 1789-ben összehívja Versailles-ban a rendi gyűlést. Ilyenre Franciaországban 175 éve nem került sor. A rossz termés tovább nehezítette az ország helyzetét. A városokban és a falvakban sokan éheztek, és a legtöbben XVI. Lajost és pazarló udvarát okolták mindezért. Az emberek elégedetlensége és haragja egyre nőtt a korlátlan királyi hatalommal szemben. Gyűléseket tartottak, és röpiratokat adtak ki. A polgárság, a harmadik rend pedig a nemesség és a papság kiváltságos helyzetének megszüntetését követelte.\n\nA rendi gyűlés átalakulása nemzetgyűléssé\n\nA rendi gyűlésben a három rend, a papság, a nemesség, valamint a városi polgárság képviselői foglaltak helyet.\n\nA király új adókat akart megszavaztatni, a harmadik rend képviselői viszont a királyi hatalmat korlátozó alkotmányt akartak. Hatottak rájuk a felvilágosodás eszméi és az angol alkotmányos királyság példája. A harmadik rendhez a két másik kiváltságos rendből is csatlakoztak. A király akaratával szembe szegülve a rendi gyűlést alkotmányozó nemzetgyűléssé alakították át.\n\nA király, látva a képviselők eltökéltségét és a forrongó indulatokat, beleegyezett az ülés folytatásába, de közben seregeket mozgósított Versailles körül. A párizsi nép meg akarta akadályozni, hogy XVI. Lajos erőszakkal oszlassa fel a nemzetgyűlést. Ezért Párizsban 1789. július 14-én fegyveres felkelés tört ki. Ennek legmeghatározóbb eseménye a királyi börtönerőd, a Bastille (basztij) ostroma volt. A francia katonaság a felkelők oldalára állt. A párizsi események hírére vidéken is lázadások törtek ki. A parasztok földesuraik ellen fordultak. A városok élére a harmadik rend képviselői kerültek, akik polgárokból álló nemzetőrségeket állítottak fel. A királyt arra kényszerítették, hogy Versailles-ból Párizsba költözzön. z alkotmányozó nemzetgyűlés eltörölte a kiváltságokat, a nemesi adómentességet, a papi tizedet, és megszüntették a jobbágyterheket. Franciaországban megszűnt a feudális rendszer. Az államadósság csökkentésére az egyházi földbirtokokat nemzeti tulajdonba vették, majd kiárusították.\n\nAz alkotmányozó nemzetgyűlés elfogadta az Emberi és polgári jogok nyilatkozatát. Ez kimondta, hogy minden ember szabad és egyenlő, és azt is, hogy az állam vezetőinek hatalma a néptől származik. Ez a nyilatkozat adta a későbbi francia polgári alkotmány alapját, és egyben összegezte a polgári szabadságjogok nagy részét.\n\nAz Emberi és polgári jogok nyilatkozata\n\nAz Emberi és polgári jogok nyilatkozata Franciaország egyik alapvető dokumentuma, mely az emberek egyéni és közösségi jogait határozza meg. Az 1789. július 14-i francia forradalom után fogalmazták meg. 1789. augusztus 26-án fogadta el az Alkotmányozó Nemzetgyűlés. Ez a dokumentum az 1791-es alkotmányt készíti elő. La Fayette készítette el, és az amerikai Thomas Jefferson is átnézte.\n\nA francia forradalom megszűntette az abszolutizmust, az abszolút monarchiát alkotmányos monarchia, ill. később köztársasági államforma váltotta fel (1792. szept.20). Az abszolutizmus lényege volt, hogy az „Isten kegyelméből” uralkodó király a három hatalmi ág: a törvényhozó, igazságszolgáltató, végrehajtó hatalom egy kézben való egyesítésével teljhatalomra tett szert, és nem felelt tetteiért az alattvalóknak. Az alkotmányos monarchia a hatalmi ágak megosztására épült. Az új állam az egyéni szabadságjogok és a politikai egyenlőség megvalósítása során a népfelség elvét juttatta érvényre.\n\nA nyilatkozat alapelvei a felvilágosodás filozófiai és politikai alapelveiből származtak, szerepeltek benne többek között\n\na Jean-Jacques Rousseau (’russzó’) által megfogalmazott egyén és társadalmi szerződés, a népszuverenitás fogalmai,\n\na Montesquieu (’monteszkiő’) által kidolgozott hatalmi ágak megosztásának elmélete.\n\nelőzménye volt a Thomas Jefferson által készített amerikai Függetlenségi nyilatkozat 1776.\n\nilletve az angol Bill of Rights (1689).\n\nA feudalizmus eltörlése után, a nyilatkozat népszuverenitást és esélyegyenlőséget hirdetett. A jogokat a nyilatkozat az „közakarat kifejezéseként” kezeli, így hirdet jogegyenlőséget és „csak a társadalomra nézve ártalmas cselekedeteket” tiltja. A bevezető a racionalizmusra utal, ill. arra, hogy az embereknek ismerniük kell a jogaikat. Az ember természetes jogait fogalmazza meg, melyet kivétel nélkül mindenkire érvényesnek tekintettek:\n\nMinden ember szabadnak és jogokban egyenlőnek születik és marad; a társadalmi különbségek csakis a közösség szempontjából való hasznosságon alapulnak. Nincsenek születési előjogok, szembefordul a nemesi kiváltságokkal.\n\nMinden politikai társulás célja az ember természetes és elévülhetetlen jogainak megőrzése. E jogok: a szabadságjog, a tulajdonjog, a biztonság s az elnyomással szemben való ellenállás. A polgári társulás célja az ember jogainak megőrzése.\n\nMinden szuverenitás elve természeténél fogva a nemzetben lakozik; sem testület, sem egyén nem gyakorolhat hatalmat, ha (az) nem határozottan tőle ered. - Ez eltér a forradalom előtti helyzettől, ahol a királyság politikai forrásjoga a királyok isten adta jogának elvéből származott. A népfelség elve: hatalom forrása a nép. Hatalommegosztás elve (törvényhozó és végrehajtó hatalom van kezdetben, majd később lesz a 3 hatalmi ág. Locke szerint 2 hatalmi ág szükséges, Montesquie 3 hatalmi ágat tart fontosnak.\n\nA szabadság annyit jelent, hogy mindent szabad, ami másnak nem árt. Az egyes ember természetes jogainak gyakorlása tehát más korlátokba nem ütközhetik, mint azokba, amelyek a társadalom többi tagjai számára ugyanezen jogok élvezetét biztosítják; s e korlátokat a törvény határozhatja meg. Ezek alapvető polgári szabadságjogok. Szabadság = mindent szabad, ami másnak nem árt.\n\nA törvénynek csak a társadalomra nézve ártalmas cselekedetek megtiltására van joga. Amit a törvény nem tilt, azt senki nem akadályozhatja meg, s amit a törvény el nem rendel, arra senkit kényszeríteni nem lehet.\n\nA törvény a közakarat kifejezése; alkotásában minden polgárnak joga van személyesen vagy képviselői révén közreműködnie. A törvény egyformán törvény mindenki számára, akár védelmez, akár büntet; s mivelhogy a törvény előtt minden polgár egyenlő, tehát minden polgár egyformán alkalmazható minden közhivatalra, állásra és méltóságra, erényeik és képességeik különbözőségén kívül egyéb különbséget nem ismerve. – Ez eltér a forradalom előtti helyzettől, ahol a francia társadalom rendekre volt felosztva: papságra, nemességre valamint a népesség többi részét kitevő harmadik rendre, és ahol az első két rendnek külön jogai voltak. Főleg a született nemesség elvével áll szemben. E pont megfogalmazója érdekes módon Talleyrand, az arisztokrata származású püspök volt. A törvényalkotásban minden polgárnak joga van közreműködni.\n\nVád alá helyezni, letartóztatni s fogva tartani bárkit is csak a törvény által meghatározott esetekben s a törvény által előírt formák között lehet. Mindenki büntetendő, aki önkényes rendelkezéseket szorgalmaz, kiad, végrehajt vagy végrehajtat; viszont minden polgárnak, akit a törvény értelmében megidéznek vagy őrizetbe vesznek, haladéktalanul engedelmeskednie kell – s ha ellenállást tanúsít, bűnösnek vallja magát vele.\n\nA törvény csak szigorúan és nyilvánvalóan szükséges büntetési tételeket állapít meg, s büntetéssel sújtani senkit másként nem lehet, mint a bűncselekmény elkövetése előtt meghozott és kihirdetett, valamint szabályszerűen alkalmazott törvény értelmében.\n\nMindaddig, amíg bűnössé nem nyilvánítják, minden ember ártatlannak vélelmezendő. Ha tehát letartóztatása mégis elkerülhetetlenné válik, a törvénynek szigorúan meg kell torolnia minden olyan keményebb rendszabályt, amelyet a szökés megakadályozásának szükségessége nem indokol. - A nyilatkozat tiltja a gyanúsítottal szembeni indokolatlan durvaságot, ugyanakkor az ártatlanság vélelmét hirdeti. A forradalom előtti Franciaországban, miután az illetékes hatóságok vád alá helyezték, technikailag azonnal bűnösként kezelték az embert.\n\nSenkit meggyőződése, vallási s egyéb nézetei miatt háborgatni nem szabad, feltéve, hogy e meggyőződés s e nézetek megnyilvánulása a törvényes rendet nem sérti.\n\nA gondolatok és vélemények szabad közlése az embernek egyik legértékesebb joga; ennélfogva minden polgár szabadon szólhat, írhat s nyomtathat ki bármit, felelősséggel tartozván viszont e szabadsággal való visszaélésért a törvény által meghatározott esetekben. - A nyilatkozat szólásszabadságot és a sajtószabadságot biztosít.\n\nAz ember és a polgár jogainak biztosítása karhatalom fenntartását teszi szükségessé; e karhatalomnak tehát az összesség hasznára kell szolgálnia, nem pedig azoknak külön céljaira, akiknek személyére e karhatalom rábízatik. A polgári jogok megvalósulásához karhatalomra van szükség.\n\nA karhatalom és a közigazgatás költségeinek fedezésére nélkülözhetetlenül szükséges mindenkinek közös hozzájárulása; s e hozzájárulást, kinek-kinek képessége szerint, a polgárok összessége közt egyenlően kell elosztani. - Az amerikai alkotmányhoz hasonlóan megemlíti a karhatalom szükségességét és a közigazgatás fenntartásához szükséges adózás alapelveit, amiben az egyenlőség elve kitüntetett szerepet kap. Lényeges különbség a forradalom előtti időkhöz képest, amikor az egyház és a nemesség mentes volt a legtöbb adónem alól.\n\nA polgároknak saját személyükben vagy képviselők útján joguk van e közös hozzájárulás szükségszerűségét megállapítani s azt szabadon megszavazni, valamint felhasználását nyomon követni, s meghatározni mennyiségét, alapját, elosztását, behajtását és időtartamát.\n\nA társadalomnak joga van a közigazgatás minden tisztviselőjét számadásra vonni.- Meghatározza a nyilvánosság előtti felelősség fogalmát.\n\nAz olyan társadalomnak, amelyből e jogok biztosítékai hiányoznak, s ahol a törvényhozó és a végrehajtó hatalom szétválasztását nem hajtották végre, semmiféle alkotmánya nincs. Ahol mindez hiányzik, annak a társadalomnak nincs alkotmánya.\n\nTulajdonától – lévén a tulajdonjog szent és sérthetetlen – senki meg nem fosztható, legfeljebb csakis oly esetekben, amikor ezt a közösség érdekéből fakadó nyilvánvaló és törvényes úton megállapított szükségesség követeli meg – ám ekkor is csak igazságos és előzetes kártalanítás fejében. A tulajdon szent és sérthetetlen.\n\nA forradalom további folytatása: az alkotmány elfogadása 1971-ben\n\n1791-ben Franciaország alkotmányos királyság lett. Az elkészült alkotmány lehetővé tette a polgárság felemelkedését. A törvényhozás választott képviselők kezébe került, ugyanakkor biztosították a király vétójogát a törvények felfüggesztésére.\n\nMegvalósították a törvény előtti egyenlőséget, a szólás- és sajtószabadságot. Eltörölték a céhrendszert, kimondták az ipar és a kereskedelem szabadságát.\n\nMiután az alkotmányozó nemzetgyűlés befejezte a munkáját, feloszlott, és átadta helyét a megválasztott képviselőkből álló törvényhozó nemzetgyűlésnek.\n\nXVI. Lajos ellenezte a nemzetgyűlés egyes döntéseit, és nem akart azzal együttműködni. Ezért titokban a családjával együtt megpróbálta elhagyni Párizst. A király szökési kísérletét sokan árulásnak tartották, és ezért a királyság teljes megszüntetését akarták. Közben az európai nagyhatalmak szembe fordultak Franciaországgal. Azt követelték, hogy állítsák vissza a francia király jogait.\n\n1792 tavaszán kitört a háború Franciaország és a Habsburg Birodalom között. XVI. Lajos azt remélte, ha Franciaország vereséget szenved, visszakapja korábbi hatalmát. Ezért számos olyan törvényt megvétózott, amely a külső hatalmak elleni háború sikeres megvívását szolgálta volna. Az idegen csapatok megtorlásától rettegő párizsiakat ez végleg felbőszítette. Megrohanták, és véres küzdelem árán elfoglalták a királyi palotát. A királyt börtönbe vetették, és 1792 szeptemberében kikiáltották a köztársaságot. Ezzel egy időben sikerült megállítani Valmynál (valmi) a betörő porosz és osztrák sereget. 1793 januárjában XVI. Lajost mint egyszerű francia állampolgárt hazaárulásért halálra ítélték, és lefejezték.\n\nA jakobinus diktatúra 1793-94.\n\nA francia hadsereget sorozatos vereségek érték. Az országon belül is egész városok és tartományok lázadtak fel a köztársaság ellen. A kenyér ára az egekbe szökött. A dühös és elkeseredett párizsi tömegek meg akartak ölni mindenkit, akit a nép ellenségének gondoltak. Az ő támogatásukkal a jakobinusok magukhoz ragadták a hatalmat, és kivégezték a korábbi vezetőket. A köztársaság védelme érdekében felfüggesztették az alkotmányos szabadságjogokat, és diktatórikus módszerekkel kormányoztak. A forradalom ellenségeinek vagyonát elkobozták, és szétosztották a szegények között. Maximalizálták a létszükségleti cikkek árát, és kötelezték a gazdagokat arra, hogy kölcsönt adjanak az államnak. A jakobinusok kíméletlenül levertek minden belső lázadást, és kivégeztek mindenkit, akit a forradalom ellenségének tartottak. Elrendelték az általános hadkötelezettséget, és szigorú intézkedésekkel helyreállították a hadsereg fegyelmét. Az újjászervezett csapatok győzelmet arattak a Franciaországra támadó idegen seregek felett is. A köztársaság megmenekült. A jakobinusok fenntartották a terrort azután is, hogy sikerült megvédeniük az országot a külső támadásoktól. Vezérük, Robespierre már azokat is kivégeztette, akikről csak feltételezte, hogy szembe szegülhetnek az akaratával. Sőt, még korábbi társait sem kímélte. Az értelmetlen és mindenkit fenyegető terrort látva a jakobinusok ellenfelei összefogtak. 1794 júliusában elfogták és kivégezték a jakobinusok vezetőit, köztük Robespierre-t. Ezzel a jakobinus diktatúra 13 hónapig tartó rémuralma véget ért.\n\nNapóleon hatalomra jutása és uralma\n\nNapóleon konzulsága (1799-1804) és császársága (1804-15)\n\n• Az 1789-ben kezdődő francia forradalmat követően jutott hatalomra Napóleon.\n\nA jakobinus diktatúrát (1793-94) felszámoló konvent 1795-ben olyan új alkotmányt hozott létre, amely korlátok közé szorította a népfelséget. Mind a királypárti, mind a jakobinus (sans-culotte) megmozdulások sorát is csak fegyverrel lehetett leverni. Ezzel egyre nőtt a katonai vezetők szerepe, mint például Bonaparte Napóleoné (1769-1821), a legnépszerűbb tábornoké.\n\nA Direktórium folytatta a forradalmi háborút:\n\n• 1796-ban Napóleon hadjárata Itáliában sikeres volt, Ausztriát békére kényszerítette, (Campoformio, 1797.). Franciaország megkapta Belgiumot és Lombardiát, az l. koalíció Franciaország ellen szétesett. A Nagy-Britannia vezetésével szerveződött franciaellenes 1. koalíció legyőzése után Bonaparte kísérletet tett Egyiptom elfoglalására, ami a 2. koalíció megszerveződéséhez vezetett.\n\n• 1798-ban Anglia megtörése érdekében Napóleon Egyiptomra támadt, legyőzte a mameluk seregeket, de miután Nelson admirális megsemmisítette a hajóit, Egyiptom foglya maradt.\n\n• 1799-ben Anglia újjá szervezte a 2. koalíciót, amelynek az oroszok, az osztrákok és Poroszország is tagja lett. A háború francia sikerekkel kezdődött, Svájcban legyőzték az oroszokat (zürichi csata, 1799), akik ki is léptek a koalícióból.\n\nBonaparte Egyiptomot feladta, de a szárazföldön legyőzte a 2. koalíciót is.\n\n• Napóleon - miután hazaszökött Egyiptomból - 1799. november 9-én (brumaire 18-án) államcsínyt hajtott végre, lemondatta a direktórium tagjait, és első konzulként átvette a hatalmat. Bonaparte lezárta a forradalom eredményeinek konszolidációs folyamatát.\n\n• 1800-ban elindult 2. itáliai hadjáratára: több csatában (Marengo, Hohenlinden) legyőzte az osztrákokat, akik megint békekötésre kényszerültek (Luneville, 1801).\n\n• Anglia ismét egyedül maradt és békét kötött Franciaországgal (Amiens, 1802).\n\nBelpolitikája:\n\n• Bonaparte egy új alkotmány rendelkezéseivel igyekezett leplezni diktatórikus hatalmát.\n\nA törvényhozásban továbbra is külön testületben folyt a törvényjavaslatok vitája (Tribunátus) és az azokról való szavazás (Törvényhozó Testület), és emellé még egy általa kinevezett tagokból álló harmadik kamarát is felállított (Szenátus). A választójogot újra általánossá tette, de a valóságban a közvetetten választott jelöltekből a Szenátus emelte ki a törvényhozó testületek tagjait. A végrehajtó hatalom az első konzul kezében volt, erre a tisztségre élethosszig Bonapartét választották. REFORMJAI:\n\nTörvényesítette a fennálló tulajdonviszonyokat.\n\nMegalapította a Nemzeti Bankot (Banque de Francé), értékálló pénzt veret, a frankot.\n\nAz adórendszert korszerűsíti.\n\nÉletbe léptette az első polgári törvénykönyvet (Code Civil), amely aztán egész Európában a modern polgári jog mintája lett: Code Napoleon.gh\n\nÁllami középiskolákat és egyetemeket alapított, elsősorban az egységesített hivatalszervezet személyi állományának képzésére.\n\nA pápával kötött konkordátummal lezárta az egyház és a forradalmi állam viszályát: a püspököket az állam nevezte ki, de egyben gondoskodott a papok fizetéséről is. A konkordátumot VII. Pius pápával köti (1801): helyre álltak a katolikus egyház jogai, de a főkegyúri jog Napóleont illette meg.\n\nA közigazgatás átszervezése, új hivatalok létrehozása (rendőrminisztérium, élén Fouche)\n\n1803-ban Louisianat eladta 15 millió dollárért az USA-nak;\n\n1804. május 18. népszavazással, december 2-án koronázással császárrá tette önmagát.\n\nNapóleon további háborúi:\n\nAz egyszemélyi hatalom 1804-ben vált teljesen nyilvánvalóvá, amikor Bonaparte I. Napóleon néven császárrá koronáztatta magát.\n\nCsaládtagjait különböző legyőzött országok trónjára ültette. Új főnemességet hozott létre rendszere híveiből.\n\n• 1805-ben megalakult a 3. koalíció Anglia vezetésével. Nagy-Britannia a koalícióba a három kontinentális nagyhatalmat vonta be (Habsburg Birodalom, Poroszország, Oroszország).\n\n• Napóleon fő terve az Anglia elleni invázió volt, de ezt lehetetlenné tette a Nelsontól elszenvedett tengeri vereség Trafalgarnál (1805. október 19-21.).\n\n• Szárazföldön azonban verhetetlen volt: legyőzte az osztrákokat (Ulm bevétele, 1805), majd a „3 császár csatájában” az osztrák és az orosz főerőket (Austerlitz, 1805. december 2.). A 3. koalíció is felbomlott, az osztrákok ismét békét kértek (Pozsony, 1805), és lemondtak Velencéről.\n\n• A napóleoni háborúk a forradalmi háborúk folytatásaként az egész konzulsága (1799-1804) és a császárság (1804-15) korszaka alatt folyamatosan dúltak. A háborúk lezárhatatlanságának több oka is volt. Napóleon népszerűsége a katonai sikereiből adódott, diktatúrájának legitimációját később is a győzelmek teremtették meg.\n\nA konzervatív dinasztiák (Habsburgok, Hohenzollernek, Romanovok) számára állandó fenyegetést jelentett a polgári jogegyenlőséget megteremtő forradalmi Franciaország.\n\nFranciaország katonai fölénye, és a polgári intézmények megteremtése után fellendülő gazdasága Nagy-Britanniát állandó beavatkozásra késztette. Franciaország sikeresen exportálta a forradalmi eszméket: Európa-szerte elterjedt az azonos jogú tagokból álló, nyelvileg-kulturálisan is egységes nemzet gondolata. Az új nemzettudat azonban idegen megszállókat látott a franciákban.\n\n• Napóleon katonai fölényét személyes tehetsége mellett a forradalmi hadseregnek köszönhette. A tömeges sorozásokkal a korábbinál sokkal nagyobb létszámú hadseregeket állítottak fel. A forradalmi, majd nemzeti lelkesedést kihasználva a csatákat már nem az elkerülő manőverek, hanem a döntő rohamok jellemezték (ami ugyanakkor sokkal több áldozatot is követelt). Továbbra is érvényesült a francia tüzérség technikai és taktikai fölénye (Bonaparte maga is tüzértiszt volt).\n\n• A francia győzelmek eredményeként átrajzolódott Európa térképe.\n\nFranciaország területe folyamatosan nőtt, legnagyobb kiterjedése idején már Belgiumot, Hollandiát, Észak-Németországot, Svájcot, Itália jelentős részét, Katalóniát, sőt Dalmáciát is magában foglalta. A legyőzött országokból először francia mintájú köztársaságokat szerveztek (antik nevekkel, pl. Batávia, Helvécia, Cisalpina), majd a császárság megalapítása után Napóleon testvérei kerültek a trónjaikra. 1806-ban Napóleon megszüntette a Német-római Császárságot. 1806-ban II. Ferenc lemondott a német-római császári címről, ezzel megszűnt a birodalom, helyébe Napóleon létrehozta a Rajnai Szövetséget.\n\nA Habsburg Birodalom és Poroszország tartósan legyőzhető volt, de Oroszország a mérete és a távolság miatt nem, ezért vele Napóleon szövetségre törekedett.\n\n• 1806-ban létrejött a porosz-orosz megállapodáson alapuló 4. koalíció:\n\n• Napóleon azonban legyőzte a poroszokat (Jéna és Auerstadt 1806. október 14.) és bevonult Berlinbe, ahol 1806-ban kihirdette a kontinentális zárlatot Anglia gazdasági megtörésére, ez azonban nem törte meg a szigetországot. Megtiltotta Európa számára, hogy kereskedjen Nagy-Britanniával.\n\n• Ezután az oroszok ellen indult, akiket 2 csatában győzött le (1807. február 8. Eylau; június 14. Friedland). Békekötés a poroszokkal és az oroszokkal (1807. tilsiti béke)\n\nNéhány területen (Spanyolország) állandósultak a nemzeti felkelések, ami jelentős katonai erőt kötött le. 1807-ben elfoglalta Portugáliát, majd 1808-ban bevonult Madridba is.\n\nNapóleon hatalmának csúcspontja:\n\n• 1809-ben egy angol-osztrák egyezménnyel megszerveződött az 5. koalíció.\n\n• Napóleon azonban ismét legyőzte az osztrákokat (Wagram, 1809. július 5-6.), győri csata 1809. Az osztrákok ezután békére kényszerültek (Schönbrunn, 1809).\n\n• Napóleon 1810-ben feleségül vette Habsburg Mária Lujzát, s ezáltal kényszerű szövetségessé tette Ausztriát.\n\n• Oroszország felmondta a számára káros kontinentális zárlatot, ezért Napóleon 1812-ben hadjáratot indított ellene. Orosz taktika: a felperzselt föld, rajtaütések.\n\nA francia erők egy része máshol volt lekötve, a soknemzetiségű császári hadsereg pedig megbízhatatlannak és használhatatlannak bizonyult. Szmolenszknél, majd Borogyinónál (1812. szeptember 7.) kiegyenlítettek voltak az erőviszonyok, de végül az oroszok visszavonultak, Napóleon pedig elfoglalta Moszkvát, ami azonban leégett. Napóleon hiába várt Moszkvában a cár békeajánlatára. Végül ki kellett vonulnia Oroszországból. Az oroszok Kutuzov tábornok vezetésével a nagy távolságokat kihasználva a felperzselt föld taktikáját alkalmazták, így az utánpótlás összeomlása miatt Napóleonnak vissza kellett vonulnia. A telet nem bírta hadserege.\n\n• 1813-ban megszerveződött a 6. koalíció: porosz-orosz-osztrák megállapodás.\n\n• Francia győzelem először (Drezda, 1813. augusztus 27.).\n\n• A „népek csatájában” már a szövetségesek győztek (Lipcse, 1813. október 16-18.).\n\n• Napóleon visszavonult, a szövetségesek 1814. március 31-én bevonultak Párizsba. 1814-ben a győztes hatalmak lemondatták, és Elba szigetére száműzték.\n\n• 1814. május 30-án Franciaországgal megkötötték a párizsi békét: az 1792-es határokat állították vissza; jóvátételt nem kellett fizetnie; visszakapta gyarmatait.\n\n• A Bourbonok visszatérése után (XVIII. Lajos), kihasználva a bécsi kongresszus vitáit és a franciák nosztalgiáját, Napóleon 1815. március közepén visszatért Elba szigetéről.\n\nA visszatérés hírére megszerveződött a 7. koalíció 1815-ben.\n\n• A Wellington vezette angol seregek a Blücher vezetésével megérkező poroszok segítségével legyőzték Napóleont (1815. június 18. Waterloo), akit ezután Szent Ilona szigetére száműztek, ahol brit fogságban halt meg.\n\nA bécsi kongresszus és a Szent Szövetség\n\nMetternich szervezésében az 1814-15-ös bécsi kongresszus feladata volt, hogy a forradalmi és napóleoni háborúk után helyreállítsa a régi rendet Európában. A rendezés egyik alapelve a történelmi dinasztiák hatalmának helyreállítása volt.\n\nMásrészt egy újabb forradalmat és forradalmi háborút akartak elkerülni. Éppen ezért a forradalom által kikényszerített társadalmi átalakulást sehol sem vonták vissza: ahol bevezették, ott megmaradt a jobbágyfelszabadítás, a jogegyenlőség, a szabad földtulajdon, a vállalkozási szabadság stb.\n\nA területi rendezés célja a hatalmi egyensúly helyreállítása és fenntartása volt, ezért nem engedték Franciaországot meggyengülni, sem Oroszországot megerősödni.\n\nFranciaország csak a hódításait veszítette el, de a határain elhelyezkedő kis államokat megerősítették: Belgiumot Hollandiához csatolták, Piemontot megnövelték.\n\nOroszország megkapta Lengyelország nagy részét (kongresszusi Lengyelország), Finnországot és Besszarábiát.\n\nA Habsburg Birodalmat Itáliában (Velence, Lombardia), Poroszországot pedig a Rajna-vidéken kárpótolták az elvesztett lengyel területeikért. Nagy-Britannia tengeri hatalmát erősítette Fokföld és Málta megszerzésével.\n\nA tartós rendezés másik eleme egy állandó politikai-katonai szervezet, a Szent Szövetség létrehozása volt.\n\nAz osztrák, a porosz és az orosz uralkodó alapította, de később Nagy-Britannia (és az Oszmán Birodalom) kivételével minden európai állam csatlakozott. A tagállamok közösen próbálták meg elfojtani a leendő forradalmakat, ezért mindenhol bevezették a cenzúrát, és felállították a titkosrendőrséget. A nemzetközi helyzetet gyakori konferenciákon értékelték, és forradalom esetén valamelyik nagyhatalom jogot kapott a katonai beavatkozásra (az Ibériai-félszigeten Franciaország, Itáliában a Habsburg Birodalom, Németországban Poroszország).\n\nA Szent Szövetség ugyanakkor kollektív biztonsági rendszerként alkalmas volt az európai hatalmi egyensúly megőrzésére is: a 19. század első felében nem volt háború a nagyhatalmak között. A nagyhatalmak céljai:\n\n• Anglia: tengeri fölény és a kereskedelmi pozíciók megtartása, egyensúly a kontinensen;\n\n• Oroszország: megszerezni egész Lengyelországot;\n\n• Poroszország lemond lengyelországi területeiről, ha megkapja Szászországot;\n\n• Ausztria: egyensúly Európában, amelynek központi eleme, egy erős Habsburg Birodalom.\n\nA kongresszus határozatai során 3 elv érvényesült:\n\n1. dinasztizmus: a régi dinasztiák visszanyerték hatalmukat (restauráció);\n\n2. kontinentális egyensúly: Franciaország és Oroszország között egy megerősödött Poroszország és Habsburg Birodalom;\n\n3. Franciaország féken tartása: Franciaország határainál ütközőállamok sora (Németalföldi Királyság, Poroszország a rajnai tartományokkal, semleges Svájc, Szárd-Piemonti Királyság).\n\n• Anglia megszerezte Máltát és Ceylon szigetét.\n\nOroszország megkapta Lengyelország nagy részét, továbbá megtartotta Finnországot és Besszarábiát. Poroszország megkapta a Rajna menti területeket, a Szász Királyság felét és svéd Pomerániát, Ausztria megkapta Velencét, Triesztet és Dalmáciát.\n\n• 2 új állam is létrejött: Luxemburg és a Krakkói Köztársaság.\n\nSZENT SZÖVETSÉG\n\n1815. szeptember 26-án I. Sándor orosz cár, I. Ferenc osztrák császár és III. Frigyes Vilmos porosz király aláírt egy nyilatkozatot, amelyben kifejtették a vallás szent elveit és a testvéri összefogás szükségességét a politikában: ez a Szent Szövetség.\n\n1815. november 2-án orosz-osztrák-porosz-angol „Négyes Szövetség” létrehozása - az aláírók meghatározott időközökben találkozókat rendeznek, ahol megtárgyalják és megoldják a felmerülő kérdéseket. A Négyes Szövetség tagjai egy pár évig a megállapodásnak megfelelően tanácskoztak és döntöttek:\n\n• Első ülésük 1818. Aachen: Franciaország csatlakozik a szövetséghez (XVIII. Lajos).\n\n• Második ülésük 1819. Karlsbad: német területek diákmozgalmainak megfékezése.\n\n• 1820-21: Troppau és Laibach: nápolyi alkotmányos mozgalom megfékezése.\n\n• 1822. Verona: a spanyol alkotmányos mozgalom megfékezésére francia csapatokat küldtek.\n\nGörög szabadságharc (1820-21)\n\n• 1821-ben kezdődött a görögök szabadságharca, amelyben a nagyhatalmak a görögök oldalára álltak, és segítségükkel a görögök győztek a törökök ellen.\n\n• 1830-ban a londoni konferencián független királysággá nyilvánították Görögországot.\n\nDekabrista felkelés (1825) Oroszországban: I. Miklós kegyetlenül leverte.\n\nA „Szent Szövetség”, vagy inkább a nagyhatalmi Ötös Szövetség az 1820-as évek elején elég jól működött, a forradalmi jellegű mozgalmakat, ha kellett, erővel, de elfojtották.\n\n1830-ban azonban forradalmi megmozdulások kezdődtek.\n\n• Franciaország: „júliusi forradalom” - július 27-29.: a párizsi munkások, értelmiségiek, polgárok felkelése elsöpörte Bourbon X. Károly (1824-1830) uralmát, és Lajos Fülöpöt választották királlyá (1830-48).\n\n• Belgium: függetlenedés a Németalföldi Királyságtól (1830. október 4-én).\n\n• Lengyel területeken felkelés kezdődött a cári hatalom ellen: a lengyelek kinyilvánították függetlenségüket (1831. január 25.), de az orosz csapatok 1831. május 14-én Osztrolenkánál legyőzték a lengyel seregeket, ezután Paszkievics nagyherceg bevonult Varsóba.', 135, 1, '2026-04-17 09:41:02', '2026-04-17 09:41:02');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(24, 24, 'A XIX. század eszméi', '24.docx', '24. tétel: A XIX. század eszméi\n\n(liberalizmus, nacionalizmus, konzervativizmus, szocializmus)\n\nA XIX. századi liberalizmus és konzervativizmus\n\nmindkét eszme Nyugat-Európában született,\n\nkeletkezésük a XVIII - XIX. századhoz kapcsolódik.\n\nA LIBERALIZMUS\n\nA XIX. századi liberális eszme fő elemei:\n\naz egyén fontos szerepe, a tolerancia, az egyenjogúság hangsúlyozása,\n\naz állam háttérbe szorulása (éjjeliőr szerep), hiszen szabadversenyes kapitalizmus van\n\na liberalizmus alapja a szabadságeszmény.\n\nA liberalizmus kialakulása összefüggött a kor társadalmi változásaival, a forradalmi mozgalmak segítették terjedését.\n\nA liberalizmus kialakulása összefüggött még a felvilágosodás eszmerendszerével.\n\nA francia forradalom, illetve a napóleoni háborúk segítették terjedését.\n\nA liberális eszme elfogadja az eltérő nézeteket, a különböző életformákat. Egyik képviselője az angol John Stuart Mill:\n\n„Hasznos az, ha eltérő nézetek léteznek, ha szabad teret kapnak a legkülönbözőbb jellemek, míg másoknak nem ártanak, ha mindenki a gyakorlatban próbálja ki a különböző életformák értékét.” (J.S.Mill)\n\nA tolerancia alapja a szabadságeszmény.\n\nA szabadság korlátja a másik ember szabadságának tiszteletben tartása.\n\nA liberális eszme egyik fő eleme az emberek közötti egyenlőség, az egyenjogúság hirdetése pl. választójog megadása, férfi és nő közötti egyenjogúság.\n\nA liberalizmus nem hisz a hagyományokra, erős államra épülő közösségben.\n\nA liberalizmus az egyén szerepét, illetve az ésszerűséget tarja fontosnak.\n\nFontos számára a szabadság és felelősség kapcsolata.\n\nSzabályozza a kormányzati hatalomhoz való viszonyt: az állam szerepét korlátozza.\n\nA liberalizmus a szabad verseny híve - ennek hátterében a kapitalizmus állt.\n\nA 19. századi politikai irányzatai a francia forradalom eszméiből alakultak ki, amelyek átalakították Európa feudális társadalmi berendezkedését. A napóleoni háborúk felélesztették az európai népek nacionalizmusát is. A „szabadság, egyenlőség, testvériség” jelszava, a francia forradalmi eszmék beépültek az európai polgárság politikai törekvéseibe. A bécsi kongresszus (1814–1815) szellemisége ókonzervatív volt ezzel szemben. A kialakuló Szent Szövetség rendszere az 1789 előtti állapotokat szerette volna restaurálni, így a Metternich által működtetett titkosrendőrség és cenzúrahivatal korlátozta a polgári szabadságjogokat, illetve a sajtószabadságot. A liberalizmus politikai áramlata a szabadságeszme megteremtését tűzte ki célul a 19. század első felében. A szabadelvű gondolkodók a felvilágosodás eszméit fejlesztették tovább. Céljuk: a polgári állam megteremtése.\n\nEgyéni szabadságjogok: a tulajdonhoz való jog, a szólás- és véleménynyilvánítási szabadság, a vallásszabadság.\n\nTársadalmi és politikai szabadságjogok: gyülekezés szabadsága, sajtószabadság, parlamentnek felelős kormány.\n\nA 19. századi liberálisok szerint csak a művelt és megfelelő anyagi háttérrel rendelkező polgárság tud működőképes demokráciát kialakítani. Úgy vélték, a polgári állam kiépülése megteremti az alsóbb rétegek felemelkedését, ezután kibővülhet a politizálók köre.\n\nKONZERVATIVIZMUS\n\nA XIX. századi konzervatív eszme fő elemei:\n\naz állam, a vallás, a hagyományok és a közösség meghatározó szerepe,\n\naz egyenjogúság elutasítása,\n\na konzervativizmus óvatos a változásokkal kapcsolatban.\n\na konzervativizmus a forradalmi, liberális eszmék terjedésének ellensúlyozásaképpen alakult ki.\n\na konzervatív eszme a kor nagyhatalmi politikájának is alapját képezte (Szent Szövetség).\n\nMindkét eszme alapelveinek kialakulása összefüggött az ipari forradalom gazdaság-és társadalomalakító tényezőivel, ezért ezek az eszmék meghatározói lettek a XIX. századi pártrendszerek megszületésének.\n\nA konzervatívok (pl. Edmund Burke) a mérsékelt politikai átalakítás hívei, mert a túl nagy változások erőszakhoz, forradalomhoz, terrorhoz vezetnek. Szerintük a múlt értékeinek beépítésével is lehet reformokat végrehajtani. és a franciák hibát követnek el, amikor semmibe veszik a több évszázados hagyományokat. A társadalom és az állam szerves fejlődésében való hit – a „megőrizve, megújítani” gondolat – állt Burke elképzelésének középpontjában, és az általa kidolgozott elméletrendszer a konzervativizmus ideológiai alapja lett, mely a 19. század első felében jelent meg. A „fontolva haladás” a hagyományokra hivatkozott, és mérsékelt reformokat szorgalmazott. Ez a szemléletmód sokban eltért a Metternich által képviselt, a változtatásokat ellenző ókonzervatív irányzattól.\n\nNACIONALIZMUS:\n\nA nacionalizmus lényege a nemzeti összetartozás-tudat, a XIX. század első felében keletkezett, bontakozott ki Európában és Amerikában. A nemzeti eszme forradalmi volt. A nacionalizmus összekapcsolódott a liberalizmussal, a szabadsággal és a függetlenséggel.\n\nA nacionalizmus főbb jellemzői és céljai: nemzeti eszme (náció = nemzet)\n\na nacionalizmus a francia forradalom hatására (és ellenhatására) kialakult politikai eszme. Franciaország egyszerre volt minta és ellenségkép.\n\nA nacionalizmus teremti meg a modern nemzetet.\n\nA nacionalizmus termékenyítő hatással volt a nemzeti kultúrára.\n\nA nacionalizmus célja a nemzetállam létrehozása volt, pl. ez egyesítési vagy függetlenségi mozgalmak a nacionalizmus jegyében jöttek létre.\n\nAz államhatalmat a nemzettől és nem az uralkodótól eredeztette.\n\nA későbbiekben konfliktusokat okozott a nemzetek között.\n\nKapcsolatban áll a liberalizmussal:\n\nközös céljuk volt az állampolgárok, azaz nemzettársak jogegyenlősége;\n\nközös céljuk volt az alkotmányos állam / népszuverenitás / ellenőrzött hatalom.\n\nA nacionalizmus a XIX. század első felében tehát összefonódott a liberalizmussal. Mindkettő forradalmi eszme.\n\nMazzini szerint a nemzetet összetartó kapcsok: a közös nyelv és kultúra; közös terület; közös történelem.\n\n„Huszonegy-huszonkétmilliós nép vagyunk, melyet emberemlékezet óta ugyanazzal a névvel illetnek, az olasz névvel, melyet az Isten által valaha húzott legpontosabb természetes határok, zárnak körül, mely ugyanazon nyelvet beszéli. Ugyanazon hitet vallja, melynek ugyanazok a szokásai és hagyományai, […] amely büszke Európa szerte ismert politikai, tudományos és művészeti múltjára.” (Giuseppe Mazzini: Itália,1845)\n\nA nacionalizmus a nemzetet „öröktől” létezőnek tartotta. A nacionalizmusban nagy szerepe volt a „nemzeti dicsőségnek” pl. a franciák dicsőséges forradalma és terjeszkedése. Franciaországban ennek nemzeti jelképe a trikolór. A forradalmárok képviselik a nemzet tagjait. Pl. Delacroix: A szabadság vezeti a népet, 1830 című festményén egy nőalak harcba hívja a franciákat, mely a szabadságot jelképezi. A művészetek fontos szerepet játszottak a nemzeti eszme elterjedésében.\n\nMagyarországon a nacionalizmus és a liberalizmus együtt jelenik meg. „Jelszavaink valának: haza és haladás.” (Kölcsey) A két eszme jegyében születtek a reformkori költemények: Kölcsey Ferenc: Himnusz, Vörösmarty Mihály: Szózat; nemzeti drámánk Katona József: Bánk bán, melynek Erkel Ferenc komponálta az operaváltozatát, ezt mutatták be 1848. március 15-én.\n\nAz újfajta nemzeti eszme, a nacionalizmus a napóleoni háborúk alatt bontakozott ki Európában. Mindenhol háttérbe szorult a rendi nemzetfelfogás, amely évszázadokon keresztül csak a kiváltságosakat tekintette a nemzet részének. A kibontakozó mozgalmak széles körű nemzeti megújulást hirdettek (például nyelvújítás, irodalom, képzőművészet). A nemzet felemelésébe beletartozott a közös azonosságtudat (identitás) kialakítása, a történelmi múlt feltárása és újraértelmezése. A soknemzetiségű, idegen dinasztiák által irányított birodalmak népei sokszor a másikkal szemben is meghatározták magukat, és a történelmi gyökereket gyakran hamis színben tüntették fel. A nacionalizmus változatai:\n\na nemzet nagyságát hirdető franciák\n\na soknemzetiségű birodalmak népeinek nemzeti törekvései\n\naz egységesítés igénye a több uralkodó fennhatósága alatt álló olaszok és németek estében.\n\nA SZOCIALIZMUS ESZMÉJE\n\nA szocializmus (latin socius = társ) olyan eszmei áramlatok, politikai ideológiák összessége, melyek először a 19. század folyamán jelentek meg, közös elemük az individualizmusnak, a magánérdek elsődlegességének elvetése, a kollektivizmus, a társadalmi egyenlőség, a szolidaritás előtérbe helyezése. A szocializmus magában foglal egy gazdasági programot – a termelési eszközök fölötti társadalmi ellenőrzés valamilyen formáját –, szociális követeléseket – társadalmi egyenlőséget, az anyagi javak igazságos elosztását – és politikai célokat – a demokrácia megvalósítását, kiszélesítését akár hagyományos parlamenti, vagy közvetlen formájában.\n\nA legáltalánosabb értelemben szocialistának nevezhetünk minden olyan törekvést, amely a társadalmi berendezkedést a szociális igazságosság szemszögéből kísérli meg átalakítani, függetlenül attól, hogy eszmeileg a marxizmus, az anarchizmus, a szociáldemokrácia vagy a keresztényszocializmus áramlatát követi.\n\nA szocializmus, mint politikai ideológia megnevezése az 1830-as években alakult ki. Először Robert Owen követőit nevezték szocialistának (1827), majd Saint-Simon követőit is ehhez az irányzathoz sorolták. Kezdettől fogva több meggyőződést foglalt magában, mint szellemi áramlat, politikai ideológia és mozgalom rendkívül változatos formákat hozott létre.\n\nKözös elemek:\n\nBírálták a kapitalizmust.\n\nAz egyenlőséget és az igazságosságot hirdették.\n\nUTÓPISTA SZOCIALISTÁK:\n\nA szocialista tanokkal először az utópista szocialisták, főként Saint-Simon (1760-1825), Charles Fourier (1772-1837) és Robert Owen (1771-1858) foglalkoztak, akik a termelés közösségi szintre történő emelését tartották a legjobb megoldásnak.\n\nSzolidárist vállalnak a munkásokkal, a munkások helyzetén szeretnének javítani egy ideális társadalom létrehozásával, aminek megvalósulása valójában utópia.\n\nVagyoni egyenlőségre és a verseny kiiktatására törekedtek zárt közösségek létrehozásával. Pl. Owen New Lanark-i gyára, Fourier falansztere – de ezek az elméletek életképtelenek voltak a gyakorlatban, ezért nevezzük őket utópistáknak. A gazdaság fejlődése a versenyen alapult, tehát nem lehet kiiktatni.\n\nA társadalmi problémákat a magántulajdon korlátozásával és a közösség, az állam szerepének növelésével akarták megoldani.\n\nFourier a falansztere kiküszöbölhetné az elidegenedést, melyben a termelékenység és az elosztás is egy humánus társadalmat eredményezhetne, a nők egyenjogúsítását is alapvető feladatnak tekintette.\n\nOwen gyakorlati megoldásokkal kísérletezett, üzemeiben szociálpolitikai reformokat, emberhez méltó körülményeket vezetett be például munkavédelem, oktatás, nevelés, magasabb bérek, mérsékelt árú termékek forgalmazása a dolgozóinak.\n\nSaint-Simon a tudósokra (szellemi vezetőkre) és az iparosokra (anyagi erőkre) bízná a társadalom vezetését.\n\nMARXIZMUS\n\nA társadalmi igazságtalanságok fokozódása életre keltette azokat az eszméket, amelyek egy harmonikusan működő, egyenlőségen alapuló társadalmat képzeltek el. A szocialista eszmék a közösségi szemléletmód kialakításában, az önző egyéni törekvések háttérbe szorításában látták a megoldást. Az elképzelések szerint igazságos társadalmat csak a magántulajdon felszámolásával, a piac és pénzforgalom megszüntetésével, valamint a javak közös elosztásával lehet teremteni. A legátfogóbb elméleti rendszert Karl Marx és Friedrich Engels dolgozta ki a 19. század közepén. A kialakítandó kommunizmust egy olyan ideális társadalmi rendszernek írták le, ahol már nem létezik államhatalom Ebben a rendszerben „mindenki képességei szerint” dolgozik, továbbá „mindenki szükségletei szerint” részesül a közös tulajdonból. Az ideológia hadat üzent a fennálló politikai rendszereknek, és radikális társadalmi forradalmat hirdetett. A Kommunista kiáltvány (1848) szerint a történelmet állandó osztályharcok jellemzik, mindig voltak elnyomók és elnyomottak; és az újkorban a proletariátus és a burzsoázia (polgárság) közötti ellentét a legélesebb.\n\n„Kísértet járja be Európát – a kommunizmus kísértete. […] Minden eddigi társadalom története osztályharcok története. Szabad és rabszolga, patrícius és plebejus, báró és jobbágy, céhmester és mesterlegény, egyszóval: elnyomó és elnyomott folytonos ellentétben álltak egymással, szakadatlan… harcot vívtak, olyan harcot, amely mindenkor az egész társadalom forradalmi átalakulásával vagy a harcban álló osztályok közös pusztulásával végződött […]. A mi korszakunkat, a burzsoázia korszakát azonban az jellemzi, hogy egyszerűsítette az osztályellentéteket. Az egész társadalom mindinkább két nagy ellenséges táborrá szakad, két nagy, egymással homlokegyenest szembenálló osztályra: burzsoáziára és proletariátusra. […] Amilyen mértékben a burzsoázia, azaz a tőke fejlődik, ugyanolyan mértékben fejlődik a proletariátus, a modern munkások osztálya, akik kénytelenek eladni magukat, éppen olyan áruk, mint minden egyéb kereskedelmi cikk. A burzsoázia pusztulása és a proletariátus győzelme egyaránt elkerülhetetlen.” (Marx Kommunista kiáltványa, 1848)\n\nA kommunista eszme radikális volt, mert kíméletlen harcot hirdetett a burzsoázia, mint elnyomó társadalmi osztály ellen. A munkásosztály (proletariátus) egy szocialista forradalommal proletárdiktatúrát vezetne be, ennek során megszüntetné a tőkés magántulajdont, és felszámolná a burzsoázia hatalmát. Marx elvetette a hagyományos zsidó-keresztény világképet, és materialista (azaz csak az anyagi világ létezését elfogadó) elveket vallott. A létező kapitalizmusban szerintük az ember „elidegenedik” az alkotómunkától. Az elidegenedés mellett a másik ember általi kizsákmányolás lépett a közösségi kapcsolatok helyére. Marx és Engels szerint a kapitalizmus tönkretette az emberi természetet, ami az általuk elképzelt kommunista társadalomban az elidegenedés és a kizsákmányolás megszüntetésével magára találna.\n\nMarx és Engels a kommunizmus ideológiáját komoly filozófiai, történelmi és közgazdasági érvekkel próbálta alátámasztani. A marxizmus 3 forrása:\n\nA klasszikus német filozófiát, Hegel dialektikáját is beépítették: tézis-antitézis-szintézis, a világ az ellentétek harca. Marx úgy fejlesztette ezt tovább és fordította meg, hogy „a lét határozza meg a tudatot”. A történelmet osztályharcok történelmének tartotta. Magasabb rendű osztálytársadalmak jönnek létre a régi társadalmak romjain. Szerinte a kapitalizmus pusztulása után megvalósul az osztály nélküli társadalom. Cél: az államhatalom megszerzése, amely a proletariátus kezébe kerül majd forradalom útján. Ő a legfejlettebb kapitalista államban, Angliában képzelte ezt el, ahol a legnagyobb számú munkásréteg élt.\n\nAz angol Smith és Ricardo közgazdasági tanai is hatottak a marxizmusra. A politikai gazdaságtan képviselői a burzsoázia szemszögéből igazolták a tőkés termelési módot, de kritizálták is annak ellentmondásait: munkaérték-elmélet.\n\nHarmadik forrása az utópista szocializmus, melynek gondolkodói látták a munkásosztály nyomorát és a burzsoázia egyre növekvő gazdagságát, s megkísérelték megtalálni a kivezető utat a kapitalizmus ellentmondásaiból.\n\nMarx főműve, A tőke (Das Kapital), melynek első kötete 1867-ben jelent meg. Marx abból indult ki, hogy a kapitalizmusban a tőkés a bérmunkás erejét piaci értéken vásárolja meg, majd a bérmunkást arra készteti, hogy értékének többszörösét állítsa elő pl. munkaideje meghosszabbításával, munkatempója növelésével. A munkások kizsákmányolását Marx közgazdasági alapokon vizsgálta a problémát, és azt igyekezett bizonyítani, hogy a kizsákmányolás és a tőkés rend bukása fog elkövetkezni. Az ideális társadalom megteremtéséhez szükség van egy átmeneti, politikai korszakra, ezért a szocializmust két szakaszra bontotta. Az első szakaszban, a szocializmusban még jelen van az állam és a jog, az elosztás a végzett munkateljesítmény alapján történik, még nem szűntek meg a társadalmon belüli egyenlőtlenségek. A következő szint kommunizmus, ahol már a szükségletek szerinti elosztás rendszere dominál. Egyúttal megszűnik az állam, a pénz, a piac.\n\nA második ipari forradalom során a gazdasági és társadalmi átalakulás több problémát is a felszínre hozott, amelyek kezelésére mind radikálisabb megoldási javaslatok születtek. A meglévő társadalmi egyenlőtlenségek, a kapitalista gazdálkodás árnyoldalai megerősítették a szocialista eszmék továbbélését. Európa-szerte számos baloldali szervezet jött létre, miközben a Marx és Engels által kidolgozott kommunista ideológia a 19. század második felében politikai erővé vált. Az általuk alapított nemzetközi munkásmozgalom (első Internacionálé, 1864) megpróbálta összefogni a baloldali munkáspártokat. Az egységes fellépést azonban megakadályozták a belső politikai ellentétek, a különböző frakcióharcok.\n\nAz 1917-es októberi orosz forradalom nyomán Oroszországban, a Szovjetunióban, majd a II. világháború végén, 1945 után a keleti blokk országaiban és másutt kiépült marxista –leninista autoriter politikai rendszerek hivatalosan szintén szocialistának tekintették magukat. A marxizmus harcos ateizmusa a 20. században egyház- és vallásüldözésbe fordult, és a kommunista ideológia gyakorlati megvalósítása véres diktatúrák kialakulásához vezetett. A hatalomra kerülő kommunista pártok mindenhol erőszakos eszközökkel törekedtek céljaik megvalósítására. A proletárdiktatúrák felszámolták az alapvető szabadságjogokat, és terrorisztikus uralmat építettek ki. A kommunista diktátorok a marxi utópisztikus társadalomkép nevében több tízmillió ember halálát okozták a 20. században.\n\nANARCHIZMUS\n\nA XIX. század 2. felében kialakuló anarchista mozgalom a kommunisták befolyását veszélyeztette. Az anarchizmus (hatalomnélküliség) szintén a társadalmi igazságtalanság ellen hirdetett harcot. A mozgalom forradalommal akarta eltörölni a fennálló rendszert. Ideológusai elvetették a proletárdiktatúrát, mivel úgy vélték, a kommunista párt kisajátítja majd a hatalmat. Az anarchisták egy önszerveződő, nemzetek feletti, állam nélküli társadalmi modellben gondolkodtak. Bár az anarchizmus főbb ideológusai elvetették az egyéni terrort, a 19. században az anarchisták a politikai gyilkosságokkal váltak ismertté. Az általuk elkövetett merényletek célpontjai a hatalomhoz köthető személyek voltak (például Erzsébet osztrák császárné és magyar királyné meggyilkolása Genfben). Az ideológiai viták miatt Marx elérte az anarchista mozgalom kizárását a munkásmozgalomból.\n\nSZOCIÁLDEMOKRÁCIA\n\nA nyugat-európai országokban a munkáspártok mérsékelt irányba fordultak, elvetették a hatalom erőszakos megragadását, és túlzottnak vélték az osztályharc erőltetését. A kialakuló szociáldemokrácia továbbra is a marxi elképzeléseken alapuló társadalmi igazságosság mellett állt ki, de annak megteremtését demokratikus úton képzelte el. Elutasította az osztályharcot, és legfőbb követelései az általános választójog bevezetésére, a parlamenti többség kialakítására, és a szociális intézkedések meghozatalára irányultak. A baloldali mozgalmon belül hamarosan újabb szakadás következett be, a kommunista ideológusok megalkuvónak tartották a szociáldemokratákat. A közösen megfogalmazott alapcélok (például a nyolcórás munkaidő követelése; május 1-jét a munka nemzetközi napjává nyilvánították) ellenére sem tudta a második Internacionálé a mozgalom egységét visszaállítani (1889).\n\nA KERESZTÉNYSZOCIALIZMUS\n\nAz egyház is reagált a változásokra. A 19. század utolsó harmadában gyökeresen átalakult a nyugati kultúrkör értékrendszere, a világról alkotott elképzelése. A tudományos ismeretek bővültek. Pl. Charles Darwin evolúciós elmélete (A fajok eredete, 1859) és az ember származásáról szóló műve (1871), majd az ősrégészet eredményei új megvilágításba helyezték a bibliai teremtéstörténetet.\n\nA világias nézetek terjedése minden egyházat érintett. A kiépülő polgári államok több feladatot átvettek az egyházaktól például oktatás, kötelező polgári házasság.\n\nA katolikus egyház vezetője, IX. Pius pápa hiába foglalta jegyzékbe a hívők számára az általa tévedésnek tartott eszméket (például ateizmus, szocializmus, kommunizmus, liberalizmus stb.), a folyamatot ez csupán lassította.\n\nA munkáskérdés megoldását sürgető „szociális katolicizmus” német területen bontakozott ki az 1860-as években. Az iparosodás társadalmi-szociális problémáira XIII. Leó (1878–1903) reagált az egyik nagy hatású körlevelében, a Rerum Novarumban, 1891-ben.\n\nA XIII. Leó pápa védelmébe vette a munkásságot, jogosnak ismerte el törekvéseiket, és méltányos bérezést sürgetett. A kibontakozó keresztényszocialista mozgalom az egyház szociális tanításának megvalósítását, az iparosodás során leszakadó társadalmi rétegek emberséges megsegítését tűzte ki célul. A keresztény alapokon álló mozgalom elutasította a liberalizmust, és felemelte szavát az ateizmust hirdető marxizmussal szemben: „Ha a társadalmi törvényeket a hit szilárd alapjára építjük, akkor nyitva áll az út a társadalmon belüli viszonyok helyes elrendezése, a békés együttélés és a virágzó jólét biztosítása felé.”', 93, 1, '2026-04-17 09:41:02', '2026-04-17 09:41:02');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(25, 25, '', '25.docx', '25. tétel:\n\nPolitikai eszmék és pártrendszer a dualizmus kori Magyarországon\n\nPOLGÁRI ÁLLAM A DUALIZMUS IDEJÉN\n\nA kiegyezés elfogadásakor (1867) kétközpontú államalakulat, a dualista Osztrák-Magyar Monarchia jött létre. Az államforma alkotmányos monarchia lett, a neoabszolutista berendezkedést felszámolták. A két tagállam az uralkodó személye és a közös ügyekre létrejött közös minisztériumok (külügy, hadügy és ezek fedezésére szolgáló pénzügy) útján kapcsolódott egymáshoz, minden más kérdésben független volt.\n\nA közös ügyek minisztériumainak alkotmányos felügyeletét a 60-60 főt számláló delegációk látták el, amelyek a két törvényhozás képviselőiből álltak össze és egymástól elkülönülve tanácskoztak, hogy megakadályozzák egy birodalmi gyűlés létrejöttét, amely veszélyeztette volna a fennálló rendszert.\n\n1867-ben létrejött a második független, felelős kormány Andrássy Gyula miniszterelnökletével. A kialakult parlamentáris rendszer a Montesquieu-féle hatalommegosztás elvén szerveződött.\n\nA kétkamarás népképviseleti törvényhozás alsó- és felsőházból állt. Az uralkodó és az országgyűlés szorosan együttműködött a törvényhozásban, visszaállították a neoabszolutizmus korában felfüggesztett szakminiszteri ellenjegyzés intézményét. Az uralkodónak előszentesítési joga volt. A kormány mint végrehajtó szerv a parlamentnek volt felelős. 1869-ben a közigazgatást elválasztották a bíráskodástól, így létrejött a három független, de egymást ellenőrző hatalmi ág.\n\nMagyarországon a polgári állam létrejöttét az 1867-es kiegyezés tette lehetővé, kialakulása összefüggött a polgári átalakulással, a rendiség felszámolásával, eszmei hátterét a liberalizmus jelentette, alapjait az 1848-as áprilisi törvények teremtették meg.\n\nA dualizmus kora 1867-től 1918-ig tartott. A polgári állam kiépülése a XIX. század utolsó évtizedeire tehető. A polgári állam kiépülése Magyarországon nyugati mintát követett.\n\nA polgári államra jellemző politikai rendszer alapvető összetevője: alkotmány, hatalommegosztás, a szabadságjogok biztosítása, jogegyenlőség.\n\nA dualista monarchia Magyarországán a kiegyezés után, illetve az 1890-es években születtek a legjelentősebb reformok, és egyre erőteljesebben érvényesül területileg is az önálló magyar kormány akarata.\n\nReformok pl. az állami anyakönyvezés bevezetése, az izraelita vallás bevetté nyilvánítása, a közigazgatás és az igazságszolgáltatás teljes szétválasztása, az igazságszolgáltatás reformja, a rendőrség és a csendőrség megszervezése, a közegészségügy megszervezése.\n\nAz állam szerepe megnőtt, az állami hivatalok és hivatalnokok létszáma nőtt.\n\nAz egyházpolitikai reformok a kormánypárt tagjait is megosztották. A reformok kiváltották az egyházak és az uralkodó ellenkezését.\n\nAz izraelita vallás bevett vallássá nyilvánítása a zsidók emancipációját segítette elő.\n\nTöbb ember számára vált elérhetővé az egészségügyi ellátás.\n\nAz igazságszolgáltatás szakszerűbbé vált, hatékonyabb lett a rendfenntartás.\n\nAz 1870-es évektől érvényesülő szabadelvű politika (Tisza Kálmán 1875-1890 vezetésével) számos intézkedésével segítette a modern állam kiépítését, de a reformok felgyorsulása Wekerle Sándor miniszterelnökségéhez kapcsolódik. A változások nyomán vált a XX. század elejére modern polgári állammá Magyarország.\n\nA polgári típusú közigazgatás kiépülése összefüggött a dualista államon belüli önálló magyar belpolitikával. A vármegye élén a kormány álláspontját képviselő főispánok álltak jelentős hatáskörrel. Jogkörük a dualista rendszer idején folyamatosan bővült, ezzel is erősítve a helyi szintű állami befolyást.\n\nA felszámolt kiváltságolt területek: szász székek, székely székek, jász-kun kerület, Határőrvidék. Ez a rendiség felszámolásának, a polgári jogegyenlőség kiterjesztésének egy lépése volt, ezzel egységes megyerendszer jött létre.\n\nA közigazgatási változások az állam szerepének erősödését eredményezték. Pl. a polgári házasság és polgári anyakönyvvezetés jelentős lépés volt az állam és egyház szétválasztásában.\n\nA polgári házasság, az anyakönyvvezetés mellett más progresszív reformok is születtek, pl. vallások liberalizációja (bevett, elismert és el nem ismert vallások kategóriája). A törvényi szabályozás következtében elhárult az akadály a különböző nemzetiségek és vallások emancipációja elől.\n\nAz 1868-ban elfogadott Eötvös-féle népiskolai törvény mérföldkő a magyar oktatás történetében, és hatására nemcsak az általános művelődési szint emelkedett, hanem megteremtődtek a tudomány fejlesztésének legfontosabb feltételei is.\n\nAz 1868-as népiskolai törvény általánosan kötelezővé tette 12 éves korig a tankötelezettséget (az oktatás anyanyelven folyhatott). Ez a törvény szabadelvűen kezelte a nemzetiségi oktatást, és eredményesen hozzájárult az analfabétizmus megszüntetéséhez. A polgári államra jellemző az állampolgárokról való gondoskodás szándéka, az intézkedés következtében csökkent tehát az analfabéták száma, az állam iskolák építésével és a tanítóképzés megszervezésével biztosította a feltételeket.\n\nA reformok ellenére továbbra is jelentős maradt a konzervatív arisztokrácia befolyása és a dzsentri mentalitás „mintaképző” szerepe. A reformfolyamat sokat változtatott a korabeli Magyarországon, közelítette az országot Nyugat-Európa fejlettebb régióihoz.\n\nA lemaradást csak részben tudta felszámolni, és számos fontos társadalmi kérdést (nemzetiségi, föld, választójog) nem tudott kezelni.\n\nA dualista monarchia létrejötte megfelelő alapot teremtetett a modern állam és intézményeinek kiépítéséhez.\n\nA dualizmus kora\n\nA kiegyezési rendszer merevsége\n\n• A magyar politikai élet aszerint tagolódott, hogy ki fogadta el a kiegyezést (Deák-párt) és ki utasította el (ellenzéki pártok).\n\n• A kiegyezés egy végletekig kifinomított kompromisszum eredménye volt, amely igen rugalmatlanná tette a rendszert minden változtatással szemben. A legkisebb változtatás is a rendszer összeomlását eredményezhette volna, ezért Magyarországon mindig biztosítani kellett a kiegyezéspárti politika túlsúlyát, azaz a kormánypárt győzelmét. Ennek a technikái a következők voltak:\n\n- a választókerületeket nem lakosság-arányosán alakították ki, hanem úgy, hogy az általában kiegyezés-ellenes magyar lakosságú területeken kevesebb, a kiegyezés-párti vegyes etnikumú, vagy nemzetiségi területeken több kerületet hoztak létre;\n\n- általánossá tették a nyílt szavazást, így a kormány az erőszakszervezeteken, állami hivatalokon, vállalatokon keresztül (megfélemlítés, elbocsátással fenyegetés) befolyásolni tudta a szavazókat;\n\n- a választójognál megmaradt a vagyoni cenzus, ezzel a szegényebb, kiegyezés-ellenes rétegeket kizárták a választásokból.\n\nA kiegyezési rendszer rugalmassága\n\n• A közjogi kérdések merev szabályozottsága két módon volt oldható: az uralkodónak elég tág szerepe volt: törvényeket kezdeményezhetett, előszentesítési joga volt, ha kellett kisebbségi kormányt nevezhetett ki (ha „véletlenül” az ellenzék győzött a választásokon, pl. 1905-ben). Gazdasági, hadügyi, külpolitikai téren lehetőség nyílt a vitákra, amelyek levezethették a feszültségeket.\n\nA közjogi viszony és a pártok\n\nA magyar politikai pártok között az igazi törésvonalat kezdetben az Ausztriához, illetve a kiegyezéshez való viszony jelentette. Ez volt az úgynevezett közjogi kérdés. A mindenkori kormánypárt elfogadta, és optimálisnak tekintette az 1867-es rendezést, mert abban látta a magyarság vezető szerepének megőrzését. Az ellenzéki pártok elsősorban ’48 örököseinek tartották magukat, elvetették a közös ügyek rendszerét, és a perszonáluniós törekvések alapján nemzeti követeléseket is megfogalmaztak (például önálló magyar vámterület, nemzeti bank, magyar vezényleti nyelv a hadseregben). A Kossuth irányvonalát képviselő ’49-esek idővel feladták a teljes függetlenség eszméjét, és ők is a perszonáluniós megoldásban gondolkodtak.\n\n1867-ben az Andrássy-kormány hátországát Deák Ferenc pártjának (az egykori Felirati Párt) képviselői adták. Andrássy Gyulát azonban az uralkodó rövidesen közös külügyminiszterré nevezte ki (1871–1879 között), akinek távozásával a Deák-párt fokozatosan meggyengült. A folyamatot Eötvös József halála és Deák politikai visszavonulása is felgyorsította.\n\nA kiegyezésnél az ellenzéki pártok egyik erejét Tisza Kálmán vezette, aki a korábbi Határozati Pártot újjá szervezte Balközép Párt néven. Tisza felismerte a kormánypárt meggyengülését, de tudta, hogy a kiegyezést elvető pártprogrammal (az ún. „bihari pontok”) nincs lehetősége hatalomba kerülni. 1875-ben megtörtént Tisza Kálmán politikai váltása: feladta ellenzéki elveit, és a Balközép Párt képviselőinek egy részével belépett a Deák-pártba. Az így létrejött Szabadelvű Párt a következő évtizedek kormánypártja lett, amely rövidesen elsöprő választási győzelmet aratott, és Tisza Kálmánt Ferenc József miniszterelnökké nevezte ki. Mivel Tisza „szegre akasztotta a bihari pontokat”, azok az ellenzéki képviselők, akik a perszonáluniós elveikhez ragaszkodtak, önálló pártot alapítottak Függetlenségi Párt néven. Néhány évvel később szövetségre léptek a kossuthi irányvonalat valló erőkkel, ezzel kialakult a 48-as Függetlenségi Párt.\n\nTisza Kálmán hosszú miniszterelnöksége idején (1875–1890) a dualizmus rendszere megszilárdult Magyarországon. A Szabadelvű Párt mindig nagy fölénnyel nyerte meg a választásokat, az ellenzék látszólag nem jelentett alternatívát, és Tiszának a saját pártján belül sem akadt politikai vetélytársa. A kortársak által „generálisnak” nevezett miniszterelnök korszakát egyrészt politikai nyugalom, másrészt a gazdaság egyre látványosabb fejlődése kísérte. Az állami gazdaságpolitika hatékony intézkedésekkel alapozta meg az iparosodást.\n\n1890-ben az egyre népszerűtlenebbé váló Tisza Kálmán lemondott a miniszterelnöki tisztségéről, de a Szabadelvű Párt még másfél évtizedig megőrizte kormánypárti pozícióját. Tovább folytatódott a polgári állam kialakítása, amelynek során az egyház és az állam viszonyát is rendezni kívánták. Az úgynevezett egyházpolitikai törvényeket ádáz politikai harcok árán Wekerle Sándor miniszterelnöksége idején hozták meg. Kimondták a kötelező polgári házasságot, és bevezették az állami anyakönyvezést (1894). (A katolikus egyház korabeli konzervatív felfogása nehezen barátkozott meg a reformmal.) A következő évben a keresztény felekezetekkel egyenjogúsították az izraelita vallást, illetve kimondták a szabad vallásgyakorlást. (Az utóbbi két törvényt már Wekerle utódja, Bánffy Dezső idején fogadták el.)\n\nA belpolitikai viták kiéleződése\n\nMagyarországon a századfordulót követően súlyos belpolitikai válság alakult ki. Az ellenzéki pártok az obstrukció (a latin eredetű obstruo szó jelentése: ’megakaszt’) alkalmazásával megbénították a hatékony parlamenti munkát. Az ellenzék először már Tisza Kálmán idejében alkalmazta az obstrukciót, amellyel hosszú ideig döntésképtelenné vált az országgyűlés. Az obstrukciónak számos megjelenési formája volt. Az órákon át tartó parlamenti hozzászólások mellett a név szerinti szavazások, a házbizottsági ülések parttalan és meddő vitákat gerjesztettek. Ferenc József haderőfejlesztési javaslatára az ellenzék „kurucos” követelésekkel reagált (önálló vámterület megteremtése, a magyar vezényleti nyelv bevezetése a hadseregben, önálló nemzeti bank létrehozása). Már Tisza Kálmán tekintélyét is aláásta, hogy az uralkodó által javasolt haderőbővítés megszavazását az ellenzék hónapokon át meggátolta. Az elhúzódó úgynevezett véderővita keresztülvitelét a Szabadelvű Párt új, erős vezetője, a korábbi miniszterelnök fia, Tisza István akarta megoldani.\n\nTisza István miniszterelnökként (1903–1905) az obstrukció letörését, illetve a kormánypárt tekintélyének visszaállítását tűzte ki célul. A politikai közélet egyik legnagyobb botránya az úgynevezett „zsebkendőszavazás” volt. A házelnök, miután az egyik kormánypárti képviselő beterjesztette az obstrukció letörésére irányuló határozati javaslatát, nem adta meg az ellenzéki pártoknak a szót, hanem zsebkendőjével jelt adott a szavazásra. A tervezetet a Szabadelvű Párt képviselői megszavazták (1904. november). A közélet eldurvulását jelezte, hogy egy hónappal később az ellenzéki képviselők tiltakozásul szétverték az új ülésterem berendezését\n\nTisza reálpolitikusként értékelte a 20. század elején bekövetkezett külpolitikai változásokat, megérezte egy nagy háború közeledését. Úgy vélte, hogy a belső ellentétek meggyengítik a magyarság pozícióját az eljövendő konfliktusban. A legfontosabb nemzeti célnak Magyarország területi egységének (integritásának) megőrzését tartotta, ennek biztosítását egyedül csak a dualista rendszer fenntartásában látta. Az új miniszterelnök a legtöbb reformtörekvést (például az általános választójog bevezetését, a földosztást) belső bomlasztásnak tekintette, ezért elvetette a közélet további demokratizálását. Meggyőződése szerint minden elkapkodott és átgondolatlan reformkísérlet csökkentette volna az ország esélyeit a várható összecsapás során.\n\nTisza István kezdetben nem járt sikerrel. Miután megpróbálkozott az obstrukció korlátozásával, 1905-ben súlyos vereséget szenvedett a parlamenti választásokon. Magyarországon először fordult elő, hogy a közjogi kérdés felülvizsgálatát követelő ellenzéki pártokból álló koalíció több mandátumot szerzett a parlamentben. A belpolitikai élet megbénult, Ferenc József saját testőrparancsnokát (báró Fejérváry Géza tábornokot) nevezte ki miniszterelnöknek.\n\nAz új kormány rendelkezéseit azonban a megyei önkormányzatok nem hajtották végre, mindenki az ellenzéki koalíció hatalomba emelését követelte. Az államélet szétzilálódott, a „kötélhúzás” másfél évig eltartott. Végül kompromisszum született, az ellenzék feladta perszonáluniós törekvéseit, cserébe az uralkodó kinevezte Wekerle Sándort miniszterelnökké. A koalíciós kormány (1906–1910) sem alakította át a dualista berendezkedést, és nyilvánvaló lett, hogy az 1867-es alapokat nem lehet megváltoztatni.\n\nPártviszonyok a dualizmus 2. felében\n\nA választójog problémája\n\nA Szabadelvű Párt dominanciájában meghatározó szerepe volt a kialakított választási kereteknek. Az 1848-ban vagyoni, jövedelmi és műveltségi cenzus alapján megállapított választójogot 1874-ben szűkítették, majd gyakorlatilag a dualizmus végéig alacsony szinten tartották, így a lakosság alig több mint 6%-a szavazhatott. A kormánypárti képviselőjelöltek sikerét a nyílt szavazás, illetve a választókerületek egyenlőtlen beosztása is segítette. Titkos szavazásra, azaz ahol a választópolgárok nem egy választási bizottság előtt mondták el szavazatukat, csak kevés helyen volt lehetőség. Fontos kiemelni, hogy a népképviseleti elv alapján meghozott törvény természetesen a nemzetiségeknek is biztosított választójogot. Az 1874-es választójogi törvény elsősorban a magyar többségű területeken (például mezővárosokban) szűkítette a választójogot, ugyanis itt korábban a 48-as elveket valló ellenzéki politikusok értek el sikereket. (Például: míg a döntően nemzetiségek által lakott Alsó-Fehér vármegyében 532 választóra, addig Szegeden 4409 választóra jutott egy parlamenti mandátum.) Emellett a cenzus (földadóminimum) is területenként eltért, az ország többségében magyarlakta térségeiben magasabb volt, mint az ország peremterületein. Ebben az is szerepet játszott, hogy a magyarok nagy része polgárosodottabb, így vagyonosabb volt, mint például a ruszin lakosság.\n\nA 19. század végére az iparosodás során kialakuló nagyipari munkásság körében megindult a politikai szervezkedés. Igazi erővé a szakszervezetekre támaszkodó Magyarországi Szociáldemokrata Párt (MSZDP, 1890) révén vált. A baloldali párt programja rövid távon az ország további demokratizálását (általános választójog bevezetése, polgári szabadságjogok kiterjesztése), hosszabb távon a tőkés rendszer felszámolását és a szocializmus megteremtését tűzte ki célul. A párt országos hálózatot hozott létre, majd a századfordulótól a tömegpolitizálás eszközéhez, a sztrájkok és tüntetések szervezéséhez folyamodott. Budapest utcáin egyre gyakrabban lehetett látni vörös zászlóval vonuló tüntetőket, a tömegdemonstrációkon sokszor már több tízezren vettek részt.\n\nA baloldali párt mellett a nyilvánosság elé lépett egy fiatal értelmiségi nemzedék is, amely a fennálló társadalmi-politikai berendezkedést elavultnak, a politikai elitet a változtatások lebonyolítására alkalmatlannak tartotta. Az ország modernizálását, az „úri” Magyarország felszámolását sürgették, és egyre élesebb kritikát fogalmaztak meg a politikai vezető réteggel szemben.\n\nA közéletben a polgári radikálisok – Jászi Oszkár vezetésével – a hagyományos, történelmi magyar berendezkedést kívánták megszüntetni. Programjuk kiterjedt az általános választójog bevezetésére, a nagybirtokrendszer megszüntetésére és az 1868-as nemzetiségi törvény következetes betartására. A polgári radikálisok, illetve az értelmiség egy részének türelmetlen politikai álláspontja nem vagy alig vette figyelembe a fennálló bonyolult magyarországi viszonyokat.\n\nNyugat-Európa több országában a 19. század végére fokozatosan bevezették a férfiak általános választójogát. A Szabadelvű Párt vezetői továbbra is elutasították ezt, mert egyrészt aggasztották a magyar többségű választókerületek ellenzéki erőket támogató szavazatai, másrészt tartottak a nemzetiségi pártokra leadott szavazatoktól is. A Monarchia osztrák felében 1907-ben bevezették az általános választójogot a férfiaknak. Ennek következtében a bécsi birodalmi parlament mind politikailag, mind etnikailag egy rendkívül heterogén törvényhozó testületté alakult, és ingataggá vált az osztrák belpolitikai élet. Tisza István emiatt továbbra is határozottan elutasította a választójog kiterjesztését. Egyrészt tartott az általa befolyásolhatónak vélt szegényparaszti és munkásrétegek kiszámíthatatlan politikai döntéseitől, másrészt a nem magyar választópolgárok számának növekedésétől. Úgy vélte, hogy az alsóbb néprétegeket csak fokozatosan, például az alapműveltség kiterjesztésével lehet bevonni a közéletbe.\n\nTisza István politikája\n\nAz 1905. évi választási vereség szétzilálta a Szabadelvű Pártot, és Tisza István átmenetileg a háttérbe húzódott. A koalíciós kormányzás azonban gyorsan hitelét vesztette, így lehetősége nyílt a visszatérésre. Tisza István új pártot alapított, a Nemzeti Munkapártot, amely fölényes győzelmet aratott a következő választásokon (1910). Tisza előbb házelnökként (1912), majd miniszterelnökként (1913-1917) újra fellépett az obstrukciós politikát folytató ellenzékkel szemben. Személyét gyakran támadták, és Tisza többször párbajjal védte meg becsületét. Budapesten például, a „vérvörös csütörtökön” (1912. május 23.), Tisza István házelnökké választását követő napon a szociáldemokraták általános sztrájkot hirdettek, és tömegtüntetést szerveztek Budapesten. A tüntetés utcai zavargásokba torkollott, amelyek már halálos áldozatokat is követeltek.\n\nEközben fenyegetőnek tűnt, hogy a trónörökös, Ferenc Ferdinánd főherceg nyíltan hangoztatta a dualista rendszer iránti ellenszenvét, és a magyar befolyás visszaszorítására készült. Szemléletmódjában visszatért a Bécs-központú, de föderalizált birodalom képe. A magyarokkal szemben ellenséges trónörökös – román és cseh tanácsadói javaslatára – a Monarchia föderatív átalakítását tervezte, amely Magyarországot etnikai alapon is érintette volna. Nyilvánvaló volt, hogy az idős Ferenc József halála után nehezen lehet majd fenntartani az 1867-es alapokat. A kiegyezéshez ragaszkodó kormánypárti képviselők nyugtalanul figyelték a trónörökös politikai szándékait, maga Tisza István is borúlátó volt a Monarchia jövőjét illetően Ferenc Ferdinánd trónra lépése esetén.\n\nEközben a politikai közbeszéd a hadseregfejlesztés, a választójog kibővítése és a nemzetiségi kérdés körül forgott. Megszavazták az újonclétszám növelését, és felszerelték tüzérséggel a honvédséget. Tisza István politikai lépései előidézték a parlamenti ellenzék átszerveződését. A hagyományos közjogi erők mellett kialakult egy a radikális reformok felé hajló irányzat is. A Függetlenségi és 48-as Párt nyitott a polgári radikálisok, illetve a baloldal felé, felvette programjába az általános és titkos választójog követelését. A következő időszakban az ellenzék a parlamenti munkától való távolmaradással tiltakozott, és a kormánypárt egyik bírálója Károlyi Mihály gróf lett, aki átvette a Függetlenségi és 48-as Párt irányítását.\n\nAz ország számos megoldatlan belső problémával közeledett az első világháború felé. Az ellenzék a rendszer további demokratizálását sürgette, holott nem igazán vették számításba, hogy az általános választójog hogyan kedvezne a nemzetiségi pártoknak és a földreformot hirdető paraszti erőknek. Tisza István hatékonyabbá tette a törvényhozás munkáját, illetve bővítette a kormány jogkörét. Egyes lépéseit indokolhatja, hogy Tisza megérezte: a közeledő háború Magyarország megmaradását veszélyezteti.\n\nÖsszegzés:\n\nPártok a dualizmus idején\n\nA dualizmus korában a pártokat a parlamenti képviselők és a közigazgatásban működő tisztségviselők alkották. A pártoknak sem tételesen leírt programjuk, sem szervezetük, alkalmazott hivatalnokaik nem voltak. (A tagkönyv, a székház ismeretlen volt, egy-egy párt politikusai a párt fővárosi vagy helyi klubjában jöttek össze.) Mindig olyan párt volt kormányon, mely a dualizmus fenntartását hirdette, korabeli kifejezéssel élve \"67-es alapokon állt\". Az ellenzék legfontosabb pártja pedig mindig egy \"48-as alapokon álló\" párt volt, melynek nevében szerepelt is a \"48-as\" vagy a \"függetlenségi\" jelző. (A függetlenségi pártkörök körül negyvennyolcas olvasókörök, honvédegyletek, a Kossuth-kultuszt ápoló népkörök hálózata épült ki, egészen a falvakig.) A függetlenségi párt programjának lényege a közös ügyek és a közös hadsereg megszűntetése, a magyar vezényleti nyelvű és öltözékű hadsereg, esetleg magyar jegybank, önálló vámterület megteremtése, a kvóta lehető csökkentése volt. A birodalmon belüli közjogi helyzetet kívánták megváltoztatni (ezért nevezzük ezt közjogi ellenzékiségnek). Ez a közjogi ellenzék a társadalom valódi problémáival (választójog, nemzetiségi kérdés, szociális helyzet stb.) éppúgy alig foglalkozott a századfordulóig, mint a kormánypárt. Mindkét nagy erő korabeli értelemben liberálisnak számított, és képviselőinek nagy része nemesi származású vagy értelmiségi volt, a magyar \"történelmi osztályok\" érdekeit képviselte (egyfelől az arisztokrácia konzervatívabb részével, és a klérussal, másfelől az alsóbb osztályok és a nemzetiségiekkel szemben egyaránt). Így a legtöbb fontos kérdésben nem volt eltérő mondanivalójuk. Ugyanakkor éppen a közjogi kérdések vitatásának nem volt igazi tétje és értelme. A közjogi ellenzék ugyanis nem csak a kormánynak, de az egész berendezkedésnek, magának a rendszernek volt ellenzéke. Ezért az uralkodó ilyen pártot választási győzelem esetén sem engedett kormányra. (1875-ben és 1905-ben is csak úgy kerültek hatalomra korábban 48-as politikusok, hogy éppen programjuk lényegéről mondtak le.) Mindenki tudta, hogy a királynak, ha a 67-es párt meggyengül, joga van a hadsereggel átvenni a hatalmat addig, amíg más megoldást nem talál. Ezért a kormány-közelbe kerülő 48-asok inkább megalkudtak a fennálló rendszerrel. Az ellenzék padsoraiból bármit lehetett mondani 48-as alapokon, de kormányozni csak 67-es alapon lehetett. Ezek a sajátosságok okozzák a dualista magyar parlamenti viták és politizálás kiüresedését, álságos jellegét.\n\nA dualizmus kori magyar állam értékelése\n\nA dualizmus rendszere sokkal nagyobb mértékben biztosította a szabadságjogokat, mint a korábbi korszak. A cenzúra megszűnt, a sajtó útján elkövetett vétségeket a független bíróság, esküdtszék ítélte meg. (A sajtószabadság viszonylag széles körű volt, a kormányt is bátran lehetett szidalmazni, bár az uralkodót már tilos volt. Lapalapításkor kauciót - óvadékot - kellett letenni, melyből az esetleges büntetést levonhatták. A belügyminiszter közérdekből betilthatta egyes lapok terjesztését.) Elvben szabad volt gyülekezni és egyesületet létrehozni, de a kormányra volt bízva, hogy pontosan mit engedélyez. A korlátozások és felszámolások főleg a munkások, szegény parasztok és nemzetiségiek gyűléseit és egyesületeit érintették. Ezzel együtt a civil (állampolgári) szerveződések ebben a korban elszaporodtak: több ezer egyesület tevékenykedett, az élet szinte valamennyi területén. Minden felnőtt férfi egyenlő volt a törvény előtt vallásra, nyelvre és származásra való tekintet nélkül. Viszont ez nem vonatkozott a nőkre, a cselédekre, és nem mindig volt érvényes a nemzetiségek esetében; minderről később még lesz szó. Az előző fejezetben látható volt, hogy az alkotmányos monarchia abszolutisztikus maradványokat is (uralkodói jogkör) magába foglalt, a formális parlamenti többpártrendszer pedig bizonyos értelemben burkolt egypártrendszert takart (csak 67-es programmal lehet kormányra kerülni). Kétségtelen ugyanakkor, hogy mindez nagy előrelépés volt az abszolutizmushoz képest, és az is, hogy - az 1848-as kezdeményezés talaján - igazi polgári jogállam jött létre, mely kiállta az összehasonlítást a legtöbb európai állammal. Hiszen számos országban volt általános választójog, miközben az alkotmányosság és parlamentarizmus a magyarországinál is kevésbé érvényesült, nem is beszélve a bírói függetlenségről, az önkormányzatiságról és a szabadságjogokról.\n\nPolgári alkotmányos viszonyok\n\n• 1874-ben alkották meg a választójogi törvényt, amely az 1848-as törvényen alapult (vagyoni és műveltségi cenzus):\n\n• míg 1848-ban a lakosság 7-8%-ának volt választójoga, és ez megfelelt a korabeli nyugat-európai szintnek;\n\n• 1905-ben már csak a lakosság 6,2%-a szavazhatott, miközben Nyugat-Európában már 20-30%!\n\n• Már az Andrássy-kormány (1867-70) idején megkezdődött a megyék feladatának és jogkörének újraértelmezése, az „állam és a megye kiegyezése”:\n\n• fennmaradt a megyék helyi ügyekben meglévő önkormányzata, de élükre a kormány által kinevezett főispán került;\n\n• a megyegyűlések továbbra is foglalkozhattak országos ügyekkel, de kötelezték őket az országgyűlés törvényeinek és a kormány rendeleteinek betartására és végrehajtására.\n\n• Tisza Kálmán folytatta a reformot:\n\n• megtörte a megyék hagyományos autonómiáját, hivatali rendszerüket alárendelte a központi kormányzatnak;\n\n• a Tiszához hű főispánok kibővített jogkörrel teljesítették a „Generális” parancsait;\n\n• elterjedt a virilizmus rendszere: a megyei önkormányzatok és a saját törvényhatósággal rendelkező városok képviselőinek csak a felét választották, a másik felét a legtöbb adót fizetők (virilisták) közül jelölték ki.\n\nAz Andrássy-kormány alatt megkezdődött a jog és az igazságszolgáltatás reformja:\n\ntörvény előtti egyenlőség, bírók jogi képzettségének előírása, a bírók függetlenségének megteremtése, a büntetőjogból törölték a kirívó embertelenségeket. Tisza Kálmán idején, 1878-ban lépett életbe a modern büntető törvénykönyv (Csemegi-kódex). 1867-ben kimondták a zsidóság teljes polgári egyenjogúságát (emancipációját).\n\nWekerle Sándor kormánya (l892-95) végrehajtotta az állam és az egyház szétválasztását:\n\n• bevezették a kötelező polgári házasságot (és annak felbonthatóságát);\n\n• bevezették az állami anyakönyvezést;\n\n• kimondták a szabad vallásgyakorlást;\n\n• az izraelita is bevett vallás lett.\n\n1868-ban a parlament elfogadta az Eötvös József által kidolgozott népiskolai törvényt:\n\n• 6-12 év között kötelezővé tették az iskolába járást;\n\n• az elkövetkező 50 évben 4000 új népiskola épült;\n\n• jelentősen csökkent az analfabéták aránya: 1867-ben 69%, míg 1910-ben már csak 31%.\n\n1883: középiskolai törvény; 1891: kisdedóvókról szóló törvény. 1871-72: a Kolozsvári Tudományegyetem megalapítása; 1912: a pozsonyi és a debreceni egyetem megalapítása.A magyar politikai élet alapvető kérdése az Ausztriához és a kiegyezéshez fűződő viszony (közjogi kérdés) volt, így a magyar pártok a közjogi kérdés mentén szerveződtek, tehát nem a Nyugat-Európára jellemző politikai ideológiák szerint.\n\nAz 1861-ben létrejött Felirati Pártból és a csatlakozó konzervatívakból jött létre 1867-ben a Deák-párt. A nagybirtokosokat képviselte, támogatta a kiegyezést és a liberális Magyarország kiépítését tűzte ki célul.\n\nA 1861-és országgyűlés után a Határozati Pártból kivált a Tisza Kálmán vezette Balközép Párt, amely a középbirtokosokat képviselte. Elismerte a kiegyezést, de a perszonáluniót támogatta.\n\nA Határozati Párt másik része, a parasztság által támogatott Országos 48-as Párt elutasította a kiegyezést és függetlenedni akart. 1874-től Függetlenségi Párt néven működött tovább.\n\n1868-ban a németajkú munkásokból szerveződött az Általános Munkásegylet, amely 1890-tól a Magyarországi Szociáldemokrata Pártként a munkásokat képviselte, fő célja az általános és titkos választójog megszerzése volt. A centrista irányzatot követte.\n\nMivel az ellenzék győzelme a kiegyezés megkérdőjelezését és a dualista állam létét veszélyeztette volna, a választásokon biztosítani kellett a kormánypárt többségét, ezért a dualizmus idején nem merült fel a cenzusos választójog kiszélesítése.\n\n1867-ben a választójogot Kiterjesztették az izraelita férfiakra, teljessé téve a zsidóság emancipációját. 1874-ben vagyoni cenzus helyett adócenzust vezettek be.\n\nAz 1875-ös közigazgatási reform megerősítette a polgári közigazgatás kiépülését (átalakították a megyerendszert, növelték az állam szerepét a megyékben, a korábbi kiváltságos területeket megszüntették). A polgári államban kiépült a rendőrség és csendőrség szervezete.\n\nA Monarchia felbomlása és az első világháború után 1918-ban a Nagy Nemzeti Tanács „Néphatározata” már a titkos, egyenlő, általános, közvetlen, nőkre is kiterjedő választójogról rendelkezett. A Monarchia gyakorlati szétesésével párhuzamosan megalakuló Károlyi-kabinet eltörölt minden addigi cenzust, a választójoggal csak a politikai jogaiktól megfosztottak, a csőd alatt állók, a közsegélyből élők és azok nem élhettek, akiknek kiskorúságát meghosszabbították vagy erkölcsrendészeti felügyelet alatt álltak. A korszakban mégis fokozatosan teret nyert a politikai elitizmus, ami a közéletben való részvételt a felsőbb társadalmi rétegek privilégiumaként kezelte. Ezen intézkedések a dualista állam meggyengülésére, ezáltal a függetlenedési törekvések megerősödésére vezethetők vissza.', 96, 1, '2026-04-17 09:41:02', '2026-04-17 09:41:02');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(26, 26, 'A két világháború közötti diktatúrák és ideológiájuk', '26.docx', '26. tétel: A két világháború közötti diktatúrák és ideológiájuk\n\n(sztálini diktatúra, olasz fasizmus, náci Németország)\n\nAz olasz fasizmus jellemzői\n\nAz első világháborút követő (1918) válsághelyzet több európai államban szélsőséges (kommunista vagy fasiszta) mozgalmak kialakulásához vezetett. A fasiszta jellegű politikai csoportosulásokhoz, amelyek szélsőségesen nacionalista, antiliberális, antimarxista és agresszív terjeszkedő politikát folytattak. A fasiszta ideológia új rendet, új civilizációt hirdet, amely felváltja majd a liberális kapitalizmust. A fasizmus hívei „szocialistának” vallották magukat, és ennek megfelelően programjukban találhatók antikapitalista és szociális ígéretek. Szigorú hierarchia alapján felépített pártjaik élén a vezér állott (Führer, Duce), és szigorú egypártrendszert vezettek be.\n\nAntikapitalista jelszavaik ellenére hamar szövetséget kötöttek a nagytőkével, a hadsereggel és a jobboldali polgári pártokkal. A fasiszta rendszerek a gazdasági válsággal összefüggésben, vagy társadalmi feszültségek miatt alakultak ki és jutottak hatalomra. Megszerezték a létükben veszélyeztetett középrétegek - alkalmazottak, tisztségviselők, kisiparosok - támogatását. Felélesztették népük történelmi mítoszait, kivételes történelmi szerepüket hirdették. E nacionalista elméletek olyan országokban alakultak ki, amelyek a kudarcok miatt sérelmeik voltak pl. Németország veresége az első világháborúban, mélypontja a gazdasági válság idején. Olaszország esetében a győzelem ellenére kevés területet kapnak.\n\nAz I. világháború után:\n\n• Az első világháborút követő gazdasági és politikai válság Olaszországban különösen erős volt. Olaszország a győztes államok vesztese volt, a háború óriási anyagi terheket és emberveszteséget okozott, a békeszerződések pedig nem elégítették ki területi igényeit. Olaszországban úgy érezték, hogy az antant győzelem ellenére az ország nem kapta meg a megígért területeket, ezért nagy az elégedetlenség, gazdasági nehézségekkel küzdöttek, magas volt a munkanélküliség.\n\nA „vörös két év” (1919-20):\n\n• fellendült a munkásmozgalom: sztrájkok, földfoglalások délen, gyárfoglalások északon;\n\n• a baloldali eredetű tömegmozgalmak megfékezésében a kormányzat a szélsőjobboldal szervezeteire próbált támaszkodni;\n\n• 1921-ben megalakult az Olasz Kommunista Párt.\n\nA szélsőjobboldal aktivizálódása:\n\n• Gábrielé d\'Annunzio légionáriusai megpróbálták a békekonferencia döntéseit átírni: 1919-ben elfoglalták Fiúmét.\n\nMussolini szocialista politikusnak indult, az első világháború mély benyomást tett rá. Benito Mussolini 1919-ben létrehozta a Fasci di Combattimento nevű nacionalista szervezetét, megszervezte a mozgalom rohamosztagait, amelyek aktívan részt vettek a sztrájkok letörésében, a baloldaliak megfélemlítésében (squadrizmus). 1921-ben megalakult a Nemzeti Fasiszta Párt.\n\nA fasiszta hatalomátvétel: első szakasz 1922-25. (még működik a korlátozott demokrácia)\n\n• 1922. okt. 28-án „marcia su Roma”, azaz Mussolini csapatai bevonultak Rómába, majd másnap III. Viktor Emmánuel király kinevezte Mussolinit miniszterelnöknek.\n\n• Mussolini 1922-ben koalíciós kormányt alakított, megígérte az alkotmányos keretek betartását, de létrehozta a Fasiszta Nagytanácsot, amely fokozatosan az állam vezető testülete lett.\n\n• Megtörte a szocialistákat és a kommunistákat.\n\n• 1924-ben választásokat tartottak, de visszaélések jellemezték (fasiszta győzelem), majd a csalások ellen tiltakozó szocialista képviselőt, Matteottit meggyilkolták. Válaszul az ellenzék kivonult a parlamentből („aventinusi blokk”).\n\n1925. jan. 3-án megkezdődött Mussolini diktatúrája: totális diktatúra 1925-45.\n\n• betiltották a baloldali pártokat;\n\n• bevezették a cenzúrát;\n\n• a miniszterelnök kezében összpontosult a hatalom.\n\n• 1927-től megkezdődött Olaszország korporatív állammá alakítása (1934-re fejeződött be):\n\n• átszervezték a munka világát, az ország gazdaságát 22 szektorra bontották;\n\n• minden gazdasági szektor élén egy testület állt, amelybe a szakmai szervezetek, a munkaadók, a dolgozók és a Fasiszta Párt küldött képviselőket;\n\n• a rendszer élén a Korporációk Nemzeti Tanácsa állt, alárendelve a Korporációügyi Minisztériumnak.\n\nA korporatív rendszer célja az volt, hogy megszűntessék az osztályharcot, biztosítsák a társadalmi békét, továbbá, hogy az állam szorosabban felügyelhesse a munka világát. Mussolini 1934-re tehát létrehozta a „korporációs rendszert”, amelyet a munkások és munkáltatók valamint a fasiszta párt képviselőiből álló termelési tanácsok alkottak; ez utóbbiak irányították a termelést, és döntöttek a munkások és munkáltatók közötti vitákban.\n\n• Gazdaságpolitika\n\n• Erőteljes állami beavatkozás, irányítás érvényesült főként a gazdasági világválság időszakától, 1929-től kezdve.\n\n• Kiemelt cél volt: a gazdasági önellátás megteremtése: kiemelten kezelték a bányászatot, az energiatermelést, a vegyipart; a „földéhség” csillapítása: mocsárlecsapolásokkal a művelhető területeket bővítették.\n\nAz egyházzal történt 1929-es kiegyezés, a lateráni egyezmény. Az olasz fasiszta kormány és a katolikus egyházfő között Rómában, a lateráni palotában megkötött egyezmény az olasz állam és a pápaság viszonyának rendezéséről. 1929. február 11-én írta alá XI. Piusz pápa és Benito Mussolini.\n\nPolitikai megegyezésük:\n\nA római katolikus vallás vált Olaszország államvallásává.\n\nA Vatikán teljesen független, szuverén állam lett, Róma pedig Olaszország fővárosa.\n\nRögzítette a Vatikán területét, illetve a hozzá tartozó, területen kívüliséget élvező ingatlanokat.\n\nA pápa személye szent és sérthetetlen.\n\nPénzügyi megállapodás\n\nA megegyezés értelmében az olasz állam a ratifikációval egy időben átadott a Szentszéknek 750 millió lírányi készpénzt és egymilliárd lírányi, 5%-os kamatozású államkötvényt. Ezzel a Szentszék végérvényesen rendezettnek tekintette az olasz állammal szemben az 1870-es események kapcsán támasztott pénzügyi követeléseit.\n\nA konkordátum előjogokat, privilégiumokat biztosított Olaszországban a katolikus egyháznak:\n\nBiztosította az egyház joghatósági hatalmának gyakorlását.\n\nA nyilvános istentiszteletek szabad végzését.\n\nBiztosította az egyházi állam védelmét. Eltörölte az egyházellenes törvényeket.\n\nKimondta az egyházi házasság civiljogi érvényességét.\n\nKötelezővé tette a hitoktatást az iskolákban. Megtiltotta a papok politikai tevékenységét.\n\nAz olasz fasizmus jellegzetességei:\n\nA Duce hatalma nem volt korlátlan, az uralkodói hatalom érintetlen maradt.\n\nAmikor a fasiszta rendszer fenntartása ugyanis veszélyeztette az uralkodó érdekeit, III. Viktor Emánuel felmentette és letartóztatta Mussolinit (1943. július 25.).\n\nA fasizmus sajátos erőszakkultusszal rendelkezett, a fasizmus célja a totális állam kiépítése volt. A fasizmusra erőszakkultusz / militarizmus / antipacifizmus jellemző.\n\nErődemonstrációval ragadták magukhoz a hatalmat, félkatonai szervezettel – a feketeingesekkel – rendelkeztek, a politikai ellenfelekkel szemben terrort alkalmaztak, agresszív külpolitikát folytattak.\n\nA fasizmus az egyénnel és a csoportokkal szemben az államot abszolutizálja pl. antiliberális ideológia, totális állam kiépítésére törekszik, diktatúrát létesített.\n\nA fasizmus (szélsőségesen) nacionalista nemzeti ideológia, a történelmet a nemzetek harcának értelmezi, hódító törekvések jellemzik, példának a Római Birodalmat tekinti.\n\nA fasizmus rokon vonásokat mutat a szocializmussal: aktív szociálpolitikát követel, és erre hivatkozva erősítené az államot, haladná meg az osztályellentéteket, korlátozná a nagytőkét, védené a kistulajdont, korporatív államot épített ki.\n\nA fasizmusra jellemző: az antidemokratizmus, rokonsága a nemzetiszocializmussal: elutasítja a többségi elvet, inkább vezérelvű eszme.\n\nA katolikus egyházzal kiegyezik, az olasz fasizmus nem rendelkezik fajelmélettel.\n\nAz olasz fasiszta ideológia főbb jellemzői: nacionalizmus, szociális demagógia, a tömegek szerepének és a nép nagyságának hangoztatása, demokráciaellenesség.\n\nEnnek alapján Mussolini nacionalista és szociális demagógiára épülő ideológiai tömegpártot hozott létre, reformokat hirdetett, és célul tűzte ki a korporatív állam megteremtését. Az ideológia alapvetően a hatalom megragadását, az állam szerepének növekedését szolgálta, Mussolini folyamatosan ehhez a célhoz igazította elképzeléseit.\n\nMussolini az osztálykülönbségeket háttérbe kívánta szorítani, és ezt erős (totális) állam megteremtésével akarta megvalósítani. Az államnak, az állam totalitásának kiemelkedő szerepet szánt a hatalom gyakorlásában, a társadalom és a gazdaság átalakításában.\n\nAzonosságok a fasizmus és nácizmus között:\n\n• új rendet, új civilizációt és nemzeti-faji kollektívumot hirdettek;\n\n• jobboldaliak, antiliberálisok, antimarxisták (bár Mussolini a baloldalról indult, a német NSDAP nevében pedig benne van a szocialista szó);\n\n• kispolgári tömegeket is mozgósító tömegmozgalom segítségével, parlamentáris keretek között kerültek hatalomra; erődemonstrációkat tartottak, manipulálták a tömegeket pl. kiváló szónokok, felvonulások, népünnepélyek, eszmék hangoztatása, filmhíradók, plakátok, rádióbeszédek, személyes megjelenés, külsőségek, jelszavak.\n\n• vezérelv (Führer – Hitler, Duce - Mussolini).\n\nAgresszív külpolitika, terjeszkedési szándék. Nacionalista jelleg. Kommunistaellenesség.\n\nKülönbségek\n\nAz olasz fasizmus:\n\nnem antiszemita (nem volt hagyománya, alig élt zsidó Olaszországban);\n\nfenntartotta a királyság intézményét;\n\nnem egyház- és vallásellenes;\n\ntradicionális külpolitikát követ (Római Birodalom feltámasztása);\n\nmesszebbre jutott a korporatív államberendezkedés megvalósításában.\n\nA sztálinizmus, fasizmus és nácizmus közötti hasonlóságok:\n\nszélsőséges politikai irányzatok (de a kommunizmus baloldali, a másik kettő jobboldali)\n\ntotális rendszer kialakítására törekedtek\n\naz állami élet minden területét uralja a párt\n\nkatonai szervezet vagy besúgóhálózat segíti a pártot\n\nerőszakon alapul pl. németek koncentrációs táborok, szovjetek GULÁGOK\n\na pártvezér szerepe nagy (személyi kultusz, vezérelv).\n\nA náci Németország\n\nA nácizmus és a bolsevizmus ideológiai értelemben a politikai irányzatok két végpontja: a nácizmus szélsőjobboldali, a bolsevik ideológia szélsőbaloldali jellegű. Eszközrendszerüket tekintve hasonlóak egymáshoz. Totális diktatúra kiépítésére törekedtek, az ember egész életét uralni kívánták, mindenre kiterjedő szabályozást vezettek be.\n\nJellemzői:\n\nA nácizmus az I. világháború után alakult ki Németországban, nagyobb népszerűségre azonban csak a gazdasági világválság idején tett szert 1929-től, hatalomra pedig 1933-ban jutott.\n\nA nácizmus eredetileg tőkeellenes, szociális programokat hirdet pl. társadalombiztosítás fejlesztése. A nácizmus nagynémet államot hirdet, és a versailles-i békerendszer felszámolását tűzi ki célul. A nácizmus fajelméletet alkot, a németeket / árjákat magasabb, a zsidókat pedig alacsonyabb értékűnek tartja. A nácik nagy fontosságot tulajdonítottak a propagandának. Hitler eredményesen befolyásolta, mozgósította a tömeget a modern média eszközeivel. Hitler elképzelései illeszkednek a korszak új irányzataihoz: szociáldarwinizmus, fajelméletek, tömegek forradalma, olasz fasizmus. Speciális német vonásai is vannak pl. az I. világháború traumája. A nácizmus szocialista és nemzeti mozgalom, és kollektivizmusa elutasítja az individualista liberalizmust és a demokráciát. Hitler programját a Mein Kampfban fejtette ki, és ideológiája megvalósítására hatalomra jutása után kerülhetett sor. Hitler kidolgozta a keleti élettér elméletét, a későbbi német terjeszkedés részben ennek jegyében történt.\n\nA nemzetiszocializmus ideológiája és propagandája\n\nElőzmények:\n\nNémetország vesztesként kerül ki az első világháborúból, jóvátételt is kell fizetnie, területeket veszít, gazdasága is válságba kerül.\n\n1919-től Németország szövetségi köztársaság\n\nA németek célja: a béke megtámadása, a visszarendezés.\n\nA nemzetiszocialista párt ideológiája, programja:\n\n1919-ben, Münchenben jött létre az NSDAP, azaz a Német Nemzetiszocialista Munkáspárt /Nationalsozialistiche Deutsche Arbeiterpartei/, azaz a náci párt. Nacionálszocializmus, azaz nácizmus jellemzi, mely a fasizmus továbbfejlesztett változata, ideológiája azonban szélsőségesebb.\n\nA náci ideológia két hagyományos mozgalom ötvöződésébe alakult ki:\n\n• az osztrák területeken jelentkező pángermanizmus (alldeutch) és antiszemitizmus,\n\n• a németországi népi (volkisch) mozgalom, amely a régi germán hagyományokhoz, mondavilághoz nyúlt vissza.\n\nA náci ideológia kialakulását XIX. századi ideológiák is meghatározták:\n\n• fajelmélet: a történelem a fajok harca;\n\n• térelmélet: a népek fennmaradása attól függ, hogy képesek- e lakosságukat, és ahhoz területüket is növelni;\n\n• tömeglélektan: az arctalan tömeg irányítható, sőt igényli, hogy vezessék;\n\n• szociál- és nacionáldarwinizmus: az emberi társadalomban és a népek között is dúl a létharc, zajlik a szelekció. A szociáldarwinizmus szerint az élet szüntelen harc, amelyben az erősebb győz, a gyenge elpusztul. A létharcot fajok vívják egymással.\n\n1923-ban az NSDAP Münchenben hatalomátvételre törekedett: ez volt a „sörpuccs”, de sikertelen, ezért bebörtönzik a puccs résztvevőit, itt írja meg Hitler a Mein Kampf, azaz Harcom című könyvét, mely a náci párt alapkönyve és programja\n\nIdeológiájuk a Mein Kampf alapján:\n\nNem fogadják el a versailles-i békeszerződést, nyíltan szembe kell szállni Franciaországgal, revansot adni neki\n\nNémetországnak új területekre van szüksége: ez az élettérelmélet, a Lebensraum. Lépései: 1. Európa valamennyi németjének egyesítése / a Szudéta-vidék és az Anschluss/ 2. egész Európára kiterjedő nagynémet birodalom, 3. német világbirodalom.\n\n„Drang nach Osten” /terjeszkedés Kelet felé, leigázni a szlávokat/.\n\nFajelmélet: - a német felsőbbrendű, uralkodó nép, azaz árja faj\n\n/sovinizmus jellemzi, hiszen ez a megnyilatkozás nemzeti felsőbbrendűséget hirdető szélsőséges nacionalizmus/ A németeket, angolokat, franciákat kultúraépítő népnek nevezi.\n\n- másodrendű fajok: a rokon népek, a nyugati germánok\n\n/flamandok, hollandok, skandinávok/\n\n- alsóbbrendű fajok a szolganépek: a szlávok, magyarok, akik kultúrafenntartók. Rabszolganépek: afrikaiak, ázsiaiak.\n\n- kiirtandó népek a zsidók, cigányok /antiszemitizmus és rasszizmus jellemzi/. Oka: minden baj forrása a zsidók. Ezek destruktív fajok, akiket ki kell irtani.\n\nA nemzet egysége: le kell számolni a nemzet egységét akadályozó elemekkel, a kommunistákkal és a zsidókkal. Így nemcsak antiszemita, hanem munkásmozgalom-ellenes is.\n\nEgypárti diktatúrára, totális hatalom kiépítésére törekszik, mely a demokratikus intézmények, pártok felszámolását jelenti.\n\nA diktatúra vezetője: Adolf Hitler /1889, Braunau – 1945, Berlin/, ő a Führer, azaz a vezér, aki a Volk, azaz a nép érdekeit képviseli\n\nA propaganda segítségével mindezt elhiteti az emberekkel, sőt népszerűsíti, újságok, gyűlések, rádió útján eszméit módszeresen terjeszti.\n\nJellemző volt az erő kultusza, a szimbólumok, jelképek használata\n\n(horogkereszt, Heil Hitler köszöntés stb.).\n\nElvek:\n\n• totalitás (az emberi élet valamennyi területére kiterjedjen); széles tömegekhez szóljon;\n\n• szubjektív és egyoldalú legyen; kevés témára koncentráljon, de azokat kitartóan ismételje.\n\n• 1933-tól Goebbels volt a propagandaminiszter.\n\n• felhasználták a sajtót, a rádiót, tömeggyűléseken a megafont;\n\n• a művészeteket is az ideológiai harc és a propaganda szolgálatába állították (utólagos „cenzúra” volt, a Führer ízlése volt a döntő). Hatalmas ünnepségeket szerveztek: nürnbergi egyhetes pártkongresszusok, megemlékezések a Führer születésnapján (április 20.), a hatalomra kerülés napján (jan. 30.) Nyilvános könyvégetések: Thomas Mann, Heine, Freud, Jack London, Einstein stb. műveit).\n\n• 1933-38 között több száz film is készült (pl. Leni Riefenstahl: „ A hit győzelme”, „Akarat diadala” és film az 1936-os berlini olimpiáról).\n\nCélja, a tömegek befolyásolása. Ennek érdekében olyan ígéreteket tesz, amelyekkel megnyeri az embereket:\n\n- a munkásoknak munkalehetőséget, több bért, népünnepélyt\n\n- a parasztoknak földet, az adóskamatok eltörlését\n\n- a kisiparosoknak adócsökkentést, a nagytőke megfékezését\n\n- a katonaságnak új hadsereget, fegyverkezést, hódításokat\n\n- a nagytőkéseknek a munkások fékentartását, háborús befektetéseket.\n\nA nemzetiszocialista párt hatalomra kerülése\n\nAz 1929-es világválság Németországot is súlyosan érintette. Az ipari termelés nagy része leállt, és emiatt súlyosan megnőtt a munkanélküliség (6 millió főre). A világgazdasági válság súlyos helyzetbe hozza Németországot, válságba kerül a politikai élet is. A náci párt kihasználja a válságot, s ígéreteinek hatására növekedik a párttagok száma / míg 1925-ben 27000, addig 1932-ben már 1 500 000 fős taglétszámmal rendelkezik/. A náci párt a parlamenti választásokon is indul 1932-ben, népszerűségük egyre nő. Az erős kéz politikáját kínálják fel és a válság megoldását /pl. közmunkaprogram, fegyverkezés, a munkanélküliség megállítása, terjeszkedés/. A világválság a köztársaság válságát, később a bukását okozta. A válságkezelés a gazdasági célok mellett politikai és társadalmi célokat is szolgált, szerepe volt a nácik hatalomra kerülésében.\n\nA náci párt a parlamenti választásokon is indul 1932-ben, népszerűségük ugyanis egyre nő. Az erős kéz politikáját kínálják fel és a válság megoldását /pl. közmunkaprogram, fegyverkezés, a munkanélküliség megállítása, terjeszkedés/.\n\n1933. január 30-án Hindenburg köztársasági elnök Hitlert kancellárrá nevezi ki a törvényeknek megfelelően, mint a legnagyobb parlamenti párt vezetőjét.\n\nA náci párt vezérkara: Rudolf Hess, Hitler helyettese; Joseph Goebbels propagandaminiszter; Göring, légimarsall, porosz miniszterelnök; Röhm, az SA vezére (Sturmabteilung – rohamosztag).\n\nA hatalom kiépítése:\n\nA választások során többségbe került a náci párt, de a többi párt felszámolására készül.\n\nVálságkezelés:\n\n1933-ban hatalomra került Adolf Hitler, a nemzetiszocialista párt vezetője, aki bejelentette a jóvátétel-fizetések eltörlését („az adósrabszolgaság vége”). Nagyszabású közmunkaprogramot indított el, hogy felszámolja a munkanélküliséget. Ekkor építették meg a berlini sugárutat és országszerte autópályákat. Bevezették a kötelező birodalmi munkaszolgálatot, majd ennek felügyeletére a Nemzeti Munkafrontot, amibe kötelező volt belépni. Hitler az ország háborúra való felkészítését tartotta elsődleges fontosságúnak, ennek megfelelően a gazdaságot is átalakította. Önellátásra törekedett és az importáruk számát a minimumra csökkentette. A külkereskedelmet elsősorban szövetséges államokkal bonyolította, hogy a kereskedelem stabilitását háború esetén is biztosítani tudja. Az intézkedések eredményeként Németország rövid idő alatt stabilizálni tudta gazdaságát.\n\nA gazdasági válság megoldásának módszere: Hitler új munkahelyek teremtését ígérte, hangsúlyozta, hogy összefogással lehet a válságból kijutni, és hogy Hitler vezetésével szüntethető meg a gazdasági válság. A náci propaganda hangsúlyozta a gazdasági válság hatásait, a válság megszüntetésének lehetőségeit. A nácik hatottak az emberek érzelmeire a hatalom megszerzése érdekében. A tömeg gazdasági befolyásolását központilag irányították: pl. az állam a vevők szokásait is szabályozni kívánta. A válság megoldásának egyik eszköze a fegyvergyártás. Az állam a termelés irányításával kívánja a gazdaságot stabilizálni.\n\nA válság fő tényezője a túltermelés és a munkanélküliség. A náci propaganda e két probléma megoldására irányult elsősorban: a munkanélküliség problémáját a munkahelyek megteremtésének hangsúlyozásával kívánták megoldani. A túltermelés megakadályozására kiiktatta a piaci szereplők közötti versenyt pl. kényszerkartellezési törvény.\n\nGazdaságpolitikájuk: átszervezték a gazdaság irányítását.\n\nközmunka-programokat indítanak,\n\ninfrastrukturális beruházásokat hajtanak végre,\n\na fegyvergyártást fokozzák, a fegyvergyártással készülnek a leendő konfliktusokra is\n\na gazdaság fejlesztésének hátterében háborús célok megvalósítása állt.\n\nA Birodalmi Bank létrehozása\n\na valuta szabályozása\n\naz új munkahelyek teremtését és a piac bővítését az infrastruktúra fejlesztésével oldják meg\n\nautópálya-építések\n\nMindez a gazdaság termelékenységét is biztosította.\n\nA program megvalósítása során éltek a propaganda lehetőségeivel.\n\nEredmény: 1934-re csökken a munkanélküliség.\n\n1933. február 27. a Reichstag felgyújtása – a kommunistákat vádolják, ezért letartóztatják a kommunista vezetőket, s megszüntetik a pártot, kezdetét veszi a lipcsei Dimitrov-per, majd júliusban felszámolják a többi pártot is. A demokráciának vége.\n\n1933. márc. 22-én a parlament megszavazta a „felhatalmazási törvényt”, amely feljogosította a kancellárt törvények, rendeletek hozására. Ezzel Hitler megszerezte azt a hatalmat, amellyel megkezdődhetett az egypárti diktatúra kiépítése.\n\n1933-tól koncentrációs táborok működnek, ahová kommunistákat és zsidókat visznek. Pl. Dachau, Buchenwald, később Mathausen, Auschwitz, Zeitz.\n\n1934. június 29-30. „hosszú kések éjszakája” – leszámolás az SA-val. Oka: az SA, azaz a párt katonai alakulata, náci rohamosztaga Rhöm vezetésével Hitler ígéreteinek betartását követelte. Hitler nem tűrte az engedetlenséget saját pártján belül sem, ezért lemészároltatta az elégedetlenkedőket az SS-szel, azaz a nácik különlegesen kiképzett terrorista elitalakulatával, mely eredetileg Hitler testőrsége volt.\n\nAz SS vezetője Heinrich Himmler. Az SS ültette át a valóságba a náci ideológiát, a Waffen SS a fronton könyörtelenül leszámolt mindenkivel, míg a Totenkopf SS vezette a halál- és koncentrációs táborokat. A belső biztonságra a Hermann Göring által vezetett Gestapo (titkosrendőrség) felügyelt. A megfélemlítés a totális diktatúra része lett. Hitler nem akarta, hogy vele szemben kialakuljon bármiféle hatalmi centrum. Senki sem érezhette magát biztonságban, mindenki figyelt mindenkit: a „versenyben” nem volt szabad hibázni.\n\n1934. augusztus 2-án meghalt Hindenburg köztársasági elnök, most már senki sincs, aki Hitlert korlátozhatná. Vége lett a weimári köztársaság korának. Hitler egy személyben kancellár és a Német Birodalom vezére /Führer/ lett. 1934-ben egyesítette az államfői és kancellári hatalmat, felvéve a Führer-titulust. Innentől kezdve a náci ideológia lett az ország hivatalos eszmerendszere. Aki ellenszegült, azt likvidálták (a helyzetet tovább fokozta, hogy később Hitler lett Németország legfőbb bírája is, vagyis totális önkényt vezetett be).\n\n1935. a nürnbergi zsidóellenes törvények, vagyis faji törvények megfosztották a zsidókat állampolgárságuktól, jogaiktól, elkobozzák vagyonukat, a zsidó könyveket nyilvánosan elégetik, egyre többen kerülnek koncentrációs táborokba vagy gettókba.\n\n1938. nov. 9-10-én „Kristályéjszaka”: szervezett támadás a zsidóság ellen egész Németországban.\n\nHitler rendkívül hatásos beszédeivel manipulálni tudja a német közvéleményt, amely melléáll, támogatja döntéseit, rajong a népvezérért /Heil Hitler! + karlendítés./\n\nÁtszervezték a munka világát: korporációs szándékkal létrejött a Nemzeti Munkafront (DAF).\n\nAz egyes társadalmi csoportokat is megszervezték, feladataikat kijelölték:\n\n-nők: „3 K” politika - „Kinder-Kirche-Küche”\n\n(gyerekszülés - egyház [gyereknevelés] - konyha [a család ellátása]);\n\n- ifjúság: fiúknak 6-18 év között Hitlerjugend; lányoknak „Hit és Szépség” nevű szervezet;\n\n- munkásság: szabadidő-szervezetük a „Kraft dur Freudé” („Erő az öröm által”), amely koncert- és\n\nszínházlátogatást, sporttevékenységeket, utazásokat és továbbtanulási lehetőségeket nyújtott.\n\nA totális állam jellemzői\n\n• egységes ideológia (nácizmus), tömegpárt (NSDAP), erőszakszervezet kialakulása, megfélemlítés.\n\n• terrorisztikus (titkos)rendőrség (GESTAPO), sajtómonopólium (propaganda: újság, rádió, film)\n\n• fegyvermonopólium (rohamosztag - SA, védőosztag - SS, hadsereg)\n\n• központilag irányított gazdaság, közös jövőkép: újra felemelkedő Nagynémet Birodalom;\n\n• Közös ellenségkép: zsidóság: 1933-tól megindult a zsidóság szervezett üldözése\n\n(üzletek bojkottja, kizárásuk az egyetemekről és a köztisztviselői karból). Közös vezér: Führer.\n\nAgresszív külpolitika. Cél: a Harmadik Német Birodalom eszméjének megvalósulása.\n\n(1933. Németország kilép a Népszövetségből, sőt gazdasága haditermelésre áll át\n\n1935. Saar-vidéki népszavazás – a terület ismét Németországé, továbbá általános hadkötelezettséget vezet be, s felállítja a légierőt a versailles-i békét ezzel megszegi\n\n1936. a Rajna-vidék német megszállása /remilitarizálása/, amely fegyvermentes volt.\n\n1936. Berlin – Róma tengely létrehozása – a tengelyhatalmak létrejötte\n\n1936. antikomintern paktum Japánnal, majd Olaszországgal /1937/- kommunistaellenes\n\n1936-39. spanyol polgárháború – a spanyol fasiszta Franco tábornokot támogatja fegyverrel, ez a második világháború főpróbája.\n\n1938. március 12. Anschluss – Ausztria bekebelezése, a német területek egyesítése\n\n1938. szeptember 29-30. müncheni konferencia - Chamberlain (angol) és Daladier (francia) és Hitler megegyezik a Szudéta-vidék Németországhoz csatolásáról.\n\n1939. március 15. a német csapatok bevonulnak Prágába /Cseh-Morva Protektorátus/\n\n1939. augusztus 23. szovjet-német megnemtámadási egyezmény Molotov – Ribbentropp paktum /titkos záradéka Lengyelország felosztásáról/\n\n1939. szeptember 1. Lengyelország megtámadása – a második világháború kezdete, Hitler nagyhatalmi terveinek megvalósítása.)\n\nA bolsevizmus kialakulása jellege, a sztálini rendszer\n\nA bolsevizmus az Oroszországi Szociáldemokrata Munkáspárt (OSZDMP) 1903-as kongresszusa után kapta nevét. Vlagyimir Iljics Lenin és hívei ugyanis többségbe kerülvén a pártban, felvették a bolsevik (az orosz bolsinsztvo [többség] szóból eredő) nevet. A szakítás okát a demokratikus centralizmus jelentette. Ellentáborukat, a mensevikeket, amely nyugati mintájú szociáldemokrata párt volt, gyorsan felszámolták. A bolsevik párt magát a társdalom élcsapatának tartotta, amelyik előbb a polgári, majd a proletárforradalomba vezeti azt. A bolsevikok világforradalomra törekszenek, tudományos elméletnek tekintik ideológiájukat, a társadalom erőszakos átalakítására törnek.\n\nA bolsevikok tehát az orosz szociáldemokrata párt egyik csoportja, nevük többséget jelent, szemben állnak a mensevikekkel. A bolsevikok a radikálisabb irányzat, más néven kommunisták. A bolsevizmus ugyanis marxista-kommunista politikai irányzat. Céljuk a magántulajdon felszámolása, az osztályok nélküli társadalom megteremtése, a proletárdiktatúra. A bolsevikok vezetője Lenin, aki továbbfejlesztette Marx munkásságát, ezért emigrációba kényszerült. Az 1905-ös orosz forradalomban is részt vettek, ezért üldözni fogják őket.\n\n1917. február 23-án polgári forradalom zajlott le, majd kettős hatalom jött létre: Lvov herceg vezetésével az Ideiglenes Kormány, s mellette a munkásküldöttek pétervári szovjetje alakult meg.\n\n1917 tavaszán a bolsevik párt még kicsi volt (kb. 20 ezres tagság), a párt vezetőinek többsége emigrációban vagy szibériai száműzetésben élt, a szovjetekben (tanácsokban) kisebbségben voltak.\n\nAz 1917-es forradalom eseményeiben a bolsevikok helyi szinten vettek részt.\n\n• 1917. ápr. 4-én az emigrációból hazatérő Lenin közzétette az „Áprilisi téziseket”, amely határozott programot adott a hatalom megszerzésére és a forradalom továbbvitelére (permanens forradalom). Lenin szerint a polgári forradalmat támogatni kell, a burzsoázia ugyanis nem viszi végig következetesen a forradalmat, mert a régi rendre támaszkodik. Ebből az elvből nőtt ki a permanens forradalom lenini elmélete, a polgári forradalom után proletárforradalmat akart, ezért támogatták 1917-ben a forradalmat.\n\n• 1917 nyarán az első világháborúban a Kerenszkij-offenzíva összeomlott, s utána általános politikai válság alakult ki, amelyben propagandával (béke, földosztás), tüntetések szervezésével a bolsevikok is szerepet játszottak. Megbukott a Lvov-kormány. Az új Kerenszkij-kormányt megpróbálta megdönteni egy puccsal Kornyilov tábornok. Ennek megakadályozásában jelentős szerepet játszottak a bolsevikok, akik ekkor fegyverhez jutottak, bebörtönzött vezetőiket kiengedték. A bolsevikokat egy intelligens, karizmatikus, intuitív vezér irányította: Lenin.\n\nA Pétervári szovjet élére, amiben a bolsevikok már többségben voltak, Trockij került. 1917. november 7-én (a Gergely-naptár szerint; de a Julianus-naptár alapján október 25-én) Szentpéterváron a bolsevikok megdöntötték a kormányt, Kerenszkij elmenekült.\n\nAz éppen ekkor ülésező Munkás- és Katonaküldöttek Szovjetjeinek II. Összoroszországi Kongresszusán: a bolsevik többség „törvényesítette\" a hatalomátvételt, kikiáltották a szovjethatalmat, azaz a proletárdiktatúrát. A bolsevikok átveszik a hatalmat.\n\nKözzétették a békedekrétumot (békekötés a németekkel Breszt-Litovszkban 1918. márc. 3-án) és a földről szóló dekrétumot.\n\nA bolsevikok pétervári győzelme korántsem jelentette, hogy az egész országot uralják:\n\n• kirobbant a polgárháború (vörösök-fehérek);\n\n• megkezdődött az antant intervenciója is.\n\nA bolsevikok hatalomra kerülésének okai:\n\nA politikai káoszban egyedül a bolsevikoknak volt világos, népszerű, jelszavakban (béke, föld) is megfogalmazható programjuk. A bolsevikok jól konspiráltak, szervezkedtek (megtanulták az illegalitásban). A bolsevikok szervezettek, fegyelmezettek voltak, elhivatottság tudatuk volt („vezetni a népet a kommunizmusig\").\n\nA bolsevizmus a kommunizmus eszméjén alapult, azon a Karl Marx és Friedrich Engels által kialakított eszmerendszeren, amelynek jellemzője az emberek egyenlősége, a termelőeszközök közös tulajdona, és az, hogy mindenki képességei szerint dolgozik, és szükségletei szerint részesedik a közös javakból. A kommunizmus tisztán sohasem valósult meg.\n\nA bolsevizmus szerint a gazdaság a szervezett élet alapja, a többi életszféra (pl. irodalom, politika, művészetek stb.) csak a gazdasági berendezkedés függvényében jön létre. A termelési eszközök feletti hatalom (azaz a magántulajdon intézménye) társadalmi osztályok létrejöttéhez vezet; közülük az egyik mindig az uralkodó osztály, amely hatalma erősítése végett létrehozza a vallást, az erkölcsöt, a kultúrát. A kizsákmányolt emberek rendre fellázadnak az igazságtalanság ellen, ám eddig mindig csak a kizsákmányolás újabb formájába léptek. A bolsevizmus alaptétele is innen származik: „Minden eddigi társadalom története osztályharcok története” - fogalmaz a Kommunista Kiáltvány (1848). A kapitalizmus az osztálytársadalom utolsó állomása, amely összeomlik, amikor az ipari munkásság fellázad. -Ezután valósították meg a proletárdiktatúrát, azaz a munkásság hatalomgyakorlását. Ezt az átmeneti periódust nevezte Lenin szocializmusnak, aki szerint miután a szocializmus megszilárdul, megszűnik a magántulajdon, az állam, valamint az osztályok, és a történelem eljut végpontjához, az osztály nélküli társadalomhoz: a kommunizmushoz. A szocializmusba azonban csak forradalmi, illetve erőszakos úton lehet átvezetni a társadalmat, aminek jutalma az emberek végső szabadsága lesz. A bolsevizmusra jellemző, hogy álcaszerű tudományosság (pl. dialektikus materializmus) mögé rejtették elképzeléseiket.\n\nA szervezetet tekintve a bolsevikok a gyakorlatban a demokratikus centralizációt alkalmazták, amely szerint a párt vezetésének megválasztása demokratikus, de utána a következő választásokig minden hatalom a vezetésé, nincs beleszólás. A nácizmushoz hasonlóan a Szovjetunióban (1922. december 30-tól hívták így) sem volt szerepe a parlamentnek, minden irányítást az SZKP KB (a Szovjet Kommunista Párt Központi Bizottsága) gyakorolt.\n\nA proletárdiktatúra jellege: az állam szerepét abszolutizálták, erőszakot alkalmaztak.\n\n• az egyenlőség felé vezető úton számos lépést tettek: 8 órás munkaidő, fizetett szabadság, polgári házasság, rangok és előjogok megszűntetése, ingyenes orvosi ellátás, nők egyenjogúsítása stb.;\n\n• az iparban és a kereskedelemben államosítás;\n\n• a polgárháborús időszakban felvetődött a pénz kiiktatása a gazdaságból, de aztán ez lekerült a napirendről.\n\n• A földkérdés: a bolsevik ideológiában távlatilag a termőföldek magántulajdonának megszüntetése, szövetkezetesítés szerepelt, de taktikai okokból (a parasztság megnyerése érdekében) mégis végrehajtották a földosztást, de egy szigorú beszolgáltatási rendszert hoztak létre, majd 1929-től megkezdődött a szövetkezetesítés.\n\nA világforradalom: A bolsevikok magukat a világforradalom első képviselőinek tekintették, és azon voltak, hogy ez a világméretű forradalom be is következzen.\n\n• 1919-20-ra azonban elhaltak a forradalmi kezdeményezések. (Magyarországon pl. 1919-ben volt tanácsköztársaság, de leverték)\n\nLenin ezt látva, kialakította a „szocializmus egy országban” koncepciót, azaz az ideiglenes együttélést a kapitalista külvilággal. A kommunista ideológia terjesztésében, a Szovjetunió érdekei képviseletében fontos szerep jutott a III. Intemacionálénak (Komintern), amelynek tagszervezetei, az egyes kommunista pártok - Moszkvából vezérelten - a Szovjetunió meghosszabbított karjaiként tevékenykedtek.\n\nRendkívül fontos volt bizonyítani a szocializmus életképességét, magasabbrendűségét a kapitalista világgal szemben.\n\nLenin szerint a világforradalom a közeljövőben nem várható, ezért meg kell kezdeni a szocializmus egy országban való felépítését. Sztálin elfogadta Lenin tételét. Vele szemben Trockij továbbra is bízott a világforradalom bekövetkeztében, mert szerinte ellenséges környezetben, és csak egy országban nem lehet felépíteni a szocializmust.\n\nSztálin munkás-paraszt ellenőrzési népbiztosként mindent behálózó és ellenőrző központot hozott létre, megszerezte a párt főtitkári posztját. Sztálin titkos szövetségre lépett Kamenyevvel és Zinovjevvel („trojka”), és sikerült elszigetelnie Trockijt, majd 1927-28-ban felszámolta a „trojkát” is. Ezután Sztálin gyakorlatilag már egyedül irányította a Szovjetuniót.\n\nA sztálini diktatúra 1927-tól 1953-ig\n\nTotális rendszert épített ki:\n\nA bolsevikok és különösen Sztálin is kiépítette a mindenre kiterjedő, azaz totális ellenőrzést. Hasonlóan tette ezt Hitler is. A parasztok nem hagyhatták el földjüket, és mindent be kellett szolgáltatni az állam részére.\n\nEszközei az erőszakszervezetek:\n\nA titkosrendőrség nevei: Cseka, GPU, 1934-től NKVD, majd KGB (a diktatúra terrorszervezetei)\n\n• Az NKVD vezetői: Jagoda (1934-36), Jezsov (1936-38), Berija (1938-tól), könyörtelenül üldözték az összes rendszerellenes elemet, sokakat küldtek munkatáborba, azaz a Gulagra.\n\n• (Lehetséges) ellenfelek meggyilkoltatása, pl. 1934-Kirov, 1940-Trockij\n\nKirov leningrádi pártfőtitkár, aki Az Össz-szövetségi Kommunista Párt 1934. évi kongresszusán a legtöbb szavazatot kapta Sztálinnal szemben, de Sztálin meghamisította a szavazás eredményét. Mivel Kirov népszerűbb volt Sztálinnál, ezért Kirov gyilkosság áldozata lett. Kirov halála ürügyén látványos koncepciós per zajlott, a gyilkosság után nagy politikai tisztogatási hullám indult, az 1934. évi kongresszus Központi Bizottsága tagjainak a többségét kivégezték, a Kirov-gyilkosság megrendelője valószínűleg Sztálin volt.\n\nKoncepciós perek (Visinszkij főügyész irányításával) koholt vádak alapján. A koncepciós perekben nem szabályos eljárásokat folytattak le)\n\n• 1936. aug.: az első nagy moszkvai per: Zinovjev, Kamenyev kivégzése\n\n• 1937. eleje: a második nagy moszkvai per\n\n• 1937. jún.: Tuhacsevszkij pere (a hadsereg „lefejezése”)\n\nA terror 1937-re elérte a Vörös Hadsereg vezetőit is, a polgárháború hőseinek élete sem volt biztonságban. Az eljárásokat gyorsan folytatták le: a tábornokok és főtisztek 90%-át kivégezték vagy kényszermunkára ítélték. A hadsereg vezetői elleni eljárás már a rendszer abszurditását mutatta, hiszen a második világháború előtt tapasztalt katonai vezetők nélkül maradt a Szovjetunió.\n\n• 1938. márc.: a harmadik nagy moszkvai per: Buharin, Rikov, Jagoda kivégzése (akasztják a hóhért)\n\n• 1940: Jezsov kivégzése\n\nGULAG (Lágerek Főparancsnoksága): munkatáborok a Szovjetunió minden részén\n\n• cél elvileg az átnevelés, de gyakorlatilag a munka (favágás, csatorna- és vasútépítés, bányászat)\n\n• embertelen körülmények, magas elhalálozási arány.\n\nA terror részeként kiépítették a javító-munkatáborok (GULAG) rendszerét, a táborok az egész országot behálózták. Kényszermunkatáborokba hurcolták az osztályellenségnek tekintett kulákokat. Az embertelen, elviselhetetlen körülmények miatt több millió ember pusztult el. A kényszermunkatáborok a társadalom megfélemlítésének az eszközei is voltak. A táborok a rendszer ipari és mezőgazdasági terveinek a megvalósítását is szolgálták. Etnikai alapon is folyt deportálás.\n\nSzemélyi kultusz: képek, versek, szobrok stb. Sztálinról. Ütemes taps.\n\nA propaganda:\n\n• bemutatta a gazdaság nagyszerű (sokszor a valóságot nem tükröző, megszépítő) eredményeit;\n\n• az emberek életkörülményeinek javulását, boldogságukat. A cél a „szocialista” embertípus kialakítása volt, aki: ideológiailag képzett és hű a párthoz; munkaszerető, családcentrikus, és hisz a szocializmusban. A propagandában jelentős szerep jutott a művészeteknek: irodalom, festészet, szobrászat; az újságoknak;\n\na filmnek és az oktatásnak. Az ifjúság nevelése érdekében létrejött az úttörőszervezet.\n\nA rendszer/ideológia jellemzője volt az egyház- és vallásellenesség, ateista nevelést kaptak a felnövekvő nemzedékek. Papok ezreit végezték ki, a templomok tízezreit pusztították vagy kobozták el.\n\nSztálin egyszemélyi vezetést, diktatúrát hozott létre, pártfőtitkárként személyesen irányította a pártbürokráciát, centralizálta a politikai hatalmat; bárkit bármikor félreállíthatott, minden pozícióba hű embereit ültette; a politikai rendőrséget használta ellenfelei likvidálására.\n\nSztálin totális államot hozott létre. A régi rendszert teljesen szétzúzták; mindent a szovjet, a párt ellenőrzött; állami terror működött; rendeletek útján törvénykeztek; a hagyományos társadalmi kötelékek szétzilálására törekedtek; az államhatalom beavatkozott a magánéletbe is; bizonytalanság, félelem, folyamatos éberség uralta a mindennapokat. A bizalmatlanság légkörében a barátok, a szomszédok, sőt a rokonok feljelentése is állampolgári kötelesség volt.\n\nSztálin személyi kultuszt épített ki maga körül: önmagát Lenin Nagy Tanítványának, a szovjet nép „bölcs vezérének” állította be. A valós eredményeket felnagyító, a társadalmi áldozatokat elhallgató propaganda hatására sokan elismerték Sztálin sikereit. A hétköznapokban képek, versek, szobrok és felvonulások dicsőítették a „szeretett” vezért. A személye körüli kultikus tiszteletről beszélhetünk, más modern diktátorok kultuszának is a mintaképe lett.\n\nA tervgazdálkodás, a szocialista iparosítás 1929-től:\n\n• 1928-29-től megkezdődött a mezőgazdaság kollektivizálása.\n\n• Sztálin ekkor már átvette Preobrazsenszkij „eredeti szocialista tőkefelhalmozás” tételét (az iparosításhoz szükséges tőkét a mezőgazdaságból kell kivonni), amely a szövetkezetesítéssel valósítható meg a legkönnyebben és leggyorsabban.\n\n• Az erőltetett kollektivizálás a parasztság elkeseredett ellenállásába ütközött (gabona-rejtegetés, állatok levágása), emiatt a mezőgazdasági teljesítmény jelentősen visszaesett. 1930 tavaszán átmenetileg megengedték a szövetkezetekből való kilépést, de 1931-től visszafordíthatatlanul folyt tovább a kollektivizálás.\n\n• A szövetkezetesítés nem váltotta be a hozzá fűzött reményeket, mert nem voltak meg a nagyüzemi gazdálkodást az egyéni gazdálkodás fölé emelő feltételek: gépek, technikák, technológiák és szaktudás.\n\n• 1932-33: a kedvezőtlen mezőgazdasági politika következményeként nagy éhínség lett, több millió halott.\n\n• 1935-től a kolhoztagok számára engedélyezték a max. 0,5 hektár háztáji föld művelését és az állattartást.\n\nIparosítás\n\n• Az első ötéves terv (1928-32):\n\n- Túltermelésre törekedtek, elsősorban mennyiségi téren pl. a széntermelést 35-ről 75 millió tonnára kellett emelni;\n\n- a terv nem teljesítése esetén bűnösöket kerestek, és találtak (kártevők, szabotőrök perei);\n\n- a beruházások döntő részét a nehézipar kapta, amely igen jelentős fejlődést produkált (új iparágak: pl. gépipar; új iparvidékek: pl. Ural-vidék). Ugyanakkor a fogyasztási cikkeket előállító ipar alig termelt: kialakult és állandósult az áruhiány.\n\n• A második ötéves terv (1933-37) már nagyobb hangsúlyt fektetett a fogyasztási cikkek gyártására.\n\n• Az ipar eredményei: ipari össztermelésben (legalábbis a statisztikai adatok szintjén) a Szovjetunió megelőzte Németországot, Angliát, Franciaországot, de a fejlettségi mutatókban még mindig messze elmaradt tőlük.\n\nKülkereskedelem\n\n• Fontos maradt a gabona- és a nyersanyagexport.\n\n• A gépek importja fokozatosan csökkent.\n\nA kitűzött gazdaságpolitikai célok:\n\n• Önellátás megteremtése, függetlenedés a kapitalista országoktól.\n\n• Egy (esetleges) háborúra való felkészülés.\n\nÁllami tervutasításos rendszer (élén a GOSZPLAN, az állami tervhivatal). A munkaerő mértéktelen kihasználása: munkaversenyek, sztahanovista mozgalom.\n\nA tervgazdálkodás megszüntette a piaci viszonyokat:\n\n• gazdaságilag irracionális, számszerűleg irreális terveket kellett teljesíteni;\n\n• mindez hamis adatokhoz; mérhetetlen emberi erő-, anyag- és energiapazarláshoz; súlyos környezetkárosításhoz vezetett.\n\nAz emberek életminősége alig javult (a párt- és állami vezetők ugyanakkor jól éltek), viszont mindennapjaikhoz hozzátartozott a félelem. A sztálini diktatúra uralt mindent.\n\nA kommunista és nemzetiszocialista ideológia összehasonlítása:\n\nKialakulása:\n\nA kommunizmussal kapcsolatos lényeges események:\n\n- 1848: Kommunista Kiáltvány (Marx)\n\n- 1917: bolsevik hatalomátvétel, a XIX–XX. század fordulóján szerveződik komoly erővé\n\n- az első világháború teszi lehetővé a hatalomra jutását\n\n- az első legjelentősebb kommunista állam Oroszország, majd más néven Szovjetunió volt.\n\n- 1922: Szovjetunió megalakulása\n\n- a második világháború után terjed el Közép-Európában és Kelet-Ázsiában,\n\n- a Szovjetunióban bő hetven évig volt uralmon, 1991-ig\n\nA nemzetiszocializmussal kapcsolatos lényeges események:\n\n- az első világháborút követően alakult ki (1919)\n\n- a nemzetiszocializmus Németországban jelent meg.\n\n- a világgazdasági válság idején (az 1930-as években) erősödött meg,k\n\n- 1933: Hitler hatalomátvétele, 1935: nürnbergi törvények\n\n- későbbi eredetű, mint a kommunizmus, marxizmus,\n\n- rövidebb ideig, 12 évig volt uralmon a nemzetiszocialista ideológia, 1945-ig.\n\nA kommunizmus célja:\n\n- osztályok megszüntetése,\n\n- a termelőeszközök köztulajdonba vétele,\n\n- a teljes egyenlőség megvalósítása\n\nA nemzetiszocializmus követelései:\n\na banktőke, a nagytőke korlátozása, a kisiparosok, kistulajdonosok védelme.\n\nMindkét eszme szocialista gyökerekkel rendelkezett\n\n- a társadalmi egyenlőséget tűzték ki célul\n\n- a kommunizmus felszámolni, a nácizmus korlátozni akarta a magántulajdont;\n\n- a kommunizmus tervgazdaságot, a nácizmus államkapitalista, korporatív gazdasági rendszert vezet be\n\n- a kommunizmus demokráciakritikája: az anyagi szükség illúzióvá teszi, átmeneti történelmi jelenség\n\n- a nemzetiszocializmus demokráciakritikája: a valóságban a nagytőke uralmát jelenti, ez egyenlő a\n\nszabad piaccal\n\n- mindkét eszme elutasította a működő liberális többségi demokráciát;\n\n- mindkét eszme népi felhatalmazásra hivatkozott, de valódi választásokat nem tartott.\n\nSzimbólumok:\n\n- az orosz-szovjet zászló változása: a zászlón kommunista jelképek jelentek meg – sarló, kalapács, vörös csillag, és a nemzeti színek helyett a munkásmozgalom vörös színét használták.\n\n- a német zászló változása: a zászló színei megmaradtak, új jelképként a náci horogkereszt jelent meg\n\n- a kommunista jelképek gyökeres szakítást jelentenek a korábbi nemzetiekkel, míg a náci jelképek módosították, kiegészítették azt;\n\n- a kommunista jelképek nemzetköziek (internacionalista), általánosak, a náci jelképek a németekre vonatkoznak (nacionalista).\n\nAz ideológiák jellemzői:\n\n- a kommunizmus internacionalista ideológia, elítéli a nacionalizmust,\n\n- a nemzetiszocializmus a nacionalizmus különösen szélsőséges, erőszakos formája,\n\n- a kommunizmus számos országban elterjedhetett,\n\n- a nácizmus kifejezetten német jelenség;\n\n- a kommunizmus nemzetközi proletárösszefogást hirdetett, a nemzeti helyett az osztályszolidaritást\n\nhangsúlyozta,\n\n- a nácizmus a nemzetet faji közösségnek tartotta, a kapcsolatokat – vélt – faji rokonság alapján épített ki; - a kommunizmus elvei ellenére sokszor támaszkodott a nemzeti érzésekre,\n\n- a nácizmus rokoneszméi sok helyen megjelentek pl. Magyarországon a nyilaskeresztesek.\n\nEllenségkép:\n\n- a kommunizmus - a kizsákmányoló osztályokat tekintette ellenségnek: burzsoázia\n\n- a nemzetiszocializmus mindenekelőtt a zsidókat tekintette ellenségnek,\n\n- mindkét ideológia elfogadta az ellenségek fizikai megsemmisítését is; pl. GULÁG, koncentrációs tábor\n\n- a kommunisták ellenségei a társadalom átalakításával eltűnnének,\n\n- a nácik az ellenséget faji alapon határozták meg\n\n- mindkét ideológia összekapcsolta az ellenségképet a kizsákmányolással.\n\nA vezér szerepe:\n\n- a kommunista ideológiában az ideológusok kultusza: Marx és Engels – mint az ideológia alapítója,\n\nilletve Lenin az ideológia továbbfejlesztője.\n\n- a bolsevikok vezetője, Sztálin az előzőek „tanítványa”, a rendszer megszilárdítója (vastaps állva, szobor) személyi kultusz\n\n- a kommunizmusban vezetők és az ideológusok egymáshoz kapcsolódó lánca alakult ki,\n\n- a kommunizmus vezetőit tudósoknak, elméleti szakembereknek állítja be, akik mindenek fölött állnak\n\n- a nemzetiszocializmus létrehozója, vezére Hitler (Führer) volt,\n\n- a nácizmusban Hitler szerepe egyedülálló (Heil, Hitler! + karlendítés, propagandabeszédek, felvonulás)\n\n- Hitler magát elsősorban politikusnak tartotta;\n\n- mindkét ideológiában erős személyi kultusz alakult ki a vezérek körül.', 332, 1, '2026-04-17 09:41:10', '2026-04-17 09:41:10');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(27, 27, 'Magyar - török küzdelmek a 15-17. században', '27.docx', '27. tétel: Magyar - török küzdelmek a 15-17. században\n\nAz Oszmán Birodalom kialakulása és terjeszkedése\n\nA korábbi Szeldzsuk-török Birodalom romjain 1299-től I. Oszmán (1288-1326) vezetésével függetlenné váló Oszmán Birodalom bekebelezte a környező területeket és tört Európa felé. Oszmán fia, I. Orhán (1326-1359) majdnem a teljes Anatóliára kiterjesztette a birodalom területét, megszervezte a közigazgatást, és az ő uralkodása alatt hódítottak a törökök Európában (1354-ben, Gallipoli elfoglalásával). I. Murád (1359-1389) idején, 1362-ben elfoglalták Drinápolyt, amely 1453-ig, Konstantinápoly elestéig fővárosuk is volt. I. Murád uralkodása végén, 1389-ben az első rigómezei csatában (a mai Koszovó területén) legyőzték a szerbeket. Az Oszmán Birodalom erejét a kitűnő közigazgatás, a jól kiépített földbirtokrendszer (ennek egy eleme volt a szpáhi-rendszer) és az erős hadsereg (köztük a janicsárság, amely gyalogos, zsoldos katona) és a tüzérség (topcsik) adta, ami ugyanakkor az állandó expanzió, terjeszkedés fenntartását igényelte. A tímárbirtok a szpáhik részére adott katonai szolgálati birtok, aminek éves jövedelme a 20 ezer akcsét nem haladhatja meg. Két fontos hadtest: ruméliai és anatóliai.\n\nA Magyarországot védő ütközőállamok török fennhatóság alá kerültek. A törökök meghódították a Balkán-félszigetet, csapataik rendszeresen betörtek Magyarországra.\n\nAz első magyar összecsapások a törökkel a XIV-XV. században:\n\nElőször I. (Nagy) Lajosnak (1342-1382) kellett megütköznie a törökkel 1366/67-ben, majd 1375-1377-ben.\n\nLUXEMBURGI ZSIGMOND (1387-1437)\n\n1389-ben az első rigómezei csatában Szerbia elesett, török kézre került. Az első igazán ismert és jelentős csatát Galambóc 1391-es török elfoglalása után Luxemburgi Zsigmond (1387-1437) vívta 1396-ban Nikápolynál. Annak ellenére, hogy külföldi segítséget is kapott, vereséget szenvedett I. Bajazid (1389-1402) szultántól. A nikápolyi vereség a törökök erőfölényéből is fakadt. Zsigmond ezután a védekezést helyezte előtérbe (déli végvárrendszer, illetve ütközőzóna kiépítése). A török elleni harc a Magyar Királyság megvédésén túl az európai kereszténység védelmét is szolgálta volna, de az összefogás hiánya nehezítette a török elleni fellépést.\n\nZsigmond a telekkatonaság bevezetésével kívánta erősíteni seregét, a katonaállítási kötelezettség alapja a jobbágyok száma volt. Magyarországon a nikápolyi csatát követően, az 1397. évi temesvári országgyűlés döntése alapján hozták létre a telekkatonaság intézményét, amely a korábbi banderiálistól független és a király irányítása alatt álló rendszer volt. Korábban a banderiális katonák a főurak vagy a megye saját zászlói és irányítása alatt vonultak csatába. Az új intézményben a földesúrnak minden 20 (később 33) jobbágytelek után egy könnyűfegyverzetű katonát kellett kiállítania. A hadseregreform nem érte el célját, ütőképes törökellenes haderő létrehozása a törekvések ellenére sem sikerült.\n\nA törökök 1402-ben súlyos vereséget szenvedtek a mongoloktól Ankaránál. 1413-ig, I. Mehmed trónra lépéséig a török birodalomban interregnum követett, így nem tudták kihasználni a győzelmüket, bár Zsigmond az 1410-es évek második felében és 1432-ben is többször megütközött velük.\n\nHunyadi János harcai\n\nMagyarországot a „kereszténység védőbástyájának” nevezték a korszakban. Hunyadi a keresztény Magyar Királyság hadvezéreként, majd kormányzójaként, de nagybirtokosként is védte a területet a törökkel szemben.\n\nHunyadi János (1407-1456, 1439-től szörényi bán, 1441-től erdélyi vajda) neve összeforrt a XV. századi törökellenes küzdelmekkel. Luxemburgi Zsigmond halála után (1437) trónviszályok lesznek Magyarországon, miközben egyre fenyegetőbb veszélyt jelent a török. Ebben az időben emelkedett a bárók közé Hunyadi János, aki Jagelló I. Ulászló (1440-1444) pártjára állt Habsburg V. Lászlóval (1453-1458) szemben. Cserébe tisztségeket és birtokokat kapott, sőt az ország haderejének jelentős részével rendelkezett.\n\nMagyarországon kiépült a végvárrendszer, szükségessé vált a balkáni népekkel való összefogás. Hunyadi János az ország legnagyobb birtokosa. Birtokai nagyrészt a déli végeken terültek el, országos tisztségeket birtokolt, az ország haderejének jelentős részével rendelkezett. Tisztségei és birtokai révén a törökellenes védekezés irányítója lett, az 1440-es évek elején aratott győzelmei népszerűséget hoztak számára.\n\nA Zsigmond halála óta elhúzódó török-magyar harcok után 1441-ben verte ki a törököt Erdélyből (ezután kapta meg az erdélyi vajda címet). 1442: Szentimre – vereség, de 1442-ben aratta gyulafehérvári győzelmét is. Erdélyben harcba hívta a környék lakosságát is, alkalmazta a huszita szekérvárat, s különböző fegyvernemeket kombinált. Elve: „Legjobb védekezés a támadás.” Győzelmei után népszerűségre tett szert.\n\nHunyadit a kereszténység védelmezőjének tekintették Európában. Hírnevét az 1442-es kereszténységet is védő hadjárataival alapozta meg. Támadó taktikát alkalmaz a törökök ellen: a „hadak villáma”. A törökök komoly ellenfélnek tartják már 1442-ben.\n\nA törökök rendszerint legalább kétszeres túlerőben voltak. Hunyadi harcmodora: a szárnyakon lendületes lovasrohammal kell megzavarni az ellenség lovasságát, miközben a gyalogság megkezdi az átkarolást. A túlerőben lévő, ám gyűrűbe szorított török sereg ily módon nem tudja kihasználni számbeli fölényét, mert csak a kör szélén elhelyezkedő katonák tudnak harcolni, a belül összetorlódottak legfeljebb azt várhatják, mikor kerülnek sorra. Hadjáratai során felhasználja itáliai, csehországi, huszita tapasztalatait a hadsereg szervezésekor: zsoldosokat, népfelkelőket, kereszteseket is irányít, saját bandériuma a familiárisaival. Módszere: a huszita szekérvár, a lovas támadás, a naszádosok felhasználása.\n\nMegszervezte szerb, lengyel és német-római segítséggel 1443/44-es hosszú (vagy balkáni) hadjáratát, aminek parancsnoka ő maga, illetve Brankovics György szerb fejedelem volt. 1443/44-ben a téli hadjárat során benyomult a török birodalomba. Az 1443-as hosszú hadjárat támadó hadjárat volt, célja a török főváros, Drinápoly elfoglalása lett volna, a magyar sereg mélyen benyomult török területre, majd visszafordulásra kényszerült. A törökök a béke értelmében kiürítették Szerbiát, a siker következtében kísérlet történt a törökellenes keresztény összefogásra, felmerült a törökök Európából történő kiszorításának gondolata, ezért a pápa újabb hadjáratra buzdította a magyar királyt.\n\nA sereget I. Ulászló (1440-1444) király vezette, a cél tehát Drinápoly (ma Edirne), az Oszmán Birodalom fővárosának elfoglalása volt.\n\nA hadjárat nem hozott jelentős stratégiai eredményt, ugyanakkor II. Murád (1421-1451) szultán tíz évre szóló békeajánlatot tett, amelyben átengedte Galambóc és Szendrő várát, valamint hadisarcot is fizetett. Az ajánlatot 1444 júniusában Drinápolyban elfogadták, azonban Ulászló engedett a nemzetközi nyomásnak és 1444 szeptemberében újabb támadást indított a török ellen. A hadjárat 1444. november 10-én a katasztrofális vereséget jelentő várnai csatával ért véget.\n\nA csata feltételei eleinte kedvezőek voltak: Hunyadi gondoskodott a megfelelő taktikáról a török ellen: a váratlan túlerővel szemben gyors támadást alkalmazott. A harc helyszínéül megfelelő terepet választott a török támadás kivédésére, mocsár védte az egyik szárnyát, próbálta ellensúlyozni a török fölényt, szekérvárat állított a másik szárnyon.\n\nA magyar sereg ennek ellenére vereséget szenvedett a várnai csatában, és a vereség oka: I. Ulászló meggondolatlanul cselekedett, és el is esett a csatában, pedig kezdetben a magyarok voltak fölényben.\n\n1445-ben ugyan a pesti országgyűlésen elismerték a kiskorú V. Lászlót királynak, de mellé hét főkapitányt választottak, köztük Hunyadit, aki 1446-tól kormányzóként (ún. gubernátorként) gyakorlatilag az ország vezetője volt. Ilyen minőségében 1448-ban nagyszabású hadjáratot indított a törökök ellen, azonban októberben a második rigómezei csatában ismét vereséget szenvedett. A vereség egy részét befolyásolta, hogy külső körülmények miatt volt Hunyadi sikertelen – elárulták, más taktikát alkalmaztak, mint amit meghatározott.\n\nKonstantinápoly 1453-as elfoglalása után II. Mehmed (1451-1481) szultán folytatta az előrenyomulást Európába. Erre válaszul Magyarországon az országgyűlés 1454-ben egy Hunyadi által vezetett hadsereg felállítását szavazta meg, míg III. Callixtus pápa keresztes hadjáratot hirdetett. A toborzásra Magyarországra érkezett Kapisztrán János ferences rendi szerzetes is. A szultán 1456. július elején kezdte meg Nándorfehérvár (ma Belgrád) ostromát, a vár védője Szilágyi Mihály volt. Nándorfehérvár a végvári vonal kulcsa.\n\nRögzítés Hunyadi áttörte a török hajózárat, bejutott a várba, a csatában képzetlen keresztes seregek is részt vettek Kapisztrán János vezetésével. Nándorfehérvár stratégiailag fontos helyen feküdt. A fő cél a török előrenyomulás megakadályozása és a kereszténység védelme volt. Hunyadi János felszabadította Nándorfehérvár várát a török ostrom alól. Hunyadi és Kapisztrán közbeavatkozására 1456. július 22-én a magyar seregek győzelmet arattak, 1456 augusztusában azonban Hunyadi meghalt a pestisjárványban. Hunyadi János sikeresen megvédte Nándorfehérvárt, ezzel elhárult a török hódítás közvetlen veszélye, több évtizedig nem érte ilyen támadás Magyarországot\n\nHunyadi Mátyás harcai\n\nHunyadi Mátyás (1458-1490)\n\nA pápa Mátyás személyével kapcsolatban örömét fejezte ki királlyá választása miatt. Isten emberét, a kereszténység védelmezőjét látta benne, és a törökellenes küzdelmek folytatását várta tőle.\n\nMátyás részben fenntartotta a korábbi banderiális rendszert, a telekkatonaság intézményét viszont az 1470-es évektől nem alkalmazta. Arra törekedett, hogy a katonaállítási kötelezettség érvényesítése helyett pénzbevételre tegyen szert, így kb. 20 000 fős állandó, csakis tőle függő - elsősorban magyarokból, csehekből és németekből álló - zsoldoshadsereget tudott fenntartani, ez volt későbbi elnevezésén a fekete sereg, amelynek vezetője többek között Haugwitz János, Hág Ferenc, Kinizsi Pál és Magyar Balázs volt. A hadászatban Mátyás széles körben alkalmazta egyrészt apja újításait (a bekerítéses taktikát, a huszita szekérvárat), de nála jelent meg új fegyvernemként a lovas huszárság is.\n\nA „fekete sereg”\n\nMátyás hadseregét halála után „fekete seregnek” nevezték. Az elnevezés eredete a mai napig vitatott. Közkeletű hiedelem, hogy a Hunyadi címerben szereplő holló színe után kapta a sereg a nevét. Más vélemények szerint a sereg Fekete Ferenc vezér vezetékneve miatt lett éppen „fekete”, míg vannak olyanok is, akik az akkoriban viselt sodronyingek sötét színéből eredeztetik az elnevezést.\n\nMátyás az 1460-as évek közepétől egyre több zsoldost fogadott fel. A zömében csehekből és lengyelekből álló sereg létszáma – Mátyás jövedelmeitől függően – akár 15-20 ezerre is emelkedhetett. A fekete sereg ellentétben a bandériumokkal, mindenhol és mindenki ellen felhasználható haderő volt. A sereg négy fegyvernemből állt: nehéz- és könnyűlovasság (huszárok), gyalogosok, tüzérség. A fekete sereg fönntartása nagy gondot okozott Mátyás számára, mivel egy lovas katona havi zsoldja 3, egy gyalogosé 2 forint volt.\n\nSerege nagy részét igyekezett állandóan fegyverben tartani. A sereg magját szolgálatába állt husziták adták, akikhez később lengyel, német és természetesen magyar katonák is csatlakoztak. A seregvezérek is ezen népekből verbuválódtak (Haugwitz, Tettauer, Geréb). Mátyás seregének több hadvezére is nagy hírnevet szerzett hősiességével (Kinizsi Pál, Magyar Balázs). A király elméletileg is képzett hadvezér volt (olvasta az ókori hadi írók munkáit). Felismerte a tüzérség jelentőségét és szívesen alkalmazott különböző mechanikai találmányokat (pl. ostromtornyot). Ám harctéri sikereit gyors helyzetfelismerő képességének, merész ötleteinek köszönhette, s annak, hogy tudott bánni katonáival.\n\nMátyás külpolitikája\n\nMátyás külpolitikája nyugat felé támadó, a török felé pedig védekező volt Támasza: az állandó zsoldoshadsereg, amelynek segítségével függetleníti magát a bárói bandériumoktól. Hadserege korszerű, kiképzett, csak a királytól függő, zsoldért harcoló had volt.\n\nTörökellenes politika\n\nMátyás törökkel szembeni politikájára az aktív védekezés volt jellemző, míg Hunyadi János taktikája a támadás volt, addig Mátyás a déli határ biztosításában látta a török elleni védekezés legfontosabb feladatát.\n\nII. Mohamed, kihasználva a magyar politikusok lekötöttségét és Brankovics halálát, végérvényesen elfoglalta Szerbiát a fontos Duna menti végvárakkal egyetemben (Galambóc, Szendrő). A török elleni harcra szorította a királyt a közhangulat is: a magyar nemesség előtt csak az az uralkodó lehetett népszerű, aki hagyományos támadó hadjáratokat indított a török ellen.\n\nMátyás 1463-ban Bosznia védelmére indult. Mindkét fél várak megszerzésével kívánta biztosítani helyzetét. Nem ütközött meg a török fősereggel, Boszniában mindketten terjeszkedtek, visszavette Jajcát 1463-ban, Szreberniket 1464-ben. Mátyás ezzel kiegészítette a végvári rendszert, a balkáni ütközőállamok megszűntek, felosztották őket. Mátyás a hadjáratot propagandacélokra is felhasználta. Így Bosznia északi része magyar, déli fele török kézre került, s a tartomány területén is kiépült a magyar és a török végvári vonal.\n\nMint láttuk, Mátyás már Boszniában is kerülte a döntő összecsapást a törökkel, s csak a végvári rendszer kiegészítésére törekedett. Ez jellemezte későbbi török politikáját is, csak sokkal nyíltabban, mert koronázása után már kevésbé volt tekintettel a nemesség óhajaira. Belátta: nyugati támogatás híján támadó hadjáratokra kevés az ország ereje az egyre erősödő törökkel szemben. A török elleni harc elhanyagolását eredményezték nyugati törekvései is.\n\nA török sem kezdeményezett támadásokat, állóháború alakult ki. Mátyás az 1470-es években többször átengedte ellenfele, III. Frigyes osztrák tartományai felé. 1474-ben a felbátorodott török Váradig benyomult az országba, és rabok tömegével hagyta el azt. Ugyanebben az évben új várat épített Szabácsnál a Száva mocsarában. A közvélemény nyomására Mátyásnak válaszolnia kellett erre a lépésre. Ezért 1475 őszén, hogy ne találkozhasson a szultáni főerőkkel, zsoldosaival és a hagyományos magyar haderővel elfoglalta a jelentéktelen várat. Gondja volt arra, hogy híre keljen törökellenes megmozdulásának. 1476-ban Szabácsot foglalja el a töröktől.\n\nAz uralkodó a déli végvárvonalat karban tartotta, sőt fejlesztette. A várak szerepe kettős volt: egyrészt kivédték a portyákat, illetve maguk indítottak délre betöréseket; másrészt a nagyobb támadásokat felfogták addig, amíg felmentő sereg érkezett az ország belsejéből. A végvári vitézek magyarok és délről menekült délszlávok voltak. Hasonló volt az összetétele a Mátyás által a dunai védelem érdekében felállított sajkás hadnak is.\n\nA török 1479-ben nagy erőkkel tört Erdélyre, és foglyok ezreivel akart kivonulni. Báthori István erdélyi vajda Gyulafehérvár közelében, Kenyérmezőnél állította meg őket. Válaszul a betörésre a király és Kinizsi Pál a következő évben Szerbiát és Boszniát dúlta.\n\nA déli határvidék megerősítése már Mátyás királyra maradt. Amikor II. Mehmed szultán 1458-ban bekebelezte Szerbiát, 1463-ban pedig Boszniát, Mátyás a török ellen indult. Állandó zsoldoshadserege segítségével sikerült visszafoglalnia a végvárak nagy részét: 1458. Galambóc, 1463. Jajca, 1464. Szrebernik.. Bosznia déli területeit azonban nem sikerült fennhatósága alá vonnia. Később, 1479-ben a kenyérmezei csatában az Erdélybe betörő törökök felett Kinizsi Pál és Báthory vajda aratott győzelmet. Mátyás II. Mehmed 1481-es halála után annak utódjával, II. Bajaziddal (1481-1512) három évig húzódó katonai konfliktus után öt évre szóló békét kötött 1483-ban. Nyugati tervei miatt Mátyás nem akart háborút, ezért kötött békét a törökkel 1483-ban öt évre, amit egészen 1520-ig a magyar királyok ismételten megújították. Ez persze nem jelentett igazi békét, csak a nagyobb hadjáratok szüneteltetését: a Délvidék tovább pusztult.\n\nÉrtékelése:\n\nMátyás törökökkel kapcsolatos politikája során tehát védekezésre rendezkedett be, békét kötött. Megerősítette a végvárrendszert, ez tette lehetővé nyugati hódításait. A béke ellenére azonban voltak portyázások. Felismerte, hogy Magyarország szövetségesek nélkül nem tudja kiűzni a törököt Európából. Mátyás uralkodása alatt történt Szabács elfoglalása, és a kenyérmezei győzelem. Szabács elfoglalásának inkább politikai jelentősége volt, a kenyérmezei csatára pedig a törökök Erdélybe indított hadjárata miatt került sor. A csatában a fekete sereg, Kinizsi Pál és az erdélyi vajda, Báthory István katonái vettek részt.\n\nMátyás alapvetően védekező politikát, békepolitikát folytatott a török irányában. Megerősítette a – Zsigmond idején épülni kezdett – végvári vonalat. Az ütközőállamok megszűnésével kettős védelmi vonal épült, ez összefüggött Mátyás nyugati hódító törekvéseivel. Mátyás modern zsoldos haderőt, a fekete sereget tartott fenn. A török elleni sikerek uralkodói hatalmának legitimálását is szolgálták, apja politikájának folytatójának tüntették fel. A korszakban a török nem próbálkozott jelentős támadással.\n\nHanyatlás és katasztrófa\n\nII. Ulászló uralkodása (1490-1516) alatt nem sikerült eredményt elérni a törökkel szemben. 1491-től váltakozó sikerű harcok folytak a déli területeken, végül 1495-ben - később többször meghosszabbított - békét kötöttek az Oszmán Birodalommal, aminek eredményeképpen a XVI. század első évtizedének végéig viszonylagos nyugalom honolt a déli határok vidékén. Mindemellett Mátyás zsoldosserege lezüllött, így a katonák rablásból tartották el magukat, ami oda vezetett, hogy 1492 szeptemberében Kinizsi Pál szétverte a sereg maradványait. Ezt követően visszaállították a banderiális hadseregszervezetet a bárók irányításával.\n\nÉrtékelése:\n\nII. Ulászló koronázási feltételeinek lényege a rendkívüli hadiadó megszüntetése. Ezzel az uralkodói jövedelmek jelentősen csökkentek, emiatt feloszlatták a fekete sereget. Az ország védelme a bandériumokra, magánhadseregekre hárult, emiatt a végvári vonal leépült, szűkült az ország külpolitikai mozgástere.\n\nAz oszmán haderő – az 1510–20-as években – elfoglalta a magyar végvárakat. 1521-ben Nándorfehérvárt. Ez a végvári vonal hanyatlásának eredménye, ezzel megnyílt az út az ország belsejébe. A Jagellók képtelenek voltak megvédeni Magyarországot.\n\nA mohácsi csata és az ország három részre szakadása\n\nII. Ulászló halála után 10 éves fia, II. Lajos (1516-1526) került trónra:\n\n• kormányzó volt mellette: Bakócz Tamás esztergomi érsek;\n\n• az ügyeket a 16 nemesből, 6 báróból és 6 főpapból álló tanács intézte.\n\nTörök támadások (1521)\n\n• I. Szulejmán (1520-66) első támadása során elfoglalta Szabácsot és\n\nNándorfehérvárt.\n\n• II. Lajos ezután megpróbálta megerősíteni a királyi hatalmat, de nem sikerült.\n\n• A török újabb támadásáról tudtak a magyarok, de semmiféle előkészületre\n\nnem került sor.\n\n• A szultáni sereg 1526 áprilisában indult Isztambulból, július elején kelt át a Száván,\n\njúlius 14-27. között bevette Péterváradot, augusztus 8-án Újlakot.\n\n• A király késlekedett, és csak július 20-án indult el Budáról.\n\nA döntő összeütközésre Mohácsnál került sor 1526. augusztus 29-én:\n\n• A magyar seregek fővezére Tomori Pál kalocsai érsek volt, aki a támadást elindította a még teljesen hadrendbe fel sem állt törökök ellen. A magyar nehézlovasság rohama azonban megtört, a janicsárok pedig megsemmisítették a magyar centrumot.\n\n• Magyar veszteségek: menekülés közben a Csele patakba fulladt a király, meghalt 7 főpap (Tomori is), 28 főúr. Túlélte viszont a vereséget Szapolyai János, aki elkésett a csatából, valamint Báthori István nádor. A halottak száma 15 000 körül lehetett.\n\nSzapolyai serege érintetlen maradt. Mohácsnál a magyar sereg megsemmisítő vereséget szenvedett. Az oszmán hadsereg létszám- és technikai fölényben volt. Magyarország nem kapott külső segítséget. A király halálával az ország vezető nélkül maradt.\n\n• I. Szulejmán a győzelem után bevonult Budára, amit katonái kifosztottak, majd foglyok tízezreivel kivonult az országból.\n\nA mohácsi csatavesztés után anarchikus állapot uralkodott. Két politikai tábor alakult ki:\n\n• Habsburg pártiak (Mária özvegy királyné körül Pozsonyban);\n\n• Szapolyai pártiak (Szapolyai János körül).\n\n1526 novemberében a fehérvári országgyűlésen 22 megye követe Szapolyai Jánost királlyá (1526-40) választotta, akit ezután a rangidős nyitrai püspök meg is koronázott.\n\n1526 decemberében a Pozsonyba összehívott országgyűlés viszont Habsburg Ferdinándot (1526-64) választotta királlyá. Ferdinánd volt nehezebb helyzetben, habár mögötte állt a testvére, Habsburg V. Károly császár:\n\n• nem voltak nagy magyarországi birtokai;\n\n• kevesebb volt a támogatóinak a száma, de néhány főúr (Báthori István, Brodarics István, Nádasdy Tamás) már csatlakozott hozzá. 1527-ben kitört a harc: Ferdinánd támadást indított Szapolyai ellen, elfoglalta Budát, majd Fehérváron őt is megkoronázták.\n\n• A menekülni kényszerült Szapolyai 1528-ban szerződést kötött I. Szulejmánnal, aki segítséget ígért a Habsburgok elleni harcban. Még ebben az évben török segítséggel Szapolyai vissza is foglalta a Tiszántúlt.\n\nÉrtékelése: Szulejmán vazallusának tekintette Szapolyait. Szapolyai török támogatással uralkodott. Ferdinánd legyőzte Szapolyait, aki a törökhöz fordult. A kettős királyválasztás következtében az ország két – lassan elkülönülő – részre szakadt.\n\nI.Szulejmán Bécs elleni hadjáratai: 1529, 1532, 1566.\n\n1529-ben I. Szulejmán megindult Bécs ellen, és „útközben” visszavette Budát, amit végül átadott Szapolyainak.\n\n• Alig hogy Szulejmán kivonult, kiújult a harc Ferdinánd és Szapolyai között. Megszerzett területeiken különálló hivatalokat állítottak fel: az ország két részre szakadt.\n\nSzulejmán 2. bécsi hadjárata (1532) során Kőszegig jutott, amit Jurisics Miklós védett több mint 3 hétig. A török így sikertelenül próbálta elfoglalni Bécset.\n\nAz ekkortól felerősödött törökellenes hangulat vezetett el Szapolyai és Ferdinánd váradi békekötéséig (1538):\n\n• megosztoztak az országon, de úgy, hogy Szapolyai halála után területei Ferdinándra szállnak majd.\n\n• A békét azonban egyik fél sem tartotta tiszteletben:\n\nFerdinánd „beárulta” Szapolyait a Portánál;\n\nSzapolyai pedig dinasztiaalapítási (utódlási) szándékkal feleségül vette Jagelló Izabellát, a lengyel király lányát, akitől született egy fia: János Zsigmond.\n\nAz 1538-as váradi egyezmény lényege: a Habsburgok uralma alatti későbbi országegyesítésben állapodtak meg. Erőegyensúly alakult ki Ferdinánd és Szapolyai János között. Az egyezményt később Szapolyai János és hívei megszegték.\n\nA két király küzdelme lehetőséget teremtett újabb török hadjáratokra, hiszen kihasználta az ország megosztottságát.\n\nAmikor 1540-ben Szapolyai János meghalt, fiát I. Szulejmán elismerte örökösének, a gyermek János Zsigmondot hívei királlyá választották, helyette anyja, Jagelló Izabella és Fráter György kormányoztak.\n\n• Ferdinánd nem nyugodott bele, és 1541-ben elfoglalta Visegrádot és Pestet, majd Budát is ostromolni kezdte. I. Szulejmán azonban segítséget küldött, előhadai felmentették a várat.\n\n• Amikor a szultán is Buda alá érkezett, táborába rendelte János Zsigmondot és híveit, eközben a török katonák békésen elfoglalták Budát (1541), ezzel a törökök állandósították jelenlétüket az országban, amely így három részre szakadt.\n\nBuda 1541-es elfoglalásával létrejött a Hódoltság, létrejött a budai vilajet, az ország három részre szakadt. János Zsigmond országrészéből alakult ki az Erdélyi Fejedelemség. Szapolyai János halálával Ferdinánd egyesíteni akarta az országot.\n\nFráter György személyes felelősséget érzett abban, hogy Budát elfoglalta a török.\n\n• Fráter György 1541-ben Ferdinánddal megkötötte a gyalui egyezményt (váradi béke felújítása);\n\n• tervbe vették Buda visszafoglalását, ez azonban még a kísérletig sem jutott el.\n\n1549-ben újabb megállapodás alapján Fráter György vállalta, hogy Ferdinándnak átadja Erdélyt:\n\n1551-ben Ferdinánd Castaldo vezetésével Erdélybe küldött egy 7500 fős sereget, de ez elégtelen volt Erdély megvédésére. Fráter György, hogy a török ellentámadást (és így Erdély elfoglalását is) megelőzze, tárgyalásokba bocsátkozott Szokollu Mehmed ruméliai beglerbéggel.\n\nCastaldo ezért Fráter Györgyöt árulónak nyilvánította, és alvinci kastélyában megölette 1551-ben.\n\nIzabella és János Zsigmond, akik Sziléziába menekültek, 1556-ban visszatértek Erdélybe. Az erdélyi országgyűlés II. János kiskorúsága idején Izabellára bízta Erdély kormányzását (1556-59). Miután Izabella meghalt, János Zsigmond és I. Ferdinánd fegyverszünetet kötött.\n\n1566-ban indul Bécs ellen ismét (3.) I. Szulejmán, de Szigetvárnál meghal.\n\nVégvári küzdelmek\n\n• A törökök magyarországi jelenléte új végvárvonal kiépítését, illetve a meglévő várak megerősítését tette szükségessé:\n\n• nyugat: Sziszek—Kapronca—Szigetvár—Kanizsa—Veszprém—Palota-Győr—Komárom;\n\n• észak: Érsekújvár—Eger—Tokaj—Szatmár;\n\n• kelet: Várad—Gyula—Lippa—Temesvár—Lúgos—Karánsebes.\n\n• A végváraknál jelentős erődítési munkálatokat kellett elvégezni:\n\n• Ha voltak, akkor elbontották a keskeny, magas falakat, és alacsonyabb, modern, olasz mérnökök tervei alapján készült, a falsíkból ékszerűen kiugró ötoldalú bástyákból, az un. fülesbástyákból álló megerősített várfalakat építettek.\n\n• Agyaggal vagy sárral megtöltött gerendasorból, vesszőnyalábokból készült palánk várakat is építettek.\n\nTörök támadások több hullámban érték Magyarországot.\n\nAz első hullám 1543-tól 1547-ig tartott. Előzménye: 1542-ben a birodalmi és magyar hadak sikertelen kísérletet tettek Buda visszafoglalására, ami kiváltotta a török támadást. A hadjárat elsődleges célja Buda védelmi övezetének kialakítása és a Duna-menti hódítások biztosítása volt. Nagyobb ellenállás nélkül került török kézre Pécs, Esztergom, Győr, Tata, Fehérvár, Visegrád, tovább növelve a hódoltsági területet.\n\nA második hullám 1552-ben kezdődött, két vezér, két irányból kezdte a hadműveleteket:\n\nCélja az volt, hogy meghiúsítsa az ország újraegyesítését. Szulejmán a nagy hadjárat vezetésével Ahmed másodvezírt bízta meg, aki Temesvár ellen indult. A vár parancsnoksága Losonczy István temesi ispán kezében volt. A spanyol zsoldosok nyomására Losonczy tárgyalásokat kezdett Ahmeddel, de a kivonuló védőket tőrbe csalták. Ali budai pasa a bányavárosok bevételére indulva a gyönge Drégelyt támadta meg, melyet Szondi György védett 150 emberével. Szondi visszautasította Ali feltételeit, megsemmisítette a várban lévő értékeket, s a romok között vesztette életét.\n\nAli és Ahmed pasa Szolnok alatt találkozott. Az őrség többsége megszökött a török elől, magára hagyva parancsnokát, Nyári Lőrincet, aki tíznapi ostrom után feladta a várat. Innen a 70 000 főnyi török sereg a „Felvidék kapuja”, Eger ellen indult, melyet Dobó István (és Mekcsey István) 2000 fővel védett. Kétheti ágyúzás után vezette a török az első rohamot a falak ellen, de ezt a védők visszaverték. Elutasították a török megadási ajánlatát. A védekezés egyre hatékonyabb eszközeit használták (aknák, ellenaknák, tüzes szerszámok). Október 18-án a török sereg a közelgő ősz elől téli szállására vonult vissza. A védők hősies helytállása bebizonyította, hogy kellő elszántsággal a szultáni seregnek is ellent lehet állni. A török haderő - befejezve a perzsa háborút - folytatta sikeres hódítását. A Balatontól délre sorra foglalta el a császáriaktól magukra hagyott várakat.\n\nA török támadások harmadik hullámára 1566-ban került sor. A 72 esztendős Szulejmán szultán utolsó hadjáratát indította Magyarország ellen. A törökök elfoglalták Jenő, Világos, Gyula várát, majd a szultán a nagyobb sereggel pedig Szigetvárt vette ostrom alá. Zrínyi Miklós horvát bán és dunántúli főkapitány 2500 főnyi horvát és magyar őrséggel védte a várat a százezres támadó törökkel szemben. Az állandó ágyútűz, az égő vár a védők helyzetét tarthatatlanná tette, a megadás helyett azonban a hősi halált választották. Szulejmán halála megakadályozta a hadjárat folytatását.\n\nI. Ferdinánd halála után I. Miksa (1564-76) megtámadta Erdélyt, amelynek megtorlására I. Szulejmán 1566-ban újabb hadjáratra indult, de Szigetvár ostroma közben, de nem harc közben halt meg.\n\n1568-ban a Habsburg I. Miksa (1564-1572) és II. Szelim (l566-74) megkötötte a drinápolyi békét: rögzült az ország 3 részre szakadása.\n\n• I. Miksa vállalta 30 ezer magyar arany adó fizetését a kezében lévő magyarországi területekért. I. Miksa ígéretet tett arra, hogy nem támadja meg Erdélyt és Moldvát.\n\n1570: speyeri szerződés I. Miksa és Szapolyai János (Zsigmond) között:\n\n• Létrejött az Erdélyi Fejedelemség.\n\n• János Zsigmond a Habsburgok javára lemondott a magyar királyi címről, és felvette az Erdély és a Partium fejedelme címet.\n\n• János Zsigmond után fiai az örökösök, ha a Szapolyai család kihal, akkor Erdély és a Partium a magyar királyra száll.\n\nA három részre szakadt Magyarország:\n\nKirályi Magyarország – Habsburgok:\n\nA Magyar Királyság a Habsburg Birodalom része volt, a Habsburgok uralma alatt állt. Európában a „kereszténység védőbástyájaként” tekintettek Magyarországra.\n\n1526 után fokozatosan alakult ki az egykori magyar királyságból a királyi Magyarország, a török hódoltsági terület és az Erdélyi Fejedelemség. A királyi Magyarország a nyugati és északi országrészeket foglalta magában.\n\nVédelmét hat főkapitány, száz végvár és 15-20 ezer katona látta el. A zsold, valamint az erősségek korszerűsítése a kincstárt terhelte. A Német-római Birodalom rendjei tetemes összeggel támogatták Magyarország védelmét.\n\nTehát a Német-római Császárság rendjei és a többi Habsburg tartomány is részt vállalt a pénzügyi támogatásból. A Habsburgok kiterjedt birodalmukra támaszkodva jelentős összegeket teremtettek elő a védekezésre. A Habsburgoknak érdekében állt a török terjeszkedés feltartóztatása. A magyar rendeket az udvarral való együttműködésre ösztönözte a pénzügyi támogatás, ugyanis a magyar rendek a bécsi udvar segítsége nélkül nem tudták volna fenntartani a végvárakat. A magyar rendek is lépéseket tettek a törökök elleni védekezés érdekében, a jobbágyok ingyenmunkájával akarták megerősíteni a várakat.\n\nMivel ezekhez a pénzforrásokhoz csak a Habsburgokon keresztül lehetett hozzájutni, a kortársak szerint Magyarország az ő segítségük nélkül nem tarthatná magát, nemcsak koncentrált támadás, de akár kisebb török haderővel szemben sem. Magyarország politikai és igazgatási rendszerében az udvar országon kívülre helyeződése és a törökellenes harc követelményei okoztak változást. Bécsben már korábban kialakultak a központi hivatalok. Ferdinánd Magyarországon felállította a magyar központi kormányszékeket: a helytartótanácsot, a magyar kancelláriát és a magyar kamarát.\n\nAz átalakulásokat a magyar rendiség intézményrendszerének zöme, pl. a nádori tisztség, az országgyűlés és a nemesi vármegye átvészelte. A főkapitányi tisztet is magyar nagybirtokosok töltötték be, így a végvári katonaságot fölhasználhatták a rendiség védelmében. A nagybirtokosok komoly magánhadsereggel rendelkeztek, törekvéseik arra irányultak, hogy megőrizzék a magyar királyság önállóságát.\n\nA rendi törekvésekre a kormányzat a nádori szék betöltetlenül hagyásával, olykor pedig az országgyűlések megritkításával válaszolt, igaz, az utóbbi összehívására az adók megajánlása miatt mégiscsak rákényszerült. A belügyekben a rendek nagyobb önállósággal rendelkeztek, ami tulajdonképpen az uralkodó és a rendek közötti hatalommegosztást tükrözte. Idegen uralom alatt kibontakozó rendi dualizmusról beszélhetünk tehát. Téves nézet Habsburg-ellenes küzdelemről beszélni már a XVI. században. Az udvar és a rendek „küzdelme” 1604-ig alkotmányos keretek között folyt.\n\n• A végvárakban több tízezer fős, zömében magyar katonaság szolgált, amely egy idő után önálló társadalmi réteggé formálódott (vitézlő rend). Voltak közöttük elüldözött vagy menekülő nemesek és jobbágyok is. A vitézlő rend átmeneti kategória volt a nemesség és a jobbágyság között, de tagjai nemesi előjogaik megtartására vagy azok megszerzésére törekedtek. A végvári katonák zsoldot kaptak, amelynek kifizetése azonban sokszor akadozott („se pénz, se posztó”), ezért sokszor indultak portyázó (rabló) hadjáratokra; részt vettek a marha-kereskedelemben, földet műveltek.\n\nA korszakban kiépült egy új végvárvonal (pl. Eger, Győr, Kanizsa). A legnagyobb várak kővárak voltak. Új bástyatípusok jelentek meg. Fontos szerepet kaptak az itáliai hadmérnökök. Kb. 100 erődített helyből állt a végvárrendszer, melyben 15–20 ezer katona szolgált. A katonai igazgatás élén az Udvari Haditanács és a főkapitányságok álltak. Az Udvari Haditanács hatásköre az egész birodalomra kiterjedt, a főkapitányságok egy-egy nagyobb vár köré szerveződtek.\n\nA Török Birodalom – Magyarország középső és déli része (Török Hódoltság)\n\nA magyar hódoltsági terület a török birodalom legészakibb tartománya volt. Az országrészt a törökök katonai alapon rendezték be. Közigazgatási egységei a vilajet (élén a pasa) és a szandzsák (élén a bég). A szultáni udvar nevezte ki a pasákat, a kádit és a defterdárt.\n\nA török birtokrendszer szerint a meghódított föld a szultáné. Ebből kaptak birtokot a tisztviselők és a szpáhik, de csak haszonélvezőként (tímárbirtok). Kedvezőbb volt a khászbirtokon (a szultán saját kezében tartott birtokán) élők helyzete. A kincstár, saját érdekében, a termelés folyamatosságának fenntartására törekedett. Az adóztatásnál figyelembe vették a korábbi magyar gyakorlatot, amiért még a magyar törvényeket is tanulmányozták. A török földesúrnak a jobbágy kapuadót, tizedet, ajándékot, a kincstárnak pedig harádzsot és rendkívüli állami hadiadót tartozott fizetni. Nem állja meg helyét az a nézet, hogy a török adó súlyosabb volt, mint a magyar, és az sem, hogy többször behajtották volna. Ami valóban megnövelte a jobbágyság terheit, az az volt, hogy a török mellett adóznia kellett a magyar földesúrnak, a magyar államnak és az egyháznak is. Ez a kettős adóztatás az egész megszállt területre kiterjedt, és a török uralom végéig fennmaradt.\n\nHabsburg - török erőegyensúly alakult ki a két hatalom közt. A XVI. században ugyanis lezárult a török terjeszkedés. A Habsburgok védekezésre rendezkedtek be. Magyarország ütközőterületté vált a két birodalom közt.\n\nAz Erdélyi Fejedelemség\n\nA XVI. század második felében alakult ki. Területéhez tartozott a Magyarországról leválasztott Partium (Részek). Ez a vidék fejlett mezőgazdaságával, bányáival gazdagította a fejedelemséget. A lakosságot vallási és etnikai megosztottság jellemezte.\n\nSajátos helyzetét Erdély a keresztény Európa és az oszmán világ közötti hatalmi viszonyok alakulásának köszönhette. Politikáját a veszélyeztetettség tudata határozta meg. Ezért kaptak elsőrendű szerepet a védelmi természetű feladatok: a hadügy, a pénzügy, ami a fejedelmi hatalom túlsúlyát eredményezte. E hatalom két pilléren nyugodott: a kincstár volt a legnagyobb birtokos, a hatalom másik pillére pedig a szultán kinevező irata (athnáme) volt, amely segítséget ígért a külső és belső ellenséggel szemben.\n\nA politikai életben szerepet játszottak a három nemzet képviselői: a magyar vármegyék, a székely és szász székek. Az 1437-ben létrejött kápolnai uniót 1542-ben a tordai országgyűlésen megújították.\n\nA fejedelmi hatalommal szemben a rendiség gyenge volt. Nem alakulhatott ki Magyarországhoz hasonló nagybirtokrendszer. Itt a kincstári jövedelemforrások magánkézre kerülése vált szokássá. Olyan politikai berendezkedés volt ez, amely csak kimagasló képességű fejedelmek irányításával - mint Báthory István, később Bethlen Gábor - szolgálta Erdély érdekeit.\n\nKülpolitikailag Erdély a Portától függött: a szultánnak évi adót fizetett, a belső megszilárdulás azonban fokozatosan kitágította külpolitikai mozgásterét. Rendszeres kapcsolatot tartott Béccsel, Franciaországgal és a protestáns hatalmakkal.\n\nFerdinánd utóda, I. Miksa császár 1568-ban békét kötött II. Szelimmel Drinápolyban. Ez a béke szentesítette az 1552. és 1566. évi török foglalásokat, s ezzel lezárta a nagy hódítások korszakát.\n\nA 15 éves háború: 1591-1606.\n\nA drinápolyi béke a királyi Magyarország és Erdély megszilárdulását hozta. I. Habsburg Miksa utóda, I. Rudolf (1572-1612) a török hatalmának megtörésére törekedett. Az összehívott tanácskozás azonban a felső-magyarországi kapitány előterjesztését fogadta el, amelyben a békés állapot biztosítását szorgalmazta. Mind a bécsi, mind a magyarországi alattvalók még mindig feltartóztathatatlannak gondolták a török terjeszkedését. Így a Habsburg-török háborút ismét a törökök kezdeményezték.\n\nA török támadás okai: a törökök Perzsia elleni háborúja területnyeréssel járt, de súlyos pénzügyi gondokat eredményezett. Az inflációs pénzzel fizetett zsoldosok, a janicsárok fellázadtak; így új hódításokkal igyekeztek kárpótolni őket. A belső gondok feloldását a győzelmektől várták. Hasszán boszniai pasa 1591-től fogva sorozatos támadást indított a drinápolyi békét (1568) megszegve Sziszek ellen, melyet 1593-ban el is foglalt. Innen a Dunántúlra indult, Székesfehérvárnál azonban a keresztény sereg győzelmet aratott a felmentő török sereg felett. A haditanács erre határozottabb törökellenes fellépést, és elsősorban téli támadást sürgetett. Ezután a felső-magyarországi vármegyék is támadásba lendültek, és a török őrség egymás után hagyta el a várakat.\n\nAz 1593/94. évi téli hadjárat fordulópontot jelentett a Habsburg-török háborúskodás történetében. Első ízben fordult elő 1526 óta, hogy a magyar királyi és külföldi csapatok védekezésből támadásba mentek át. A pápa rendszeres segélyt folyósított, Franciaország és a lengyelek semlegességet tanúsítottak, a Habsburg Birodalom rendjei pedig felemelték évi hozzájárulásukat. Csatlakoztak a román vajdaságok és Erdély is.\n\nA háború kezdetén Erdély nehéz választás előtt állott: Szinán nagyvezír segítséget kért a török hadaknak, élelmet és fegyveres erőt. Erdélyben erős tábora volt a törökkel való békének, Báthory Zsigmond fejedelem azonban Bocskai István váradi kapitány tanácsára mégis vállalta a török elleni háborút. Zsigmond a két román fejedelemséggel szorosabbra fűzte kapcsolatait, hogy a három fejedelemségből erős hatalmi tömb alakuljon ki.\n\nA Maros menti várak visszafoglalása után a háború súlypontja a Havasalföldre helyeződött át. 1595-ben a gyurgyevói átkelésnél szenvedte el a török a háború legnagyobb vereségét Bocskai István és Mihály vajda hadaitól.\n\nIII. Mohamed 1593 és 1598 között észak felé támadt, elfoglalta Egert is. 1595 után a háború súlypontja újból a magyarországi hadszíntérre helyeződött át. 1596-ban Nyáry Pál Eger feladására kényszerült. Ezt követte a Mezőkeresztesnél kivívott török győzelem (2. mohácsi csata). A századfordulón a törökellenes összefogás bomlása figyelhető meg. Közben megromlott Bécs és a magyar rendek viszonya.\n\nA Habsburg Birodalom pénzügyi nehézségekkel küzdött. A háború terheiből sokat a magyar nemesekre hárított. Felségsértési pereket indított főleg a protestáns magyar főurak ellen, ami fej-és jószágvesztéssel végződött.\n\n1604-ben fegyveres felkelés tört ki a Habsburgok ellen Kelet-Magyarországon. A felkelést Belgiojoso Bocskai István bihari várai ellen intézett támadása váltotta ki. Bocskai a hozzá átállt hajdúk segítségével győzelmet aratott a császáriak fölött. Elfoglalta az egész Felvidéket és birtokba vette Erdélyt. 1605-ben a szerencsi országgyűlés is fejedelemmé választotta. A szultán koronát küldött Bocskainak, aki csak ajándékként és nem felségjelvényként fogadta el. Rudolf császár, miután a Német-római Birodalomban és szövetségeseitől nem kapott segítséget, hajlott a béketárgyalásokra. 1606-ban a bécsi béke zárta le a Bocskai-szabadságharcot (1604-1606), mely kimondta a rendi alkotmány biztosítását, a protestánsok vallásszabadságát, és elismerte Erdély önállóságát.\n\nA Habsburgok és a törökök közötti 15 éves háborút az 1606-os zsitvatoroki béke zárta le, mely rendezte a határokat, a szultán egyenrangú félnek nyilvánította a magyar királyt, és végleg lemondott a Bécs által fizetendő évi adóról.\n\n1606-ban Bocskai politikai végrendelete: az egységes Magyarországot csakis abban az esetben tartotta ugyanis kívánatosnak, ha a magyar korona valóban magyar kézben maradna.\n\n1608-as országgyűlés Pozsonyban!!!!\n\nZrínyi Miklós tevékenysége és törökellenes küzdelmei\n\nAz egyik legnagyobb magyarországi birtokos, később horvát bán Zrínyi Miklós (1620-1664) élete során jelentős szerepet vállalt a törökök elleni harcokban. Zrínyi Miklós horvát katolikus főúr; családja birtokai az ország délnyugati részén terültek el, a tengerhez vezető útvonalak mentén Csáktornyától az Adriáig. A tengeri kikötők nagy jövedelmet biztosítottak a családnak, emiatt portyázásaival a török gyakran háborgatta. Zrínyi a végek harcaiban lett politikus. Zrínyi katonai teljesítménye mellett irodalmi munkái is jelentősek, amelyek között több is haditechnikai, politikai tartalmú, és mindegyik a törökök legyőzésének a lehetőségével foglalkozik. Felismeri, hogy ezt csak nemzetközi összefogással lehet megvalósítani, ugyanakkor fontosnak tartja egy erős, önálló magyar hadsereg kiképzését, hogy a felszabadulás utáni esetleges idegen elnyomást meg lehessen akadályozni.\n\nZrínyi Miklóst III. Ferdinánd 1647-ben nevezte ki horvát bánnak, ezzel a déli részek őrzőjévé vált. Ő is várta a Habsburgok segítségét, de hamar ráébredt, hogy előbb az országnak is meg kell újulnia: fel kell számolni a belső megosztottságot, modernizálni kell a közigazgatást, a hadsereget. Műveiben ezeket a feladatokat írta le.\n\nAz egész Európára kiterjedő 30 éves (1618-48) háború Magyarországon háttérbe szorította a török-kérdést, de lezárulta után újból előkerült a törökök kiűzésének ideája. 1648-ban a vesztfáliai békével a Habsburgok nagy háborúja befejeződött, azután lehetőség kínálkozott a török elleni összefogásra. Lengyelországban tárgyalások folytak egy nemzetközi összefogással szervezendő törökellenes hadjáratról Velence és a pápa szövetségével, de számítottak a Habsburgokra is. II. Rákóczi György szintén felajánlotta részvételét, bár a török fennhatósága alatt uralkodott.\n\nIII. Ferdinánd azonban szélnek eresztette hadseregét, ezzel kinyilvánította, hogy a béke mellett döntött. A magyarországi főrendek körében ez a lépés nagy felháborodást váltott ki. Kinyilvánította nemtetszését Zrínyi Miklós horvátországi bán is, aki azonban a megoldásra javaslatokat tett. Elképzeléseit nádorként szerette volna megvalósítani, de 1655-ben nem őt, hanem Wesselényi Ferencet választották nádorrá.\n\nA gyakorlat tanulságait a könyvekből vett ismeretekkel gazdagította. Magyarország akkoriban leggazdagabb magánkönyvtárát gyűjtötte össze. Vitézi híre Európa-szerte ismert, az országgyűléseken tekintélyes politikus volt.\n\nEposza és hadtudományi művei:\n\n• Szigeti veszedelem (1645/46): példát állít a nemzet elé.\n\n• Tábori kis tracta (1649): hadseregszervezés elméleti munkája.\n\n• Vitéz hadnagy (1653): elmélkedés a jó hadvezérről.\n\n• Mátyás király életéről való elmélkedés (1656): bírálja a döntésképtelen Habsburg uralkodókat, hangsúlyozza az aktív török-ellenes külpolitikát. II. Rákóczi György erdélyi fejedelmet tekintette jelöltnek nemzeti királynak.\n\n• Az török áfium ellen való orvosság, avagy az töröknek magyarral való békessége ellen való antidotum [ellenméreg] (1661): „Aki békét akar, készüljön a háborúra” - meghirdette a nemzeti (nemesekből, hajdúkból, jobbágyokból álló) zsoldoshadsereg kialakításának programját, amelynek 3 alapfeltételét jelölte meg:\n\n- pénzügyi alapok megteremtése;\n\n- a kapcsolatok rendezése Ausztriával;\n\n- a magyar közigazgatás korszerűsítése.\n\nZrínyi Miklós a török elleni harc szolgálatába állította munkásságát. A „Szigeti veszedelem” c. eposzával a hősi halált halt dédapjának 1566-ban folytatott harcát írta le, de saját kortársait akarta buzdítani a török hódoltság felszámolására, az ország egyesítésére. Hadtudományi munkáiban („Tábori kis trakta”, „Vitéz hadnagy”) a felkészülés gyakorlati feladatait fogalmazta meg. A „Mátyás király életéről való elmélkedések” c. munkájában a korszerű uralkodó példáját állította kortársai elé. Keményen bírálta a rendi államot, a kusza magyarországi állapotokat. Mátyás kormányzását felidézve az abszolutista állam híve volt. Erős kezű uralkodó vezette, jól szervezett országban látta Magyarország jövőjét. Ezután fordult II. Rákóczi György erdélyi fejedelem (1648-60) felé, aki azonban meggondolatlan lengyelországi hadjáratával kivívta a török haragját, és állandóan menekülésben volt, így nem lehetett a nemzeti összefogás vezetője.\n\nA magyar királyi trónra II. Rákóczi György erdélyi fejedelmet szánta, aki svéd szövetségben a lengyel trón megszerzéséért szállt hadba, de vereséggel tért vissza. Az egész erdélyi sereg tatár fogságba esett, valamennyiüket a Krímbe hurcolták. A tatárok Erdélyt is feldúlták. 1660-ban a Porta megtorló hadjárata Erdély ellen szomorú következményekkel járt. Várad elesett, a várral együtt óriási terület veszett el, az ország védelmi rendszere megroppant. A velencei útjáról hazatérő Zrínyi mozgósította hadseregét, Kanizsát ostrom alá vette, de Bécs ezt megtiltotta. Erre Zrínyi a Mura partján Kanizsa ellenében várat épített: Zrínyi-Újvárat.\n\n• Zrínyi ezekben a zavaros időkben (trónharcok Erdélyben, a törökök elfoglalták Váradot, vallási viták az országgyűléseken, hideg telek és éhínségek) fogott hozzá - a török engedélye nélkül - a Mura bal partján Zrínyi-Újvár építéséhez.\n\nAz udvar hosszú ideig mellőzte, sem nádornak, 1663-ig pedig még fővezérnek sem nevezték ki. Ekkor azonban az udvar engedélyt adott a Zrínyi által kitervelt téli hadjáratra, amelynek során az újdonsült fővezér mélyen behatolt a hódoltsági területre.\n\n1661 őszén Köprülü Mehmed helyébe lépő fia, Köprülü Ahmed új hódítási tervekkel akarta feleleveníteni az oszmán terjeszkedő politikáját. Erre bátorították erdélyi sikerei és a magyarországi állapotok, az udvar és a főrendek, illetve a vármegyék ellentétei.\n\nA török kérdés túlnőtt a Habsburg Birodalom határain, kezdett kialakulni a törökellenes nemzetközi koalíció körvonala. Szervezője a Rajnai Szövetség, melynek vezetője János Fülöp mainzi választófejedelem, legfőbb tényezője pedig Franciaország. A koalícióhoz tartozott volna még Lengyelország, a pápai állam, Velence, Erdély, Moldva, Havasalföld. Lipót császár éppoly kevéssé maradhatott volna távol tőle, bár a Habsburg-dinasztiára nézve a koalíció veszélyeket is rejthetett volna.\n\nUgyanekkor, 1663-ban jelent meg Zrínyi híres röpirata, „Az török áfium ellen való orvosság”. Ebben fejtette ki legrészletesebben a magyar nemzeti hadsereg felállításának szükségességét. A röpirat aktuális politikai céllal készült. Állandó, jól szervezett hadsereget, nemesi adófizetést követelt. Mindkettő a korszerű abszolutista állam követelménye.\n\nKüprülü Ahmed nagyvezír 1663-ban nagy hadjáratra indult, célja Bécs volt, de egy 40 napos eső Budán tartotta.\n\n1663-ban körülzárta Érsekújvárt. Terve az volt, hogy egész Magyarországot a szultán hatalma alá vonja. Elfoglalta viszont a Forgách Ádám védte Érsekújvárt, de hadjáratát nem folytathatta, így nagyratörő politikai elgondolása is kudarcba fulladt. Időközben a magyar főrendek félretették egymás közötti ellentéteiket, elfogadták Zrínyi külpolitikai elképzeléseit, támadási haditervét, és hozzákezdtek a háború országos feltételeinek megteremtéséhez. Zrínyi közös cselekvésre szólította az ország legbefolyásosabb főurait. A kibontakozás alapfeltételének a közügyek iránti közöny leküzdését tekintette. Az ország vezetői, Wesselényi Ferenc nádor, Nádasdy Ferenc országbíró, Lippay György esztergomi érsek, Batthyány Ádám dunántúli főkapitány, továbbá a vármegyék vezetői csatlakoztak, de még Erdélybe is elértek a szervezkedés szálai. 1663-ban konföderációt kötöttek. Wesselényi nádor nemesi felkelést hirdetett.\n\nZrínyi tekintélye megnövekedett udvari körökben. I. Lipót is biztosította bizalmáról, és a magyar csapatok főparancsnokának nevezte ki. Montecuccolival közös haditervet dolgoztak ki, de a magyar és a császári haderőt nem tudták összehangolni, így Érsekújvár felmentéséről elkéstek. Közben Zrínyi a Dunántúl déli részén aratta sikereit. Tekintélye Magyarországon immár az uralkodóéval vetekedett.\n\n• A Rajnai Szövetség Zrínyi kezdeményezésére döntött úgy, hogy téli támadással kezdi meg a háborút, melynek előkészítő hadművelete a téli hadjárat és Kanizsa ostroma. Zrínyi Miklós eközben sikeresen harcolt a Muraközben, majd hozzákezdett az ún. téli hadjárathoz (1664. jan. 21-febr. 9.):\n\n• célja: elfoglalni Kanizsát; elfoglalta Babocsa várát és Pécset;\n\n• majd a török utánpótlást megakadályozandó felégette az eszéki Dráva-hidat. Zrínyi a lovassággal elérte és felgyújtotta az eszéki fahidat, a török birodalom egyik legfontosabb nyugati átkelőhelyét. Elvágták a török utánpótlási vonalát, és Kanizsa várát minden segítségtől elszigetelték. A szövetséges csapatok sikerrel verték vissza a nagyvezír támadásait. Zrínyi-Újvár négy hétig állta a törökök ostromát.\n\n• E sikerek után a német birodalomból érkezett seregekkel kiegészült haderő - parancs híján - csak késlekedve kezdte meg Kanizsa ostromát, így az Eszéknél új hidat építő törökök fel tudták menteni a várat.\n\nAz udvar a Habsburg-dinasztia ellen irányuló veszedelmes politikának látta a magyar mozgalom és a nemzetközi szövetség összefogását. A császár közvetlen környezete azon munkálkodott, hogy az események irányítását kézbe ragadja. I. Lipót 1664-ben felfüggesztette a nádor helytartói és Zrínyi főparancsnoki hatáskörét, és ragaszkodott Montecuccoli fővezérségéhez. Köprülü Kanizsáról kiindulva a Rába déli partján vonult Nyugatra, hogy Bécs irányában törjön előre. Sikerült magához ragadni a kezdeményezést, és a szövetségesek haderejével szemben kierőszakolta a döntő összecsapást Szentgotthárd alatt. A szövetségesek azonban hét órán át tartó csatában győzelmet arattak a török főseregen. Mindez a nemzetközi koalíció erőfölényét és nagy lehetőségeit bizonyította.\n\n• Zrínyi győzelmei nem voltak tartósak, mivel I. Lipót új fővezért nevezett ki, az olasz Montecuccolit, aki hagyta, hogy az ellentámadó török seregeknek sikerüljön elfoglalni a Zrínyi által építtetett Új-Zrínyivárat.\n\nTehát Zrínyit leváltották a dél-dunántúli erők éléről, és Montecuccoli tábornokot nevezték ki főparancsnoknak, azzal az utasítással, hogy Stájerországot és Bécset védje. Ezért Zrínyi-Újvárat feladták.\n\n• A törökök megindultak Bécs felé. Amikor Küprülü Ahmed 1664. aug. l-jén Szentgotthárdnál át akart kelni a Rábán, Montecuccoli csatát vállalt, és véres ütközetben győzött. A legyőzött törökök visszavonultak, de közben a kezükben lévő Zrínyi-Újvárat felrobbantották. 1664. augusztus 10-én ugyan a szentgotthárdi csatában legyőzte Ahmed vezír seregét, de a győzelmet követő vasvári békében az udvar meghagyta a törökök területi szerzeményeit.\n\nMégis I. Lipót - a szövetségesek tudta nélkül - megalázó békét kötött 1664-ben Vasváron. Török kézen hagyta az előző évek foglalásait, ígéretet tett az erdélyi várakból a német katonaság kivonására. A felek kötelezték magukat, hogy a magyarokat nem segítik, sőt tájékoztatják egymást azok ellenséges terveiről. Bécs ezzel biztosítékot kapott, hogy a magyar rendek nem támadhatnak ellene török segítséggel.\n\n• A („szégyenteljes”, „siralmas”) vasvári béke (1664. aug. 10.):\n\n• a zsitvatoroki béke alapján 20 évre kötött béke;\n\n• elismerte, és a török kezén hagyta hódításait (Várad, Érsekújvár);\n\n• a Habsburgok és a törökök is kivonulnak Erdélyből;\n\n• Zrínyi- Újvárat nem szabad újjáépíteni;\n\n• a Habsburg uralkodó 200 ezer forint ajándékot küld a szultánnak;\n\n• a két fél kereskedelmi szerződést köt.\n\n• A vasvári béke igen nagy felháborodást keltett Európában és Magyarországon is:\n\n• a császár a békét a szövetségesek tudta nélkül kötötte meg;\n\n• olyan feltételekkel, mintha a törökök győztek volna.\n\nA gyors békekötés magyarázata: Bécs francia támadástól tartott. A béke csalódást, országos elégedetlenséget váltott ki, ami egy Habsburg-ellenes rendi szervezkedést indított el Wesselényi nádor vezetésével.\n\n• Zrínyi Miklós a harcok befejeztével több európai országban is tárgyalásokat folytatott, hogy támogatókat szerezzen az országegyesítés programjához, de eredménye már nem volt ezeknek, mert 1664. nov. 18-án Zrínyi egy vadkanvadászaton halálosan megsebesült. (Londonban gyászversek füzérét adták ki: „Velence védőbástyája”, „A keresztény szabadság megmentője”, „Magyarország erős Marsa”, „Európa csillaga” címekkel.)\n\nZrínyi ugyan tiltakozott, de 1664. november 18-án a kursaneci erdőben egy vadászbalesetben kétes körülmények között életét vesztette.\n\nA török kiűzése (vázlat)\n\n1683: Kara Musztafa, IV. Mehmed nagyvezíre sikertelenül ostromolta Bécset.\n\n1684: XI. Ince pápa szervezésében megalakult a törökellenes Szent Liga (Liga Sacra) a Habsburgok, Lengyelország, Velence részvételével. A Szent Liga seregei Lotharingiai Károly, II. Miksa Emánuel bajor választó és Sobieski János lengyel király vezetésével 1686 szeptemberében visszafoglalták Budát, amelyet Ali Abdurrahman pasa védett. Az ország felszabadítása:\n\n• 1686-90\n\n- 1687: a nagyharsányi (második mohácsi) győztes csata a török ellen;\n\n- 1688: Bádeni Lajos elfoglalta Belgrádot.\n\n- 1690: a törökök visszafoglalták Belgrádot, Lippát, Kanizsát; - 1697: a zentai csatában Savoyai Jenő legyőzte a Tiszán átkelő törököket. Békekötés: 1699 - karlócai békék\n\n• Habsburg - török béke (II. Musztafa és I. Lipót kötötte 25 évre):\n\nA Temes-vidék kivételével az összes magyarországi terület és Horvátország a Habsburgok fennhatósága alá került.\n\n• Orosz-, lengyel-, velencei - török békék: a törökök területeket veszítettek.\n\nA török kiűzése (kifejtés)\n\nAz oszmán seregek egyik legfontosabb prioritása Európában Bécs városának, így az egyik legjelentősebb európai uralkodóháznak térdre kényszerítése volt. A feladattal többször is próbálkoztak sikertelenül (1529-ben és 1532-ben). A IV. Mehmed által nagyvezírré kinevezett Kara Musztafa újabb kísérletet tett 1683 márciusában Bécs elfoglalására.\n\nI. Lipót (1657-1705) azonban széles koalíciót szervezett a város védelmére (többek között III. Sobieski János lengyel király, II. Miksa Emánuel bajor és III. János György szász választófejedelmek bevonásával). A város védelméről Starhemberg gróf gondoskodott, de a nagy erejű török támadást (amely Bécs felé menet számos magyar várat - így Veszprémet, Pápát, Tatát - elfoglalt) csak szeptember közepére sikerült teljesen visszaverni. A csatában főszerepet játszó Lotharingiai Károly menetben visszafoglalta Párkányt és Esztergomot, így a török kiűzése kézzelfogható közelségbe került. Ezt ismerte fel XI. Ince pápa is, aki óriási anyagi támogatással 1684-ben létrehozta a Szent Ligát Habsburg, lengyel, velencei, pápai és 1686-tól orosz részvétellel. A francia XIV Lajost pedig húszéves békére kényszerítette a célból, hogy a szövetség csak a keleti frontra koncentrálhasson. Bár 1684 májusában még sikertelen volt Buda visszafoglalási kísérlete, az 1686. június 18-án kezdődő ostrom során szeptember 2-re sikerült visszaszerezni a várat Abdurrahman budai pasától. A csatában a kor jellemző várostromtechnikáit (így robbanóanyagokat, sáncrendszert) alkalmazták.\n\nA siker után folytatódott az előrenyomulás a hódoltsági területeken: Lotharingiai Károly vezetésével a Duna mentén haladva foglalták vissza a várakat, majd a nagyharsányi győzelem (1687. augusztus 12.) után ő maga Erdély felé vette az irányt, amelyet a balázsfalvi szerződéssel behódoltatott. A fővezéri poszton Miksa Emánuel váltotta fel.\n\nA visszalépés évei\n\nBelgrád, Havasalföld és Albánia bevétele után 1690-ben fordulat következett be a császári stratégiában. Egyrészt ezeket a területeket egyre nehezebb volt ellenőrzés alá vonni, másrészt XIV Lajos féltékenyen szemlélte a Habsburgok közép-európai sikereit, így - a békeszerződést megszegve - arra kényszerítette I. Lipótot, hogy legkiválóbb hadvezéreit és csapatainak egy részét a rajnai frontra vezényelje át. A frissen kinevezett Köprülü Musztafa nagyvezír ezt kihasználva a balkáni területeket Belgráddal együtt gyorsan visszafoglalta. Közel tíz évig egyik fél sem tudott jelentős előrelépést elérni - ez alól csak az 1691-es császári győzelmet jelentő véres szalánkeméni csata volt kivétel. 1697-ben Savoyai Jenő herceg, a tehetséges francia hadvezér lett a főparancsnok, aki a hegyaljai felkelés leverése után Zentánál óriási győzelmet aratott a török felett, ami egyúttal a harci cselekmények lezárását és a béketárgyalások kezdetét is jelentette. 1699 januárjában Karlócán kötötték meg a békét William Paget konstantinápolyi angol követ közvetítésével, amely a fennálló viszonyok (status quo) alapján rendezte az osztrák és oszmán fél helyzetét: a Temesköz kivételével a magyar és horvát területek Habsburg fennhatóság alá kerültek, ezen felül Velence, Oroszország és Lengyelország is gazdagodtak területekkel. Magyarország számára azonban a politikai következmények ennél sokkal súlyosabbnak bizonyultak. Habsburg - török béke (II. Musztafa és I. Lipót kötötte 25 évre): Temes-vidék kivételével az összes magyarországi terület és Horvátország a Habsburgok fennhatósága alá került.\n\nA török kiűzésének közjogi és politikai következményei\n\nA Wesselényi-féle összeesküvés után az I. Lipót által bevezetett abszolutisztikus intézkedések már bebizonyították, hogy a Habsburgok minél jobban igyekeznek az irányításuk alá vonni a rendeket és rajtuk keresztül az országot. Bár az 1681-ben összehívott soproni országgyűlés beismerően eltörölte a lipóti korlátozásokat, a töröktől való megszabadítás ismét okot szolgáltatott arra, hogy növekedjék a Habsburgok befolyása. A magyar rendek által vallott önrendelkezés igényének illúzióját hamar eloszlatta az a bécsi tétel, miszerint Magyarországot fegyverrel meghódított területként kezelték, s ennek megfelelő szerepet szántak az országnak a birodalomban. 1687-ben a magyar rendek lemondanak királyválasztó jogukról a Habsburgok javára, és az Aranybulla ellenállási záradékáról a győzelmek hatására.\n\nA béke után az ország területi széttagoltsága megmaradt, és létrehozták az udvari irányítás alá eső, széles körű autonómiával rendelkező szerbek lakta Határőrvidéket is. Erdély különállását az I. Lipót által 1691. december 4-én kiadott Diploma Leopoldium rögzítette, így nem egyesült Magyarországgal. Az erdélyi vallási tagozódást, adomány- és hivatalrendszert érintetlenül hagyta. Ugyanakkor Erdély seregeit német tábornok vezette, igazgatását pedig egy Bécs alá tartozó gubernátor (Bánffy György, 1661-1708) végezte.\n\nAmi a magyar területeket illeti: az adóterhek és különböző illetmények száma és mértéke ismét növekedett. Bevezetésre került a porció (a katonaság elszállásoltatása) és a forspont (fuvaroztatás). Azoknak, akik vissza kívánták kapni birtokaikat, a hivatalos okiratok bemutatása mellett a földbirtok értékének 10%-át fegyverváltság címén be kellett fizetniük az Újszerzeményi Bizottságnak, azaz a Neoacquistica Commissio. A katolikusok ezen intézkedések alól mentességet kaptak. Az uniformizálás jegyében betiltották a protestánsok számára 1681-ben rögzített, korlátozott vallásszabadságot, a magyar várrendszert pedig módszeresen leépítették, és a katonai állományt császári katonákkal töltötték fel.\n\nÉrtékelés: a török mintegy másfél évszázados uralmának ugyan vége lett, de ezt a Habsburgok még hosszabb ideig tartó irányítása váltotta fel. A politikai és katonai téren bevezetett abszolutisztikus intézkedések azonban sorozatos ellenállásokba ütköztek, és ezeknek a megmozdulásoknak a leverése a Habsburgok szemében csak igazolta politikájukat.', 225, 1, '2026-04-17 09:41:10', '2026-04-17 09:41:10');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(28, 28, 'Az első világháború és következményei', '28.docx', '28. tétel: Az első világháború és következményei\n\n(szövetségi rendszerek, okok, hadviselők, frontok, a háború, békék)\n\nAz első világháború előzményei\n\nEURÓPA ORSZÁGAI AZ ELSŐ VILÁGHÁBORÚ ELŐESTÉJÉN\n\na) Anglia\n\n- Nagy gyarmatbirodalommal rendelkezik (pl. India, Egyiptom, Dél-Afrika, Ausztrália, Kanada, Szudán, Kenya, Nigéria, Pretoria).\n\n- A pénzügyi és kereskedelmi világ vezetője.\n\n- A világ legnagyobb hadiflottájával rendelkezik, gyarmati és kereskedelmi hatalom.\n\nKülpolitikájának célja: az európai kontinentális egyensúly lenn tartása Németország, Franciaország és Oroszország között;\n\n- gyarmatbirodalmának megtartása, új birtokok megszerzése: Közép-Afrika, Kairó-Fokváros-vonal). Sikert akkor remélhet, ha flottája megőrzi vezető szerepét, és jól működő diplomáciával szövetségi rendszereket sikerül kialakítania a rivális nagyhatalmakkal szemben.\n\nb) Franciaország\n\n- Jelentős gyarmattartó (pl. Indokína, Tunézia, Marokkó, Nyugat-Afrika).\n\n- Gazdasága - főleg a XIX. század végén - dinamikusan fejlődik.\n\n- Európában az 1870/71-es francia-porosz háborúban elvesztette kontinentális vezető szerepét.\n\nKülpolitikájának célja: gyarmatbirodalmának megvédése és kiterjesztése (e téren Angliával vannak konfliktusai Afrikában, pl. fashodai válság 1898);\n\n- Európában kontinentális vezető szerepének visszaszerzése, visszavágás Németországnak (revanspolitika), Elzász-Lotaringia visszaszerzése.\n\nAz egyre erősödő Németország komoly veszélyt jelentett a francia gyarmatbirodalomra és gazdaságra. A francia diplomácia tudta, hogy az ellentétek békés eszközökkel nem oldhatók fel, ezért egy németellenes szövetségi rendszer kialakítását tűzte ki célul.\n\nc) Oroszország\n\n- Területe óriási, lakossága rendkívül nagyszámú.\n\n- Gazdasági, társadalmi viszonyai elmaradottak, feudális jellegűek.\n\n- A krími háborúban elvesztette nagyhatalmi presztízsét (1853-56).\n\n- A század második felére jellemző a dinasztikus expanzió, amely terjeszkedést jelent a cár személyes hatalmának növelése érdekében. A terjeszkedés iránya Közép-Ázsia, Szibéria, a Kaukázuson túli területek.\n\nKülpolitikájának célja: a válságban lévő Törökország hatalmi helyének betöltése a Balkánon és Kis-Ázsiában; ezúton a fekete-tengeri szorosok megszerzése, hogy az országnak legyen melegtengeri kikötője.\n\nAz orosz politikai propagandának fontos része a pánszlávizmus (pánszláv = szlávok egysége). A pánszlávizmus gondolata: a világon élő összes szláv nép egyesülését jelenti egy nagy szláv birodalomban, amely vezető politikai hatalom lenne. A szláv kölcsönösség indokával lépett fel Oroszország a balkáni szláv népek „védelmezőjeként”.\n\nd) Németország\n\n- 1871-ben egyesült ismét egységes politikai állammá\n\n- Gazdasága a legdinamikusabban fejlődik. A német ipar korszerű technológiával, jelentős szakembergárdával néhány évtized alatt vetélytársa lett a klasszikus kapitalista gazdaságoknak.\n\n- Gyarmatbirodalma kevés. Fokozatosan fejlődő ipara újabb nyersanyagbázist, munkaerőt és piacokat igényel. Gyarmatait csak a többi nagyhatalom rovására tudta volna növelni pl. Német Kelet-Afrika, Német Délnyugat-Afrika, Togo, Kamerun.\n\nA német külpolitika célja II. Vilmos idején, 1896-tól:\n\n- teljes európai hegemónia (Franciaország és Oroszország ellenében);\n\n- a „Drang nach Osten” politikája: terjeszkedés Keleten pl. Berlin – Bagdad vasút terve.\n\n- német befolyási övezet Közép-Európában;\n\n- Afrikában és a Csendes-óceánon gyarmatainak növelése (Anglia, az USA ellenében). Ennek érdekében nagyarányú flottaépítési akciót kezdett, jelentősen növelte fegyvergyártását.\n\nNyilvánvalóvá vált, hogy hatalmi igényeit nem a diplomácia útján tudja érvényesíteni.\n\nr) Osztrák - Magyar Monarchia\n\nNagy területű, soknemzetiségű monarchia.\n\nBelpolitikai gondok (gazdaság, nemzetiségi kérdés, társadalmi ellentétek).\n\nKülpolitikájának célja: politikai befolyás a Balkánon; igazodás Németország közel-keleti terjeszkedéséhez. A „Drang nach Osten” politikája egy összefüggő szövetségi területet képzelt el Németországtól a Balkánon át egészen Kis-Ázsiáig. A Monarchia fennmaradását ettől a szövetségtől remélte.\n\nSZÖVETSÉGI RENDSZEREK, A VILÁGHÁBORÚ KIROBBANÁSA\n\na) Központi hatalmak\n\n1879-ben Németország Bismarck elképzelései alapján hozta létre a kettős szövetséget az Osztrák-Magyar Monarchiával, Oroszország ellen.\n\n1882-ben Németország, az Osztrák-Magyar Monarchia és Olaszország között létrejött az úgynevezett hármas szövetség, amelyhez Olaszország azért kapcsolódott, mert Franciaország útját állta észak-afrikai terjeszkedésének. Ám ez nem jelentett stabil szövetséget, mivel a szerződésnek volt egy olyan kitétele, hogy érvénytelen a szövetség, ha az Anglia elleni háborúhoz vezetne. Németországnak így az Osztrák-Magyar Monarchia a stabil szövetségese.\n\nb) Antanthatalmak\n\n- 1893-ban létrejött egy francia-orosz katonai szerződés.\n\n- 1904-ben Anglia rendezte gyarmati ellentéteit Franciaországgal (pl. fashodai incidens Afrikában), és megkötötték az entente cordiale-t, a szívélyes megegyezés elnevezésű szerződést: antant.\n\n- 1907-ben angol-orosz katonai szerződést kötöttek.\n\nE szerződésekkel kialakult az antanthatalmak tömbje. A szerződések lényege, hogy az egymás elleni konfliktusokat békés úton oldják meg, és háború esetén közösen lépnek fel ellenségeikkel szemben.\n\nc) Erőviszonyok\n\n- A központi hatalmak előnye: összefüggő terület, így könnyebben lehet a csapatokat mozgatni, élelmet, fegyvert szállítani.\n\n- Hátrányai: nincs elég nyersanyag felhalmozva egy elhúzódó háború esetére. Kétfrontos háborút kell vívni.\n\n- Az antanthatalmak előnyei:\n\nJelentős gyarmatbirodalmuk nyersanyagbázist jelent. Nagyobb a felhalmozott fegyverkészlet.\n\n- Hátrányai:\n\nEgy gyors, nagy erejű támadással legyőzhetők, mert szárazföldi hadseregeik gyengébbek.\n\nd) Haditervek:\n\nSchlieffen-terv (Németország terve): feltételezi Oroszország lassú mozgósítását.\n\n1. lépés: Németország egyfrontos háborút vív Franciaország, a Monarchia pedig Szerbia ellen. E frontokon villámháborús győzelem.\n\n2. lépés: Oroszország elleni háború.\n\nAngol-francia haditerv: a központi hatalmak első nagy erejű támadásának kivédése.\n\nOroszország azonnali támadása Németország és az Osztrák-Magyar Monarchia ellen.\n\ne) Hadüzenetek\n\nA „casus belli”(háborús ürügy). 1914 júniusában a Monarchia hadserege Bosznia-Hercegovinában hadgyakorlatot tartott. Ekkor volt az első rigómezei csata évfordulója, a szerbek gyásznapja. Ebben a csatában bukott el az önálló szerb állam, 1389-ban török kézre került.\n\nGavrilo Princip 1914. június 28-án Szarajevóban lelőtte Ferenc Ferdinánd trónörököst. Július 23-án a Monarchia demarsot (erőteljes tiltakozást) küldött Szerbiának. Szerbia ezt visszautasította.\n\n1914. július 28-án az Osztrák - Magyar Monarchia hadat üzent Szerbiának. A hadüzenetet Németországgal egyeztetve küldték.\n\nA nagyhatalmak hadba léptek:\n\n1914. augusztus l-jén Németország hadüzenete Oroszországnak;\n\nAugusztus 3-án Németország hadüzenete Franciaországnak és Belgiumnak;\n\nAugusztus 4-én Anglia hadüzenete Németországnak;\n\nAugusztus 5-én a Monarchia hadüzenete Oroszországnak;\n\nAugusztus 12-én hadiállapot a Monarchia és Anglia, Franciaország között;\n\nAugusztus 23-án Japán hadüzenete Németországnak.\n\nAz USA, Olaszország, Románia, Bulgária semlegességi nyilatkozatot tett.\n\nA HÁBORÚ MENETE\n\nAz 1914. évi hadműveletek\n\nNyugati front:\n\nAugusztus 3. a villámháború során német támadás indult Belgium, majd Franciaország ellen. Cél: Párizs elfoglalása.\n\nSzeptember 5-10.: az antantcsapatok a Marne folyónál ellentámadást indítottak, és megállították a németeket. Állóháború alakult ki, illetve lövészárok háború.\n\nKeleti front:\n\nAz orosz mozgósítás hamarabb befejeződött, mint azt a németek gondolták, így a német hadseregnek többfrontos háborút kellett vívnia. Augusztus: orosz támadás indult Galíciában és Kelet-Poroszországban. Augusztus 17-19.: Hindenburg német tábornok győzelmet aratott Tannenbergnél (megsemmisítette a 2. orosz hadsereget). Szeptember 6-15.: német győzelem a Mazuri-tavaknál. Augusztus vége: az oroszok elfoglalták Kelet-Galíciát. A Monarchia ide koncentrálta erőit, s a támadást a Kárpátok vonalánál megállította.\n\nBalkáni front:\n\nA Monarchia nem volt képes elfoglalni Szerbiát, állóháború alakul ki.\n\nEurópán kívüli csaták:\n\nJapán elfoglalta Németország távol-keleti gyarmatait.\n\nOktóber: Törökország belépett a háborúba a központi hatalmak oldalán. Mezopotámiában, a Dardanelláknál, Palesztinában és a Kaukázusban is megindultak a harcok. A Boszporusznál és a Dardanelláknál elzárták Oroszországot szövetségeseitől.\n\nNovember 1.: A német flotta kudarcot vallott Helgolandnál.\n\nNovember 2.: Anglia tengeri blokád alá vonta Németországot.\n\nAz 1914. évi hadműveletek a német vezetés villámháborús tervének kudarcát hozták. Jelentős győzelmet egyik fronton sem sikerült elérniük.\n\nAz 1915. évi hadműveletek\n\nMájus: Olaszország belépett a háborúba az antant oldalán.\n\nA Monarchia az Isonzó folyónál megállította az olasz támadást. (Súlyos veszteségek.)\n\nNémetország fő erőit keletre irányította.\n\nMájus 2.: Gorlicénél áttörték a frontot, jelentős területeket foglaltak el.\n\nSzeptember: Bulgária belépett a háborúba a központi hatalmak oldalán.\n\nOktóber: Bulgária és a Monarchia együttesen legyőzték Szerbiát.\n\nYpernnél (belga) német gáztámadás (mustárgáz, kezdetleges gázálarc). A széljárás miatt a német katonák is elestek. Állóháború.\n\nA keleti fronton elért sikerek ellenére 1915-ben a harc eldöntetlen maradt. Az elhúzódó háború növelte az antant esélyeit.\n\nAz 1916. évi hadműveletek\n\n1916-ban ismét a nyugati fronton próbált a német hadsereg győzelmet kivívni (s ezzel békeajánlatot kicsikarni).\n\nFebruártól: „verduni vérszivattyú”: Verdun erődjének véres ostroma.\n\nJúniustól a Somme folyónál az antant feltartóztatta a német hadsereget, majd ellentámadásba ment át.\n\nMájus: Az Isonzó folyónál a Monarchia jelentős sikereket ért el.\n\nMájus-június: Jütland partjainál kiegyenlített tengeri csatát vívtak a német és az angol erők.\n\nJúnius: Bruszilov orosz tábornok vezetésével váratlan offenzíva bontakozott ki a keleti fronton, Galíciában. A támadást a német-osztrák-magyar erők visszaverték.\n\nAugusztus 17.: A román hadsereg betört Erdélybe, ezzel Románia megtámadta a Monarchiát. (Egy 1916-os titkos szerződés értelmében Románia az antanttól hadba lépése esetére jogot kapott Erdély, a Partium, a Kelet-Alföld és a Bánság egy részének elfoglalására.)\n\nDecember: A Monarchia seregei német segítséggel visszaverték a román támadást, majd Bukarestet is elfoglalták.\n\nKözben 1916 novemberében meghalt Ferenc József. Utódja IV. Károly lett, aki béketárgyalásokat kezdeményezett.\n\n1916-ban a nagy áttörés nem sikerült Németországnak. Bár még mindig Németország támadott, a véres csaták sikertelensége bebizonyította, hogy nem képes döntő csapást mérni az antantra.\n\n1916 végén a központi hatalmak békeajánlattal fordultak az antanthoz, amit az elutasított.\n\nAz 1917. évi hadműveletek\n\n1917. február 1.: a németek meghirdették a korlátlan tengeralattjáró háborút. (Az angol tengeri blokád szorítását kívánták enyhíteni ezzel.)\n\nÁprilis: Erre válaszul az USA belépett a háborúba az antant oldalán. Indokai: a Lusitania hajó elsüllyesztése 1915-ben; pénzügyi és gazdasági kötődés Angliához.\n\nFebruár: Oroszországban forradalom - megdöntik a cárizmust.\n\nJúlius: A Kerenszkij-offenzíva, az orosz kormány által indított támadás sikertelen maradt.\n\nMájus: Az antanttámadás Észak-Franciaországban elakadt.\n\nNovember: A 12. isonzói csata után az osztrák-magyar csapatok áttörték a caporettói frontot, és a Piave folyóig nyomultak előre.\n\nNovemberben, Oroszországban szocialista forradalom tört ki, ezután decemberben béketárgyalások kezdődtek Oroszország és a központi hatalmak között.\n\nAz 1918. évi hadműveletek\n\nJanuár: Wilson kihirdette 14 pontos béketervét.\n\nFebruár: az újabb német támadást a Vörös Hadsereg Narvánál megállította. Március 3-án Breszt-Litovszkban különbékét írtak alá.\n\nMárcius: a nyugati fronton a német hadsereg utoljára próbált győzelmet elérni. A 2. marne-i csatában az antant seregei ismét visszaverték a támadást.\n\nJúlius-augusztus: az amerikai csapatok támadását követően végleg összeomlott a német hadsereg.\n\nOktóber 24. a piavei csatában a Monarchia hadserege alulmaradt a megerősített olasz haderőkkel szemben.\n\nNovember 3. Páduában a Monarchia aláírta a fegyverszünetet.\n\nNovember 11. a compiégne-i erdőben Németország is aláírta a fegyverszünetet.\n\nBulgária szeptember 29-én, Törökország október 30-án kapitulált.\n\nA PÁRIZS KÖRNYÉKI BÉKÉK\n\nBékejavaslatok:\n\n- a szovjet kormány békedekrétuma;\n\n- Wilson 14 pontja. Wilson 14 pontos békeajánlatának 6. pontja értelmében „minden nemzet maga dönt politikai fejlődéséről”.\n\nA területi rendezés nem a meghirdetett elvek (történeti, etnikai), hanem hatalmi szempontok (pl. Franciaország biztonsága és az utódállamok igényei) alapján történt.\n\nNyílt, nyíltan letárgyalt békeszerződések, amelyek megkötése után nem lesz többé semmiféle titkos nemzetközi megállapodás, hanem a diplomácia mindig nyíltan és a nyilvánosság színe előtt fog tevékenykedni.\n\nA hajózás teljes szabadsága a felségvizeken kívül eső tengereken, békében és háborúban egyaránt, kivéve, ha a tengereket nemzetközi szerződések végrehajtására irányuló nemzetközi akció révén teljesen vagy részben lezárnák.\n\nMinden gazdasági korlátozás lehető legnagyobb mértékű megszüntetése és egyenlő kereskedelmi feltételek megteremtése mindazon nemzetek részére, amelyek hozzájárulnak a békéhez és csatlakoznak annak fenntartásához.\n\nMegfelelő biztosíték nyújtása és elfogadása arra, hogy a nemzeti fegyverkezéseket a belső biztonsággal összefüggő legalacsonyabb szintre csökkentsék.\n\nAz összes gyarmati igények szabad, elfogulatlan és teljesen pártatlan rendezése, annak az elvnek a szigorú betartása alapján, hogy a szuverenitás idevonatkozó kérdéseinek eldöntésénél az érintett lakosság érdekei ugyanolyan súllyal essenek latba, mint annak a kormánynak méltányos érdekei, amelynek igényei jogosságát el kell bírálni.\n\nAz összes orosz területek kiürítése és az Oroszországot érintő összes kérdések olyan rendezése, amely a világ többi nemzeteinek legjobb és legszabadabb együttműködését biztosítja arra nézve, hogy Oroszország akadálytalanul és korlátozás nélkül alkalmat kapjon saját politikai fejlődésének és nemzeti politikájának független meghatározására, valamint hogy biztosítva legyen Oroszország őszinte fogadtatása a szabad nemzetek társaságában az általa választott intézményekkel együtt, sőt ezen a fogadtatáson túlmenően biztosítva legyen részére minden olyan támogatás, amelyre szüksége lehet és amelyet ő maga is óhajt. Az a bánásmód, amelyben Oroszországot testvérnemzetei az elkövetkező hónapokban részesíteni fogják, próbaköve lesz jóakaratuknak, Oroszország szükségletei iránti saját érdekeiktől elvonatkoztatva tanúsított megértésüknek, valamint értelmes és önzetlen rokonszenvüknek.\n\nAz egész világ egyet fog érteni abban, hogy Belgiumot ki kell üríteni, és helyre kell állítani, anélkül, hogy megkísérelnék korlátozni szuverenitását, amelyet minden más szabad nemzettel együtt élvez. Egyetlen más cselekedet sem fogja ennél jobban szolgálni a nemzetek bizalmának helyreállítását azon törvények iránt, amelyeket egymás közötti kapcsolataik szabályozására maguk alkottak és meghatároztak. E kiegyeztető cselekedet nélkül a nemzetközi jog egész szerkezete és érvénye örök időkre csorbát szenvedne.\n\nMinden francia területet fel kell szabadítani és elözönlött részeit helyre kell állítani. Azt az igazságtalanságot, amelyet Poroszország 1871-ben Elzász-Lotaringia tekintetében Franciaországnak okozott, és amely közel ötven évig nyugtalanította a világ békéjét, jóvá kell tenni, hogy a béke mindenki érdekében újból biztosítva legyen.\n\nAz olasz határokat a világosan felismerhető nemzeti vonalak szerint kell kiigazítani.\n\nAusztria-Magyarország népei részére, amelyeknek helyét a nemzetek között oltalmazni és biztosítani kívánjuk, meg kell adni az önálló fejlődés legszabadabb lehetőségét.\n\nRomániát, Szerbiát és Montenegrót ki kell üríteni. A megszállt területeket helyre kell állítani; Szerbiának szabad és biztosított kijáratot kell adni a tengerhez; a különböző balkáni államok egymás közötti kapcsolatait barátságos tanácskozás útján az állami és nemzeti hovatartozás történelmileg kialakult vonalai szerint kell meghatározni; a különböző balkáni államok politikai és gazdasági függetlenségét és területi sérthetetlenségét nemzetközi garanciákkal kell alátámasztani.\n\nA jelenlegi Ottomán Birodalom török részeinek teljes szuverenitást kell biztosítani, de a többi nemzetiségek részére, amelyek most török uralom alatt élnek, biztosítani kell létük feltétlen biztonságát, önálló fejlődésük teljes és zavartalan lehetőségét. A Dardanellákat mint nemzetközi garanciákkal biztosított szabad átjárót, minden nemzet hajói és kereskedelme számára állandóan nyitva kell tartani.\n\nFüggetlen lengyel államot kell létesíteni, amelynek magában kell foglalnia a vitathatatlanul lengyel lakosság lakta területeket, szabad és biztonságos kijáratot kell biztosítani számára a tengerhez, politikai és gazdasági függetlenségét és területi sérthetetlenségét nemzetközi szerződéssel kell biztosítani.\n\nKülönleges szerződésekkel meg kell alakítani a nemzetek általános szövetségét avégből, hogy a nagy és a kis államok politikai függetlensége és területi sérthetetlensége kölcsönös garanciákkal biztosítva legyen: ez lesz a Népszövetség.\n\nA békekonferenciát 1919. január 18-án Versailles-ban nyitották meg\n\n(1871. január 18-án Versailles-ban deklarálták az egységes Németországot is)\n\n27 állam vett részt a tárgyalásokon - a veszteseket nem hívták meg.\n\n- Az államokat 70 hivatalos delegátus, körülbelül ezer szakértő képviselte.\n\n- Vezető szerepet játszott a „tízek tanácsa”, az 5 nagyhatalom:\n\nUSA, Anglia, Franciaország, Olaszország, Japán 2-2 képviselője.\n\nMeghatározó személyiség a „négy nagy” volt:\n\nClemenceau francia miniszterelnök,\n\nLloyd George brit miniszterelnök,\n\nWilson, az USA elnöke,\n\nOrlando olasz miniszterelnök.\n\nA megtárgyalandó öt nagy kérdés:\n\n1. Németország,\n\n2. az Osztrák-Magyar Monarchia,\n\n3. az „orosz kérdés”,\n\n4. a Török Birodalom,\n\n5. a német gyarmatok sorsa.\n\n„Orosz kérdés”: a bolsevik Oroszországot nem fogadták el győztes hatalomnak, a szovjet vezetést nem tekintették legitim, demokratikus kormánynak, így nem hívták meg a béketárgyalásokra.\n\nEllentétek feszülnek a nagyhatalmi elképzelések között. A területi rendezés nem a meghirdetett elvek (történeti, etnikai), hanem hatalmi szempontok - pl. Franciaország biztonsága és az utódállamok igényei - alapján történt.\n\nA nagyhatalmak érdekei ütköztek a béketárgyalások előkészítése és lebonyolítása időszakában.\n\nWilson elnök 14 pontja és programja kárpótlás és annexió nélküli béke volt, ennek pacifista szelleme a kollektív biztonságot, egy következő háború elkerülését jelentette. Wilson programjának elutasítása miatt az amerikaiak kivonultak a tárgyalásokról, s ez növelte a franciák mozgásterét.\n\nA francia és az angol érdekek Németország meggyengítése és a háborús veszteségek kárpótlása volt, ez vezetett a Németország számára szigorú béke megszületéséhez. Elsősorban a franciák – Clemenceau - ragaszkodtak Németország meggyengítéséhez pl. védelmi övezet kialakítása, jóvátétel, lefegyverzés. A mérsékeltebb angolok - Lloyd George - a gyarmati igények későbbi francia támogatásában bízva álltak melléjük. Keynes már a tárgyalások időpontjában felhívta a figyelmet arra, hogy a diktátum katonai, területi és főleg gazdasági intézkedései revanshoz fognak vezetni. A jóvátétel nemcsak a győztesek kárpótlását, hanem a német gazdasági potenciál meggyengítését is szolgálta.\n\nA nagyhatalmak céljai\n\nAnglia: Németország gyarmatait megkapni, tengeri hatalmát megszüntetni, Európában gátolni Franciaország túlzott megerősödését.\n\nFranciaország: Németország teljes körű és hosszú távú meggyengítése.\n\nOlaszország: területeket akart a Monarchiától, az Adriai-tenger „beltengere legyen.\n\nUSA: távol-keleti, dél-amerikai, szibériai területeken volt érdekelt.\n\nA vesztesek:\n\nA vesztes országokkal különböző időpontokban és helyszíneken kötöttek békét: Németország (Versailles, 1919. június 28.), Ausztria (Saint-Germain, 1919. szeptember 10.). Bulgária (Neully, 1919. november 27.) Magyarország (1920. június 4.), Törökország (Sévres, 1920. augusztus 10., majd újabb tárgyalások Lausanne, 1923. július 24.)\n\nNémetország - Versailles, 1919. június 28.\n\n- Elzász-Lotaringia Franciaországé lett.\n\n- A Saar-vidéket 15 évre nemzetközi felügyelet alá helyezték, utána népszavazás dönt.\n\n- A Rajna-vidék bal partját teljesen, jobb partját 50 km-es sávban demilitarizálták.\n\n- Danzig (Gdansk) szabad város lett.\n\n- A hadsereget 100 ezer főben maximálták, megtiltották a sorozást.\n\n- Át kellett adni a német hadiflottát. Elvesztette minden gyarmatát.\n\n- Jóvátételt kellett fizetniük a németeknek (1921-bcn a jóvátétel összegét 132 millió aranymárkában szabták meg).\n\nAusztria - Saint Germain, 1919. szeptember 10.\n\n- Megszűnt a Habsburg-monarchia.\n\n- Trieszt, Isztria, Dél-Tirol elvesztése: Olaszországhoz kerül.\n\n- Katonai korlátozások (hadsereg, fegyverkészlet maximálása) + jóvátételt fizet..\n\n-A Németországgal való egyesülés (Anschluss) tilalma.\n\nTörökország – Sévres, 1920. augusztus 10.\n\nTerületét felosztották, a tengerszorosokat nemzetközi ellenőrzés alá helyezték.\n\n1923. július 24-én Lausanne-ban újabb békét kötöttek velük. Oka: 1923 októberében a Musztafa Kemál vezetésével kikiáltották a parlamentáris köztársaságot, eltörölték a szultáni hatalmat, megszüntették az ország széttagoltságát.\n\n1923. október 27. után Török Köztársaság – megtarthatta Anatóliát, a kurd és örmény területekkel együtt. ellenőrzése alá vehette a Boszporuszt és a nyugati hatalmak fegyveres erőinek ki kellett vonulniuk az ország területéről. Törökország elveszítette Irakot, Szíriát és Ciprust, megtarthatta viszont Kelet-Trákiát, Isztambult és Szmirnát. Eltörölték a kapitulációkat (a nyugati hatalmak számára kereskedelmi és egyéb előjogokat biztosító szerződéseket) és egyezmény született Görögországgal a lakosságcseréről, aminek következtében néhány hónappal később szinte az összes görög lakos elhagyta Anatóliát.\n\nÚj államok:\n\nLengyelország ismét egységes, szabad állam lett, jelentős területeket kapott a Német Császárságtól, megkapta továbbá Galícia, Bukovina egyes területeit, egyes orosz birodalmi területeket.\n\nCsehszlovákia: Csehország és Szlovákia politikai egysége. Megkapta a Felvidéket, a Szudéta-vidéket és Kárpátalját.\n\nSzerb-Horvát-Szlovén Királyság - 1929-től Jugoszlávia.\n\nRománia: bővült Erdéllyel + a Partiummal + bánáti + kelet-alföldi területekkel, továbbá Besszarábia, Bukovina, Dél-Dobrudzsa területeivel.\n\nTovábbi jelentős események:\n\n- 1921-22: washingtoni konferencia a távol-keleti kérdések megoldására.\n\n-1919: a wilsoni pontok alapján létrehozták a Népszövetséget, amely elvileg a béke megtartására szolgáló szervezet lett volna.\n\nA trianoni béke: 1920. június 4.\n\nMagyarország az Osztrák- Magyar Monarchia tagjaként vett részt az első világháborúban a központi hatalmak oldalán, így a vesztes országok közé tartozott. A háború végén, 1918-ban felbomlott a Monarchia. Magyarországon 1918-ban az őszirózsás forradalom, 1919-ben a tanácsköztársaság kikiáltása, majd a fehérterror időszaka alatt nem volt olyan kormány, amelyet a győztes antant hatalmak elfogadtak volna, hogy békét kössenek velünk. Csak 1920-ban jött létre az antant által is elfogadható törvényes kormány, s ezt követően kötöttek Magyarországgal békét 1920. június 4-én a Párizs melletti Trianoni kastélyban. A magyar békedelegáció gróf Apponyi Albert vezetésével érkezett Párizsba 1920 januárjában. A küldöttség kifejthette álláspontját a békekonferencia előtt, de ez nem befolyásolta a győztesek döntését. A magyar küldöttség visszautasította a béketervezetet. Magyarország területi integritásának szükségességét hangsúlyozták, azt, hogy nem lehet egy ország történelmi, földrajzi, gazdasági és kulturális egységét megbontani. Apponyi az elcsatolandó területeken népszavazásra tett javaslatot. Wilson USA elnök önrendelkezési elvére hivatkozott a békeküldöttség: azaz minden nép maga döntse el, hogy melyik országhoz akar tartozni. Gróf Teleki Pál elkészítette Magyarország „vörös térképét”, amely jelöli, hogy mely területeken laknak többségében magyarok (vörös színnel). Az antant vezetői azonban elsősorban a csehszlovák, román, és jugoszláv követeléseket fogadták el, és a Millerand-levélben elutasították a magyarok kéréseit és tiltakozását: mivel Magyarország vesztes ország, nincs abban a helyzetben, hogy feltételeket diktáljon.\n\nA trianoni béke következményei:\n\nMagyarország területe 283.000 km²-ről 93.000-re csökkent, lakossága 18,2 millióról 7,6-re. A magyarság kb. 1/3-a 3,3 millió fő idegen fennhatóság alá került. Magyarország elvesztette a Felvidéket, Kárpátalját, Erdélyt, a Partiumot (Részek), Bánátot, Bácskát, Burgenlandot (Őrvidéket). Romániához kb. 102.000 km² (Erdély és a Részek) és 1,6 millió magyar, Csehszlovákiához 61.000 km² (Felvidék, Kárpátalja) és 1 millió magyar, a Szerb – Horvát - Szlovén Királysághoz, ami 1929-től Jugoszlávia (Bácska, Bánát, Újvidék) 21.000 km² és 0,5 millió magyar, Ausztriához 4.000 km² (Burgenland) és 25.000 magyar.\n\nEredetileg Sopron Ausztriához kerül volna, de a magyar kormánynak sikerült 1921-re népszavazást elérnie. A lakosság a Magyarországhoz való csatlakozás mellett voksolt, ezért Sopront a „leghűségesebb város – civitas fidelissima” címmel tüntették ki. A békeszerződést a Simonyi - Semadam Sándor kormány idején írták alá, ezt követően a kormány lemondott. Az aláíró: Drache – Lázár Alfréd és Benárd Ágoston volt.\n\nA békeszerződés következményei a jóvátétel fizetésén kívül a különböző katonai (max. 35.000 fő katona) és kereskedelmi korlátozások voltak. Az etnikai elvet csak a környező népek esetében vették figyelembe, s azzal nem törődtek, hogy több millió magyar került idegen uralom alá. Súlyos gazdasági válságot okozott Magyarországon, hogy a nyersanyagforrások, bányák, vasúthálózat nagy része az országhatáron kívül maradt.\n\nA trianoni békeszerződés példátlan mértékű területvesztés volt, ezt a magyarság nem tudta elfogadni és tragédiának fogta fel. A kormányok célja ezután a revízió, azaz a béke felülvizsgálata, a határok visszaállítása volt. A békeszerződés újabb háborúba sodorta emiatt Magyarországot, és ez máig is súlyos nemzetiségi problémák forrása.\n\nMAGYARORSZÁG AZ ELSŐ VILÁGHÁBORÚBAN\n\nMagyarország az 1. világháború kirobbanásakor (1914) az Osztrák - Magyar Monarchia (1867-1918) része volt. Nagy területű, soknemzetiségű monarchia. Magyarország 1. világháborús története megegyezik a Monarchia első világháborús szerepvállalásával.\n\nBelpolitikai gondok (gazdaság, nemzetiségi kérdés, társadalmi ellentétek).\n\nKülpolitikájának célja: politikai befolyás a Balkánon; igazodás Németország közel-keleti terjeszkedéséhez. A „Drang nach Osten” politikája egy összefüggő szövetségi területet képzelt el Németországtól a Balkánon át egészen Kis-Ázsiáig. A Monarchia fennmaradását ettől a szövetségtől remélte.\n\nMAGYARORSZÁG belpolitikája:\n\nHáborús gazdaság:\n\n- rendkívüli törvények és intézkedések;\n\n- katonai ellenőrzés az üzemekben;\n\n- 50 éves korig a férfiak kötelesek voltak munkát vállalni;\n\n- élelmiszerek begyűjtése - rekvirálások;\n\n- jegyrendszer - központi elosztás.\n\nA Monarchia gazdasága nem bírta a háborús terheket, hamar kimerült. Ennek jeleként infláció, áruhiány, tüzelőhiány, ellátási zavarok alakultak ki. 1916 januárjától panaszbizottságokkal próbálták enyhíteni az elégedetlenséget.\n\nBelpolitikai helyzet\n\n1914: Tisza István kormánya a szarajevói merénylet után még háborúellenes volt, de később vállalta a háborút. A magyarországi szociáldemokraták 1915-től békét követeltek.\n\n1916: Károlyi Mihály vezetésével megalakult a Függetlenségi és 48-as Párt. Ellenezték a németbarátságot, szorgalmazták a kapcsolatteremtést az antanttal.\n\n1916. november meghal Ferenc József, utána IV. Károly lett az uralkodó.\n\n1917. február: IV. Károly béketárgyalásokat kezdeményezett. Meghirdette a Monarchia föderalista átszervezésének gondolatát, kezdeményezte a választójog kiterjesztését.\n\n1917. május: Lemondott Tisza István. A miniszterelnök Esterházy Móric, majd Wekerle Sándor lett (1918-ban).\n\nTisza lemondásával összefüggésben alakult meg az úgynevezett Választójogi Blokk:\n\n- a szociáldemokraták,\n\n- a Károlyi-párt,\n\n- a polgári radikálisok és\n\n- Vázsonyi Vilmos Demokrata Pártja részvételével.\n\nCéljuk az egyenlő, titkos, általános választójog bevezetése és a béke megteremtése volt. A háborúellenes csoportokban kezdtek körvonalazódni a háború utáni belpolitika meghatározó irányzatai.\n\nNemzetiségek\n\nIV. Károly reformkísérletei nem találtak széles táborra a Monarchia, illetve Magyarország nemzetiségei körében. A csehek, szerbek, románok ekkor (1917-18) már az önálló nemzetállam megteremtésén dolgoztak. Diplomáciai és katonai céljuk az volt, hogy minél nagyobb területet szerezzenek meg a széteső Monarchiából.\n\n1918. április: a római kongresszuson az antant elismerte a csehek és a románok területi igényeit. Az antanthatalmak hadviselő félnek ismerték el Csehszlovákia Nemzeti Tanácsát (vezetője Tomas Masaryk) és a Román Egység Nemzeti Tanácsát (vezetője Octavian Goga).\n\nA Monarchián belül - főleg Magyarországon - a nemzetiségi határok igen nehezen vagy egyáltalán nem húzhatók meg. Már 1918 elején nyilvánvalóvá vált, hogy a Monarchia esetleges széthullása esetén az országhatárokat nem a történelmi, kulturális múlt és a reális etnikai viszonyok, hanem az antant pillanatnyi politikai érdeke fogja meghatározni.\n\nMagyarország 1. világháború után\n\nA TANÁCSKÖZTÁRSASÁG 1919. március 21 – augusztus 1-ig\n\nFegyveres küzdelmek és bukás:\n\n1919. április 16-án a román, április 28-án a csehszlovák hadsereg indított támadást, Csap és Munkács között találkoztak.\n\nAz északi hadjárat során ellentámadást indított a magyar Vörös Hadsereg Stromfeld Aurél vezetésével. A megszerzett területeket az antant nyomására fel kellett adniuk.\n\n1919. július 30-án a román hadsereg átkelt a Tiszán, ás megindult Budapest felé. Ennek hatására 1919. augusztus 1-jén a Kormányzótanács lemondott.\n\nÉRTÉKELÉSE:\n\nA Tanácsköztársaság megteremtését a polgári állam szétesése, illetve az elkövetkező világforradalomba vetett hit tette lehetővé. A hatalmat ilyen körülmények között csak diktatórikus eszközökkel, sokszor terrorral lehetett fönntartani.\n\nA Tanácsköztársaság diktatórikus jellegéből adódó ellentmondások: a hatalom koncentrációja és a proletariátus hatalomgyakorlása, a választásra jogosultak diszkriminatív megkülönböztetése és az alkotmányosság kísérlete.\n\nA Tanácsköztársaság proletárdiktatúrának nevezte magát, ezért számos intézkedésével osztályalapon osztotta meg a társadalmat. A Tanácsköztársaság hatalomra kerülése minden demokratikus elvnek ellentmondott. A proletárdiktatúra vezetését a népbiztosok szűk körű testülete látta el, élén Kun Bélával. Ez is közrejátszott abban, hogy a rendszer társadalmi elfogadottsága rendkívül alacsony volt.\n\nA Tanácsköztársaság irányító testülete a Forradalmi Kormányzótanács, mely diktatórikus módon gyakorolta a hatalmat, uralma idején több száz rendeletet bocsátott ki, és az élet minden területét szabályozni próbálta, ez is fokozta az emberek kiszolgáltatottságát.\n\nAz ideiglenes alkotmány, mely a Forradalmi Kormányzótanács hatalmára épült, végig meghatározta a Tanácsköztársaság működését.\n\nAz alkotmánytervezete értelmében egy viszonylag szűk csoport kezébe koncentrálódott volna a hatalom. Osztályalapon kirekesztették a választójogból az összes jogosult jelentős részét, ez az intézkedés elfogadhatatlan a demokratikus normák szempontjából. Az elvek és a gyakorlat abban is ellentmondott egymásnak, hogy a Tanácsköztársaság programja a dolgozók demokratikus jogainak kiterjesztését hirdette, alkotmánytervezete mégis egy fentről lefelé építkező államszervezetet fogalmazott meg, ez a felépítés gyakorlatilag kizárta volna a hatalommegosztás érdemi érvényesülését.\n\nA tanácsköztársaság végén, a Kormányzótanács lemondása után 1919. augusztus 1-jén Peidl Gyula vezetésével szociáldemokrata kormány alakult. A román csapatok augusztus 4-én bevonultak Budapestre. A kormánynak nem volt tényleges ereje, így augusztus 6-án egy fegyveres csoport könnyen lemondásra kényszerítette. Az új kormányfő a puccs vezetője Friedrich István lett. (Közben a románok megszállták a Dunántúl északi részét is.) Horthy Miklós, a szegedi kormány hadügyminisztere önálló fővezérséget létesített Siófokon. A nemzeti hadsereg egységei a románok által meg nem szállt területeken büntetőakciókba kezdtek a forradalmak helyi vezetői, szimpatizánsai ellen (fehér-terror). A román kivonulás után, 1919. november 16-án Horthy egységei bevonultak Budapestre. Huszár Károly vezetésével ideiglenes kormány alakult, amely lebonyolította a választásokat. A békekonferencia ideiglenesen elismerte az új kormányt, és meghívást küldött a béketárgyalásokra. Az 1920. január végén megtartott választásokon a Kisgazdapárt és a Keresztény Nemzeti Egyesülés Pártja kapta a legtöbb szavazatot. Február végén a nemzetgyűlés elfogadta az 1920:I. törvénycikket, amely kimondta, hogy az államfői méltóság kérdésének végleges rendezéséig a nemzetgyűlés ideiglenes jelleggel kormányzót választ. 1920. március 1-jén a nemzetgyűlés Magyarország kormányzójává választotta Horthy Miklóst. A Horthy-rendszer 1920 és 1944 között állt fenn Magyarországon.\n\nAz új államfő előbb Simonyi - Semadam Sándort nevezte ki miniszterelnöknek, ez a kormány írta alá a békeszerződést.\n\nA trianoni béke: 1920. június 4.\n\nMagyarország az Osztrák- Magyar Monarchia tagjaként vett részt az első világháborúban a központi hatalmak oldalán, így a vesztes országok közé tartozott. A háború végén, 1918-ban felbomlott a Monarchia. Magyarországon 1918-ban az őszirózsás forradalom, 1919-ben a tanácsköztársaság kikiáltása, majd a fehérterror időszaka alatt nem volt olyan kormány, amelyet a győztes antant hatalmak elfogadtak volna, hogy békét kössenek velünk. Csak 1920-ban jött létre az antant által is elfogadható törvényes kormány, s ezt követően kötöttek Magyarországgal békét 1920. június 4-én a Párizs melletti Trianoni kastélyban. A magyar békedelegáció gróf Apponyi Albert vezetésével érkezett Párizsba 1920 januárjában. A küldöttség kifejthette álláspontját a békekonferencia előtt, de ez nem befolyásolta a győztesek döntését. A magyar küldöttség visszautasította a béketervezetet. Magyarország területi integritásának szükségességét hangsúlyozták, azt, hogy nem lehet egy ország történelmi, földrajzi, gazdasági és kulturális egységét megbontani. Apponyi az elcsatolandó területeken népszavazásra tett javaslatot. Wilson USA elnök önrendelkezési elvére hivatkozott a békeküldöttség: azaz minden nép maga döntse el, hogy melyik országhoz akar tartozni. Gróf Teleki Pál elkészítette Magyarország „vörös térképét”, amely jelöli, hogy mely területeken laknak többségében magyarok (vörös színnel). Az antant vezetői azonban elsősorban a csehszlovák, román, és jugoszláv követeléseket fogadták el, és a Millerand-levélben elutasították a magyarok kéréseit és tiltakozását: mivel Magyarország vesztes ország, nincs abban a helyzetben, hogy feltételeket diktáljon.\n\nA trianoni béke következményei:\n\nMagyarország területe 283.000 km²-ről 93.000-re csökkent, lakossága 18,2 millióról 7,6-re. A magyarság kb. 1/3-a 3,3 millió fő idegen fennhatóság alá került. Magyarország elvesztette a Felvidéket, Kárpátalját, Erdélyt, a Partiumot (Részek), Bánátot, Bácskát, Burgenlandot (Őrvidéket). Romániához kb. 102.000 km² (Erdély és a Részek) és 1,6 millió magyar, Csehszlovákiához 61.000 km² (Felvidék, Kárpátalja) és 1 millió magyar, a Szerb – Horvát - Szlovén Királysághoz, ami 1929-től Jugoszlávia (Bácska, Bánát, Újvidék) 21.000 km² és 0,5 millió magyar, Ausztriához 4.000 km² (Burgenland) és 25.000 magyar.\n\nEredetileg Sopron Ausztriához kerül volna, de a magyar kormánynak sikerült 1921-re népszavazást elérnie. A lakosság a Magyarországhoz való csatlakozás mellett voksolt, ezért Sopront a „leghűségesebb város – civitas fidelissima” címmel tüntették ki. A békeszerződést a Simonyi - Semadam Sándor kormány idején írták alá, ezt követően a kormány lemondott. Az aláíró: Drache – Lázár Alfréd és Benárd Ágoston volt.\n\nA békeszerződés következményei a jóvátétel fizetésén kívül a különböző katonai (max. 35.000 fő katona) és kereskedelmi korlátozások voltak. Az etnikai elvet csak a környező népek esetében vették figyelembe, s azzal nem törődtek, hogy több millió magyar került idegen uralom alá. Súlyos gazdasági válságot okozott Magyarországon, hogy a nyersanyagforrások, bányák, vasúthálózat nagy része az országhatáron kívül maradt.\n\nA trianoni békeszerződés példátlan mértékű területvesztés volt, ezt a magyarság nem tudta elfogadni és tragédiának fogta fel. A kormányok célja ezután a revízió, azaz a béke felülvizsgálata, a határok visszaállítása volt. A békeszerződés újabb háborúba sodorta emiatt Magyarországot, és ez máig is súlyos nemzetiségi problémák forrása. A trianoni békeszerződés 1920. június 4-i aláírása után Teleki Pál lett a miniszterelnök.', 255, 1, '2026-04-17 09:41:10', '2026-04-17 09:41:10');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(29, 29, 'A második világháború (egyetemes, magyar)', '29.docx', '29. tétel: A második világháború (egyetemes, magyar)\n\nA második világháború: 1939-1945\n\nI. Előzmények:\n\nAz első világháború utáni békeszerződések konfliktusok forrásaivá váltak. A vesztes országok közül Németország agresszív külpolitikája a második világháborúhoz vezet\n\n1933. Németországban Hitler és a nemzetiszocialisták kerülnek hatalomra. A németek kilépnek a Népszövetségből, sőt gazdaságukat haditermelésre állítják át.\n\n1935. Saar-vidéki népszavazás – a terület ismét Németországé, továbbá általános hadkötelezettséget vezet be, s felállítja a légierőt a versailles-i békét ezzel megszegi.\n\n1936. a Rajna-vidék német megszállása /remilitarizálása/, amely fegyvermentes volt.\n\n1936. Berlin – Róma tengely létrehozása – a tengelyhatalmak létrejötte. Céljuk az első világháború utáni visszarendezés, a versailles-i béke megtámadása, a terjeszkedés, azaz az expanziós politika. Ezért felrúgják a nemzetközi törvényeket.\n\n1936. antikomintern paktum Japánnal, majd Olaszországgal /1937/- kommunistaellenes szövetséget kötnek és elismerik egymás területi igényeit. Japán Kínát, Délkelet-Ázsiát hódítja meg és a Csendes-óceán térségét birtokolná, Olaszország Fiume után Albániát és Etiópiát foglalja el s Afrikában terjeszkedne.\n\n1936-39. spanyol polgárháború – a spanyol fasiszta Franco tábornokot támogatja Németország és Olaszország fegyverrel. Ez a második világháború főpróbája. Anglia és Franciaország nem avatkozik bele, mert nem akar háborút.\n\n1938. március 12. Anschluss – Ausztria bekebelezése, a német területek egyesítése.\n\n1938. szeptember 29-30. müncheni konferencia - Chamberlain (angol), Daladier (francia) és Hitler megegyezik a Szudéta-vidék Németországhoz csatolásáról. /Ez volt a XX. századi Canossa-járás./ A nyugati hatalmak abban bíznak, ha Hitler igényeit teljesítik, elodázhatják, vagy megakadályozhatják a háborút, ezért hagyják sorsára Csehszlovákiát. A nemzetközi biztonsági rendszer ezzel felborult.\n\n1939. március 15. a német csapatok bevonulnak Prágába, létrehozzák a Cseh-Morva Protektorátust, Magyarország megkapja tőlük Kárpátalját.\n\n1939. augusztus 23. szovjet-német meg nem támadási egyezmény: Molotov – Ribbentrop paktum /titkos záradéka Lengyelország felosztásáról szól/ A nyugati hatalmak nem akarnak ugyanis a szovjetekkel megegyezni, mert a bolsevik veszélytől jobban féltek, mint a fasizmustól.\n\n1939. szeptember 1. Lengyelország megtámadása – a második világháború kezdete. Hitler nagyhatalmi terveinek megvalósítására törekszik.\n\nA második világháború szakaszai:\n\nI. 1939. szeptember 1 – 1941. június 22.\n\nLengyelország megtámadásától Szovjetunió megtámadásáig\n\nII: 1941. június 22 – 1943. február 2.\n\nSzovjetunió megtámadásától a németek sztálingrádi kapitulációjáig\n\nIII. 1943 – a fordulat éve, a szövetségesek ellentámadása, győzelmei\n\nIV. 1943 végétől 1945. szeptember 2-ig\n\na teheráni konferenciától a fasiszta hatalmak legyőzéséig, Japán kapitulációjáig\n\nA második világháború kezdete, első szakasza 1939. szeptember 1 – 1941. június 22.\n\n1939. szeptember 1. Lengyelország német megtámadása hadüzenet nélkül történt. Szeptember 17-én Szovjetunió is megtámadja, s felosztják egymás között a Curson-vonalig. Anglia és Franciaország hadüzenetet küld szeptember 3-án, de összeütközésre nem kerül sor, ezért hívják ezt FURCSA HÁBORÚ”-nak.\n\nÉszaki hadjárat: VILLÁMHÁBORÚ. 1939 novemberében Szovjetunió megtámadja Finnországot, 1940 áprilisában Németország, pedig Dániát és Norvégiát. A stratégiailag fontos területeket ellenőrzésük alá veszik, hogy északról ne támadhassák.\n\nNyugati hadszíntér:\n\n1940. május 10. – a semleges Belgium, Hollandia, majd Franciaország elleni támadás. A németek elkerülik a franciák által kiépített védelmi vonalat, a Maginot-vonalat. (A németek ABC-hadműveletnek, Churchill Sarlóvágás-hadműveletnek nevezi.) A németek gyorsan előrenyomulnak.\n\n1940. május Dinamó-hadművelet: a francia-belga-angol csapatokat az óceánig szorítják Dunkerque-nél, az angolok a polgári lakosságot is mozgósítják a vízi mentésre, kb. 300 000 katonát menekítenek Franciaországból Angliába.\n\n1940. június – Olaszország is hadba lép a franciák ellen, a németek elfoglalják Párizst. 1940. június 22. Compiégne-ben fegyverszünetet kötnek a franciákkal. (Épp abban a vasúti kocsiban, ahol a németek 1918-ban írták alá)\n\nFranciaország északi és nyugati területét megszállják, délen Vichyben bábkormányt hoznak létre Pétain vezetésével. De Gaulle ellenállási mozgalma!\n\n1940. augusztus 1. az angliai csata kezdete\n\n1940 májusától Churchill a miniszterelnök: „csak vért és könnyeket ígérhetek”\n\nHitler csak légi úton támad, mert a brit hadiflottával nem tudna elbánni. (A világ legnagyobb hadiflottájával rendelkezik Anglia.) Kb. 40 000 angol halt meg az angliai bombázások során. A németeknek azonban üzemanyag-ellátási nehézségeik voltak, hiszen csak rövid ideig tudtak a légtérben maradni. Októberben elhalasztják Anglia bombázását a köd és az angolok találmánya, a radar miatt. Valójában később már nem tudták megtámadni.\n\n4. Déli hadszíntér 1941. Mussolini sikertelen támadásai Egyiptomban és a Balkánon\n\nHitler Mussolini segítségére siet: 1941. április 6. megtámadja Jugoszláviát\n\n1941. április – elfoglalja Görögországot (de partizánháborúk)\n\nRommel vezetésével a német Africacorps győzelmeket arat Egyiptomban, de 1942. okt.-ben az angol Montgomery El-Alameinnél legyőzi\n\n5. Diplomácia: - 1940. szept. háromhatalmi egyezmény: Japán, Olasz- és Németország\n\n- 1941. aug. Atlanti Charta USA és Anglia között + Szovjetunió. Ok:\n\nA háború második szakasza 1941. június 22-től, a Szovjetunió megtámadásától\n\n1941. június 22-én a Barbarossa-terv értelmében meglepetésszerűen támadják meg a németek Szovjetuniót /Drang nach Osten/. Sztálin nem akarta elhinni, így később mozgósította csapatait. A németek célja a szovjet nyersanyaglelőhelyek megszerzése, a szlávok leigázása. Három irányból támadtak a németek:\n\nészakon Leningrádot 900 napig blokád alatt tartották, de nem tudták elfoglalni.\n\nközépen Moszkvát támadták, de a szovjetek visszaszorították. Sztálin alig hiszi el, hogy Hitler megtámadta.\n\ndélen Kijevet elfoglalták, a kaukázusi olajmezők felé tartottak, de Sztálingrádnál 1942 augusztusában vereséget szenvedtek, Paulus német csapatai 1943. február 2-án kapituláltak. A Don folyónál lévő 200 000 fős 2. magyar hadsereget ekkor érték nagy veszteségek Voronyezsnél.\n\n1941. december 7. Japán megtámadja az USA-t Pearl Harbornál (Hawaii), s lebombázza a csendes-óceáni amerikai flottát, ezért az USA feladja izolacionalista politikáját és belép a háborúba. A németek és az olaszok is hadat üzennek neki. Japán elfoglalja a csendes-óceáni amerikai és európai gyarmatokat. Az USA csak 1942 júniusában tudta megállítani terjeszkedésüket a Midway-szigeteknél, majd McArthur vezetésével szigetről szigetre nyomult előre (békaugrás hadművelet). Légi és tengeri csatákat vívtak, de az USA nem tudott partra szállni Japánban. A háború világméretű. Az USA elnöke ekkor Roosevelt.\n\nII. világháború – a 1943 a fordulat éve\n\nSzövetséges hatalmak:\n\nUSA\n\nAnglia\n\nSzovjetunió\n\nTengelyhatalmak:\n\nNémetország\n\nOlaszország\n\nJapán\n\nA szövetségesek és a tengelyhatalmak szemben álltak egymással.\n\n1943 ellentámadásba lendülnek a szövetséges hatalmak.\n\nEz volt a fordulat éve.\n\nAz első frontot Olaszországban 1943-ban nyitják meg a szövetségesek, mert ez volt a leggyengébb fasiszta állam. Afrika és Szicília felől támadnak. Lassan haladnak. Csiga-offenzíva. ( A Gusztáv-vonalig jutnak el.) – ez az 1. front.\n\nÉszak - Olaszországban létrehozza Mussolini a Saloi köztársaságot, de 1945-ben meggyilkolják.\n\n1943 nov.-dec. : Teheráni konferencia (témája: a 2. front megnyitása.)\n\nUSA Roosevelt\n\nANGLIA Churchill\n\nSZOVJETUNIÓ Sztálin\n\nChurchill a Balkánon akarta megnyitni, Görögországban Ez Magyarország számára előnyös lett volna, hogy kiugorjunk a háborúból.\n\nSztálin viszont Normandiát (Franciaország) javasolta és neki lett döntő szava.\n\nEisenhoower (USA) tábornok vezette a 2. front megnyitását.\n\n1944. június 6. D-nap\n\n1945 jan.-febr.: Jaltai konferencia\n\nA szövetségesek elhatározzák, hogy a fasiszta hatalmak teljes győzelméig nem állnak meg.\n\nÉrdekszférákra osztják Európát attól függően, hogy melyik szövetségi hatalom szerzi vissza a fasisztáktól a területeket.\n\nPl. felosztották Magyarországot 80-20% arányban. (80% – szovjeteké, 20% – angoloké, amerikaiaké)\n\n1945. május 9. : Elbai kézfogás, az európai háború vége.\n\nAz Elba folyónál találkoznak.\n\nKelet felöl jönnek a szovjetek, és nyugatról pedig az angolok és az amerikaiak.\n\nItt és ekkor ér véget a II. világháború Európában.\n\n1945 júl.-aug. : Potsdami konferencia\n\nFeladata: a világháború utáni rendezés Európában, illetve előkészítik a párizsi békét.\n\nRésztvevők:\nUSA Truman elnök (mert Roosevelt meghalt)\nANGLIA Attlee (mert a választások során nem nyert Churchill. )\nSZOVJETUNIÓ Sztálin (maradt…)\n\nII. világháború befejezése\n\nJapán elleni háború.\n\nAz USA nem tud partra szállni Japánban, ezért 2 atombombát dobnak le.\n\n1945. aug. 6. Hirosima\n\n1945. aug. 9. Nagasaki\n\nMajd ezek után 1945 szept. 2-án Hirohito (japán császár) bejelenti Japán kapitulációját\n\nA II. világháború befejeződik.\n\n1946-ban nürnbergi per náci háborús bűnösök pere\n\n1947 párizsi béke.\n\nMagyarország a II. világháborúban\n\nElőzmények:\n\nTerületgyarapodás Németországnak és Olaszországnak köszönhetően.\n\n1938. nov. 2. Első bécsi döntés. Csehszlovákiától megkapjuk Felvidék egy részét. Kb.: 12.000 km2.\n\n1939. márc. 13 Csehszlovákiától Kárpátalját elfoglaljuk.\n\n1940. aug. 30 Második bécsi döntés. Romániától Észak-Erdélyt és Székelyföldet megkapjuk.\n\n1941 április Jugoszláviától Délvidéket szerezzük meg.\n\nA háború idején:\n\n1939 – 1945 II. világháború.\n\n1939 – 1941 Teleki Pál a miniszterelnök a fegyveres semlegességet preferálja.\n\n1940. dec. Jugoszláviával örökbarátsági szerződést írunk alá.\n\n1941. márc. Németország felszólítja Magyarországot Jugoszlávia megtámadására.\n\nTeleki nem akarja háborúba sodorni az országot.\n\n1941. ápr. 3. Teleki Pál öngyilkosságot követ el. Bárdossy László belép:\n\n1941. ápr. 11. Hitlerrel megtámadjuk Jugoszláviát.\n\n1941. június 26. Kassa bombázása (szovjetek?) – belépünk a 2. világháborúba Szovjetunióval szemben.\n\nMagyarország a második világháborúban\n\nTeleki Pál (1939-41) miniszterelnök idején\n\nAz első világháborúból vesztesként kikerülő Magyarország jelentős területeket veszített el az 1920-ban kötött trianoni béke értelmében. A magyar kormányok célkitűzései ezután a revíziós politika, amely újabb világháborúba sodorja az országot.\n\nHitler segítségével az I. bécsi döntés (1938. nov. 2.) értelmében visszakaptuk a Felvidék határ menti területét, közel 12.000 km2-rel bővült az ország területe, melynek lakossága 50-60%-ban magyar volt.\n\n1939. március 15-én elfoglaltuk Kárpátalját. Ezután Németország elkötelezettjeivé váltunk.\n\n1939. szeptember 1-jén kitört a 2. világháború. Németország megtámadja Lengyelországot, Magyarország a fegyveres semlegesség politikáját képviseli. Magyarország számára kedvező pozíció biztosítása volt a célja.\n\n1939-ben Magyarország nem vett részt sem Lengyelország megtámadásában, sem a háborúban. A lengyel-magyar barátságnak történelmi gyökerei vannak. Több ezer lengyel katona menekült a háború kezdetén Magyarországra, Balatonbogláron még lengyel középiskolát is indítunk.\n\nKövettük a német zsidóüldözési politikát is:\n\n1939. a II. zsidótörvényt. A törvény már nemcsak vallási (1. zsidótörvény 1938), hanem faji alapon határozta meg, ki számít zsidónak. A zsidó foglalkoztatottak számát az 1. zsidótörvény (1938) szerinti 20%-ról 6%-ra csökkentette.\n\n1939-ben a németek Lengyelországot lerohanták, de a Teleki- kormány igyekezett kívül maradni a háborún. Teleki Pál miniszterelnök a háború kitörése után is a fegyveres semlegességre törekedett, lehetővé tette, hogy lengyelek tízezrei meneküljenek hazánkba.\n\nA német-olasz területi döntőbíróság 1940-ben kimondta az úgynevezett második bécsi döntést, amelynek értelmében 43 ezer km2 terület került vissza Mo.-hoz. Visszakaptuk Észak- Erdélyt és Székelyföldet. Magyarország így még jobban elkötelezte magát a Németország mellett.\n\n1940 novemberében Mo. csatlakozott a háromhatalmi egyezményhez.\n\n1940. decemberben örök barátsági szerződést kötött Jugoszláviával Magyarország. Két független állam szerződésére került sor. A Magyar Királyság békés viszony kialakítására törekedett a Jugoszláv Királysággal. Ezzel a lépéssel akarta bizonyítani Teleki Nyugat felé a semlegességet, így próbálta fenntartani a kapcsolatot az angolszász hatalmakkal, és így kívánta elkerülni a túlzott német orientációt. Déli szomszédunk területileg nem volt a németek befolyása alatt még ekkor.\n\n1941 márciusában Hitler felszólította Horthyt, hogy a magyar hadsereg vegyen részt a Jugoszlávia elleni háborúban. A fegyveres semlegesség politikája megbukott, ezért 1941. április 3-án gróf Teleki Pál miniszterelnök öngyilkos lett.\n\n1941. április 11-én Magyarország bekapcsolódik a Jugoszlávia elleni háborúba, és a II. világháborúba (1939-45) Horthy Miklós kormányzó Bárdossy Lászlót nevezte ki kormányfőnek.\n\nElfoglalták a Bácskát, a Muraközt és a baranyai háromszöget. 11.417 km2 terület került vissza Mo.-hoz. A Délvidéket megszállják a csapatok.\n\nMagyarország a németek oldalán hadviselő fél lett.\n\nA területi revíziós politika sikerének feltételeit a törvényhozás is támogatta pl. a honvédelemről szóló törvény, amely a fegyveres semlegesség támogatását készítette elő: általános hadkötelezettség, leventeképzés, légvédelmi kötelezettség, a törvény hatásaként növekedett a feszültség Magyarország és a szomszédai között.\n\nMagyarország a Szovjetunió elleni háború idején\n\nA Barbarossa-terv elindításakor Németország megtámadta Szovjetuniót 1941. június 22-én. Ebben a román és szlovák csapatok támogatták, de Magyarország nem.\n\n1941. június 26-ban azonban ismeretlen eredetű gépek Kassát, Munkácsot és Rahót bombázták. Horthy megítélése szerint csakis a szovjetek lehettek.\n\n1941. július 1-jén a magyar hadsereg egyik alakulata, a Kárpát-csoport átlépte a szovjet határt. bebizonyosodott, hogy a magyar hadsereg felszereltsége és kiképzettsége hiányos. Pedig a győri program (1938) modernizálta a haderőt. Csak a gyorshadtest maradt a fronton.\n\nMagyarország 1941 decemberétől hadiállapotban állt az USA-val és Angliával is.\n\nEzzel egy időben rendkívüli belpolitikai intézkedéseket is tett a Bárdossy-kormány:\n\n- a német igényeknek megfelelő árukivitel, a katonai bíráskodás kiszélesítése, munkaszolgálat;\n- III. zsidótörvény – megtiltotta a zsidók és nem zsidók házasságát (1941).\n\n200.000 katonát küld a frontra 1942 áprilisától a Don folyóhoz: a 2. magyar hadsereget, melyet Jány Gusztáv vezetett, de Paulus német parancsnoksága alá került. Voronyezs térségében, majd 1943. január-februárban a Don folyó kanyarulatában.\n\nA szovjetek felmorzsolták a magyar haderőt: 1943. január 12. és február 9. között\n\n(40 ezer halott, 70 ezer hadifogoly, sokan eltűntek).\n\nKözben Magyarországon antifasiszta, háborúellenes megmozdulások voltak.\n\nKállay Miklós hintapolitikája:\n\nA második világháborúban német szövetségben harcoló Magyarország miniszterelnöke (1942 és 1944 között) Kállay Miklós volt.\n\n1942-ben Horthy Miklós kormányzó menesztette a túlzottan németbarát miniszterelnököt, Bárdossy Lászlót, és Kállay Miklóst nevezte ki miniszterelnökké. Az új miniszterelnök feladata a Németországhoz fűződő szálak lazítása, és óvatos külpolitikai fordulat előkészítése volt (ez a „Kállay-kettős”, illetve hintapolitika). Titkos tárgyalások kezdődtek az angolszász hatalmakkal (Isztambul, Szent-Györgyi Albert). Kállay nyilvánosan németbarát tevékenységet folytatott, eközben titokban a szövetségesekkel lépett kapcsolatba. Tehát ezt nevezzük Kállay-kettősnek, vagy hintapolitikának. Magyarország háborúból való kiugrásának lehetősége és a szövetségesek katonai hadmozdulatai között lavírozott. Az elsőrangú német hírszerzés azonban pontos információval rendelkezett a titkos tárgyalásokról.\n\nKállay miniszterelnöksége alatt került sor a második magyar hadsereg doni katasztrófájára 1943. január 12 - február 9. között.\n\nKállaynak a fordulatot titokban kellett előkészítenie, és mindeközben ügyelnie kellett arra, hogy a németekkel fenntartsa a jó viszonyt. Közben a szövetséges hatalmak és Magyarország között tárgyalások folytak. Kötelezettségeink: Magyarország csökkenti a katonai és gazdasági együttműködést Németországgal, átalakítja a magyar hadvezetést. Ezek az elképzelések csak akkor valósultak volna meg, ha a szövetséges (angol– amerikai) haderő eléri az ország határát.\n\nKözben a szövetségesek egymást segítve minden fronton fölénybe kerültek 1942/43 folyamán. Az első front: az olaszországi front megnyitása volt 1943-ban. Anglia katonai és politikai okokból is nagy reményeket fűzött az olaszországi partraszálláshoz, de a terv részben kudarcba fulladt a „csigaoffenzíva”, illetve a gyors német megszállás miatt. Az olasz kapituláció után, 1943. szeptember 9-én titkos fegyverszüneti egyezményt írtak alá a magyarok Isztambulban.\n\nA szövetségesek teheráni megállapodásával (1943. nov. 28 – dec. 1.) szertefoszlott a remény, hogy Mo. területére angolszász seregek lépnek. Churchill nem nyithatott frontot a Balkánon, mert a szovjetek részéről Sztálin nem fogadta el. A térségben kizárólag a Vörös Hadsereg fog szárazföldi hadműveletet folytatni. Magyarország helyzete összefüggésben állt a második front megnyitásával kapcsolatos nagyhatalmi, politikai célokkal. A második front megnyitásával kapcsolatos szovjet álláspont Franciaországot tekinti az ideális helyszínnek. Németországot így többfrontos háborúra kényszeríthették, de a magyarok esélyei így csökkennek a németekkel szemben, nehezebb a háborúból való kiugrásunk. A második front megnyitásának helyszínében a szövetségesek sokáig nem értettek egyet, de Németország minél gyorsabb legyőzésében mindenki érdekelt volt. Sztálinnak politikai érdeke is fűződött a franciaországi új hadszíntérhez, hiszen így a szövetségesek nem akadályozzák a tervezett kelet-közép-európai terjeszkedésben. Az angolok a balkáni terveikkel a Földközi-tenger térségét szerették volna biztosítani.\n\nIII. Magyarország a világháború végén\n\nKállay reménye a balkáni partraszállást illetően kudarcot vallott, hiszen a teheráni konferencián a szövetségesek a normandiai partraszállás mellett döntöttek. Magyarország mozgástere ezután folyamatosan szűkült (német megszállás).\n\nA németek a titkos tárgyalásokról értesülve többé nem bíztak a magyar szövetségben, ezért 1944. március 19-én a „Margaréta” terv alapján megszállták az országot. Miniszterelnök a németek embere, Sztójay Döme.\n\nA megszállás következményei:\n\n- Megindultak a deportálások, a zsidóüldözés. 1944 tavaszán a németek, a magyar hatóságok közreműködésével közel félmillió vidéki zsidó vagy annak nyilvánított magyar állampolgárt deportáltak és gyilkoltak meg. A budapesti deportálásokat Horthy leállította.\n\n- Megindult az ország gazdasági kirablása (nyersanyag, munkaerő, közlekedés).\nRendeletek sorozatával megfosztották a zsidókat vagyonuktól, elbocsátották állásaikból, elvették műhelyeiket, üzleteiket, ápr. 5-től elrendelték a sárga csillag viselését. Ápr.7-től megkezdődött a nagyvárosokban (kivéve Budapest) a gettók felállítása, vidéken pedig a gyűjtőtáborok létesítése. 1944. május közepén kezdődött el a vidéki zsidóság deportálása, elsősorban Auschwitzba, aztán Buchenwaldba, Zeitzba.\n\nHorthy titkos tárgyalásokat kezdeményezett a háborúból és a német szövetségből való kiválás érdekében. Lakatos Gézát nevezte ki miniszterelnökké. Feladata a magyar kiugrás előkészítése.\n\n1944 szeptemberétől a trianoni Magyarország területén van a Vörös Hadsereg. Októberben magyar fegyverszüneti küldöttség utazott Moszkvába.\n\n- 1944. október 15.: Horthy rádióbeszédben jelentette be, hogy fegyverszünetet kér Horthy kiugrási kísérlete összeomlott.\n\nA németek Szálasi Ferenc nyilas kormányát juttatták hatalomra: felállították a budapesti gettót, ahonnan több száz embert elhurcoltak, sokakat az utcákon vagy a Duna-parton végeztek ki. Az 1941-es határok között élt mintegy 825.000 főt számláló zsidóság vesztesége kb. 500 000-600 000 között volt.\n\n1944 szeptemberétől a szovjet harcok már Magyarországon zajlottak.\n\nVégleges 1945. április 13-án verték ki Magyarországról a német csapatokat. A szovjet hadsereg hadműveletei nyomán a nyilas-fasiszta uralom megszűnt Mo.-on. 1945. április elejére az ország egész területe szovjet katonai megszállás alá került és a szovjet érdekszférába. A felszabadulást megszállás követte, amely 1991 júniusában ért véget.', 152, 1, '2026-04-17 09:41:10', '2026-04-17 09:41:10');
INSERT INTO `tetelek` (`id`, `sorszam`, `cim`, `forras_fajlnev`, `tartalom`, `bekezdes_db`, `aktiv`, `created_at`, `updated_at`) VALUES
(30, 30, 'A kétpólusú világrend', '30.docx', '30. tétel: A kétpólusú világrend\n\n(kialakulása, jellemzői, a két blokk berendezkedése, konfliktusok, felbomlása)\n\nA hidegháború\n\nA keleti és a nyugati blokk jellemzői:\n\nTájékozódás térben és időben:\n\nA hidegháború, a kétpólusú világrend kezdete: 1947 / 1948 / 1949.\n\nA szovjet megszállás már 1945-ben elkezdődött, ez egyben a kommunista hatalomátvétel kezdete is a keleti tömb országaiban. A kétpólusú világrend vége: a rendszerváltások: 1989 / 1990, illetve a Szovjetunió összeomlása: 1991.\n\nTérbeli jellemzők:\n\nA keleti blokk a Szovjetuniót és kelet- / közép-európai országokat jelentette.\n\nA nyugati blokk az Amerikai Egyesült Államokat és nyugat-európai szövetségeseit jelentette.\n\nPOLITIKAI TÉREN:\n\nA keleti blokk országai kommunista, egypárti diktatúrák voltak.\n\nA nyugati blokk országai (többpárti) demokráciák voltak.\n\nÖsszehasonlítva: Nyugaton érvényesült a hatalommegosztás elve, Keleten pedig a pártvezetés kezében összpontosult a hatalom. Nyugaton szabad választások voltak több párt részvételével, Keleten a választások formálisak voltak. Nyugaton független igazságszolgáltatás működött, Keleten az igazságszolgáltatás a lakosság megfélemlítésének eszköze volt pl. koncepciós perek.\n\nGAZDASÁGI TÉREN\n\nA keleti blokk országaiban bevezették a tervgazdaságot.\n\nA nyugati blokk országaiban fennmaradt a piacgazdaság vagy helyreállították a piacgazdaságot.\n\nMarshall-segély(1947)\nA KGST-kereskedelem sajátosságai: keleten (1949)\n\na közép-európai államok gépeket, míg a Szovjetunió nyersanyagot szállított;\n\nalapvetően kétoldalú kapcsolatok voltak a Szovjetunió és a kisebb tagállamok között.\n\nA Közös Piac célkitűzései: nyugaton\n\nközös vámterület kiépítése;\n\na négy szabadság megvalósítása: áruk, tőke, szolgáltatások, munkaerő.\n\na piaci viszonyok megőrzése a nagyobb térségen belül.\n\nA KGST-n belül közvetlen árucsere, barterkereskedelem folyt, míg a Közös Piacon belül fennmaradt a piaci verseny. A KGST-kereskedelem nem ösztönzött a növekedésre, fejlesztésre, míg a Közös Piac gazdasági fejlődést eredményezett.\n\nKeleten a termelést és a fogyasztást is megtervezték, Nyugaton ezt a piaci verseny alakította. Keleten a tervgazdaság merevsége, hibái gazdasági lemaradáshoz vezettek, Nyugaton a piacgazdaság biztosította a technikai és gazdasági fejlődést. A tervgazdaságokban az állami tulajdon vált uralkodóvá, a piacgazdaságokban a magántulajdon maradt az.\n\nKATONAI TÉREN:\n\nA Szovjetunió fölénye a szárazföldről indítható interkontinentális és közép-hatótávolságú atomfegyverek terén.\n\nAz USA fölénye a tengeralattjárókról és repülőkről indítható atomfegyverek terén.\n\nAz egész korszakban kiélezett fegyverkezési verseny folyt a két blokk és szuperhatalom között.\n\nA nukleáris fegyverkezési verseny célja az elrettentés volt. Az Egyesült Államok a hagyományos tengeri és légi fegyverek terén is erre törekedett, míg a Szovjetunió szárazföldi fölénnyel rendelkezett.\n\nA fegyverkezési verseny költségei a Szovjetuniót sokkal jobban megviselték.\n\nA nyugati blokk katonai szövetsége volt a NATO. A keleti blokk katonai szövetsége volt a Varsói Szerződés. A NATO célja a szovjet fenyegetés elhárítása volt amerikai segítséggel, míg Varsói Szerződés a Szovjetunió eszköze volt csatlósai ellenőrzésére. A NATO rögtön a hidegháború kezdetén megalakult, 1949-ben, míg a Varsói Szerződést csak később hozták létre, 1955-ben – az NSZK újrafelfegyverzése, az osztrák államszerződés aláírása, illetve a közép-európai csatlósok megszállásának legalizálása miatt.\n\nKIFEJTÉS:\n\nA hidegháború két szuperhatalom, az USA és a szovjetunió (SZU) között jött létre 1945 után. A második világháború végén 1945 májusában megtörtént a szövetségesek elbai kézfogása, azaz a szovjet és angol-amerikai csapatok találkozása, melyek nyugat-keleti irányból támadtak Németországra, s annak teljes legyőzéséig együttműködtek. Az 1943-ban Teheránban, 1945-ben Jaltában, majd Potsdamban tartott konferencián a szövetségesek a háborúval kapcsolatos megbeszéléseken kívül a háború utáni kérdéssel is foglakoztak, s Jaltában érdekszférákra osztották fel Európát. A szovjetek által felszabadított területeken a Szovjetunió, a nyugati részen angol, amerikai és francia befolyás érvényesült. 1945. augusztus 6-án és 9-én Hirosimára és Nagasakira atombombát dobtak az amerikaiak, ezzel megtörték a japánok ellenállását, akik 1945. szeptember 2-án kapituláltak, s ezzel véget ért a 2. világháború. A háborút követően az USA sokat nyerő győztesként szerepel, s az atombomba birtokában a világ vezető hatalmává vált. Ezt majd az űrrakéták és a műholdas védelmi rendszer fogja felülmúlni (1981). A SZU is igyekezett atombombát létrehozni 1946-ban. A hidegháború kezdete: 1947, a 2. világháborút lezáró párizsi békék után. A II. világháború végén a szövetségesek kialakították saját befolyási zónáikat.\n\nAZ INTEGRÁCIÓ ÉS A HIDEGHÁBORÚ: a háborút követően a szövetséges hatalmak útjai szétváltak, a Szovjetunió Közép- és Kelet-Európában és Délkelet-Ázsiában éreztette befolyását, és célja a szocialista világrendszer kiépítése volt. Az USA a tőkés világ vezető hatalma lett. Az angol Churchill fogalmazta meg 1946-ban a fultoni beszédében, hogy a világ kettészakadt, s közötte vasfüggöny húzódik, ennek a másik oldalán áll a kommunista vezetésű Szovjetunió és érdekszférája. Truman amerikai elnök kidolgozta politikai koncepcióját 1947-ben: az USA vezető szerepet vállal, és támogatni fogja a kommunizmus ellen fellépő országokat. 1947-ben gazdasági téren is segítséget nyújtott a nyugati tömbhöz csatlakozó európai országoknak, ez volt a Marshall-segély. Célja a piac bővítése és megtartása az USA számára, az európai demokráciák stabilizálása, az USA gazdasági és politikai hatalmának erősítése. 1949-ben katonai szervezetet hoznak étre, a NATO-t, ez az Észak-atlanti Szerződés Szervezetét, hogy megakadályozza a SZU uralmának további kiterjedését.\n\nKatonai integráció:\n\nA nyugati blokk katonai szövetsége a NATO, a keleti blokk katonai szövetsége a Varsói Szerződés volt. A NATO célja a szovjet fenyegetés elhárítása volt amerikai segítséggel, míg a Varsói Szerződés a Szovjetunió eszköze volt a keleti blokk ellenőrzésére. A NATO rögtön a hidegháború kezdetén megalakult, 1949-ben, míg a Varsói Szerződést csak később hozták létre, 1955-ben – az NSZK újrafelfegyverzése, NATO-tagsága, az osztrák államszerződés aláírása, illetve a közép-európai csatlósok megszállásának legalizálása miatt.\n\nAz egész korszakban kiélezett fegyverkezési verseny folyt a két blokk, szuperhatalom között. A Szovjetunió fölénye a szárazföldről indítható interkontinentális és közép-hatótávolságú atomfegyverek terén figyelhető meg, az USA fölényét a tengeralattjárókról és repülőkről indítható atomfegyverek biztosítják. A nukleáris fegyverkezési verseny célja az elrettentés volt. Az Egyesült Államok a hagyományos fegyverek terén is tengeri és légi, míg a Szovjetunió szárazföldi fölénnyel rendelkezett. A fegyverkezési verseny költségei a Szovjetuniót sokkal jobban megviselték.\n\nAmíg a nyugati hatalmak az államok szabad önrendelkezését figyelembe vették, addig a „vasfüggöny” keleti oldalán húzódó országok (Magyarország, Lengyelország, NDK, Csehszlovákia, Bulgária, Románia) a Szovjetunió befolyása alá kerültek. A Szovjetunió második világháború végén nemcsak felszabadította a német uralom alól, hanem egyben meg is szállta a kelet-közép-európai országokat. A SZU fő eszköze az országokban állomásozó szovjet katonaság, a Kominform, a helyi párt és a karhatalmi szervek voltak.\n\nEzeket az országokat 1949-től gazdaságilag a Kölcsönös Gazdasági Segítség Tanácsa (KGST), katonailag 1955-től a Varsói Szerződés fogta össze.\n\nPolitikai jellemzők:\n\nA keleti blokk országai kommunista, egypárti diktatúrák voltak, a nyugati blokk országai pedig (többpárti) demokráciák. Nyugaton érvényesült a hatalommegosztás elve, Keleten a pártvezetés kezében összpontosult a hatalom. Nyugaton szabad választások voltak több párt részvételével, Keleten a választások formálisak voltak. Nyugaton független igazságszolgáltatás működött, Keleten az igazságszolgáltatás a lakosság megfélemlítésének eszköze volt.\n\nGazdasági jellemzők:\n\nA KGST-kereskedelem (1949) során a közép-európai államok gépeket, míg a Szovjetunió nyersanyagot szállított; alapvetően kétoldalú kapcsolatok voltak a Szovjetunió és a kisebb tagállamok között. Nyugat-Európában létrejött 1957-ben a Közös Piac, célkitűzése: közös vámterület kiépítése; a négy szabadság megvalósítása; a piaci viszonyok megőrzése a nagyobb térségen belül. Összehasonlítva: a KGST-n belül közvetlen árucsere, barterkereskedelem folyt, míg a Közös Piacon belül fennmaradt a piaci verseny. A KGST-kereskedelem nem ösztönzött a növekedésre, fejlesztésre, míg a Közös Piac gazdasági fejlődést eredményezett. A keleti blokk országaiban bevezették a tervgazdaságot, a nyugati blokk országaiban fennmaradt vagy helyreállították a piacgazdaságot. Keleten a termelést és a fogyasztást is megtervezték, Nyugaton ezt a piaci verseny alakította; a tervgazdaság merevsége gazdasági lemaradáshoz vezetett. A nyugati piacgazdaság biztosította a technikai, gazdasági fejlődést. A tervgazdaságokban az állami tulajdon vált uralkodóvá, a piacgazdaságokban a magántulajdon maradt az.\n\n1953-tól a Sztálin halála utáni enyhülés történt, de a tüntetések, forradalmak leveréséhez katonai beavatkozásra volt szükség (1953, NDK; 1956, Lengyelország, Magyarország; 1968, Csehszlovákia). Egy ország kilépése a szovjet blokkból megengedhetetlen volt.\n\nA keleti (SZU) és nyugati (USA) tömb fegyverkezési versenybe kezdett, de mindig egy 3. országban csaptak össze. Korea a háború előtt japán gyarmat volt, a világháború után az északi része szovjet, a déli része amerikai befolyás alá került. 1950-53 között háború robbant ki a két állam között Korea területén, de Sztálin 1953-as halála miatt befejeződtek. A két nagyhatalom befolyását jelzi a szuezi válság megoldása 1956-ban: Anglia és Franciaország el kell, hogy hagyja a térséget, hiszen az erősebb jogán a két nagyhatalom beavatkozott az egyiptomi-izraeli konfliktusba. 1962-ben a karibi válság során veszélyhelyzetbe kerül az USA. A szovjetek nukleáris rakétákat telepítettek Kubába, melyek az USA elpusztítására képesek lettek volna. Válaszul Kennedy elnök blokádot rendelt el a Karib-tengeren. A harckészültség után végül is kompromisszum született: Szovjetunió visszavonta rakétáit Kubából. Aki a nukleáris fegyvert elsőként beveti, másodikként hal meg. 1964-73. az USA a vietnámi háborúban vesz részt, melyet háborúellenes tiltakozások miatt kell feladnia. 1979-től Afganisztánban ütközik össze a Szovjetunióval. A fegyverkezési versenyben az USA kerül ki győztesen, az 1980-as években Ronald Reagen elnök meghirdeti a csillagháborús fegyverkezési versenyt, amit a SZU nem tud követni. A keleti blokk országaiban a gazdasági összeomlásnak és Gorbacsov reformpolitikájának köszönhetően 1989-ben a kommunista pártok hatalmának megdöntésére került sor. 1991-ben Szovjetunió felbomlott. Az USA jelenleg is a világ vezető hatalma.\n\nA hidegháborúról másképpen\n\nA II. világháborút követően az Atlanti Charta felbomlásával fokozatosan egymás ellen fordult az Amerikai Egyesült Államok és a Szovjetunió. A két szuperhatalom és szövetséges rendszereik kiépülése nyomán két pólusra szakadt a nemzetközi politikai színtér (ún. bipoláris rendszer). A rendszer sajátos irányítója a „zéró összegű játszma”elve (az egyik fél nyeresége egyben a másik fel veszteségét is jelenti) és az atomfegyverek birtoklását megalapozó kölcsönös elrettentés doktrínája volt.\n\nA szakítás folyamata\n\nA négy szövetséges hatalom (Nagy-Britannia, USA, Franciaország, Szovjetunió) egyszerre szállta meg a vesztes Németországot 1948-ra a francia, a brit és az amerikai zóna egyesült, Trizónia néven. Az USA ugyanebben az évben a londoni konferencián kezdeményezte, hogy a több milliárd dolláros, vissza nem térítendő támogatást jelentő, 1947-ben induló Marshall-segélyt terjesszék ki Németországra is. A segély egyetlen feltétele a többpártrendszer megtartása volt. Ez a tervezet feszültséghez vezetett a Szovjetunióval.\n\nAz első komoly háborús veszély szintén 1948-ban következett be, amikor a Trizóniában bevezették az új német márkát. Válaszként a szovjetek blokád alá vették Nyugat-Berlint, amit azonban a szövetséges légihíd megtört. A krízis elülte után, 1949-ben megalakult a Kölcsönös Gazdasági Segítségnyújtás Tanácsa (KGST), amivel a szovjetek a Marshall-tervet igyekeztek ellensúlyozni. 1949 májusában megalakult a Német Szövetségi Köztársaság Bonn, míg októberben a Német Demokratikus Köztársaság Kelet-Berlin fővárossal. Az USA megalapította a Központi Hírszerző Ügynökséget (Central Intelligence Agency, CIA), majd 1949. április 4-én Washingtonban az Észak-atlanti Szerződés Szervezetét (North Atlantic Treaty Organisation, NATO), 12 alapító taggal. A katonai-biztonsági szervezet Szerződésének V cikkelye szerint az egyik tagállamot ért támadás az összes tagállamot ért támadásnak minősül.\n\nAz 1950-es, \'60-as évek\n\nA világ számos területén a két szuperhatalom közvetett módon (harmadik felek bevonásával) harcolt egymással, mint például a koreai (1950-53), az első és második indokínai/vietnámi háborúban (1959-75) vagy Guatemalában.\n\nKOREAI HÁBORÚ\n\nKorea a háború előtt japán gyarmat volt, a világháború után az északi része szovjet, a déli része amerikai befolyás alá került a 38 szélességi fok mentén. Kína és a Szovjetunió az északi kommunista államot támogatta. 1950-53 között háború robbant ki a két állam között Korea területén, de Sztálin 1953-as halála miatt befejeződtek.\n\nCsak tűzszünetet kötött egymással a két Korea Panmindzsonban 1953-ban.\n\nCsak 2018. április 27-én sikerült megegyeznie a két Koreának: Kim Jong-un és Moon Jae-in koreai vezetők történelmi csúcstalálkozót tartottak, formálisan is befejezték így ezzel a koreai háborút.\n\nAz USA létrehozta az un. COCOM-listát, amelyben felsorolta azokat a termékeket, amelyeket tilos volt a Szovjetuniónak vagy csatlósállamainak eladni. 1953-ban fordulat állt be a világpolitikában Sztálin halálával: utódja, Nyikita Hruscsov békülékenyebb politikát folytatott. Az európai kettészakadás azonban nem állt meg. 1955-ben felvették az NSZK-t a NATO-ba; válaszul a szovjetek létrehozták a Varsói Szerződést. Európa katonailag is kettévált. 1956-ban a Szovjet Kommunista Párt XX. kongresszusán a pártfőtitkár Hruscsov szakított a sztálini terrorral, és elítélte a személyi kultuszt. A fellángoló 1956-os kelet-európai (poznani, magyarországi) forradalmakat azonban leverték. 1958-ban az NDK pártfőtitkára javasolta, hogy egész Berlin csatlakozzon a keleti blokkhoz. Ebből kifolyólag találkozott Eisenhower amerikai elnök és Hruscsov az USA-ban.\n\nKözben egy kubai forradalmár, Fidel Castro elűzte Batista tábornokot, és Kubában kommunista rendszert vezetett be, alig pár száz kilométerre az amerikai partoktól. A hidegháború logikájából fakadóan erre az USA-nak ellenlépést kellett tennie. 1961-ben a CIA egy kubai menekültekből álló alakulatot vetett be a Disznó-öbölben Fidel Castro likvidálására, de az akció sikertelen volt. A Szovjetunió elhatározta, hogy atomrakétákat telepít a karibi államba, de miután ez kiderült, Kennedy elnök hadihajókat küldött a térségbe. A helyzet atomháború kitörésével fenyegetett, Magyarországon megindult a sorozás. Hruscsov végül visszalépett, és a két vezető egyezséget kötött, amelynek értelmében a kubai rakéták leszerelésével egyetemben az USA is kivonta rakétáit Törökországból. Berlin eközben végleg kettévált, 1961. augusztus 13-án pedig megkezdődött a berlini fal építése.\n\nA vietnámi háború\n\nA vietnámi háború az 1960-as, ’70-es években, 1964–1973 között zajlott. A háború során Észak- és Dél-Vietnám harcolt egymással.\n\nA vietnámi háború kitörése: a korábbi genfi egyezmény nem valósult meg, az északi kommunisták megtámadták a déli országrészt. Az északi csapatok amerikai hajókat is megtámadtak. Az amerikai hadsereg nyíltan beavatkozott a déliek oldalán, az északiakat a szovjetek támogatták. A Truman-elv vagy dominóelv, azaz a feltartóztatási politika értelmében lépett fel az Egyesült Államok. A hidegháború jellemzője volt a szuperhatalmak beavatkozása egy regionális válságba, az északiakat a szovjetek, illetve a délieket az amerikaiak támogatták a háborúban.\n\nA háború hatalmas veszteségekkel járt, az amerikai csapatok nem tudtak igazi győzelmeket aratni. Kennedy szerint az amerikai csapatoknak Vietnámban kell maradniuk, ugyanis az amerikaiak a kommunista kínai befolyás növekedésétől tartottak. Az amerikai vereségek hozzájárultak a hippi mozgalmak kialakulásához. Az amerikai közvélemény is ellenezte a háborút, hiszen a háború súlyos amerikai veszteségekkel járt. A világ közvéleménye is elítélte az amerikai beavatkozást. A sajtó híradásai gyengítették a háborús hangulatot, rendszeressé váltak a háborúellenes tüntetések. A háborúellenesség az diáklázadások összetartó ereje lett, a közvélemény nyomása hozzájárult a háború befejezéséhez.\n\nAz északiak gerillataktikája sikeresnek bizonyult. A vietnámi háború az északiak, azaz a kommunisták győzelmével ért véget. Az amerikai csapatokat ki kellett vonni Dél-Vietnámból. Az amerikaiak távozása után egész Vietnám kommunista országgá vált, a két pólusú világban a szovjet tömbhöz csatlakozott. Az amerikai vereségek enyhülést eredményeztek a hidegháborúban.\n\nAz enyhülés időszaka (1969-1975)\n\nAZ ÚJ KELETI POLITIKA\n\nEgyre nyilvánvalóbbá vált, hogy Európa megosztottságát a Nyugat nem tudja felszámolni, ugyanakkor a szovjet politika Európában nem kívánt további előretörést, ezért az enyhülés részeként a német kérdést is újragondolták. Az „új keleti politika” vagy „reálpolitika” az újjászülető német szociáldemokráciához és a párt vezetőjének, Willy Brandtnak a nevéhez kötődik. A kancellári széket 1969-ban elnyerő Brandt elfogadtatta politikáját a közvéleménnyel, s megkötötte a német-szovjet, majd a német-lengyel szerződést (1970), amelyben elismerték az új német határokat (a sokat vitatott keleti, Odera-Neisse folyóknál húzódó határt is). Az új keleti politika eredményeként 1971-ben létrejöhetett a Nyugat-Berlinre vonatkozó négyhatalmi megegyezés. Ebben rögzítették a város különleges helyzetét, a Szovjetunió pedig vállalta, hogy biztosítja a városrészhez vezető utak zavartalanságát. Rövidesen rendezték - a fennálló helyzet alapján - a két német állam viszonyát (1972), s a következő évben mindkét országot felvették az ENSZ-be. A német kérdés rendezése jelentősen hozzájárult az európai stabilitás és biztonság megerősödéséhez.\n\nAz események tehát ismét Németországból indultak ki, ahol Willy Brandt, az NSZK kancellárja elismerte az NDK-t és a határok sérthetetlenségét, de nem mondott le a két német állam jövőbeni egyesítéséről. A kommunisták is belátták, hogy gazdasági okokból nélkülözhetetlen a Nyugattal való kapcsolattartás. Ehhez hozzájárult az a tény, hogy a \'70-es évekre a keleti államok elindultak az eladósodás útján.\n\nHenry Kissinger, az USA kiemelkedő külpolitikusa úgy vélte, hogy katonailag szükséges az USA és a Szovjetunió hegemóniája, de politikailag új elemek is kellenek a rendszerbe, így tárgyalásokba kezdett Kínával, majd a korszak végére a kétpólusú berendezkedés kezdett fellazulni, az Európai Közösség és Japán is megjelent a nemzetközi színtéren. Gazdasági multipolaritás (többpólusú rendszer) alakult ki. Kissinger véleménye szerint a Szovjetuniót gazdaságilag kellett összeroppantani, ezért kellett bevonni őket is a világgazdaságba, amivel eladósíthatták a kommunista államokat. Ennek érdekében kezdődött meg többek között a hűtőszekrények exportja a Szovjetunióba.\n\nA fegyverkezési verseny 1972-ben tört meg a SALT-1 tárgyalások révén. Csökkentették a hadiarzenált, kölcsönös ellenőrzési jogot biztosítottak egymás számára. A folyamat tetőpontja 1975-ben következett be Helsinkiben, az Európai Biztonsági és Együttműködési Értekezleten (EBEÉ), ahol a záróokmányt 33 európai ország (köztük hazánk), az USA és Kanada írta alá. A dokumentumban tíz alapelvet fogalmaztak meg, többek között a határok sérthetetlenségét, a tartózkodást az erőszaktól, az emberi jogok tiszteletben tartását, valamint a népek önrendelkezési jogát. Olyan rendelkezéseket is tartalmazott az egyezmény, amelyek a szocialista államok fennmaradását szavatolták. Az egyezményt nem tartották be, de az új fegyverkezési hullámot a Szovjetunió nem bírta.\n\nA „kis” hidegháború\n\nA \'80-as évekre a keleti pólus meggyengült. Az afganisztáni háborúban (1979-89) a Szovjetunió katonailag megroppant. Ekkor az USA hivatalban lévő elnöke, Ronald Reagan új fegyverkezési programot hirdetett meg, növelte a hadi kiadásokat. Ennek része volt az 1983-ban meghirdetett csillagháborús terv, amelynek részeként olyan műholdas védőernyő létrehozását tervezték, amellyel az űrből képesek lettek volna a szovjet rakéták semlegesítésére.\n\nA Szovjetunió nem tudott lépést tartani, így az 1985-től új főtitkár, Mihail Gorbacsov reformokat vezetett be. Politikáját a glasznoszty (nyíltság) és a peresztrojka (átalakítás) határozta meg. Nem kívánta megváltoztatni a teljes politikai struktúrát, de a gazdasági lemaradás magával hozta a változtatás kényszerét a társadalmi és a politikai vezetés szintjén. 1985-ben Genf városában leszerelési tárgyalásokba kezdett, majd visszavonta a Brezsnyev-doktrínát. 1989. november 9-én leomlott a berlini fal. A változást érzékeltette, hogy Gorbacsov nem vetette be a Vörös Hadsereget sem a berlini, sem a magyar, a lengyel vagy a román rendszerváltás eseményeit látva. 1990 őszén neki ítélték Oslóban a Béke Nobel-díjat. A szovjet hadsereg mindenhonnan kivonult. 1991 decemberében megszűnt a Szovjetunió. Az újonnan létrejövő Oroszország elnöke Borisz Jelcin lett. A reform szükséges volt, azonban a kommunizmus nem bírta a változást, így felbomlott a rendszer.\n\nA szovjet blokk és rendszerváltozás Kelet-Közép-Európában\n\nA II. világháború végén a szövetségesek kialakították saját befolyási zónáikat, ám amíg a nyugati hatalmak az államok szabad önrendelkezését figyelembe vették, addig a „vasfüggöny” keleti oldalán húzódó országok (Magyarország, Lengyelország, NDK, Csehszlovákia, Bulgária, Románia) a Szovjetunió befolyása alá kerültek. Ezeket az országokat 1949-től gazdaságilag a Kölcsönös Gazdasági Segítség Tanácsa (KGST), katonailag 1955-től a Varsói Szerződés fogta össze.\n\nA keleti blokkon belül a Szovjetunió és azon belül is a Szovjet Kommunista Párt (SZKP) dominanciája érvényesült. A szovjet blokk országai nem önszántukból léptek a „szocializmus útjára”. A Szovjetunió második világháború végén nemcsak felszabadította a német uralom alól, hanem egyben meg is szállta a kelet-közép-európai országokat. A SZU fő eszköze az országokban állomásozó szovjet katonaság, a Kominform, a helyi párt és a karhatalmi szervek voltak. A szovjet pártfőtitkárok vezetési stílusa meghatározta a többi tagország politikai irányvonalát és mozgásterét.\n\n1953-tól a Sztálin halála utáni enyhülés sok „baráti országban” további engedményeket, a felszabadulás reményét keltette. A tüntetések, forradalmak leveréséhez többször katonai beavatkozásra volt szükség (1953, NDK; 1956, Magyarország; 1968, Csehszlovákia). Egy ország kilépése a szovjet blokkból stratégiai és ideológiai okok miatt is megengedhetetlen volt. A KGST sikertelensége, az európai integrációból való kirekesztés, a tervutasításos rendszer szerkezete, az ésszerűtlen iparosítás és az olajárrobbanások együttesen vezettek a keleti blokk országainak eladósodásához. A gazdasági összeomlásnak és Gorbacsov reformpolitikájának köszönhetően az országok többségében változást követelő ellenzéki csoportok jelentek meg.\n\n1989-ben a szovjet blokk országaiban a kommunista pártok hatalmának megdöntésére került sor. Lengyelországban a tömegtüntetések, addig Magyarországon kerekasztal-tárgyalások vezettek a hatalom megosztásához. Csehszlovákiában a „bársonyos forradalom”, az NDK-ban a Lipcsében rendezett hétfői tüntetések és a határok megnyitása, Romániában pedig véres forradalom, Ceaucescu erőszakos eltávolítása vezetett az új rendszer kiépítéséhez. A rendszerváltások minden országban másképpen mentek végbe, általános jellemzőként említhető az országon belüli ellenzék nyomása, valamint a külső támogatás hiánya. A katonai beavatkozás elmaradásában nagy szerepe volt az 1985-ben hatalomra került Gorbacsov reformpolitikájának és az amerikai-szovjet tárgyalásoknak is (pl. Máltai csúcstalálkozó). Az 1989-es év lehetőséget adott az országoknak, hogy a demokratikus államberendezkedés és a szociális piacgazdaság kiépítésével saját útjukra léphessenek.\n\nA szocialista világrendszer 1980-as években omlott össze: a kelet- és közép-európai szocialista országok és a Szovjetunió.\n\nA tönkrement szocialista rendszerek hibái: a perspektívátlanság, kiszolgáltatottság, a szocialista rendszerek eladósodása, gazdasági válsága. Csak a nyugati piacgazdaságoktól remélhettek újabb gazdasági támogatást, kölcsönt. A szocializmus összeomlásához vezető okok: a pártállami diktatúrák válsága, reformképtelensége, az egypárti politikai rendszer és a tervgazdálkodás merevsége. A szocialista rendszerek teljesíthetetlen célokat tűztek ki maguk elé: a fegyverkezési versenyt, a piaci viszonyok felszámolását, az életszínvonal folyamatos növelését. A XX. század végére a kapitalista világrendszer fölénybe került, a Nyugat megnyerte a fegyverkezési versenyt, gazdasági hatékonysága kiterjedt a technológiai megújulás készségére, az életszínvonal (fogyasztás) folyamatos növelésére.\n\nA szovjet blokk létrejöttétől a felbomlásig\n\nA II. világháború után Kelet-Közép-Európa a Szovjetunió érdekszférájába került.\n\n• A kommunista pártok hatalomátvételének, az egypárti diktatúra létrehozásának hasonlóságai:\n\nElőször „koalíciós időszak” (Csehországban közel 3 év, 1948. februárig; Magyarországon 2,5 év, 1947. májusig; Romániában 6 hónap, 1945. márciusig; Bulgáriában 4 hónap, 1945 januárig tartott ez az időszak - Lengyelországban és Jugoszláviában nem volt koalíció):\n\nszovjetbarát kormányok létrehozása, erős kommunista pozíciókkal (segítette őket a Vörös Hadsereg jelenléte, a szovjet vezetésű SZEB: Szövetséges Ellenőrző Bizottság);\n\nállamosításokkal és földreformmal tönkretették a polgári erők gazdasági bázisát;\n\na „fasisztákkal” való leszámolás jegyében sok nem szélsőjobboldali politikust, hivatalnokot kiszorítottak a politikából és a közigazgatásból;\n\na választásokon listás szavazásokra került sor, a kommunisták demokratikus pártokkal közösen indultak, így legitimálták magukat, illetve elfedték tényleges (alacsony) társadalmi támogatottságukat.\n\nEzt követően „álkoalíciós időszak”:\n\nformálisan még működött a pártok kormányzati szövetsége, gyakorlatilag azonban már a kommunisták irányítottak minden jelentősebb területet.\n\nA monolitikus egypárti diktatúra kialakítása:\n\nlétrejött a munkáspártok egysége, azaz egyesült a szociáldemokrata és a kommunista párt;\n\nfelszámolták a többpártrendszert, üldözni kezdték a polgári politikusokat, az egyházi vezetőket; az állampárton belül is tisztogatásokat hajtottak végre (koncepciós perek).\n\n• A szocialista országok kezdetben utánozták a sztálini modellt:\n\n• külsőségek: egyenruha, ünnepségek, intézmények, orosz nyelv;\n\n• lényegi vonások: egypártrendszer, személyi kultusz, tervgazdálkodás, erőltetett iparosítás, a mezőgazdaság kollektivizálása. A keleti blokk politikai, gazdasági, katonai szervezettsége:\n\n• 1947: Kominform megalakítása\n\n• 1949: KGST megalakítása\n\n• 1955: Varsói Szerződés megalakítása\n\nTito Jugoszláviájának kiközösítése, mert nem rendelte alá magát és országát a Szovjetuniónak. A Sztálin halála utáni desztalinizálási hullámot követően Albánia (Enver Hodzsa) külön útra lépett. 1980-as években Románia (Ceausescu) külön útja.\n\nElszakadási kísérletek:\n\n1953: Kelet-Berlinben szovjet-ellenes felkelés\n\n1956: poznani felkelés Lengyelországban és a magyarországi 56-os forradalom\n\n1968: prágai tavasz\n\n1981: rendkívüli állapot Lengyelországban (Szolidaritás)\n\nRendszerváltozás a szocialista országokban:\n\n• A szocialista országok a sokszor hangoztatott jelszóval (beérik, sőt lehagyják a nyugati országokat) szemben egyre inkább lemaradtak. Ennek okai:\n\n• a tervgazdálkodás rugalmatlansága, piaci viszonyok figyelmen kívül hagyása;\n\n• szervezetlenség, alacsony munkamorál;\n\n• állandó áruhiány, illetve anyag- és energiapazarlás egyidejű jelenléte a mennyiségi szemléletből következően;\n\n• lemaradás a technikai versenyben: hiába fedezték fel a szovjetek és az amerikaiak egyszerre a lézert, de a lézeres gyógyítást és a lézernyomtatót az amerikaiak fejlesztették ki;\n\n• hatalmas környezetszennyezés;\n\n• rosszabb életminőség, agyonhajszolt emberek, alacsonyabb várható élettartam.\n\n• Lengyelországban 1980-ban országos sztrájkmozgalom kezdődött, amelynek eredményeként megalakulhatott a szocialista világ első független szakszervezete, a Szolidaritás, élén Lech Walesával. A Szolidaritásnak fénykorában 10 millió tagja volt, és a lengyel katolikus egyház mellett a párt új vetélytársává vált. 1981-ben Jaruzelski tábornok katonai szükségállapotot vezetett be: több ezer embert internáltak, a kulcspozíciókat katonák foglalták el, de a Szolidaritást nem sikerült felszámolni.\n\nCsehszlovákia: Charta 77 ellenzéki mozgalom.\n\nSzovjetunióban ellenzéki személyiségek: Szaharov, Szolzsenyicin\n\n• Mihail Gorbacsov, az SZKP főtitkára (1985-91) által elindított reformok:\n\n„nyíltság” (glasznoszty): a hibák nyílt feltárása, a szabadságjogok óvatos megvalósítása;\n\n„átalakítás” (peresztrojka): a gazdaság és a társadalom modernizálása;\n\n„gyorsítás” (uszkorenyije): a gazdasági fejlődés felgyorsítása.\n\n• A reformok során a „nyíltság” területén értek el eredményeket, de ez együtt járt azzal, hogy a lakosság „hivatalosan” is értesült a kommunista rendszer bűneiről; az „átalakítás” ténylegesen a piaci viszonyok elterjesztésével volt csak elérhető, amely azonban aláásta a „szocialista gazdaság alapjait”; a „gyorsítás” pedig végül a SzU széteséséhez vezetett.\n\n1988-89-ben indult el a szocialista országokban a rendszerváltozás.\n\n• Felerősödtek az ellenzéki mozgalmak.\n\n• A változások élén Lengyelország és Magyarország haladt: „tárgyalásos forradalmak” zajlottak le, ahol az állampárt és az ellenzék megállapodott az átmenetben.\n\n• Csehszlovákia: „bársonyos forradalom” - ez is vértelen volt (Waclav Havel és Alexander Dubcek voltak a szimbolikus alakjai).\n\n• Románia: 1989 karácsonyán a televízió által is közvetített véres forradalom döntötte meg a Ceausescu-rendszert.\n\n• NDK: az 1989. szeptemberi magyarországi határnyitás után (az NDK-s menekülteket Magyarország kiengedte Ausztriába) szétesett az állami vezetés, novemberben leomlott a berlini fal.\n\n• 1990-ben valamennyi kelet-közép-európai szocialista országban többpárti választásokat tartottak.\n\nA közép-európai régió sajátos problémái:\n\nPolitika: meg kell szilárdulnia a demokratikus rendszernek (általában két választási ciklus, kb. 8 év).\n\n• Meg kell tanulni a demokráciát működtetni.\n\n• Vége lett a szovjet államszerepnek, fel kell oldódnia az állampolgári passzivitásnak.\n\n• Gazdaság:\n\n• Megszűnt a KGST zárt és biztos piaca, a vállalatoknak a világpiacon kell versenyezniük.\n\n• Az átalakulás: megnövekedett munkanélküliséget, gazdasági visszaesést, fokozódó társadalmi különbségeket hozott magával.\n\n• Több ország komoly mértékben eladósodott.\n\n• Mindmáig jellemző a tőkehiány, amin a külföldi tőkebefektetések enyhítenek.\n\n• Gyengén fejlett az infrastruktúra (pl. úthálózat).\n\n• Jelentős környezeti károk maradtak a szocialista korszakból pl. 1984. Csernobil.\n\n• A soknemzetiségű államok felbomlottak, és új államok jöttek létre:\n\n• 1990-től háborúba torkollott Jugoszlávia szétesése;\n\n• 1991: felbomlott a Szovjetunió;\n\n• 1993. jan. 1-től békésen kettévált Csehszlovákia.\n\n1990-ben egyesült az egykori NSZK és NDK: Németország lett.\n\nKövetkezmények:\n\n• Megnövekedett a térség államainak, önálló gazdasági-politikai egységeinek a száma. Számos ország geopolitikai helyzete megváltozott. (Pl. Magyarország egy közép-európai kisállamból egy közepes méretű állammá lett.)\n\n• Az új, szuverén „nemzetállamok” kialakulásának elkerülhetetlen és szükséges folyamata alapozhatta meg az önkéntességen alapuló európai integráció kiterjedését térségünkre. A térségben továbbra is nagyon jelentős a kisebbségek száma és aránya.\n\nA közép-európai országok rendszerváltozás utáni céljai: EU és NATO-tagság. A NATO tagság általában megelőzte az EU tagság elérését. A térség volt szocialista országai közül:\n\n• Lengyelország, Csehország, Szlovákia, Szlovénia és Magyarország 2004-től tagja az Európai Uniónak.\n\n• Románia, Bulgária pedig 2007-től, Horvátország 2013-tól vált EU taggá.\n\n• Kérdésesek:\n\na jugoszláv utódállamok: Szerbia, Montenegró, Horvátország, Bosznia, Szlovénia\n\na SZU utódállamainak jövője.\n\nA német kérdés\n\nNémetország számára, az 1945-ben kötött feltétel nélküli fegyverszünet nem csak a II. világháború végét, hanem az ország megszállásának kezdetét is jelentette.\n\nA szövetséges hatalmak a nácik likvidálásában, az 1945-ös jaltai konferencia értelmében befolyási zónák kialakításában és ellenőrzésében egyetértettek. Németország nyugati részén angol, francia és amerikai zónák jöttek létre, az Elbától keletre pedig szovjet zóna. A megszállási övezetekre osztott Berlin, Németország fővárosa a két Németország kialakulásával párhuzamosan szintén megosztott maradt. A győztes hatalmak négy megszállási övezetre osztották fel Berlint és Németországot is.\n\nA hidegháborús évek kezdetével azonban a terület folyamatos konfliktusok helyszínévé vált. Először az angol és amerikai megszállási övezetek egyesültek gazdaságilag – Bizónia -, majd a francia zóna is csatlakozott ehhez: Trizónia. 1948-ban a német kérdés rendezésére összehívott londoni konferenciára a szovjeteket nem hívták meg. 1848 júniusában a nyugati zónában pénzreformot vezettek be. Tiltakozásul 1948-ban Sztálin utasítására a Szovjetunió Nyugat-Berlint blokád alá vonta (reakcióként arra, hogy a nyugati hatalmak bevezették a nyugatnémet márkát, és attól tartva, hogy egykori szövetségesei egész Németországot a befolyásuk alá vonják), amit a nyugati hatalmak „légihíd” segítségével hidaltak át. Nyugat-Berlin kérdése stratégiai kérdéssé vált a hidegháború időszakában.\n\nA győztes hatalmak a II. világháború után nem tudtak megegyezni Németország sorsáról, a köztük lévő politikai-ideológiai ellentétek két különálló állam megalakításához vezettek, és ez a megosztottság egészen 1990-ig maradt fenn. Ez a megosztottság 1949-re két német állam (NDK, NSZK) megalakulásához vezetett. Berlin angolok, franciák és amerikaiak által megszállt övezetei szorosan a létrejövő NSZK-hoz kapcsolódtak (Nyugat-Berlin), keleti szovjet zónájából pedig az NDK fővárosa (Berlin) lett.\n\n1949-ben a pártfőtitkár a blokád felszámolásáról döntött, de Németország még ebben az évben kettészakadt. Ez egyben a két világrend kettészakadását is jelképezte. Megalakult 1949. május 23-án Trizóniából a Német Szövetségi Köztársaság (NSZK) és szovjet befolyás alatt 1949. október 7-én a Német Demokratikus Köztársaság (NDK).\n\nAz NDK alkotmánya formálisan elismeri az emberi jogokat; demokráciára hivatkozva korlátozza a politikai véleménynyilvánítást. Az NSZK alaptörvénye elismeri és védi az emberi jogokat; a felvilágosodás örökségéhez kötődik. Az emberi jogok a valóságban csak Nyugaton érvényesültek. Keleten a valóságban korlátozták az emberi jogokat – az elnyomás, az imperializmus elleni harcra hivatkozva.\n\nSztálin halála után, 1953-ban keletnémet felkelés tört ki, amit a szovjetek csak tankokkal tudtak leverni. 1955-ben az osztrák államszerződés és az NSZK NATO csatlakozására válaszul a Szovjetunió létrehozta saját katonai tömbjét, a Varsói Szerződést. Berlin végleges kettéosztását az 1961. augusztus 13-án épített berlini fal jelentette.\n\nA falat az NDK állama és a szovjet katonák húzták fel. A fal kettéválasztotta a két különböző államhoz tartozó városrészeket, minderre ideológiai és gazdasági okokból volt szükség, pl. a menekültáradat megállítására. Az amerikai elnök az NSZK és Nyugat-Berlin melletti amerikai kiállást demonstrálta, ezzel egyben a szabadság ideológiáját is hirdette a fallal körülvett városban. A falat tehát gazdasági-politikai és migrációs okok miatt építették. A fal a kelet-nyugati megosztottság (a kétpólusú világ) szimbólumává vált. De nemcsak két világrendszert, hanem egy népet, és egy korábban szerves egységben élő várost is kettéosztott.\n\nAz NSZK és az NDK között megalakulásuk óta jelentős különbségek voltak. Az NSZK az 1947-ben nyújtott amerikai Marshall-segélynek és az európai integrációnak köszönhetően óriási gazdasági fejlődésen ment keresztül, Konrád Adenauer nyugatnémet kancellár pedig komoly külpolitikai sikereket ért el. Az NDK a keleti blokk és a KGST tagjaként kevés politikai, ill. gazdasági mozgástérrel rendelkezett. Az enyhülés érdekében Willy Brandt kancellár „új keleti politikát”- hirdetett. 1970-ben a szovjetekkel kötött szerződést a nyugatnémet-lengyel határ elismerése követte. 1972-ben NSZK-NDK megegyezésére került sor, ennek hatására 1973-ban mindkét állam csatlakozhatott az ENSZ-hez.\n\nMihail Gorbacsov hatalomra jutása (1985) után a két német államnak egyre több lehetősége adódott a kapcsolatok szorosabbá tételére. 1989-ben Helmut Kohl és Gorbacsov a be nem avatkozás mellett döntöttek, így miután 1989-ban több határátkelőt megnyitottak, a folyamatok megállíthatatlannak tűntek. 1989. november 9-én elkezdődött a berlini fal lebontása. Demonstrációk sorozata után, 1990. október 3-án szerződés keretében a két országrészt újraegyesítették.\n\nÖSSZEGZÉS:\n\nA hidegháború két szuperhatalom, az USA és a szovjetunió (SZU) között jött létre 1945 után. A második világháború végén 1945 májusában megtörtént a szövetségesek elbai kézfogása, azaz a szovjet és angol-amerikai csapatok találkozása, melyek nyugat-keleti irányból támadtak Németországra, s annak teljes legyőzéséig együttműködtek. Az 1943-ban Teheránban, 1945-ben Jaltában, majd Potsdamban tartott konferencián a szövetségesek a háborúval kapcsolatos megbeszéléseken kívül a háború utáni kérdéssel is foglakoztak, s Jaltában érdekszférákra osztották fel Európát. A szovjetek által felszabadított területeken a Szovjetunió, a nyugati részen angol, amerikai és francia befolyás érvényesült. 1945. augusztus 6-án és 9-én Hirosimára és Nagasakira atombombát dobtak az amerikaiak, ezzel megtörték a japánok ellenállását, akik 1945. szeptember 2-án kapituláltak, s ezzel véget ért a 2. világháború. A háborút követően az USA sokat nyerő győztesként szerepel, s az atombomba birtokában a világ vezető hatalmává vált. Ezt majd az űrrakéták és a műholdas védelmi rendszer fogja felülmúlni (1981). A SZU is igyekezett atombombát létrehozni 1946-ban. A hidegháború kezdete: 1947, a 2. világháborút lezáró párizsi békék után.\n\nAZ INTEGRÁCIÓ ÉS A HIDEGHÁBORÚ: a háborút követően a szövetséges hatalmak útjai szétváltak, a Szovjetunió Közép- és Kelet-Európában és Délkelet-Ázsiában éreztette befolyását, és célja a szocialista világrendszer kiépítése volt. Az USA a tőkés világ vezető hatalma lett. Az angol Churchill fogalmazta meg 1946-ban a fultoni beszédében, hogy a világ kettészakadt, s közötte vasfüggöny húzódik, ennek a másik oldalán áll a kommunista vezetésű Szovjetunió és érdekszférája. Truman amerikai elnök kidolgozta politikai koncepcióját 1947-ben: az USA vezető szerepet vállal, és támogatni fogja a kommunizmus ellen fellépő országokat. 1947-ben gazdasági téren is segítséget nyújtott a nyugati tömbhöz csatlakozó európai országoknak, ez volt a Marshall-segély. Célja a piac bővítése és megtartása az USA számára, az európai demokráciák stabilizálása, az USA gazdasági és politikai hatalmának erősítése. 1949-ben katonai szervezetet hoznak étre, a NATO-t, ez az Észak-atlanti Szerződés Szervezetét, hogy megakadályozza a SZU uralmának további kiterjedését.\n\nA II. világháború végén a szövetségesek kialakították saját befolyási zónáikat, ám amíg a nyugati hatalmak az államok szabad önrendelkezését figyelembe vették, addig a „vasfüggöny” keleti oldalán húzódó országok (Magyarország, Lengyelország, NDK, Csehszlovákia, Bulgária, Románia) a Szovjetunió befolyása alá kerültek. A Szovjetunió második világháború végén nemcsak felszabadította a német uralom alól, hanem egyben meg is szállta a kelet-közép-európai országokat. A SZU fő eszköze az országokban állomásozó szovjet katonaság, a Kominform, a helyi párt és a karhatalmi szervek voltak. Ezeket az országokat 1949-től gazdaságilag a Kölcsönös Gazdasági Segítség Tanácsa (KGST), katonailag 1955-től a Varsói Szerződés fogta össze. 1953-tól a Sztálin halála utáni enyhülés történt, de a tüntetések, forradalmak leveréséhez katonai beavatkozásra volt szükség (1953, NDK; 1956, Magyarország; 1968, Csehszlovákia). Egy ország kilépése a szovjet blokkból megengedhetetlen volt.\n\nA keleti tömb gazdaságpolitikája\n\nIPAR: ÁLLAMOSÍTÁSOK, TERVGAZDÁLKODÁS, A NEHÉZIPAR FEJLESZTÉSE\n\nAz erőltetett iparosítás mellett szovjet mintára és felsőbb rendelkezésre tervutasításos rendszer jön létre. A nehézipart államosítják, fejlesztik, ennek célja a szovjet fegyverkezési versenyhez szükséges nyersanyagok biztosítása. Az ipar tehát szocialista jellegű átalakításon megy végbe. Létrejön az állami tulajdon túlsúlya. Az üzemek élére nem szakmailag, hanem politikailag megbízható embereket állítottak. Nem a minőségre, hanem a mennyiségre törekedtek a termelés során. Az országok gazdasági sajátosságait nem veszik figyelembe, a nehézipart tehát egyoldalúan fejlesztik szovjet mintára, katonai célokból. A hidegháború légkörében a hadsereg megerősítésére volt szükség, ezért kellett a nehézipart fejleszteni, ezért több hadiüzem épült. A túlzott iparosítás következtében csökkent az életszínvonal, s a szolgáltatások színvonala. A fogyasztási cikkek, a könnyűipari termékek mennyisége, minősége elmaradt a lakossági igényektől. A keleti tömb országaiban, 1949-ben megalakult KGST, a Kölcsönös Gazdasági Segítség Tanácsa. Ez a szocialista országok kereskedelmét hangolta össze, de főleg a Szovjetunió kiszolgálói lettek. 1947-ben szovjet nyomásra elutasították a nyugati tömbből érkező amerikai segélyt, a Marshall-segélyt, ez gazdasági téren is integrálódást jelentett Magyarország számára. A nyugati tömb országainak gazdaságára kapitalizmus, míg a keleti tömbben szocializmus volt jellemző.\n\nMEZŐGAZDASÁG: KOLLEKTIVIZÁLÁS, KULÁKÜLDÖZÉS, VISSZAFEJLŐDÉS\n\nSzovjet mintára megindul a kollektivizálás, azaz a földek közös tulajdonba kerülnek. Erőszakos szövetkezetesítési program indul, a földek állami tulajdonba kerülnek. Kötelező beszolgáltatási rendszert vezetnek be, s aki nem teljesíti, azt szabotálónak tartják, s börtönbe, munkatáborba kerülhet. A gazdag parasztokat, azaz a kulákokat üldözik, megbélyegzik, arra kényszerítik őket, hogy földjeiket állami tulajdonba adják. Adózással, zaklatással, perekkel felszámolták az árutermelő középparasztságot. A Kádár-rendszer idején (1956-1989) Magyarországon viszonylag magasabb volt az életszínvonal a keleti tömb országaihoz képest, ezért hívták a legvidámabb barakknak, vagy gulyáskommunizmusnak ezt a rendszert, vagy fridzsider-szocializmusnak a fogyasztási cikkek beszerzésére való törekvés miatt.\n\nA HIDEGHÁBORÚS KONFLIKTUSOK:\n\nA keleti (SZU) és nyugati (USA) tömb fegyverkezési versenybe kezdett, de mindig egy 3. országban csaptak össze.\n\nKorea a háború előtt japán gyarmat volt, a világháború után az északi része szovjet, a déli része amerikai befolyás alá került. 1950-53 között háború robbant ki a két állam között Korea területén, de Sztálin 1953-as halála miatt befejeződtek.\n\nA két nagyhatalom befolyását jelzi a szuezi válság megoldása 1956-ban: Anglia és Franciaország el kell, hogy hagyja a térséget, hiszen az erősebb jogán a két nagyhatalom beavatkozott az egyiptomi-izraeli konfliktusba.\n\n1961-ben emelték Kelet-Berlin és Nyugat-Berlin között a berlini falat, amely a rendszerváltozásig, 1989-ig állt fenn.\n\n1962-ben a karibi válság során veszélyhelyzetbe kerül az USA. A szovjetek nukleáris rakétákat telepítettek Kubába, melyek az USA elpusztítására képesek lettek volna. Válaszul Kennedy elnök blokádot rendelt el a Karib-tengeren. A harckészültség után végül is kompromisszum született: Szovjetunió visszavonta rakétáit Kubából. Aki a nukleáris fegyvert elsőként beveti, másodikként hal meg.\n\n1964-73. az USA a vietnámi háborúban vesz részt, melyet háborúellenes tiltakozások miatt kell feladnia.\n\n1979-től Afganisztánban ütközik össze a Szovjetunióval.\n\nA fegyverkezési versenyben az USA kerül ki győztesen, az 1980-as években Ronald Reagen elnök meghirdeti a csillagháborús fegyverkezési versenyt, amit a SZU nem tud követni. A keleti blokk országaiban a gazdasági összeomlásnak és Gorbacsov reformpolitikájának köszönhetően 1989-ben a kommunista pártok hatalmának megdöntésére került sor. 1991-ben Szovjetunió felbomlott. Az USA jelenleg is a világ vezető hatalma.', 183, 1, '2026-04-17 09:41:10', '2026-04-17 09:41:10');
